window.HADITH_CACHE["muslim_6"] = {"3001":{"ar":"و حَدَّثَنَا عَبْدُ بْنُ حُمَيْدٍ أَخْبَرَنَا عَبْدُ الرَّزَّاقِ أَخْبَرَنَا مَعْمَرٌ عَنْ الزُّهْرِيِّ عَنْ عُرْوَةَ عَنْ عَائِشَةَ قَالَتْجَاءَتْ هِنْدٌ إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَتْ يَا رَسُولَ اللَّهِ وَاللَّهِ مَا كَانَ عَلَى ظَهْرِ الْأَرْضِ أَهْلُ خِبَاءٍ أَحَبَّ إِلَيَّ مِنْ أَنْ يُذِلَّهُمْ اللَّهُ مِنْ أَهْلِ خِبَائِكَ وَمَا عَلَى ظَهْرِ الْأَرْضِ أَهْلُ خِبَاءٍ أَحَبَّ إِلَيَّ مِنْ أَنْ يُعِزَّهُمْ اللَّهُ مِنْ أَهْلِ خِبَائِكَ فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَأَيْضًا وَالَّذِي نَفْسِي بِيَدِهِ ثُمَّ قَالَتْ يَا رَسُولَ اللَّهِ إِنَّ أَبَا سُفْيَانَ رَجُلٌ مُمْسِكٌ فَهَلْ عَلَيَّ حَرَجٌ أَنْ أُنْفِقَ عَلَى عِيَالِهِ مِنْ مَالِهِ بِغَيْرِ إِذْنِهِ فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا حَرَجَ عَلَيْكِ أَنْ تُنْفِقِي عَلَيْهِمْ بِالْمَعْرُوفِ","id":"Dan telah menceritakan kepada kami [Abd bin Humaid] telah mengabarkan kepada kami [Abdurrazaq] telah mengabarkan kepada kami [Ma'mar] dari [Az Zuhri] dari ['Urwah] dari ['Aisyah] dia berkata, \"Suatu ketika Hindun datang kepada Nabi shallallahu 'alaihi wasallam dan berkata, \"Wahai Rasulullah, Demi Allah, dahulu tidak ada ahli bait di muka bumi ini yang lebih aku sukai supaya Allah menghinakannya daripada ahli baitmu, namun sekarang tidak ada ahli bait di muka bumi ini yang lebih aku sukai supaya Allah memuliakannya selain ahli baitmu.\" Maka Nabi shallallahu 'alaihi wasallam bersabda: \"Demi dzat yang jiwaku berada di tangan-Nya, mungkin kamu ingin mengatakan sesuatu yang lain?\" Kemudian dia berkata, \"Wahai Rasulullah, sesungguhnya Abu Sufyan adalah laki-laki yang bakhil, apakah aku berdosa jika aku memebelanjakan hartanya untuk keluarganya tanpa sepengetahuan darinya?\" maka Nabi shallallahu 'alaihi wasallam bersabda: \"Kamu tidak berdosa jika mengemabil untuk menafkahi keluarganya dengan sekedarnya (tidak berlebihan).\""},"3002":{"ar":"حَدَّثَنَا زُهَيْرُ بْنُ حَرْبٍ حَدَّثَنَا يَعْقُوبُ بْنُ إِبْرَاهِيمَ حَدَّثَنَا ابْنُ أَخِي الزُّهْرِيِّ عَنْ عَمِّهِ أَخْبَرَنِي عُرْوَةُ بْنُ الزُّبَيْرِ أَنَّ عَائِشَةَ قَالَتْجَاءَتْ هِنْدٌ بِنْتُ عُتْبَةَ بْنِ رَبِيعَةَ فَقَالَتْ يَا رَسُولَ اللَّهِ وَاللَّهِ مَا كَانَ عَلَى ظَهْرِ الْأَرْضِ خِبَاءٌ أَحَبَّ إِلَيَّ مِنْ أَنْ يَذِلُّوا مِنْ أَهْلِ خِبَائِكَ وَمَا أَصْبَحَ الْيَوْمَ عَلَى ظَهْرِ الْأَرْضِ خِبَاءٌ أَحَبَّ إِلَيَّ مِنْ أَنْ يَعِزُّوا مِنْ أَهْلِ خِبَائِكَ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَأَيْضًا وَالَّذِي نَفْسِي بِيَدِهِ ثُمَّ قَالَتْ يَا رَسُولَ اللَّهِ إِنَّ أَبَا سُفْيَانَ رَجُلٌ مِسِّيكٌ فَهَلْ عَلَيَّ حَرَجٌ مِنْ أَنْ أُطْعِمَ مِنْ الَّذِي لَهُ عِيَالَنَا فَقَالَ لَهَا لَا إِلَّا بِالْمَعْرُوفِ","id":"Telah menceritakan kepada kami [Zuhair bin Harb] telah menceritakan kepada kami [Ya'qub bin Ibrahim] telah menceritakan kepada kami [anak saudara Az Zuhri] dari [pamannya] telah mengabarkan kepadaku ['Urwah bin Zubair] bahwa ['Aisyah] berkata, \"Suatu ketika Hindun binti 'Utbah bin Rabi'ah datang seraya berkata, \"Wahai Rasulullah, dahulu tidak ada ahli bait di muka bumi ini yang paling aku sukai supaya Allah menghinakannya selain ahli baitmu, namun sekarang tidak ada ahli bait di muka bumi ini yang paling aku sukai supaya Allah memuliakannya selain dari ahli baitmu.\" Maka Rasulullah shallallahu 'alaihi wasallam bersabda: \"Demi dzat yang jiwaku berada di tangan-Nya, mungkin kamu hendak mengatakan sesuatu yang lain.\" Kemudian dia berkata, \"Wahai Rasulullah, sesungguhnya Abu Sufyan adalah laki-laki yang bakhil, apakah aku berdosa jika aku memberi makan keluarganya dari hartanya?\" beliau menjawab: \"Tidak, jika kamu menggunakannya dengan baik.\""},"3003":{"ar":"حَدَّثَنِي زُهَيْرُ بْنُ حَرْبٍ حَدَّثَنَا جَرِيرٌ عَنْ سُهَيْلٍ عَنْ أَبِيهِ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّ اللَّهَ يَرْضَى لَكُمْ ثَلَاثًا وَيَكْرَهُ لَكُمْ ثَلَاثًا فَيَرْضَى لَكُمْ أَنْ تَعْبُدُوهُ وَلَا تُشْرِكُوا بِهِ شَيْئًا وَأَنْ تَعْتَصِمُوا بِحَبْلِ اللَّهِ جَمِيعًا وَلَا تَفَرَّقُوا وَيَكْرَهُ لَكُمْ قِيلَ وَقَالَ وَكَثْرَةَ السُّؤَالِ وَإِضَاعَةِ الْمَالِو حَدَّثَنَا شَيْبَانُ بْنُ فَرُّوخَ أَخْبَرَنَا أَبُو عَوَانَةَ عَنْ سُهَيْلٍ بِهَذَا الْإِسْنَادِ مِثْلَهُ غَيْرَ أَنَّهُ قَالَ وَيَسْخَطُ لَكُمْ ثَلَاثًا وَلَمْ يَذْكُرْ وَلَا تَفَرَّقُوا","id":"Telah menceritakan kepadaku [Zuhair bin Harb] telah menceritakan kepada kami [Jarir] dari [Suhail] dari [ayahnya] dari [Abu Hurairah] dia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sesungguhnya Allah menyukai bagimu tiga perkara dan membenci tiga perkara; Dia menyukai kalian supaya beribadah kepada-Nya dan tidak menyekutukan-Nya dengan sesuatu apapun, kalian berpegang teguh dengan agama-Nya dan tidak berpecah belah. Dan Allah membenci kalian dari mengatakan sesuatu yang tidak jelas sumbernya, banyak bertanya dan menyia-nyiakan harta.\" Dan telah menceritakan kepada kami [Syaiban bin Farruh] telah mengabarkan kepada kami [Abu 'Awanah] dari [Suhail] dengan isnad seperti ini, namun dia berkata, 'Dan dia murka terhadap tiga perkara dari kalian', dan tidak menyebutkan, 'dan janganlah kalian berpecah belah'.\""},"3004":{"ar":"و حَدَّثَنَا إِسْحَقُ بْنُ إِبْرَاهِيمَ الْحَنْظَلِيُّ أَخْبَرَنَا جَرِيرٌ عَنْ مَنْصُورٍ عَنْ الشَّعْبِيِّ عَنْ وَرَّادٍ مَوْلَى الْمُغِيرَةِ بْنِ شُعْبَةَ عَنْ الْمُغِيرَةِ بْنِ شُعْبَةَعَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِنَّ اللَّهَ عَزَّ وَجَلَّ حَرَّمَ عَلَيْكُمْ عُقُوقَ الْأُمَّهَاتِ وَوَأْدَ الْبَنَاتِ وَمَنْعًا وَهَاتِ وَكَرِهَ لَكُمْ ثَلَاثًا قِيلَ وَقَالَ وَكَثْرَةَ السُّؤَالِ وَإِضَاعَةَ الْمَالِو حَدَّثَنِي الْقَاسِمُ بْنُ زَكَرِيَّاءَ حَدَّثَنَا عُبَيْدُ اللَّهِ بْنُ مُوسَى عَنْ شَيْبَانَ عَنْ مَنْصُورٍ بِهَذَا الْإِسْنَادِ مِثْلَهُ غَيْرَ أَنَّهُ قَالَ وَحَرَّمَ عَلَيْكُمْ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَلَمْ يَقُلْ إِنَّ اللَّهَ حَرَّمَ عَلَيْكُمْ","id":"Dan telah menceritakan kepada kami [Ishaq bin Ibrahim Al Handlali] telah mengabarkan kepada kami [Jarir] dari [Manshur] dari [Asy Sya'bi] dari [Warrad] bekas budak Al Mughirah bin Syu'bah, dari [Mughirah bin Syu'bah] dari Rasulullah shallallahu 'alaihi wasallam, beliau bersabda: \"Sesungguhnya Allah 'azza wajalla mengharamkan kalian mendurhakai seorang ibu, mengubur anak perempuan hidup-hidup, dan tidak suka memberi dan suka meminta-minta. Dan membenci atasmu tiga perkara; mengatakan sesuatu yang tidak jelas sumbernya, banyak bertanya dan menyia-nyiakan harta.\" Dan telah menceritakan kepadaku [Al Qasim bin Zakaria] telah menceritakan kepada kami ['Ubaidullah bin Musa] dari [Syaiban] dari [Manshur] dengan isnad seperti ini, hanya saja ia menyebutkan, 'Dan Rasulullah shallallahu 'alaihi wasallam telah mengharamkan atas kalian', tidak menyebutkan, 'Sesungguhnya Allah mengharamkan atas kalian'.\""},"3005":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا إِسْمَعِيلُ ابْنُ عُلَيَّةَ عَنْ خَالِدٍ الْحَذَّاءِ حَدَّثَنِي ابْنُ أَشْوَعَ عَنْ الشَّعْبِيِّ حَدَّثَنِي كَاتِبُ الْمُغِيرَةِ بْنِ شُعْبَةَ قَالَكَتَبَ مُعَاوِيَةُ إِلَى الْمُغِيرَةِ اكْتُبْ إِلَيَّ بِشَيْءٍ سَمِعْتَهُ مِنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَكَتَبَ إِلَيْهِ أَنِّي سَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ إِنَّ اللَّهَ كَرِهَ لَكُمْ ثَلَاثًا قِيلَ وَقَالَ وَإِضَاعَةَ الْمَالِ وَكَثْرَةَ السُّؤَالِ","id":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] telah menceritakan kepada kami [Ismail bin Ulayyah] dari [Khalid Al Khaddza`] telah menceritakan kepadaku [Ibnu Asywa'] dari [As Sya'bi] telah menceritakan kepadaku [Sekretaris Mughirah bin Syu'bah] dia berkata, \"Mu'awiyah pernah mengirim surat kepada [Mughirah], 'Tulislah untukku sesuatu yang pernah kamu dengar dari Rasulullah shallallahu 'alaihi wasallam! ' Lantas dia membalas suratnya, 'Aku pernah mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sesungguhnya Allah membenci atas kalian tiga perkara; mengatakan sesuatu yang tidak jelas sumbernya, menyia-nyiakan harta dan banyak bertanya.\""},"3006":{"ar":"حَدَّثَنَا ابْنُ أَبِي عُمَرَ حَدَّثَنَا مَرْوَانُ بْنُ مُعَاوِيَةَ الْفَزَارِيُّ عَنْ مُحَمَّدِ بْنِ سُوقَةَ أَخْبَرَنَا مُحَمَّدُ بْنُ عُبَيْدِ اللَّهِ الثَّقَفِيُّ عَنْ وَرَّادٍ قَالَكَتَبَ الْمُغِيرَةُ إِلَى مُعَاوِيَةَ سَلَامٌ عَلَيْكَ أَمَّا بَعْدُ فَإِنِّي سَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ إِنَّ اللَّهَ حَرَّمَ ثَلَاثًا وَنَهَى عَنْ ثَلَاثٍ حَرَّمَ عُقُوقَ الْوَالِدِ وَوَأْدَ الْبَنَاتِ وَلَا وَهَاتِ وَنَهَى عَنْ ثَلَاثٍ قِيلَ وَقَالَ وَكَثْرَةِ السُّؤَالِ وَإِضَاعَةِ الْمَالِ","id":"Dan telah menceritakan kepada kami [Ibnu Abu Umar] telah menceritakan kepada kami [Marwan bin Mu'awiyah Al Fazari] dari [Muhammad bin Suqah] telah mengabarkan kepada kami [Muhammad bin 'Ubaidullah At Tsaqafi] dari [Warrad] dia berkata, \" [Mughirah] pernah berkirim surat kepada Mu'wiyah, \"Semoga engkau mendapat keselamatan. Amma ba'du, sesungguhnya aku pernah mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sesungguhnya Allah mengharamkan tiga perkara dan melarang dari tiga perkara; Allah mengharamkan durhaka terhadap orang tua, mengubur anak perempuan hidup-hidup dan tidak mau memberi. Dan Allah melarang dari tiga perkara; mengatakan sesuatu yang tidak jelas sumbernya, banyak bertanya dan menyia-nyiakan harta.\""},"3007":{"ar":"حَدَّثَنَا يَحْيَى بْنُ يَحْيَى التَّمِيمِيُّ أَخْبَرَنَا عَبْدُ الْعَزِيزِ بْنُ مُحَمَّدٍ عَنْ يَزِيدَ بْنِ عَبْدِ اللَّهِ بْنِ أُسَامَةَ بْنِ الْهَادِ عَنْ مُحَمَّدِ بْنِ إِبْرَاهِيمَ عَنْ بُسْرِ بْنِ سَعِيدٍ عَنْ أَبِي قَيْسٍ مَوْلَى عَمْرِو بْنِ الْعَاصِ عَنْ عَمْرِو بْنِ الْعَاصِأَنَّهُ سَمِعَ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِذَا حَكَمَ الْحَاكِمُ فَاجْتَهَدَ ثُمَّ أَصَابَ فَلَهُ أَجْرَانِ وَإِذَا حَكَمَ فَاجْتَهَدَ ثُمَّ أَخْطَأَ فَلَهُ أَجْرٌو حَدَّثَنِي إِسْحَقُ بْنُ إِبْرَاهِيمَ وَمُحَمَّدُ بْنُ أَبِي عُمَرَ كِلَاهُمَا عَنْ عَبْدِ الْعَزِيزِ بْنِ مُحَمَّدٍ بِهَذَا الْإِسْنَادِ مِثْلَهُ وَزَادَ فِي عَقِبِ الْحَدِيثِ قَالَ يَزِيدُ فَحَدَّثْتُ هَذَا الْحَدِيثَ أَبَا بَكْرِ بْنَ مُحَمَّدِ بْنِ عَمْرِو بْنِ حَزْمٍ فَقَالَ هَكَذَا حَدَّثَنِي أَبُو سَلَمَةَ عَنْ أَبِي هُرَيْرَةَ و حَدَّثَنِي عَبْدُ اللَّهِ بْنُ عَبْدِ الرَّحْمَنِ الدَّارِمِيُّ أَخْبَرَنَا مَرْوَانُ يَعْنِي ابْنَ مُحَمَّدٍ الدِّمَشْقِيَّ حَدَّثَنَا اللَّيْثُ بْنُ سَعْدٍ حَدَّثَنِي يَزِيدُ بْنُ عَبْدِ اللَّهِ بْنِ أُسَامَةَ بْنِ الْهَادِ اللَّيْثِيُّ بِهَذَا الْحَدِيثِ مِثْلَ رِوَايَةِ عَبْدِ الْعَزِيزِ بْنِ مُحَمَّدٍ بِالْإِسْنَادَيْنِ جَمِيعًا","id":"Telah menceritakan kepada kami [Yahya bin Yahya At Tamimi] telah mengabarkan kepada kami [Abdul Aziz bin Muhammad] dari [Yazid bin Abdullah bin Usamah bin Hadi] dari [Muhammad bin Ibrahim] dari [Busr bin Sa'id] dari [Abu Qais] bekas budak 'Amru bin'Ash, dari ['Amru bin'Ash] bahwa dia pernah mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Jika seorang hakim berijtihad dalam menetapkan suatu hukum, ternyata hukumnya benar, maka hakim tersebut akan mendapatkan dua pahala, dan apabila dia berijtihad dalam menetapkan suatu hukum, namun dia salah, maka dia akan mendapatkan satu pahala.\" Dan telah menceritakan kepadaku [Ishaq bin Ibrahim] dan [Muhammad bin Abu Umar] keduanya dari [Abdul Aziz bin Muhammad] dengan isnad seperti ini, namun ada sedikit tambahan dalam akhir haditsnya. [Yazid] berkata, \"Aku telah menceritakan hadits ini kepada [Abu Bakar bin Muhammad bin 'Amru bin Hazm] lalu dia berkata, \"Seperti inilah [Abu Salamah] menceritakan kepadaku dari [Abu Hurairah].\" Dan telah menceritakan kepadaku [Abdullah bin Abdurrahman Ad Darimi] telah mengabarkan kepada kami [Marwan] -yaitu Ibnu Muhammad Ad Damasyqi- telah menceritakan kepada kami [Laits bin Sa'd] telah menceritakan kepadaku [Yazid bin Abdullah bin Usamah bin Hadi Al Laitsi] dengan hadits ini seperti riwayat Abdul Aziz bin Muhammad dengan kedua isnad tersebut.\""},"3008":{"ar":"حَدَّثَنَا قُتَيْبَةُ بْنُ سَعِيدٍ حَدَّثَنَا أَبُو عَوَانَةَ عَنْ عَبْدِ الْمَلِكِ بْنِ عُمَيْرٍ عَنْ عَبْدِ الرَّحْمَنِ بْنِ أَبِي بَكْرَةَ قَالَ كَتَبَ أَبِي وَكَتَبْتُ لَهُ إِلَى عُبَيْدِ اللَّهِ بْنِ أَبِي بَكْرَةَ وَهُوَ قَاضٍ بِسِجِسْتَانَ أَنْ لَا تَحْكُمَ بَيْنَ اثْنَيْنِ وَأَنْتَ غَضْبَانُ فَإِنِّيسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ لَا يَحْكُمْ أَحَدٌ بَيْنَ اثْنَيْنِ وَهُوَ غَضْبَانُو حَدَّثَنَاه يَحْيَى بْنُ يَحْيَى أَخْبَرَنَا هُشَيْمٌ ح و حَدَّثَنَا شَيْبَانُ بْنُ فَرُّوخَ حَدَّثَنَا حَمَّادُ بْنُ سَلَمَةَ ح و حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا وَكِيعٌ عَنْ سُفْيَانَ ح و حَدَّثَنَا مُحَمَّدُ بْنُ الْمُثَنَّى حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ ح و حَدَّثَنَا عُبَيْدُ اللَّهِ بْنُ مُعَاذٍ حَدَّثَنَا أَبِي كِلَاهُمَا عَنْ شُعْبَةَ ح و حَدَّثَنَا أَبُو كُرَيْبٍ حَدَّثَنَا حُسَيْنُ بْنُ عَلِيٍّ عَنْ زَائِدَةَ كُلُّ هَؤُلَاءِ عَنْ عَبْدِ الْمَلِكِ بْنِ عُمَيْرٍ عَنْ عَبْدِ الرَّحْمَنِ بْنِ أَبِي بَكْرَةَ عَنْ أَبِيهِ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِمِثْلِ حَدِيثِ أَبِي عَوَانَةَ","id":"Telah menceritakan kepada kami [Qutaibah bin Sa'id] telah menceritakan kepada kami [Abu 'Awanah] dari [Abdul Malik bin Umair] dari [Abdurrahman bin Abu Bakrah] dia berkata, \"Suatu hari [ayahku] menulis surat -dan sebenarnya akulah yang menuliskannya- kepada Ubaidullah bin Abu Bakrah yang sedang menjabat sebagai hakim di negeri Sajastan, di antara isinya adalah, 'Wahai Ubaidullah, janganlah kamu menetapkan suatu hukum di antara dua orang sedangkan kamu dalam keadaan marah, sebab aku pernah mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: 'Janganlah seseorang menetapkan hukum di antara dua orang yang bersengketa, sedangkan dia dalam keadaan marah'.\" Dan telah menceritakan kepada kami [Yahya bin Yahya] telah mengabarkan kepada kami [Husyaim]. (dalam jalur lain disebutkan) Telah menceritakan kepada kami [Syaiban bin Farruh] telah menceritakan kepada kami [Hammad bin Salamah]. (dalam jalur lain disebutkan) Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] telah menceritakan kepada kami [Waki'] dari [Sufyan]. (dalam jalur lain disebutkan) Telah menceritakan kepada kami [Muhammad bin Al Mutsanna] telah menceritakan kepada kami [Muhamamd bin Ja'far]. (dalam jalur lain disebutkan) Telah menceritakan kepada kami [Ubaidullah bin Mu'adz] telah menceritakan kepada kami [ayahku] keduanya dari [Syu'bah]. (dalam jalur lain disebutkan) Telah menceritakan kepada kami [Abu Kuraib] telah menceritakan kepada kami [Husain bin 'Ali] dari [Zaidah] mereka semua dari [Abdul Malik bin Umair] dari [Abdurrahman bin Abu Bakrah] dari [ayahnya] dari Nabi shallallahu 'alaihi wasallam seperti hadits riwayat Abu 'Awanah.\""},"3009":{"ar":"حَدَّثَنَا أَبُو جَعْفَرٍ مُحَمَّدُ بْنُ الصَّبَّاحِ وَعَبْدُ اللَّهِ بْنُ عَوْنٍ الْهِلَالِيُّ جَمِيعًا عَنْ إِبْرَاهِيمَ بْنِ سَعْدٍ قَالَ ابْنُ الصَّبَّاحِ حَدَّثَنَا إِبْرَاهِيمُ بْنُ سَعْدِ بْنِ إِبْرَاهِيمَ بْنِ عَبْدِ الرَّحْمَنِ بْنِ عَوْفٍ حَدَّثَنَا أَبِي عَنْ الْقَاسِمِ بْنِ مُحَمَّدٍ عَنْ عَائِشَةَ قَالَتْقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ أَحْدَثَ فِي أَمْرِنَا هَذَا مَا لَيْسَ مِنْهُ فَهُوَ رَدٌّ","id":"Telah menceritakan kepada kami [Abu Ja'far Muhammad bin Shabah] dan [Abdullah bin 'Aun Al Hilali] semuanya dari [Ibrahim bin Sa'd]. [Ibnu Shabah] berkata; telah menceritakan kepada kami [Ibrahim bin Sa'd bin Ibrahim bin Abdurrahman bin Auf] telah menceritakan kepada kami [ayahku] dari [Al Qasim bin Muhammad] dari ['Aisyah] dia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa mengada-ngada sesuatu yang baru dalam urusan (agama) kami, padahal kami tidak perintahkan, maka hal itu tertolak.\""},"3010":{"ar":"و حَدَّثَنَا إِسْحَقُ بْنُ إِبْرَاهِيمَ وَعَبْدُ بْنُ حُمَيْدٍ جَمِيعًا عَنْ أَبِي عَامِرٍ قَالَ عَبْدٌ حَدَّثَنَا عَبْدُ الْمَلِكِ بْنُ عَمْرٍو حَدَّثَنَا عَبْدُ اللَّهِ بْنُ جَعْفَرٍ الزُّهْرِيُّ عَنْ سَعْدِ بْنِ إِبْرَاهِيمَ قَالَ سَأَلْتُ الْقَاسِمَ بْنَ مُحَمَّدٍ عَنْ رَجُلٍ لَهُ ثَلَاثَةُ مَسَاكِنَ فَأَوْصَى بِثُلُثِ كُلِّ مَسْكَنٍ مِنْهَا قَالَ يُجْمَعُ ذَلِكَ كُلُّهُ فِي مَسْكَنٍ وَاحِدٍ ثُمَّ قَالَ أَخْبَرَتْنِي عَائِشَةُأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ عَمِلَ عَمَلًا لَيْسَ عَلَيْهِ أَمْرُنَا فَهُوَ رَدٌّ","id":"Dan telah menceritakan kepada kami [Ishaq bin Ibrahim] dan [Abd bin Humaid] semuanya dari [Abu Amir]. [Abd] berkata; telah menceritakan kepada kami [Abdul Malik bin Amru] telah menceritakan kepada kami [Abdullah bin Ja'far Az Zuhri] dari [Sa'd bin Ibrahim] dia berkata; aku bertanya kepada [Al Qasim bin Muhammad] tentang seseorang yang memilki tiga tempat tinggal, lalu dia mewasiatkan sepertiga dari setiap satu tempat tinggal.\" Sa'd melanjutkan, \"Kemudian dia mengumpulkannya menjadi satu.\" Al Qasim menjawab, \" [Aisyah] telah mengabarkan kepadaku bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa mengamalkan suaru perkara yang tidak kami perintahkan, maka ia tertolak.\""},"3011":{"ar":"و حَدَّثَنَا يَحْيَى بْنُ يَحْيَى قَالَ قَرَأْتُ عَلَى مَالِكٍ عَنْ عَبْدِ اللَّهِ بْنِ أَبِي بَكْرٍ عَنْ أَبِيهِ عَنْ عَبْدِ اللَّهِ بْنِ عَمْرِو بْنِ عُثْمَانَ عَنْ ابْنِ أَبِي عَمْرَةَ الْأَنْصَارِيِّ عَنْ زَيْدِ بْنِ خَالِدٍ الْجُهَنِيِّأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ أَلَا أُخْبِرُكُمْ بِخَيْرِ الشُّهَدَاءِ الَّذِي يَأْتِي بِشَهَادَتِهِ قَبْلَ أَنْ يُسْأَلَهَا","id":"Telah menceritakan kepada kami [Yahya bin Yahya] dia berkata; aku bacakan di hadapan [Malik]; dari [Abdullah bin Abu Bakar] dari [ayahnya] dari [Abdullah bin Amru bin Utsman] dari [Ibnu Abu 'Amrah Al Anshari] dari [Zaid bin Khalid Al Juhani], bahwa Nabi shallallahu 'alaihi wasallam bersabda: \"Maukah aku beritahukan kepada kalian mengenai saksi yang paling baik? Yaitu orang yang datang memberi kesaksian sebelum diminta (untuk bersaksi).\""},"3012":{"ar":"حَدَّثَنِي زُهَيْرُ بْنُ حَرْبٍ حَدَّثَنِي شَبَابَةُ حَدَّثَنِي وَرْقَاءُ عَنْ أَبِي الزِّنَادِ عَنْ الْأَعْرَجِ عَنْ أَبِي هُرَيْرَةَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ بَيْنَمَا امْرَأَتَانِ مَعَهُمَا ابْنَاهُمَا جَاءَ الذِّئْبُ فَذَهَبَ بِابْنِ إِحْدَاهُمَا فَقَالَتْ هَذِهِ لِصَاحِبَتِهَا إِنَّمَا ذَهَبَ بِابْنِكِ أَنْتِ وَقَالَتْ الْأُخْرَى إِنَّمَا ذَهَبَ بِابْنِكِ فَتَحَاكَمَتَا إِلَى دَاوُدَ فَقَضَى بِهِ لِلْكُبْرَى فَخَرَجَتَا عَلَى سُلَيْمَانَ بْنِ دَاوُدَ عَلَيْهِمَا السَّلَام فَأَخْبَرَتَاهُ فَقَالَ ائْتُونِي بِالسِّكِّينِ أَشُقُّهُ بَيْنَكُمَا فَقَالَتْ الصُّغْرَى لَا يَرْحَمُكَ اللَّهُ هُوَ ابْنُهَا فَقَضَى بِهِ لِلصُّغْرَىقَالَ قَالَ أَبُو هُرَيْرَةَ وَاللَّهِ إِنْ سَمِعْتُ بِالسِّكِّينِ قَطُّ إِلَّا يَوْمَئِذٍ مَا كُنَّا نَقُولُ إِلَّا الْمُدْيَةَ و حَدَّثَنَا سُوَيْدُ بْنُ سَعِيدٍ حَدَّثَنِي حَفْصٌ يَعْنِي ابْنَ مَيْسَرَةَ الصَّنْعَانِيَّ عَنْ مُوسَى بْنِ عُقْبَةَ ح و حَدَّثَنَا أُمَيَّةُ بْنُ بِسْطَامَ حَدَّثَنَا يَزِيدُ بْنُ زُرَيْعٍ حَدَّثَنَا رَوْحٌ وَهُوَ ابْنُ الْقَاسِمِ عَنْ مُحَمَّدِ بْنِ عَجْلَانَ جَمِيعًا عَنْ أَبِي الزِّنَادِ بِهَذَا الْإِسْنَادِ مِثْلَ مَعْنَى حَدِيثِ وَرْقَاءَ","id":"Telah menceritakan kepada kami [Zuhair bin Harb] telah menceritakan kepadaku [Syababah] telah menceritakan kepadaku [Warqa`] dari [Abu Az Zinnad] dari [Al A'raj] dari [Abu Hurairah] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Dahulu ada dua orang wanita yang sedang bermain bersama anak mereka masing-masing. Tiba-tiba datang seekor serigala yang menerkam dan membawa anak salah seorang dari mereka berdua. Seorang dari mereka berkata kepada yang lain, 'sebenarnya yang dimangsa serigala tadi adalah anakmu'. Rupanya wanita yang satunya menyangkal seraya berkata, 'Tidak, yang dimangsa oleh serigala tersebut adalah anakmu'. Akhirnya kedua wanita meminta keputusan dari Daud, namun Daud menetapkan bahwa anak yang masih hidup itu milik wanita yang usianya lebih tua. Kemudian keduanya pergi menemui Sulaiman bin Daud 'alaihima salam, lantas kedua wanita tersebut menceritakan apa yang sebenarnya terjadi, setelah mendengar ceritanya, Sulaiman berkata, 'Baiklah, sekarang tolong ambilkan aku pisau, aku akan membelah dan membagi dua anak ini untuk kalian berdua'. Tiba-tiba wanita yang lebih muda berkata, 'Tidak, semoga Allah merahmati anda, berikanlah anak tersebut untuknya'. Maka Sulaiman pun menetapkan anak itu untuk wanita yang lebih muda umurnya.\" Al A'raj melanjutkan, \"Lalu Abu Hurairah memberi komentar terhadap hadits ini, 'Sungguh, baru kali ini aku mendengar kata sikkin (pisau) dari cerita hadits ini, karena biasanya kami menyebutnya dengan mudyah (pisau).\" Dan telah menceritakan kepada kami [Suwaid bin Sa'id] telah menceritakan kepadaku [Hafsh] -yaitu Ibnu Maisarah Ash Shan'ani- dari [Musa bin 'Uqbah]. (dalam jalur lain disebutkan) Telah menceritakan kepada kami [Umayyah bin Bistham] telah menceritakan kepada kami [Yazid bin Zurai'] telah menceritakan kepada kami [Rauh] -yaitu Ibnu Al Qasim- dari [Muhammad bin 'Ajlan] semuanya dari [Abu Zinnad] dengan isnad ini, dan semakna dengan haditsnya Warqa`.\""},"3013":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ رَافِعٍ حَدَّثَنَا عَبْدُ الرَّزَّاقِ حَدَّثَنَا مَعْمَرٌ عَنْ هَمَّامِ بْنِ مُنَبِّهٍ قَالَ هَذَا مَا حَدَّثَنَا أَبُو هُرَيْرَةَ عَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَذَكَرَ أَحَادِيثَ مِنْهَاوَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ اشْتَرَى رَجُلٌ مِنْ رَجُلٍ عَقَارًا لَهُ فَوَجَدَ الرَّجُلُ الَّذِي اشْتَرَى الْعَقَارَ فِي عَقَارِهِ جَرَّةً فِيهَا ذَهَبٌ فَقَالَ لَهُ الَّذِي اشْتَرَى الْعَقَارَ خُذْ ذَهَبَكَ مِنِّي إِنَّمَا اشْتَرَيْتُ مِنْكَ الْأَرْضَ وَلَمْ أَبْتَعْ مِنْكَ الذَّهَبَ فَقَالَ الَّذِي شَرَى الْأَرْضَ إِنَّمَا بِعْتُكَ الْأَرْضَ وَمَا فِيهَا قَالَ فَتَحَاكَمَا إِلَى رَجُلٍ فَقَالَ الَّذِي تَحَاكَمَا إِلَيْهِ أَلَكُمَا وَلَدٌ فَقَالَ أَحَدُهُمَا لِي غُلَامٌ وَقَالَ الْآخَرُ لِي جَارِيَةٌ قَالَ أَنْكِحُوا الْغُلَامَ الْجَارِيَةَ وَأَنْفِقُوا عَلَى أَنْفُسِكُمَا مِنْهُ وَتَصَدَّقَا","id":"Telah menceritakan kepada kami [Muhammad bin Rafi'] telah menceritakan kepada kami [Abdurrazaq] telah menceritakan kepada kami [Ma'mar] dari [Hammam bin Munabbih] dia berkata; ini adalah sesuatu yang pernah diceritakan oleh [Abu Hurairah] dari Rasulullah shallallahu 'alaihi wasallam, lalu dia menyebutkan beberapa hadits yang di antaranya adalah, bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Ada seseorang yang membeli tanah dari orang lain, lalu orang yang membeli tanah itu menemukan guci berisi emas dari dalam tanah yang telah dibelinya. Orang yang membeli tanah itu berkata kepada yang menjualnya, 'Ambillah emasmu dari tanah yang aku beli ini, sebab aku hanya membeli tanah darimu, dan tidak membeli emasmu.' Sedangkan orang yang menjual tanah berkata, 'Yang aku jual kepadamu adalah tanah berikut isinya, oleh karena itu, jika kamu mendapati emas, maka itu sudah menjadi hakmu.' Akhirnya kedua orang tersebut pergi menemui seseorang untuk meminta keputusan antara mereka berdua. Lalu orang yang dimintai keputusan bertanya kepada keduanya, 'Apakah kalian berdua memiliki anak? ' seorang di antara mereka menjawab, 'Ya, aku memiliki anak laki-laki', dan yang satunya menjawab, 'Ya, aku juga memiliki anak perempuan'. Kemudian orang yang dimintai keputusan itu berkata, 'Sebaiknya nikahkan saja anak laki-laki dan anak perempuan kelian berdua. Setelah itu, belanjakanlah emas tersebut untuk kepentingan kalian, dan bersedekahlah untuk diri kalian berdua.\""},"3014":{"ar":"حَدَّثَنَا يَحْيَى بْنُ يَحْيَى التَّمِيمِيُّ قَالَ قَرَأْتُ عَلَى مَالِكٍ عَنْ رَبِيعَةَ بْنِ أَبِي عَبْدِ الرَّحْمَنِ عَنْ يَزِيدَ مَوْلَى الْمُنْبَعِثِ عَنْ زَيْدِ بْنِ خَالِدٍ الْجُهَنِيِّ أَنَّهُ قَالَجَاءَ رَجُلٌ إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَسَأَلَهُ عَنْ اللُّقَطَةِ فَقَالَ اعْرِفْ عِفَاصَهَا وَوِكَاءَهَا ثُمَّ عَرِّفْهَا سَنَةً فَإِنْ جَاءَ صَاحِبُهَا وَإِلَّا فَشَأْنَكَ بِهَا قَالَ فَضَالَّةُ الْغَنَمِ قَالَ لَكَ أَوْ لِأَخِيكَ أَوْ لِلذِّئْبِ قَالَ فَضَالَّةُ الْإِبِلِ قَالَ مَا لَكَ وَلَهَا مَعَهَا سِقَاؤُهَا وَحِذَاؤُهَا تَرِدُ الْمَاءَ وَتَأْكُلُ الشَّجَرَ حَتَّى يَلْقَاهَا رَبُّهَا قَالَ يَحْيَى أَحْسِبُ قَرَأْتُ عِفَاصَهَا","id":"Telah menceritakan kepada kami [Yahya bin Yahya At Tamimi] dia berkata; aku bacakan di hadapan [Malik]; dari [Rabi'ah bin Abu Abdurrahman] dari [Yazid] bekas budak Al Munba'is, dari [Zaid bin Khalid Al Juhani] bahwa dia berkata, \"Seseorang datang kepada Nabi shallallahu 'alaihi wasallam dan menanyakan mengenai barang temuan.\" Lalu beliau bersabda: \"Kenalilah wadah dan talinya, setelah itu umumkanlah kepada khalayak ramai, apabila pemiliknya datang maka berikanlah barang tersebut kepadanya.\" Kemudian orang itu juga bertanya, \"Wahai Rasulullah, bagaimana jika yang ditemukan adalah kambing?\" Rasulullah shallallahu 'alaihi wasallam menjawab: \"Mungkin ia dapat menjadi milikmu atau milik saudaramu atau bahkan menjadi milik serigala.\" Dia berkata, \"Wahai Rasulullah, bagaimana jika yang ditemukan adalah unta?\" beliau menjawab: \"Apa urusanmu dengan unta yang hilang? Ia telah membawa sepatu (punya kaki) dan wadah airnya sendiri. Ia dapat mendatangi mata air dan makan dedaunan sampai ia bertemu pemiliknya.\" Yahya berkata, \"Sepertinya aku membaca 'iffashaha (wadahnya).\""},"3015":{"ar":"و حَدَّثَنَا يَحْيَى بْنُ أَيُّوبَ وَقُتَيْبَةُ وَابْنُ حُجْرٍ قَالَ ابْنُ حُجْرٍ أَخْبَرَنَا و قَالَ الْآخَرَانِ حَدَّثَنَا إِسْمَعِيلُ وَهُوَ ابْنُ جَعْفَرٍ عَنْ رَبِيعَةَ بْنِ أَبِي عَبْدِ الرَّحْمَنِ عَنْ يَزِيدَ مَوْلَى الْمُنْبَعِثِ عَنْ زَيْدِ بْنِ خَالِدٍ الْجُهَنِيِّأَنَّ رَجُلًا سَأَلَ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ اللُّقَطَةِ فَقَالَ عَرِّفْهَا سَنَةً ثُمَّ اعْرِفْ وِكَاءَهَا وَعِفَاصَهَا ثُمَّ اسْتَنْفِقْ بِهَا فَإِنْ جَاءَ رَبُّهَا فَأَدِّهَا إِلَيْهِ فَقَالَ يَا رَسُولَ اللَّهِ فَضَالَّةُ الْغَنَمِ قَالَ خُذْهَا فَإِنَّمَا هِيَ لَكَ أَوْ لِأَخِيكَ أَوْ لِلذِّئْبِ قَالَ يَا رَسُولَ اللَّهِ فَضَالَّةُ الْإِبِلِ قَالَ فَغَضِبَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حَتَّى احْمَرَّتْ وَجْنَتَاهُ أَوْ احْمَرَّ وَجْهُهُ ثُمَّ قَالَ مَا لَكَ وَلَهَا مَعَهَا حِذَاؤُهَا وَسِقَاؤُهَا حَتَّى يَلْقَاهَا رَبُّهَاو حَدَّثَنِي أَبُو الطَّاهِرِ أَخْبَرَنَا عَبْدُ اللَّهِ بْنُ وَهْبٍ أَخْبَرَنِي سُفْيَانُ الثَّوْرِيُّ وَمَالِكُ بْنُ أَنَسٍ وَعَمْرُو بْنُ الْحَارِثِ وَغَيْرُهُمْ أَنَّ رَبِيعَةَ بْنَ أَبِي عَبْدِ الرَّحْمَنِ حَدَّثَهُمْ بِهَذَا الْإِسْنَادِ مِثْلَ حَدِيثِ مَالِكٍ غَيْرَ أَنَّهُ زَادَ قَالَ أَتَى رَجُلٌ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَأَنَا مَعَهُ فَسَأَلَهُ عَنْ اللُّقَطَةِ قَالَ وَقَالَ عَمْرٌو فِي الْحَدِيثِ فَإِذَا لَمْ يَأْتِ لَهَا طَالِبٌ فَاسْتَنْفِقْهَا و حَدَّثَنِي أَحْمَدُ بْنُ عُثْمَانَ بْنِ حَكِيمٍ الْأَوْدِيُّ حَدَّثَنَا خَالِدُ بْنُ مَخْلَدٍ حَدَّثَنِي سُلَيْمَانُ وَهُوَ ابْنُ بِلَالٍ عَنْ رَبِيعَةَ بْنِ أَبِي عَبْدِ الرَّحْمَنِ عَنْ يَزِيدَ مَوْلَى الْمُنْبَعِثِ قَالَ سَمِعْتُ زَيْدَ بْنَ خَالِدٍ الْجُهَنِيَّ يَقُولُا أَتَى رَجُلٌ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَذَكَرَ نَحْوَ حَدِيثِ إِسْمَعِيلَ بْنِ جَعْفَرٍ غَيْرَ أَنَّهُ قَالَ فَاحْمَارَّ وَجْهُهُ وَجَبِينُهُ وَغَضِبَ وَزَادَ بَعْدَ قَوْلِهِ ثُمَّ عَرِّفْهَا سَنَةً فَإِنْ لَمْ يَجِئْ صَاحِبُهَا كَانَتْ وَدِيعَةً عِنْدَكَ","id":"Dan telah menceritakan kepada kami [Yahya bin Ayyub] dan [Qutaibah] dan [Ibin Hujr]. Ibnu Hujr berkata; telah mengabarkan kepada kami, sedangkan yang dua orang mengatakan; telah menceritakan kepada kami [Isma'il] -yaitu Ibnu Ja'far- dari [Rabi'ah bin Abu Abdurrahman] dari [Yazid] -bekas budak Al Munba'its- dari [Zaid bin Khalid Al Juhani] bahwa seorang laki-laki bertanya kepada Rasulullah shallallahu 'alaihi wasallam tentang barang temuan, lalu beliau bersabda: \"Umumkanlah selama setahun, lalu kenalilah wadah dan talinya setelah itu manfaatkanlah ia, jika pemiliknya datang maka berikanlah barang tersebut kepadanya.\" Kemudian orang itu bertanya lagi, \"Wahai Rasulullah, bagaimana dengan kambing yang hilang?\" Beliau menjawab: \"Ambillah, mungkin ia dapat menjadi milikmu atau milik saudaramu atau bahkan menjadi milik serigala.\" Dia bertanya lagi, \"Wahai Rasulullah, bagaimana jika yang ditemukan adalah unta?\" Zaid bin Khalid berkata, \"Maka Rasulullah shallallahu 'alaihi wasallam marah hingga wajahnya memerah, kemudian beliau bersabda: \"Apa urusanmu dengan unta yang hilang? Ia telah membawa sepatu (punya kaki) dan wadah airnya sendiri hingga ia bertemu pemiliknya.\" Dan telah menceritakanku [Abu At Thahir] telah mengabarkan kepada kami [Abdullah bin Wahb] telah mengabarkan kepadaku [Sufyan Ats Tsauri] dan [Malik bin Anas] dan ['Amru bin Al Harits] dan yang lainnya, bahwa [Rabi'ah bin Abu Abdurrahman] telah menceritakan kepada mereka dengan isnad ini seperti hadits Malik, hanya saja ia menambahkan; Zaid berkata, \"Seorang laki-laki datang menemui Rasulullah shallallahu 'alaihi wasallam, sedangkakn saat itu aku bersama beliau, lantas dia bertanya mengenai barang temuan.\" Perawi berkata; Amru menyebutkan dalam hadits, \"Jika pemiliknya belum datang untuk mengambilnya, maka kamu boleh memanfaatkannya.\" Dan telah menceritakanku [Ahmad bin Utsman bin Hakim Al Audi] telah menceritakan kepadaku [Khlaid bin Makhlad] telah menceritakanku [Sulaiman] -yaitu Ibnu Bilal- dari [Rabi'ah bin Abu Abdurrahman] dari [Yazid] -bekas budak Al Munba'its- dia berkata; aku pernah mendengar [Zaid bin Khalid Al Juhani] berkata, \"Seorang laki-laki datang menemui Rasulullah shallallahu 'alaihi wasallam, lalu dia menyebutkan seperti hadits Isma'il bin Ja'far, namun dia menyebutkan, \"Lalu beliau marah sampai terlihat wajahnya memerah.\" Dan setelah perkataanya, \"kemudian umumkanlah selama setahun, jika pemiliknya belum datang maka ia menjadi barang titipan untukmu.\""},"3016":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ مَسْلَمَةَ بْنِ قَعْنَبٍ حَدَّث��نَا سُلَيْمَانُ يَعْنِي ابْنَ بِلَالٍ عَنْ يَحْيَى بْنِ سَعِيدٍ عَنْ يَزِيدَ مَوْلَى الْمُنْبَعِثِ أَنَّهُ سَمِعَ زَيْدَ بْنَ خَالِدٍ الْجُهَنِيَّ صَاحِبَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُاسُئِلَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ اللُّقَطَةِ الذَّهَبِ أَوْ الْوَرِقِ فَقَالَ اعْرِفْ وِكَاءَهَا وَعِفَاصَهَا ثُمَّ عَرِّفْهَا سَنَةً فَإِنْ لَمْ تَعْرِفْ فَاسْتَنْفِقْهَا وَلْتَكُنْ وَدِيعَةً عِنْدَكَ فَإِنْ جَاءَ طَالِبُهَا يَوْمًا مِنْ الدَّهْرِ فَأَدِّهَا إِلَيْهِ وَسَأَلَهُ عَنْ ضَالَّةِ الْإِبِلِ فَقَالَ مَا لَكَ وَلَهَا دَعْهَا فَإِنَّ مَعَهَا حِذَاءَهَا وَسِقَاءَهَا تَرِدُ الْمَاءَ وَتَأْكُلُ الشَّجَرَ حَتَّى يَجِدَهَا رَبُّهَا وَسَأَلَهُ عَنْ الشَّاةِ فَقَالَ خُذْهَا فَإِنَّمَا هِيَ لَكَ أَوْ لِأَخِيكَ أَوْ لِلذِّئْبِو حَدَّثَنِي إِسْحَقُ بْنُ مَنْصُورٍ أَخْبَرَنَا حَبَّانُ بْنُ هِلَالٍ حَدَّثَنَا حَمَّادُ بْنُ سَلَمَةَ حَدَّثَنِي يَحْيَى بْنُ سَعِيدٍ وَرَبِيعَةُ الرَّأْيِ بْنُ أَبِي عَبْدِ الرَّحْمَنِ عَنْ يَزِيدَ مَوْلَى الْمُنْبَعِثِ عَنْ زَيْدِ بْنِ خَالِدٍ الْجُهَنِيِّ أَنَّ رَجُلًا سَأَلَ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ ضَالَّةِ الْإِبِلِ زَادَ رَبِيعَةُ فَغَضِبَ حَتَّى احْمَرَّتْ وَجْنَتَاهُ وَاقْتَصَّ الْحَدِيثَ بِنَحْوِ حَدِيثِهِمْ وَزَادَ فَإِنْ جَاءَ صَاحِبُهَا فَعَرَفَ عِفَاصَهَا وَعَدَدَهَا وَوِكَاءَهَا فَأَعْطِهَا إِيَّاهُ وَإِلَّا فَهِيَ لَكَ","id":"Telah menceritakan kepada kami [Abdullah bin Maslamah bin Qa'nab] telah menceritakan kepada kami [Sulaiman] -yaitu Ibnu Bilal- dari [Yahya bin Sa'id] dari [Yazid] -bekas budak Al Munba'its- bahwa dia mendengar [Zaid bin Khalid Al Juhani] salah seorang sahabat Rasulullah shallallahu 'alaihi wasallam berkata, \"Rasulullah shallallahu 'alaihi wasallam pernah ditanya mengenai barang temuan yang berisi emas atau perak.\" Maka beliau bersabda: \"Kenalilah wadah dan talinya, kemudian umumkanlah selama setahun, apabila pemiliknya tidak datang untuk mengenalinya, maka -untuk sementara waktu- kamu boleh memanfaatkan, dan itu sebagai barang titipan untukmu. Seandainya di suatu hari pemiliknya datang mencari barang tersebut, maka berikanlah barang tersebut kepadanya.\" Lalu dia bertanya menegani temuan unta, maka beliau balik bertanya kepada dia: \"Apa urusanmu dengan unta yang hilang? Biarkanlah unta itu pergi, karena ia membawa sepatu (punya kaki) dan wadah airnya sendiri. Ia dapat mendatangi mata air dan makan dedaunan sampai ia bertemu pemiliknya.\" Orang itu bertanya lagi mengenai temuan kambing, beliau menjawab: \"Ambillah ia, mungkin ia dapat menjadi milikmu atau milik saudaramu atau bahkan menjadi milik serigala.\" Dan telah menceritakan kepadaku [Ishaq bin Manshur] telah mengabarkan kepada kami [Habban bin Hilal] telah menceritakan kepada kami [Hamamd bin Salamah] telah menceritakan kepadaku [Yahya bin Sa'id] dan [Rabi'ah Ar Ra'iy bin Abu Abdurrahman] dari [Yazid] bekas budak Al Munba'its, dari [Zaid bin Khalid Al Juhani], bahwa ada seorang laki-laki yang bertanya kepada Nabi shallallahu 'alaihi wasallam mengenai unta temuan, Rabi'ah menambahkan, \"Lalu beliau marah hingga terlihat wajahnya memerah...lalu dia menceritakan hadits tersebut seperti hadits mereka. Dia juga menambahkan, \"Jika pemiliknya datang dan mengenali talinya, jumlah serta wadahnya maka berikanlah kepadanya, jika tidak maka itu menjadi milikmu.\""},"3017":{"ar":"و حَدَّثَنِي أَبُو الطَّاهِرِ أَحْمَدُ بْنُ عَمْرِو بْنِ سَرْحٍ أَخْبَرَنَا عَبْدُ اللَّهِ بْنُ وَهْبٍ حَدَّثَنِي الضَّحَّاكُ بْنُ عُثْمَانَ عَنْ أَبِي النَّضْرِ عَنْ بُسْرِ بْنِ سَعِيدٍ عَنْ زَيْدِ بْنِ خَالِدٍ الْجُهَنِيِّ قَالَسُئِلَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ اللُّقَطَةِ فَقَالَ عَرِّفْهَا سَنَةً فَإِنْ لَمْ تُعْتَرَفْ فَاعْرِفْ عِفَاصَهَا وَوِكَاءَهَا ثُمَّ كُلْهَا فَإِنْ جَاءَ صَاحِبُهَا فَأَدِّهَا إِلَيْهِو حَدَّثَنِيهِ إِسْحَقُ بْنُ مَنْصُورٍ أَخْبَرَنَا أَبُو بَكْرٍ الْحَنَفِيُّ حَدَّثَنَا الضَّحَّاكُ بْنُ عُثْمَانَ بِهَذَا الْإِسْنَادِ وَقَالَ فِي الْحَدِيثِ فَإِنْ اعْتُرِفَتْ فَأَدِّهَا وَإِلَّا فَاعْرِفْ عِفَاصَهَا وَوِكَاءَهَا وَعَدَدَهَا","id":"Dan telah menceritakan kepadaku [Abu At Thahir Ahmad bin 'Amru bin Sarh] telah mengabarkan kepada kami [Abdullah bin Wahb] telah menceritakan kepadaku [Adl Dlahak bin Utsman] dari [Abu An Nadlr] dari [Busr bin Sa'id] dari [Zaid bin Khalid Al Juhani] dia berkata, \"Rasulullah shallallahu 'alaihi wasallam pernah ditanya mengenai barang temuan, maka beliau menjawab: \"Umumkanlah sampai setahun lamanya, jika ada orang yang mengenalinya, maka kenalilah tali dan wadahnya kemudian makanlah, jika pemiliknya datang maka kembalikanlah ia kepadanya.\" Dan telah menceritakan kepadaku [Ishaq bin Manshur] telah mengabarkan kepada kami [Abu Bakar Al Hanafi] telah menceritakan kepada kami [Ad Dlahak bin Utsman] dengan isnad ini, dan dia menyebutkan dalam haditsnya, \"Jika pemiliknya mengenailnya, maka kembalikanlah ia kepadanya, jika tidak (dapat mengenalinya) maka kenalilah tali, wadah dan jumlahnya.\""},"3018":{"ar":"و حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ حَدَّثَنَا شُعْبَةُ ح و حَدَّثَنِي أَبُو بَكْرِ بْنُ نَافِعٍ وَاللَّفْظُ لَهُ حَدَّثَنَا غُنْدَرٌ حَدَّثَنَا شُعْبَةُ عَنْ سَلَمَةَ بْنِ كُهَيْلٍ قَالَ سَمِعْتُ سُوَيْدَ بْنَ غَفَلَةَ قَالَ خَرَجْتُ أَنَا وَزَيْدُ بْنُ صُوحَانَ وَسَلْمَانُ بْنُ رَبِيعَةَ غَازِينَ فَوَجَدْتُ سَوْطًا فَأَخَذْتُهُ فَقَالَا لِي دَعْهُ فَقُلْتُ لَا وَلَكِنِّي أُعَرِّفُهُ فَإِنْ جَاءَ صَاحِبُهُ وَإِلَّا اسْتَمْتَعْتُ بِهِ قَالَ فَأَبَيْتُ عَلَيْهِمَا فَلَمَّا رَجَعْنَا مِنْ غَزَاتِنَا قُضِيَ لِي أَنِّي حَجَجْتُ فَأَتَيْتُ الْمَدِينَةَ فَلَقِيتُ أُبَيَّ بْنَ كَعْبٍ فَأَخْبَرْتُهُ بِشَأْنِ السَّوْطِ وَبِقَوْلِهِمَا فَقَالَإِنِّي وَجَدْتُ صُرَّةً فِيهَا مِائَةُ دِينَارٍ عَلَى عَهْدِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَتَيْتُ بِهَا رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ عَرِّفْهَا حَوْلًا قَالَ فَعَرَّفْتُهَا فَلَمْ أَجِدْ مَنْ يَعْرِفُهَا ثُمَّ أَتَيْتُهُ فَقَالَ عَرِّفْهَا حَوْلًا فَعَرَّفْتُهَا فَلَمْ أَجِدْ مَنْ يَعْرِفُهَا ثُمَّ أَتَيْتُهُ فَقَالَ عَرِّفْهَا حَوْلًا فَعَرَّفْتُهَا فَلَمْ أَجِدْ مَنْ يَعْرِفُهَا فَقَالَ احْفَظْ عَدَدَهَا وَوِعَاءَهَا وَوِكَاءَهَا فَإِنْ جَاءَ صَاحِبُهَا وَإِلَّا فَاسْتَمْتِعْ بِهَا فَاسْتَمْتَعْتُ بِهَا فَلَقِيتُهُ بَعْدَ ذَلِكَ بِمَكَّةَ فَقَالَ لَا أَدْرِي بِثَلَاثَةِ أَحْوَالٍ أَوْ حَوْلٍ وَاحِدٍو حَدَّثَنِي عَبْدُ الرَّحْمَنِ بْنُ بِشْرٍ الْعَبْدِيُّ حَدَّثَنَا بَهْزٌ حَدَّثَنَا شُعْبَةُ أَخْبَرَنِي سَلَمَةُ بْنُ كُهَيْلٍ أَوْ أَخْبَرَ الْقَوْمَ وَأَنَا فِيهِمْ قَالَ سَمِعْتُ سُوَيْدَ بْنَ غَفَلَةَ قَالَ خَرَجْتُ مَعَ زَيْدِ بْنِ صُوحَانَ وَسَلْمَانَ بْنِ رَبِيعَةَ فَوَجَدْتُ سَوْطًا وَاقْتَصَّ الْحَدِيثَ بِمِثْلِهِ إِلَى قَوْلِهِ فَاسْتَمْتَعْتُ بِهَا قَالَ شُعْبَةُ فَسَمِعْتُهُ بَعْدَ عَشْرِ سِنِينَ يَقُولُ عَرَّفَهَا عَامًا وَاحِدًا و حَدَّثَنَا قُتَيْبَةُ بْنُ سَعِيدٍ حَدَّثَنَا جَرِيرٌ عَنْ الْأَعْمَشِ ح و حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا وَكِيعٌ ح و حَدَّثَنَا ابْنُ نُمَيْرٍ حَدَّثَنَا أَبِي جَمِيعًا عَنْ سُفْيَانَ ح و حَدَّثَنِي مُحَمَّدُ بْنُ حَاتِمٍ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ جَعْفَرٍ الرَّقِّيُّ حَدَّثَنَا عُبَيْدُ اللَّهِ يَعْنِي ابْنَ عَمْرٍو عَنْ زَيْدِ بْنِ أَبِي أُنَيْسَةَ ح و حَدَّثَنِي عَبْدُ الرَّحْمَنِ بْنُ بِشْرٍ حَدَّثَنَا بَهْزٌ حَدَّثَنَا حَمَّادُ بْنُ سَلَمَةَ كُلُّ هَؤُلَاءِ عَنْ سَلَمَةَ بْنِ كُهَيْلٍ بِهَذَا الْإِسْنَادِ نَحْوَ حَدِيثِ شُعْبَةَ وَفِي حَدِيثِهِمْ جَمِيعًا ثَلَاثَةَ أَحْوَالٍ إِلَّا حَمَّادَ بْنَ سَلَمَةَ فَإِنَّ فِي حَدِيثِهِ عَامَيْنِ أَوْ ثَلَاثَةً وَفِي حَدِيثِ سُفْيَانَ وَزَيْدِ بْنِ أَبِي أُنَيْسَةَ وَحَمَّادِ بْنِ سَلَمَةَ فَإِنْ جَاءَ أَحَدٌ يُخْبِرُكَ بِعَدَدِهَا وَوِعَائِهَا وَوِكَائِهَا فَأَعْطِهَا إِيَّاهُ وَزَادَ سُفْيَانُ فِي رِوَايَةِ وَكِيعٍ وَإِلَّا فَهِيَ كَسَبِيلِ مَالِكَ وَفِي رِوَايَةِ ابْنِ نُمَيْرٍ وَإِلَّا فَاسْتَمْتِعْ بِهَا","id":"Dan telah menceritakan kepada kami [Muhammad bin Basyar] telah menceritakan kepada kami [Muhammad bin Ja'far] telah menceritakan kepada kami [Syu'bah]. (dalam jalur lain disebutkan) Telah menceritakan kepadaku [Abu Bakar bin Nafi'] sedangkan lafadznya dari dia, telah menceritakan kepada kami [Ghundar] telah menceritakan kepada kami [Syu'bah] dari [Salamah bin Kuhail] dia berkata; aku mendengar [Suwaid bin Ghafalah] dia berkata, \"Aku bersama Zaid bin Shuhan serta Salman bin Rabi'ah pergi berperang, di tengah perjalanan aku menemukan cemeti dan kuambil. Maka kedua temanku tersebut berkata, \"Jangan diambil, biarkan saja.\" Maka aku menimpalinya, 'Tidak, tetapi aku akan mengumumkannya, jika pemiliknya datang meminta aku akan berikan kepadanya, namun jika tidak ada yang datang meminta, aku akan memanfaatkannya sendiri.' Aku tidak setuju dengan pendapat kedua kawanku itu. Setelah kami kembali dari peperangan, Allah mentakdirkanku untuk menunaikan ibadah haji, setibanya aku di Madinah, aku bertemu dengan [Ubay bin Ka'ab], lantas aku memeberitahukan kepadanya perihal cambuk temuanku dan pendapat kedua kawanku tentangnya. Dia menjawab, \"Pada masa Rasulullah shallallahu 'alaihi wasallam, aku juga pernah menemukan pundi-pundi berisi seratus dinar emas, lalu pundi-pundi itu aku bawa ke hadapan Rasulullah shallallahu 'alaihi wasallam, lantas beliau bersabda: \"Umumkanlah selama setahun.\" Maka aku mengumumkannya selama setahun, namun tidak ada seorang pun yang mengakuinya. Kemudian aku bawa kembali kepada Rasulullah shallallahu 'alaihi wasallam, beliau bersabda: \"Umumkanlah selama setahun.\" Lalu aku mengumumkannya lagi, akan tetapi tidak ada seorang pun yang memintanya. Maka beliau bersabda: \"Catatlah berapa jumlahnya, tandai tali pengikat dan wadahnya, jika pemiliknya datang dan memintanya maka berikanlah kepadanya, jika tidak ada yang datang meminta maka kamu boleh mempergunakannya.\" Akhirnya emas itu aku pergunakan untuk keperluanku, lalu aku bertemu dengannya di Makkah, dia berkata, \"Aku tidak tahu apakah dia mengumumkan sampai tiga tahun atau hanya setahun.\" Dan telah menceritakan kepadaku [Abdurrahman bin Bisyr Al 'Abdi] telah menceritakan kepada kami [Bahs] telah menceritakan kepada kami [Syu'bah] telah mengabarkan kepadaku [Salamah bin Kuhail] atau dia telah mengabarkan kepada suatu kaum, sedangkan aku termasuk yang ikut mendengarnya, dia berkata; aku pernah mendengar [Suwaid bin Ghafalah] berkata, \"Aku pergi bersama Zaid bin Shuhan dan Salman bin Rabi'ah, lalu aku menemukan cemeti …lalu dia meneruskan seperti hadits di atas, sampai kepada perkataannya, 'Kemudian aku pergunakan untuk keperluanku'.\" Syu'bah berkata, \"Aku pernah mendengarnya sejak sepuluh tahun yang lalu, bahwa dia berkata, \"Umumkanlah selama setahun.\" Dan telah menceritakan kepada kami [Qutaibah bin Sa'id] telah menceritakan kepada kami [Jarir] dari [Al A'masy]. (dalam jalur lain disebutkan) Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] telah menceritakan kepada kami [Waki']. (dalam jalur lain disebutkan) Telah menceritakan kepada kami [Ibnu Numair] telah menceritakan kepada kami [ayahku] semuanya dari [Sufyan]. (dalam jalur lain disebutkan) Telah menceritakan kepadaku [Muhammad bin Hatim] telah menceritakan kepada kami [Abdullah bin Ja'far Ar Raqi] telah menceritakan kepada kami [Ubaidullah] -yaitu Ibnu 'Amru- dari [Zaid bin Abu Unaisah]. (dalam jalur lain disebutkan) Telah menceritakan kepadaku [Abdurrahman bin Bisyr] telah menceritakan kepada kami [Bahs] telah menceritakan kepada kami [Hammad bin salamah] mereka semua dari [Salamah bin Kuhail] dengan isnad ini yang semakna dengan hadits Syu'bah. Dan dalam hadits mereka semua disebutkan, 'Tiga tahun', kecuali hadits Hamamd bin Salamah, disebutkan, 'dua tahun atau tiga tahun'.\" Dan dalam hadits Sufyan dan Zaid bin Abu Unaisah serta Hammad bin Salamh disebutkan, 'Jika ada seseorang datang kepadamu dan memberitahukan jumlahnya, wadahnya, dan talinya, maka berikanlah kepadanya'. Sufyan menambahkan dalam riwayatnya Waki', 'Jika tidak, maka ia seperti hak kepemilikan'. Dan dalam riwayatnya Ibnu Numair disebutkan, 'Jika tidak, maka pergunakanlah ia'.\""},"3019":{"ar":"حَدَّثَنِي أَبُو الطَّاهِرِ وَيُونُسُ بْنُ عَبْدِ الْأَعْلَى قَالَا أَخْبَرَنَا عَبْدُ اللَّهِ بْنُ وَهْبٍ أَخ��بَرَنِي عَمْرُو بْنُ الْحَارِثِ عَنْ بُكَيْرِ بْنِ عَبْدِ اللَّهِ بْنِ الْأَشَجِّ عَنْ يَحْيَى بْنِ عَبْدِ الرَّحْمَنِ بْنِ حَاطِبٍ عَنْ عَبْدِ الرَّحْمَنِ بْنِ عُثْمَانَ التَّيْمِيِّأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَهَى عَنْ لُقَطَةِ الْحَاجِّ","id":"Telah menceritakan kepadaku [Abu At Thahir] dan [Yunus bin Abdul A'la] keduanya berkata; telah mengabarkan kepada kami [Abdullah bin Wahb] telah mengabarkan kepadaku [Amru bin Al Harits] dari [Bukair bin Abdullah Al Asyaj] dari [Yahya bin Abdurrahman bin Hathib] dari [Abdurrahman bin 'Utsman At Taimi], bahwa Rasulullah shallallahu 'alaihi wasallam melarang mengambil barang temuan (jamaah) haji.\""},"3020":{"ar":"و حَدَّثَنِي أَبُو الطَّاهِرِ وَيُونُسُ بْنُ عَبْدِ الْأَعْلَى قَالَا حَدَّثَنَا عَبْدُ اللَّهِ بْنُ وَهْبٍ قَالَ أَخْبَرَنِي عَمْرُو بْنُ الْحَارِثِ عَنْ بَكْرِ بْنِ سَوَادَةَ عَنْ أَبِي سَالِمٍ الْجَيْشَانِيِّ عَنْ زَيْدِ بْنِ خَالِدٍ الْجُهَنِيِّعَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهُ قَالَ مَنْ آوَى ضَالَّةً فَهُوَ ضَالٌّ مَا لَمْ يُعَرِّفْهَا","id":"Dan telah menceritakan kepadaku [Abu At Thahir] dan [Yunus bin Abdul A'la] keduanya berkata; telah menceritakan kepada kami [Abdullah bin Wahb] dia berkata; telah mengabarkan kepadaku ['Amru bin Harits] dari [Bakr bin Sawadah] dari [Abu Salim Al Jaisyani] dari [Zaid bin Khalid Al Juhani] dari Rasulullah shallallahu 'alaihi wasallam, bahwa beliau bersabda: \"Barangsiapa menyembunyikan barang temuan (emas atau perak), maka dia bersalah selama tidak mengumumkannya.\""},"3021":{"ar":"حَدَّثَنَا يَحْيَى بْنُ يَحْيَى التَّمِيمِيُّ قَالَ قَرَأْتُ عَلَى مَالِكِ بْنِ أَنَسٍ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَا يَحْلُبَنَّ أَحَدٌ مَاشِيَةَ أَحَدٍ إِلَّا بِإِذْنِهِ أَيُحِبُّ أَحَدُكُمْ أَنْ تُؤْتَى مَشْرُبَتُهُ فَتُكْسَرَ خِزَانَتُهُ فَيُنْتَقَلَ طَعَامُهُ إِنَّمَا تَخْزُنُ لَهُمْ ضُرُوعُ مَوَاشِيهِمْ أَطْعِمَتَهُمْ فَلَا يَحْلُبَنَّ أَحَدٌ مَاشِيَةَ أَحَدٍ إِلَّا بِإِذْنِهِو حَدَّثَنَاه قُتَيْبَةُ بْنُ سَعِيدٍ وَمُحَمَّدُ بْنُ رُمْحٍ جَمِيعًا عَنْ اللَّيْثِ بْنِ سَعْدٍ ح و حَدَّثَنَاه أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا عَلِيُّ بْنُ مُسْهِرٍ ح و حَدَّثَنَا ابْنُ نُمَيْرٍ حَدَّثَنِي أَبِي كِلَاهُمَا عَنْ عُبَيْدِ اللَّهِ ح و حَدَّثَنِي أَبُو الرَّبِيعِ وَأَبُو كَامِلٍ قَالَا حَدَّثَنَا حَمَّادٌ ح و حَدَّثَنِي زُهَيْرُ بْنُ حَرْبٍ حَدَّثَنَا إِسْمَعِيلُ يَعْنِي ابْنَ عُلَيَّةَ جَمِيعًا عَنْ أَيُّوبَ ح و حَدَّثَنَا ابْنُ أَبِي عُمَرَ حَدَّثَنَا سُفْيَانُ عَنْ إِسْمَعِيلَ بْنِ أُمَيَّةَ ح و حَدَّثَنَا مُحَمَّدُ بْنُ رَافِعٍ حَدَّثَنَا عَبْدُ الرَّزَّاقِ عَنْ مَعْمَرٍ عَنْ أَيُّوبَ وَابْنُ جُرَيْجٍ عَنْ مُوسَى كُلُّ هَؤُلَاءِ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَحْوَ حَدِيثِ مَالِكٍ غَيْرَ أَنَّ فِي حَدِيثِهِمْ جَمِيعًا فَيُنْتَثَلَ إِلَّا اللَّيْثَ بْنَ سَعْدٍ فَإِنَّ فِي حَدِيثِهِ فَيُنْتَقَلَ طَعَامُهُ كَرِوَايَةِ مَالِكٍ","id":"Telah menceritakan kepada kami [Yahya bin Yahya At Tamimi] dia berkata; aku bacakan di hadapan [Malik bin Anas]; dari [Nafi'] dari [Ibnu Umar] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Janganlah salah seorang dari kalian memeras susu ternak orang lain kecuali minta izin darinya, sukakah salah seorang dari kalian jika wadah airnya diberikan namun tempat penyimpanannya dipecahkan serta makanannya dipindahkan? Hanyasanya kantung-kantung susu kambing merekalah yang menjadi tempat penyimpanan makanan mereka, maka jangan sekali-kali salah seorang dari kalian memerah susu ternak orang lain tanpa izin pemiliknya.\" Dan telah menceritakan kepada kami [Qutaibah bin Sa'id] dan [Muhammad bin Rumh] semuanya dari [Laits bin Sa'd]. (dalam riwayat lain disebutkan) Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] telah menceritakan kepada kami [Ali bin Mushir]. (dalam riwayat lain disebutkan) Telah menceritakan kepada kami [Ibnu Numair] telah menceritakan kepadaku [ayahku] keduanya dari [Ubaidullah]. (dalam riwayat lain disebutkan) Telah menceritakan kepadaku [Abu Ar Rabi'] dan [Abu Kamil] keduanya berkata; telah menceritakan kepada kami [Hammad]. (dalam riwayat lain disebutkan) Telah menceritakan kepadaku [Zuhair bin Harb] telah menceritakan kepada kami [Isma'il] -yaitu Ibnu 'Ulayyah- semuanya dari [Ayyub]. (dalam riwayat lain disebutkan) Telah menceritakan kepada kami [Ibnu Abu 'Umar] telah menceritakan kepada kami [Sufyan] dari [Isma'il bin Umayyah]. (dalam riwayat lain disebutkan) Telah menceritakan kepada kami [Muhammad bin Rafi'] telah menceritakan kepada kami [Abdurrazaq] dari [Ma'mar] dari [Ayyub] dan [Ibnu Juraij] dari [Musa] mereka semua dari [Nafi'] dari [Ibnu Umar] dari Nabi shallallahu 'alaihi wasallam seperti hadits Malik, hanya saja hadits mereka semua disebutkan, 'hendaknya dia memberikan sebagian makanannya', kecuali riwayat Laits bin Sa'd disebutkan, 'hendaknya memberikan makanannya', sebagaimana riwayat Malik.\""},"3022":{"ar":"حَدَّثَنَا قُتَيْبَةُ بْنُ سَعِيدٍ حَدَّثَنَا لَيْثٌ عَنْ سَعِيدِ بْنِ أَبِي سَعِيدٍ عَنْ أَبِي شُرَيْحٍ الْعَدَوِيِّ أَنَّهُ قَالَسَمِعَتْ أُذُنَايَ وَأَبْصَرَتْ عَيْنَايَ حِينَ تَكَلَّمَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ مَنْ كَانَ يُؤْمِنُ بِاللَّهِ وَالْيَوْمِ الْآخِرِ فَلْيُكْرِمْ ضَيْفَهُ جَائِزَتَهُ قَالُوا وَمَا جَائِزَتُهُ يَا رَسُولَ اللَّهِ قَالَ يَوْمُهُ وَلَيْلَتُهُ وَالضِّيَافَةُ ثَلَاثَةُ أَيَّامٍ فَمَا كَانَ وَرَاءَ ذَلِكَ فَهُوَ صَدَقَةٌ عَلَيْهِ وَقَالَ مَنْ كَانَ يُؤْمِنُ بِاللَّهِ وَالْيَوْمِ الْآخِرِ فَلْيَقُلْ خَيْرًا أَوْ لِيَصْمُتْ","id":"Telah menceritakan kepada kami [Qutaibah bin Sa'id] telah menceritakan kepada kami [Laits] dari [Sa'id bin Abu Sa'id] dari [Abu Syuraih Al 'Adawi] bahwa dia berkata, \"Aku telah mendengar dengan kedua telingaku dan melihat dengan kedua mataku, ketika Rasulullah shallallahu 'alaihi wasallam mengucapkan sabdanya: \"Barangsiapa beriman kepada Allah dan hari akhir maka hendaklah memuliakan tamu dan menjamunya?\" mereka bertanya, \"Apa yang dimaksud dengan menjamunya wahai Rasulullah?\" beliau menjawab: \"Yaitu pada siang dan malam harinya, bertamu itu tiga hari, lebih dari itu adalah sedekah bagi tamu tersebut.\" Dan beliau bersabda: \"Barangsiapa beriman kepada Allah dan hari akhir, hendaknya dia berkata dengan perkataan yang baik atau diam.\""},"3023":{"ar":"حَدَّثَنَا أَبُو كُرَيْبٍ مُحَمَّدُ بْنُ الْعَلَاءِ حَدَّثَنَا وَكِيعٌ حَدَّثَنَا عَبْدُ الْحَمِيدِ بْنُ جَعْفَرٍ عَنْ سَعِيدِ بْنِ أَبِي سَعِيدٍ الْمَقْبُرِيِّ عَنْ أَبِي شُرَيْحٍ الْخُزَاعِيِّ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الضِّيَافَةُ ثَلَاثَةُ أَيَّامٍ وَجَائِزَتُهُ يَوْمٌ وَلَيْلَةٌ وَلَا يَحِلُّ لِرَجُلٍ مُسْلِمٍ أَنْ يُقِيمَ عِنْدَ أَخِيهِ حَتَّى يُؤْثِمَهُ قَالُوا يَا رَسُولَ اللَّهِ وَكَيْفَ يُؤْثِمُهُ قَالَ يُقِيمُ عِنْدَهُ وَلَا شَيْءَ لَهُ يَقْرِيهِ بِهِو حَدَّثَنَاه مُحَمَّدُ بْنُ الْمُثَنَّى حَدَّثَنَا أَبُو بَكْرٍ يَعْنِي الْحَنَفِيَّ حَدَّثَنَا عَبْدُ الْحَمِيدِ بْنُ جَعْفَرٍ حَدَّثَنَا سَعِيدٌ الْمَقْبُرِيُّ أَنَّهُ سَمِعَ أَبَا شُرَيْحٍ الْخُزَاعِيَّ يَقُولُا سَمِعَتْ أُذُنَايَ وَبَصُرَ عَيْنِي وَوَعَاهُ قَلْبِي حِينَ تَكَلَّمَ بِهِ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَذَكَرَ بِمِثْلِ حَدِيثِ اللَّيْثِ وَذَكَرَ فِيهِ وَلَا يَحِلُّ لِأَحَدِكُمْ أَنْ يُقِيمَ عِنْدَ أَخِيهِ حَتَّى يُؤْثِمَهُ بِمِثْلِ مَا فِي حَدِيثِ وَكِيعٍ","id":"Telah menceritakan kepada kami [Abu Kuraib Muhammad bin Al 'Ala] telah menceritakan kepada kami [Waki'] telah menceritakan kepada kami [Abdul Hamid bin Ja'far] dari [Sa'id bin Abu Sa'id Al Maqburi] dari [Abu Syuraih Al Khuza'i] dia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Bertamu itu selama tiga hari, dan pelayanannya selama siang atau malam hari. Tidak halal bagi seorang muslim bermukim di rumah saudaranya sampai saudaranya berdosa karenanya.\" Para sahabat bertanya, \"Wahai Rasulullah, bagaimana dia bisa berdosa?\" beliau menjawab: \"Dia bermukim di rumah saudaranya hingga saudaranya tidak punya apa-apa lagi untuk menjamunya.\" Dan telah menceritakan kepada kami [Muhammad bin Al Mutsanna] telah menceritakan kepada kami [Abu Bakar] -yaitu Al Hanafi- telah menceritakan kepada kami [Abdul Hamid bin Ja'far] telah menceritakan kepada kami [Sa'id Al Maqbury] bahwa dia mendengar [Abu Syuraih Al Khuza'i] berkata, \"Aku mendengar sendiri dengan kedua telingaku, melihat dengan kedua mataku dan hatiku ketika Rasulullah shallallahu 'alaihi wasallam mengucapkan sabdanya…kemudian dia menyebutkan seperti haditsnya Laits, dan dalam hadits tersebut ia menyebutkan, \"Dan tidak dihalalkan salah seorang dari kalian bermukim di tempat saudaranya hingga saudaranya berdosa karenanya…seperti hadits riwayat Waki'.\""},"3024":{"ar":"حَدَّثَنَا قُتَيْبَةُ بْنُ سَعِيدٍ حَدَّثَنَا لَيْثٌ ح و حَدَّثَنَا مُحَمَّدُ بْنُ رُمْحٍ أَخْبَرَنَا اللَّيْثُ عَنْ يَزِيدَ بْنِ أَبِي حَبِيبٍ عَنْ أَبِي الْخَيْرِ عَنْ عُقْبَةَ بْنِ عَامِرٍ أَنَّهُ قَالَقُلْنَا يَا رَسُولَ اللَّهِ إِنَّكَ تَبْعَثُنَا فَنَنْزِلُ بِقَوْمٍ فَلَا يَقْرُونَنَا فَمَا تَرَى فَقَالَ لَنَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنْ نَزَلْتُمْ بِقَوْمٍ فَأَمَرُوا لَكُمْ بِمَا يَنْبَغِي لِلضَّيْفِ فَاقْبَلُوا فَإِنْ لَمْ يَفْعَلُوا فَخُذُوا مِنْهُمْ حَقَّ الضَّيْفِ الَّذِي يَنْبَغِي لَهُمْ","id":"Telah menceritakan kepada kami [Qutaibah bin Sa'id] telah menceritakan kepada kami [Laits]. (dalam jalur lain disebutkan) Telah menceritakan kepada kami [Muhammad bin Rumh] telah mengabarkan kepada kami [Laits] dari [Yazid bin Abu Habib] dari [Abu Al Khair] dari ['Uqbah bin 'Amir] bahwa dia berkata, \"Kami pernah bertanya, \"Wahai Rasulullah, sesungguhnya anda mengirim kami, lalu kami singgah di suatu kaum sebagai tamu, akan tetapi mereka tidak melayani kami sebagaimana layaknya, bagaimana menurut anda?\" maka Rasulullah shallallahu 'alaihi wasallam bersabda kepada kami: \"Jika kalian singgah di suatu kaum, lalu mereka melayani kalian sebagaimana layaknya seorang tamu maka terimalah layanan mereka. Jika mereka tidak melayani kalian, maka kalian boleh mengambil dari mereka hak tamu yang pantas mereka berikan.\""},"3025":{"ar":"حَدَّثَنَا شَيْبَانُ بْنُ فَرُّوخَ حَدَّثَنَا أَبُو الْأَشْهَبِ عَنْ أَبِي نَضْرَةَ عَنْ أَبِي سَعِيدٍ الْخُدْرِيِّ قَالَبَيْنَمَا نَحْنُ فِي سَفَرٍ مَعَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذْ جَاءَ رَجُلٌ عَلَى رَاحِلَةٍ لَهُ قَالَ فَجَعَلَ يَصْرِفُ بَصَرَهُ يَمِينًا وَشِمَالًا فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ كَانَ مَعَهُ فَضْلُ ظَهْرٍ فَلْيَعُدْ بِهِ عَلَى مَنْ لَا ظَهْرَ لَهُ وَمَنْ كَانَ لَهُ فَضْلٌ مِنْ زَادٍ فَلْيَعُدْ بِهِ عَلَى مَنْ لَا زَادَ لَهُ قَالَ فَذَكَرَ مِنْ أَصْنَافِ الْمَالِ مَا ذَكَرَ حَتَّى رَأَيْنَا أَنَّهُ لَا حَقَّ لِأَحَدٍ مِنَّا فِي فَضْلٍ","id":"Telah menceritakan kepada kami [Syaiban bin Farruh] telah menceritakan kepada kami [Abu Al Asyhab] dari [Abu Nashrah] dari [Sa'id Al Khudri] dia berkata, \"Ketika kami dalam perjalanan bersama-sama dengan Nabi shallallahu 'alaihi wasallam, tiba-tiba ada seorang laki-laki datang dengan mengendarai kendaraannya sambil menoleh ke kanan dan ke kiri, maka Rasulullah shallallahu 'alaihi wasallam bersabda: \"Siapa yang memiliki kelebihan tempat pada kendaraannya, hendaklah dia memberikannya kepada orang yang tidak memiliki tempat, dan siapa yang memiliki kelebihan perbekalan hendaklah dia memberikannya kepada orang yang tidak memiliki perbekalan.\" Abu Sa'id berkata, \"Lalu beliau menyebutkan golongan yang berhak mendapatkan harta sehingga kami melihat bahwa tidak ada lagi dari kami yang berhak mendapatkan kelebihan harta.\""},"3026":{"ar":"حَدَّثَنِي أَحْمَدُ بْنُ يُوسُفَ الْأَزْدِيُّ حَدَّثَنَا النَّضْرُ يَعْنِي ابْنَ مُحَمَّدٍ الْيَمَامِيَّ حَدَّثَنَا عِكْرِمَةُ وَهُوَ ابْنُ عَمَّارٍ حَدَّثَنَا إِيَاسُ بْنُ سَلَمَةَ عَنْ أَبِيهِ قَالَخَرَجْنَا مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي غَزْوَةٍ فَأَصَابَنَا جَهْدٌ حَتَّى هَمَمْنَا أَنْ نَنْحَرَ بَعْضَ ظَهْرِنَا فَأَمَرَ نَبِيُّ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَجَمَعْنَا مَزَاوِدَنَا فَبَسَطْنَا لَهُ نِطَعًا فَاجْتَمَعَ زَادُ الْقَوْمِ عَلَى النِّطَعِ قَالَ فَتَطَاوَلْتُ لِأَحْزِرَهُ كَمْ هُوَ فَحَزَرْتُهُ كَرَبْضَةِ الْعَنْزِ وَنَحْنُ أَرْبَعَ عَشْرَةَ مِائَةً قَالَ فَأَكَلْنَا حَتَّى شَبِعْنَا جَمِيعًا ثُمَّ حَشَوْنَا جُرُبَنَا فَقَالَ نَبِيُّ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَهَلْ مِنْ وَضُوءٍ قَالَ فَجَاءَ رَجُلٌ بِإِدَاوَةٍ لَهُ فِيهَا نُطْفَةٌ فَأَفْرَغَهَا فِي قَدَحٍ فَتَوَضَّأْنَا كُلُّنَا نُدَغْفِقُهُ دَغْفَقَةً أَرْبَعَ عَشْرَةَ مِائَةً قَالَ ثُمَّ جَاءَ بَعْدَ ذَلِكَ ثَمَانِيَةٌ فَقَالُوا هَلْ مِنْ طَهُورٍ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَرِغَ الْوَضُوءُ","id":"Telah menceritakan kepadaku [Ahmad bin Yusuf Al Azdi] telah menceritakan kepada kami [An Nadlr] -yaitu Ibnu Muhamamd Al Yamami- telah menceritakan kepada kami [Ikrimah] -yaitu Ibnu 'Ammar- telah menceritakan kepada kami [Iyas bin Salamah] dari [ayahnya] dia berkata, \"Suatu ketika, kami pernah keluar bersama Rasulullah shallallahu 'alaihi wasallam dalam sebuah peperangan, lalu kami mendapat kesulitan sampai-sampai kami berniat untuk mengorbankan sebagian dari unta tunggangan kami. Lalu Nabi shallallahu 'alaihi wasallam menyuruh kami untuk mengumpulkan semua perbekalan kami, lalu kamipun membentangkan sebuah tikar hingga semua perbekalan kami terkumpul di atas tikar tersebut.\" Salamah berkata, \"Lalu aku berusaha menghitung jumlah anggota pasukan saat itu, seperti halnya seorang pengembala kambing, dan ternyata kami saat itu berjumlah seratus empat belas.\" Salamah melanjutkan, \"Kemudian kami makan hingga kami semua merasa kenyang, lalu kami mengisi kantong kulit kami. Kemudian Nabi Allah shallallahu 'alaihi wasallam bersabda: \"Adakah air untuk berwudlu?\" Maka datanglah seorang lelaki dengan membawa kantong airnya, lalu beliau menuangkannya ke dalam ember, hingga kami semua yang saat berjumlah seratus empat belas orang dapat berwudlu dengannya.\" Salamah melanjutkan, \"Setelah itu ada delapan orang yang datang dan menanyakan, \"Apakah masih ada air untuk bersuci?\" Rasulullah shallallahu 'alaihi wasallam menjawab: \"Air wudlu telah habis.\""},"3027":{"ar":"حَدَّثَنَا يَحْيَى بْنُ يَحْيَى التَّمِيمِيُّ حَدَّثَنَا سُلَيْمُ بْنُ أَخْضَرَ عَنْ ابْنِ عَوْنٍ قَالَ كَتَبْتُ إِلَى نَافِعٍ أَسْأَلُهُ عَنْ الدُّعَاءِ قَبْلَ الْقِتَالِ قَالَفَكَتَبَ إِلَيَّ إِنَّمَا كَانَ ذَلِكَ فِي أَوَّلِ الْإِسْلَامِ قَدْ أَغَارَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَلَى بَنِي الْمُصْطَلِقِ وَهُمْ غَارُّونَ وَأَنْعَامُهُمْ تُسْقَى عَلَى الْمَاءِ فَقَتَلَ مُقَاتِلَتَهُمْ وَسَبَى سَبْيَهُمْ وَأَصَابَ يَوْمَئِذٍ قَالَ يَحْيَى أَحْسِبُهُ قَالَ جُوَيْرِيَةَ أَوْ قَالَ الْبَتَّةَ ابْنَةَ الْحَارِثِ وَحَدَّثَنِي هَذَا الْحَدِيثَ عَبْدُ اللَّهِ بْنُ عُمَرَ وَكَانَ فِي ذَاكَ الْجَيْشِو حَدَّثَنَا مُحَمَّدُ بْنُ الْمُثَنَّى حَدَّثَنَا ابْنُ أَبِي عَدِيٍّ عَنْ ابْنِ عَوْنٍ بِهَذَا الْإِسْنَادِ مِثْلَهُ وَقَالَ جُوَيْرِيَةَ بِنْتَ الْحَارِثِ وَلَمْ يَشُكَّ","id":"Telah menceritakan kepada kami [Yahya bin Yahya At Tamimi] telah menceritakan kepada kami [Sulaim bin Ahdlar] dari [Ibnu 'Aun] dia berkata, \"Aku pernah mengirim surat kepada [Nafi'] dan bertanya perihal pernyataan perang sebelum perang di mulai.\" Ibnu 'Aun melanjutkan, \"Lalu Nafi' membalas suratku, tulisnya, 'Hal itu pernah terjadi pada permulaan Islam, suatu ketika Rasulullah shallallahu 'alaihi wasallam menyerang Bani Musthaliq secara mendadak disaat mereka sedang lengah, yaitu ketika mereka sedang memberi minum ternak mereka. Kemudian terjadilah perang hingga mereka banyak yang terbunuh dan tertawan, dan pada hari itulah Juwairiyah binti Hatits tertawan'.\" [Yahya] berkata, \"Aku kira dia mengatakan, 'Juwairiyah' atau, 'anak gadisnya Al Harits'. Hadits ini disampaikan kepadaku oleh [Abdullah bin Umar], saat itu dia termasuk orang yang ikut berperang sebagai prajurit dalam pasukan.\" Dan telah menceritakan kepada kami [Muhammad bin Al Mutsanna] telah menceritakan kepada kami [Ibnu Abu Adi] dari [Ibnu 'Aun] dengan isnad seperti ini. Ibnu 'Aun berkata, \"Yaitu Juwairiyah binti Al Harits -tanpa ada keraguan-.\""},"3028":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا وَكِيعُ بْنُ الْجَرَّاحِ عَنْ سُفْيَانَ ح و حَدَّثَنَا إِسْحَقُ بْنُ إِبْرَاهِيمَ أَخْبَرَنَا يَحْيَى بْنُ آدَمَ حَدَّثَنَا سُفْيَانُ قَالَ أَمْلَاهُ عَلَيْنَا إِمْلَاءً ح و حَدَّثَنِي عَبْدُ اللَّهِ بْنُ هَاشِمٍ وَاللَّفْظُ لَهُ حَدَّثَنِي عَبْدُ الرَّحْمَنِ يَعْنِي ابْنَ مَهْدِيٍّ حَدَّثَنَا سُفْيَانُ عَنْ عَلْقَمَةَ بْنِ مَرْثَدٍ عَنْ سُلَيْمَانَ بْنِ بُرَيْدَةَ عَنْ أَبِيهِ قَالَكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا أَمَّرَ أَمِيرًا عَلَى جَيْشٍ أَوْ سَرِيَّةٍ أَوْصَاهُ فِي خَاصَّتِهِ بِتَقْوَى اللَّهِ وَمَنْ مَعَهُ مِنْ الْمُسْلِمِينَ خَيْرًا ثُمَّ قَالَ اغْزُوا بِاسْمِ اللَّهِ فِي سَبِيلِ اللَّهِ قَاتِلُوا مَنْ كَفَرَ بِاللَّهِ اغْزُوا وَلَا تَغُلُّوا وَلَا تَغْدِرُوا وَلَا تَمْثُلُوا وَلَا تَقْتُلُوا وَلِيدًا وَإِذَا لَقِيتَ عَدُوَّكَ مِنْ الْمُشْرِكِينَ فَادْعُهُمْ إِلَى ثَلَاثِ خِصَالٍ أَوْ خِلَالٍ فَأَيَّتُهُنَّ مَا أَجَابُوكَ فَاقْبَلْ مِنْهُمْ وَكُفَّ عَنْهُمْ ثُمَّ ادْعُهُمْ إِلَى الْإِسْلَامِ فَإِنْ أَجَابُوكَ فَاقْبَلْ مِنْهُمْ وَكُفَّ عَنْهُمْ ثُمَّ ادْعُهُمْ إِلَى التَّحَوُّلِ مِنْ دَارِهِمْ إِلَى دَارِ الْمُهَاجِرِينَ وَأَخْبِرْهُمْ أَنَّهُمْ إِنْ فَعَلُوا ذَلِكَ فَلَهُمْ مَا لِلْمُهَاجِرِينَ وَعَلَيْهِمْ مَا عَلَى الْمُهَاجِرِينَ فَإِنْ أَبَوْا أَنْ يَتَحَوَّلُوا مِنْهَا فَأَخْبِرْهُمْ أَنَّهُمْ يَكُونُونَ كَأَعْرَابِ الْمُسْلِمِينَ يَجْرِي عَلَيْهِمْ حُكْمُ اللَّهِ الَّذِي يَجْرِي عَلَى الْمُؤْمِنِينَ وَلَا يَكُونُ لَهُمْ فِي الْغَنِيمَةِ وَالْفَيْءِ شَيْءٌ إِلَّا أَنْ يُجَاهِدُوا مَعَ الْمُسْلِمِينَ فَإِنْ هُمْ أَبَوْا فَسَلْهُمْ الْجِزْيَةَ فَإِنْ هُمْ أَجَابُوكَ فَاقْبَلْ مِنْهُمْ وَكُفَّ عَنْهُمْ فَإِنْ هُمْ أَبَوْا فَاسْتَعِنْ بِاللَّهِ وَقَاتِلْهُمْ وَإِذَا حَاصَرْتَ أَهْلَ حِصْنٍ فَأَرَادُوكَ أَنْ تَجْعَلَ لَهُمْ ذِمَّةَ اللَّهِ وَذِمَّةَ نَبِيِّهِ فَلَا تَجْعَلْ لَهُمْ ذِمَّةَ اللَّهِ وَلَا ذِمَّةَ نَبِيِّهِ وَلَكِنْ اجْعَلْ لَهُمْ ذِمَّتَكَ وَذِمَّةَ أَصْحَابِكَ فَإِنَّكُمْ أَنْ تُخْفِرُوا ذِمَمَكُمْ وَذِمَمَ أَصْحَابِكُمْ أَهْوَنُ مِنْ أَنْ تُخْفِرُوا ذِمَّةَ اللَّهِ وَذِمَّةَ رَسُولِهِ وَإِذَا حَاصَرْتَ أَهْلَ حِصْنٍ فَأَرَادُوكَ أَنْ تُنْزِلَهُمْ عَلَى حُكْمِ اللَّهِ فَلَا تُنْزِلْهُمْ عَلَى حُكْمِ اللَّهِ وَلَكِنْ أَنْزِلْهُمْ عَلَى حُكْمِكَ فَإِنَّكَ لَا تَدْرِي أَتُصِيبُ حُكْمَ اللَّهِ فِيهِمْ أَمْ لَاقَالَ عَبْدُ الرَّحْمَنِ هَذَا أَوْ نَحْوَهُ وَزَادَ إِسْحَقُ فِي آخِرِ حَدِيثِهِ عَنْ يَحْيَى بْنِ آدَمَ قَالَ فَذَكَرْتُ هَذَا الْحَدِيثَ لِمُقَاتِلِ بْنِ حَيَّانَ قَالَ يَحْيَى يَعْنِي أَنَّ عَلْقَمَةَ يَقُولُهُ لِابْنِ حَيَّانَ فَقَالَ حَدَّثَنِي مُسْلِمُ بْنُ هَيْصَمٍ عَنْ النُّعْمَانِ بْنِ مُقَرِّنٍ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَحْوَهُ و حَدَّثَنِي حَجَّاجُ بْنُ الشَّاعِرِ حَدَّثَنِي عَبْدُ الصَّمَدِ بْنُ عَبْدِ الْوَارِثِ حَدَّثَنَا شُعْبَةُ حَدَّثَنِي عَلْقَمَةُ بْنُ مَرْثَدٍ أَنَّ سُلَيْمَانَ بْنَ بُرَيْدَةَ حَدَّثَهُ عَنْ أَبِيهِ قَالَ كَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا بَعَثَ أَمِيرًا أَوْ سَرِيَّةً دَعَاهُ فَأَوْصَاهُ وَسَاقَ الْحَدِيثَ بِمَعْنَى حَدِيثِ سُفْيَانَ حَدَّثَنَا إِبْرَاهِيمُ حَدَّثَنَا مُحَمَّدُ بْنُ عَبْدِ الْوَهَّابِ الْفَرَّاءُ عَنْ الْحُسَيْنِ بْنِ الْوَلِيدِ عَنْ شُعْبَةَ بِهَذَا","id":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] telah menceritakan kepada kami [Waki' bin Al Jarrah] dari [Sufyan]. (dalam riwayat lain disebutkan) Telah menceritakan kepada kami [Ishaq bin Ibrahim] telah mengabarkan kepada kami [Yahya bin Adam] telah menceritakan kepada kami [Sufyan] dia berkata; dan dia telah mendikte kami. (dalam riwayat lain disebutkan) Telah menceritakan kepadaku [Abdullah bin Hasyim] sedangkan lafadznya dari dia. Telah menceritakan kepadaku [Abdurrahman bin Mahdi] telah menceritakan kepada kami [Sufyan] dari ['Alqamah bin Martsad] dari [Sulaiman bin Buraidah] dari [ayahnya] dia berkata, \"Apabila Rasulullah shallallahu 'alaihi wasallam mengangkat seorang panglima atau komandan pasukan perang, beliau selalu mewasiatkan untuk selalu bertakwa kepada Allah, kemudian beliau bersabda: \"Berperanglah dengan nama Allah untuk menegakkan di jalan Allah, perangilah orang-orang yang kafir kepada Allah, berperanglah kalian dan janganlah kalian menipu (dalam harta rampasan), jangan kalian mengkhianati janji, jangan membunuh seseorang dengan cara yang kejam, dan janganlah membunuh anak-anak. Apabila kalian bertemu dengan musuhmu dari orang-orang musyrik, maka ajaklah mereka kepada tiga hal, apabila mereka mau menerima salah satu dari tiga hal tersebut, maka terimalah mereka dan berhentilah memerangi mereka, setelah itu serulah mereka untuk masuk agama Islam. Apabila mereka mau menerima ajakanmu maka terimalah, setelah itu ajaklah mereka untuk pindah dari kampung halaman mereka ke kampung halaman kaum Muhajirin. Apabila mereka mau menerima ajakanmu tersebut, maka beritahukanlah bahwa mereka mempunyai hak dan kewajiban yang sama seperti kaum Muhajirin. Apabila mereka enggan pindah dari kampung halamannya ke kampung halaman kaum Muhajirin, maka beritahukanlah kepada mereka bahwa mereka sama dengan orang-orang Arab Muslim lainnya, yang tidak memperoleh sedikitpun harta rampasan perang, kecuali jika mereka ikut berjuang bersama kaum Muslimin lainnya. Jika mereka menolak maka mintalah upeti kepada mereka, apabila mereka mau menyerahkan upeti tersebut kepadamu maka terimalah dan janganlah kamu memerangi mereka, namun jika mereka enggan, maka mohonlah pertolongan kepada Allah lalu perangilah mereka. Apabila kalian mengepung suatu benteng, lalu orang-orang yang berada di dalamnya meminta keamanan dan jaminan dari Allah dan Rasul-Nya, maka janganlah kamu penuhi permintaan tersebut. Tetapi jadikanlah merka dalam perlindungan kalian dan perlindungan sahabat-sahabat kalian, sebab resikonya lebih ringan jika kamu harus merusak keamanan kalian dan teman-teman kalian daripada kalian merusak keamanan Allah dan Rasul-Nya. Apabila mereka menghendaki agar ditempatkan pada hukum Allah maka janganlah kalian berlakukan hal itu kepada mereka, yang lebih baik adalah apabila kalian memberlakukan hukuman sendiri, sebab kalian sendiri mungkin tidak akan mengetahui, apakah kalian dapat menegakkan hukum Allah kepada mereka atau tidak.\" Abdurrahman berkata, \"Seperti ini atau yang semisalnya.\" [Ishaq] menambahkan diakhir haditsnya, dari [Yahya bin Adam] dia berkata; aku meneyebutkan hadits ini kepada [Muqatil bin Hayyan]. Yahya berkata, \"Yaitu bahwa Al Qamah pernah berkata kepada Ibnu Hayyan, katanya; telah menceritakan kepadaku [Muslim bin Haisham] dari [An Nu'man bin Muqarrin] dari Nabi shallallahu 'alaihi wasallam seperti itu.\" Dan telah menceritakan kepadaku [Hajjaj bin Sya'ir] telah menceritakan kepadaku [Abdush Shammad bin Abdul Warits] telah menceritakan kepada kami [Syu'bah] telah menceritakan kepadaku ['Alqamah bin Martsad] bahwa [Sulaiman bin Buraidah] telah menceritakan dari [ayahnya] dia berkata, \"Apabila Rasulullah shallallahu 'alaihi wasallam mengangkat seorang panglima atau komandan pasukan perang, beliau selalu mendo'akannya dan mewasiatkan kepadanya...lalu dia melanjutkan hadits tersebut semakna dengan hadits Sufyan.\" Telah menceritakan kepada kami Ibrahim telah menceritakan kepada kami Muhammad bin Abdul Wahhab Al Farra` dari Al Husain bin Walid dari Syu'bah dengan isnad ini.\""},"3029":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ وَأَبُو كُرَيْبٍ وَاللَّفْظُ لِأَبِي بَكْرٍ قَالَا حَدَّثَنَا أَبُو أُسَامَةَ عَنْ بُرَيْدِ بْنِ عَبْدِ اللَّهِ عَنْ أَبِي بُرْدَةَ عَنْ أَبِي مُوسَى قَالَكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا بَعَثَ أَحَدًا مِنْ أَصْحَابِهِ فِي بَعْضِ أَمْرِهِ قَالَ بَشِّرُوا وَلَا تُنَفِّرُوا وَيَسِّرُوا وَلَا تُعَسِّرُوا","id":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] dan [Abu Kuraib] sedangkan lafadznya dari Abu Bakar, keduanya berkata; telah menceritakan kepada kami [Abu Usamah] dari [Buraid bin Abdullah] dari [Abu Burdah] dari [Abu Musa] dia berkata, \"Apabila Rasulullah shallallahu 'alaihi wasallam mengangkat seseorang dari sahabatnya untuk melaksanakan perintahnya, beliau bersabda: \"Berilah mereka kabar gembira dan janganlah menakut-nakuti, mudahkan urusan mereka jangan kamu persulit.\""},"3030":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا وَكِيعٌ عَنْ شُعْبَةَ عَنْ سَعِيدِ بْنِ أَبِي بُرْدَةَ عَنْ أَبِيهِ عَنْ جَدِّهِأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بَعَثَهُ وَمُعَاذًا إِلَى الْيَمَنِ فَقَالَ يَسِّرَا وَلَا تُعَسِّرَا وَبَشِّرَا وَلَا تُنَفِّرَا وَتَطَاوَعَا وَلَا تَخْتَلِفَاو حَدَّثَنَا مُحَمَّدُ بْنُ عَبَّادٍ حَدَّثَنَا سُفْيَانُ عَنْ عَمْرٍو ح و حَدَّثَنَا إِسْحَقُ بْنُ إِبْرَاهِيمَ وَابْنُ أَبِي خَلَفٍ عَنْ زَكَرِيَّاءَ بْنِ عَدِيٍّ أَخْبَرَنَا عُبَيْدُ اللَّهِ عَنْ زَيْدِ بْنِ أَبِي أُنَيْسَةَ كِلَاهُمَا عَنْ سَعِيدِ بْنِ أَبِي بُرْدَةَ عَنْ أَبِيهِ عَنْ جَدِّهِ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَحْوَ حَدِيثِ شُعْبَةَ وَلَيْسَ فِي حَدِيثِ زَيْدِ بْنِ أَبِي أُنَيْسَةَ وَتَطَاوَعَا وَلَا تَخْتَلِفَا","id":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] telah menceritakan kepada kami [Waki'] dari [Syu'bah] dari [Sa'id bin Abu Burdah] dari [ayahnya] dari [kakeknya], bahwa Nabi shallallahu 'alaihi wasallam pernah mengutus kakeknya dan Mu'adz ke negeri Yaman, maka beliau bersabda: \"Hendaklah kalian mudahkan dan jangan persulit, beri kabar gembira dan jangan membuat orang lari, saling patuhlah kalian berdua dan jangan saling bersengketa.\" Dan telah menceritakan kepada kami [Muhammad bin 'Abbad] telah menceritakan kepada kami [Sufyan] dari ['Amru]. Dan di diriwayatkan dari jalur lain, telah menceritakan kepada kami [Ishaq bin Ibrahim] dan [Ibnu Abu Khalaf] dari [Zakaria bin 'Adi] telah mengabarkan kepada kami ['Ubaidullah] dari [Zaid bin Abu Unaisah] keduanya dari [Sa'id bin Abu Burdah] dari [ayahnya] dari [kakeknya] dari Nabi shallallahu 'alaihi wasallam, seperti hadits Syu'bah, namun dalam hadits Zaid bin Abu Unaisah tidak disebutkan, 'Saling patuhlah kalian berdua dan jangan berselisih'.\""},"3031":{"ar":"حَدَّثَنَا عُبَيْدُ اللَّهِ بْنُ مُعَاذٍ الْعَنْبَرِيُّ حَدَّثَنَا أَبِي حَدَّثَنَا شُعْبَةُ عَنْ أَبِي التَّيَّاحِ عَنْ أَنَسٍ ح و حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا عُبَيْدُ اللَّهِ بْنُ سَعِيدٍ ح و حَدَّثَنَا مُحَمَّدُ بْنُ الْوَلِيدِ حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ كِلَاهُمَا عَنْ شُعْبَةَ عَنْ أَبِي التَّيَّاحِ قَالَ سَمِعْتُ أَنَسَ بْنَ مَالِكٍ يَقُولُاقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَسِّرُوا وَلَا تُعَسِّرُوا وَسَكِّنُوا وَلَا تُنَفِّرُوا","id":"Telah menceritakan kepada kami [Ubaidulalh bin Mu'adz Al 'Anbari] telah menceritakan kepada kami [ayahku] telah menceritakan kepada kami [Syu'bah] dari [Abu At Tayah] dari [Anas]. (dalam riwayat lain disebutkan) Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] telah menceritakan kepada kami [Ubaidullah bin Sa'id]. (dalam riwayat lain disebutkan) Telah menceritakan kepada kami [Muhammad bin Al Walid] telah menceritakan kepada kami [Muhammad bin Ja'far] keduanya dari [Syu'bah] dari [Abu At Tayah] dia berkata; aku mendengar [Anas bin Malik] berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Permudahlah oleh kalian dan jangan mempersulit, buatlah hati mereka tenang dan jangan menakut-nakuti.\""},"3032":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا مُحَمَّدُ بْنُ بِشْرٍ وَأَبُو أُسَامَةَ ح و حَدَّثَنِي زُهَيْرُ بْنُ حَرْبٍ وَعُبَيْدُ اللَّهِ بْنُ سَعِيدٍ يَعْنِي أَبَا قُدَامَةَ السَّرَخْسِيَّ قَالَا حَدَّثَنَا يَحْيَى وَهُوَ الْقَطَّانُ كُلُّهُمْ عَنْ عُبَيْدِ اللَّهِ ح و حَدَّثَنَا مُحَمَّدُ بْنُ عَبْدِ اللَّهِ بْنِ نُمَيْرٍ وَاللَّفْظُ لَهُ حَدَّثَنَا أَبِي حَدَّثَنَا عُبَيْدُ اللَّهِ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا جَمَعَ اللَّهُ الْأَوَّلِينَ وَالْآخِرِينَ يَوْمَ الْقِيَامَةِ يُرْفَعُ لِكُلِّ غَادِرٍ لِوَاءٌ فَقِيلَ هَذِهِ غَدْرَةُ فُلَانِ بْنِ فُلَانٍحَدَّثَنَا أَبُو الرَّبِيعِ الْعَتَكِيُّ حَدَّثَنَا حَمَّادٌ حَدَّثَنَا أَيُّوبُ ح و حَدَّثَنَا عَبْدُ اللَّهِ بْنُ عَبْدِ الرَّحْمَنِ الدَّارِمِيُّ حَدَّثَنَا عَفَّانُ حَدَّثَنَا صَخْرُ بْنُ جُوَيْرِيَةَ كِلَاهُمَا عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِهَذَا الْحَدِيثِ","id":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] telah menceritakan kepada kami [Muhammad bin Bisyr] dan [Abu Usamah]. (dalam riwayat lain disebutkan) Telah menceritakan kepadaku [Zuhair bin Harb] dan [Ubaidullah bin Sa'id] -yaitu Abu Qudamah As Sarahsi- keduanya berkata; telah menceritakan kepada kami [Yahya] -yaitu Al Qatthan- semuanya dari [Ubaidullah]. (dalam riwayat lain disebutkan) Telah menceritakan kepada kami [Muhammad bin Abdullah bin Numair] sedangkan lafadznya dari dia, telah menceritakan kepada kami [ayahku] telah menceritakan kepada kami [Ubaidullah] dari [Nafi'] dari [Ibnu Umar] dia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Apabila Allah mengumpulkan orang-orang yang terdahulu dan orang-orang yang terakhir kelak di hari Kiamat, maka akan dikibarkan bendera bagi setiap pengkhianat, lalu dikatakan, 'Ini adalah bendera si fulan bin fulan'.\" Telah menceritakan kepada kami [Abu Ar Rabi' Aal 'Ataki] telah menceritakan kepada kami [Hammad] telah menceritakan kepada kami [Ayyub]. (dalam riwayat lain disebutkan) Telah menceritakan kepada kami [Abdullah bin Abdurrahman Ad darimi] telah menceritakan kepada kami [Affan] telah menceritakan kepada kami [Shahr bin Juwairiyah] keduanya dari [Nafi'] dari [Ibnu Umar] dari Nabi shallallahu 'alaihi wasallam dengan hadits ini.\""},"3033":{"ar":"و حَدَّثَنَا يَحْيَى بْنُ أَيُّوبَ وَقُتَيْبَةُ وَابْنُ حُجْرٍ عَنْ إِسْمَعِيلَ بْنِ جَعْفَرٍ عَنْ عَبْدِ اللَّهِ بْنِ دِينَارٍ أَنَّهُ سَمِعَ عَبْدَ اللَّهِ بْنَ عُمَرَ يَقُولُاقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّ الْغَادِرَ يَنْصِبُ اللَّهُ لَهُ لِوَاءً يَوْمَ الْقِيَامَةِ فَيُقَالُ أَلَا هَذِهِ غَدْرَةُ فُلَانٍ","id":"Dan telah menceritakan kepada kami [Yahya bin Ayyub] dan [Qutaibah] serta [Ibnu Hujr] dari [Isma'il bin Ja'far] dari [Abdullah bin Dinar] bahwa dia pernah mendengar [Abdullah bin Umar] berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sesungguhnya Allah akan mengibarkan bendera untuk para pengkhianat, dan dikatakan kepadanya, 'Ini adalah bendera pengkhianatan si fulan'.\""},"3034":{"ar":"حَدَّثَنِي حَرْمَلَةُ بْنُ يَحْيَى أَخْبَرَنَا ابْنُ وَهْبٍ أَخْبَرَنِي يُونُسُ عَنْ ابْنِ شِهَابٍ عَنْ حَمْزَةَ وَسَالِمٍ ابْنَيْ عَبْدِ اللَّهِ أَنَّ عَبْدَ اللَّهِ بْنَ عُمَرَ قَالَسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ لِكُلِّ غَادِرٍ لِوَاءٌ يَوْمَ الْقِيَامَةِ","id":"Telah menceritakan kepadaku [Harmalah bin Yahya] telah mengabarkan kepada kami [Ibnu Wahb] telah mengabarkan kepadaku [Yunus] dari [Ibnu Syihab] dari [Hamzah] dan [Salim] yang keduanya adalah anak Abdullah, bahwa [Abdullah bin Umar] berkata, \"Aku mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Setiap pengkhianat akan membawa benderanya masing-masing di hari Kiamat kelak.\""},"3035":{"ar":"حَدَّثَنِي مُحَمَّدُ بْنُ الْمُثَنَّى وَابْنُ بَشَّارٍ قَالَا حَدَّثَنَا ابْنُ أَبِي عَدِيٍّ ح و حَدَّثَنِي بِشْرُ بْنُ خَالِدٍ أَخْبَرَنَا مُحَمَّدٌ يَعْنِي ابْنَ جَعْفَرٍ كِلَاهُمَا عَنْ شُعْبَةَ عَنْ سُلَيْمَانَ عَنْ أَبِي وَائِلٍ عَنْ عَبْدِ اللَّهِعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لِكُلِّ غَادِرٍ لِوَاءٌ يَوْمَ الْقِيَامَةِ يُقَالُ هَذِهِ غَدْرَةُ فُلَانٍو حَدَّثَنَاه إِسْحَقُ بْنُ إِبْرَاهِيمَ أَخْبَرَنَا النَّضْرُ بْنُ شُمَيْلٍ ح و حَدَّثَنِي عُبَيْدُ اللَّهِ بْنُ سَعِيدٍ حَدَّثَنَا عَبْدُ الرَّحْمَنِ جَمِيعًا عَنْ شُعْبَةَ فِي هَذَا الْإِسْنَادِ وَلَيْسَ فِي حَدِيثِ عَبْدِ الرَّحْمَنِ يُقَالُ هَذِهِ غَدْرَةُ فُلَانٍ","id":"Telah menceritakan kepadaku [Muhammad bin Al Mutsanna] dan [Ibnu Basyar] keduanya berkata; telah menceritakan kepada kami [Ibnu Abu 'Adi]. (dalam riwayat lain disebutkan) Telah menceritakan kepadaku [Bisyr bin Khalid] telah mengabarkan kepada kami [Muhammad] -yaitu Ibnu Ja'far- keduanya dari [Syu'bah] dari [Sulaiman] dari [Abu Wa`il] dari [Abdullah] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Di hari Kiamat kelak setiap pengkhianat akan senantiasa mengibarkan benderanya masing-masing, dikatakan, 'Ini adalah bendera pengkhianatan fulan'.\" Dan telah menceritakan kepada kami [Ishaq bin Ibrahim] telah mengabarkan kepada kami [An Nadlr bin Syumail]. (dalam riwayat lain disebutkan) Telah menceritakan kepadaku [Ubaidullah bin Sa'id] telah menceritakan kepada kami [Abdurrahman] semuanya dari [Syu'bah] dengan isnad ini, namun dalam hadits Abdurrahman tidak disebutkan, 'Ini adalah bendera pengkhianatan si fulan'.\""},"3036":{"ar":"و حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا يَحْيَى بْنُ آدَمَ عَنْ يَزِيدَ بْنِ عَبْدِ الْعَزِيزِ عَنْ الْأَعْمَشِ عَنْ شَقِيقٍ عَنْ عَبْدِ اللَّهِ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لِكُلِّ غَادِرٍ لِوَاءٌ يَوْمَ الْقِيَامَةِ يُعْرَفُ بِهِ يُقَالُ هَذِهِ غَدْرَةُ فُلَانٍ","id":"Dan telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] telah menceritakan kepada kami [Yahya bin Adam] dari [Yazid bin Abdul Aziz] dari [Al A'masy] dari [Syaqiq] dari [Abdullah] dia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Setiap pengkhianat akan membawa bendera yang mudah untuk dikenali, dikatakan, 'Ini adalah bendera pengkhianatan si fulan'.\""},"3037":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ الْمُثَنَّى وَعُبَيْدُ اللَّهِ بْنُ سَعِيدٍ قَالَا حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ مَهْدِيٍّ عَنْ شُعْبَةَ عَنْ ثَابِتٍ عَنْ أَنَسٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لِكُلِّ غَادِرٍ لِوَاءٌ يَوْمَ الْقِيَامَةِ يُعْرَفُ بِهِ","id":"Telah menceritakan kepada kami [Muhammad bin Al Mutsanna] dan [Ubaidullah bin Sa'id] keduanya berkata; telah menceritakan kepada kami [Abdurrahman bin Mahdi] dari [Syu'bah] dari [Tsabit] dari [Anas] dia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Setiap pengkhianat akan membawa bendera yang mudah dikenali di hari Kiamat kelak'.\""},"3038":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ الْمُثَنَّى وَعُبَيْدُ اللَّهِ بْنُ سَعِيدٍ قَالَا حَدَّثَنَا عَبْدُ الرَّحْمَنِ حَدَّثَنَا شُعْبَةُ عَنْ خُلَيْدٍ عَنْ أَبِي نَضْرَةَ عَنْ أَبِي سَعِيدٍعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لِكُلِّ غَادِرٍ لِوَاءٌ عِنْدَ اسْتِهِ يَوْمَ الْقِيَامَةِ","id":"Telah menceritakan kepada kami [Muhammad bin Al Mutsanna] dan [Ubaidullah bin Said] keduanya berkata; telah menceritakan kepada kami [Abdurrahman] telah menceritakan kepada kami [Syu'bah] dari [Khulaid] dari [Abu Nadlrah] dari [Abu Sa'id] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Setiap pengkhianat akan membawa bendera di belakangnya di hari Kiamat kelak.\""},"3039":{"ar":"حَدَّثَنَا زُهَيْرُ بْنُ حَرْبٍ حَدَّثَنَا عَبْدُ الصَّمَدِ بْنُ عَبْدِ الْوَارِثِ حَدَّثَنَا الْمُسْتَمِرُّ بْنُ الرَّيَّانِ حَدَّثَنَا أَبُو نَضْرَةَ عَنْ أَبِي سَعِيدٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لِكُلِّ غَادِرٍ لِوَاءٌ يَوْمَ الْقِيَامَةِ يُرْفَعُ لَهُ بِقَدْرِ غَدْرِهِ أَلَا وَلَا غَادِرَ أَعْظَمُ غَدْرًا مِنْ أَمِيرِ عَامَّةٍ","id":"Telah menceritakan kepada kami [Zuhair bin Harb] telah menceritakan kepada kami [Abdus Shamad bin Abdul Warits] telah menceritakan kepada kami [Mustamir bin Ar Rayan] telah menceritakan kepada kami [Abu Nadlrah] dari [Abu Sa'id] dia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Di hari Kiamat kelak setiap pengkhianat akan membawa bendera yang dikibarkannya tinggi-tinggi sesuai dengan pengkhianatannya. Ketahuilah, tidak ada pengkhianatan yang lebih besar daripada pengkhianatan seorang penguasa terhadap rakyatnya.\""},"3040":{"ar":"و حَدَّثَنَا عَلِيُّ بْنُ حُجْرٍ السَّعْدِيُّ وَعَمْرٌو النَّاقِدُ وَزُهَيْرُ بْنُ حَرْبٍ وَاللَّفْظُ لِعَلِيٍّ وَزُهَيْرٍ قَالَ عَلِيٌّ أَخْبَرَنَا و قَالَ الْآخَرَانِ حَدَّثَنَا سُفْيَانُ قَالَ سَمِعَ عَمْرٌو جَابِرًا يَقُولُاقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْحَرْبُ خَدْعَةٌ","id":"Dan telah menceritakan kepada kami [Ali bin Hujr As Sa'di] dan ['Amru An Naqid] dan [Zuhair bin Harb] sedangkan lafadznya dari Ali dan Zuhair, Ali berkata; telah mengabarkan kepada kami, sedangkan yang dua orang mengatakan; telah menceritakan kepada kami [Sufyan] dia berkata; ['Amru] pernah mendengar [Jabir] berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Perang adalah tipu daya.\""},"3041":{"ar":"و حَدَّثَنَا مُحَمَّدُ بْنُ عَبْدِ الرَّحْمَنِ بْنِ سَهْمٍ أَخْبَرَنَا عَبْدُ اللَّهِ بْنُ الْمُبَارَكِ أَخْبَرَنَا مَعْمَرٌ عَنْ هَمَّامِ بْنِ مُنَبِّهٍ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْحَرْبُ خَدْعَةٌ","id":"Dan telah menceritakan kepada kami [Muhammad bin Abdurrahman bin Sahm] telah mengabarkan kepada kami [Abdullah bin Mubarrak] telah mengabarkan kepada kami [Ma'mar] dari [Hammam bin Munabbih] dari [Abu Hurairah] dia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Perang adalah tipu daya.\""},"3042":{"ar":"حَدَّثَنَا الْحَسَنُ بْنُ عَلِيٍّ الْحُلْوَانِيُّ وَعَبْدُ بْنُ حُمَيْدٍ قَالَا حَدَّثَنَا أَبُو عَامِرٍ الْعَقَدِيُّ عَنْ الْمُغِيرَةِ وَهُوَ ابْنُ عَبْدِ الرَّحْمَنِ الْحِزَامِيُّ عَنْ أَبِي الزِّنَادِ عَنْ الْأَعْرَجِ عَنْ أَبِي هُرَيْرَةَأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَا تَمَنَّوْا لِقَاءَ الْعَدُوِّ فَإِذَا لَقِيتُمُوهُمْ فَاصْبِرُوا","id":"Telah menceritakan kepada kami [Al Hasan bin Ali Al Khulwani] dan [Abd bin Humaid] keduanya berkata; telah menceritakan kepada kami [Abu 'Amir Al 'Aqadi] dari [Mughirah] -yaitu Ibnu Abdurrahman Al Hizami- dari [Abu Az Zinnad] dari [Al A'raj] dari [Abu Hurairah] bahwa Nabi shallallahu 'alaihi wasallam bersabda: \"Janganlah kalian mengharap bertemu musuh, namun jika kalian bertemu mereka maka bersabarlah (teguhkan hati kalian).\""},"3043":{"ar":"و حَدَّثَنِي مُحَمَّدُ بْنُ رَافِعٍ حَدَّثَنَا عَبْدُ الرَّزَّاقِ أَخْبَرَنَا ابْنُ جُرَيْجٍ أَخْبَرَنِي مُوسَى بْنُ عُقْبَةَ عَنْ أَبِي النَّضْرِعَنْ كِتَابِ رَجُلٍ مِنْ أَسْلَمَ مِنْ أَصْحَابِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُقَالُ لَهُ عَبْدُ اللَّهِ بْنُ أَبِي أَوْفَى فَكَتَبَ إِلَى عُمَرَ بْنِ عُبَيْدِ اللَّهِ حِينَ سَارَ إِلَى الْحَرُورِيَّةِ يُخْبِرُهُ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ فِي بَعْضِ أَيَّامِهِ الَّتِي لَقِيَ فِيهَا الْعَدُوَّ يَنْتَظِرُ حَتَّى إِذَا مَالَتْ الشَّمْسُ قَامَ فِيهِمْ فَقَالَ يَا أَيُّهَا النَّاسُ لَا تَتَمَنَّوْا لِقَاءَ الْعَدُوِّ وَاسْأَلُوا اللَّهَ الْعَافِيَةَ فَإِذَا لَقِيتُمُوهُمْ فَاصْبِرُوا وَاعْلَمُوا أَنَّ الْجَنَّةَ تَحْتَ ظِلَالِ السُّيُوفِ ثُمَّ قَامَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَقَالَ اللَّهُمَّ مُنْزِلَ الْكِتَابِ وَمُجْرِيَ السَّحَابِ وَهَازِمَ الْأَحْزَابِ اهْزِمْهُمْ وَانْصُرْنَا عَلَيْهِمْ","id":"Dan telah menceritakan kepadaku [Muhammad bin Rafi'] telah menceritakan kepada kami [Abdurrazaq] telah mengabarkan kepada kami [Ibnu Juraij] telah mengabarkan kepadaku [Musa bin Uqbah] dari [Abu An Nadlr], bahwa dia pernah menerima sepucuk surat dari suku Aslam yang bernama [Abdullah bin Abu Aufa] -termasuk salah seorang sahabat Nabi shallallahu 'alaihi wasallam-, maka dia menulis surat kepada Umar bin Ubaidullah ketika ia berangkat untuk memerangi orang-orang Haruriyah, dan memberitahukan kepadanya bahwa, suatu ketika Rasulullah shallallahu 'alaihi wasallam pernah bertemu dengan para musuh, lalu beliau menunggu hingga matahari condong ke arah barat. Setelah itu, beliau berdiri di antara para sahabat seraya bersabda: \"Wahai kaum Muslimin, janganlah kalian mengharap bertemu dengan musuh, dan mohonlah kesehatan kepada Allah, namun apabila kalian bertemu dengan mereka maka bersabarlah. Ketahuilah oleh kalian semua, bahwa surga berada di bawah naungan pedang.\" Kemudian Nabi shallallahu 'alaihi wasallam berdiri sambil bermunajat: \"Ya Allah, dzat yang menurunkan Al Qur'an, dzat yang menggerakkan awan, dzat yang dapat mengalahkan pasukan Ahzab, hancurkanlah mereka semua dan berikanlah kemenangan atas kami.\""},"3044":{"ar":"حَدَّثَنَا سَعِيدُ بْنُ مَنْصُورٍ حَدَّثَنَا خَالِدُ بْنُ عَبْدِ اللَّهِ عَنْ إِسْمَعِيلَ بْنِ أَبِي خَالِدٍ عَنْ عَبْدِ اللَّهِ بْنِ أَبِي أَوْفَى قَالَدَعَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَلَى الْأَحْزَابِ فَقَالَ اللَّهُمَّ مُنْزِلَ الْكِتَابِ سَرِيعَ الْحِسَابِ اهْزِمْ الْأَحْزَابَ اللَّهُمَّ اهْزِمْهُمْ وَزَلْزِلْهُمْو حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا وَكِيعُ بْنُ الْجَرَّاحِ عَنْ إِسْمَعِيلَ بْنِ أَبِي خَالِدٍ قَالَ سَمِعْتُ ابْنَ أَبِي أَوْفَى يَقُولُا دَعَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِمِثْلِ حَدِيثِ خَالِدٍ غَيْرَ أَنَّهُ قَالَ هَازِمَ الْأَحْزَابِ وَلَمْ يَذْكُرْ قَوْلَهُ اللَّهُمَّ و حَدَّثَنَاه إِسْحَقُ بْنُ إِبْرَاهِيمَ وَابْنُ أَبِي عُمَرَ جَمِيعًا عَنْ ابْنِ عُيَيْنَةَ عَنْ إِسْمَعِيلَ بِهَذَا الْإِسْنَادِ وَزَادَ ابْنُ أَبِي عُمَرَ فِي رِوَايَتِهِ مُجْرِيَ السَّحَابِ","id":"Telah menceritakan kepada kami [Sa'id bin Manshur] telah menceritakan kepada kami [Khalid bin Abdullah] dari [Isma'il bin Abu Khalid] dari [Abdullah bin Abu Aufa] dia berkata, \"Rasulullah shallallahu 'alaihi wasallam mendo'akan kehancuran bagi pasukan Ahzab, beliau bersabda: \"Ya Allah, dzat yang menurunkan kitab, dzat yang segera membuat perhitungan, hancurkanlah pasukan Ahzab. Ya Allah, hancurkanlah mereka dan cerai-beraikanlah mereka.\" Dan telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] telah menceritakan kepada kami [Waki' bin Jarrah] dari [Isma'il bin Abu Khalid] dia berkata; aku pernah mendengar [Ibnu Abu Aufa] berkata, \"Rasulullah shallallahu 'alaihi wasallam pernah mendo'akan...seperti hadits riwayat Khalid, hanya saja ia menyebutkan, 'Hancurkanlah pasukan Ahzab', dan tidak menyebutkan, 'Ya Allah'.\" Dan telah menceritakan kepada kami [Ishaq bin Ibrahim] dan [Ibnu Abu Umar] semuanya dari [Ibnu Uyainah] dari [Isma'il] dengan isnad ini, dan dalam riwayat Ibnu Abu Umar disebutkan, 'Dzat yang menggerakkan awan'.\""},"3045":{"ar":"و حَدَّثَنِي حَجَّاجُ بْنُ الشَّاعِرِ حَدَّثَنَا عَبْدُ الصَّمَدِ حَدَّثَنَا حَمَّادٌ عَنْ ثَابِتٍ عَنْ أَنَسٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يَقُولُ يَوْمَ أُحُدٍ اللَّهُمَّ إِنَّكَ إِنْ تَشَأْ لَا تُعْبَدْ فِي الْأَرْضِ","id":"Dan telah menceritakan kepadaku [Hajjaj bin Sya'ir] telah menceritakan kepada kami [Abdush Shamad] telah menceritakan kepada kami [Hammad] dari [Tsabit] dari [Anas], bahwa Rasulullah shallallahu 'alaihi wasallam pernah berdoa saat terjadinya perang uhud: \"Ya Allah, jika Engkau menghendaki (kemenangan atas orang kafir dan mengalahkan pasukan Islam) niscaya Engkau tidak di sembah di muka bumi.\""},"3046":{"ar":"حَدَّثَنَا يَحْيَى بْنُ يَحْيَى وَمُحَمَّدُ بْنُ رُمْحٍ قَالَا أَخْبَرَنَا اللَّيْثِ ح و حَدَّثَنَا قُتَيْبَةُ بْنُ سَعِيدٍ حَدَّثَنَا لَيْثٌ عَنْ نَافِعٍ عَنْ عَبْدِ اللَّهِأَنَّ امْرَأَةً وُجِدَتْ فِي بَعْضِ مَغَازِي رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَقْتُولَةً فَأَنْكَرَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَتْلَ النِّسَاءِ وَالصِّبْيَانِ","id":"Telah menceritakan kepada kami [Yahya bin Yahya] dan [Muhammad bin Rumh] keduanya berkata; telah mengabarkan kepada kami [Al Laits]. (dalam riwayat lain disebutkan) Telah menceritakan kepada kami [Qutaibah bin Sa'id] telah menceritakan kepada kami [Laits] dari [Nafi'] dari [Abdullah] bahwa dalam salah satu peperangan Rasulullah shallallahu 'alaihi wasallam pernah ditemukan jasad seorang wanita, maka Rasulullah shallallahu 'alaihi wasallam pun melarang pembunuhan wanita dan anak-anak.\""},"3047":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا مُحَمَّدُ بْنُ بِشْرٍ وَأَبُو أُسَامَةَ قَالَا حَدَّثَنَا عُبَيْدُ اللَّهِ بْنُ عُمَرَ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَ قَالَوُجِدَتْ امْرَأَةٌ مَقْتُولَةً فِي بَعْضِ تِلْكَ الْمَغَازِي فَنَهَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ قَتْلِ النِّسَاءِ وَالصِّبْيَانِ","id":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] telah menceritakan kepada kami [Muhammad bin Bisyr] dan [Abu Usamah] keduanya berkata; telah menceritakan kepada kami [Ubaidullah bin Umar] dari [Nafi'] dari [Ibnu Umar] dia berkata, \"Seorang wanita didapati telah terbunuh di suatu peperangan, maka Rasulullah shallallahu 'alaihi wasallam melarang untuk membunuh wanita dan anak-anak.\""},"3048":{"ar":"و حَدَّثَنَا يَحْيَى بْنُ يَحْيَى وَسَعِيدُ بْنُ مَنْصُورٍ وَعَمْرٌو النَّاقِدُ جَمِيعًا عَنْ ابْنِ عُيَيْنَةَ قَالَ يَحْيَى أَخْبَرَنَا سُفْيَانُ بْنُ عُيَيْنَةَ عَنْ الزُّهْرِيِّ عَنْ عُبَيْدِ اللَّهِ عَنْ ابْنِ عَبَّاسٍ عَنْ الصَّعْبِ بْنِ جَثَّامَةَ قَالَسُئِلَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ الذَّرَارِيِّ مِنْ الْمُشْرِكِينَ يُبَيَّتُونَ فَيُصِيبُونَ مِنْ نِسَائِهِمْ وَذَرَارِيِّهِمْ فَقَالَ هُمْ مِنْهُمْ","id":"Dan telah menceritakan kepada kami [Yahya bin Yahya] dan [Sa'id bin Manshur] dan [Amru An Naqid] semuanya dari [Ibnu 'Uyainah]. [Yahya] berkata; telah mengabarkan kepada kami [Sufyan bin 'Uyainah] dari [Az Zuhri] dari [Ubaidullah] dari [Ibnu Abbas] dari [Ash Sha'b bin Jatsamah] dia berkata, \"Nabi shallallahu 'alaihi wasallam pernah ditanya mengenai anak-anak dan wanita Musyrikin yang terbunuh ketika terjadi serangan malam.\" Beliau menjawab: \"Mereka termasuk dari golongan musuh.\""},"3049":{"ar":"حَدَّثَنَا عَبْدُ بْنُ حُمَيْدٍ أَخْبَرَنَا عَبْدُ الرَّزَّاقِ أَخْبَرَنَا مَعْمَرٌ عَنْ الزُّهْرِيِّ عَنْ عُبَيْدِ اللَّهِ بْنِ عَبْدِ اللَّهِ بْنِ عُتْبَةَ عَنْ ابْنِ عَبَّاسٍ عَنْ الصَّعْبِ بْنِ جَثَّامَةَ قَالَقُلْتُ يَا رَسُولَ اللَّهِ إِنَّا نُصِيبُ فِي الْبَيَاتِ مِنْ ذَرَارِيِّ الْمُشْرِكِينَ قَالَ هُمْ مِنْهُمْ","id":"Telah menceritakan kepada kami [Abd bin Humaid] telah mengabarkan kepada kami [Abdurrazaq] telah mengabarkan kepada kami [Ma'mar] dari [Az Zuhri] dari [Ubaidullah bin Abdullah bin 'Utbah] dari [Ibnu Abbas] dari [Ash Sha'b bin Jastamah] dia berkata, \"Aku bertanya, \"Wahai Rasulullah, kami pernah menyerang musuh di malam hari, hingga kami membunuh para anak-anak dan kaum wanita dari orang-orang Musyrik!\" Beliau bersabda: \"Mereka termasuk dari golongan musuh.\""},"3050":{"ar":"و حَدَّثَنِي مُحَمَّدُ بْنُ رَافِعٍ حَدَّثَنَا عَبْدُ الرَّزَّاقِ أَخْبَرَنَا ابْنُ جُرَيْجٍ أَخْبَرَنِي عَمْرُو بْنُ دِينَارٍ أَنَّ ابْنَ شِهَابٍ أَخْبَرَهُ عَنْ عُبَيْدِ اللَّهِ بْنِ عَبْدِ اللَّهِ بْنِ عُتْبَةَ عَنْ ابْنِ عَبَّاسٍ عَنْ الصَّعْبِ بْنِ جَثَّامَةَأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قِيلَ لَهُ لَوْ أَنَّ خَيْلًا أَغَارَتْ مِنْ اللَّيْلِ فَأَصَابَتْ مِنْ أَبْنَاءِ الْمُشْرِكِينَ قَالَ هُمْ مِنْ آبَائِهِمْ","id":"Dan telah menceritakan kepadaku [Muhammad bin Rafi'] telah menceritakan kepada kami [Abdurrazaq] telah mengabarkan kepada kami [Ibnu Juraij] telah mengabarkan kepadaku ['Amru bin Dinar] bahwa [Ibnu Syihab] telah mengabarkan kepadanya dari [Ubaidullah bin Abdullah bin 'Utbah] dari [Ibnu Abbas] dari [Ash Sha'b bin Jatsamah], bahwa Nabi shallallahu 'alaihi wasallam ditanya, \"Bagaimana jika ada pasukan berkuda menyerang musuh di malam hari, sehingga anak orang-orang Musyrik banyak yang ikut terbunuh?\" Beliau menjawab: \"Mereka seperti bapak-bapak mereka.\""},"3051":{"ar":"حَدَّثَنَا يَحْيَى بْنُ يَحْيَى وَمُحَمَّدُ بْنُ رُمْحٍ قَالَا أَخْبَرَنَا اللَّيْثُ و حَدَّثَنَا قُتَيْبَةُ بْنُ سَعِيدٍ حَدَّثَنَا لَيْثٌ عَنْ نَافِعٍ عَنْ عَبْدِ اللَّهِأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حَرَّقَ نَخْلَ بَنِي النَّضِيرِ وَقَطَعَ وَهِيَ الْبُوَيْرَةُ زَادَ قُتَيْبَةُ وَابْنُ رُمْحٍ فِي حَدِيثِهِمَا فَأَنْزَلَ اللَّهُ عَزَّ وَجَلَّ{ مَا قَطَعْتُمْ مِنْ لِينَةٍ أَوْ تَرَكْتُمُوهَا قَائِمَةً عَلَى أُصُولِهَا فَبِإِذْنِ اللَّهِ وَلِيُخْزِيَ الْفَاسِقِينَ }","id":"Telah menceritakan kepada kami [Yahya bin Yahya] dan [Muhammad bin Rumh] keduanya berkata; telah mengabarkan kepada kami [Al Laits] dan telah menceritakan kepada kami [Qutaibah bin Sa'id] telah menceritakan kepada kami [Laits] dari [Nafi'] dari [Abdullah], bahwa Rasulullah shallallahu 'alaihi wasallam pernah membakar dan menebang kebun kurma milik (Yahudi) Bani Nadlir di Buwairah, lalu Allah Azza Wa Jalla menurunkan ayat: '(Apa saja yang kamu tebang dari pohon kurma (milik orang-orang kafir) atau yang kamu biarkan (tumbuh) berdiri di atas pokoknya, maka (semua itu) adalah dengan izin Allah; dan Karena dia hendak memberikan kehinaan kepada orang-orang fasik) ' (Qs. Al Hasyr: 5)."},"3052":{"ar":"حَدَّثَنَا سَعِيدُ بْنُ مَنْصُورٍ وَهَنَّادُ بْنُ السَّرِيِّ قَالَا حَدَّثَنَا ابْنُ الْمُبَارَكِ عَنْ مُوسَى بْنِ عُقْبَةَ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَطَعَ نَخْلَ بَنِي النَّضِيرِ وَحَرَّقَ وَلَهَا يَقُولُ حَسَّانُ وَهَانَ عَلَى سَرَاةِ بَنِي لُؤَيٍّحَرِيقٌ بِالْبُوَيْرَةِ مُسْتَطِيرُوَفِي ذَلِكَ نَزَلَتْ{ مَا قَطَعْتُمْ مِنْ لِينَةٍ أَوْ تَرَكْتُمُوهَا قَائِمَةً عَلَى أُصُولِهَا }الْآيَةَ","id":"Telah menceritakan kepada kami [Sa'id bin Manshur] dan [Hannad bin As Sarry] keduanya berkata; telah menceritakan kepada kami [Ibnu Mubarak] dari [Musa bin 'Uqbah] dari [Nafi'] dari [Ibnu Umar], bahwa Rasulullah shallallahu 'alaihi wasallam pernah menebang dan membakar kebun kurma milik (Yahudi) Bani Nadlir, dalam peristiwa itu, Hassan sempat membaca sebait sya'ir: \"Alangkah terhinanya tokoh-tokoh Bani Lu`aiy saat kebakaran melumat kebun kurma mereka yang berada di daerah Buwairah.\" Sehubungan dengan itu, maka turunlah ayat: '(Apa saja yang kamu tebang dari pohon kurma (milik orang-orang kafir) atau yang kamu biarkan (tumbuh) berdiri di atas pokoknya...) ' (Qs. Al Hasyr: 5)."},"3053":{"ar":"و حَدَّثَنَا سَهْلُ بْنُ عُثْمَانَ أَخْبَرَنِي عُقْبَةُ بْنُ خَالِدٍ السَّكُونِيُّ عَنْ عُبَيْدِ اللَّهِ عَنْ نَافِعٍ عَنْ عَبْدِ اللَّهِ بْنِ عُمَرَ قَالَحَرَّقَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَخْلَ بَنِي النَّضِيرِ","id":"Telah menceritakan kepada kami [Sahl bin Utsman] telah mengabarkan kepadaku [Uqbah bin Khalid As Sakuni] dari [Ubaidullah] dari [Nafi'] dari [Abdullah bin Umar] dia berkata, \"Rasulullah shallallahu 'alaihi wasallam pernah membakar habis kebun kurma milik (Yahudi) Bani Nadlir.\""},"3054":{"ar":"و حَدَّثَنَا أَبُو كُرَيْبٍ مُحَمَّدُ بْنُ الْعَلَاءِ حَدَّثَنَا ابْنُ الْمُبَارَكِ عَنْ مَعْمَرٍ ح و حَدَّثَنَا مُحَمَّدُ بْنُ رَافِعٍ وَاللَّفْظُ لَهُ حَدَّثَنَا عَبْدُ الرَّزَّاقِ أَخْبَرَنَا مَعْمَرٌ عَنْ هَمَّامِ بْنِ مُنَبِّهٍ قَالَ هَذَا مَا حَدَّثَنَا أَبُو هُرَيْرَةَ عَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَذَكَرَ أَحَادِيثَ مِنْهَاوَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ غَزَا نَبِيٌّ مِنْ الْأَنْبِيَاءِ فَقَالَ لِقَوْمِهِ لَا يَتْبَعْنِي رَجُلٌ قَدْ مَلَكَ بُضْعَ امْرَأَةٍ وَهُوَ يُرِيدُ أَنْ يَبْنِيَ بِهَا وَلَمَّا يَبْنِ وَلَا آخَرُ قَدْ بَنَى بُنْيَانًا وَلَمَّا يَرْفَعْ سُقُفَهَا وَلَا آخَرُ قَدْ اشْتَرَى غَنَمًا أَوْ خَلِفَاتٍ وَهُوَ مُنْتَظِرٌ وِلَادَهَا قَالَ فَغَزَا فَأَدْنَى لِلْقَرْيَةِ حِينَ صَلَاةِ الْعَصْرِ أَوْ قَرِيبًا مِنْ ذَلِكَ فَقَالَ لِلشَّمْسِ أَنْتِ مَأْمُورَةٌ وَأَنَا مَأْمُورٌ اللَّهُمَّ احْبِسْهَا عَلَيَّ شَيْئًا فَحُبِسَتْ عَلَيْهِ حَتَّى فَتَحَ اللَّهُ عَلَيْهِ قَالَ فَجَمَعُوا مَا غَنِمُوا فَأَقْبَلَتْ النَّارُ لِتَأْكُلَهُ فَأَبَتْ أَنْ تَطْعَمَهُ فَقَالَ فِيكُمْ غُلُولٌ فَلْيُبَايِعْنِي مِنْ كُلِّ قَبِيلَةٍ رَجُلٌ فَبَايَعُوهُ فَلَصِقَتْ يَدُ رَجُلٍ بِيَدِهِ فَقَالَ فِيكُمْ الْغُلُولُ فَلْتُبَايِعْنِي قَبِيلَتُكَ فَبَايَعَتْهُ قَالَ فَلَصِقَتْ بِيَدِ رَجُلَيْنِ أَوْ ثَلَاثَةٍ فَقَالَ فِيكُمْ الْغُلُولُ أَنْتُمْ غَلَلْتُمْ قَالَ فَأَخْرَجُوا لَهُ مِثْلَ رَأْسِ بَقَرَةٍ مِنْ ذَهَبٍ قَالَ فَوَضَعُوهُ فِي الْمَالِ وَهُوَ بِالصَّعِيدِ فَأَقْبَلَتْ النَّارُ فَأَكَلَتْهُ فَلَمْ تَحِلَّ الْغَنَائِمُ لِأَحَدٍ مِنْ قَبْلِنَا ذَلِكَ بِأَنَّ اللَّهَ تَبَارَكَ وَتَعَالَى رَأَى ضَعْفَنَا وَعَجْزَنَا فَطَيَّبَهَا لَنَا","id":"Telah menceritakan kepada kami [Abu Kuraib Muhammad bin Al 'Ala] telah menceritakan kepada kami [Ibnu Mubarak] dari [Ma'mar]. (dalam riwayat lain disebutkan) Telah menceritakan kepada kami [Muhammad bin Rafi'] sedangkan susunan redaksi hadits ini berasal dari dia, telah menceritakan kepada kami [Abdurrazaq] telah mengabarkan kepada kami [Ma'mar] dari [Hammam bin Munabbih] dia berkata, \"Ini adalah beberapa hadits yang pernah diceritakan oleh [Abu Hurairah] kepada kami dari Rasulullah shallallahu 'alaihi wasallam, lalu dia menyebutkan beberapa hadits yang di antaranya adalah, bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Dulu ada seorang Nabi dari para Nabi yang hendak berperang, lalu dia berkata kepada kaumnya: 'Janganlah ikut serta berperang bersamaku, yaitu orang yang telah menikah dan ingin menggauli isterinya, orang-orang yang sedang membangun rumah dan ia belum sempat menaikkan atapnya, atau orang yang telah membeli seekor kambing atau seekor unta bunting, sementara ia tengah menunggu kelahiran anak ternak tersebut'. Lalu Nabi tersebut berangkat berperang, menjelang waktu Ashar, ia telah sampai di suatu perkampungan, lalu dia berkata kepada Matahari: 'Hai Matahari, kamu diperintah dan aku pun diperintah'. Setelah itu dia berdo'a: 'Ya Allah, hentikanlah laju putaran matahari demi kepentingan urusanku'. Lalu matahari pun berhenti, hingga Allah dapat memenangkan mereka atas musuhnya. Setelah harta rampasan perang terkumpul menjadi satu, tiba-tiba api yang ingin menyambar harta rampasan tersebut tidak jadi menyambarnya. Lantas Nabi tersebut berkata, 'Di antara kalian pasti ada yang menyembunyikan harta rampasan, maka hendaklah setiap orang dari berbagai kabila berbaiat kepadaku!. Maka, mereka pun berbaiat kepada Nabi tersebut dengan menjabat tangannya. Lalu dia berkata lagi, 'Di antara kalian pasti ada yang menyembunyikan harta rampasan, hendaknya setiap kabilah berbaiat kepadaku!. lalu dia menjabat tangan dua orang laki-laki atau tiga orang laki-laki sekaligus, lantas Nabi tersebut berkata, 'Kalian telah menyembunyikan harta rampasan'.\" Rasulullah melanjutkan: \"Setelah itu mereka mengeluarkan seonggok emas sebesar kepala sapi dan menyerahkan kepada Nabi tersebut, lalu dia meletakkanya pada tumpukan harta rampasan yang berada di atas bukit. Tidak lama kemudian, api datang melahap harta rampasan tersebut.\" Setelah itu beliau bersabda: \"Harta rampasan perang itu sama sekali tidak dihalalkann bagi salah seorang sebelum kita, karena Allah mengetahui kelemahan dan kekurangan kita, akhirnya Allah menghalalkannya atas kita.\""},"3055":{"ar":"و حَدَّثَنَا قُتَيْبَةُ بْنُ سَعِيدٍ حَدَّثَنَا أَبُو عَوَانَةَ عَنْ سِمَاكٍ عَنْ مُصْعَبِ بْنِ سَعْدٍ عَنْ أَبِيهِ قَالَأَخَذَ أَبِي مِنْ الْخُمْسِ سَيْفًا فَأَتَى بِهِ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ هَبْ لِي هَذَا فَأَبَى فَأَنْزَلَ اللَّهُ عَزَّ وَجَلَّ{ يَسْأَلُونَكَ عَنْ الْأَنْفَالِ قُلْ الْأَنْفَالُ لِلَّهِ وَالرَّسُولِ }","id":"Dan telah menceritakan kepada kami [Qutaibah bin Sa'id] telah menceritakan kepada kami [Abu 'Awanah] dari [Simak] dari [Mush'ab bin Sa'd] dari [ayahnya] dia berkata, \"Ayahku, Sa'd, pernah mengambil pedang dari seperlima bagian ghanimah, lalu dia membawanya ke hadapan Nabi shallallahu 'alaihi wasallam. Ayahku berkata, \"Berikanlah pedang ini kepadaku.\" Namun Rasulullah enggan, maka Allah Azza Wa Jalla menurunkan ayat: \"Mereka menanyakan kepadamu tentang (pembagian) harta rampasan perang. Katakanlah, 'Harta rampasan perang kepunyaan Allah dan Rasul) ' (Qs. Al Anfaal: 1)."},"3056":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ الْمُثَنَّى وَابْنُ بَشَّارٍ وَاللَّفْظُ لِابْنِ الْمُثَنَّى قَالَا حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ حَدَّثَنَا شُعْبَةُ عَنْ سِمَاكِ بْنِ حَرْبٍ عَنْ مُصْعَبِ بْنِ سَعْدٍ عَنْ أَبِيهِ قَالَنَزَلَتْ فِيَّ أَرْبَعُ آيَاتٍ أَصَبْتُ سَيْفًا فَأَتَى بِهِ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ يَا رَسُولَ اللَّهِ نَفِّلْنِيهِ فَقَالَ ضَعْهُ ثُمَّ قَامَ فَقَالَ لَهُ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ضَعْهُ مِنْ حَيْثُ أَخَذْتَهُ ثُمَّ قَامَ فَقَالَ نَفِّلْنِيهِ يَا رَسُولَ اللَّهِ فَقَالَ ضَعْهُ فَقَامَ فَقَالَ يَا رَسُولَ اللَّهِ نَفِّلْنِيهِ أَؤُجْعَلُ كَمَنْ لَا غَنَاءَ لَهُ فَقَالَ لَهُ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ضَعْهُ مِنْ حَيْثُ أَخَذْتَهُ قَالَ فَنَزَلَتْ هَذِهِ الْآيَةُ{ يَسْأَلُونَكَ عَنْ الْأَنْفَالِ قُلْ الْأَنْفَالُ لِلَّهِ وَالرَّسُولِ }","id":"Telah menceritakan kepada kami [Muhammad bin Al Mutsanna] dan [Ibnu Basyar] sedangkan redaksi hadits ini lafadznya berasal dari Ibnu Mutsanna, keduanya berkata; telah menceritakan kepada kami [Muhammad bin Ja'far] telah menceritakan kepada kami [Syu'bah] dari [Simak bin Harb] dari [Mush'ab bin Sa'd] dari [ayahnya] dia berkata, \"Ada empat ayat Al Qur'an yang turun dan menyinggung tentangku; aku pernah mendapatkan sebilah pedang, lalu aku membawanya kepada Nabi shallallahu 'alaihi wasallam seraya kukatakan, 'Wahai Rasulullah, berikanlah pedang itu kepadaku sebagai ghanimah'. Maka Nabi shallallahu 'alaihi wasallam bersabda: \"Letakkanlah pedang itu pada tempat di mana kamu mengambilnya.\" Kemudian ayahku berdiri dan berkata, \"Wahai Rasulullah, berikanlah pedang ini kepadaku sebagai ghanimah.\" Maka beliau bersabda: \"Letakkanlah pedang itu.\" Rupanya ayahku tetap berdiri dan berkata, \"Wahai Rasulullah, berikanlah pedang itu kepadaku, niscaya aku akan memanfaatkan dengan sebaik-baiknya.\" Namun Nabi shallallahu 'alaihi wasallam tetap bersabda: \"Letakkanlah pedang itu pada tempat dimana kamu telah mengambilnya.\" Kemudian turunlah ayat berikut ini: '(Mereka menanyakan kepadamu tentang (pembagian) harta rampasan perang. Katakanlah: \"Harta rampasan perang kepunyaan Allah dan Rasul...) ' (Qs. Al Anfaal: 1)."},"3057":{"ar":"حَدَّثَنَا يَحْيَى بْنُ يَحْيَى قَالَ قَرَأْتُ عَلَى مَالِكٍ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَ قَالَبَعَثَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ سَرِيَّةً وَأَنَا فِيهِمْ قِبَلَ نَجْدٍ فَغَنِمُوا إِبِلًا كَثِيرَةً فَكَانَتْ سُهْمَانُهُمْ اثْنَا عَشَرَ بَعِيرًا أَوْ أَحَدَ عَشَرَ بَعِيرًا وَنُفِّلُوا بَعِيرًا بَعِيرًا","id":"Telah menceritakan kepada kami [Yahya bin Yahya] dia berkata; aku bacakan di hadapan [Malik]; dari [Nafi'] dari [Ibnu Umar] dia berkata, \"Nabi shallallahu 'alaihi wasallam pernah mengirim suatu pasukan ke negeri Najd, sedangkan aku termasuk dalam pasukan tersebut. Mereka kemudian memperoleh ghanimah berupa unta yang sangat banyak, sehingga masing-masing mereka mendapat bagian dua belas ekor atau sebelas ekor unta, bahkan setiap dari mereka mendapatkan tambahan satu ekor unta.\""},"3058":{"ar":"و حَدَّثَنَا قُتَيْبَةُ بْنُ سَعِيدٍ حَدَّثَنَا لَيْثٌ ح و حَدَّثَنَا مُحَمَّدُ بْنُ رُمْحٍ أَخْبَرَنَا اللَّيْثُ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بَعَثَ سَرِيَّةً قِبَلَ نَجْدٍ وَفِيهِمْ ابْنُ عُمَرَ وَأَنَّ سُهْمَانَهُمْ بَلَغَتْ اثْنَيْ عَشَرَ بَعِيرًا وَنُفِّلُوا سِوَى ذَلِكَ بَعِيرًا فَلَمْ يُغَيِّرْهُ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Dan telah menceritakan kepada kami [Qutaibah bin Sa'id] telah menceritakan kepada kami [Laits]. (dalam riwayat lain disebutkan) Telah menceritakan kepada kami [Muhammad bin Rumh] telah mengabarkan kepada kami [Laits] dari [Nafi'] dari [Ibnu Umar], bahwa Rasulullah shallallahu 'alaihi wasallam pernah mengirim suatu pasukan menuju daerah Najd, sedangkan Ibnu Umar termasuk dalam prajurit tersebut. Lalu pasukan tersebut mendapatkan ghanimah yang banyak sehingga masing-masing dari mereka mendapatkan dua belas unta dan masih ditambah dengan satu unta lagi untuk setiap prajurit, dan Rasulullah shallallahu 'alaihi wasallam tidak merubah ketetapan tersebut.\""},"3059":{"ar":"و حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا عَلِيُّ بْنُ مُسْهِرٍ وَعَبْدُ الرَّحِيمِ بْنُ سُلَيْمَانَ عَنْ عُبَيْدِ اللَّهِ بْنِ عُمَرَ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَ قَالَبَعَثَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ سَرِيَّةً إِلَى نَجْدٍ فَخَرَجْتُ فِيهَا فَأَصَبْنَا إِبِلًا وَغَنَمًا فَبَلَغَتْ سُهْمَانُنَا اثْنَيْ عَشَرَ بَعِيرًا اثْنَيْ عَشَرَ بَعِيرًا وَنَفَّلَنَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بَعِيرًا بَعِيرًاو حَدَّثَنَا زُهَيْرُ بْنُ حَرْبٍ وَمُحَمَّدُ بْنُ الْمُثَنَّى قَالَا حَدَّثَنَا يَحْيَى وَهُوَ الْقَطَّانُ عَنْ عُبَيْدِ اللَّهِ بِهَذَا الْإِسْنَادِ و حَدَّثَنَاه أَبُو الرَّبِيعِ وَأَبُو كَامِلٍ قَالَا حَدَّثَنَا حَمَّادٌ عَنْ أَيُّوبَ ح و حَدَّثَنَا ابْنُ الْمُثَنَّى حَدَّثَنَا ابْنُ أَبِي عَدِيٍّ عَنْ ابْنِ عَوْنٍ قَالَ كَتَبْتُ إِلَى نَافِعٍ أَسْأَلُهُ عَنْ النَّفَلِ فَكَتَبَ إِلَيَّ أَنَّ ابْنَ عُمَرَ كَانَ فِي سَرِيَّةٍ ح و حَدَّثَنَا ابْنُ رَافِعٍ حَدَّثَنَا عَبْدُ الرَّزَّاقِ أَخْبَرَنَا ابْنُ جُرَيْجٍ أَخْبَرَنِي مُوسَى ح و حَدَّثَنَا هَارُونُ بْنُ سَعِيدٍ الْأَيْلِيُّ حَدَّثَنَا ابْنُ وَهْبٍ أَخْبَرَنِي أُسَامَةُ بْنُ زَيْدٍ كُلُّهُمْ عَنْ نَافِعٍ بِهَذَا الْإِسْنَادِ نَحْوَ حَدِيثِهِمْ","id":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] telah menceritakan kepada kami [Ali bin Mushir] dan [Abdurrahim bin Sulaiman] dari [Ubaidullah bin Umar] dari [Nafi'] dari [Ibnu Umar] dia berkata, \"Rasulullah shallallahu 'alaihi wasallam pernah mengirim suatu utusan ke negeri Najd, dan aku termasuk dari prajurit tersebut, saat itu kami mendapatkan ghanimah banyak sekali sehingga setiap kita mendapatkan dua belas ekor unta, dan Rasulullah shallallahu 'alaihi wasallam masih menambahkan lagi satu ekor unta untuk setiap prajurit.\" Dan telah menceritakan kepada kami [Zuhair bin Harb] dan [Muhammad bin Al Mutsanna] keduanya berkata; telah menceritakan kepada kami [Yahya] -yaitu Al Qatthan- dari [Ubaidullah] dengan isnad ini.\" Dan telah menceritakan kepada kami [Abu Ar Rabi'] dan [Abu Kamil] keduanya berkata; telah menceritakan kepada kami [Hammad] dari [Ayyub]. (dalam riwayat lain disebutkan) Telah menceritakan kepada kami [Ibnu Al Mutsanna] telah menceritakan kepada kami [Ibnu Abu 'Adi] dari [Ibnu 'Aun] dia berkata, \"Aku pernah menulis surat kepada Nafi' untuk menanyakan perihal bagian dari harta rampasan perang, lalu dia membalas suratku bahwa Ibnu Umar pernah ikut dalam suatu pasukan. (dalam riwayat lain disebutkan) Telah menceritakan kepada kami [Ibnu Rafi'] telah menceritakan kepada kami [Abdurrazaq] telah mengabarkan kepada kami [Ibnu Juraij] telah mengabarkan kepadaku [Musa]. (dalam riwayat lain disebutkan) Telah menceritakan kepada kami [Harun bin Sa'id Al Aili] telah menceritakan kepada kami [Ibnu Wahb] telah mengabarkan kepadaku [Usamah bin Zaid] mereka semua dari [Nafi'] dengan sanad ini, seperti hadits mereka.\""},"3060":{"ar":"و حَدَّثَنَا سُرَيْجُ بْنُ يُونُسَ وَعَمْرٌو النَّاقِدُ وَاللَّفْظُ لِسُرَيْجٍ قَالَا حَدَّثَنَا عَبْدُ اللَّهِ بْنُ رَجَاءٍ عَنْ يُونُسَ عَنْ الزُّهْرِيِّ عَنْ سَالِمٍ عَنْ أَبِيهِ قَالَنَفَّلَنَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَفَلًا سِوَى نَصِيبِنَا مِنْ الْخُمْسِ فَأَصَابَنِي شَارِفٌ وَالشَّارِفُ الْمُسِنُّ الْكَبِيرُو حَدَّثَنَا هَنَّادُ بْنُ السَّرِيِّ حَدَّثَنَا ابْنُ الْمُبَارَكِ ح و حَدَّثَنِي حَرْمَلَةُ بْنُ يَحْيَى أَخْبَرَنَا ابْنُ وَهْبٍ كِلَاهُمَا عَنْ يُونُسَ عَنْ ابْنِ شِهَابٍ قَالَ بَلَغَنِي عَنْ ابْنِ عُمَرَ قَالَ نَفَّلَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ سَرِيَّةً بِنَحْوِ حَدِيثِ ابْنِ رَجَاءٍ","id":"Dan telah menceritakan kepada kami [Suraij bin Yunus] dan [Amru An Naqid] sedangkan lafadz haditnya dari Suraij, keduanya berkata; telah menceritakan kepada kami [Abdullah bin Raja`] dari [Yunus] dari [Az Zuhri] dari [Salim] dari [ayahnya] dia berkata, \"Rasulullah shallallahu 'alaihi wasallam pernah membagi harta rampasan perang selain dari bagian kita yang seperlima, saat itu aku mendapatkan jatah seekor unta -yaitu unta yang telah berumur-.\" Dan telah menceritakan kepada kami [Hannad bin As Sari] telah menceritakan kepada kami [Ibnu Mubarrak]. (dalam riwayat lain disebutkan) Telah menceritakan kepadaku [Harmalah bin Yahya] telah mengabarkan kepada kami [Ibnu Wahb] keduanya dari [Yunus] dari [Ibnu Syihab] dia berkata; [telah sampai kepadaku] dari [Ibnu Umar] dia berkata, \"Rasulullah shallallahu 'alaihi wasallam pernah membagi harta rampasan perang kepada prajurit...seperti hadits riwayat Ibnu Raja`.\""},"3061":{"ar":"و حَدَّثَنَا عَبْدُ الْمَلِكِ بْنُ شُعَيْبِ بْنِ اللَّيْثِ حَدَّثَنِي أَبِي عَنْ جَدِّي قَالَ حَدَّثَنِي عُقَيْلُ بْنُ خَالِدٍ عَنْ ابْنِ شِهَابٍ عَنْ سَالِمٍ عَنْ عَبْدِ اللَّهِأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَدْ كَانَ يُنَفِّلُ بَعْضَ مَنْ يَبْعَثُ مِنْ السَّرَايَا لِأَنْفُسِهِمْ خَاصَّةً سِوَى قَسْمِ عَامَّةِ الْجَيْشِ وَالْخُمْسُ فِي ذَلِكَ وَاجِبٌ كُلِّهِ","id":"Dan telah menceritakan kepada kami [Abdul Malik bin Shu'aib bin Laits] telah menceritakan kepadaku [ayahku] dari [kakekku] dia berkata; telah menceritakan kepadaku ['Uqail bin Khalid] dari [Ibnu Syihab] dari [Salim] dari [Abdullah], bahwa Rasulullah shallallahu 'alaihi wasallam pernah memberikan tambahan bagian dari harta rampasan perang kepada para anggota pasukan selain dari pembagian secara umum, sedangkan seperlima bagian dari seluruh harta rampasan wajib dibagikan.\""},"3062":{"ar":"حَدَّثَنَا يَحْيَى بْنُ يَحْيَى التَّمِيمِيُّ أَخْبَرَنَا هُشَيْمٌ عَنْ يَحْيَى بْنِ سَعِيدٍ عَنْ عُمَرَ بْنِ كَثِيرِ بْنِ أَفْلَحَ عَنْ أَبِي مُحَمَّدٍ الْأَنْصَارِيِّ وَكَانَ جَلِيسًا لِأَبِي قَتَادَةَ قَالَ قَالَ أَبُو قَتَادَةَ وَاقْتَصَّ الْحَدِيثَ و حَدَّثَنَا قُتَيْبَةُ بْنُ سَعِيدٍ حَدَّثَنَا لَيْثٌ عَنْ يَحْيَى بْنِ سَعِيدٍ عَنْ عُمَرَ بْنِ كَثِيرٍ عَنْ أَبِي مُحَمَّدٍ مَوْلَى أَبِي قَتَادَةَ أَنَّ أَبَا قَتَادَةَ قَالَ وَسَاقَ الْحَدِيثَ و حَدَّثَنَا أَبُو الطَّاهِرِ وَحَرْمَلَةُ وَاللَّفْظُ لَهُ أَخْبَرَنَا عَبْدُ اللَّهِ بْنُ وَهْبٍ قَالَ سَمِعْتُ مَالِكَ بْنَ أَنَسٍ يَقُولُ حَدَّثَنِي يَحْيَى بْنُ سَعِيدٍ عَنْ عُمَرَ بْنِ كَثِيرِ بْنِ أَفْلَحَ عَنْ أَبِي مُحَمَّدٍ مَوْلَى أَبِي قَتَادَةَ عَنْ أَبِي قَتَادَةَ قَالَخَرَجْنَا مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَامَ حُنَيْنٍ فَلَمَّا الْتَقَيْنَا كَانَتْ لِلْمُسْلِمِينَ جَوْلَةٌ قَالَ فَرَأَيْتُ رَجُلًا مِنْ الْمُشْرِكِينَ قَدْ عَلَا رَجُلًا مِنْ الْمُسْلِمِينَ فَاسْتَدَرْتُ إِلَيْهِ حَتَّى أَتَيْتُهُ مِنْ وَرَائِهِ فَضَرَبْتُهُ عَلَى حَبْلِ عَاتِقِهِ وَأَقْبَلَ عَلَيَّ فَضَمَّنِي ضَمَّةً وَجَدْتُ مِنْهَا رِيحَ الْمَوْتِ ثُمَّ أَدْرَكَهُ الْمَوْتُ فَأَرْسَلَنِي فَلَحِقْتُ عُمَرَ بْنَ الْخَطَّابِ فَقَالَ مَا لِلنَّاسِ فَقُلْتُ أَمْرُ اللَّهِ ثُمَّ إِنَّ النَّاسَ رَجَعُوا وَجَلَسَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ مَنْ قَتَلَ قَتِيلًا لَهُ عَلَيْهِ بَيِّنَةٌ فَلَهُ سَلَبُهُ قَالَ فَقُمْتُ فَقُلْتُ مَنْ يَشْهَدُ لِي ثُمَّ جَلَسْتُ ثُمَّ قَالَ مِثْلَ ذَلِكَ فَقَالَ فَقُمْتُ فَقُلْتُ مَنْ يَشْهَدُ لِي ثُمَّ جَلَسْتُ ثُمَّ قَالَ ذَلِكَ الثَّالِثَةَ فَقُمْتُ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَا لَكَ يَا أَبَا قَتَادَةَ فَقَصَصْتُ عَلَيْهِ الْقِصَّةَ فَقَالَ رَجُلٌ مِنْ الْقَوْمِ صَدَقَ يَا رَسُولَ اللَّهِ سَلَبُ ذَلِكَ الْقَتِيلِ عِنْدِي فَأَرْضِهِ مِنْ حَقِّهِ وَقَالَ أَبُو بَكْرٍ الصِّدِّيقُ لَا هَا اللَّهِ إِذًا لَا يَعْمِدُ إِلَى أَسَدٍ مِنْ أُسُدِ اللَّهِ يُقَاتِلُ عَنْ اللَّهِ وَعَنْ رَسُولِهِ فَيُعْطِيكَ سَلَبَهُ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ صَدَقَ فَأَعْطِهِ إِيَّاهُ فَأَعْطَانِي قَالَ فَبِعْتُ الدِّرْعَ فَابْتَعْتُ بِهِ مَخْرَفًا فِي بَنِي سَلِمَةَ فَإِنَّهُ لَأَوَّلُ مَالٍ تَأَثَّلْتُهُ فِي الْإِسْلَامِوَفِي حَدِيثِ اللَّيْثِ فَقَالَ أَبُو بَكْرٍ كَلَّا لَا يُعْطِيهِ أُضَيْبِعَ مِنْ قُرَيْشٍ وَيَدَعُ أَسَدًا مِنْ أُسُدِ اللَّهِ وَفِي حَدِيثِ اللَّيْثِ لَأَوَّلُ مَالٍ تَأَثَّلْتُهُ","id":"Telah menceritakan kepada kami [Yahya bin Yahya At Tamimi] telah mengabarkan kepada kami [Husyaim] dari [Yahya bin Sa'id] dari [Umar bin Katsir bin Aflah] dari [Abu Muhammad Al Anshari] -murid Abu Qatadah- ia berkata berkata; [Abu Qatadah] berkata; lalu ia menceritakan hadits.\" Dan telah menceritakan kepada kami [Qutaibah bin Sa'id] telah menceritakan kepada kami [Laits] dari [Yahya bin Sa'id] dari [Umar bin Katsir] dari [Abu Muhammad] bekas budak Abu Qatadah, bahwa [Abu Qatadah] berkata; lalu ia menyebutkan hadits tersebut.\" Dan telah menceritakan kepada kami.\" Dan telah menceritakan kepada kami [Abu At Thahir] dan [Harmalah] sedangkan redaksi lafadz haditsnya dari dia, telah mengabarkan kepada kami [Abdullah bin Wahb] dia berkata; aku mendengar [Malik bin Anas] berkata; telah menceritakan kepadaku [Yahya bin Sa'id] dari [Umar bin katsir bin Aflah] dari [Abu Muhammad] bekas budak Abu Qatadah, dari [Abu Qatadah] dia berkata, \"Kami pernah pergi berperang bersama Rasulullah shallallahu 'alaihi wasallam dalam pertempuran Hunain, tatkala kami berhadapan dengan musuh, maka sebagian kaum Muslimin mundur. Aku melihat seorang laki-laki Musyrik sedang menguasai seorang Muslim, aku langsung berbalik sehingga aku dapat mendatanginya dari arah belakang. Kemudian aku penggal batang lehernya, akan tetapi seorang Musyrik tersebut berbalik kepadaku dan merangkulku dengan kuat, aku tahu kalau dia hampir mati, setelah dia tewas, baru aku dilepaskan. Setelah itu aku bertemu dengan Umar bin Khattab, dia bertanya kepadaku, \"Bagaimana kondisi pasukan?\" aku menjawab, \"Itu urusan Allah.\" Kemudian orang-orang kembali, sementara Rasulullah shallallahu 'alaihi wasallam duduk seraya bersabda: \"Barangsiapa dapat membunuh seorang musuh, sedangkan dia memiliki seorang saksi, maka segenap perlengkapan si terbunuh boleh dimilikinya.\" Aku langsung berdiri dan berkata, \"Siapa yang mau menjadi saksiku?\" kemudian aku duduk kembali, dan Rasulullah shallallahu 'alaihi wasallam kembali bersabda seperti tadi. Lalu aku berdiri lagi sambil berkata, \"Siapa yang mau menjadi saksi bagiku?\" kemudian aku duduk kembali, dan beliau bersabda seperti itu untuk ketiga kalinya, maka aku pun berdiri kembali. Rasulullah shallallahu 'alaihi wasallam lalu bertanya kepadaku: \"Apa apa denganmu wahai Abu Qatadah?\" lalu aku ceritakan kisah bagaimana aku telah membunuhh seorang musuh. Seorang anggota pasukan lantas angkat bicara, 'Abu Qatadah benar wahai Rasulullah! sedangkan perlengkapan orang yang dibunuhnya berada di tanganku, oleh karena itu suruhlah dia merelakan haknya untukku'. Abu Bakar berkata, \"Jangan, demi Allah, tidaklah singa dari singa-singa Allah yang berjuang membela-Nya dan rasul-Nya, lalu harta rampasannya diberikan kepamu.\" Maka Rasulullah shallallahu 'alaihi wasallam bersabda: \"Hal itu benar, oleh karena itu, berikanlah kepada Abu Qatadah apa telah yang menjadi haknya.\" Kemudian baju besinya aku jual, lalu aku belikan sebidang kebun di perkebunan Bani Salamah. Itulah harta yang aku peroleh di awal-awal Islamku.\" Dan dalam hadits Laits disebutkan; Abu Bakar berkata, \"Sekali-kali tidak, (Allah) tidak memberikannya dengan maksud menyepelekan orang quraiys dan meninggalkan hak-hak singa dari singa-singa Allah.\" Dan dalam hadits Al Laits disebutkan, 'harta pertama yang aku dapatkan dalam Islam'.\""},"3063":{"ar":"حَدَّثَنَا يَحْيَى بْنُ يَحْيَى التَّمِيمِيُّ أَخْبَرَنَا يُوسُفُ بْنُ الْمَاجِشُونِ عَنْ صَالِحِ بْنِ إِبْرَاهِيمَ بْنِ عَبْدِ الرَّحْمَنِ بْنِ عَوْفٍ عَنْ أَبِيهِ عَنْ عَبْدِ الرَّحْمَنِ بْنِ عَوْفٍ أَنَّهُ قَالَبَيْنَا أَنَا وَاقِفٌ فِي الصَّفِّ يَوْمَ بَدْرٍ نَظَرْتُ عَنْ يَمِينِي وَشِمَالِي فَإِذَا أَنَا بَيْنَ غُلَامَيْنِ مِنْ الْأَنْصَارِ حَدِيثَةٍ أَسْنَانُهُمَا تَمَنَّيْتُ لَوْ كُنْتُ بَيْنَ أَضْلَعَ مِنْهُمَا فَغَمَزَنِي أَحَدُهُمَا فَقَالَ يَا عَمِّ هَلْ تَعْرِفُ أَبَا جَهْلٍ قَالَ قُلْتُ نَعَمْ وَمَا حَاجَتُكَ إِلَيْهِ يَا ابْنَ أَخِي قَالَ أُخْبِرْتُ أَنَّهُ يَسُبُّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَالَّذِي نَفْسِي بِيَدِهِ لَئِنْ رَأَيْتُهُ لَا يُفَارِقُ سَوَادِي سَوَادَهُ حَتَّى يَمُوتَ الْأَعْجَلُ مِنَّا قَالَ فَتَعَجَّبْتُ لِذَلِكَ فَغَمَزَنِي الْآخَرُ فَقَالَ مِثْلَهَا قَالَ فَلَمْ أَنْشَبْ أَنْ نَظَرْتُ إِلَى أَبِي جَهْلٍ يَزُولُ فِي النَّاسِ فَقُلْتُ أَلَا تَرَيَانِ هَذَا صَاحِبُكُمَا الَّذِي تَسْأَلَانِ عَنْهُ قَالَ فَابْتَدَرَاهُ فَضَرَبَاهُ بِسَيْفَيْهِمَا حَتَّى قَتَلَاهُ ثُمَّ انْصَرَفَا إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَخْبَرَاهُ فَقَالَ أَيُّكُمَا قَتَلَهُ فَقَالَ كُلُّ وَاحِدٍ مِنْهُمَا أَنَا قَتَلْتُ فَقَالَ هَلْ مَسَحْتُمَا سَيْفَيْكُمَا قَالَا لَا فَنَظَرَ فِي السَّيْفَيْنِ فَقَالَ كِلَاكُمَا قَتَلَهُ وَقَضَى بِسَلَبِهِ لِمُعَاذِ بْنِ عَمْرِو بْنِ الْجَمُوحِ وَالرَّجُلَانِ مُعَاذُ بْنُ عَمْرِو بْنِ الْجَمُوحِ وَمُعَاذُ بْنُ عَفْرَاءَ","id":"Telah menceritakan kepada kami [Yahya bin Yahya At Tamimi] telah mengabarkan kepada kami [Yusuf bin Al Majisyun] dari [Shalih bin Ibrahim bin Abdurrahman bin Auf] dari [ayahnya] dari [Abdurrahman bin Auf] bahwa dia berkata, \"Ketika aku berdiri dalam barisan tentara pada saat perang Badar, aku melihat ke samping kanan dan kiriku, ternyata aku berada di antara dua anak muda dari kaum anshar, padahal sebelumnya aku berangan-angan berada di antara dua orang yang lebih kuat daripada mereka berdua. Kemudian salah seorang dari keduanya memberi isyarat kepadaku dengan matanya seraya berkata, \"Wahai paman, apakah paman mengetahui orang yang bernama Abu Jahal?\" Aku menjawab, \"Ya, lantas apa keperluanmu dengannya wahai anak saudaraku?\" dia menjawab, \"Aku mendapat kabar bahwa ia telah mencela Rasulullah shallallahu 'alaihi wasallam, demi Dzat yang jiwaku berada di tangan-Nya, jika aku melihatnya maka aku tidak akan berpisah darinya sampai ada di antara kami yang menemui ajalnya.\" Abdurrahman melanjutkan, \"Aku pun terkejut mendengarnya. Lalu seorang lainnya memberi isyarat kepadaku dengan matanya seraya bertanya dengan pertanyaan yang sama. Tidak lama setelah itu, aku melihat Abu Jahal bergerak di antara kerumunan orang-orang sehingga aku berkata kepada keduanya, \"Tidakkah kalian lihat, itulah orang yang kalian tanyakan kepadaku tadi.\" Abdurrahman melanjutkan, \"Setelah itu mereka berdua segera memburunya dan memukulkan pedang mereka hingga akhirnya mereka berdua dapat membunuh Abu Jahal. Setelah membunhnya, keduanya kembali menemui Rasulullah shallallahu 'alaihi wasallam dan memberitahukan kepada beliau, maka beliau pun bertanya: 'Siapakah di antara kalian berdua yang telah membunuhnya? ' masing-masing dari mereka menjawab, 'Akulah yang telah membunuhnya! ' Beliau bersabda: 'Apakah kalian berdua telah membersihkan pedang kalian? ' Mereka berkata, 'Belum.' Beliaupun melihat kedua pedang itu sambil bersabda: 'Kalian berdua telah membunuhnya.' Kemudian beliau memberikan harta yang diambil dari musuh yang terbunuh kepada Mu'adz bin 'Amru bin Jamuh. Sedangkan kedua anak muda itu adalah Mu'adz bin 'Amru bin Jamuh dan Mu'adz bin 'Afra.\""},"3064":{"ar":"و حَدَّثَنِي أَبُو الطَّاهِرِ أَحْمَدُ بْنُ عَمْرِو بْنِ سَرْحٍ أَخْبَرَنَا عَبْدُ اللَّهِ بْنُ وَهْبٍ أَخْبَرَنِي مُعَاوِيَةُ بْنُ صَالِحٍ عَنْ عَبْدِ الرَّحْمَنِ بْنِ جُبَيْرٍ عَنْ أَبِيهِ عَنْ عَوْفِ بْنِ مَالِكٍ قَالَقَتَلَ رَجُلٌ مِنْ حِمْيَرَ رَجُلًا مِنْ الْعَدُوِّ فَأَرَادَ سَلَبَهُ فَمَنَعَهُ خَالِدُ بْنُ الْوَلِيدِ وَكَانَ وَالِيًا عَلَيْهِمْ فَأَتَى رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَوْفُ بْنُ مَالِكٍ فَأَخْبَرَهُ فَقَالَ لِخَالِدٍ مَا مَنَعَكَ أَنْ تُعْطِيَهُ سَلَبَهُ قَالَ اسْتَكْثَرْتُهُ يَا رَسُولَ اللَّهِ قَالَ ادْفَعْهُ إِلَيْهِ فَمَرَّ خَالِدٌ بِعَوْفٍ فَجَرَّ بِرِدَائِهِ ثُمَّ قَالَ هَلْ أَنْجَزْتُ لَكَ مَا ذَكَرْتُ لَكَ مِنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَسَمِعَهُ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَاسْتُغْضِبَ فَقَالَ لَا تُعْطِهِ يَا خَالِدُ لَا تُعْطِهِ يَا خَالِدُ هَلْ أَنْتُمْ تَارِكُونَ لِي أُمَرَائِي إِنَّمَا مَثَلُكُمْ وَمَثَلُهُمْ كَمَثَلِ رَجُلٍ اسْتُرْعِيَ إِبِلًا أَوْ غَنَمًا فَرَعَاهَا ثُمَّ تَحَيَّنَ سَقْيَهَا فَأَوْرَدَهَا حَوْضًا فَشَرَعَتْ فِيهِ فَشَرِبَتْ صَفْوَهُ وَتَرَكَتْ كَدْرَهُ فَصَفْوُهُ لَكُمْ وَكَدْرُهُ عَلَيْهِمْو حَدَّثَنِي زُهَيْرُ بْنُ حَرْبٍ حَدَّثَنَا الْوَلِيدُ بْنُ مُسْلِمٍ حَدَّثَنَا صَفْوَانُ بْنُ عَمْرٍو عَنْ عَبْدِ الرَّحْمَنِ بْنِ جُبَيْرِ بْنِ نُفَيْرٍ عَنْ أَبِيهِ عَنْ عَوْفِ بْنِ مَالِكٍ الْأَشْجَعِيِّ قَالَ خَرَجْتُ مَعَ مَنْ خَرَجَ مَعَ زَيْدِ بْنِ حَارِثَةَ فِي غَزْوَةِ مُؤْتَةَ وَرَافَقَنِي مَدَدِيٌّ مِنْ الْيَمَنِ وَسَاقَ الْحَدِيثَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِنَحْوِهِ غَيْرَ أَنَّهُ قَالَ فِي الْحَدِيثِ قَالَ عَوْفٌ فَقُلْتُ يَا خَالِدُ أَمَا عَلِمْتَ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَضَى بِالسَّلَبِ لِلْقَاتِلِ قَالَ بَلَى وَلَكِنِّي اسْتَكْثَرْتُهُ","id":"Dan telah menceritakan kepadaku [Abu At Thahir Ahmad bin 'Amru bin Sarh] telah mengabarkan kepada kami [Abdullah bin Wahb] telah mengabarkan kepadaku [Mu'awiyah bin Shalih] dari [Abdurrahman bin Jubair] dari [ayahnya] dari ['Auf bin Malik] dia berkata, \"Seorang laki-laki dari suku Himyar telah membunuh seorang musuh, lalu dia hendak mengambil harta dari musuh yang dibunuhnya, namun Khalid bin Walid mencegahnya, sebab dia adalah panglima dari laki-laki itu. Lalu 'Auf bin Malik melaporkan kepada Rasulullah shallallahu 'alaihi wasallam, maka beliau bersabda: \"Apa alasanmu untuk tidak memberikan harta rampasannya?\" Khlaid menjawab, \"Dia sudah banyak aku beri wahai Rasulullah!\" Beliau bersabda: \"Berikanlah dia bagiannya!\" Suatu ketika Khalid lewat di hadapan 'Auf, lalu 'Auf menarik kainnya dengan keras sambil berkata, \"Apakah kamu tidak mendengar apa yang aku sampaikan dari putusan Rasulullah shallallahu 'alaihi wasallam? Ternyata Rasulullah shallallahu 'alaihi wasallam mendengar perkataanya 'Auf, lantas beliau marah kepadanya seraya bersabda: \"Wahai Khalid, janganlah kamu memberinya, jangan kamu memberinya!\" Kemudian beliau bersabda kepada 'Auf: \"Mengapa tidak kamu serahkan saja kepadaku urusan dengan panglima-panglima yang aku angkat? Hanyasanya perumpamaanmu dengan perumpamaan mereka seperti penggembala unta atau kambing dengan hewan gembalaannya, bila waktu minum telah tiba, hewan-hewan itu dibawanya ke telaga, hewan-hewan tersebut lalu masuk ke dalam telaga dan meminum air yang bersih, hingga tinggalah air yang kotor. Air bersih untuk kalian dan air kotor untuk mereka.\" Telah menceritakan kepadaku [Zuhair bin Harb] telah menceritakan kepada kami [Al Walid bin Muslim] telah menceritakan kepada kami [Shafwan bin 'Amru] dari [Abdurrahman bin Jubair bin Nufair] dari [ayahnya] dari ['Auf bin Malik Al Asyja'i] dia berkata; aku keluar bersama Zaid bin Haritsah pada peperangan Mu'tah, tiba-tiba sekelompok tentara dari Yaman datang untuk membantuku…kemudian dia melanjutkan hadits tersebut sebagaimana hadits di atas, namun dalam hadits tersebut disebutkan, \" [Auf] berkata, 'Maka aku berkata, 'Wahai [Khalid], apakah kamu tidak tahu bahwa Rasulullah shallallahu 'alaihi wasallam telah memutuskan bagi seorang yang membunuh akan mendapatkan barang rampasan musuh yang di bunuhnya? Khalid menjawab, \"Ya, namun aku telah banyak memberi.\""},"3065":{"ar":"حَدَّثَنَا زُهَيْرُ بْنُ حَرْبٍ حَدَّثَنَا عُمَرُ بْنُ يُونُسَ الْحَنَفِيُّ حَدَّثَنَا عِكْرِمَةُ بْنُ عَمَّارٍ حَدَّثَنِي إِيَاسُ بْنُ سَلَمَةَ حَدَّثَنِي أَبِي سَلَمَةُ بْنُ الْأَكْوَعِ قَالَغَزَوْنَا مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ هَوَازِنَ فَبَيْنَا نَحْنُ نَتَضَحَّى مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذْ جَاءَ رَجُلٌ عَلَى جَمَلٍ أَحْمَرَ فَأَنَاخَهُ ثُمَّ انْتَزَعَ طَلَقًا مِنْ حَقَبِهِ فَقَيَّدَ بِهِ الْجَمَلَ ثُمَّ تَقَدَّمَ يَتَغَدَّى مَعَ الْقَوْمِ وَجَعَلَ يَنْظُرُ وَفِينَا ضَعْفَةٌ وَرِقَّةٌ فِي الظَّهْرِ وَبَعْضُنَا مُشَاةٌ إِذْ خَرَجَ يَشْتَدُّ فَأَتَى جَمَلَهُ فَأَطْلَقَ قَيْدَهُ ثُمَّ أَنَاخَهُ وَقَعَدَ عَلَيْهِ فَأَثَارَهُ فَاشْتَدَّ بِهِ الْجَمَلُ فَاتَّبَعَهُ رَجُلٌ عَلَى نَاقَةٍ وَرْقَاءَ قَالَ سَلَمَةُ وَخَرَجْتُ أَشْتَدُّ فَكُنْتُ عِنْدَ وَرِكِ النَّاقَةِ ثُمَّ تَقَدَّمْتُ حَتَّى كُنْتُ عِنْدَ وَرِكِ الْجَمَلِ ثُمَّ تَقَدَّمْتُ حَتَّى أَخَذْتُ بِخِطَامِ الْجَمَلِ فَأَنَخْتُهُ فَلَمَّا وَضَعَ رُكْبَتَهُ فِي الْأَرْضِ اخْتَرَطْتُ سَيْفِي فَضَرَبْتُ رَأْسَ الرَّجُلِ فَنَدَرَ ثُمَّ جِئْتُ بِالْجَمَلِ أَقُودُهُ عَلَيْهِ رَحْلُهُ وَسِلَاحُهُ فَاسْتَقْبَلَنِي رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَالنَّاسُ مَعَهُ فَقَالَ مَنْ قَتَلَ الرَّجُلَ قَالُوا ابْنُ الْأَكْوَعِ قَالَ لَهُ سَلَبُهُ أَجْمَعُ","id":"Telah menceritakan kepada kami [Zuhair bin Harb] telah menceritakan kepada kami [Umar bin Yunus Al Hanafi] telah menceritakan kepada kami [Ikrimah bin 'Amar] telah menceritakan kepadaku [Iyyas bin Salamah] telah menceritakan kepadaku [Abu Salamah bin Al Akwa'] dia berkata, \"Aku pernah ikut berperang bersama dengan Rasulullah shallallahu 'alaihi wasallam ke wilayah Hawazin. Ketika kami sedang makan siang bersama Rasulullah shallallahu 'alaihi wasallam, tiba-tiba datang seorang laki-laki yang mengendarai seekor unta yang berwarna merah. Setelah menderumkan unta dan melepaskan tali pengikatnya, laki-laki itu lalu ikut makan bersama kami -dengan melirik kesana kemari- selesai makan, sebagian di antara kami ada yang beristirahat karena meresa lelah setelah beberapa hari berada di atas kendaraanya, terlebih lagi bagi sebagian kami yang berjalan kami, tentunya lebih merasa lelah sekali. Tidak lama kemudian, lelaki itu berjalan keluar menuju kendaraan untanya dengan tergesa-gesa, setelah melepaskan tali ikatnya, ia naik ke atas punggung untanya seraya menariknya agar segera berlari dengan cepat. Tanpa kami sadari, rupanya ada seorang laki-laki lain yang mengendarai seekor unta berwarna kelabu tengah membuntutinya dari belakang. Salamah berkata, \"Lantas aku bergegas keluar untuk menyusulnya dari belakang dengan mengendarai seekor unta, kemudian aku mengejarnya hingga aku dekat dengan untanya, hingga ketika aku berada di belakang untanya, aku langsung memegang tali kekang unta tersebut. Ketika aku berhasil menderumkan untanya dan kaki laki-laki tersebut menyentuh tanah, maka aku langsung menghunuskan pedang dan menebasnya hingga ia mati terkapar. Kemudian aku kembali dengan mengendarai unta sambil menuntun unta dan harta benda milik lelaki yang terbunuh itu. Ternyata Rasulullah shallallahu 'alaihi wasallam dan para sahabatnya menyambut kedatanganku, beliau bersabda: \"Siapakah yang membunuh laki-laki itu?\" para sahabat menjawab, \"Ibnu Akwa'.\" Beliau bersabda: \"Dengan demikian, dia berhak mendapatkan seluruh harta orang yang di bunuhnya itu.\""},"3066":{"ar":"حَدَّثَنَا زُهَيْرُ بْنُ حَرْبٍ حَدَّثَنَا عُمَرُ بْنُ يُونُسَ حَدَّثَنَا عِكْرِمَةُ بْنُ عَمَّارٍ حَدَّثَنِي إِيَاسُ بْنُ سَلَمَةَ حَدَّثَنِي أَبِي قَالَغَزَوْنَا فَزَارَةَ وَعَلَيْنَا أَبُو بَكْرٍ أَمَّرَهُ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَلَيْنَا فَلَمَّا كَانَ بَيْنَنَا وَبَيْنَ الْمَاءِ سَاعَةٌ أَمَرَنَا أَبُو بَكْرٍ فَعَرَّسْنَا ثُمَّ شَنَّ الْغَارَةَ فَوَرَدَ الْمَاءَ فَقَتَلَ مَنْ قَتَلَ عَلَيْهِ وَسَبَى وَأَنْظُرُ إِلَى عُنُقٍ مِنْ النَّاسِ فِيهِمْ الذَّرَارِيُّ فَخَشِيتُ أَنْ يَسْبِقُونِي إِلَى الْجَبَلِ فَرَمَيْتُ بِسَهْمٍ بَيْنهُمْ وَبَيْنَ الْجَبَلِ فَلَمَّا رَأَوْا السَّهْمَ وَقَفُوا فَجِئْتُ بِهِمْ أَسُوقُهُمْ وَفِيهِمْ امْرَأَةٌ مِنْ بَنِي فَزَارَةَ عَلَيْهَا قَشْعٌ مِنْ أَدَمٍ قَالَ الْقَشْعُ النِّطَعُ مَعَهَا ابْنَةٌ لَهَا مِنْ أَحْسَنِ الْعَرَبِ فَسُقْتُهُمْ حَتَّى أَتَيْتُ بِهِمْ أَبَا بَكْرٍ فَنَفَّلَنِي أَبُو بَكْرٍ ابْنَتَهَا فَقَدِمْنَا الْمَدِينَةَ وَمَا كَشَفْتُ لَهَا ثَوْبًا فَلَقِيَنِي رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي السُّوقِ فَقَالَ يَا سَلَمَةُ هَبْ لِي الْمَرْأَةَ فَقُلْتُ يَا رَسُولَ اللَّهِ وَاللَّهِ لَقَدْ أَعْجَبَتْنِي وَمَا كَشَفْتُ لَهَا ثَوْبًا ثُمَّ لَقِيَنِي رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِنْ الْغَدِ فِي السُّوقِ فَقَالَ لِي يَا سَلَمَةُ هَبْ لِي الْمَرْأَةَ لِلَّهِ أَبُوكَ فَقُلْتُ هِيَ لَكَ يَا رَسُولَ اللَّهِ فَوَاللَّهِ مَا كَشَفْتُ لَهَا ثَوْبًا فَبَعَثَ بِهَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِلَى أَهْلِ مَكَّةَ فَفَدَى بِهَا نَاسًا مِنْ الْمُسْلِمِينَ كَانُوا أُسِرُوا بِمَكَّةَ","id":"Telah menceritakan kepada kami [Zuhair bin Harb] telah menceritakan kepada kami [Umar bin Yunus] telah menceritakan kepada kami [Ikrimah bin 'Ammar] telah menceritakan kepadaku [Iyas bin Salamah] telah menceritakan kepadaku [ayahku] dia berkata, \"Aku pernah ikut berperang di wilayah Fazarah di bawah komando Abu Bakar yang telah diangkat Rasulullah shallallahu 'alaihi wasallam untuk memimpin kami. Ketika jarak ke mata air hanya membutuhkan waktu beberapa saat, maka Abu Bakar memerintahkan kami agar beristirahat sejenak sambil mengarahkan strategi penyerangan, bagaimana seharusnya mendekati mata air tersebut dan menyerang serta menawan tawanan. Lalu aku sempat melihat di antara mereka (musuh) ada tawanan dari anak-anak dan wanita. Karena merasa khawatir mereka akan mendaki gunung terlebih dahulu, maka aku menghujani dengan anak panah ke arah rombongan musuh yang berada di sekitar gunung. Begitu melihat anah panah melesat ke arah mereka, mereka pun berhenti dan aku pun meringkus mereka. Ternyata di antara mereka terdapat seorang wanita dari Bani Fazarah yang mengenakan penutup kepala yang terbuat dari kulit, ditemani dengan anak gadisnya yang cantik rupawan di antara bangsa Arab. Kemudian aku menyerahkannya kepada Abu Bakar, lalu Abu Bakar memberikan anak gadisnya kepadaku sebagai harta ghanimah. Setelah itu kami pulang dan tiba di Madinah, dan aku juga belum sempat menggauli gadis tersebut. Ketika aku berada di pasar, aku berjumpa dengan Rasulullah shallallahu 'alaihi wasallam, beliau langsung bersabda kepadaku: \"Wahai Abu Salamah, berikanlah anak gadis kemarin kepadaku!\" Maka aku menjawab, \"Wahai Rasulullah, demi Allah sungguh ia telah menakjubkanku, namun aku belum sempat menggaulinya.\" Kemudian di esok harinya, Rasulullah shallallahu 'alaihi wasallam menemuiku di pasar seraya bersabda kepadaku: \"Wahai Salamah, berikanlah anak gadis kemarin kepadaku!\" Maka aku berkata, \"Dia untukmu wahai Rasulullah, demi Allah aku belum pernah menggaulinya.\" Kemudian Rasulullah shallallahu 'alaihi wasallam mengirimkan gadis tersebut ke Makkah sebagai tebusan pasukan kaum Muslimin yang tengah ditawan di sana.\""},"3067":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ حَنْبَلٍ وَمُحَمَّدُ بْنُ رَافِعٍ قَالَا حَدَّثَنَا عَبْدُ الرَّزَّاقِ أَخْبَرَنَا مَعْمَرٌ عَنْ هَمَّامِ بْنِ مُنَبِّهٍ قَالَ هَذَا مَا حَدَّثَنَا أَبُو هُرَيْرَةَ عَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَذَكَرَ أَحَادِيثَ مِنْهَا وَقَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَيُّمَا قَرْيَةٍ أَتَيْتُمُوهَا وَأَقَمْتُمْ فِيهَا فَسَهْمُكُمْ فِيهَا وَأَيُّمَا قَرْيَةٍ عَصَتْ اللَّهَ وَرَسُولَهُ فَإِنَّ خُمُسَهَا لِلَّهِ وَلِرَسُولِهِ ثُمَّ هِيَ لَكُمْ","id":"Telah menceritakan kepada kami [Ahmad bin Hanbal] dan [Muhammad bin Rafi'] kemduanya berkata; telah menceritakan kepada kami [Abdurrazaq] telah mengabarkan kepada kami [Ma'mar] dari [Hammam bin Munabbih] dia berkata; hal ini sebagaimana yang pernah diceritakan oleh [Abu Hurairah] kepada kami dari Rasulullah shallallahu 'alaihi wasallam, kemudian dia menyebutkan beberapa hadits yang di antaranya adalah, bahwa Abu Hurairah berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Negeri mana saja yang kalian taklukkan tanpa pertempuran, maka kalian mendapatkan bagian atas harta rampasannya, dan negeri mana saja yang kalian taklukan dengan peperangan, maka seperlima harta rampasanya untuk Allah dan Rasul-Nya, kemudian sisanya untuk kalian semua.\""},"3068":{"ar":"حَدَّثَنَا قُتَيْبَةُ بْنُ سَعِيدٍ وَمُحَمَّدُ بْنُ عَبَّادٍ وَأَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ وَإِسْحَقُ بْنُ إِبْرَاهِيمَ وَاللَّفْظُ لِابْنِ أَبِي شَيْبَةَ قَالَ إِسْحَقُ أَخْبَرَنَا و قَالَ الْآخَرُونَ حَدَّثَنَا سُفْيَانُ عَنْ عَمْرٍو عَنْ الزُّهْرِيِّ عَنْ مَالِكِ بْنِ أَوْسٍ عَنْ عُمَرَ قَالَكَانَتْ أَمْوَالُ بَنِي النَّضِيرِ مِمَّا أَفَاءَ اللَّهُ عَلَى رَسُولِهِ مِمَّا لَمْ يُوجِفْ عَلَيْهِ الْمُسْلِمُونَ بِخَيْلٍ وَلَا رِكَابٍ فَكَانَتْ لِلنَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ خَاصَّةً فَكَانَ يُنْفِقُ عَلَى أَهْلِهِ نَفَقَةَ سَنَةٍ وَمَا بَقِيَ يَجْعَلُهُ فِي الْكُرَاعِ وَالسِّلَاحِ عُدَّةً فِي سَبِيلِ اللَّهِحَدَّثَنَا يَحْيَى بْنُ يَحْيَى قَالَ أَخْبَرَنَا سُفْيَانُ بْنُ عُيَيْنَةَ عَنْ مَعْمَرٍ عَنْ الزُّهْرِيِّ بِهَذَا الْإِسْنَادِ","id":"Telah menceritakan kepada kami [Qutaibah bin Sa'id] dan [Muhammad bin 'Abbad] dan [Abu Bakar bin Abu Syaibah] dan [Ishaq bin Ibrahim] dan ini adalah lafadz Ibnu Abu Syaibah, Ishaq berkata; telah mengabarkan kepada kami, sedangkan yang lainnya mengatakan; telah menceritakan kepada kami [Sufyan] dari ['Amru] dari [Az Zuhri] dari [Malik bin Aus] dari [Umar] dia berkata, \"Harta benda bani Nadlir adalah fai' (harta rampasan) yang Allah berikan kepada Rasul-Nya tanpa mengharuskan kaum Muslimin untuk mengarahkan seekor kuda atau unta pun (untuk berperang). Hal itu khusus diberikan untuk Nabi shallallahu 'alaihi wasallam, dari fai' tersebut beliau memberi nafkah kepada keluarganya selama setahun, selebihnya beliau berikan untuk persiapan kendaraan dan persenjataan dalam jihad fi sabilillah.\" Telah menceritakan kepada kami [Yahya bin Yahya] dia berkata; telah mengabarkan kepada kami [Sufyan bin 'Uyainah] dari [Ma'mar] dari [Az Zuhri] dengan isnad ini.\""},"3069":{"ar":"و حَدَّثَنِي عَبْدُ اللَّهِ بْنُ مُحَمَّدِ بْنِ أَسْمَاءَ الضُّبَعِيُّ حَدَّثَنَا جُوَيْرِيَةُ عَنْ مَالِكٍ عَنْ الزُّهْرِيِّ أَنَّ مَالِكَ بْنَ أَوْسٍ حَدَّثَهُ قَالَ أَرْسَلَ إِلَيَّ عُمَرُ بْنُ الْخَطَّابِ فَجِئْتُهُ حِينَ تَعَالَى النَّهَارُ قَالَ فَوَجَدْتُهُ فِي بَيْتِهِ جَالِسًا عَلَى سَرِيرٍ مُفْضِيًا إِلَى رُمَالِهِ مُتَّكِئًا عَلَى وِسَادَةٍ مِنْ أَدَمٍ فَقَالَ لِي يَا مَالُ إِنَّهُ قَدْ دَفَّ أَهْلُ أَبْيَاتٍ مِنْ قَوْمِكَ وَقَدْ أَمَرْتُ فِيهِمْ بِرَضْخٍ فَخُذْهُ فَاقْسِمْهُ بَيْنَهُمْ قَالَ قُلْتُ لَوْ أَمَرْتَ بِهَذَا غَيْرِي قَالَ خُذْهُ يَا مَالُ قَالَ فَجَاءَ يَرْفَا فَقَالَ هَلْ لَكَ يَا أَمِيرَ الْمُؤْمِنِينَ فِي عُثْمَانَ وَعَبْدِ الرَّحْمَنِ بْنِ عَوْفٍ وَالزُّبَيْرِ وَسَعْدٍ فَقَالَ عُمَرُ نَعَمْ فَأَذِنَ لَهُمْ فَدَخَلُوا ثُمَّ جَاءَ فَقَالَ هَلْ لَكَ فِي عَبَّاسٍ وَعَلِيٍّ قَالَ نَعَمْ فَأَذِنَ لَهُمَا فَقَالَ عَبَّاسٌ يَا أَمِيرَ الْمُؤْمِنِينَ اقْضِ بَيْنِي وَبَيْنَ هَذَا الْكَاذِبِ الْآثِمِ الْغَادِرِ الْخَائِنِ فَقَالَ الْقَوْمُ أَجَلْ يَا أَمِيرَ الْمُؤْمِنِينَ فَاقْضِ بَيْنَهُمْ وَأَرِحْهُمْ فَقَالَ مَالِكُ بْنُ أَوْسٍ يُخَيَّلُ إِلَيَّ أَنَّهُمْ قَدْ كَانُوا قَدَّمُوهُمْ لِذَلِكَفَقَالَ عُمَرُ اتَّئِدَا أَنْشُدُكُمْ بِاللَّهِ الَّذِي بِإِذْنِهِ تَقُومُ السَّمَاءُ وَالْأَرْضُ أَتَعْلَمُونَ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَا نُورَثُ مَا تَرَكْنَا صَدَقَةٌ قَالُوا نَعَمْ ثُمَّ أَقْبَلَ عَلَى الْعَبَّاسِ وَعَلِيٍّ فَقَالَ أَنْشُدُكُمَا بِاللَّهِ الَّذِي بِإِذْنِهِ تَقُومُ السَّمَاءُ وَالْأَرْضُ أَتَعْلَمَانِ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَا نُورَثُ مَا تَرَكْنَاهُ صَدَقَةٌ قَالَا نَعَمْ فَقَالَ عُمَرُ إِنَّ اللَّهَ جَلَّ وَعَزَّ كَانَ خَصَّ رَسُولَهُ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِخَاصَّةٍ لَمْ يُخَصِّصْ بِهَا أَحَدًا غَيْرَهُ قَالَ{ مَا أَفَاءَ اللَّهُ عَلَى رَسُولِهِ مِنْ أَهْلِ الْقُرَى فَلِلَّهِ وَلِلرَّسُولِ }مَا أَدْرِي هَلْ قَرَأَ الْآيَةَ الَّتِي قَبْلَهَا أَمْ لَا قَالَ فَقَسَمَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بَيْنَكُمْ أَمْوَالَ بَنِي النَّضِيرِ فَوَاللَّهِ مَا اسْتَأْثَرَ عَلَيْكُمْ وَلَا أَخَذَهَا دُونَكُمْ حَتَّى بَقِيَ هَذَا الْمَالُ فَكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَأْخُذُ مِنْهُ نَفَقَةَ سَنَةٍ ثُمَّ يَجْعَلُ مَا بَقِيَ أُسْوَةَ الْمَالِ ثُمَّ قَالَ أَنْشُدُكُمْ بِاللَّهِ الَّذِي بِإِذْنِهِ تَقُومُ السَّمَاءُ وَالْأَرْضُ أَتَعْلَمُونَ ذَلِكَ قَالُوا نَعَمْ ثُمَّ نَشَدَ عَبَّاسًا وَعَلِيًّا بِمِثْلِ مَا نَشَدَ بِهِ الْقَوْمَ أَتَعْلَمَانِ ذَلِكَ قَالَا نَعَمْ قَالَ فَلَمَّا تُوُفِّيَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ أَبُو بَكْرٍ أَنَا وَلِيُّ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَجِئْتُمَا تَطْلُبُ مِيرَاثَكَ مِنْ ابْنِ أَخِيكَ وَيَطْلُبُ هَذَا مِيرَاثَ امْرَأَتِهِ مِنْ أَبِيهَا فَقَالَ أَبُو بَكْرٍ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَا نُورَثُ مَا تَرَكْنَاهُ صَدَقَةٌ فَرَأَيْتُمَاهُ كَاذِبًا آثِمًا غَادِرًا خَائِنًا وَاللَّهُ يَعْلَمُ إِنَّهُ لَصَادِقٌ بَارٌّ رَاشِدٌ تَابِعٌ لِلْحَقِّ ثُمَّ تُوُفِّيَ أَبُو بَكْرٍ وَأَنَا وَلِيُّ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَوَلِيُّ أَبِي بَكْرٍ فَرَأَيْتُمَانِي كَاذِبًا آثِمًا غَادِرًا خَائِنًا وَاللَّهُ يَعْلَمُ إِنِّي لَصَادِقٌ بَارٌّ رَاشِدٌ تَابِعٌ لِلْحَقِّ فَوَلِيتُهَا ثُمَّ جِئْتَنِي أَنْتَ وَهَذَا وَأَنْتُمَا جَمِيعٌ وَأَمْرُكُمَا وَاحِدٌ فَقُلْتُمَا ادْفَعْهَا إِلَيْنَا فَقُلْتُ إِنْ شِئْتُمْ دَفَعْتُهَا إِلَيْكُمَا عَلَى أَنَّ عَلَيْكُمَا عَهْدَ اللَّهِ أَنْ تَعْمَلَا فِيهَا بِالَّذِي كَانَ يَعْمَلُ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَخَذْتُمَاهَا بِذَلِكَ قَالَ أَكَذَلِكَ قَالَا نَعَمْ قَالَ ثُمَّ جِئْتُمَانِي لِأَقْضِيَ بَيْنَكُمَا وَلَا وَاللَّهِ لَا أَقْضِي بَيْنَكُمَا بِغَيْرِ ذَلِكَ حَتَّى تَقُومَ السَّاعَةُ فَإِنْ عَجَزْتُمَا عَنْهَا فَرُدَّاهَا إِلَيَّحَدَّثَنَا إِسْحَقُ بْنُ إِبْرَاهِيمَ وَمُحَمَّدُ بْنُ رَافِعٍ وَعَبْدُ بْنُ حُمَيْدٍ قَالَ ابْنُ رَافِعٍ حَدَّثَنَا و قَالَ الْآخَرَانِ أَخْبَرَنَا عَبْدُ الرَّزَّاقِ أَخْبَرَنَا مَعْمَرٌ عَنْ الزُّهْرِيِّ عَنْ مَالِكِ بْنِ أَوْسِ بْنِ الْحَدَثَانِ قَالَ أَرْسَلَ إِلَيَّ عُمَرُ بْنُ الْخَطَّابِ فَقَالَ إِنَّهُ قَدْ حَضَرَ أَهْلُ أَبْيَاتٍ مِنْ قَوْمِكَ بِنَحْوِ حَدِيثِ مَالِكٍ غَيْرَ أَنَّ فِيهِ فَكَانَ يُنْفِقُ عَلَى أَهْلِهِ مِنْهُ سَنَةً وَرُبَّمَا قَالَ مَعْمَرٌ يَحْبِسُ قُوتَ أَهْلِهِ مِنْهُ سَنَةً ثُمَّ يَجْعَلُ مَا بَقِيَ مِنْهُ مَجْعَلَ مَالِ اللَّهِ عَزَّ وَجَلَّ","id":"Dan telah menceritakan kepadaku [Abdullah bin Muhammad bin Asma Adl dluba'i] telah menceritakan kepada kami [Juwairiyah] dari [Malik] dari [Az Zuhri] bahwa [Malik bin Aus] telah menceritakan kepadanya, katanya, \" [Umar bin Khattab] mengundangku, lalu aku datang kepadanya ketika hari mulai panas.\" Malik bin Aus berkata, \"Aku menemukan dia di rumahnya sedang duduk di atas ranjang yang langsung menyentuh tanah, dan bertelekan di atas bantas yang terbuat dari kulit.\" Dia berkata kepadaku, \"Wahai Malik, sesungguhnya kaummu bersama keluarganya telah datang dengan perjalanan yang sangat cepat. Dan aku telah memerintahkan untuk membagikan sesuatu kepada mereka, oleh karena itu bagikanlah (harta rampasan) kepada mereka.\" Malik bin Aus berkata, \"Aku berkata, \"Lebih baik anda memerintahkan orang lain selainku.\" Umar berkata, \"Ambillah wahai Malik.\" Malik bin Aus berkata, \"Lalu datanglah Yarfa seraya berkata, \"Wahai Amirul Mukminin, apakah [Utsman bin 'Affan], [Abdurrahman bin 'Auf], [Zubair bin 'Awwam] dan [Sa'd] boleh masuk?\" Umar menjawab, \"Ya, persilahkanlah mereka masuk.\" Kemudian mereka masuk, setelah itu Yarfa datang lagi saraya berkata, \"Apakah [Ali] dan [Abbas] boleh masuk?\" Umar menjawab, \"Ya, boleh.\" Keduanya pun diizinkan masuk. Lalu Abbas berkata, \"Wahai Amirul Mukminin, berilah keputusan hukum antara aku dengan pendusta, pengkhianat dan pendosa ini.\" Maka sebagian kaum berkata, \"Benar wahai Amirul Mukminin, berilah keputusan terhadapnya dan selesaikanlah urusannya.\" Malik bin Aus berkata, \"Aku berperasangka bahwa Abbas dan Ali yang menggiring rombongan terebut datang.\" Umar berkata, \"Tenanglah kalian berdua, aku memohon kebaikan untuk kalian kepada Allah yang atas izin-Nya berdiri langit dan bumi, apakah kalian tahu bahwa Rasulullah shallallahu 'alaihi wasallam pernah bersabda: \"Kami tidak mewarisi sesuatu pun, dan yang kami tinggalkan hanya berupa sedekah.\" Mereka menjawab, \"Benar.\" Kemudian Umar menghadap kepada Ali dan Abbas seraya berkata, \"Aku memohon kebaikan untuk kalian kepada Allah yang atas izin-Nya berdiri langit dan bumi, apakah kalian tahu bahwa Rasulullah shallallahu 'alaihi wasallam pernah bersabda: \"Kami tidak mewarisi sesuatu pun, dan yang kami tinggalkan hanya berupa sedekah.\" Abbas dan Ali berkata, \"Ya, benar.\" Umar lantas berkata, \"Sesungguhnya Allah Azza Wa Jalla memberikan kekhususan kepada Rasul-Nya shallallahu 'alaihi wasallam yang tidak diberikan kepada orang lain, Allah berfirman: '(Dan apa saja harta rampasan yang diberikan Allah kepada Rasul-Nya maka harta tersebut untuk Allah dan rasul-Nya …) ' (Qs. Al Hasyr: 7) -aku tidak tahu apakah Umar membaca ayat sebelumnya ataukah tidak-, Umar berkata, \"Kemudian Rasulullah shallallahu 'alaihi wasallam membagi harta Bani Nadlir kepada kalian. Demi Allah, beliau tidak membuat pemberian itu untuk dirinya sendiri tanpa kalian, sehingga harta itu masih tersisa. Rasulullah shallallahu 'alaihi wasallam mengambil harta tersebut untuk menafkahi keluarganya selama setahun, dan selebihnya beliau menjadikan sebagai harta untuk kemaslahatan umum.\" Kemudian Umar berkata, \"Aku bertanya kepada kalian semua dengan izin Allah yang atas izin-Nya langit dan bumi berdiri, apakah kalian telah mengetahui hal itu?\" mereka menjawab, \"Ya, benar.\" Kemudian dia menghadap ke arah Abbas dan Ali sebagaimana perkataannya kepada rombongan kaum tersebut, \"Apakah kalian berdua mengetahui hal itu?\" keduanya menjawab, \"Ya, benar.\" Umar melanjutkan, \"Ketika Rasulullah shallallahu 'alaihi wasallam wafat, [Abu Bakar] berkata, \"Aku adalah pengganti Rasulullah shallallahu 'alaihi wasallam, kemudian masing-masing dari kalian berdua meminta harta peninggalannya dari anak pamanmu sedangkan yang ini (Ali) menuntut warisan isterinya dari ayahnya, maka Abu Bakar berkata, \"Bukankah Rasulullah shallallahu 'alaihi wasallam telah bersabda: \"Kami tidak mewarisi sesuatu apapun, namun yang kami tinggalkan hanyalah berupa sedekah.\" Apakah kalian berdua melihatnya ia seorang pendusta, pendosa dan seorang pengkhianat! Demi Allah, Dia tahu bahwa Abu Bakar adalah orang yang jujur, baik, berakal dan patuh terhadap kebenaran, setelah Abu Bakar wafat, maka akulah pengganti Rasulullah shallallahu 'alaihi wasallam dan pengganti Abu Bakar, maka apakah kalian berdua melihatku seorang pendusta, pendosa dan seorang pengkhianat! Demi Allah, Dia lebih tahu bahwa aku adalah orang yang jujur, baik dan berakal serta mengikuti kebenaran, namun kalian berdua berpaling dariku. Kemudian datang kepadaku, kamu berdua dan ini dan semuanya datang sedangkan perkara kalian hanya satu. Kalian berdua bertanya kepadaku, lalu aku menjawab, \"Jika kalian ingin bagian tersebut aku bagikan kepada kalian, maka kalian harus menggunakannya sesuai dengan yang telah dilakukan Rasulullah shallallahu 'alaihi wasallam, dan kalian mengambil bagian itu sesuai dengan perjanjian yang ada. Tetapi, sekarang kalian datang kepadaku agar aku memberikan keputusan di antara kalian berdua dengan keputusan yang tidak sesuai dengan perjanjian itu. Demi Allah, aku tidak akan memberikan keputusan selain sesuai dengan perjanjian tersebut hingga hari Kiamat. Jika kalian tidak mampu memenuhi persyaratan itu, maka kembalikanlah bagian itu kepadaku.\" Telah menceritakan kepada kami [Ishaq bin Ibrahim] dan [Muhammad bin rafi'] dan [Abd bin Humaid], [Ibnu Rafi'] berkata; telah menceritakan kepada kami, sedangkan yang dua mengatakan; telah mengabarkan kepada kami [Abdurrazaq] telah mengabarkan kepada kami [Ma'mar] dari [Az Zuhri] dari [Malik bin Aus bin Al Haddatsan] dia berkata, \"Umar bin Khattab mengutus kepadaku seraya berkata, \"Sesungguhnya orang-orang dari beberapa keluarga dari kaummu …seperti hadits Malik, namun dalam haditsnya disebutkan, \"Dengannya beliau menafkahi keluarganya selama setahun.\" Dan sepertinya Ma'mar mengatakan, \"Beliau memberikan nafkah darinya kepada keluarganya selama setahun, kemudian beliau menjadikan sisa dari harta tersebut sebagai harta Allah Azza Wa Jalla.\""},"3070":{"ar":"حَدَّثَنَا يَحْيَى بْنُ يَحْيَى قَالَ قَرَأْتُ عَلَى مَالِكٍ عَنْ ابْنِ شِهَابٍ عَنْ عُرْوَةَ عَنْ عَائِشَةَ أَنَّهَا قَالَتْإِنَّ أَزْوَاجَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حِينَ تُوُفِّيَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَرَدْنَ أَنْ يَبْعَثْنَ عُثْمَانَ بْنَ عَفَّانَ إِلَى أَبِي بَكْرٍ فَيَسْأَلْنَهُ مِيرَاثَهُنَّ مِنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَتْ عَائِشَةُ لَهُنَّ أَلَيْسَ قَدْ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا نُورَثُ مَا تَرَكْنَا فَهُوَ صَدَقَةٌ","id":"Telah menceritakan kepada kami [Yahya bin Yahya] dia berkata; aku telah membacakan di hadapan [Malik]; dari [Ibnu Syihab] dari ['Urwah] dari ['Aisyah] bahwa dia berkata, \"Setelah wafatnya Rasulullah shallallahu 'alaihi wasallam, para isteri Nabi shallallahu 'alaihi wasallam pernah hendak mengutus Utsman bin Affan untuk menemui Abu Bakar dan meminta bagian dari harta peninggalan Nabi shallallahu 'alaihi wasallam, maka 'Aisyah berkata kepada mereka, \"Tidakkah Rasulullah shallallahu 'alaihi wasallam pernah bersabda: \"Kami tidak meninggalkan harta peninggalan kecuali hal itu hanya sebagai sedekah.\""},"3071":{"ar":"حَدَّثَنِي مُحَمَّدُ بْنُ رَافِعٍ أَخْبَرَنَا حُجَيْنٌ حَدَّثَنَا لَيْثٌ عَنْ عُقَيْلٍ عَنْ ابْنِ شِهَابٍ عَنْ عُرْوَةَ بْنِ الزُّبَيْرِ عَنْ عَائِشَةَ أَنَّهَا أَخْبَرَتْهُ أَنَّ فَاطِمَةَ بِنْتَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَرْسَلَتْ إِلَى أَبِي بَكْرٍ الصِّدِّيقِ تَسْأَلُهُ مِيرَاثَهَا مِنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِمَّا أَفَاءَ اللَّهُ عَلَيْهِ بِالْمَدِينَةِ وَفَدَكٍ وَمَا بَقِيَ مِنْ خُمْسِ خَيْبَرَفَقَالَ أَبُو بَكْرٍ إِنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَا نُورَثُ مَا تَرَكْنَا صَدَقَةٌ إِنَّمَا يَأْكُلُ آلُ مُحَمَّدٍ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي هَذَا الْمَالِ وَإِنِّي وَاللَّهِ لَا أُغَيِّرُ شَيْئًا مِنْ صَدَقَةِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ حَالِهَا الَّتِي كَانَتْ عَلَيْهَا فِي عَهْدِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَلَأَعْمَلَنَّ فِيهَا بِمَا عَمِلَ بِهِ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَبَى أَبُو بَكْرٍ أَنْ يَدْفَعَ إِلَى فَاطِمَةَ شَيْئًا فَوَجَدَتْ فَاطِمَةُ عَلَى أَبِي بَكْرٍ فِي ذَلِكَ قَالَ فَهَجَرَتْهُ فَلَمْ تُكَلِّمْهُ حَتَّى تُوُفِّيَتْ وَعَاشَتْ بَعْدَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ سِتَّةَ أَشْهُرٍ فَلَمَّا تُوُفِّيَتْ دَفَنَهَا زَوْجُهَا عَلِيُّ بْنُ أَبِي طَالِبٍ لَيْلًا وَلَمْ يُؤْذِنْ بِهَا أَبَا بَكْرٍ وَصَلَّى عَلَيْهَا عَلِيٌّ وَكَانَ لِعَلِيٍّ مِنْ النَّاسِ وِجْهَةٌ حَيَاةَ فَاطِمَةَ فَلَمَّا تُوُفِّيَتْ اسْتَنْكَرَ عَلِيٌّ وُجُوهَ النَّاسِ فَالْتَمَسَ مُصَالَحَةَ أَبِي بَكْرٍ وَمُبَايَعَتَهُ وَلَمْ يَكُنْ بَايَعَ تِلْكَ الْأَشْهُرَ فَأَرْسَلَ إِلَى أَبِي بَكْرٍ أَنْ ائْتِنَا وَلَا يَأْتِنَا مَعَكَ أَحَدٌ كَرَاهِيَةَ مَحْضَرِ عُمَرَ بْنِ الْخَطَّابِ فَقَالَ عُمَرُ لِأَبِي بَكْرٍ وَاللَّهِ لَا تَدْخُلْ عَلَيْهِمْ وَحْدَكَ فَقَالَ أَبُو بَكْرٍ وَمَا عَسَاهُمْ أَنْ يَفْعَلُوا بِي إِنِّي وَاللَّهِ لَآتِيَنَّهُمْ فَدَخَلَ عَلَيْهِمْ أَبُو بَكْرٍ فَتَشَهَّدَ عَلِيُّ بْنُ أَبِي طَالِبٍ ثُمَّ قَالَ إِنَّا قَدْ عَرَفْنَا يَا أَبَا بَكْرٍ فَضِيلَتَكَ وَمَا أَعْطَاكَ اللَّهُ وَلَمْ نَنْفَسْ عَلَيْكَ خَيْرًا سَاقَهُ اللَّهُ إِلَيْكَ وَلَكِنَّكَ اسْتَبْدَدْتَ عَلَيْنَا بِالْأَمْرِ وَكُنَّا نَحْنُ نَرَى لَنَا حَقًّا لِقَرَابَتِنَا مِنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَلَمْ يَزَلْ يُكَلِّمُ أَبَا بَكْرٍ حَتَّى فَاضَتْ عَيْنَا أَبِي بَكْرٍ فَلَمَّا تَكَلَّمَ أَبُو بَكْرٍ قَالَ وَالَّذِي نَفْسِي بِيَدِهِ لَقَرَابَةُ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَحَبُّ إِلَيَّ أَنْ أَصِلَ مِنْ قَرَابَتِي وَأَمَّا الَّذِي شَجَرَ بَيْنِي وَبَيْنَكُمْ مِنْ هَذِهِ الْأَمْوَالِ فَإِنِّي لَمْ آلُ فِيهَا عَنْ الْحَقِّ وَلَمْ أَتْرُكْ أَمْرًا رَأَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَصْنَعُهُ فِيهَا إِلَّا صَنَعْتُهُ فَقَالَ عَلِيٌّ لِأَبِي بَكْرٍ مَوْعِدُكَ الْعَشِيَّةُ لِلْبَيْعَةِ فَلَمَّا صَلَّى أَبُو بَكْرٍ صَلَاةَ الظُّهْرِ رَقِيَ عَلَى الْمِنْبَرِ فَتَشَهَّدَ وَذَكَرَ شَأْنَ عَلِيٍّ وَتَخَلُّفَهُ عَنْ الْبَيْعَةِ وَعُذْرَهُ بِالَّذِي اعْتَذَرَ إِلَيْهِ ثُمَّ اسْتَغْفَرَ وَتَشَهَّدَ عَلِيُّ بْنُ أَبِي طَالِبٍ فَعَظَّمَ حَقَّ أَبِي بَكْرٍ وَأَنَّهُ لَمْ يَحْمِلْهُ عَلَى الَّذِي صَنَعَ نَفَاسَةً عَلَى أَبِي بَكْرٍ وَلَا إِنْكَارًا لِلَّذِي فَضَّلَهُ اللَّهُ بِهِ وَلَكِنَّا كُنَّا نَرَى لَنَا فِي الْأَمْرِ نَصِيبًا فَاسْتُبِدَّ عَلَيْنَا بِهِ فَوَجَدْنَا فِي أَنْفُسِنَا فَسُرَّ بِذَلِكَ الْمُسْلِمُونَ وَقَالُوا أَصَبْتَ فَكَانَ الْمُسْلِمُونَ إِلَى عَلِيٍّ قَرِيبًا حِينَ رَاجَعَ الْأَمْرَ الْمَعْرُوفَحَدَّثَنَا إِسْحَقُ بْنُ إِبْرَاهِيمَ وَمُحَمَّدُ بْنُ رَافِعٍ وَعَبْدُ بْنُ حُمَيْدٍ قَالَ ابْنُ رَافِعٍ حَدَّثَنَا و قَالَ الْآخَرَانِ أَخْبَرَنَا عَبْدُ الرَّزَّاقِ أَخْبَرَنَا مَعْمَرٌ عَنْ الزُّهْرِيِّ عَنْ عُرْوَةَ عَنْ عَائِشَةَ أَنَّ فَاطِمَةَ وَالْعَبَّاسَ أَتَيَا أَبَا بَكْرٍ يَلْتَمِسَانِ مِيرَاثَهُمَا مِنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَهُمَا حِينَئِذٍ يَطْلُبَانِ أَرْضَهُ مِنْ فَدَكٍ وَسَهْمَهُ مِنْ خَيْبَرَ فَقَالَ لَهُمَا أَبُو بَكْرٍ إِنِّي سَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَسَاقَ الْحَدِيثَ بِمِثْلِ مَعْنَى حَدِيثِ عُقَيْلٍ عَنْ الزُّهْرِيِّ غَيْرَ أَنَّهُ قَالَ ثُمَّ قَامَ عَلِيٌّ فَعَظَّمَ مِنْ حَقِّ أَبِي بَكْرٍ وَذَكَرَ فَضِيلَتَهُ وَسَابِقَتَهُ ثُمَّ مَضَى إِلَى أَبِي بَكْرٍ فَبَايَعَهُ فَأَقْبَلَ النَّاسُ إِلَى عَلِيٍّ فَقَالُوا أَصَبْتَ وَأَحْسَنْتَ فَكَانَ النَّاسُ قَرِيبًا إِلَى عَلِيٍّ حِينَ قَارَبَ الْأَمْرَ الْمَعْرُوفَ","id":"Telah menceritakan kepadaku [Muhammad bin Rafi'] telah mengabarkan kepada kami [Hujain] telah menceritakan kepada kami [Laits] dari ['Uqil] dari [Ibnu Syihab] dari ['Urwah bin Zubair] dari ['Aisyah], bahwa dia telah mengabarkan kepadanya bahwa Fatimah binti Rasulullah shallallahu 'alaihi wasallam mengutus seseorang untuk menemui [Abu Bakar], dia meminta supaya diberi bagian dari harta peninggalan Rasulullah shallallahu 'alaihi wasallam di Kota Madinah dan Fadak dan seperlima hasil rampasan perang Khaibar yang masih tersisa. Maka Abu Bakar menjawab, \"Rasulullah shallallahu 'alaihi wasallam pernah bersabda: \"Sesungguhnya harta peninggalan kami tidak dapat diwarisi, yang kami tinggalkan hanya berupa sedekah, dan keluarga Muhammad shallallahu 'alaihi wasallam hanya boleh menikmati sedekah itu.\" Demi Allah, aku tidak berani merubah sedikitpun sedekah yang telah Rasulullah shallallahu 'alaihi wasallam tetapkan, aku akan tetap membiarkan seperti pada masa Rasulullah shallallahu 'alaihi wasallam, dan aku akan tetap melaksanakan apa yang telah dilakukan Rasulullah shallallahu 'alaihi wasallam.\" Ternyata Abu Bakar tetap menolak permintaan Fatimah, oleh karena itu Fatimah sangat gusar dan marah atas tindakan Abu Bakar mengenai hal itu.\" Urwah melanjutkan, \"Sampai-sampai Fatimah enggan menyapanya -tidak mengajaknya berbicara- hingga ajal menjemputnya, tepatnya enam bulan setelah wafatnya Rasulullah shallallahu 'alaihi wasallam. Ketika Fatimah meninggal dunia, jenazahnya dimakamkan oleh suaminya sendiri, Ali bin Abu Thalib, pada malam hari tanpa memberitahukan terlebih dahulu kepada Abu Bakar. Setelah itu Ali pulalah yang menshalatkan jenazah Fatimah. Ketika Fatimah masih hidup, banyak orang menaruh hormat kepada Ali, tetapi hal itu mulai berubah ketika Fatimah telah meninggal dunia. Lalu dia mulai berfikir untuk segera berdamai dengan Abu Bakar sekaligus membai'atnya, karena beberapa bulan dia tidak sempat menemuinya untuk membai'atnya. Setelah itu, Ali menulis surat kepada Abu Bakar yang isinya, \"Aku mengrapkan kamu datang menemuiku, namun jangan sampai ada seorang pun yang ikut menemuimu.\" -sepertinya Ali tidak suka jika Abu Bakar ditemani Umar bin Khattab- Umar lalu berkata kepada Abu Bakar, \"Demi Allah, janganlah kamu menemuinya seorang diri.\" Abu Bakar menjawab, \"Aku yakin, Ali tidak akan berbuat macam-macam kepadaku, demi Allah, aku akan tetap menemuinya.\" Dengan penuh keyainan, akhirnya Abu Bakar pergi menemui Ali, ketika bertemu, Ali bin Abu Thalib langsung bersaksi kepadanya (maksudnya membai'atnya) seraya berkata, \"Wahai Abu Bakar, sesungguhnya aku telah mengetahui segala keutamaan dan kebaikan yang Allah anugerahkan kepadamu, dan aku tidak merasa iri dan dengki pada anugerah yang Allah limpahkan kepadamu. Akan tetapi menurutku, kamu telah berbuat sewenang-wenang terhadapku, sebagai keluarga terdekat Rasulullah shallallahu 'alaihi wasallam, semestinya aku mempunyai hak untuk memperoleh harta peninggalan beliau.\" Ucapan-ucapan Ali begitu derasnya kepada Abu Bakar hingga tak terasa Abu Bakar meneteskan air matanya. Dengan perasaan haru, Abu Bakar menjelaskan kepadanya, katanya, \"Demi Dzat yang jiwaku berada di tangan-Nya, sebenarnya keluarga dan kerabat Rasulullah shallallahu 'alaihi wasallam jauh lebih aku cintai daripada keluarga aku sendiri. Mengenai harta peninggalan yang tengah kita perselisihkan ini, sebenarnya aku selalu berusaha bersikap adil dan bijaksana serta berpijak kepada kebenaran. Dan aku tidak akan meninggalkan apa yang pernah dilakukan oleh Rasulullah shallallahu 'alaihi wasallam, bahkan aku akan tetap mempertahankannya.\" Maka Ali berkata kepada Abu Bakar, \"Walau bagaimanapun aku akan tetap membai'atmu nanti sore.\" Seusai melaksanakan shalat dhuhur, Abu Bakar langsung naik ke atas mimbar, setelah membaca syahadat, ia pun mencoba menjelaskan kepada kaum Muslimin yang hadir pada saat itu, masalah keterlambatan Ali untuk berbai'at beserta alasannya, kemudian dia membaca istighfar. Setelah itu, tibalah giliran Ali bersaksi dan menghormati sikap Abu Bakar, Ali menyatakan bahwa dia tidak merasa iri dan dengki sama sekali terhadap keutamaan dan kelebihan yang dianugerahkan Allah kepada Abu Bakar, akan tetapi -lanjut Ali-, \"Kami keluarga terdekat Rasulullah shallallahu 'alaihi wasallam melihat bahwa beliau berlaku tidak adil terhadap keluarga kami, terutama dalam hal harta rampasan perang peninggalan Rasulullah shallallahu 'alaihi wasallam, jadi sudah menjadi hak kami untuk menuntut hak tersebut.\" Mayoritas kamu Muslimin yang hadir saat itu merasa gembira mendengar pernyataan Ali, mereka berkata, \"Benar yang kamu ucapkan.\" Akhirnya Ali menjadi lebih dekat dengan kaum Muslimin setelah dia berani mengungkapkan perkara itu.\" Telah menceritakan kepada kami [Ishaq bin Ibrahim] dan [Muhammad bin Rafi'] serta [Abd bin Humaid], Ibnu Rafi' mengatakan; telah menceritakan kepada kami, sedangkan yang dua mengatakan; telah mengabarkan kepada kami [Abdurrazaq] telah mengabarkan kepada kami [Ma'mar] dari [Az Zuhri] dari ['Urwah] dari ['Aisyah] bahwa Fatimah dan Abbas pernah mendatangi [Abu Bakar] untuk meminta bagian dari harta peninggalan Rasulullah shallallahu 'alaihi wasallam, saat itu keduanya meminta kembali tanah Fadak dan bagian harta warisan dari peninggalan Khaibar. Maka Abu Bakar berkata kepada keduanya, \"Sesungguhnya aku pernah mendengar Rasulullah shallallahu 'alaihi wasallam …kemudian dia melanjutkan hadits tersebut sebagaimana makna hadits 'Uqail dari Az Zuhri, namun dia menyebutkan, \"Kemudian Ali berdiri dan menghormati hak-hak Abu Bakar, dia juga menyebutkan keutamaan dan kelebihannya, setelah itu dia menemui Abu Bakar dan membai'atnya, saat itu orang-orang menerima Ali dengan perasaan gembira, mereka berkata, \"Kamu banar dan telah melakukan suatu kebaikan.\" Saat itu orang-orang menjadi lebih dekat dengan Ali setelah dia berani mengungkapkan perkara itu.\""},"3072":{"ar":"و حَدَّثَنَا ابْنُ نُمَيْرٍ حَدَّثَنَا يَعْقُوبُ بْنُ إِبْرَاهِيمَ حَدَّثَنَا أَبِي ح و حَدَّثَنَا زُهَيْرُ بْنُ حَرْبٍ وَالْحَسَنُ بْنُ عَلِيٍّ الْحُلْوَانِيُّ قَالَا حَدَّثَنَا يَعْقُوبُ وَهُوَ ابْنُ إِبْرَاهِيمَ حَدَّثَنَا أَبِي عَنْ صَالِحٍ عَنْ ابْنِ شِهَابٍ أَخْبَرَنِي عُرْوَةُ بْنُ الزُّبَيْرِ أَنَّ عَائِشَةَ زَوْجَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَخْبَرَتْهُ أَنَّ فَاطِمَةَ بِنْتَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ سَأَلَتْ أَبَا بَكْرٍ بَعْدَ وَفَاةِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنْ يَقْسِمَ لَهَا مِيرَاثَهَا مِمَّا تَرَكَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِمَّا أَفَاءَ اللَّهُ عَلَيْهِفَقَالَ لَهَا أَبُو بَكْرٍ إِنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَا نُورَثُ مَا تَرَكْنَا صَدَقَةٌ قَالَ وَعَاشَتْ بَعْدَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ سِتَّةَ أَشْهُرٍ وَكَانَتْ فَاطِمَةُ تَسْأَلُ أَبَا بَكْرٍ نَصِيبَهَا مِمَّا تَرَكَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِنْ خَيْبَرَ وَفَدَكٍ وَصَدَقَتِهِ بِالْمَدِينَةِ فَأَبَى أَبُو بَكْرٍ عَلَيْهَا ذَلِكَ وَقَالَ لَسْتُ تَارِكًا شَيْئًا كَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَعْمَلُ بِهِ إِلَّا عَمِلْتُ بِهِ إِنِّي أَخْشَى إِنْ تَرَكْتُ شَيْئًا مِنْ أَمْرِهِ أَنْ أَزِيغَ فَأَمَّا صَدَقَتُهُ بِالْمَدِينَةِ فَدَفَعَهَا عُمَرُ إِلَى عَلِيٍّ وَعَبَّاسٍ فَغَلَبَهُ عَلَيْهَا عَلِيٌّ وَأَمَّا خَيْبَرُ وَفَدَكُ فَأَمْسَكَهُمَا عُمَرُ وَقَالَ هُمَا صَدَقَةُ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَتَا لِحُقُوقِهِ الَّتِي تَعْرُوهُ وَنَوَائِبِهِ وَأَمْرُهُمَا إِلَى مَنْ وَلِيَ الْأَمْرَ قَالَ فَهُمَا عَلَى ذَلِكَ إِلَى الْيَوْمِ","id":"Dan telah menceritakan kepada kami [Ibnu Numair] telah menceritakan kepada kami [Ya'qub bin Ibrahim] telah menceritakan kepada kami [ayahku]. (dalam jalur lain disebutkan) Telah menceritakan kepada kami [Zuhair bin Harb] dan [Al Hasan bin Ali Al Khulwani] keduanya berkata; telah menceritakan kepada kami [Ya'qub] -yaitu Ibnu Ibrahim- telah menceritakan kepada kami [ayahku] dari [Shalih] dari [Ibnu Syihab] telah mengabarkan kepadaku ['Urwah bin Zubair] bahwa ['Aisyah] isteri Nabi shallallahu 'alaihi wasallam telah mengabarkan kepadanya bahwa Fatimah binti Rasulullah shallallahu 'alaihi wasallam pernah meminta bagian dari harta peninggalan ayahnya kepada [Abu Bakar], setelah wafat Rasulullah shallallahu 'alaihi wasallam. Abu Bakar lalu menjawab, \"Sesungguhnya Rasulullah shallallahu 'alaihi wasallam telah bersabda: \"Harta warisan yang aku tinggalkan tidak dapat diwariskan, tetapi hanya merupakan sedekah.\" 'Urwah berkata, \"Fatimah hidup selama enam bulan setelah wafatnya Rasulullah shallallahu 'alaihi wasallam, dia selalu meminta bagian harta peninggalan Rasulullah shallallahu 'alaihi wasallam kepada Abu Bakar dari rampasan perang yang masih tersisa di daerah Khaibar, yaitu fadak dan di kota Madinah. Namun Abu Bakar tetap menolaknya seraya berkata, \"Aku tidak berani merubah sedikitpun apa yang telah ditetapkan Rasulullah shallallahu 'alaihi wasallam, dan aku tetap akan melakukan seperti apa yang telah beliau lakukan. Sungguh, aku khawatir jika aku menyalahi perintahnya, aku akan condong kepada kesesatan.\" Adapun sedekahnya di Madinah, maka Umar tetap mempertahankannya dari Ali dan Abbas, begitu juga tanah Fadak, dia berkata, \"Keduanya adalah sedekah Rasulullah shallallahu 'alaihi wasallam yang harus ditunaikan hak-haknya, yaitu sedekah yang diberikan kepada orang-orang yang membutuhkan. Sedangkan keduanya berjalan seperti itu sampai hari ini.\""},"3073":{"ar":"حَدَّثَنَا يَحْيَى بْنُ يَحْيَى قَالَ قَرَأْتُ عَلَى مَالِكٍ عَنْ أَبِي الزِّنَادِ عَنْ الْأَعْرَجِ عَنْ أَبِي هُرَيْرَةَأَنَّ رَسُولَ اللَّهِ ��َلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَا يَقْتَسِمُ وَرَثَتِي دِينَارًا مَا تَرَكْتُ بَعْدَ نَفَقَةِ نِسَائِي وَمَئُونَةِ عَامِلِي فَهُوَ صَدَقَةٌحَدَّثَنَا مُحَمَّدُ بْنُ يَحْيَى بْنِ أَبِي عُمَرَ الْمَكِّيُّ حَدَّثَنَا سُفْيَانُ عَنْ أَبِي الزِّنَادِ بِهَذَا الْإِسْنَادِ نَحْوَهُ","id":"Telah menceritakan kepada kami [Yahya bin Yahya] dia berkata; aku membacakan di hadapan [Malik]; dari [Abu Az Zinad] dari [Al A'raj] dari [Abu Hurairah], bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Harta warisanku tidak dapat dibagikan satu dinar pun. Harta yang aku tinggalkan selain untuk nafkah isteri-isteriku dan memberi upah kepada para pekerja adalah sedekah.\" Telah menceritakan kepada kami [Muhammad bin Yahya bin Abu Umar Al Makki] telah menceritakan kepada kami [Sufyan] dari [Abu Az Zinad] dengan isnad seperti ini.\""},"3074":{"ar":"و حَدَّثَنِي ابْنُ أَبِي خَلَفٍ حَدَّثَنَا زَكَرِيَّاءُ بْنُ عَدِيٍّ أَخْبَرَنَا ابْنُ الْمُبَارَكِ عَنْ يُونُسَ عَنْ الزُّهْرِيِّ عَنْ الْأَعْرَجِ عَنْ أَبِي هُرَيْرَةَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَا نُورَثُ مَا تَرَكْنَا صَدَقَةٌ","id":"Dan telah menceritakan kepadaku [Ibnu Abu Khalaf] telah menceritakan kepada kami [Zakaria bin 'Adi] telah mengabarkan kepada kami [Ibnu Mubarak] dari [Yunus] dari [Az Zuhri] dari [Al A'raj] dari [Abu Hurairah] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Kami tidak diwarisi, apa yang kami tinggalkanadalah sedekah.\""},"3075":{"ar":"حَدَّثَنَا يَحْيَى بْنُ يَحْيَى وَأَبُو كَامِلٍ فُضَيْلُ بْنُ حُسَيْنٍ كِلَاهُمَا عَنْ سُلَيْمٍ قَالَ يَحْيَى أَخْبَرَنَا سُلَيْمُ بْنُ أَخْضَرَ عَنْ عُبَيْدِ اللَّهِ بْنِ عُمَرَ حَدَّثَنَا نَافِعٌ عَنْ عَبْدِ اللَّهِ بْنِ عُمَرَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَسَمَ فِي النَّفَلِ لِلْفَرَسِ سَهْمَيْنِ وَلِلرَّجُلِ سَهْمًاو حَدَّثَنَاه ابْنُ نُمَيْرٍ حَدَّثَنَا أَبِي حَدَّثَنَا عُبَيْدُ اللَّهِ بِهَذَا الْإِسْنَادِ مِثْلَهُ وَلَمْ يَذْكُرْ فِي النَّفَلِ","id":"Telah menceritakan kepada kami [Yahya bin Yahya] dan [Abu Kamil Fudlail bin Husain] keduanya dari [Sulaim], [Yahya] berkata; telah mengabarkan kepada kami [Sulaim bin Akhdlar] dari ['Ubaidullah bin umar] telah menceritakan kepada kami [Nafi'] dari [Abdullah bin Umar], bahwa Rasulullah shallallahu 'alaihi wasallam membagikan harta rampasan perang untuk tentara berkuda dua bagian, sedangkan untuk tentara pejalan kaki satu bagian.\" Dan telah menceritakan kepada kami [Ibnu Numair] telah menceritakan kepada kami [ayahku] telah menceritakan kepada kami ['Ubaidullah] dengan isnad seperti ini, namun dia tidak menyebutkan, \"Nafl (harta rampasan).\""},"3076":{"ar":"حَدَّثَنَا هَنَّادُ بْنُ السَّرِيِّ حَدَّثَنَا ابْنُ الْمُبَارَكِ عَنْ عِكْرِمَةَ بْنِ عَمَّارٍ حَدَّثَنِي سِمَاكٌ الْحَنَفِيُّ قَالَ سَمِعْتُ ابْنَ عَبَّاسٍ يَقُولُ حَدَّثَنِي عُمَرُ بْنُ الْخَطَّابِ قَالَ لَمَّا كَانَ يَوْمُ بَدْرٍ ح و حَدَّثَنَا زُهَيْرُ بْنُ حَرْبٍ وَاللَّفْظُ لَهُ حَدَّثَنَا عُمَرُ بْنُ يُونُسَ الْحَنَفِيُّ حَدَّثَنَا عِكْرِمَةُ بْنُ عَمَّارٍ حَدَّثَنِي أَبُو زُمَيْلٍ هُوَ سِمَاكٌ الْحَنَفِيُّ حَدَّثَنِي عَبْدُ اللَّهِ بْنُ عَبَّاسٍ قَالَ حَدَّثَنِي عُمَرُ بْنُ الْخَطَّابِ قَالَلَمَّا كَانَ يَوْمُ بَدْرٍ نَظَرَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِلَى الْمُشْرِكِينَ وَهُمْ أَلْفٌ وَأَصْحَابُهُ ثَلَاثُ مِائَةٍ وَتِسْعَةَ عَشَرَ رَجُلًا فَاسْتَقْبَلَ نَبِيُّ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْقِبْلَةَ ثُمَّ مَدَّ يَدَيْهِ فَجَعَلَ يَهْتِفُ بِرَبِّهِ اللَّهُمَّ أَنْجِزْ لِي مَا وَعَدْتَنِي اللَّهُمَّ آتِ مَا وَعَدْتَنِي اللَّهُمَّ إِنْ تُهْلِكْ هَذِهِ الْعِصَابَةَ مِنْ أَهْلِ الْإِسْلَامِ لَا تُعْبَدْ فِي الْأَرْضِ فَمَا زَالَ يَهْتِفُ بِرَبِّهِ مَادًّا يَدَيْهِ مُسْتَقْبِلَ الْقِبْلَةِ حَتَّى سَقَطَ رِدَاؤُهُ عَنْ مَنْكِبَيْهِ فَأَتَاهُ أَبُو بَكْرٍ فَأَخَذَ رِدَاءَهُ فَأَلْقَاهُ عَلَى مَنْكِبَيْهِ ثُمَّ الْتَزَمَهُ مِنْ وَرَائِهِ وَقَالَ يَا نَبِيَّ اللَّهِ كَفَاكَ مُنَاشَدَتُكَ رَبَّكَ فَإِنَّهُ سَيُنْجِزُ لَكَ مَا وَعَدَكَ فَأَنْزَلَ اللَّهُ عَزَّ وَجَلَّ{ إِذْ تَسْتَغِيثُونَ رَبَّكُمْ فَاسْتَجَابَ لَكُمْ أَنِّي مُمِدُّكُمْ بِأَلْفٍ مِنْ الْمَلَائِكَةِ مُرْدِفِينَ }فَأَمَدَّهُ اللَّهُ بِالْمَلَائِكَةِ قَالَ أَبُو زُمَيْلٍ فَحَدَّثَنِي ابْنُ عَبَّاسٍ قَالَ بَيْنَمَا رَجُلٌ مِنْ الْمُسْلِمِينَ يَوْمَئِذٍ يَشْتَدُّ فِي أَثَرِ رَجُلٍ مِنْ الْمُشْرِكِينَ أَمَامَهُ إِذْ سَمِعَ ضَرْبَةً بِالسَّوْطِ فَوْقَهُ وَصَوْتَ الْفَارِسِ يَقُولُ أَقْدِمْ حَيْزُومُ فَنَظَرَ إِلَى الْمُشْرِكِ أَمَامَهُ فَخَرَّ مُسْتَلْقِيًا فَنَظَرَ إِلَيْهِ فَإِذَا هُوَ قَدْ خُطِمَ أَنْفُهُ وَشُقَّ وَجْهُهُ كَضَرْبَةِ السَّوْطِ فَاخْضَرَّ ذَلِكَ أَجْمَعُ فَجَاءَ الْأَنْصَارِيُّ فَحَدَّثَ بِذَلِكَ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ صَدَقْتَ ذَلِكَ مِنْ مَدَدِ السَّمَاءِ الثَّالِثَةِ فَقَتَلُوا يَوْمَئِذٍ سَبْعِينَ وَأَسَرُوا سَبْعِينَ قَالَ أَبُو زُمَيْلٍ قَالَ ابْنُ عَبَّاسٍ فَلَمَّا أَسَرُوا الْأُسَارَى قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لِأَبِي بَكْرٍ وَعُمَرَ مَا تَرَوْنَ فِي هَؤُلَاءِ الْأُسَارَى فَقَالَ أَبُو بَكْرٍ يَا نَبِيَّ اللَّهِ هُمْ بَنُو الْعَمِّ وَالْعَشِيرَةِ أَرَى أَنْ تَأْخُذَ مِنْهُمْ فِدْيَةً فَتَكُونُ لَنَا قُوَّةً عَلَى الْكُفَّارِ فَعَسَى اللَّهُ أَنْ يَهْدِيَهُمْ لِلْإِسْلَامِ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَا تَرَى يَا ابْنَ الْخَطَّابِ قُلْتُ لَا وَاللَّهِ يَا رَسُولَ اللَّهِ مَا أَرَى الَّذِي رَأَى أَبُو بَكْرٍ وَلَكِنِّي أَرَى أَنْ تُمَكِّنَّا فَنَضْرِبَ أَعْنَاقَهُمْ فَتُمَكِّنَ عَلِيًّا مِنْ عَقِيلٍ فَيَضْرِبَ عُنُقَهُ وَتُمَكِّنِّي مِنْ فُلَانٍ نَسِيبًا لِعُمَرَ فَأَضْرِبَ عُنُقَهُ فَإِنَّ هَؤُلَاءِ أَئِمَّةُ الْكُفْرِ وَصَنَادِيدُهَا فَهَوِيَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَا قَالَ أَبُو بَكْرٍ وَلَمْ يَهْوَ مَا قُلْتُ فَلَمَّا كَانَ مِنْ الْغَدِ جِئْتُ فَإِذَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَأَبُو بَكْرٍ قَاعِدَيْنِ يَبْكِيَانِ قُلْتُ يَا رَسُولَ اللَّهِ أَخْبِرْنِي مِنْ أَيِّ شَيْءٍ تَبْكِي أَنْتَ وَصَاحِبُكَ فَإِنْ وَجَدْتُ بُكَاءً بَكَيْتُ وَإِنْ لَمْ أَجِدْ بُكَاءً تَبَاكَيْتُ لِبُكَائِكُمَا فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَبْكِي لِلَّذِي عَرَضَ عَلَيَّ أَصْحَابُكَ مِنْ أَخْذِهِمْ الْفِدَاءَ لَقَدْ عُرِضَ عَلَيَّ عَذَابُهُمْ أَدْنَى مِنْ هَذِهِ الشَّجَرَةِ شَجَرَةٍ قَرِيبَةٍ مِنْ نَبِيِّ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَأَنْزَلَ اللَّهُ عَزَّ وَجَلَّ{ مَا كَانَ لِنَبِيٍّ أَنْ يَكُونَ لَهُ أَسْرَى حَتَّى يُثْخِنَ فِي الْأَرْضِ إِلَى قَوْلِهِ فَكُلُوا مِمَّا غَنِمْتُمْ حَلَالًا طَيِّبًا }فَأَحَلَّ اللَّهُ الْغَنِيمَةَ لَهُمْ","id":"Telah menceritakan kepada kami [Hannad bin Sari] telah menceritakan kepada kami [Ibnu Al Mubarak] dari [Ikrimah bin Ammar] telah menceritakan kepadaku [Simak Al Hanafi] dia berkata; aku mendengar [Ibnu Abbas] berkata; telah menceritakan kepadaku [Umar bin Khattab] berkata, \"Ketika perang Badr.\" (dalam jalur lain disebutkan) Telah menceritakan kepada kami [Zuhair bin Harb] dan ini adalah lafadz dia, telah menceritakan kepada kami [Umar bin Yunus Al Hanafi] telah menceritakan kepada kami [Ikrimah bin 'Ammar] telah menceritakan kepadaku [Abu Zumail] -yaitu Simak Al Hanafi- telah menceritakan kepadaku [Abdullah bin Abbas] dia berkata; telah menceritakan kepadaku [Umar bin Khattab] dia berkata, \"Saat terjadi perang Badr, Rasulullah shallallahu 'alaihi wasallam melihat pasukan orang-orang Musyrik berjumlah seribu pasukan, sedangkan para sahabat beliau hanya berjumlah tiga ratus Sembilan belas orang. Kemudian Nabi Allah shallallahu 'alaihi wasallam menghadapkan wajahnya ke arah kiblat sambil menengadahkan tangannya, beliau berdo'a: \"ALLAHUMMA ANJIS LII MAA WA'ADTANI, ALLAHUMMA AATI MAA WA'ADTANI, ALLAHUMMA IN TUHLIK HAADZIHIL 'ISHAABAH MIN AHLIL ISLAM LA TU'BAD FIL ARDLI (Ya Allah, tepatilah janji-Mu kepadaku. Ya Allah, berilah apa yang telah Engkau janjikan kepadaku. Ya Allah, jika pasukan Islam yang berjumlah sedikit ini musnah, niscaya tidak ada lagi orang yang akan menyembah-Mua di muka bumi ini).' Demikianlah, beliau senantiasa berdo'a kepada Rabbnya dengan mengangkat tangannya sambil menghadap ke kiblat, sehingga selendang beliau terlepas dari bahunya. Abu Bakar lalu mendatangi beliau seraya mengambil selendang dan menaruhnya di bahu beliau, dan dia selalu menyeratai di belakang beliau.\" Abu Bakar kemudian berkata, \"Ya Nabi Allah, cukuplah kiranya anda bermunajat kepada Allah, karena Dia pasti akan menepati janji-Nya kepada anda.\" Lalu Allah menurunkan ayat: '((ingatlah), ketika kamu memohon pertolongan kepada Tuhanmu, lalu diperkenankan-Nya bagimu: \"Sesungguhnya Aku akan mendatangkan bala bantuan kepada kamu dengan seribu malaikat yang datang berturut-turut) ' (Qs. Al Anfaal: 9), Allah lalu membantunya dengan tentara Malaikat.\" Abu Zumail berkata, \"Ibnu Abbas menceritakan kepadaku, dia katakan, \"Pada hari itu, ketika seorang tentara Islam mengejar tentara Musyrikin yang berada di hadapannya, tiba-tiba terdengar olehnya bunyi suara cemeti di atas kepala seorang Musyrik itu, dan suara seorang penunggang kuda berkata, \"Majulah terus wahai Haizum!. Tanpa diduga, seorang Musyrik yang berada di hadapannya telah mati terkapar dengan hidungnya bengkak, dan mukanya terbelah seperti bekas pukulan cambuk serta seluruh tubuhnya menghijau. Lalu tentara Muslim itu datang melaporkan peristiwa yang baru saja dialaminya kepada Rasulullah shallallahu 'alaihi wasallam, maka beliau bersabda: \"Kamu benar, itu adalah pertolongan Allah dari langit ketiga.\" Pada hari itu, tentara kaum Muslimin dapat membunuh tujuh puluh tentara kaum Musyrikin, dan berhasil menawan tujuh puluh orang tawanan.\" Abu Zumail melanjutkan, \"Ibnu Abbas berkata, \"Tatkala tawanan telah mereka tahan, Rasulullah shallallahu 'alaihi wasallam bertanya kepada Abu Bakar dan Umar: \"Bagaimana pendapat kalian mengenai tawanan ini?\" Abu Bakar menjawab, \"Wahai Nabi Allah, mereka itu adalah anak-anak paman dan masih famili kita, aku berpendapat, sebaiknya kita pungut tebusan dari mereka. Dengan begitu, kita akan menjadi kuat terhadap orang-orang kafir, semoga Allah menunjuki mereka supaya masuk Islam.\" Kemudian Rasulullah shallallahu 'alaihi wasallam berkata: \"Bagaimana pendapatmu wahai Ibnul Khattab?\" Aku menjawab, \"Tidak, demi Allah wahai Rasulullah, aku tidak setuju dengan pendapat Abu Bakar. Menurutku, berilah aku kesempatan untuk memenggal leher mereka, berilah kesempatan kepada Ali supaya memenggal leher 'Uqail, dan berilah kesempatan kepadaku supaya memenggal leher si fulan -maksudnya saudaranya sendiri-, karena mereka adalah para pemimpin kaum kafir dan pembesar-pembesar mereka.\" Akan tetapi Rasulullah shallallahu 'alaihi wasallam menyetujui pendapat Abu Bakar dan tidak menyutujui pendapatku. Di keesokan harinya, aku menemui Rasulullah shallallahu 'alaihi wasallam, aku dapati beliau sedang duduk menangis berdua dengan Abu Bakar, lalu aku berkata, \"Ceritakanlah kepadaku, apa sebabnya anda berdua menangis? Jika bisa menangis maka aku akan menangis, jika tidak bisa maka aku akan pura-pura menangis untuk kalian.\" Rasulullah shallallahu 'alaihi wasallam bersabda: \"Aku menangis karena tebusan yang dipungut sahabatmu terhadap para tawanan itu, lebih murah daripada harga kayu ini.\" -yaitu kayu yang berada didekat Nabi Allah shallallahu 'alaihi wasallam- Lalu Allah Azza wa jalla menurunkan ayat: \"…Tidak pantas bagi seorang Nabi mempunyai seorang tawanan sebelum dia dapat melumpuhkan musuhnya di muka bumi ini…-hingga firman Nya- maka makanlah olehmu sebagian harta rampasan) ' (Qs. Al Nafaal: 67-69). Karena itulah Allah menghalalkan harta rampasan buat mereka.\""},"3077":{"ar":"حَدَّثَنَا قُتَيْبَةُ بْنُ سَعِيدٍ حَدَّثَنَا لَيْثٌ عَنْ سَعِيدِ بْنِ أَبِي سَعِيدٍ أَنَّهُ سَمِعَ أَبَا هُرَيْرَةَ يَقُولُابَعَثَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ خَيْلًا قِبَلَ نَجْدٍ فَجَاءَتْ بِرَجُلٍ مِنْ بَنِي حَنِيفَةَ يُقَالُ لَهُ ثُمَامَةُ بْنُ أُثَالٍ سَيِّدُ أَهْلِ الْيَمَامَةِ فَرَبَطُوهُ بِسَارِيَةٍ مِنْ سَوَارِي ��لْمَسْجِدِ فَخَرَجَ إِلَيْهِ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ مَاذَا عِنْدَكَ يَا ثُمَامَةُ فَقَالَ عِنْدِي يَا مُحَمَّدُ خَيْرٌ إِنْ تَقْتُلْ تَقْتُلْ ذَا دَمٍ وَإِنْ تُنْعِمْ تُنْعِمْ عَلَى شَاكِرٍ وَإِنْ كُنْتَ تُرِيدُ الْمَالَ فَسَلْ تُعْطَ مِنْهُ مَا شِئْتَ فَتَرَكَهُ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حَتَّى كَانَ بَعْدَ الْغَدِ فَقَالَ مَا عِنْدَكَ يَا ثُمَامَةُ قَالَ مَا قُلْتُ لَكَ إِنْ تُنْعِمْ تُنْعِمْ عَلَى شَاكِرٍ وَإِنْ تَقْتُلْ تَقْتُلْ ذَا دَمٍ وَإِنْ كُنْتَ تُرِيدُ الْمَالَ فَسَلْ تُعْطَ مِنْهُ مَا شِئْتَ فَتَرَكَهُ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حَتَّى كَانَ مِنْ الْغَدِ فَقَالَ مَاذَا عِنْدَكَ يَا ثُمَامَةُ فَقَالَ عِنْدِي مَا قُلْتُ لَكَ إِنْ تُنْعِمْ تُنْعِمْ عَلَى شَاكِرٍ وَإِنْ تَقْتُلْ تَقْتُلْ ذَا دَمٍ وَإِنْ كُنْتَ تُرِيدُ الْمَالَ فَسَلْ تُعْطَ مِنْهُ مَا شِئْتَ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَطْلِقُوا ثُمَامَةَ فَانْطَلَقَ إِلَى نَخْلٍ قَرِيبٍ مِنْ الْمَسْجِدِ فَاغْتَسَلَ ثُمَّ دَخَلَ الْمَسْجِدَ فَقَالَ أَشْهَدُ أَنْ لَا إِلَهَ إِلَّا اللَّهُ وَأَشْهَدُ أَنَّ مُحَمَّدًا عَبْدُهُ وَرَسُولُهُ يَا مُحَمَّدُ وَاللَّهِ مَا كَانَ عَلَى الْأَرْضِ وَجْهٌ أَبْغَضَ إِلَيَّ مِنْ وَجْهِكَ فَقَدْ أَصْبَحَ وَجْهُكَ أَحَبَّ الْوُجُوهِ كُلِّهَا إِلَيَّ وَاللَّهِ مَا كَانَ مِنْ دِينٍ أَبْغَضَ إِلَيَّ مِنْ دِينِكَ فَأَصْبَحَ دِينُكَ أَحَبَّ الدِّينِ كُلِّهِ إِلَيَّ وَاللَّهِ مَا كَانَ مِنْ بَلَدٍ أَبْغَضَ إِلَيَّ مِنْ بَلَدِكَ فَأَصْبَحَ بَلَدُكَ أَحَبَّ الْبِلَادِ كُلِّهَا إِلَيَّ وَإِنَّ خَيْلَكَ أَخَذَتْنِي وَأَنَا أُرِيدُ الْعُمْرَةَ فَمَاذَا تَرَى فَبَشَّرَهُ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَأَمَرَهُ أَنْ يَعْتَمِرَ فَلَمَّا قَدِمَ مَكَّةَ قَالَ لَهُ قَائِلٌ أَصَبَوْتَ فَقَالَ لَا وَلَكِنِّي أَسْلَمْتُ مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَلَا وَاللَّهِ لَا يَأْتِيكُمْ مِنْ الْيَمَامَةِ حَبَّةُ حِنْطَةٍ حَتَّى يَأْذَنَ فِيهَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَحَدَّثَنَا مُحَمَّدُ بْنُ الْمُثَنَّى حَدَّثَنَا أَبُو بَكْرٍ الْحَنَفِيُّ حَدَّثَنِي عَبْدُ الْحَمِيدِ بْنُ جَعْفَرٍ حَدَّثَنِي سَعِيدُ بْنُ أَبِي سَعِيدٍ الْمَقْبُرِيُّ أَنَّهُ سَمِعَ أَبَا هُرَيْرَةَ يَقُولُا بَعَثَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ خَيْلًا لَهُ نَحْوَ أَرْضِ نَجْدٍ فَجَاءَتْ بِرَجُلٍ يُقَالُ لَهُ ثُمَامَةُ بْنُ أُثَالٍ الْحَنَفِيُّ سَيِّدُ أَهْلِ الْيَمَامَةِ وَسَاقَ الْحَدِيثَ بِمِثْلِ حَدِيثِ اللَّيْثِ إِلَّا أَنَّهُ قَالَ إِنْ تَقْتُلْنِي تَقْتُلْ ذَا دَمٍ","id":"Telah menceritakan kepada kami [Qutaibah bin Sa'id] telah menceritakan kepada kami [Laits] dari [Sa'id bin Abu Sa'id] bahwa dia pernah mendengar [Abu Hurairah] berkata, \"Rasulullah shallallahu 'alaihi wasallam pernah mengirim pasukan berkuda ke negeri Najd, lantas mereka dapat menawan dan membawa seorang laki-laki dari Bani Hanifah yang bernama Tsumamah bin Utsal seorang tokoh penduduk Yamamah. Mereka mengikat tawanan tersebut di salah satu tiang masjid, lalu Rasulullah shallallahu 'alaihi wasallam keluar menemuinya seraya bersabda: \"Apa kabarmu wahai Tsumamah?\" dia menjawab, \"Kabarku baik-baik saja wahai Muhammad, jika kamu membunuhku berarti kamu telah menumpahkan darah, namun jika kamu membebaskanku, berarti kamu telah membebaskan orang yang pandai berterima kasih. Jika kamu menginginkan harta katakan saja, aku akan berikan berapa yang kamu kehendaki.\" Kemudian Rasulullah shallallahu 'alaihi wasallam meninggalkannya. Keesokan harinya, beliau bertanya lagi: \"Apa kabar wahai Tsumamah?\" dia menjawab, \"Kabarku sebagaimana yang telah kukabarkan kepadamu, jika kamu membunuhku berarti kamu telah menumpahkan darah, namun jika kamu membebaskanku, berarti kamu telah membebaskan orang yang pandai berterima kasih. Jika kamu menginginkan harta katakan saja, aku akan berikan berapa yang kamu kehendaki.\" Kemudian Rasulullah shallallahu 'alaihi wasallam meninggalkannya. Keesokan harinya, beliau bertanya lagi: \"Apa kabar wahai Tsumamah?\" dia menjawab, \"Kabarku sebagaimana yang telah kukatakan kepadamu, jika kamu membunuhku berarti kamu telah menumpahkan darah, namun jika kamu membebaskanku, berarti kamu telah membebaskan orang yang pandai berterima kasih. Jika kamu menginginkan harta katakan saja, aku akan berikan berapa yang kamu kehendaki.\" Kemudian Rasulullah shallallahu 'alaihi wasallam bersabda: \"Bebaskanlah Tsumamah!\" Kemudian dia pergi ke suatu batang pohon kurma dekat masjid, lalu dia mandi dan masuk masjid seraya berkata, \"Aku bersaksi bahwa tidak ada tuhan yang berhak disembah kecuali Allah dan aku bersaksi bahwa Muhammad adalah hamba dan utusan-Nya. Wahai Muhammad, demi Allah, tadinya tidak ada seraut wajah yang paling aku benci di muka bumi ini selain wajahmu, akan tetapi kini wajahmulah yang paling aku cintai di antara seluruh wajah. Demi Allah, tadinya tidak ada agama yang paling aku benci selain agamamu, akan tetapi kini agamamulah yang paling aku cintai daripada seluruh agama. Dulunya tidak ada negeri yang paling aku benci selain negerimu, akan tetapi kini tidak ada negeri yang paling aku cintai daripada negeri ini. Ketika pasukan berkuda menangkapku, aku bermaksud hendak pergi umrah, sekarang bagaimana pendapatmu?\" Rasulullah shallallahu 'alaihi wasallam menyampaikan berita gembira kepadanya, sesudah itu beliau menyuruhnya pergi umrah. Sesampainya tiba di Makkah, orang-orang bertanya kepadanya, \"Apakah kamu telah pindah agama?\" dia menjawab, \"Tidak, akan tetapi aku memeluk agama Islam bersama-sama Rasulullah shallallahu 'alaihi wasallam. Demi Allah janganlah kalian mengharap, sebiji gandumpun tidak akan datang kepada kalian dari Yamamah sebelum kalian mendapat izin dari Rasulullah shallallahu 'alaihi wasallam.\" Telah menceritakan kepada kami [Muhammad bin Mutsanna] telah menceritakan kepada kami [Abu Bakar Al Hanafi] telah menceritakan kepadaku [Abdul Hamid bin Ja'far] telah menceritakan kepadaku [Sa'id bin Abu Sa'id Al Maqburi] bahwa dia mendengar [Abu Hurairah] berkata, \"Rasulullah shallallahu 'alaihi wasallam pernah mengirim pasukan berkuda menuju ke arah Najd, lalu tentara tersebut membawa seorang laki-laki yang bernama Tsumamah bin Utsal Al Hanafi, seorang tokoh penduduk Yamamah…lalu dia melanjutkan hadits tersebut seperti hadits riwayat Laits, namun dia menyebutkan, \"Jika kamu membunuhku, berarti kamu telah menumpahkan darah.\""},"3078":{"ar":"حَدَّثَنَا قُتَيْبَةُ بْنُ سَعِيدٍ حَدَّثَنَا لَيْثٌ عَنْ سَعِيدِ بْنِ أَبِي سَعِيدٍ عَنْ أَبِيهِ عَنْ أَبِي هُرَيْرَةَ أَنَّهُ قَالَبَيْنَا نَحْنُ فِي الْمَسْجِدِ إِذْ خَرَجَ إِلَيْنَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ انْطَلِقُوا إِلَى يَهُودَ فَخَرَجْنَا مَعَهُ حَتَّى جِئْنَاهُمْ فَقَامَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَنَادَاهُمْ فَقَالَ يَا مَعْشَرَ يَهُودَ أَسْلِمُوا تَسْلَمُوا فَقَالُوا قَدْ بَلَّغْتَ يَا أَبَا الْقَاسِمِ فَقَالَ لَهُمْ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ذَلِكَ أُرِيدُ أَسْلِمُوا تَسْلَمُوا فَقَالُوا قَدْ بَلَّغْتَ يَا أَبَا الْقَاسِمِ فَقَالَ لَهُمْ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ذَلِكَ أُرِيدُ فَقَالَ لَهُمْ الثَّالِثَةَ فَقَالَ اعْلَمُوا أَنَّمَا الْأَرْضُ لِلَّهِ وَرَسُولِهِ وَأَنِّي أُرِيدُ أَنْ أُجْلِيَكُمْ مِنْ هَذِهِ الْأَرْضِ فَمَنْ وَجَدَ مِنْكُمْ بِمَالِهِ شَيْئًا فَلْيَبِعْهُ وَإِلَّا فَاعْلَمُوا أَنَّ الْأَرْضَ لِلَّهِ وَرَسُولِهِ","id":"Telah menceritakan kepada kami [Qutaibah bin Sa'id] telah menceritakan kepada kami [Laits] dari [Sa'id bin Abu Sa'id] dari [ayahnya] dari [Abu Hurairah] bahwa dia berkata, \"Ketika kami berada dalam masjid, tiba-tiba Rasulullah shallallahu 'alaihi wasallam keluar dan bersabda: \"Mari kita pergi ke pemukiman orang-orang Yahudi.\" Lalu kami pergi bersama beliau, setelah kami sampai di pemukiman mereka, Rasulullah shallallahu 'alaihi wasallam berdiri di hadapan mereka dan berseru: \"Wahai kaum Yahudi, masuk Islamlah kalian niscaya kalian akan selamat.\" Mereka lalu menjawab, \"Wahai Abu Qasim, kamu telah sampaikan itu.\" Rasulullah shallallahu 'alaihi wasallam menimpali: \"Itu yang aku inginkan. Masuk Islamlah kalian akan selamat. Mereka menjawab, \"Kamu telah sampaikan itu wahai Abu Qasim.\" Rasulullah shallallahu 'alaihi wasallam bersabda: \"Begitulah yang kami inginkan.\" Beliau mengulang seruan tersebut sampai tiga kali. Sesudah itu, beliau bersabda: \"Ketahuilah, sesungguhnya bumi ini kepunyaan Allah dan Rasul-Nya, oleh karena itu aku mengusir kalian dari negeri ini, barangsiapa masih memiliki harta di antara kalian, hendaknya dijual, jika tidak maka ketahuilah, bahwa bumi ini adalah milik Allah dan Rasul-Nya.\""},"3079":{"ar":"و حَدَّثَنِي مُحَمَّدُ بْنُ رَافِعٍ وَإِسْحَقُ بْنُ مَنْصُورٍ قَالَ ابْنُ رَافِعٍ حَدَّثَنَا و قَالَ إِسْحَقُ أَخْبَرَنَا عَبْدُ الرَّزَّاقِ أَخْبَرَنَا ابْنُ جُرَيْجٍ عَنْ مُوسَى بْنِ عُقْبَةَ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَأَنَّ يَهُودَ بَنِي النَّضِيرِ وَقُرَيْظَةَ حَارَبُوا رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَجْلَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بَنِي النَّضِيرِ وَأَقَرَّ قُرَيْظَةَ وَمَنَّ عَلَيْهِمْ حَتَّى حَارَبَتْ قُرَيْظَةُ بَعْدَ ذَلِكَ فَقَتَلَ رِجَالَهُمْ وَقَسَمَ نِسَاءَهُمْ وَأَوْلَادَهُمْ وَأَمْوَالَهُمْ بَيْنَ الْمُسْلِمِينَ إِلَّا أَنَّ بَعْضَهُمْ لَحِقُوا بِرَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَآمَنَهُمْ وَأَسْلَمُوا وَأَجْلَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَهُودَ الْمَدِينَةِ كُلَّهُمْ بَنِي قَيْنُقَاعَ وَهُمْ قَوْمُ عَبْدِ اللَّهِ بْنِ سَلَامٍ وَيَهُودَ بَنِي حَارِثَةَ وَكُلَّ يَهُودِيٍّ كَانَ بِالْمَدِينَةِو حَدَّثَنِي أَبُو الطَّاهِرِ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ وَهْبٍ أَخْبَرَنِي حَفْصُ بْنُ مَيْسَرَةَ عَنْ مُوسَى بِهَذَا الْإِسْنَادِ هَذَا الْحَدِيثَ وَحَدِيثُ ابْنِ جُرَيْجٍ أَكْثَرُ وَأَتَمُّ","id":"Telah menceritakan kepadaku [Muhammad bin Rafi'] dan [Ishaq bin Manshur], [Ibnu Rafi'] berkata; telah menceritakan kepada kami, sedangkan [Ishaq] berkata; telah menceritakan kepada kami [Abdurrazaq] telah menceritakan kepada kami [Ibnu Juraij] dari [Musa bin 'Uqbah] dari [Nafi'] dari [Ibnu Umar], bahwa kaum Yahudi Bani Nadlir dan Bani Quraidzah hendak memerangi Rasulullah shallallahu 'alaihi wasallam. Maka beliaupun mengusir Bani Nadlir dan membiarkan Bani Quraidzah (tetap berada di Madinah-pent) sampai akhirnya mereka memerangi Rasulullah shallallahu 'alaihi wasallam setelah itu. Maka Rasulullah shallallahu 'alaihi wasallam pun membunuh para kaum lelaki dari mereka, lalu para wanita, anak-anak, dan harta benda mereka beliau bagikan kepada kaum muslimin. Namun sebagian mereka ada yang menemui Rasulullah shallallahu 'alaihi wasallam untuk meminta jaminan keamanan dan masuk Islam. Dan Rasulullah shallallahu 'alaihi wasallam mengeluarkan seluruh kaum Yahudi yang ada di Madinah, baik itu Bani Qainuqa', para pengikut Abdullah bin Salam, Bani Haritsah, dan semua kaum Yahudi yang ada di Madinah tanpa terkecuali.\" Dan telah menceritakan kepadaku [Abu At Thahir] telah menceritakan kepada kami [Abdullah bin Wahb] telah menceritakan kepadaku [Hafsh bin Maisarah] dari [Musa] dengan sanad yang sama seperti ini. Hadits ini dan juga hadits Ibnu Juraij lebih banyak dan lebih lengkap.\""},"3080":{"ar":"و حَدَّثَنِي زُهَيْرُ بْنُ حَرْبٍ حَدَّثَنَا الضَّحَّاكُ بْنُ مَخْلَدٍ عَنْ ابْنِ جُرَيْجٍ ح و حَدَّثَنِي مُحَمَّدُ بْنُ رَافِعٍ وَاللَّفْظُ لَهُ حَدَّثَنَا عَبْدُ الرَّزَّاقِ أَخْبَرَنَا ابْنُ جُرَيْجٍ أَخْبَرَنِي أَبُو الزُّبَيْرِ أَنَّهُ سَمِعَ جَابِرَ بْنَ عَبْدِ اللَّهِ يَقُولُ أَخْبَرَنِي عُمَرُ بْنُ الْخَطَّابِأَنَّهُ سَمِعَ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ لَأُخْرِجَنَّ الْيَهُودَ وَالنَّصَارَى مِنْ جَزِيرَةِ الْعَرَبِ حَتَّى لَا أَدَعَ إِلَّا مُسْلِمًاو حَدَّثَنِي زُهَيْرُ بْنُ حَرْبٍ حَدَّثَنَا رَوْحُ بْنُ عُبَادَةَ أَخْبَرَنَا سُفْيَانُ الثَّوْرِيُّ ح و حَدَّثَنِي سَلَمَةُ بْنُ شَبِيبٍ حَدَّثَنَا الْحَسَنُ بْنُ أَعْيَنَ حَدَّثَنَا مَعْقِلٌ وَهُوَ ابْنُ عُبَيْدِ اللَّهِ كِلَاهُ��َا عَنْ أَبِي الزُّبَيْرِ بِهَذَا الْإِسْنَادِ مِثْلَهُ","id":"Dan telah menceritakan kepadaku [Zuhair bin Harb] telah menceritakan kepada kami [Ad Dlahak bin Makhlad] dari [Ibnu Juraij]. (dalam jalur lain disebutkan) Telah menceritakan kepadaku [Muhammad bin Rafi'] dan ini adalah lafadz dari dia, telah menceritakan kepada kami [Abdurrazaq] telah menceritakan kepada kami [Ibnu Juraij] telah menceritakan kepadaku [Abu Az Zubair] bahwa dia pernah mendengar [Jabir bin Abdullah] berkata; telah menceritakan kepadaku [Umar bin Khattab] bahwa dia pernah mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sungguh, aku akan mengeluarkan orang-orang Yahudi dan Nashrani dari jazirah arab, hingga tidak ada yang tersisa kecuali orang-orang Muslim.\" Dan telah menceritakan kepadaku [Zuhair bin Harb] telah menceritakan kepada kami [Rauh bin 'Ubadah] telah menceritakan kepada kami [Sufyan At tsauri]. (dalam jalur lain disebutkan) Telah menceritakan kepadaku [Salamah bin Syabib] telah menceritakan kepada kami [Al Hasan bin A'yan] telah menceritakan kepada kami [Ma'qil] -yaitu Ibnu 'Ubadillah- keduanya dari [Abu Az Zubair] dengan isnad seperti ini.\""},"3081":{"ar":"و حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ وَمُحَمَّدُ بْنُ الْمُثَنَّى وَابْنُ بَشَّارٍ وَأَلْفَاظُهُمْ مُتَقَارِبَةٌ قَالَ أَبُو بَكْرٍ حَدَّثَنَا غُنْدَرٌ عَنْ شُعْبَةَ و قَالَ الْآخَرَانِ حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ حَدَّثَنَا شُعْبَةُ عَنْ سَعْدِ بْنِ إِبْرَاهِيمَ قَالَ سَمِعْتُ أَبَا أُمَامَةَ بْنَ سَهْلِ بْنِ حُنَيْفٍ قَالَ سَمِعْتُ أَبَا سَعِيدٍ الْخُدْرِيَّ قَالَنَزَلَ أَهْلُ قُرَيْظَةَ عَلَى حُكْمِ سَعْدِ بْنِ مُعَاذٍ فَأَرْسَلَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِلَى سَعْدٍ فَأَتَاهُ عَلَى حِمَارٍ فَلَمَّا دَنَا قَرِيبًا مِنْ الْمَسْجِدِ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لِلْأَنْصَارِ قُومُوا إِلَى سَيِّدِكُمْ أَوْ خَيْرِكُمْ ثُمَّ قَالَ إِنَّ هَؤُلَاءِ نَزَلُوا عَلَى حُكْمِكَ قَالَ تَقْتُلُ مُقَاتِلَتَهُمْ وَتَسْبِي ذُرِّيَّتَهُمْ قَالَ فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَضَيْتَ بِحُكْمِ اللَّهِ وَرُبَّمَا قَالَ قَضَيْتَ بِحُكْمِ الْمَلِكِ وَلَمْ يَذْكُرْ ابْنُ الْمُثَنَّى وَرُبَّمَا قَالَ قَضَيْتَ بِحُكْمِ الْمَلِكِو حَدَّثَنَا زُهَيْرُ بْنُ حَرْبٍ حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ مَهْدِيٍّ عَنْ شُعْبَةَ بِهَذَا الْإِسْنَادِ وَقَالَ فِي حَدِيثِهِ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَقَدْ حَكَمْتَ فِيهِمْ بِحُكْمِ اللَّهِ وَقَالَ مَرَّةً لَقَدْ حَكَمْتَ بِحُكْمِ الْمَلِكِ","id":"Dan telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] dan [Muhammad bin Al Mutsanna] dan [Ibnu Basyar] sedangkan lafadz mereka saling berdekatan, [Abu Bakar] berkata; telah menceritakan kepada kami [Ghundar] dari [Syu'bah], sedangkan yang dua orang berkata; telah menceritakan kepada kami [Muhammad bin Ja'far] telah menceritakan kepada kami [Syu'bah] dari [Sa'd bin Ibrahim] dia berkata; aku pernah mendengar [Abu Umamah bin Sahl bin Hanif] berkata; aku pernah mendengar [Abu Sa'id Al Khudri] berkata, \"Penduduk Bani Quraizhah tunduk kepada hukum Sa'd bin Mu'adz, lantas Rasulullah shallallahu 'alaihi wasallam mengutus seseorang menemui Sa'd (agar ia datang menemui beliau), maka Sa'd pun datang menemui beliau dengan mengendarai seekor keledai. Ketika Sa'd telah dekar dengan masjid, Rasulullah shallallahu 'alaihi wasallam menyeru kepada orang-orang Anshar: \"Berdirilah kalian untuk pemuka kalian.\" Atau bersabda: \"Untuk orang yang terbaik kalian.\" Kemudian beliau bersabda: \"Sesungguhnya mereka semua menanti keputusan darimu.\" Sa'd lalu berkata, \"Sesungguhnya aku memutuskan untuk membunuh semua yang ikut berperang dan menawan anak-anak mereka.\" Abu Sa'id berkata, \"Nabi shallallahu 'alaihi wasallam lalu bersabda: \"Sungguh kamu telah memutuskan dengan hukum Allah.\" Atau beliau bersabda: \"Kamu telah memutuskan sesuai dengan hukum Raja (Allah).\" Namun Ibnu Mutsanna tidak menyebutkan kalimat 'Atau beliau bersabda: 'Kamu telah memutuskan sesuai dengan hukum Raja (Allah) '.\" Dan telah menceritakan kepada kami [Zuhair bin Harb] telah menceritakan kepada kami [Abdurrahman bin Mahdi] dari [Syu'bah] dengan isnad ini, dan dia menyebutkan dalam haditsnya, \"Lantas Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sungguh kamu telah menghukumi di antara mereka dengan hukum Allah.\" Dan sesekali beliau bersabda: \"Sungguh, kamu telah menghukumi dengan hukum Raja (Allah).\""},"3082":{"ar":"و حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ وَمُحَمَّدُ بْنُ الْعَلَاءِ الْهَمْدَانِيُّ كِلَاهُمَا عَنْ ابْنِ نُمَيْرٍ قَالَ ابْنُ الْعَلَاءِ حَدَّثَنَا ابْنُ نُمَيْرٍ حَدَّثَنَا هِشَامٌ عَنْ أَبِيهِ عَنْ عَائِشَةَ قَالَتْأُصِيبَ سَعْدٌ يَوْمَ الْخَنْدَقِ رَمَاهُ رَجُلٌ مِنْ قُرَيْشٍ يُقَالُ لَهُ ابْنُ الْعَرِقَةِ رَمَاهُ فِي الْأَكْحَلِ فَضَرَبَ عَلَيْهِ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ خَيْمَةً فِي الْمَسْجِدِ يَعُودُهُ مِنْ قَرِيبٍ فَلَمَّا رَجَعَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِنْ الْخَنْدَقِ وَضَعَ السِّلَاحَ فَاغْتَسَلَ فَأَتَاهُ جِبْرِيلُ وَهُوَ يَنْفُضُ رَأْسَهُ مِنْ الْغُبَارِ فَقَالَ وَضَعْتَ السِّلَاحَ وَاللَّهِ مَا وَضَعْنَاهُ اخْرُجْ إِلَيْهِمْ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَيْنَ فَأَشَارَ إِلَى بَنِي قُرَيْظَةَ فَقَاتَلَهُمْ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَنَزَلُوا عَلَى حُكْمِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَرَدَّ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْحُكْمَ فِيهِمْ إِلَى سَعْدٍ قَالَ فَإِنِّي أَحْكُمُ فِيهِمْ أَنْ تُقْتَلَ الْمُقَاتِلَةُ وَأَنْ تُسْبَى الذُّرِّيَّةُ وَالنِّسَاءُ وَتُقْسَمَ أَمْوَالُهُمْو حَدَّثَنَا أَبُو كُرَيْبٍ حَدَّثَنَا ابْنُ نُمَيْرٍ حَدَّثَنَا هِشَامٌ قَالَ قَالَ أَبِي فَأَخْبَرْتُ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَقَدْ حَكَمْتَ فِيهِمْ بِحُكْمِ اللَّهِ عَزَّ وَجَلَّ","id":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] dan [Muhammad bin Al 'Ala Al Hamdani] keduanya dari [Ibnu Numair], [Ibnu 'Ala] berkata; telah menceritakan kepada kami [Ibnu Numair] telah menceritakan kepada kami [Hisyam] dari [ayahnya] dari ['Aisyah] dia berkata, \"Pada waktu perang Khandaq Sa'd dipanah oleh seorang laki-laki Quraisy bernama Ibnu 'Ariqah, dia terkena panah tepat pada urat nadinya. Akhirnya Rasulullah shallallahu 'alaihi wasallam mendirikan kemah untuknya yang letaknya berdekatan dengan masjid, sehingga sewaktu-waktu beliau dapat menjenguknya. Sekembalinya dari perang Khandaq, Rasulullah shallallahu 'alaihi wasallam langsung meletakkan senjatanya, saat beliau mandi dan membersihkan badannya, Jibril datang dan meniup kepala beliau dari debu. Jibril bertanya, \"Apakah anda meletakkan senjata (untuk berdamai)? Demi Allah, kita tidak boleh meletakkan senjata, keluar dan perangilah mereka.\" Rasulullah shallallahu 'alaihi wasallam kemudian bersabda: \"Kemana aku harus keluar?\" Jibril lalu memberikan isyarat kepada beliau untuk pergi ke perkampungan kaum Yahudi Bani Quraizhah. Kemudian Rasulullah shallallahu 'alaihi wasallam bersama dengan kaum Muslimin memerangi mereka. Akhirnya mereka takluk dan tunduk kepada keputusan Rasulullah shallallahu 'alaihi wasallam, akan tetapi Rasulullah shallallahu 'alaihi wasallam menyerahkan keputusan tersebut kepada Sa'd. Selanjutnya Sa'd berkata, \"Sesungguhnya aku memutuskan untuk membunuh semua yang turut serta dalam peperangan, menawan anak-anak dan kaum wanita, serta membagi-bagikan harta benda mereka.\" Telah menceritakan kepada kami [Abu Kuraib] telah menceritakan kepada kami [Ibnu Numair] telah menceritakan kepada kami [Hisyam] dia berkata; [ayahku] berkata, \"Aku lalu kabarkan kepadanya bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sungguh, kamu telah menghukumi perkara mereka dengan hukum Allah.\""},"3083":{"ar":"حَدَّثَنَا أَبُو كُرَيْبٍ حَدَّثَنَا ابْنُ نُمَيْرٍ عَنْ هِشَامٍ أَخْبَرَنِي أَبِي عَنْ عَائِشَةَأَنَّ سَعْدًا قَالَ وَتَحَجَّرَ كَلْمُهُ لِلْبُرْءِ فَقَالَ اللَّهُمَّ إِنَّكَ تَعْلَمُ أَنْ لَيْسَ أَحَدٌ أَحَبَّ إِلَيَّ أَنْ أُجَاهِدَ فِيكَ مِنْ قَوْمٍ كَذَّبُوا رَسُولَكَ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَأَخْرَجُوهُ اللَّهُمَّ فَإِنْ كَانَ بَقِيَ مِنْ حَرْبِ قُرَيْشٍ شَيْءٌ فَأَبْقِنِي أُجَاهِدْهُمْ فِيكَ اللَّهُمَّ فَإِنِّي أَظُنُّ أَنَّكَ قَدْ وَضَعْتَ الْحَرْبَ بَيْنَنَا وَبَيْنَهُمْ فَإِنْ كُنْتَ وَضَعْتَ الْحَرْبَ بَيْنَنَا وَبَيْنَهُمْ فَافْجُرْهَا وَاجْعَلْ مَوْتِي فِيهَا فَانْفَجَرَتْ مِنْ لَبَّتِهِ فَلَمْ يَرُعْهُمْ وَفِي الْمَسْجِدِ مَعَهُ خَيْمَةٌ مِنْ بَنِي غِفَارٍ إِلَّا وَالدَّمُ يَسِيلُ إِلَيْهِمْ فَقَالُوا يَا أَهْلَ الْخَيْمَةِ مَا هَذَا الَّذِي يَأْتِينَا مِنْ قِبَلِكُمْ فَإِذَا سَعْدٌ جُرْحُهُ يَغِذُّ دَمًا فَمَاتَ مِنْهَاو حَدَّثَنَا عَلِيُّ بْنُ الْحُسَيْنِ بْنِ سُلَيْمَانَ الْكُوفِيُّ حَدَّثَنَا عَبْدَةُ عَنْ هِشَامٍ بِهَذَا الْإِسْنَادِ نَحْوَهُ غَيْرَ أَنَّهُ قَالَ فَانْفَجَرَ مِنْ لَيْلَتِهِ فَمَا زَالَ يَسِيلُ حَتَّى مَاتَ وَزَادَ فِي الْحَدِيثِ قَالَ فَذَاكَ حِينَ يَقُولُ الشَّاعِرُ أَلَا يَا سَعْدُ سَعْدَ بَنِي مُعَاذٍفَمَا فَعَلَتْ قُرَيْظَةُ وَالنَّضِيرُلَعَمْرُكَ إِنَّ سَعْدَ بَنِي مُعَاذٍغَدَاةَ تَحَمَّلُوا لَهُوَ الصَّبُورُتَرَكْتُمْ قِدْرَكُمْ لَا شَيْءَ فِيهَاوَقِدْرُ الْقَوْمِ حَامِيَةٌ تَفُورُوَقَدْ قَالَ الْكَرِيمُ أَبُو حُبَابٍأَقِيمُوا قَيْنُقَاعُ وَلَا تَسِيرُواوَقَدْ كَانُوا بِبَلْدَتِهِمْ ثِقَالًاكَمَا ثَقُلَتْ بِمَيْطَانَ الصُّخُورُ","id":"Telah menceritakan kepada kami [Abu Kuraib] telah menceritakan kepada kami [Ibnu Numair] dari [Hisyam] telah menceritakan kepadaku [ayahku] dari ['Aisyah] bahwa Sa'd berkata -ketika penyakit yang dideritanya semakin parah-, dia katakan, \"Ya Allah, sesungguhnya Engkau tahu bahwa tidak ada sesuatupun yang paling saya cintai melainkan berjihad di jalan-Mu untuk memerangi orang-orang yang mendustakan Rasul-Mu shallallahu 'alaihi wasallam dan mengusir beliau. Ya Allah, jika masih tersisa peperang dengan orang-orang Quraisy, maka tetapkanlah saya hidup supaya dapat memerangi mereka di jalan-Mu. Sungguh, saya yakin bahwa Engkau telah menetapkan peperangan antara kami dan mereka, maka jika Engkau telah menetapkan peperangan antara kami dengan mereka, jadikanlah matiku di dalam peperang tersebut.\" Darah pun semakin deras mengucur dari luka Sa'd, namun para sahabat tidak menyadarinya. Sedangkan dalam Masjid terdapat tenda dari Bani Ghifar, sehingga darah tersebut terus mengalir sampai kepada mereka yang ada di tenda, maka mereka berkata, \"Wahai penghuni tenda, darah apa yang mengalir dari arah kalian?\" Ternyata luka Sa'd lah yang mengalirkan darah, hingga dia wafat karenanya.\" Dan telah menceritakan kepada kami [Ali bin Al Husain bin Sulaiman Al Kufi] dan telah menceritakan kepada kami ['Abdah] dari [Hisyam] dengan sanad ini, seperti hadits tersebut. Hanya saja ia menyebutkan, \"Malam itu lukanya terus mengeluarkan darah hingga ia pun meninggal, dan dalam hadits ditambahkan, ia berkata \"Yang demikian itu, ketika seorang penyair bersenandung, \"Ketahuilah wahai Sa'd, Quraizhah dan Nadlir tidak berbuat sesuatu terhadap Sa'd bani Mu'adz. #Demi umurmu, bahwa Sa'd bani Mu'adz berpagi-pagi menanggung kepedihan sedang dia tetap bersabar. #Kalian tinggalkan periuk kalian yang tidak terisi, sedang periuk orang lain mendidih di atas tungku. #Al karim Abu Hubab telah berkata; tinggallah wahai bani Qainuqa' jangan bergerak. #Di negri sendiri mereka merasa penat, sebagiamana mereka penat di Mithan ash Shukhur.\""},"3084":{"ar":"و حَدَّثَنِي عَبْدُ اللَّهِ بْنُ مُحَمَّدِ بْنِ أَسْمَاءَ الضُّبَعِيُّ حَدَّثَنَا جُوَيْرِيَةُ بْنُ أَسْمَاءَ عَنْ نَافِعٍ عَنْ عَبْدِ اللَّهِ قَالَنَادَى فِينَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَوْمَ انْصَرَفَ عَنْ الْأَحْزَابِ أَنْ لَا يُصَلِّيَنَّ أَحَدٌ الظُّهْرَ إِلَّا فِي بَنِي قُرَيْظَةَ فَتَخَوَّفَ نَاسٌ فَوْتَ الْوَقْتِ فَصَلَّوْا دُونَ بَنِي قُرَيْظَةَ وَقَالَ آخَرُونَ لَا نُصَلِّي إِلَّا حَيْثُ أَمَرَنَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَإِنْ فَاتَنَا الْوَقْتُ قَالَ فَمَا عَنَّفَ وَاحِدًا مِنْ الْفَرِيقَيْنِ","id":"Dan telah menceritakan kepadaku [Abdullah bin Muhammad bin Asma Ad Bua'i] telah menceritakan kepada kami [Juwairiyah bin Asma] dari [Nafi'] dari [Abdullah] dia berkata, \"Ketika kami telah kembali dari perang Ahzab, Rasulullah shallallahu 'alaihi wasallam berseru kepada kami: \"Hendaklah tidak ada seorangpun yang melaksanakan shalat zhuhur kecuali jika ia telah sampai di tempat Bani Quraizhah.\" Lalu sebagian sahabat ada yang khawatir akan habisnya waktu shalat, sehingga mereka melaksanakannya sebelum memasuki daerah Bani Quraizhah. Sedangkan yang lainnya berkata, \"Kami tidak akan melaksanakan shalat kecuali pada tempat yang telah Rasulullah shallallahu 'alaihi wasallam pesankan untuk kami, meskipun waktu shalat telah habis.\" Abdullah berkata, \"Dan ternyata beliau tidak mencela salah satu dari kedua kelompok tersebut.\""},"3085":{"ar":"و حَدَّثَنِي أَبُو الطَّاهِرِ وَحَرْمَلَةُ قَالَا أَخْبَرَنَا ابْنُ وَهْبٍ أَخْبَرَنِي يُونُسُ عَنْ ابْنِ شِهَابٍ عَنْ أَنَسِ بْنِ مَالِكٍ قَالَلَمَّا قَدِمَ الْمُهَاجِرُونَ مِنْ مَكَّةَ الْمَدِينَةَ قَدِمُوا وَلَيْسَ بِأَيْدِيهِمْ شَيْءٌ وَكَانَ الْأَنْصَارُ أَهْلَ الْأَرْضِ وَالْعَقَارِ فَقَاسَمَهُمْ الْأَنْصَارُ عَلَى أَنْ أَعْطَوْهُمْ أَنْصَافَ ثِمَارِ أَمْوَالِهِمْ كُلَّ عَامٍ وَيَكْفُونَهُمْ الْعَمَلَ وَالْمَئُونَةَ وَكَانَتْ أُمُّ أَنَسِ بْنِ مَالِكٍ وَهِيَ تُدْعَى أُمَّ سُلَيْمٍ وَكَانَتْ أُمُّ عَبْدِ اللَّهِ بْنِ أَبِي طَلْحَةَ كَانَ أَخًا لِأَنَسٍ لِأُمِّهِ وَكَانَتْ أَعْطَتْ أُمُّ أَنَسٍ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عِذَاقًا لَهَا فَأَعْطَاهَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أُمَّ أَيْمَنَ مَوْلَاتَهُ أُمَّ أُسَامَةَ بْنِ زَيْدٍ قَالَ ابْنُ شِهَابٍ فَأَخْبَرَنِي أَنَسُ بْنُ مَالِكٍ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَمَّا فَرَغَ مِنْ قِتَالِ أَهْلِ خَيْبَرَ وَانْصَرَفَ إِلَى الْمَدِينَةِ رَدَّ الْمُهَاجِرُونَ إِلَى الْأَنْصَارِ مَنَائِحَهُمْ الَّتِي كَانُوا مَنَحُوهُمْ مِنْ ثِمَارِهِمْ قَالَ فَرَدَّ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِلَى أُمِّي عِذَاقَهَا وَأَعْطَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أُمَّ أَيْمَنَ مَكَانَهُنَّ مِنْ حَائِطِهِقَالَ ابْنُ شِهَابٍ وَكَانَ مِنْ شَأْنِ أُمِّ أَيْمَنَ أُمِّ أُسَامَةَ بْنِ زَيْدٍ أَنَّهَا كَانَتْ وَصِيفَةً لِعَبْدِ اللَّهِ بْنِ عَبْدِ الْمُطَّلِبِ وَكَانَتْ مِنْ الْحَبَشَةِ فَلَمَّا وَلَدَتْ آمِنَةُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بَعْدَ مَا تُوُفِّيَ أَبُوهُ فَكَانَتْ أُمُّ أَيْمَنَ تَحْضُنُهُ حَتَّى كَبِرَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَعْتَقَهَا ثُمَّ أَنْكَحَهَا زَيْدَ بْنَ حَارِثَةَ ثُمَّ تُوُفِّيَتْ بَعْدَ مَا تُوُفِّيَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِخَمْسَةِ أَشْهُرٍ","id":"Dan telah menceritakan kepadaku [Abu At Thahir] dan [Harmalah] keduanya; telah mengabarkan kepada kami [Ibnu Wahb] telah mengabarkan kepadaku [Yunus] dari [Ibnu Syihab] dari [Anas bin Malik] dia berkata, \"Ketika kaum muhajirin tiba dari Makkah ke Madinah, mereka datang dengan tidak membawa sesuatupun, sedangkan kaum Anshar mempunyai tanah dan kebun kurma yang luas. Maka orang-orang Anshar membagikan sebagiannya kepada Sahabat Muhajirin dengan syarat mereka memberikan setengah dari hasil penennya setiap tahun. Maka orang-orang Muhajirin pun membayar kepada orang-orang Anshar dengan kerja dan makanan.\" Ibu Anas bin Malik atau yang biasa dipanggil Ummu Sulaim, dan Ibu Abdullah bin Abu Thalhah - saudara seibu Anas-, Ibu Anas memberikan kebun kurma miliknya kepada Rasulullah shallallahu 'alaihi wasallam, lalu beliau memberikannya kepada Ummu Aiman, budak Ibu Usamah bin Zaid.\" Ibnu Syihab berkata, \"Lalu Anas bin Malik mengabarkan kepadaku, bahwa ketika Rasulullah shallallahu 'alaihi wasallam kembali dari perang Khaibar beliau pulang ke Madinah, lalu kaum muhajirin mengembalikan kebun kurma pemberian kaum anshar kepada mereka.\" Ibnu Syihab berkata, \"Rasulullah shallallahu 'alaihi wasallam juga mengembalikan kebun kurmanya kepada ibuku, dan beliau shallallahu 'alaihi wasallam juga memberikan bagian dari kebun kurmanya kepada Ummu Aiman.\" Ibnu Syihab berkata, \"Yang menjadi permasalahan Ummu Aiman ialah, bahwa Ibu Usamah bin Zaid dulunya seorang pelayan milik Abdullah bin Abdul Muththallib yang berasal dari Habasyah. Ketika Aminah (Ibu Rasul) melahirkan Rasulullah shallallahu 'alaihi wasallam, setelah ditinggal wafat oleh ayahnya, maka Ummu Aimanlah yang merawat beliau hingga beliau shallallahu 'alaihi wasallam dewasa, kemudian ia dimerdekakan dan dinikahi oleh Zaid bin Haritsah. Ummu Aiman meninggal dunia lima tahun setelah meninggalnya Rasulullah shallallahu 'alaihi wasallam.\""},"3086":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ وَحَامِدُ بْنُ عُمَرَ الْبَكْرَاوِيُّ وَمُحَمَّدُ بْنُ عَبْدِ الْأَعْلَى الْقَيْسِيُّ كُلُّهُمْ عَنْ الْمُعْتَمِرِ وَاللَّفْظُ لِابْنِ أَبِي شَيْبَةَ حَدَّثَنَا مُعْتَمِرُ بْنُ سُلَيْمَانَ التَّيْمِيُّ عَنْ أَبِيهِ عَنْ أَنَسٍأَنَّ رَجُلًا وَقَالَ حَامِدٌ وَابْنُ عَبْدِ الْأَعْلَى أَنَّ الرَّجُلَ كَانَ يَجْعَلُ لِلنَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ النَّخَلَاتِ مِنْ أَرْضِهِ حَتَّى فُتِحَتْ عَلَيْهِ قُرَيْظَةُ وَالنَّضِيرُ فَجَعَلَ بَعْدَ ذَلِكَ يَرُدُّ عَلَيْهِ مَا كَانَ أَعْطَاهُ قَالَ أَنَسٌ وَإِنَّ أَهْلِي أَمَرُونِي أَنْ آتِيَ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَسْأَلَهُ مَا كَانَ أَهْلُهُ أَعْطَوْهُ أَوْ بَعْضَهُ وَكَانَ نَبِيُّ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَدْ أَعْطَاهُ أُمَّ أَيْمَنَ فَأَتَيْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَعْطَانِيهِنَّ فَجَاءَتْ أُمُّ أَيْمَنَ فَجَعَلَتْ الثَّوْبَ فِي عُنُقِي وَقَالَتْ وَاللَّهِ لَا نُعْطِيكَاهُنَّ وَقَدْ أَعْطَانِيهِنَّ فَقَالَ نَبِيُّ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَا أُمَّ أَيْمَنَ اتْرُكِيهِ وَلَكِ كَذَا وَكَذَا وَتَقُولُ كَلَّا وَالَّذِي لَا إِلَهَ إِلَّا هُوَ فَجَعَلَ يَقُولُ كَذَا حَتَّى أَعْطَاهَا عَشْرَةَ أَمْثَالِهِ أَوْ قَرِيبًا مِنْ عَشْرَةِ أَمْثَالِهِ","id":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah], [Hamid bin Umar Al Bakrawi] dan [Muhammad bin Abdul A'la Al Qaisi] semuanya dari [Al Mu'tamir] sedangkan lafadznya dari Ibnu Abu Syaibah telah menceritakan kepada kami [Mu'tamir bin Sulaiman At Taimi] dari [ayahnya] dari [Anas] bahwa seorang laki-laki…\" sedangkan Hamid dan Ibnu Abdul A'la mengatakan; \"Bahwa seorang laki-laki pernah memberikan sebagian kebun kurmanya kepada Rasulullah shallallahu 'alaihi wasallam, sampai beliau menaklukkan Bani Quraidlah dan Bani Nadlir. Setelah penaklukan tersebut, maka beliau mengembalikan sebagian kebun kurma kepada laki-laki itu.\" Anas berkata; \"Sesungguhnya keluargaku menyuruhku mendatangi Nabi shallallahu 'alaihi wasallam untuk meminta kembali apa yang pernah di berikan oleh beliau yaitu berupa sebidang kebun, padahal Nabi shallallahu 'alaihi wasallam telah memberikannya kepada Ummu Aiman. Lantas aku mendatangi Nabi shallallahu 'alaihi wasallam dan beliaupun menyerahkannya kembali kepadaku, tiba-tiba Ummu Aiman datang sambil menaruh selendangnya di leherku seraya berkata; \"Demi Allah, kami tidak akan memberikannya kepadamu, sebab beliau telah memberikannya kepadaku.\" Maka Nabi shallallahu 'alaihi wasallam bersabda: \"Wahai Ummu Aiman, biarkanlah dia mengambilnya lagi, dan untukmu ini dan ini.\" Namun dia tetap mengatakan; \"Sekali-kali tidak, demi Dzat yang tidak adak ilah selain Dia…\" Ummu Aiman masih tetap berkata seperti itu sehingga beliau memberinya sepuluh kali dari pemberian yang hendak di ambil oleh Anas, atau mendekati sepuluh kali lipatnya.\""},"3087":{"ar":"حَدَّثَنَا شَيْبَانُ بْنُ فَرُّوخَ حَدَّثَنَا سُلَيْمَانُ يَعْنِي ابْنَ الْمُغِيرَةِ حَدَّثَنَا حُمَيْدُ بْنُ هِلَالٍ عَنْ عَبْدِ اللَّهِ بْنِ مُغَفَّلٍ قَالَأَصَبْتُ جِرَابًا مِنْ شَحْمٍ يَوْمَ خَيْبَرَ قَالَ فَالْتَزَمْتُهُ فَقُلْتُ لَا أُعْطِي الْيَوْمَ أَحَدًا مِنْ هَذَا شَيْئًا قَالَ فَالْتَفَتُّ فَإِذَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مُتَبَسِّمًا","id":"Telah menceritakan kepada kami [Syaiban bin Farruh] telah menceritakan kepada kami [Sulaiman] -yaitu Ibnu Al Mughirah- telah menceritakan kepada kami [Humaid bin Hilal] dari [Abdullah bin Mughaffal] dia berkata, \"Aku mendapatkan sekantong lemak ketika penaklukan Khaibar. Kemudian aku mengambilnya seraya berkata, \"Hari ini aku tidak akan memberikannya kepada seorangpun.\" Abdullah berkata melanjutkan, \"Kemudian aku menoleh, ternyata Rasulullah shallallahu 'alaihi wasallam tersenyum saat mendengarnya.\""},"3088":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ الْعَبْدِيُّ حَدَّثَنَا بَهْزُ بْنُ أَسَدٍ حَدَّثَنَا شُعْبَةُ حَدَّثَنِي حُمَيْدُ بْنُ هِلَالٍ قَالَ سَمِعْتُ عَبْدَ اللَّهِ بْنَ مُغَفَّلٍ يَقُولُارُمِيَ إِلَيْنَا جِرَابٌ فِيهِ طَعَامٌ وَشَحْمٌ يَوْمَ خَيْبَرَ فَوَثَبْتُ لِآخُذَهُ قَالَ فَالْتَفَتُّ فَإِذَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَاسْتَحْيَيْتُ مِنْهُو حَدَّثَنَاه مُحَمَّدُ بْنُ الْمُثَنَّى حَدَّثَنَا أَبُو دَاوُدَ حَدَّثَنَا شُعْبَةُ بِهَذَا الْإِسْنَادِ غَيْرَ أَنَّهُ قَالَ جِرَابٌ مِنْ شَحْمٍ وَلَمْ يَذْكُرْ الطَّعَامَ","id":"Telah menceritakan kepada kami [Muhammad bin Basyar] telah menceritakan kepada kami [Bahz bin Asad] telah menceritakan kepada kami [Syu'bah] telah menceritakan kepadaku [Humaid bin Hilal] dia berkata; aku mendengar [Abdullah bin Mughaffal] berkata, \"Ketika penaklukan kota Khaibar, sekantong kulit berisikan perbekalan makanan dan lemak dilemparkan kepada kami, lalu aku melompat untuk segera mengambilnya, kemudian aku menoleh ternyata ada Rasulullah shallallahu 'alaihi wasallam hingga aku malu karenanya.\" Dan telah menceritakan kepada kami [Muhamad bin Al Mutsanna] telah menceritakan kepada kami [Abu Daud] telah menceritakan kepada kami [Syu'bah] dengan isnad ini, namun dia menyebutkan, 'Sekantong kulit berisikan lemak, ' dan tidak menyebutkan, 'Makanan'.\""},"3089":{"ar":"حَدَّثَنَا إِسْحَقُ بْنُ إِبْرَاهِيمَ الْحَنْظَلِيُّ وَابْنُ أَبِي عُمَرَ وَمُحَمَّدُ بْنُ رَافِعٍ وَعَبْدُ بْنُ حُمَيْدٍ وَاللَّفْظُ لِابْنِ رَافِعٍ قَالَ ابْنُ رَافِعٍ وَابْنُ أَبِي عُمَرَ حَدَّثَنَا و قَالَ الْآخَرَانِ أَخْبَرَنَا عَبْدُ الرَّزَّاقِ أَخْبَرَنَا مَعْمَرٌ عَنْ الزُّهْرِيِّ عَنْ عُبَيْدِ اللَّهِ بْنِ عَبْدِ اللَّهِ بْنِ عُتْبَةَ عَنْ ابْنِ عَبَّاسٍ أَنَّ أَبَا سُفْيَانَ أَخْبَرَهُ مِنْ فِيهِ إِلَى فِيهِ قَالَانْطَلَقْتُ فِي الْمُدَّةِ الَّتِي كَانَتْ بَيْنِي وَبَيْنَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ فَبَيْنَا أَنَا بِالشَّأْمِ إِذْ جِيءَ بِكِتَابٍ مِنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِلَى هِرَقْلَ يَعْنِي عَظِيمَ الرُّومِ قَالَ وَكَانَ دَحْيَةُ الْكَلْبِيُّ جَاءَ بِهِ فَدَفَعَهُ إِلَى عَظِيمِ بُصْرَى فَدَفَعَهُ عَظِيمُ بُصْرَى إِلَى هِرَقْلَ فَقَالَ هِرَقْلُ هَلْ هَاهُنَا أَحَدٌ مِنْ قَوْمِ هَذَا الرَّجُلِ الَّذِي يَزْعُمُ أَنَّهُ نَبِيٌّ قَالُوا نَعَمْ قَالَ فَدُعِيتُ فِي نَفَرٍ مِنْ قُرَيْشٍ فَدَخَلْنَا عَلَى هِرَقْلَ فَأَجْلَسَنَا بَيْنَ يَدَيْهِ فَقَالَ أَيُّكُمْ أَقْرَبُ نَسَبًا مِنْ هَذَا الرَّجُلِ الَّذِي يَزْعُمُ أَنَّهُ نَبِيٌّ فَقَالَ أَبُو سُفْيَانَ فَقُلْتُ أَنَا فَأَجْلَسُونِي بَيْنَ يَدَيْهِ وَأَجْلَسُوا أَصْحَابِي خَلْفِي ثُمَّ دَعَا بِتَرْجُمَانِهِ فَقَالَ لَهُ قُلْ لَهُمْ إِنِّي سَائِلٌ هَذَا عَنْ الرَّجُلِ الَّذِي يَزْعُمُ أَنَّهُ نَبِيٌّ فَإِنْ كَذَبَنِي فَكَذِّبُوهُ قَالَ فَقَالَ أَبُو سُفْيَانَ وَايْمُ اللَّهِ لَوْلَا مَخَافَةُ أَنْ يُؤْثَرَ عَلَيَّ الْكَذِبُ لَكَذَبْتُ ثُمَّ قَالَ لِتَرْجُمَانِهِ سَلْهُ كَيْفَ حَسَبُهُ فِيكُمْ قَالَ قُلْتُ هُوَ فِينَا ذُو حَسَبٍ قَالَ فَهَلْ كَانَ مِنْ آبَائِهِ مَلِكٌ قُلْتُ لَا قَالَ فَهَلْ كُنْتُمْ تَتَّهِمُونَهُ بِالْكَذِبِ قَبْلَ أَنْ يَقُولَ مَا قَالَ قُلْتُ لَا قَالَ وَمَنْ يَتَّبِعُهُ أَشْرَافُ النَّاسِ أَمْ ضُعَفَاؤُهُمْ قَالَ قُلْتُ بَلْ ضُعَفَاؤُهُمْ قَالَ أَيَزِيدُونَ أَمْ يَنْقُصُونَ قَالَ قُلْتُ لَا بَلْ يَزِيدُونَ قَالَ هَلْ يَرْتَدُّ أَحَدٌ مِنْهُمْ عَنْ دِينِهِ بَعْدَ أَنْ يَدْخُلَ فِيهِ سَخْطَةً لَهُ قَالَ قُلْتُ لَا قَالَ فَهَلْ قَاتَلْتُمُوهُ قُلْتُ نَعَمْ قَالَ فَكَيْفَ كَانَ قِتَالُكُمْ إِيَّاهُ قَالَ قُلْتُ تَكُونُ الْحَرْبُ بَيْنَنَا وَبَيْنَهُ سِجَالًا يُصِيبُ مِنَّا وَنُصِيبُ مِنْهُ قَالَ فَهَلْ يَغْدِرُ قُلْتُ لَا وَنَحْنُ مِنْهُ فِي مُدَّةٍ لَا نَدْرِي مَا هُوَ صَانِعٌ فِيهَا قَالَ فَوَاللَّهِ مَا أَمْكَنَنِي مِنْ كَلِمَةٍ أُدْخِلُ فِيهَا شَيْئًا غَيْرَ هَذِهِ قَالَ فَهَلْ قَالَ هَذَا الْقَوْلَ أَحَدٌ قَبْلَهُ قَالَ قُلْتُ لَا قَالَ لِتَرْجُمَانِهِ قُلْ لَهُ إِنِّي سَأَلْتُكَ عَنْ حَسَبِهِ فَزَعَمْتَ أَنَّهُ فِيكُمْ ذُو حَسَبٍ وَكَذَلِكَ الرُّسُلُ تُبْعَثُ فِي أَحْسَابِ قَوْمِهَا وَسَأَلْتُكَ هَلْ كَانَ فِي آبَائِهِ مَلِكٌ فَزَعَمْتَ أَنْ لَا فَقُلْتُ لَوْ كَانَ مِنْ آبَائِهِ مَلِكٌ قُلْتُ رَجُلٌ يَطْلُبُ مُلْكَ آبَائِهِ وَسَأَلْتُكَ عَنْ أَتْبَاعِهِ أَضُعَفَاؤُهُمْ أَمْ أَشْرَافُهُمْ فَقُلْتَ بَلْ ضُعَفَاؤُهُمْ وَهُمْ أَتْبَاعُ الرُّسُلِ وَسَأَلْتُكَ هَلْ كُنْتُمْ تَتَّهِمُونَهُ بِالْكَذِبِ قَبْلَ أَنْ يَقُولَ مَا قَالَ فَزَعَمْتَ أَنْ لَا فَقَدْ عَرَفْتُ أَنَّهُ لَمْ يَكُنْ لِيَدَعَ الْكَذِبَ عَلَى النَّاسِ ثُمَّ يَذْهَبَ فَيَكْذِبَ عَلَى اللَّهِ وَسَأَلْتُكَ هَلْ يَرْتَدُّ أَحَدٌ مِنْهُمْ عَنْ دِينِهِ بَعْدَ أَنْ يَدْخُلَهُ سَخْطَةً لَهُ فَزَعَمْتَ أَنْ لَا وَكَذَلِكَ الْإِيمَانُ إِذَا خَالَطَ بَشَاشَةَ الْقُلُوبِ وَسَأَلْتُكَ هَلْ يَزِيدُونَ أَوْ يَنْقُصُونَ فَزَعَمْتَ أَنَّهُمْ يَزِيدُونَ وَكَذَلِكَ الْإِيمَانُ حَتَّى يَتِمَّ وَسَأَلْتُكَ هَلْ قَاتَلْتُمُوهُ فَزَعَمْتَ أَنَّكُمْ قَدْ قَاتَلْتُمُوهُ فَتَكُونُ الْحَرْبُ بَيْنَكُمْ وَبَيْنَهُ سِجَالًا يَنَالُ مِنْكُمْ وَتَنَالُونَ مِنْهُ وَكَذَلِكَ الرُّسُلُ تُبْتَلَى ثُمَّ تَكُونُ لَهُمْ الْعَاقِبَةُ وَسَأَلْتُكَ هَلْ يَغْدِرُ فَزَعَمْتَ أَنَّهُ لَا يَغْدِرُ وَكَذَلِكَ الرُّسُلُ لَا تَغْدِرُ وَسَأَلْتُكَ هَلْ قَالَ هَذَا الْقَوْلَ أَحَدٌ قَبْلَهُ فَزَعَمْتَ أَنْ لَا فَقُلْتُ لَوْ قَالَ هَذَا الْقَوْلَ أَحَدٌ قَبْلَهُ قُلْتُ رَجُلٌ ائْتَمَّ بِقَوْلٍ قِيلَ قَبْلَهُ قَالَ ثُمَّ قَالَ بِمَ يَأْمُرُكُمْ قُلْتُ يَأْمُرُنَا بِالصَّلَاةِ وَالزَّكَاةِ وَالصِّلَةِ وَالْعَفَافِ قَالَ إِنْ يَكُنْ مَا تَقُولُ فِيهِ حَقًّا فَإِنَّهُ نَبِيٌّ وَقَدْ كُنْتُ أَعْلَمُ أَنَّهُ خَارِجٌ وَلَمْ أَكُنْ أَظُنُّهُ مِنْكُمْ وَلَوْ أَنِّي أَعْلَمُ أَنِّي أَخْلُصُ إِلَيْهِ لَأَحْبَبْتُ لِقَاءَهُ وَلَوْ كُنْتُ عِنْدَهُ لَغَسَلْتُ عَنْ قَدَمَيْهِ وَلَيَبْلُغَنَّ مُلْكُهُ مَا تَحْتَ قَدَمَيَّ قَالَ ثُمَّ دَعَا بِكِتَابِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَرَأَهُ فَإِذَا فِيهِ بِسْمِ اللَّهِ الرَّحْمَنِ الرَّحِيمِ مِنْ مُحَمَّدٍ رَسُولِ اللَّهِ إِلَى هِرَقْلَ عَظِيمِ الرُّومِ سَلَامٌ عَلَى مَنْ اتَّبَعَ الْهُدَى أَمَّا بَعْدُ فَإِنِّي أَدْعُوكَ بِدِعَايَةِ الْإِسْلَامِ أَسْلِمْ تَسْلَمْ وَأَسْلِمْ يُؤْتِكَ اللَّهُ أَجْرَكَ مَرَّتَيْنِ وَإِنْ تَوَلَّيْتَ فَإِنَّ عَلَيْكَ إِثْمَ الْأَرِيسِيِّينَ وَ{ يَا أَهْلَ الْكِتَابِ تَعَالَوْا إِلَى كَلِمَةٍ سَوَاءٍ بَيْنَنَا وَبَيْنَكُمْ أَنْ لَا نَعْبُدَ إِلَّا اللَّهَ وَلَا نُشْرِكَ بِهِ شَيْئًا وَلَا يَتَّخِذَ بَعْضُنَا بَعْضًا أَرْبَابًا مِنْ دُونِ اللَّهِ فَإِنْ تَوَلَّوْا فَقُولُوا اشْهَدُوا بِأَنَّا مُسْلِمُونَ }فَلَمَّا فَرَغَ مِنْ قِرَاءَةِ الْكِتَابِ ارْتَفَعَتْ الْأَصْوَاتُ عِنْدَهُ وَكَثُرَ اللَّغْطُ وَأَمَرَ بِنَا فَأُخْرِجْنَا قَالَ فَقُلْتُ لِأَصْحَابِي حِينَ خَرَجْنَا لَقَدْ أَمِرَ أَمْرُ ابْنِ أَبِي كَبْشَةَ إِنَّهُ لَيَخَافُهُ مَلِكُ بَنِي الْأَصْفَرِ قَالَ فَمَا زِلْتُ مُوقِنًا بِأَمْرِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهُ سَيَظْهَرُ حَتَّى أَدْخَلَ اللَّهُ عَلَيَّ الْإِسْلَامَو حَدَّثَنَاه حَسَنٌ الْحُلْوَانِيُّ وَعَبْدُ بْنُ حُمَيْدٍ قَالَا حَدَّثَنَا يَعْقُوبُ وَهُوَ ابْنُ إِبْرَاهِيمَ بْنِ سَعْدٍ حَدَّثَنَا أَبِي عَنْ صَالِحٍ عَنْ ابْنِ شِهَابٍ بِهَذَا الْإِسْنَادِ وَزَادَ فِي الْحَدِيثِ وَكَانَ قَيْصَرُ لَمَّا كَشَفَ اللَّهُ عَنْهُ جُنُودَ فَارِسَ مَشَى مِنْ حِمْصَ إِلَى إِيلِيَاءَ شُكْرًا لِمَا أَبْلَاهُ اللَّهُ وَقَالَ فِي الْحَدِيثِ مِنْ مُحَمَّدٍ عَبْدِ اللَّهِ وَرَسُولِهِ وَقَالَ إِثْمَ الْيَرِيسِيِّينَ وَقَالَ بِدَاعِيَةِ الْإِسْلَامِ","id":"Telah menceritakan kepada kami [Ishaq bin Ibrahim Al Hanzhali] dan [Ibnu Abu Umar] serta [Muhammad bin Rafi'] dan [Abd bin Humaid] sedangkan lafadznya dari Ibnu Rafi', Ibnu Rafi' dan Ibnu Abu Umar mengatakan; telah menceritakan kepada kami, sedangkan yang dua mengatakan; telah mengabarkan kepada kami [Abdurrazaq] telah mengabarkan kepada kami [Ma'mar] dari [Az Zuhri] dari [Ubaidullah bin Abdullah bin 'Utbah] dari [Ibnu Abbas] bahwa [Abu Sufyan] mengisahkan dari mulutnya sendiri sebagai berikut, \"Pada saat berlangsungnya perjanjian damai antara aku dengan Rasulullah shallallahu 'alaihi wasallam, aku pergi berniaga ke negeri Syam. Ketika aku berada di sana, ada seseorang yang mengirim sepucuk surat dari Rasulullah shallallahu 'alaihi wasallam kepada kaisar Heraclius, penguasa agung Rumawi, yang membawa surat itu adalah Dihyah Al Kalbi kepada pembesar Bushra, kemudian pembesar Bushra menyampaikannya kepada Heraclius. Lantas Heraclius bertanya, \"Adakah di sini orang yang berasal dari kaumnya laki-laki yang mengaku sebagai Nabi ini (Rasulullah)? ' mereka menjawab, \"Ya.\" Lalu aku dipanggil untuk menghadap Heraclius bersama beberapa kawanku dari suku Quraisy, kami masuk dan duduk menghadap Hiraclius. Heraclius lantas bertanya, \"Siapakah di antara kalian, yang dekat pertalian darahnya dengan orang yang mendakwakan dirinya menjadi Nabi itu?\" Abu Sufyan berkata, \"Lalu aku menjawab, \"Aku.\" Lalu aku duduk di depan, sedangkan kawan-kawanku duduk di belakangku. Kemudian dia memanggil penerjemahnya, lalu dia berkata kepada penerjemahnya, \"Katakanlah kepada mereka, bahwa aku menanyakan kepada mereka perihal laki-laki yang mendakwakan dirinya sebagai Nabi, jika dia berdusta, katakan dia telah berdusta.\" Abu Sufyan berkata, \"Demi Allah, kalaulah aku tidak takut dicap sebagai pendusta, sungguh telah ku dustai mereka.\" Kemudian Heraclius berkata kepada penerjemahnya, \"Tanyakan kepadanya, bagaimana kebangsaan orang itu di kalanganmu.\" Abu Sufyan berkata, \"Jawabku, \"Dia seorang bangsawan di kalangan kami.\" Dia bertanya, \"Apakah dia keturunan raja?\" aku menjawab, \"Tidak.\" Dia bertanya, \"Pernahkah kalian mengatakannya sebagai pembohong sebelum ia menjadi seorang Nabi?\" Jaawabku, \"Tidak.\" Dia bertanya, \"Apakah orang-orang yang mengikutinya dari kalangan pembesar ataukah hanya rakyat kecil?\" jawabku, \"Hanya rakyat kecil.\" Dia bertanya, \"Apakah pengikutnya selalu bertambah?\" Jawabku, \"Mereka selalu bertambah.\" Dia bertanya, \"Adakah di antara pengikutnya itu murtad karena benci terhadap agama yang dikembangkannya?\" Jawabku, \"Tidak.\" Dia bertanya, \"Apakah kamu berperang melawannya?\" Jawabku, \"Ya, pernah.\" Dia bertanya, \"Bagaimana perjalanan peperanganmu melawannya?\" Jawabku, \"Peperangan kami berjalan silih berganti antara menang dan kalah. Kadang-kadang kamilah yang menang dan dia yang kalah, dan terkadang pula kami yang kalah dan dia yang menang.\" Dia bertanya, \"Apakah dia pernah ingkat janji?\" Jawabku, \"Tidak, bahkan kami sedang dalam masa perjanjian damai, yaitu tidak akan serang menyerang dengannya. Aku tidak tahu apa yang akan dibuatnya terhadap perjanjian tersebut.\" Kata Abu Sufyan selanjutnya, \"Demi Allah, tidak ada kalimat lain yang dapat kami ucapkan selain dari pada itu semua.\" Dia bertanya, \"Apakah ada orang lain sebelum dia, yang mendakwakan dirinya sebagai Nabi seperti dia?\" Jawabku, \"Tidak.\" Kemudian dia berkata kepada penerjemahnya, \"Katakan kepadanya, \"Kutanyakan kepadamu tentang bangsanya (status sosialnya), maka kalian katakan dia termasuk dari bangsawan. Memang demikianlah halnya semua para rasul, mereka dibangkitkan dari kalangan bangsawan kaumnya. Kutanyakan pula kepadamu, apakah dia dari keturunan para raja? Jawabmu 'tidak', kalau sekiranya bapak dan kakeknya yang menjadi raja, tentunya ada sangkaan bahwa dia ingin mengembalikan kekusaan nenek moyangnya. Kutanyakan pula tentang pengikutnya, apakah terdiri dari rakyat kecil atau dari orang-orang besar? Kamu menjawab 'hanya terdiri dari rakyat kecil', memang merekalah pengikut para rasul. Kutanyakan pula, pernahkah kamu menuduhnya sebagai pembohong sebelumnya? Kamu menjawab 'tidak', aku tahu, bahwa dia tidak akan pernah berdusta kepada manusia, apalagi bedusta kepada Allah. Aku tanyakan kepadamu; adakah pengikutnya yang murtad atau mereka membenci agama baru setelah memeluknya? Jawabmu 'tidak', memang begitulah halnya, apabila iman telah tertanam dalam hati seseorang. Aku bertanya kepadamu, apakah pengikutnya berkurang? Jawabmu 'bahkan mereka selalu bertambah', memang seperti itulah iman hingga ia tumbuh sempurna. Kutanya pula, pernahkah kamu memeranginya? Jawabmu 'ya kami memerangi, dan peperangan silih berganti, terkadang menang dan terkadang kalah'. Memang demikianlah halnya, para rasul itu selalu diuji. Namun demikian, kemengangan terakhir selalu dipihak mereka. Kutanyakan pula, pernahkah dia ingkar janji? Jawabmu 'tidak pernah', memang demikian para rasul tidak mungkin ingkar janji. Kutanyakan pula kepadamu, adakah orang lain sebelum dia yang mengaku menjadi Nabi seperti dia? Jawabmu 'tidak', begitulah, kalau ada orang sebelumnya yang mendakwakan dirinya sebagai Nabi seperti dia, mungkin dia hanya ikut-ikutan dengan orang yang sebelumnya.\" Kemudian dia bertanya, \"Apa saja yang diperintahkanya kepadamu?\" Jawabku, \"Dia menyuruh kami shalat, membayar zakat, menjalin tali silaturrahmi dan menjaga kehormatan diri.\" dia berkata, \"Jika yang kamu katakan itu benar semuanya, maka tak salah lagi bahwa lelaki tersebut adalah seorang Nabi, aku tahu bahwa dia akan muncul, akan tetapi aku tidak menduga bahwa dia akan muncul dari kalangan kalian, sekiranya aku dapat bertemu dengannya, saat di sampingnya maka sungguh aku akan membasuh kedua kakinya. Dan daerah kekuasaannya kelak, akan sampai ke daerah kekuasanku ini.\" Abu Sufyan berkata, \"Kemudian dia meminta surat dari Rasulullah shallallahu 'alaihi wasallam dan membacanya, di dalamnya tertulis: \"Dengan nama Allah yang Maha pengasih lagi Maha penyayang, dari Muhammad Rasulullah kepada Heraclius pembesar Rumawi. Keselamatan bagi orang yang mengikuti petunjuk, sesungguhnya aku mengajak anda untuk masuk Islam, masuk Islamlah anda niscaya anda akan selamat. Masuk Islamlah anda, niscaya Allah akan memberi pahala kepada anda dengan berlipat ganda. Jika anda menolak, maka anda akan memikul dosa kaum 'arisyiyun. '(Hai ahli kitab, marilah (berpegang) kepada suatu kalimat (ketetapan) yang tidak ada perselisihan antara kami dan kamu, bahwa kita tidak akan menyembah kecuali Allah dan tidak kita persekutukan dia dengan sesuatupun dan tidak (pula) sebagian kita menjadikan sebagian yang lain sebagai Tuhan selain Allah. jika mereka menolak, maka Katakanlah kepada mereka: \"Saksikanlah, bahwa kami adalah orang-orang yang berserah diri (kepada Allah) ' (Qs. Ali Imran: 64) Setelah dia selesai membaca surat tersebut, tiba-tiba terdengar suara heboh di sekitarnya. Dia memerintahkan kami supaya keluar. Sesampainya di luar, aku berkata kepada kawan-kawanku, \"Sungguh luar biasa urusan Ibnu Abu Kabsyah (maksudnya Rasulullah), hingga dia diikuti oleh raja bani Ashfar (bangsa berkulit kuning), karena itu aku senantiasa yakin bahwa agama Rasulullah shallallahu 'alaihi wasallam ini pasti menang, dan akhirnya Allah memasukkan hidayah Islam ke dalam hati sanubariku.\" Dan telah menceritakan kepada kami [Hasan Al Khulwani] dan [Abd bin Humaid] keduanya berkata; telah menceritakan kepada kami [Ya'qub] -yaitu Ibnu Ibrahim bin Sa'd- telah menceritakan kepada kami [ayahku] dari [Shalih] dari [Ibnu Syihab] dengan isnad ini, dan ia menambahkan dalam haditsnya, \"Setelah Allah memenangkan tentara Persi atasnya, maka Kaisar berjalan kaki dari daerah Himsha hingga Iliya` sebagai bentuk syukur akan ujian Allah.\" Dan dalam hadits itu pula disebutkan, \"Dari Muhammad, seorang hamba Allah dan Rasul-Nya.\" Dan dia juga menyebutkan, \"Dosa kaum Yarisiyin.\" Dan dia menyebutkan, \"Dengan seruan Islam.\""},"3090":{"ar":"حَدَّثَنِي يُوسُفُ بْنُ حَمَّادٍ الْمَعْنِيُّ حَدَّثَنَا عَبْدُ الْأَعْلَى عَنْ سَعِيدٍ عَنْ قَتَادَةَ عَنْ أَنَسٍأَنَّ نَبِيَّ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَتَبَ إِلَى كِسْرَى وَإِلَى قَيْصَرَ وَإِلَى النَّجَاشِيِّ وَإِلَى كُلِّ جَبَّارٍ يَدْعُوهُمْ إِلَى اللَّهِ تَعَالَى وَلَيْسَ بِالنَّجَاشِيِّ الَّذِي صَلَّى عَلَيْهِ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَو حَدَّثَنَاه مُحَمَّدُ بْنُ عَبْدِ اللَّهِ الرُّزِّيُّ حَدَّثَنَا عَبْدُ الْوَهَّابِ بْنُ عَطَاءٍ عَنْ سَعِيدٍ عَنْ قَتَادَةَ حَدَّثَنَا أَنَسُ بْنُ مَالِكٍ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِمِثْلِهِ وَلَمْ يَقُلْ وَلَيْسَ بِالنَّجَاشِيِّ الَّذِي صَلَّى عَلَيْهِ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ و حَدَّثَنِيهِ نَصْرُ بْنُ عَلِيٍّ الْجَهْضَمِيُّ أَخْبَرَنِي أَبِي حَدَّثَنِي خَالِدُ بْنُ قَيْسٍ عَنْ قَتَادَةَ عَنْ أَنَسٍ وَلَمْ يَذْكُرْ وَلَيْسَ بِالنَّجَاشِيِّ الَّذِي صَلَّى عَلَيْهِ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah menceritakan kepadaku [Yusuf bin Hammad Al Ma'ni] telah menceritakan kepada kami [Abdul A'la] dari [Sa'id] dari [Qatadah] dari [Anas], bahwa Nabi shallallahu 'alaihi wasallam pernah mengirim surat kepada Kisra (raja persi), Qaishar (raja Romawi), raja Najasyi, dan kepada semua penguasa diktator. Beliau mengajak mereka untuk beriman kepada Allah Ta'ala. Bukankah raja Najasyi pernah dishalatkan oleh Nabi shallallahu 'alaihi wasallam (ktika wafat)?.\" Dan telah menceritakan kepada kami [Muhammad bin Abdullah Ar Ruzzi] telah menceritakan kepada kami [Abdul Wahhab bin 'Atha] dari [Sa'id] dari [Qatadah], telah menceritakan kepada kami [Anas bin Malik] dari Nabi shallallahu 'alaihi wasallam seperti hadits di atas, namun ia tidak menyebutkan, 'Dan bukankah raja najasyi pernah dishalatkan oleh Nabi shallallahu 'alaihi wasallam? '\" Dan telah menceritakan kepadaku [Nashr bin Ali Al Jahdlami] telah mengabarkan kepadaku [ayahku] telah menceritakan kepadaku [Khalid bin Qais] dari [Qatadah] dari [Anas], dan ia juga tidak menyebutkan, 'Dan bukankah raja Najasyi pernah dishalatkan oleh Nabi shallallahu 'alaihi wasallam? '.\""},"3091":{"ar":"و حَدَّثَنِي أَبُو الطَّاهِرِ أَحْمَدُ بْنُ عَمْرِو بْنِ سَرْحٍ أَخْبَرَنَا ابْنُ وَهْبٍ أَخْبَرَنِي يُونُسُ عَنْ ابْنِ شِهَابٍ قَالَ حَدَّثَنِي كَثِيرُ بْنُ عَبَّاسِ بْنِ عَبْدِ الْمُطَّلِبِ قَالَ قَالَ عَبَّاسٌشَهِدْتُ مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَوْمَ حُنَيْنٍ فَلَزِمْتُ أَنَا وَأَبُو سُفْيَانَ بْنُ الْحَارِثِ بْنِ عَبْدِ الْمُطَّلِبِ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَلَمْ نُفَارِقْهُ وَرَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَلَى بَغْلَةٍ لَهُ بَيْضَاءَ أَهْدَاهَا لَهُ فَرْوَةُ بْنُ نُفَاثَةَ الْجُذَامِيُّ فَلَمَّا الْتَقَى الْمُسْلِمُونَ وَالْكُفَّارُ وَلَّى الْمُسْلِمُونَ مُدْبِرِينَ فَطَفِقَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَرْكُضُ بَغْلَتَهُ قِبَلَ الْكُفَّارِ قَالَ عَبَّاسٌ وَأَنَا آخِذٌ بِلِجَامِ بَغْلَةِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَكُفُّهَا إِرَادَةَ أَنْ لَا تُسْرِعَ وَأَبُو سُفْيَانَ آخِذٌ بِرِكَابِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَيْ عَبَّاسُ نَادِ أَصْحَابَ السَّمُرَةِ فَقَالَ عَبَّاسٌ وَكَانَ رَجُلًا صَيِّتًا فَقُلْتُ بِأَعْلَى صَوْتِي أَيْنَ أَصْحَابُ السَّمُرَةِ قَالَ فَوَاللَّهِ لَكَأَنَّ عَطْفَتَهُمْ حِينَ سَمِعُوا صَوْتِي عَطْفَةُ الْبَقَرِ عَلَى أَوْلَادِهَا فَقَالُوا يَا لَبَّيْكَ يَا لَبَّيْكَ قَالَ فَاقْتَتَلُوا وَالْكُفَّارَ وَالدَّعْوَةُ فِي الْأَنْصَارِ يَقُولُونَ يَا مَعْشَرَ الْأَنْصَارِ يَا مَعْشَرَ الْأَنْصَارِ قَالَ ثُمَّ قُصِرَتْ الدَّعْوَةُ عَلَى بَنِي الْحَارِثِ بْنِ الْخَزْرَجِ فَقَالُوا يَا بَنِي الْحَارِثِ بْنِ الْخَزْرَجِ يَا بَنِي الْحَارِثِ بْنِ الْخَزْرَجِ فَنَظَرَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَهُوَ عَلَى بَغْلَتِهِ كَالْمُتَطَاوِلِ عَلَيْهَا إِلَى قِتَالِهِمْ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ هَذَا حِينَ حَمِيَ الْوَطِيسُ قَالَ ثُمَّ أَخَذَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حَصَيَاتٍ فَرَمَى بِهِنَّ وُجُوهَ الْكُفَّارِ ثُمَّ قَالَ انْهَزَمُوا وَرَبِّ مُحَمَّدٍ قَالَ فَذَهَبْتُ أَنْظُرُ فَإِذَا الْقِتَالُ عَلَى هَيْئَتِهِ فِيمَا أَرَى قَالَ فَوَاللَّهِ مَا هُوَ إِلَّا أَنْ رَمَاهُمْ بِحَصَيَاتِهِ فَمَا زِلْتُ أَرَى حَدَّهُمْ كَلِيلًا وَأَمْرَهُمْ مُدْبِرًاو حَدَّثَنَاه إِسْحَقُ بْنُ إِبْرَاهِيمَ وَمُحَمَّدُ بْنُ رَافِعٍ وَعَبْدُ بْنُ حُمَيْدٍ جَمِيعًا عَنْ عَبْدِ الرَّزَّاقِ أَخْبَرَنَا مَعْمَرٌ عَنْ الزُّهْرِيِّ بِهَذَا الْإِسْنَادِ نَحْوَهُ غَيْرَ أَنَّهُ قَالَ فَرْوَةُ بْنُ نُعَامَةَ الْجُذَامِيُّ وَقَالَ انْهَزَمُوا وَرَبِّ الْكَعْبَةِ انْهَزَمُوا وَرَبِّ الْكَعْبَةِ وَزَادَ فِي الْحَدِيثِ حَتَّى هَزَمَهُمْ اللَّهُ قَالَ وَكَأَنِّي أَنْظُرُ إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَرْكُضُ خَلْفَهُمْ عَلَى بَغْلَتِهِ و حَدَّثَنَاه ابْنُ أَبِي عُمَرَ حَدَّثَنَا سُفْيَانُ بْنُ عُيَيْنَةَ عَنْ الزُّهْرِيِّ قَالَ أَخْبَرَنِي كَثِيرُ بْنُ الْعَبَّاسِ عَنْ أَبِيهِ قَالَ كُنْتُ مَعَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَوْمَ حُنَيْنٍ وَسَاقَ الْحَدِيثَ غَيْرَ أَنَّ حَدِيثَ يُونُسَ وَحَدِيثَ مَعْمَرٍ أَكْثَرُ مِنْهُ وَأَتَمُّ","id":"Dan telah menceritakan kepadaku [Abu At Thahir Ahmad bin 'Amru bin Sarh] telah mengabarkan kepada kami [Ibnu Wahb] telah mengabarkan kepadaku [Yunus] dari [Ibnu Syihab] dia berkata; telah menceritakan kepadaku [Katsir bin Abbas bin Abdul Mutthalib] dia berkata; [Abbas] mengatakan, \"Aku pernah ikut perang Hunain bersama Rasulullah shallallahu 'alaihi wasallam, maka aku dan Abu Sufyan bin Harits bin Abdul Mutthalib selalu mendampingi Rasulullah shallallahu 'alaihi wasallam dan tidak pernah berpisah dengan beliau. Ketika itu Rasulullah shallallahu 'alaihi wasallam mengendarai bighal putih miliknya, hadiah dari Farwah bin Nufatsah Al Judzami. Tatkala kamu Muslimin dan tentara Kafir saling berhadapan, kaum Muslimin mundur ke belakang, karena itu Rasulullah shallallahu 'alaihi wasallam memacu bighalnya ke arah kaum Kufar.\" Abbas mengatakan, \"Namun aku pegangi tali kekang bighal beliau, menahannya jangan sampai ia berlari kencang. Sedangkan Abu Sufyan memegangi pula pelana Rasulullah shallallahu 'alaihi wasallam, maka Rasulullah shallallahu 'alaihi wasallam bersabda: \"Wahai Abbas, serulah regu Samurah!\" Abbas -dia adalah orang yang mempunyai suara yang keras- berkata, \"Lalu aku panggil mereka dengan suaraku yang lantang, 'Manakah regu Samurah…! ' maka demi Allah, alangkah cepatnya mereka datang setelah mendengar panggilanku, bagaikan larinya induk sapi ketika mendengar suara anaknya. Mereka kemudian berkata, \"Ya, kami datang, kami datang.\" Abbas berkata, \"Lalu mereka berperang melawan kaum kafir. Kemudian panggilan tertuju kepada kaum Anshar, \"Wahai kaum Anshar, wahai kaum Anshar!\" Abbas melanjutkan, \"Kemudian seruan dialihkan kepada Bani Harits bin Khazraj, \"Wahai Bani Al Harits bin Khazraj, Wahai Bani Al Harits bin Khazraj!\" Kemudian Rasulullah shallallahu 'alaihi wasallam melihat jalannya pertempuran dari atas bighal beliau, seperti menggelorakan semangat pasukan yang sedang bertempur. Beliau bersabda: \"Beginilah kalau pertempuran sedang berkecamuk.\" Abbas berkata, \"Lalu beliau mengambil beberapa butir kerikil dan melemparkannya ke arah orang-orang kafir sambil bersabda: \"Demi Rabb Muhammad, kalian telah kalah…!\" Abbas berkata, \"Demi Allah, aku menyaksikan jalannya pertempuran, dan tidaklah Rasulullah shallallahu 'alaihi wasallam melempar mereka melainkan beliau melempar dengan beberapa kerikil saja, dan aku terus menyaksikan mereka berangsur-angsur kalah dan lari kocar kacir.\" Dan telah menceritakan kepada kami [Ishaq bin Ibrahim] dan [Muhammad bin Rafi'] serta [Abd bin Humaid] semuanya dari [Abdurrazaq] telah mengabarkan kepada kami [Ma'mar] dari [Az Zuhri] dengan isnad seperti ini, namun dia menyebutkan, \"Farwah bin Nu'amah Al Judzami berkata, \"Beliau bersabda: \"Demi Rabbul Ka'bah, Hancurlah kalian semua.\" Dan dalam hadits ia menambahkan, \"Sehingga Allah menghancurkan mereka.\" Abbas berkata, \"Seakan-akan aku melihat Nabi shallallahu 'alaihi wasallam memberikan semangat (juang) di belakang pasukan dari atas bighalnya.\" Dan telah menceritakan kepada kami [Ibnu Abu Umar] telah menceritakan kepada kami [Sufyan bin 'Uyainah] dari [Az Zuhri] dia berkata; telah mengabarkan kepadaku [Katsir bin Al Abbas] dari [ayahnya] dia berkata, \"Aku pernah bersama Nabi shallallahu 'alaihi wasallam ketika perang Hunain…kemudian dia melanjutkan hadits tersebut, namun dalam hadits Yunus dan haditsnya Ma'mar lebih panjang dan lebih sempurna daripada hadits tersebut.\""},"3092":{"ar":"حَدَّثَنَا يَحْيَى بْنُ يَحْيَى أَخْبَرَنَا أَبُو خَيْثَمَةَ عَنْ أَبِي إِسْحَقَ قَالَقَالَ رَجُلٌ لِلْبَرَاءِ يَا أَبَا عُمَارَةَ أَفَرَرْتُمْ يَوْمَ حُنَيْنٍ قَالَ لَا وَاللَّهِ مَا وَلَّى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَلَكِنَّهُ خَرَجَ شُبَّانُ أَصْحَابِهِ وَأَخِفَّاؤُهُمْ حُسَّرًا لَيْسَ عَلَيْهِمْ سِلَاحٌ أَوْ كَثِيرُ سِلَاحٍ فَلَقُوا قَوْمًا رُمَاةً لَا يَكَادُ يَسْقُطُ لَهُمْ سَهْمٌ جَمْعَ هَوَازِنَ وَبَنِي نَصْرٍ فَرَشَقُوهُمْ رَشْقًا مَا يَكَادُونَ يُخْطِئُونَ فَأَقْبَلُوا هُنَاكَ إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَرَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَلَى بَغْلَتِهِ الْبَيْضَاءِ وَأَبُو سُفْيَانَ بْنُ الْحَارِثِ بْنِ عَبْدِ الْمُطَّلِبِ يَقُودُ بِهِ فَنَزَلَ فَاسْتَنْصَرَ وَقَالَ أَنَا النَّبِيُّ لَا كَذِبْأَنَا ابْنُ عَبْدِ الْمُطَّلِبْثُمَّ صَفَّهُمْ","id":"Telah menceritakan kepada kami [Yahya bin Yahya] telah mengabarkan kepada kami [Abu Khaitsamah] dari [Abu Ishaq] dia berkata; seorang laki-laki bertanya kepada [Barra], \"Wahai Abu 'Umarah, apakah kalian pernah lari dari perang Hunain?\" dia menjawab, \"Tidak, demi Allah (pasukan) Rasulullah shallallahu 'alaihi wasallam tidak pernah lari, namun ketika itu beliau dan beberapa pemuda dari sahabat beliau, serta orang-orang yang ikut bersama beliau, pergi berperang dengan tergesa-gesa tanpa membawa persenjataan dan perlengkapan dengan sempurna. Kebetulan mereka bertemu dengan pasukan pemanah dari pihak musuh, ketika mereka memanah hampir tidak meleset sedikitpun dari sasaran. Yaitu pasukan gabungan Bani Hawazin dan Bani Nashr. Lantas pasukan pemanah itu serta merta memanah mereka (kaum Muslimin) sehingga mereka terpaksa berbalik kepada Rasulullah shallallahu 'alaihi wasallam, sedangkan saat itu Rasulullah shallallahu 'alaihi wasallam berada di atas bighal putih beliau, dan Abu Sufyan bin Harits bin Abdul Mutthalib mengawal beliau. Kemudian beliau turun dari bighal beliau dan memohon pertolongan kepada Allah, beliau bersabda: \"Aku adalah seorang Nabi, bukan seorang pendusta, aku adalah putra Ibnu Abdul Mutthalib.\" Setelah itu beliau merapikan barisan mereka. "},"3093":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ جَنَابٍ الْمِصِّيصِيُّ حَدَّثَنَا عِيسَى بْنُ يُونُسَ عَنْ زَكَرِيَّاءَ عَنْ أَبِي إِسْحَقَ قَالَجَاءَ رَجُلٌ إِلَى الْبَرَاءِ فَقَالَ أَكُنْتُمْ وَلَّيْتُمْ يَوْمَ حُنَيْنٍ يَا أَبَا عُمَارَةَ فَقَالَ أَشْهَدُ عَلَى نَبِيِّ اللَّهِ ��َلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَا وَلَّى وَلَكِنَّهُ انْطَلَقَ أَخِفَّاءُ مِنْ النَّاسِ وَحُسَّرٌ إِلَى هَذَا الْحَيِّ مِنْ هَوَازِنَ وَهُمْ قَوْمٌ رُمَاةٌ فَرَمَوْهُمْ بِرِشْقٍ مِنْ نَبْلٍ كَأَنَّهَا رِجْلٌ مِنْ جَرَادٍ فَانْكَشَفُوا فَأَقْبَلَ الْقَوْمُ إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَأَبُو سُفْيَانَ بْنُ الْحَارِثِ يَقُودُ بِهِ بَغْلَتَهُ فَنَزَلَ وَدَعَا وَاسْتَنْصَرَ وَهُوَ يَقُولُ أَنَا النَّبِيُّ لَا كَذِبْأَنَا ابْنُ عَبْدِ الْمُطَّلِبْاللَّهُمَّ نَزِّلْ نَصْرَكَ قَالَ الْبَرَاءُ كُنَّا وَاللَّهِ إِذَا احْمَرَّ الْبَأْسُ نَتَّقِي بِهِ وَإِنَّ الشُّجَاعَ مِنَّا لَلَّذِي يُحَاذِي بِهِ يَعْنِي النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah menceritakan kepada kami [Ahmad bin Jannab Al Mishishi] telah menceritakan kepada kami [Isa bin Yunus] dari [Zakaria] dari [Abu Ishaq] dia berkata, \"Seorang laki-laki datang kepada [Al Barra] seraya bertanya, \"Wahai Abu 'Umarah, apakah kalian pernah lari dari peperangan Hunain?\" maka dia menjawab, \"Aku bersaksi atas Nabi Allah shallallahu 'alaihi wasallam, (pasukan) beliau tidaklah lari, akan tetapi saat itu orang-orang (yang ikut serta) tergesa-gesa tanpa membawa persenjataan yang lengkap menuju perkampungan Bani Hawazin ini, padahal mereka adalah pasukan pemanah, lantas orang-orang kafir melemparinya dengan anak panah, seakan-akan mereka (kaum Muslimin) seperti sekumpulan belalang. Sehingga kaum Muslimin pun kocar-kacir dan terpaksa berbalik kepada Rasulullah shallallahu 'alaihi wasallam, sementara itu Abu Sufyan sedang mengawal dengan memegang bighal beliau. Kemudian beliau turun dan berdo'a dengan memohon pertolongan, beliau bersabda: \"Aku adalah seorang Nabi, tidak seorang pendusta, aku adalah putra Abdul Mutthalib. Ya Allah…turunkanlah bala bantuan-Mu.\" Barra berkata, \"Demi Allah, kami saat itu sangat mengkhawatirkan karena dahsyatnya peperangan, dan orang yang paling pemberani adalah orang yang paling dekat dengan peperangan, yaitu Nabi shallallahu 'alaihi wasallam.\""},"3094":{"ar":"و حَدَّثَنَا مُحَمَّدُ بْنُ الْمُثَنَّى وَابْنُ بَشَّارٍ وَاللَّفْظُ لِابْنِ الْمُثَنَّى قَالَا حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ حَدَّثَنَا شُعْبَةُ عَنْ أَبِي إِسْحَقَ قَالَسَمِعْتُ الْبَرَاءَ وَسَأَلَهُ رَجُلٌ مِنْ قَيْسٍ أَفَرَرْتُمْ عَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَوْمَ حُنَيْنٍ فَقَالَ الْبَرَاءُ وَلَكِنْ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَمْ يَفِرَّ وَكَانَتْ هَوَازِنُ يَوْمَئِذٍ رُمَاةً وَإِنَّا لَمَّا حَمَلْنَا عَلَيْهِمْ انْكَشَفُوا فَأَكْبَبْنَا عَلَى الْغَنَائِمِ فَاسْتَقْبَلُونَا بِالسِّهَامِ وَلَقَدْ رَأَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَلَى بَغْلَتِهِ الْبَيْضَاءِ وَإِنَّ أَبَا سُفْيَانَ بْنَ الْحَارِثِ آخِذٌ بِلِجَامِهَا وَهُوَ يَقُولُ أَنَا النَّبِيُّ لَا كَذِبْأَنَا ابْنُ عَبْدِ الْمُطَّلِبْو حَدَّثَنِي زُهَيْرُ بْنُ حَرْبٍ وَمُحَمَّدُ بْنُ الْمُثَنَّى وَأَبُو بَكْرِ بْنُ خَلَّادٍ قَالُوا حَدَّثَنَا يَحْيَى بْنُ سَعِيدٍ عَنْ سُفْيَانَ قَالَ حَدَّثَنِي أَبُو إِسْحَقَ عَنْ الْبَرَاءِ قَالَ قَالَ لَهُ رَجُلٌ يَا أَبَا عُمَارَةَ فَذَكَرَ الْحَدِيثَ وَهُوَ أَقَلُّ مِنْ حَدِيثِهِمْ وَهَؤُلَاءِ أَتَمُّ حَدِيثًا","id":"Dan telah menceritakan kepada kami [Muhammad bin Al Mutsanna] dan [Ibnu Basyar] sedangkan lafadznya dari Ibnu Mutsanna, keduanya berkata; telah menceritakan kepada kami [Muhammad bin Ja'far] telah menceritakan kepada kami [Syu'bah] dari [Abu Ishaq] dia berkata; aku mendengar? [Al Barra] ditanya oleh seorang laki-laki dari Qais, \"Apakah kalian pernah lari dari Rasulullah shallallahu 'alaihi wasallam pada waktu peperangan Hunain?\" Al Barra menjawab, \"(pasukan) Rasulullah shallallahu 'alaihi wasallam tidaklah lari dari peperangan, ketika itu Bani Hawazin memiliki sekelompok ahli pemanah. Dan ketika kami menyerang mereka, mereka lari kocar kacir sehingga kami berdesak-desakan untuk mengambil ghanimah, tidak lama setelah itu mereka mengadakan serangan balik dengan melempari anak panah kepada kami, sungguh saat itu aku melihat Rasulullah shallallahu 'alaihi wasallam berada di atas bighal putihnya, sedangkan Abu Sufyan bin Harits memegang tali kekangnya. Beliau bersabda: \"Aku adalah seorang Nabi, bukan seorang pendusta, aku adalah putra Abdul Mutthalib.\" Dan telah menceritakan kepadaku [Zuhair bin Harb] dan [Muhammad bin Al Mutsanna] serta [Abu Bakar bin Khallad] mereka berkata; telah menceritakan kepada kami [Yahya bin Sa'id] dari [Sufyan] dia berkata; telah menceritakan kepadaku [Abu Ishaq] dari [Al Barra] dia berkata, \"Seorang laki-laki pernah bertanya kepadanya, \"Wahai Abu 'Umarah…kemudian dia menyebutkan hadits tersebut, sedangkan hadits mereka lebih sempurna daripada haditnya dia.\""},"3095":{"ar":"و حَدَّثَنَا زُهَيْرُ بْنُ حَرْبٍ حَدَّثَنَا عُمَرُ بْنُ يُونُسَ الْحَنَفِيُّ حَدَّثَنَا عِكْرِمَةُ بْنُ عَمَّارٍ حَدَّثَنِي إِيَاسُ بْنُ سَلَمَةَ حَدَّثَنِي أَبِي قَالَغَزَوْنَا مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حُنَيْنًا فَلَمَّا وَاجَهْنَا الْعَدُوَّ تَقَدَّمْتُ فَأَعْلُو ثَنِيَّةً فَاسْتَقْبَلَنِي رَجُلٌ مِنْ الْعَدُوِّ فَأَرْمِيهِ بِسَهْمٍ فَتَوَارَى عَنِّي فَمَا دَرَيْتُ مَا صَنَعَ وَنَظَرْتُ إِلَى الْقَوْمِ فَإِذَا هُمْ قَدْ طَلَعُوا مِنْ ثَنِيَّةٍ أُخْرَى فَالْتَقَوْا هُمْ وَصَحَابَةُ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَوَلَّى صَحَابَةُ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَأَرْجِعُ مُنْهَزِمًا وَعَلَيَّ بُرْدَتَانِ مُتَّزِرًا بِإِحْدَاهُمَا مُرْتَدِيًا بِالْأُخْرَى فَاسْتَطْلَقَ إِزَارِي فَجَمَعْتُهُمَا جَمِيعًا وَمَرَرْتُ عَلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مُنْهَزِمًا وَهُوَ عَلَى بَغْلَتِهِ الشَّهْبَاءِ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَقَدْ رَأَى ابْنُ الْأَكْوَعِ فَزَعًا فَلَمَّا غَشُوا رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَزَلَ عَنْ الْبَغْلَةِ ثُمَّ قَبَضَ قَبْضَةً مِنْ تُرَابٍ مِنْ الْأَرْضِ ثُمَّ اسْتَقْبَلَ بِهِ وُجُوهَهُمْ فَقَالَ شَاهَتْ الْوُجُوهُ فَمَا خَلَقَ اللَّهُ مِنْهُمْ إِنْسَانًا إِلَّا مَلَأَ عَيْنَيْهِ تُرَابًا بِتِلْكَ الْقَبْضَةِ فَوَلَّوْا مُدْبِرِينَ فَهَزَمَهُمْ اللَّهُ عَزَّ وَجَلَّ وَقَسَمَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ غَنَائِمَهُمْ بَيْنَ الْمُسْلِمِينَ","id":"Telah menceritakan kepada kami [Zuhair bin Harb] telah menceritakan kepada kami ['Umar bin Yunus Al Hanafi] telah menceritakan kepada kami [Ikrimah bin 'Ammar] telah menceritakan kepadaku [Iyas bin Salamah] telah menceritakan kepadaku [ayahku] dia berkata, \"Kami pernah ikut perang Hunain bersama Rasulullah shallallahu 'alaihi wasallam. Ketika kami telah berhadapan dengan musuh, aku maju lebih dahulu dengan mendaki bukit, tiba-tiba aku bertemu dengan seorang musuh lalu ku panah dia dengan panahku, tetapi dia menghilang seketika sehingga aku tidak tahu apa yang sedang dibuatnya. Ketika aku melihat musuh, ternyata mereka telah berada di atas bukit yang lain. Lalu mereka bertempur dengan para sahabat Nabi shallallahu 'alaihi wasallam. Para sahabat mundur dan aku juga ikut mundur dengan kocar kacir. Sa'at itu aku mengenakan dua kain burdah, yang satu kupakai sebagai sarung dan yang lain aku selempangkan. Tiba-tiba sarungku lepas, lalu aku ikatkan dua kain tersebut menjadi satu. Aku lewat di hadapan Rasulullah shallallahu 'alaihi wasallam sambil berlari, sedangkan beliau berada di atas bighal putihnya, Rasulullah shallallahu 'alaihi wasallam bersabda: \"Rupanya Ibnu Akwa' melihat sesuatu yang menakutkan.\" Tatkala Rasulullah shallallahu 'alaihi wasallam terkepung, beliau turun dari bighalnya, kemudian beliau mengambil segenggam tanah dan melemparkannya ke arah musuh sambil bersabda: \"Muka-muka buruk.\" Maka tidaklah Allah menyisakan dari mereka melainkan wajah-wajah mereka telah dipenuhi dengan segenggam tanah. Lalu mereka lari tunggang langgang. Allah Azza Wa Jalla telah mengalahkan mereka. Kemudian Rasulullah shallallahu 'alaihi wasallam membagikan ghanimah kepada kaum Muslimin.\""},"3096":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ وَزُهَيْرُ بْنُ حَرْبٍ وَابْنُ نُمَيْرٍ جَمِيعًا عَنْ سُفْيَانَ قَالَ زُهَيْرٌ حَدَّثَنَا سُفْيَانُ بْنُ عُيَيْنَةَ عَنْ عَمْرٍو عَنْ أَبِي الْعَبَّاسِ الشَّاعِرِ الْأَعْمَى عَنْ عَبْدِ اللَّهِ بْنِ عَمْرٍو قَالَحَاصَرَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَهْلَ الطَّائِفِ فَلَمْ يَنَلْ مِنْهُمْ شَيْئًا فَقَالَ إِنَّا قَافِلُونَ إِنْ شَاءَ اللَّهُ قَالَ أَصْحَابُهُ نَرْجِعُ وَلَمْ نَفْتَتِحْهُ فَقَالَ لَهُمْ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ اغْدُوا عَلَى الْقِتَالِ فَغَدَوْا عَلَيْهِ فَأَصَابَهُمْ جِرَاحٌ فَقَالَ لَهُمْ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّا قَافِلُونَ غَدًا قَالَ فَأَعْجَبَهُمْ ذَلِكَ فَضَحِكَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] dan [Zuhair bin Harb] serta [Ibnu Numair] semuanya dari [Sufyan], [Zuhair] berkata; telah menceritakan kepada kami [Sufyan bin 'Uyainah] dari ['Amru] dari [Abu Al Abbas Asy Sya'ir Al A'ma] dari [Abdullah bin 'Amru] dia berkata, \"Rasulullah shallallahu 'alaihi wasallam pernah mengepung penduduk Tha`if, namun beliau tidak mendapatkan sesuatupun dari mereka.\" Lalu beliau bersabda: \"Insya Allah besok kita akan kembali pulang.\" Para sahabat bertanya, \"Apakah kita akan kembali padahal kita belum menaklukkan sesuatu pun?\" Rasulullah shallallahu 'alaihi wasallam bersabda kepada mereka: \"Kalau begitu, pergilah kalian besok pagi untuk memerangi mereka.\" Keesokan harinya mereka berangkat perang sehingga mereka banyak yang terluka. Lantas Rasulullah shallallahu 'alaihi wasallam bersabda kepada mereka: \"Besok kita akan kembali pulang.\" Abdullah bin 'Amru berkata, \"Merekapun merasa heran dengan hal itu. Kemudian Rasulullah shallallahu 'alaihi wasallam tertawa.\""},"3097":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا عَفَّانُ حَدَّثَنَا حَمَّادُ بْنُ سَلَمَةَ عَنْ ثَابِتٍ عَنْ أَنَسٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ شَاوَرَ حِينَ بَلَغَهُ إِقْبَالُ أَبِي سُفْيَانَ قَالَ فَتَكَلَّمَ أَبُو بَكْرٍ فَأَعْرَضَ عَنْهُ ثُمَّ تَكَلَّمَ عُمَرُ فَأَعْرَضَ عَنْهُ فَقَامَ سَعْدُ بْنُ عُبَادَةَ فَقَالَ إِيَّانَا تُرِيدُ يَا رَسُولَ اللَّهِ وَالَّذِي نَفْسِي بِيَدِهِ لَوْ أَمَرْتَنَا أَنْ نُخِيضَهَا الْبَحْرَ لَأَخَضْنَاهَا وَلَوْ أَمَرْتَنَا أَنْ نَضْرِبَ أَكْبَادَهَا إِلَى بَرْكِ الْغِمَادِ لَفَعَلْنَا قَالَ فَنَدَبَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ النَّاسَ فَانْطَلَقُوا حَتَّى نَزَلُوا بَدْرًا وَوَرَدَتْ عَلَيْهِمْ رَوَايَا قُرَيْشٍ وَفِيهِمْ غُلَامٌ أَسْوَدُ لِبَنِي الْحَجَّاجِ فَأَخَذُوهُ فَكَانَ أَصْحَابُ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَسْأَلُونَهُ عَنْ أَبِي سُفْيَانَ وَأَصْحَابِهِ فَيَقُولُ مَا لِي عِلْمٌ بِأَبِي سُفْيَانَ وَلَكِنْ هَذَا أَبُو جَهْلٍ وَعُتْبَةُ وَشَيْبَةُ وَأُمَيَّةُ بْنُ خَلَفٍ فَإِذَا قَالَ ذَلِكَ ضَرَبُوهُ فَقَالَ نَعَمْ أَنَا أُخْبِرُكُمْ هَذَا أَبُو سُفْيَانَ فَإِذَا تَرَكُوهُ فَسَأَلُوهُ فَقَالَ مَا لِي بِأَبِي سُفْيَانَ عِلْمٌ وَلَكِنْ هَذَا أَبُو جَهْلٍ وَعُتْبَةُ وَشَيْبَةُ وَأُمَيَّةُ بْنُ خَلَفٍ فِي النَّاسِ فَإِذَا قَالَ هَذَا أَيْضًا ضَرَبُوهُ وَرَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَائِمٌ يُصَلِّي فَلَمَّا رَأَى ذَلِكَ انْصَرَفَ قَالَ وَالَّذِي نَفْسِي بِيَدِهِ لَتَضْرِبُوهُ إِذَا صَدَقَكُمْ وَتَتْرُكُوهُ إِذَا كَذَبَكُمْ قَالَ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ هَذَا مَصْرَعُ فُلَانٍ قَالَ وَيَضَعُ يَدَهُ عَلَى الْأَرْضِ هَاهُنَا هَاهُنَا قَالَ فَمَا مَاطَ أَحَدُهُمْ عَنْ مَوْضِعِ يَدِ رَسُولِ اللَّهِ صَل��َى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] telah menceritakan kepada kami ['Affan] telah menceritakan kepada kami [Hammad bin Salamah] dari [Tsabit] dari [Anas], bahwa Rasulullah shallallahu 'alaihi wasallam mengadakan musywarah ketika sampai kepada beliau kabar mengenai kedatangan kafilah Abu Sufyan. Anas berkata, \"Maka Abu Bakar berbicara, namun beliau tidak memperdulikannya, kemudian Umar angkat bicara, dan beliau pun tidak memperdulikannya, lantas Sa'd bin Ubadah berdiri sambil berkata, \"Kamikah yang anda kehendaki wahai Rasulullah, demi Allah yang jiwaku berada di tangan-Nya, seandainya anda memerintahkan kami mengarungi lautan, pasti akan kami arungi, dan seandainya anda memerintahkan kami pergi ke ujung bumi, pasti kami akan pergi.\" Anas melanjutkan, \"Kemudian Rasulullah shallallahu 'alaihi wasallam mengajak orang-orang untuk berkumpul, setelah itu mereka berangkat hingga sampai Badar. Di sana mereka bertemu dengan para pencari air untuk orang-orang Quraisy. Di antara mereka terdapat seorang budak hitam kepunyaan Bani Hajjaj, kemudian mereka mengangkapnya. Lantas para sahabat Rasulullah shallallahu 'alaihi wasallam mengintrogasinya perihal Abu Sufyan dan pasukannya. Dia menjawab, \"Aku tidak tahu perihal Abu Sufyan, tetapi yang aku tahu adalah Abu Jahal, 'Utbah, Syaibah dan Umayyah bin Khalaf bersama dengan rombongan manusia (tentara).\" Setiap kali ia mengatakan hal yang serupa, maka mereka memukulinya, hingga ia berkata, \"Ya, aku memberitahukan kepada kalian, Abu Sufyan juga ada.\" Kemudian mereka membiarkan budak tersebut, tidak lama setelah itu mereka tanya kembali perihal Abu Sufyan, lalu dia menjawab, \"Aku tidak tahu dimana Abu Sufyan, yang ada adalah Abu Jahal, 'Utbah, Syaibah dan Umayyah bin Khalaf bersama dengan rombongan manusia (tentara).\" Setiap kali ia menjawab seperti itu, maka mereka memukuli budak tersebut.\" Saat itu Rasulullah shallallahu 'alaihi wasallam sedang berdiri menunaikan shalat, ketika selesai shalat dan beliau melihat peristiwa itu, beliau bersabda: \"Demi jiwaku yang berada di tangan-Nya, mengapa kalian memukulnya jika dia berkata benar, dan kalian biarkan jika ia berdusta?\" Selanjutnya Rasulullah shallallahu 'alaihi wasallam bersabda: \"Di situlah tempat terbunuhnya si fulan -sambil menunjukkan ke tanah- di sini, dan di sini.\" Anas berkata, \"Dan tidak satupun tempat-tempat yang di tunjukkan beliau itu berjauhan dengan tempat tewasnya orang-orang yang ditunjukkan dengan tangan Rasulullah shallallahu 'alaihi wasallam.\""},"3098":{"ar":"حَدَّثَنَا شَيْبَانُ بْنُ فَرُّوخَ حَدَّثَنَا سُلَيْمَانُ بْنُ الْمُغِيرَةِ حَدَّثَنَا ثَابِتٌ الْبُنَانِيُّ عَنْ عَبْدِ اللَّهِ بْنِ رَبَاحٍ عَنْ أَبِي هُرَيْرَةَ قَالَ وَفَدَتْ وُفُودٌ إِلَى مُعَاوِيَةَ وَذَلِكَ فِي رَمَضَانَ فَكَانَ يَصْنَعُ بَعْضُنَا لِبَعْضٍ الطَّعَامَ فَكَانَ أَبُو هُرَيْرَةَ مِمَّا يُكْثِرُ أَنْ يَدْعُوَنَا إِلَى رَحْلِهِ فَقُلْتُ أَلَا أَصْنَعُ طَعَامًا فَأَدْعُوَهُمْ إِلَى رَحْلِي فَأَمَرْتُ بِطَعَامٍ يُصْنَعُ ثُمَّ لَقِيتُ أَبَا هُرَيْرَةَ مِنْ الْعَشِيِّ فَقُلْتُ الدَّعْوَةُ عِنْدِي اللَّيْلَةَ فَقَالَ سَبَقْتَنِي قُلْتُ نَعَمْ فَدَعَوْتُهُمْفَقَالَ أَبُو هُرَيْرَةَ أَلَا أُعْلِمُكُمْ بِحَدِيثٍ مِنْ حَدِيثِكُمْ يَا مَعْشَرَ الْأَنْصَارِ ثُمَّ ذَكَرَ فَتْحَ مَكَّةَ فَقَالَ أَقْبَلَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حَتَّى قَدِمَ مَكَّةَ فَبَعَثَ الزُّبَيْرَ عَلَى إِحْدَى الْمُجَنِّبَتَيْنِ وَبَعَثَ خَالِدًا عَلَى الْمُجَنِّبَةِ الْأُخْرَى وَبَعَثَ أَبَا عُبَيْدَةَ عَلَى الْحُسَّرِ فَأَخَذُوا بَطْنَ الْوَادِي وَرَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي كَتِيبَةٍ قَالَ فَنَظَرَ فَرَآنِي فَقَالَ أَبُو هُرَيْرَةَ قُلْتُ لَبَّيْكَ يَا رَسُولَ اللَّهِ فَقَالَ لَا يَأْتِينِي إِلَّا أَنْصَارِيٌّ زَادَ غَيْرُ شَيْبَانَ فَقَالَ اهْتِفْ لِي بِالْأَنْصَارِ قَالَ فَأَطَافُوا بِهِ وَوَبَّشَتْ قُرَيْشٌ أَوْبَاشًا لَهَا وَأَتْبَاعًا فَقَالُوا نُقَدِّمُ هَؤُلَاءِ فَإِنْ كَانَ لَهُمْ شَيْءٌ كُنَّا مَعَهُمْ وَإِنْ أُصِيبُوا أَعْطَيْنَا الَّذِي سُئِلْنَا فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ تَرَوْنَ إِلَى أَوْبَاشِ قُرَيْشٍ وَأَتْبَاعِهِمْ ثُمَّ قَالَ بِيَدَيْهِ إِحْدَاهُمَا عَلَى الْأُخْرَى ثُمَّ قَالَ حَتَّى تُوَافُونِي بِالصَّفَا قَالَ فَانْطَلَقْنَا فَمَا شَاءَ أَحَدٌ مِنَّا أَنْ يَقْتُلَ أَحَدًا إِلَّا قَتَلَهُ وَمَا أَحَدٌ مِنْهُمْ يُوَجِّهُ إِلَيْنَا شَيْئًا قَالَ فَجَاءَ أَبُو سُفْيَانَ فَقَالَ يَا رَسُولَ اللَّهِ أُبِيحَتْ خَضْرَاءُ قُرَيْشٍ لَا قُرَيْشَ بَعْدَ الْيَوْمِ ثُمَّ قَالَ مَنْ دَخَلَ دَارَ أَبِي سُفْيَانَ فَهُوَ آمِنٌ فَقَالَتْ الْأَنْصَارُ بَعْضُهُمْ لِبَعْضٍ أَمَّا الرَّجُلُ فَأَدْرَكَتْهُ رَغْبَةٌ فِي قَرْيَتِهِ وَرَأْفَةٌ بِعَشِيرَتِهِ قَالَ أَبُو هُرَيْرَةَ وَجَاءَ الْوَحْيُ وَكَانَ إِذَا جَاءَ الْوَحْيُ لَا يَخْفَى عَلَيْنَا فَإِذَا جَاءَ فَلَيْسَ أَحَدٌ يَرْفَعُ طَرْفَهُ إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حَتَّى يَنْقَضِيَ الْوَحْيُ فَلَمَّا انْقَضَى الْوَحْيُ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَا مَعْشَرَ الْأَنْصَارِ قَالُوا لَبَّيْكَ يَا رَسُولَ اللَّهِ قَالَ قُلْتُمْ أَمَّا الرَّجُلُ فَأَدْرَكَتْهُ رَغْبَةٌ فِي قَرْيَتِهِ قَالُوا قَدْ كَانَ ذَاكَ قَالَ كَلَّا إِنِّي عَبْدُ اللَّهِ وَرَسُولُهُ هَاجَرْتُ إِلَى اللَّهِ وَإِلَيْكُمْ وَالْمَحْيَا مَحْيَاكُمْ وَالْمَمَاتُ مَمَاتُكُمْ فَأَقْبَلُوا إِلَيْهِ يَبْكُونَ وَيَقُولُونَ وَاللَّهِ مَا قُلْنَا الَّذِي قُلْنَا إِلَّا الضِّنَّ بِاللَّهِ وَبِرَسُولِهِ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّ اللَّهَ وَرَسُولَهُ يُصَدِّقَانِكُمْ وَيَعْذِرَانِكُمْ قَالَ فَأَقْبَلَ النَّاسُ إِلَى دَارِ أَبِي سُفْيَانَ وَأَغْلَقَ النَّاسُ أَبْوَابَهُمْ قَالَ وَأَقْبَلَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حَتَّى أَقْبَلَ إِلَى الْحَجَرِ فَاسْتَلَمَهُ ثُمَّ طَافَ بِالْبَيْتِ قَالَ فَأَتَى عَلَى صَنَمٍ إِلَى جَنْبِ الْبَيْتِ كَانُوا يَعْبُدُونَهُ قَالَ وَفِي يَدِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَوْسٌ وَهُوَ آخِذٌ بِسِيَةِ الْقَوْسِ فَلَمَّا أَتَى عَلَى الصَّنَمِ جَعَلَ يَطْعُنُهُ فِي عَيْنِهِ وَيَقُولُ{ جَاءَ الْحَقُّ وَزَهَقَ الْبَاطِلُ }فَلَمَّا فَرَغَ مِنْ طَوَافِهِ أَتَى الصَّفَا فَعَلَا عَلَيْهِ حَتَّى نَظَرَ إِلَى الْبَيْتِ وَرَفَعَ يَدَيْهِ فَجَعَلَ يَحْمَدُ اللَّهَ وَيَدْعُو بِمَا شَاءَ أَنْ يَدْعُوَو حَدَّثَنِيهِ عَبْدُ اللَّهِ بْنُ هَاشِمٍ حَدَّثَنَا بَهْزٌ حَدَّثَنَا سُلَيْمَانُ بْنُ الْمُغِيرَةِ بِهَذَا الْإِسْنَادِ وَزَادَ فِي الْحَدِيثِ ثُمَّ قَالَ بِيَدَيْهِ إِحْدَاهُمَا عَلَى الْأُخْرَى احْصُدُوهُمْ حَصْدًا وَقَالَ فِي الْحَدِيثِ قَالُوا قُلْنَا ذَاكَ يَا رَسُولَ اللَّهِ قَالَ فَمَا اسْمِي إِذًا كَلَّا إِنِّي عَبْدُ اللَّهِ وَرَسُولُهُ","id":"Telah menceritakan kepada kami [Syaiban bin Farruh] telah menceritakan kepada kami [Sulaiman bin Al Mughirah] telah menceritakan kepada kami [Tsabit Al Bunani] dari [Abdullah bin Rabbah] dari [Abu Hurairah] dia berkata, \"Suatu delegasi datang kepada Mu'awiyah di bulan Ramadan, oleh karena itu sebagian kami sibuk membuat makanan untuk sebagian yang lain, di antaranya terdapat Abu Hurairah yang sering mengajak kami ke tempatnya (rumahnya), lalu aku berkata kepadanya, \"Tidak layakkah jika aku membuat makanan lalu aku undang mereka untuk makan-makan di rumahku?\" lalu aku menyuruh (keluargaku) untuk membuatkan makanan.\" Di petang harinya, aku menemui Abu Hurairah, kukatakan padanya, \"Sekarang makan malam di rumahku.\" Abu Hurairah menjawab, \"Kamu telah mendahuluiku.\" Aku berkata; \"Ya, aku mendahuluimu, dan juga mengundang mereka semua.\" Setelah itu, Abu Hurairah berkata; \"Sukakah jika aku ceritakan kepada kalian suatu peristiwa mengenai diri kalian wahai orang-orang Anshar?\" kemudian dia menyebutkan seputar penaklukan kota Makkah, katanya, \"Saat itu Rasulullah shallallahu 'alaihi wasallam berangkat hingga beliau tiba di Makkah. Lantas beliau mengangkat Zubair mengepalai satu sayap (pasukan), Khalid pada sayap yang lain, dan mengangkat Abu 'Ubaidah mengepalai pasukan yang tidak mengenakan baju besi. Mereka masuk ke dalam lembah, sedangkan Rasulullah shallallahu 'alaihi wasallam dalam satu regu.\" Abu Hurairah berkata, \"Lalu beliau melihatku seraya bersabda: \"Wahai Abu Hurairah.\" Jawabku, \"Ya wahai Rasulullah!.\" Beliau bersabda: \"Jangan perbolehkan orang-orang mendekat kepadaku selain orang-orang Anshar.\" -beliau menambahkan- \"Kecuali Syaiban.\" Beliau melanjutkan: \"Suruh orang-orang Anshar mendekat kepadaku.\" Abu Hurairah melanjutkan, \"Mereka segera berkumpul di sekeliling beliau, sedangkan orang-orang Quraisy juga telah menyusun barisan dalam beberapa pasukan. Kata orang-orang Quraisy, \"Biarkan mereka mendahului kita, jika mereka beruntung, maka kita sama-sama dengan mereka, namun jika mereka membahayakan, maka kita berikan kepada mereka apa yang dimintanya.\" Rasulullah shallallahu 'alaihi wasallam bersabda: \"Kalian lihatlah pasukan Quraisy dan pengikut-pengikut mereka!\" kemudian beliau memberi isyarat dengan kedua tangannya, yang satu di atas yang lain (maksudnya supaya waspada dan saling melindungi), kemudian beliau bersabda lagi: \"Sampai berjumpa di Shaffa.\" Abu Hurairah berkata, \"Kami terus berjalan, dan tidak seorang pun di antara kami yang membunuh, kecuali jika seorang Quraisy itu membunuh.\" Ternyata tidak ada perlawanan yang ditujukan kepada kami. Kemudian Abu Sufyan datang sembari berkata, \"Wahai Rasulullah, jikalau orang-orang Quraisy dibunuhi, maka tidak akan ada lagi orang-orang Quraisy sesudah ini.\" (artinya; orang-orang Quraisy menyerah kalah tanpa pertumpahan darah), maka beliau bersabda: \"Siapa yang masuk ke rumah Abu Sufyan, dia akan aman.\" Maka orang-orang Anshar berkata sesama mereka, \"Agaknya laki-laki ini, telah dipengaruhi perasaan rindu kepada kampung halamannya sehingga timbul rasa kasih terhadap sanak familinya.\" Abu Hurairah berkata, \"Ketika itu wahyu turun. Kalau wahyu turun, tidak seorang pun dari kami yang memandang Rasulullah shallallahu 'alaihi wasallam hingga wahyu selesai turun. Ketika wahyu selesai turun, Rasulullah shallallahu 'alaihi wasallam bersabda: \"Wahai kaum Anshar!\" Mereka menjawab, \"Kami wahai Rasulullah?\" beliau bersabda: \"Kaliankah yang berkata bahwa laki-laki ini, agaknya telah dipengaruhi perasaan rindu dengan kampung halamanya?\" mereka menjawab, \"Batul\" Beliau bersabda: \"Sekali-kali tidak, aku adalah hamba Allah dan Rasul-Nya. Aku telah hijrah kepada Allah dan kepada kalian semua, hijdup dan matiku juga bersama kalian.\" Setelah mendengar itu mereka datang menghampiri beliau sambil menagis dan berkata, \"Demi Allah, kami tidak mengatakan seperti itu melainkan kami iri dengan Allah dan Rasul-Nya.\" Maka Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sesungguhnya Allah dan Rasul-Nya membenarkan pengakuan kalian semua dan memaafkan kalian.\" Abu Hurairah berkata, \"Kemudian orang-orang (penduduk Makkah) berdatangan ke rumah Abu Sufyan, dan mereka menutup pintu rumah mereka. Lantas Rasulullah shallallahu 'alaihi wasallam berjalan hingga tiba di Hajar Aswad dan menciumnya, setelah itu beliau thawaf mengelilingi Ka'bah. Abu Hurairah berkata, \"Beliau juga mendatangi berhala sesembahan orang-orang Quraisy yang terletak di sekitar Ka'bah, lalu beliau tusuk matanya dengan busur panah yang ada di tangan beliau sambil bersabda: \"Telah datang kebenaran, dan lenyaplah kebatilan.\" Setelah selesai thawaf, beliau menuju bukit shafa lalu naik ke puncaknya. Sesampainya di atas, beliau memandang ke Ka'bah, kemudian beliau mengangkat kedua tangannya sambil memuji Allah dan berdo'a dengan do'a yang beliau kehendaki.\" Dan telah menceritakan kepadaku [Abdullah bin Hasyim] telah menceritakan kepada kami [Bahz] telah menceritakan kepada kami [Sulaiman bin Al Mughirah] dengan isnad seperti ini, dan dalam haditsnya ia menambahkan, \"kemudian beliau mengisyaratkan dengan kedua tangannya, yang satu dengan yang lainnya saling mempererat (melindungi).\" Dan dia menyebutkan dalam haditsnya, \"Mereka berkata, \"Memang kami telah mengatakan seperti itu wahai Rasulullah.\" Beliau bersabda: \"Lupakah kalian siapakah aku, sekali-kali tidak, sesungguhnya aku adalah hamba Allah dan Rasul-Nya.\""},"3099":{"ar":"حَدَّثَنِي عَبْدُ اللَّهِ بْنُ عَبْدِ الرَّحْمَنِ الدَّارِمِيُّ حَدَّثَنَا يَحْيَى بْنُ حَسَّانَ حَدَّثَنَا حَمَّادُ بْنُ سَلَمَةَ أَخْبَرَنَا ثَابِتٌ عَنْ عَبْدِ اللَّهِ بْنِ رَبَاحٍ قَالَ وَفَدْنَا إِلَى مُعَاوِيَةَ بْنِ أَبِي سُفْيَانَ وَفِينَا أَبُو هُرَيْرَةَ فَكَانَ كُلُّ رَجُلٍ مِنَّا يَصْنَعُ طَعَامًا يَوْمًا لِأَصْحَابِهِ فَكَانَتْ نَوْبَتِي فَقُلْتُ يَا أَبَا هُرَيْرَةَ الْيَوْمُ نَوْبَتِي فَجَاءُوا إِلَى الْمَنْزِلِ وَلَمْ يُدْرِكْ طَعَامُنَافَقُلْتُ يَا أَبَا هُرَيْرَةَ لَوْ حَدَّثْتَنَا عَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حَتَّى يُدْرِكَ طَعَامُنَا فَقَالَ كُنَّا مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَوْمَ الْفَتْحِ فَجَعَلَ خَالِدَ بْنَ الْوَلِيدِ عَلَى الْمُجَنِّبَةِ الْيُمْنَى وَجَعَلَ الزُّبَيْرَ عَلَى الْمُجَنِّبَةِ الْيُسْرَى وَجَعَلَ أَبَا عُبَيْدَةَ عَلَى الْبَيَاذِقَةِ وَبَطْنِ الْوَادِي فَقَالَ يَا أَبَا هُرَيْرَةَ ادْعُ لِي الْأَنْصَارَ فَدَعَوْتُهُمْ فَجَاءُوا يُهَرْوِلُونَ فَقَالَ يَا مَعْشَرَ الْأَنْصَارِ هَلْ تَرَوْنَ أَوْبَاشَ قُرَيْشٍ قَالُوا نَعَمْ قَالَ انْظُرُوا إِذَا لَقِيتُمُوهُمْ غَدًا أَنْ تَحْصُدُوهُمْ حَصْدًا وَأَخْفَى بِيَدِهِ وَوَضَعَ يَمِينَهُ عَلَى شِمَالِهِ وَقَالَ مَوْعِدُكُمْ الصَّفَا قَالَ فَمَا أَشْرَفَ يَوْمَئِذٍ لَهُمْ أَحَدٌ إِلَّا أَنَامُوهُ قَالَ وَصَعِدَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الصَّفَا وَجَاءَتْ الْأَنْصَارُ فَأَطَافُوا بِالصَّفَا فَجَاءَ أَبُو سُفْيَانَ فَقَالَ يَا رَسُولَ اللَّهِ أُبِيدَتْ خَضْرَاءُ قُرَيْشٍ لَا قُرَيْشَ بَعْدَ الْيَوْمِ قَالَ أَبُو سُفْيَانَ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ دَخَلَ دَارَ أَبِي سُفْيَانَ فَهُوَ آمِنٌ وَمَنْ أَلْقَى السِّلَاحَ فَهُوَ آمِنٌ وَمَنْ أَغْلَقَ بَابَهُ فَهُوَ آمِنٌ فَقَالَتْ الْأَنْصَارُ أَمَّا الرَّجُلُ فَقَدْ أَخَذَتْهُ رَأْفَةٌ بِعَشِيرَتِهِ وَرَغْبَةٌ فِي قَرْيَتِهِ وَنَزَلَ الْوَحْيُ عَلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ قُلْتُمْ أَمَّا الرَّجُلُ فَقَدْ أَخَذَتْهُ رَأْفَةٌ بِعَشِيرَتِهِ وَرَغْبَةٌ فِي قَرْيَتِهِ أَلَا فَمَا اسْمِي إِذًا ثَلَاثَ مَرَّاتٍ أَنَا مُحَمَّدٌ عَبْدُ اللَّهِ وَرَسُولِهِ هَاجَرْتُ إِلَى اللَّهِ وَإِلَيْكُمْ فَالْمَحْيَا مَحْيَاكُمْ وَالْمَمَاتُ مَمَاتُكُمْ قَالُوا وَاللَّهِ مَا قُلْنَا إِلَّا ضِنًّا بِاللَّهِ وَرَسُولِهِ قَالَ فَإِنَّ اللَّهَ وَرَسُولَهُ يُصَدِّقَانِكُمْ وَيَعْذِرَانِكُمْ","id":"Telah menceritakan kepadaku [Abdullah bin Abdurrahman Ad Darimi] telah menceritakan kepada kami [Yahya bin Hasan] telah menceritakan kepada kami [Hammad bin Salamah] telah mengabarkan kepada kami [Tsabit] dari [Abdullah bin Rabah] dia berkata, \"Kami datang sebagai delegasi kepada Mu'awiyah bin Abu Sufyan, dan di antara kami ada [Abu Hurairah]. Kami bergilir memasak makanan masing-masing satu hari. Ketika giliranku memasak, aku berkata, \"Wahai Abu Hurairah, hari ini adalah giliranku memasak.\" Tidak lama kemudian mereka telah datang ke tempatku, tetapi makanan belum tersedia, lantas aku berkata, \"Wahai Abu Hurairah, alangkah baiknya jika kamu bercerita kepada kami tentang Rasulullah shallallahu 'alaihi wasallam sampai makanan kita terhidang!\" Dia berkata, \"Kami pernah pergi bersama-sama dengan Rasulullah shallallahu 'alaihi wasallam pada hari penaklukan kota Makkah, beliau mengangkat Khalid bin Walid selaku komandan pasukan sayap kanan, dan mengangkat Zubair menjadi komandan pasukan sayap kiri, serta mengangkat Abu 'Ubaidah mengepalai pasukan pejalan kaki yang di tempatkan di lembah. Kemudian beliau bersabda: \"Wahai Abu Hurairah, panggilah orang-orang Anshar untuk mendekat Aku!\" Aku langsung memanggil mereka hingga mereka pun segera berkerumun di dekat beliau, lalu belau bersabda: \"Wahai orang-orang Anshar, adakah kalian melihat pasukan tentara Quraisy?\" mereka menjawab, \"Ya.\" Beliau bersabda: \"Perhatikan baik-baik, apabila kalian bertemu dengan mereka besok hari, maka habisilah mereka.\" sambil memberi isyarat dengan kedua tangannya -meletakkan yang kanan di atas yang kiri-. Kemudian beliau bersabda: \"Sampai bertemu di Shafa.\" Abu Hurairah berkata, \"Dan saat itu tidak ada seorang pun yang mendekati mereka melainkan mereka habisi.\" Abu Hurairah melanjutkan, \"Kemudian Rasulullah shallallahu 'alaihi wasallam naik ke bukit Shafa, dan orang-orang Anshar datang sembari mengililingi beliau di Shafa, ketika mereka sedang di Shafa, tiba-tiba Abu Sufyan datang seraya berkata, \"Wahai Rasulullah, jika orang-orang Quraisy di habisi semua, maka tidak akan ada lagi orang-orang Quraisy setelah ini.\" Abu Sufyan mengatakan, \"Kemudian Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa masuk ke rumah Abu Sufyan maka dia aman, barangsiapa meletakkan senjatanya maka dia aman, barangsiapa menutup pintunya maka dia aman.\" Setelah itu orang-orang Anshar sama berkata, \"Agaknya laki-laki ini (Rasulullah) telah dipengaruhi perasaan kasih sayang kepada keluarganya hingga timbul rasa cinta terhadap sanak familinya.\" Maka turunlah wahyu kepada Rasulullah shallallahu 'alaihi wasallam, beliau bersabda: \"Kaliankah yang mengatakan, 'agaknya laki-laki ini telah dipengaruhi perasaan kasih sayang terhadap keluarganya hingga timbul rasa cinta terhadap sanak familinya?, sekali-kali tidak, lupakah kalian siapa aku? -beliau mengucapkannya hingga tiga kali- aku adalah Muhammad seorang hamba Allah dan Rasul-Nya, aku telah berhijrah kepada Allah dan kepada kalian semua, maka hidup dan matiku bersama kalian.\" Mereka lantas berkata, \"Demi Allah, tidaklah kami mengatakan melainkan karena kami iri dengan Allah dan Rasul-Nya.\" Beliau bersabda: \"Sesungguhnya Allah dan Rasul-Nya membenarkan apa yang kalian katakan dan memaafkan perbuatan kalian.\""},"3100":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ وَعَمْرٌو النَّاقِدُ وَابْنُ أَبِي عُمَرَ وَاللَّفْظُ لِابْنِ أَبِي شَيْبَةَ قَالُوا حَدَّثَنَا سُفْيَانُ بْنُ عُيَيْنَةَ عَنْ ابْنِ أَبِي نَجِيحٍ عَنْ مُجَاهِدٍ عَنْ أَبِي مَعْمَرٍ عَنْ عَبْدِ اللَّهِ قَالَدَخَلَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَكَّةَ وَحَوْلَ الْكَعْبَةِ ثَلَاثُ مِائَةٍ وَسِتُّونَ نُصُبًا فَجَعَلَ يَطْعُنُهَا بِعُودٍ كَانَ بِيَدِهِ وَيَقُولُ{ جَاءَ الْحَقُّ وَزَهَقَ الْبَاطِلُ إِنَّ الْبَاطِلَ كَانَ زَهُوقًا }{ جَاءَ الْحَقُّ وَمَا يُبْدِئُ الْبَاطِلُ وَمَا يُعِيدُ }زَادَ ابْنُ أَبِي عُمَرَ يَوْمَ الْفَتْحِو حَدَّثَنَاه حَسَنُ بْنُ عَلِيٍّ الْحُلْوَانِيُّ وَعَبْدُ بْنُ حُمَيْدٍ كِلَاهُمَا عَنْ عَبْدِ الرَّزَّاقِ أَخْبَرَنَا الثَّوْرِيُّ عَنْ ابْنِ أَبِي نَجِيحٍ بِهَذَا الْإِسْنَادِ إِلَى قَوْلِهِ زَهُوقًا وَلَمْ يَذْكُرْ الْآيَةَ الْأُخْرَى وَقَالَ بَدَلَ نُصُبًا صَنَمًا","id":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] dan ['Amru An Naqid] serta [Ibnu Abu Umar] sedangkan lafadznya dari Ibnu Abu Syaibah, mereka berkata; telah menceritakan kepada kami [Sufyan bin 'Uyainah] dari [Ibnu Abu Najih] dari [Mujahid] dari [Abu Ma'mar] dari [Abdullah] dia berkata, \"Ketika Nabi shallallahu 'alaihi wasallam masuk Makkah, saat itu terdapat tiga ratus enam puluh patung di sekitar Ka'bah. Lantas dengan tongkatnya beliau memukul patung tersebut sambil membaca: \"Telah datang kebenaran dan lenyaplah kebatilan, sesungguhnya kebatilan pasti lenyap…) ' (Qs. Al Israa: 81) '(Kebenaran telah datang dan yang batil itu tidak akan memulai dan tidak (pula) akan mengulangi) ' (Qs. Sabaa: 49). Ibnu Abu Umar menambahkan, \"Ketika hari penaklukan Kota Makkah.\" Dan telah menceritakan kepada kami [Hasan bin Ali Al Khulwani] dan [Abd bin Humaid] keduanya dari [Abdurrazaq] telah mengabarkan kepada kami [At Tsauri] dari [Ibnu Abu Najih] dengan isnad ini hingga perkataan, \"(dan kebatilan) itu pasti lenyap.\" Dan tidak menyebutkan ayat yang lain, dia juga berkata, \"Arca\" sebagai ganti dari \"Patung.\""},"3101":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا عَلِيُّ بْنُ مُسْهِرٍ وَوَكِيعٌ عَنْ زَكَرِيَّاءَ عَنْ الشَّعْبِيِّ قَالَ أَخْبَرَنِي عَبْدُ اللَّهِ بْنُ مُطِيعٍ عَنْ أَبِيهِ قَالَسَمِعْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ يَوْمَ فَتْحِ مَكَّةَ لَا يُقْتَلُ قُرَشِيٌّ صَبْرًا بَعْدَ هَذَا الْيَوْمِ إِلَى يَوْمِ الْقِيَامَةِحَدَّثَنَا ابْنُ نُمَيْرٍ حَدَّثَنَا أَبِي حَدَّثَنَا زَكَرِيَّاءُ بِهَذَا الْإِسْنَادِ وَزَادَ قَالَ وَلَمْ يَكُنْ أَسْلَمَ أَحَدٌ مِنْ عُصَاةِ قُرَيْشٍ غَيْرَ مُطِيعٍ كَانَ اسْمُهُ الْعَاصِي فَسَمَّاهُ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مُطِيعًا","id":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] telah menceritakan kepada kami [Ali bin Mushir] dan [Waki'] dari [Zakaria] dari [As Sya'bi] dia mengatakan; telah mengabarkan kepadaku [Abdullah bin Muthi'] dari [ayahnya] dia berkata, \"Aku mendengar Nabi shallallahu 'alaihi wasallam bersabda ketika penaklukan kota Makkah: \"Orang-orang Quraisy tidak akan dibunuh dengan cara diikat dan dilempari batu sampai mati, setelah hari ini hingga hari kiamat.\" Telah menceritakan kepada kami [Ibnu Numair] telah menceritakan kepada kami [ayahku] telah menceritakan kepada kami [Zakaria] dengan isnad ini, dengan tambahan, \"Dan tidak ada seorang pun yang selamat dari orang-orang Quraisy yang keras permusuhannya dengan beliau selain Muthi', dan asal namanya adalah Al 'Ashi (pelaku maksiat), lantas Rasulullah shallallahu 'alaihi wasallam menamainya Muthi' (orang yang taat) \""},"3102":{"ar":"حَدَّثَنِي عُبَيْدُ اللَّهِ بْنُ مُعَاذٍ الْعَنْبَرِيُّ حَدَّثَنَا أَبِي حَدَّثَنَا شُعْبَةُ عَنْ أَبِي إِسْحَقَ قَالَ سَمِعْتُ الْبَرَاءَ بْنَ عَازِبٍ يَقُولُاكَتَبَ عَلِيُّ بْنُ أَبِي طَالِبٍ الصُّلْحَ بَيْنَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَبَيْنَ الْمُشْرِكِينَ يَوْمَ الْحُدَيْبِيَةِ فَكَتَبَ هَذَا مَا كَاتَبَ عَلَيْهِ مُحَمَّدٌ رَسُولُ اللَّهِ فَقَالُوا لَا تَكْتُبْ رَسُولُ اللَّهِ فَلَوْ نَعْلَمُ أَنَّكَ رَسُولُ اللَّهِ لَمْ نُقَاتِلْكَ فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لِعَلِيٍّ امْحُهُ فَقَالَ مَا أَنَا بِالَّذِي أَمْحَاهُ فَمَحَاهُ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِيَدِهِ قَالَ وَكَانَ فِيمَا اشْتَرَطُوا أَنْ يَدْخُلُوا مَكَّةَ فَيُقِيمُوا بِهَا ثَلَاثًا وَلَا يَدْخُلُهَا بِسِلَاحٍ إِلَّا جُلُبَّانَ السِّلَاحِ قُلْتُ لِأَبِي إِسْحَقَ وَمَا جُلُبَّانُ السِّلَاحِ قَالَ الْقِرَابُ وَمَا فِيهِحَدَّثَنَا مُحَمَّدُ بْنُ الْمُثَنَّى وَابْنُ بَشَّارٍ قَالَا حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ حَدَّثَنَا شُعْبَةُ عَنْ أَبِي إِسْحَقَ قَالَ سَمِعْتُ الْبَرَاءَ بْنَ عَازِبٍ يَقُولُا لَمَّا صَالَحَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَهْلَ الْحُدَيْبِيَةِ كَتَبَ عَلِيٌّ كِتَابًا بَيْنَهُمْ قَالَ فَكَتَبَ مُحَمَّدٌ رَسُولُ اللَّهِ ثُمَّ ذَكَرَ بِنَحْوِ حَدِيثِ مُعَاذٍ غَيْرَ أَنَّهُ لَمْ يَذْكُرْ فِي الْحَدِيثِ هَذَا مَا كَاتَبَ عَلَيْهِ","id":"Telah menceritakan kepadaku ['Ubaidullah bin Mua'd Al 'Anbari] telah menceritakan kepada kami [ayahku] telah menceritakan kepada kami [Syu'bah] dari [Abu Ishaq] dia berkata; aku mendengar [Al Barra bin 'Azzib] berkata, \"Ali bin Abu Thalib pernah menuliskan perjanjian damai antara Nabi shallallahu 'alaihi wasallam dengan orang-orang Musyrik (Makkah) ketika perjanjian Hudaibiyyah. Ali menuliskan, \"Ini adalah perjanjian yang ditulis oleh Muhammad Rasulullah.\" Lantas mereka berkata, \"Jikalau kami tahu bahwa kamu adalah Rasulullah, tentu kami tidak akan memerangimu.\" Maka Nabi shallallahu 'alaihi wasallam bersabda kepada Ali: \"Hapus kata-kata itu (tulisan 'Rasulullah').\" Ali menjawab, \"Aku tidak mau menghapusnya.\" Maka Nabi shallallahu 'alaihi wasallam yang menghapusnya dengan tangannya sendiri.\" Al Barra` berkata, \"Isi perjanjian itu antara lain menetapkan bahwa kaum Muslimin boleh masuk dan tinggal di kota Makkah selama tiga hari. Tidak boleh membawa senjata kecuali diletakkan dalam sarungnya.\" Aku bertanya kepada Abu Ishaq, \"Apa yang dimaksud dengan sarung pedang?\" dia menjawab, \"Yaitu sarung pedang dan sesuatu yang ada di dalamnya.\" Telah menceritakan kepada kami [Muhammad bin Al Mutsanna] dan [Ibnu Basyar] keduanya berkata; telah menceritakan kepada kami [Muhammad bin Ja'far] telah menceritakan kepada kami [Syu'bah] dari [Abu Ishaq] dia berkata; aku mendengar [Al Barra` bin 'Azib] berkata, \"Rasulullah shallallahu 'alaihi wasallam pernah mengadakan perjanjian Hudaibiyyah, lantas Ali menulis suatu catatan di anatara mereka.\" Al Barra` berkata, \"Lalu dia menulis; Muhammad Rasulullah...kemudian dia menyebutkan seperti hadits Mu'adz, namun dalam haditsnya dia tidak menyebutkan, \"Ini adalah perjanjian yang ditulis olehnya.\""},"3103":{"ar":"حَدَّثَنَا إِسْحَقُ بْنُ إِبْرَاهِيمَ الْحَنْظَلِيُّ وَأَحْمَدُ بْنُ جَنَابٍ الْمِصِّيصِيُّ جَمِيعًا عَنْ عِيسَى بْنِ يُونُسَ وَاللَّفْظُ لِإِسْحَقَ أَخْبَرَنَا عِيسَى بْنُ يُونُسَ أَخْبَرَنَا زَكَرِيَّاءُ عَنْ أَبِي إِسْحَقَ عَنْ الْبَرَاءِ قَالَلَمَّا أُحْصِرَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عِنْدَ الْبَيْتِ صَالَحَهُ أَهْلُ مَكَّةَ عَلَى أَنْ يَدْخُلَهَا فَيُقِيمَ بِهَا ثَلَاثًا وَلَا يَدْخُلَهَا إِلَّا بِجُلُبَّانِ السِّلَاحِ السَّيْفِ وَقِرَابِهِ وَلَا يَخْرُجَ بِأَحَدٍ مَعَهُ مِنْ أَهْلِهَا وَلَا يَمْنَعَ أَحَدًا يَمْكُثُ بِهَا مِمَّنْ كَانَ مَعَهُ قَالَ لِعَلِيٍّ اكْتُبْ الشَّرْطَ بَيْنَنَا بِسْمِ اللَّهِ الرَّحْمَنِ الرَّحِيمِ هَذَا مَا قَاضَى عَلَيْهِ مُحَمَّدٌ رَسُولُ اللَّهِ فَقَالَ لَهُ الْمُشْرِكُونَ لَوْ نَعْلَمُ أَنَّكَ رَسُولُ اللَّهِ تَابَعْنَاكَ وَلَكِنْ اكْتُبْ مُحَمَّدُ بْنُ عَبْدِ اللَّهِ فَأَمَرَ عَلِيًّا أَنْ يَمْحَاهَا فَقَالَ عَلِيٌّ لَا وَاللَّهِ لَا أَمْحَاهَا فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَرِنِي مَكَانَهَا فَأَرَاهُ مَكَانَهَا فَمَحَاهَا وَكَتَبَ ابْنُ عَبْدِ اللَّهِ فَأَقَامَ بِهَا ثَلَاثَةَ أَيَّامٍ فَلَمَّا أَنْ كَانَ يَوْمُ الثَّالِثِ قَالُوا لِعَلِيٍّ هَذَا آخِرُ يَوْمٍ مِنْ شَرْطِ صَاحِبِكَ فَأْمُرْهُ فَلْيَخْرُجْ فَأَخْبَرَهُ بِذَلِكَ فَقَالَ نَعَمْ فَخَرَجَو قَالَ ابْنُ جَنَابٍ فِي رِوَايَتِهِ مَكَانَ تَابَعْنَاكَ بَايَعْنَاكَ","id":"Telah menceritakan kepada kami [Ishaq bin Ibrahim Al Hamzhali] dan [Ahmad bin Janab Al Mishishi] semuanya dari [Isa bin Yunus] sedangkan lafadznya dari Ishaq, telah mengabarkan kepada kami [Isa bin Yunus] telah mengabarkan kepada kami [Zakaria] dari [Abu Ishaq] dari [Al Barra`] dia berkata, \"Ketika nabi shallallahu 'alaihi wasallam dilarang melaksanakn Haji, maka penduduk Makkah mengadakan perjanjian damai yaitu; supaya beliau masuk dan bermukim hanya tiga hari, tidak masuk (Makkah) melainkan dengan pedang yang masih diletakkan dalam sarungnya, setiap orang dari kaumnya tidak boleh keluar bersama beliau, namun sebaliknya mereka membolehkan sahabat beliau yang hendak ikut bersama mereka (tinggal di Makkah). Lantas beliau bersabda kepada Ali: \"Tulislah syarat antara kami dengan mereka dengan Bismillahirrahmanirrahim, ini adalah hasil keputusan yang ditetapkan oleh Muhammad Rasulullah.\" Maka orang-orang Musyrik berkata kepada beliau, \"Sekiranya kami mengetahui kalau kamu adalah Rasulullah, niscaya kami akan mengikutimu, akan tetapi tulislah Muhammad bin Abdullah.\" Lalu beliau menyuruh Ali supaya menghapusnya, namun Ali berkata, \"Demi Allah, aku tidak akan menghapusnya.\" Kemudian Rasulullah shallallahu 'alaihi wasallam bersabda: \"Beritahukanlah kepadaku tempat yang kamu tulis tadi.\" Maka Ali memberitahukan kepada beliau tempatnya, lalu beliau sendiri yang menghapusnya, dan diganti dengan Ibnu Abdullah. Beliau tinggal selama tiga hari, tatkala hari yang ke tiga, mereka (orang-orang Quraisy) berkata kepada Ali, \"Ini adalah hari terakhir sebagaimana dalam syarat yang dibuat oleh saudaramu, maka suruhlah dia keluar (dari Makkah).\" Lantas Ali memberitahukan kepada belau, akhirnya beliau keluar (dari Makkah).\" Dan dalam riwayat Ibnu Janab disebutkan, \"Niscaya kami akan mengikutimu dan berbaiat kepadamu.\""},"3104":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا عَفَّانُ حَدَّثَنَا حَمَّادُ بْنُ سَلَمَةَ عَنْ ثَابِتٍ عَنْ أَنَسٍأَنَّ قُرَيْشًا صَالَحُوا النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِيهِمْ سُهَيْلُ بْنُ عَمْرٍو فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لِعَلِيٍّ اكْتُبْ بِسْمِ اللَّهِ الرَّحْمَنِ الرَّحِيمِ قَالَ سُهَيْلٌ أَمَّا بِاسْمِ اللَّهِ فَمَا نَدْرِي مَا بِسْمِ اللَّهِ الرَّحْمَنِ الرَّحِيمِ وَلَكِنْ اكْتُبْ مَا نَعْرِفُ بِاسْمِكَ اللَّهُمَّ فَقَالَ اكْتُبْ مِنْ مُحَمَّدٍ رَسُولِ اللَّهِ قَالُوا لَوْ عَلِمْنَا أَنَّكَ رَسُولُ اللَّهِ لَاتَّبَعْنَاكَ وَلَكِنْ اكْتُبْ اسْمَكَ وَاسْمَ أَبِيكَ فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ اكْتُبْ مِنْ مُحَمَّدِ بْنِ عَبْدِ اللَّهِ فَاشْتَرَطُوا عَلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنْ مَنْ جَاءَ مِنْكُمْ لَمْ نَرُدَّهُ عَلَيْكُمْ وَمَنْ جَاءَكُمْ مِنَّا رَدَدْتُمُوهُ عَلَيْنَا فَقَالُوا يَا رَسُولَ اللَّهِ أَنَكْتُبُ هَذَا قَالَ نَعَمْ إِنَّهُ مَنْ ذَهَبَ مِنَّا إِلَيْهِمْ فَأَبْعَدَهُ اللَّهُ وَمَنْ جَاءَنَا مِنْهُمْ سَيَجْعَلُ اللَّهُ لَهُ فَرَجًا وَمَخْرَجًا","id":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] telah menceritakan kepada kami [Affan] telah menceritakan kepada kami [Hammad bin Salamah] dari [Tsabit] dari [Anas] bahwa orang-orang Quraisy pernah mengadakan perjanjian damai dengan Nabi shallallahu 'alaihi wasallam. Sedangkan dikalangan mereka terdapat Suhail bin 'Amru. Maka Nabi shallallahu 'alaihi wasallam bersabda kepada Ali: \"Tulsilah Bismillahirrahmanirrahim.\" Suhail berkata, \"Aku tidak tahu apa itu Bismillahirrahmanirrahim, akan tetapi tulislah sebagaimana yang kami ketahui yaitu, 'Bismikallahumma'.\" Beliau bersabda: \"Tulislah dari Muhammad Rasulullah.\" Mereka berkata, \"Sekiranya kami mengetahui bahwa kamu adalah Rasulullah, sungguh kami akan mengikutimu, akan tetapi tulislah namamu dan nama ayahmu.\" Lantas Nabi shallallahu 'alaihi wasallam bersabda: \"Tulislah dari Muhammad bin Abdullah.\" Kemudian mereka mengajukan persyaratan-persyaratan kepada Nabi shallallahu 'alaihi wasallam, di antaranya ialah, bahwa setiap orang yang datang dari pihak kalian, maka kami tidak akan mengembalikannya kepada kalian, namun jika pihak kami ada yang datang kepada kalian, maka kalian harus mengembalikannya kepada kami.\" Maka para sahabat bertanya, \"Wahai Rasulullah, apakah kita harus menulis persyaratan tersebut?\" beliau menjawab: \"Ya, sebab orang-orang kita yang pergi kepada mereka, maka Allah akan menjauhkannya (dari rahmat-Nya), namun jika dari pihak mereka datang kepada kita, mudah-mudahan Allah memberikan jalan keluar.\""},"3105":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ نُمَيْرٍ ح و حَدَّثَنَا ابْنُ نُمَيْرٍ وَتَقَارَبَا فِي اللَّفْظِ حَدَّثَنَا أَبِي حَدَّثَنَا عَبْدُ الْعَزِيزِ بْنُ سِيَاهٍ حَدَّثَنَا حَبِيبُ بْنُ أَبِي ثَابِتٍ عَنْ أَبِي وَائِلٍ قَالَقَامَ سَهْلُ بْنُ حُنَيْفٍ يَوْمَ صِفِّينَ فَقَالَ أَيُّهَا النَّاسُ اتَّهِمُوا أَنْفُسَكُمْ لَقَدْ كُنَّا مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَوْمَ الْحُدَيْبِيَةِ وَلَوْ نَرَى قِتَالًا لَقَاتَلْنَا وَذَلِكَ فِي الصُّلْحِ الَّذِي كَانَ بَيْنَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَبَيْنَ الْمُشْرِكِينَ فَجَاءَ عُمَرُ بْنُ الْخَطَّابِ فَأَتَى رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ يَا رَسُولَ اللَّهِ أَلَسْنَا عَلَى حَقٍّ وَهُمْ عَلَى بَاطِلٍ قَالَ بَلَى قَالَ أَلَيْسَ قَتْلَانَا فِي الْجَنَّةِ وَقَتْلَاهُمْ فِي النَّارِ قَالَ بَلَى قَالَ فَفِيمَ نُعْطِي الدَّنِيَّةَ فِي دِينِنَا وَنَرْجِعُ وَلَمَّا يَحْكُمِ اللَّهُ بَيْنَنَا وَبَيْنَهُمْ فَقَالَ يَا ابْنَ الْخَطَّابِ إِنِّي رَسُولُ اللَّهِ وَلَنْ يُضَيِّعَنِي اللَّهُ أَبَدًا قَالَ فَانْطَلَقَ عُمَرُ فَلَمْ يَصْبِرْ مُتَغَيِّظًا فَأَتَى أَبَا بَكْرٍ فَقَالَ يَا أَبَا بَكْرٍ أَلَسْنَا عَلَى حَقٍّ وَهُمْ عَلَى بَاطِلٍ قَالَ بَلَى قَالَ أَلَيْسَ قَتْلَانَا فِي الْجَنَّةِ وَقَتْلَاهُمْ فِي النَّارِ قَالَ بَلَى قَالَ فَعَلَامَ نُعْطِي الدَّنِيَّةَ فِي دِينِنَا وَنَرْجِعُ وَلَمَّا يَحْكُمِ اللَّهُ بَيْنَنَا وَبَيْنَهُمْ فَقَالَ يَا ابْنَ الْخَطَّابِ إِنَّهُ رَسُولُ اللَّهِ وَلَنْ يُضَيِّعَهُ اللَّهُ أَبَدًا قَالَ فَنَزَلَ الْقُرْآنُ عَلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِالْفَتْحِ فَأَرْسَلَ إِلَى عُمَرَ فَأَقْرَأَهُ إِيَّاهُ فَقَالَ يَا رَسُولَ اللَّهِ أَوْ فَتْحٌ هُوَ قَالَ نَعَمْ فَطَابَتْ نَفْسُهُ وَرَجَعَ","id":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] telah menceritakan kepada kami [Abdullah bin Numair]. (dalam jalur lain disebutkan) Telah menceritakan kepada kami [Ibnu Numair] sedangkan lafadznya saling berdekatan, telah menceritakan kepada kami [ayahku] telah menceritakan kepada kami [Abdul Aziz bin Siyah] telah menceritakan kepada kami [Habib bin Abu Tsabit] dari [Abu Wa`il] dia berkata, \" [Sahal bin Hunaif] pernah berdiri ketika terjadi perang Shifin, dia berseru, \"Wahai manusia, koreksilah diri kalian masing-masing. Ketika terjadi perjanjian Hudaibiyyah, kami bersama-sama dengan Rasulullah shallallahu 'alaihi wasallam. Seandainya waktu itu kami melihat adanya pembunuhan, pasti kami telah berperang. Hal ini terjadi ketika terjadi perjanjian damai antara Rasulullah shallallahu 'alaihi wasallam dengan orang-orang Musyrik. Maka umar bin Khatthab datang menghampiri Rasulullah shallallahu 'alaihi wasallam seraya berkata, \"Wahai Rasulullah, tidakkah kita dalam kebenaran dan mereka dalam kebathilan?\" beliau bersabda: \"Ya.\" Dia berkata, \"Bukankah jika kita terbunuh akan masuk surga? sedangkan jika mereka terbunuh, mereka akan masuk neraka?\" beliau menjawab: \"Ya benar.\" Umar bertanya, \"Mengapakah kita harus mengalah mengenai agama kita, dan pulang begitu saja? Padahal Allah belum memberikan keputusan apa-apa antara kita dengan mereka?\" Beliau menjawab: \"Wahai Ibnul Khattab, sesungguhnya aku adalah Rasulullah, dan sekali-kali Allah tidak akan menyia-nyiakan aku selama-lamanya.\" Abu Wa'il berkata, \"Umar lalu pergi dalam keadaan tidak puas, bahkan terlihat marah. Lalu dia mendatangi Abu Bakar seraya berkata, \"Wahai Abu Bakar, bukankah kita di atas yang hak dan mereka dalam kebathilan.\" Dia menjawab, \"Ya, benar.\" Umar bertanya, \"Tidakkah jika kita terbunuh, maka kita akan masuk surga, sedangkan jika mereka yang terbunuh, maka mereka akan masuk neraka?\" Abu Bakar menjawab, \"Ya, benar.\" Umar bertanya lagi, \"Mengapakah kita harus mengalah mengenai agama kita, dan pulang begitu saja? Padahal Allah belum memberikan keputusan apa-apa antara kita dengan mereka?\" Maka Abu Bakar berkata, \"Wahai Ibnul Khattab, sesungguhnya beliau adalah Rasulullah, dan sekali-kali Allah tidak akan menyia-nyiakan beliau selama-lamanya.\" Suhail berkata, \"Maka turunlah ayat Al Qur'an kepada Rasulullah, yaitu surat Al Fath. Maka beliau menyuruh seseorang untuk membacakan kepada Umar, lantas dia bertanya, \"Wahai Rasulullah, apakah itu yang dimaksud dengan kemenangan?\" beliau bersabda: \"Ya, benar.\" Barulah dia bertaubat dan kembali.\""},"3106":{"ar":"حَدَّثَنَا أَبُو كُرَيْبٍ مُحَمَّدُ بْنُ الْعَلَاءِ وَمُحَمَّدُ بْنُ عَبْدِ اللَّهِ بْنِ نُمَيْرٍ قَالَا حَدَّثَنَا أَبُو مُعَاوِيَةَ عَنْ الْأَعْمَشِ عَنْ شَقِيقٍ قَالَ سَمِعْتُ سَهْلَ بْنَ حُنَيْفٍ يَقُولُا بِصِفِّينَ أَيُّهَا النَّاسُ اتَّهِمُوا رَأْيَكُمْوَاللَّهِ لَقَدْ رَأَيْتُنِي يَوْمَ أَبِي جَنْدَلٍ وَلَوْ أَنِّي أَسْتَطِيعُ أَنْ أَرُدَّ أَمْرَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَرَدَدْتُهُ وَاللَّهِ مَا وَضَعْنَا سُيُوفَنَا عَلَى عَوَاتِقِنَا إِلَى أَمْرٍ قَطُّ إِلَّا أَسْهَلْنَ بِنَا إِلَى أَمْرٍ نَعْرِفُهُ إِلَّا أَمْرَكُمْ هَذَا لَمْ يَذْكُرْ ابْنُ نُمَيْرٍ إِلَى أَمْرٍ قَطُّو حَدَّثَنَاه عُثْمَانُ بْنُ أَبِي شَيْبَةَ وَإِسْحَقُ جَمِيعًا عَنْ جَرِيرٍ ح و حَدَّثَنِي أَبُو سَعِيدٍ الْأَشَجُّ حَدَّثَنَا وَكِيعٌ كِلَاهُمَا عَنْ الْأَعْمَشِ بِهَذَا الْإِسْنَادِ وَفِي حَدِيثِهِمَا إِلَى أَمْرٍ يُفْظِعُنَا","id":"Telah menceritakan kepada kami [Abu Kuraib Muhammad bin Al 'Ala] dan [Muhammad bin Abdullah bin Numair] keduanya berkata; telah menceritakan kepada kami [Abu Mu'awiyah] dari [Al A'masy] dari [Syaqiq] dia berkata; aku mendengar [Sahal bin Hunaif] berkata ketika di Shifin, \"Wahai para manusia, koreksilah diri kalian masing-masing, demi Allah, aku telah mengalami sendiri ketika peristiwa Abu Jandal, sekiranya aku mampu menolak perintah Rasulullah shallallahu 'alaihi wasallam, sungguh aku akan menolaknya (untuk tidak berperang). Demi Allah, ketika itu kami tidak melakukan peperangan sedikitpun, melainkan Allah memudahkan urusan kami, sangat berbeda dengan peristiwa kalian saat ini!\" Ibnu Numair tidak menyebutkan, \"Hingga suatu perkara yang mengkhawatirkan.\" Dan telah menceritakan kepada kami [Utsman bin Abu Syaibah] dan [Ishaq] semuanya dari [Jarir]. Dan telah diriwayatkan dari jalur lain, telah menceritakan kepadaku [Abu Sa'id Al Asyaj] telah menceritakan kepada kami [Waki'] keduanya dari [Al A'masy] dengan isnad in, dan dalam hadits keduanya di sebutkan, \"Sampai kepada peristiwa yang menagerikan.\""},"3107":{"ar":"و حَدَّثَنِي إِبْرَاهِيمُ بْنُ سَعِيدٍ الْجَوْهَرِيُّ حَدَّثَنَا أَبُو أُسَامَةَ عَنْ مَالِكِ بْنِ مِغْوَلٍ عَنْ أَبِي حَصِينٍ عَنْ أَبِي وَائِلٍ قَالَ سَمِعْتُ سَهْلَ بْنَ حُنَيْفٍ بِصِفِّينَ يَقُولُا اتَّهِمُوا رَأْيَكُمْ عَلَى دِينِكُمْفَلَقَدْ رَأَيْتُنِي يَوْمَ أَبِي جَنْدَلٍ وَلَوْ أَسْتَطِيعُ أَنْ أَرُدَّ أَمْرَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَا فَتَحْنَا مِنْهُ فِي خُصْمٍ إِلَّا انْفَجَرَ عَلَيْنَا مِنْهُ خُصْمٌ","id":"Dan telah menceritakan kepadaku [Ibrahim bin Sa'id Al Jauhari] telah menceritakan kepada kami [Abu Usamah] dari [Malik bin Mighwal] dari [Abu Hashin] dari [Abu Wa`il] dia berkata; aku mendengar [Sahl bin Hunaif] berkata ketika di Shifin, \"Perhatikanlah diri kalian, niscaya kalian akan mengetahui perkara agama kalian, sungguh aku pernah melihat peristiwa Abu Jandal, sekiranya aku mampu menolak perintah Rasulullah shallallahu 'alaihi wasallam, niscaya kami tidak akan diberi jalan keluar dalam permusuhan tersebut, melainkan permusuhan tersebut senantiasa masih ada.\""},"3108":{"ar":"و حَدَّثَنَا نَصْرُ بْنُ عَلِيٍّ الْجَهْضَمِيُّ حَدَّثَنَا خَالِدُ بْنُ الْحَارِثِ حَدَّثَنَا سَعِيدُ بْنُ أَبِي عَرُوبَةَ عَنْ قَتَادَةَ أَنَّ أَنَسَ بْنَ مَالِكٍ حَدَّثَهُمْ قَالَلَمَّا نَزَلَتْ{ إِنَّا فَتَحْنَا لَكَ فَتْحًا مُبِينًا لِيَغْفِرَ لَكَ اللَّهُ إِلَى قَوْلِهِ فَوْزًا عَظِيمًا }مَرْجِعَهُ مِنْ الْحُدَيْبِيَةِ وَهُمْ يُخَالِطُهُمْ الْحُزْنُ وَالْكَآبَةُ وَقَدْ نَحَرَ الْهَدْيَ بِالْحُدَيْبِيَةِ فَقَالَ لَقَدْ أُنْزِلَتْ عَلَيَّ آيَةٌ هِيَ أَحَبُّ إِلَيَّ مِنْ الدُّنْيَا جَمِيعًاو حَدَّثَنَا عَاصِمُ بْنُ النَّض��رِ التَّيْمِيُّ حَدَّثَنَا مُعْتَمِرٌ قَالَ سَمِعْتُ أَبِي حَدَّثَنَا قَتَادَةُ قَالَ سَمِعْتُ أَنَسَ بْنَ مَالِكٍ ح و حَدَّثَنَا ابْنُ الْمُثَنَّى حَدَّثَنَا أَبُو دَاوُدَ حَدَّثَنَا هَمَّامٌ ح و حَدَّثَنَا عَبْدُ بْنُ حُمَيْدٍ حَدَّثَنَا يُونُسُ بْنُ مُحَمَّدٍ حَدَّثَنَا شَيْبَانُ جَمِيعًا عَنْ قَتَادَةَ عَنْ أَنَسٍ نَحْوَ حَدِيثِ ابْنِ أَبِي عَرُوبَةَ","id":"Telah menceritakan kepada kami [Nashr bin Ali Al Jahzhami] telah menceritakan kepada kami [Khalid bin Al Harits] berkata, telah menceritakan kepada kami [Sa'id bin Abu 'Arubah] dari [Qatadah] bahwa [Anas bin Malik] telah menceritakan kepada mereka, dia berkata, \"Ketika turun ayat: '(Sesungguhnya kami telah memberikan kepadamu kemenangan yang nyata, supaya Allah memberikan ampunan kepadamu terhadap dosamu -hingga firmanNya- dengan pertolongan yang kuat (banyak).' (Qs. Al Fath: 1-3), ketika itu mereka baru pulang dari Hudaibiyyah dengan diliputi perasaan jengkel dan kesal, padahal mereka telah menyembelih binatang kurban. Maka beliau bersabda: \"Sungguh telah turun kepadaku suatu ayat yang lebih aku cintai daripada dunia dan isinya.\" Dan telah menceritakan kepada kami ['Ashim bin An Nadlr At Taimi] telah menceritakan kepada kami [Mu'tamir] dia berkata; aku mendengar [ayahku] telah menceritakan kepada kami [Qatadah] dia berkata; aku pernah mendengar [Anas bin Malik]. (dalam jalur lain disebutkan) Telah menceritakan kepada kami [Ibnu Al Mutsanna] telah menceritakan kepada kami [Abu Daud] telah menceritakan kepada kami [Hammam] (dalam jalur lain disebutkan) telah menceritakan kepada kami [Abd bin Humaid] telah menceritakan kepada kami [Yunus bin Muhammad] telah menceritakan kepada kami [Syaiban] semuanya dari [Qatadah] dari [Anas] sebagaimana hadits Ibnu Abu 'Arubah.\""},"3109":{"ar":"و حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا أَبُو أُسَامَةَ عَنْ الْوَلِيدِ بْنِ جُمَيْعٍ حَدَّثَنَا أَبُو الطُّفَيْلِ حَدَّثَنَا حُذَيْفَةُ بْنُ الْيَمَانِ قَالَمَا مَنَعَنِي أَنْ أَشْهَدَ بَدْرًا إِلَّا أَنِّي خَرَجْتُ أَنَا وَأَبِي حُسَيْلٌ قَالَ فَأَخَذَنَا كُفَّارُ قُرَيْشٍ قَالُوا إِنَّكُمْ تُرِيدُونَ مُحَمَّدًا فَقُلْنَا مَا نُرِيدُهُ مَا نُرِيدُ إِلَّا الْمَدِينَةَ فَأَخَذُوا مِنَّا عَهْدَ اللَّهِ وَمِيثَاقَهُ لَنَنْصَرِفَنَّ إِلَى الْمَدِينَةِ وَلَا نُقَاتِلُ مَعَهُ فَأَتَيْنَا رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَخْبَرْنَاهُ الْخَبَرَ فَقَالَ انْصَرِفَا نَفِي لَهُمْ بِعَهْدِهِمْ وَنَسْتَعِينُ اللَّهَ عَلَيْهِمْ","id":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] telah menceritakan kepada kami [Abu Usamah] dari [Al Walid bin Jumai'] telah menceritakan kepada kami [Abu At Thufail] telah menceritakan kepada kami [Hudzaifah bin Yaman] dia berkata, \"Tidak ada yang menghalangiku untuk turut bertempur di Badar kecuali karena aku dan ayahku yaitu Husail tertangkap oleh orang-orang Quraisy ketika kami keluar dari Makkah. Mereka bertanya, \"Apakah kalian hendak pergi menemui Muhammad? Kami menjawab, \"Tidak, kami hanya akan berjalan-jalan ke Madinah.\" Lalu mereka membuat perjanjian dengan kami, bahwa kami boleh pergi ke Madinah akan tetapi tidak boleh berperang memihak beliau. Lalu kami mendatangi Rasulullah shallallahu 'alaihi wasallam dan memberitahukan kepada beliau akan peristiwa kami tersebut. Maka beliau bersabda: \"Pergilah kalian, dan pegang teguhlah janji kalian dengan mereka, kita akan memohon pertolongan kepada Allah untuk mengalahkan mereka.\""},"3110":{"ar":"حَدَّثَنَا زُهَيْرُ بْنُ حَرْبٍ وَإِسْحَقُ بْنُ إِبْرَاهِيمَ جَمِيعًا عَنْ جَرِيرٍ قَالَ زُهَيْرٌ حَدَّثَنَا جَرِيرٌ عَنْ الْأَعْمَشِ عَنْ إِبْرَاهِيمَ التَّيْمِيِّ عَنْ أَبِيهِ قَالَكُنَّا عِنْدَ حُذَيْفَةَ فَقَالَ رَجُلٌ لَوْ أَدْرَكْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَاتَلْتُ مَعَهُ وَأَبْلَيْتُ فَقَالَ حُذَيْفَةُ أَنْتَ كُنْتَ تَفْعَلُ ذَلِكَ لَقَدْ رَأَيْتُنَا مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَيْلَةَ الْأَحْزَابِ وَأَخَذَتْنَا رِيحٌ شَدِيدَةٌ وَقُرٌّ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَلَا رَجُلٌ يَأْتِينِي بِخَبَرِ الْقَوْمِ جَعَلَهُ اللَّهُ مَعِي يَوْمَ الْقِيَامَةِ فَسَكَتْنَا فَلَمْ يُجِبْهُ مِنَّا أَحَدٌ ثُمَّ قَالَ أَلَا رَجُلٌ يَأْتِينَا بِخَبَرِ الْقَوْمِ جَعَلَهُ اللَّهُ مَعِي يَوْمَ الْقِيَامَةِ فَسَكَتْنَا فَلَمْ يُجِبْهُ مِنَّا أَحَدٌ ثُمَّ قَالَ أَلَا رَجُلٌ يَأْتِينَا بِخَبَرِ الْقَوْمِ جَعَلَهُ اللَّهُ مَعِي يَوْمَ الْقِيَامَةِ فَسَكَتْنَا فَلَمْ يُجِبْهُ مِنَّا أَحَدٌ فَقَالَ قُمْ يَا حُذَيْفَةُ فَأْتِنَا بِخَبَرِ الْقَوْمِ فَلَمْ أَجِدْ بُدًّا إِذْ دَعَانِي بِاسْمِي أَنْ أَقُومَ قَالَ اذْهَبْ فَأْتِنِي بِخَبَرِ الْقَوْمِ وَلَا تَذْعَرْهُمْ عَلَيَّ فَلَمَّا وَلَّيْتُ مِنْ عِنْدِهِ جَعَلْتُ كَأَنَّمَا أَمْشِي فِي حَمَّامٍ حَتَّى أَتَيْتُهُمْ فَرَأَيْتُ أَبَا سُفْيَانَ يَصْلِي ظَهْرَهُ بِالنَّارِ فَوَضَعْتُ سَهْمًا فِي كَبِدِ الْقَوْسِ فَأَرَدْتُ أَنْ أَرْمِيَهُ فَذَكَرْتُ قَوْلَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَلَا تَذْعَرْهُمْ عَلَيَّ وَلَوْ رَمَيْتُهُ لَأَصَبْتُهُ فَرَجَعْتُ وَأَنَا أَمْشِي فِي مِثْلِ الْحَمَّامِ فَلَمَّا أَتَيْتُهُ فَأَخْبَرْتُهُ بِخَبَرِ الْقَوْمِ وَفَرَغْتُ قُرِرْتُ فَأَلْبَسَنِي رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِنْ فَضْلِ عَبَاءَةٍ كَانَتْ عَلَيْهِ يُصَلِّي فِيهَا فَلَمْ أَزَلْ نَائِمًا حَتَّى أَصْبَحْتُ فَلَمَّا أَصْبَحْتُ قَالَ قُمْ يَا نَوْمَانُ","id":"Telah menceritakan kepada kami [Zuhair bin Harb] dan [Ishaq bin Ibrahim] semuanya dari [Jarir], [Zuhair] berkata; telah menceritakan kepada kami [Jarir] dari [Al A'masy] dari [Ibrahim At Taimi] dari [ayahnya] dia berkata, \"Suatu ketika kami berada di dekat [Hudzaifah], tiba-tiba ada seorang laki-laki yang berkata, \"Seandainya aku mendapatkan Rasulullah shallallahu 'alaihi wasallam, niscaya aku akan berperang bersama beliau dan aku akan bersungguh-sunbgguh.\" Hudzaifah berkata, \"Betulkah kalian akan berbuat seperti itu?\" aku sendiri pernah mengalami perang bersama Rasulullah shallallahu 'alaihi wasallam ketika perang Ahzab. Saat itu kami diserang oleh angin yang sangat kencang dan udara yang dingin. Maka Rasulullah shallallahu 'alaihi wasallam bersabda: \"Adakah seseorang yang sanggup mencari berita tentang musuh? Maka Allah akan menempatkannya bersamaku kelak di hari Kiamat.\" Semuanya diam, dan tidak ada satupun yang menjawab. Kemudian beliau bertanya lagi: \"Adakah seseorang yang sanggup mencari berita tentang musuh? Maka Allah akan menempatkannya bersamaku kelak di hari Kiamat.\" Semuanya diam, dan tidak ada satupun yang menjawab. Kemudian beliau bertanya pula: \"Adakah seseorang yang sanggup mencari berita tentang musuh? Maka Allah akan menempatkannya bersamaku kelak di hari Kiamat.\" Kami masih terdiam semuanya, dan tidak ada satupun yang menjawab. Lalu beliau bersabda: \"Wahai Hudzaifah, berdiri dan carilah kabar mengenai musuh!\" Maka tidak bisa tidak, aku harus berdiri, karena beliau jelas memanggil namaku. Beliau bersabda: \"Pergi dan carilah kabar mengenai musuh, dan jangan kamu mengagetkan mereka tentang diriku.\" Tatkala aku telah berpaling dari sisi beliau, seakan-akan aku berjalan dengan kehangatan (tidak seperti yng lain dalam kedinginan-red), sehingga aku mendatangi mereka, lantas aku melihat Abu Sufyan yang sedang menghangatkan badannya dengan api, maka aku langsung menaruh anak panah pada busurnya dan hendak memanahnya, sekiranya aku tidak ingat dengan pesan Rasulullah shallallahu 'alaihi wasallam: \"Jangan kamu mengagetkan mereka dengan diriku.\" Niscaya aku telah panah dan akan mengenainya. Lalu aku kembali sambil berjalan kaki dengan kehangatan, kemudian aku menemui beliau dan melaporkan mengenai kondisi musuh, setelah itu aku pergi, tiba-tiba diriku mulai merasakan kedinginan, maka Rasulullah shallallahu 'alaihi wasallam memakaikanku kain burdah yang biasa dipakai beliau untuk shalat, kemudian aku tertidur sampai pagi, keesokan harinya beliau bersabda: \"Bangun wahai orang yang banyak tidur.\""},"3111":{"ar":"و حَدَّثَنَا هَدَّابُ بْنُ خَالِدٍ الْأَزْدِيُّ حَدَّثَنَا حَمَّادُ بْنُ سَلَمَةَ عَنْ عَلِيِّ بْنِ زَيْدٍ وَثَابِتٍ الْبُنَانِيِّ عَنْ أَنَسِ بْنِ مَالِكٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أُفْرِدَ يَوْمَ أُحُدٍ فِي سَبْعَةٍ مِنْ الْأَنْصَارِ وَرَجُلَيْنِ مِنْ قُرَيْشٍ فَلَمَّا رَهِقُوهُ قَالَ مَنْ يَرُدُّهُمْ عَنَّا وَلَهُ الْجَنَّةُ أَوْ هُوَ رَفِيقِي فِي الْجَنَّةِ فَتَقَدَّمَ رَجُلٌ مِنْ الْأَنْصَارِ فَقَاتَلَ حَتَّى قُتِلَ ثُمَّ رَهِقُوهُ أَيْضًا فَقَالَ مَنْ يَرُدُّهُمْ عَنَّا وَلَهُ الْجَنَّةُ أَوْ هُوَ رَفِيقِي فِي الْجَنَّةِ فَتَقَدَّمَ رَجُلٌ مِنْ الْأَنْصَارِ فَقَاتَلَ حَتَّى قُتِلَ فَلَمْ يَزَلْ كَذَلِكَ حَتَّى قُتِلَ السَّبْعَةُ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لِصَاحِبَيْهِ مَا أَنْصَفْنَا أَصْحَابَنَا","id":"Telah menceritakan kepada kami [Haddab bin Khalid Al Azdi] telah menceritakan kepada kami [Hammad bin Salamah] dari [Ali bin Zaid] dan [Tsabit bin Al Banani] dari [Anas bin Malik], bahwa ketika perang Uhud berkecamuk, Rasulullah shallallahu 'alaihi wasallam terdesak sendirian bersama-sama dengan tujuh orang Anshar dan dua sahabat Quraisy (Muhajirin), ketika musuh semakin mendekati beliau, beliau bersabda: \"Barangsiapa dapat menghalau mereka (musuh) dari kami, maka baginya surga atau dia akan bersamaku di surga.\" Maka seorang laki-laki dari Anshar maju kehadapan dan bertempur hingga terbunuh, kemudian musuh semakin mendekati beliau, beliau bersabda: \"Barangsiapa dapat menghalau mereka dariku, maka baginya surga atau dia akan bersamaku di surga.\" Maka seorang laki-laki dari Anshar maju kehadapan dan bertempur hingga terbunuh. Peristiwa tersebut terus seperti itu hingga ketujuh sahabat Anshar terbunuh, maka Rasulullah shallallahu 'alaihi wasallam bersabda kepada kedua sahabat Quraisy: \"Betapa adilnya para sahabat kita.\""},"3112":{"ar":"حَدَّثَنَا يَحْيَى بْنُ يَحْيَى التَّمِيمِيُّ حَدَّثَنَا عَبْدُ الْعَزِيزِ بْنُ أَبِي حَازِمٍ عَنْ أَبِيهِأَنَّهُ سَمِعَ سَهْلَ بْنَ سَعْدٍ يَسْأَلُ عَنْ جُرْحِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَوْمَ أُحُدٍ فَقَالَ جُرِحَ وَجْهُ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَكُسِرَتْ رَبَاعِيَتُهُ وَهُشِمَتْ الْبَيْضَةُ عَلَى رَأْسِهِ فَكَانَتْ فَاطِمَةُ بِنْتُ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ تَغْسِلُ الدَّمَ وَكَانَ عَلِيُّ بْنُ أَبِي طَالِبٍ يَسْكُبُ عَلَيْهَا بِالْمِجَنِّ فَلَمَّا رَأَتْ فَاطِمَةُ أَنَّ الْمَاءَ لَا يَزِيدُ الدَّمَ إِلَّا كَثْرَةً أَخَذَتْ قِطْعَةَ حَصِيرٍ فَأَحْرَقَتْهُ حَتَّى صَارَ رَمَادًا ثُمَّ أَلْصَقَتْهُ بِالْجُرْحِ فَاسْتَمْسَكَ الدَّمُحَدَّثَنَا قُتَيْبَةُ بْنُ سَعِيدٍ حَدَّثَنَا يَعْقُوبُ يَعْنِي ابْنَ عَبْدِ الرَّحْمَنِ الْقَارِيَّ عَنْ أَبِي حَازِمٍ أَنَّهُ سَمِعَ سَهْلَ بْنَ سَعْدٍ وَهُوَ يَسْأَلُ عَنْ جُرْحِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ أَمَ وَاللَّهِ إِنِّي لَأَعْرِفُ مَنْ كَانَ يَغْسِلُ جُرْحَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَمَنْ كَانَ يَسْكُبُ الْمَاءَ وَبِمَاذَا دُووِيَ جُرْحُهُ ثُمَّ ذَكَرَ نَحْوَ حَدِيثِ عَبْدِ الْعَزِيزِ غَيْرَ أَنَّهُ زَادَ وَجُرِحَ وَجْهُهُ وَقَالَ مَكَانَ هُشِمَتْ كُسِرَتْ و حَدَّثَنَاه أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ وَزُهَيْرُ بْنُ حَرْبٍ وَإِسْحَقُ بْنُ إِبْرَاهِيمَ وَابْنُ أَبِي عُمَرَ جَمِيعًا عَنْ ابْنِ عُيَيْنَةَ ح و حَدَّثَنَا عَمْرُو بْنُ سَوَّادٍ الْعَامِرِيُّ أَخْبَرَنَا عَبْدُ اللَّهِ بْنُ وَهْبٍ أَخْبَرَنِي عَمْرُو بْنُ الْحَارِثِ عَنْ سَعِيدِ بْنِ أَبِي هِلَالٍ ح و حَدَّثَنِي مُحَمَّدُ بْنُ سَهْلٍ التَّمِيمِيُّ حَدَّثَنِي ابْنُ أَبِي مَرْيَمَ حَدَّثَنَا مُحَمَّدٌ يَعْنِي ابْنَ مُطَرِّفٍ كُلُّهُمْ عَنْ أَبِي حَازِمٍ عَنْ سَهْلِ بْنِ سَعْدٍ بِهَذَا الْحَدِيثِ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي حَدِيثِ ابْنِ أَبِي هِلَالٍ أُصِيبَ وَجْهُهُ وَفِي حَدِيثِ ابْنِ مُطَرِّفٍ جُرِحَ وَجْهُهُ","id":"Telah menceritakan kepada kami [Yahya bin Yahya At Tamimi] telah menceritakan kepada kami [Abdul Aziz bin Abu Hazim] dari [ayahnya] bahwa dia mendengar [Sahl bin Sa'id] ditanya seseorang mengenai luka yang pernah diderita Rasulullah shallallahu 'alaihi wasallam dalam pertempuran Uhud, maka dia menjawab, \"Rasulullah shallallahu 'alaihi wasallam terluka, gigi taringnya patah, dan topi baja yang bliau kenakan juga pecah. Lalu Fatimah binti Rasulullah shallallahu 'alaihi wasallam membersihkan darah beliau, sedangkan Ali menyiramkan air dari perisai. Ketika Fatimah melihat darah semakin bertambah banyak keluar, dia mengambil potongan pelepah kurma lalu dia bakar hingga menjadi abu, kemudian abu tersebut diletakkan di atas luka beliau hingga darahnya berhenti keluar.\" Telah menceritakan kepada kami [Qutaibah bin Sa'id] telah menceritakan kepada kami [Ya'qub] -yaitu Ibnu Abdurrahman Al Qari- dari [Abu Hazim] bahwa dia mendengar [Sahl bin Sa'id] ditanya mengenai luka Rasulullah shallallahu 'alaihi wasallam, maka dia menjawab, \"Demi Allah, sungguh aku telah melihat sendiri orang yang mencuci luka Rasulullah shallallahu 'alaihi wasallam dan yang menuangkan air, serta dengan apa dia mengobati luka beliau...kemudian dia menyebutkan seperti haditsnya Abdul Aziz, namun dia menambahkan, 'dan wajahnya terluka' dia juga menyebtkan, 'giginya pecah'.\" Dan telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] dan [Zuhair bin Harb] dan [Ishaq bin Ibrahim] serta [Ibnu Abu Umar] semuanya dari [Ibnu Uyainah]. (dalam jalur lain disebutkan) Telah menceritakan kepada kami ['Amru bin Sawad Al 'Amiri] telah mengabarkan kepada kami [Abdullah bin Wahb] telah mengabarkan kepadaku ['Amru bin Al Harits] dari [Sa'id bin Abu Hilal]. (dalam jalur lain disebutkan) Telah menceritakan kepadaku [Muhammad bin Sahl At Tamimi] telah menceritakan kepadaku [Ibnu Abu Maryam] telah menceritakan kepada kami [Muhammad] -yaitu Ibnu Mutharrif- semuanya dari [Abu Hazim] dari [Sahl bin Sa'id] dengan hadits ini dari Nabi shallallahu 'alaihi wasallam. Dalam hadits Ibnu Abu Hilal disebutkan, 'wajah beliau terkena', sedangkan dalam hadits Ibnu Mutharif disebutkan, 'wajah beliau terluka.'"},"3113":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ مَسْلَمَةَ بْنِ قَعْنَبٍ حَدَّثَنَا حَمَّادُ بْنُ سَلَمَةَ عَنْ ثَابِتٍ عَنْ أَنَسٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كُسِرَتْ رَبَاعِيَتُهُ يَوْمَ أُحُدٍ وَشُجَّ فِي رَأْسِهِ فَجَعَلَ يَسْلُتُ الدَّمَ عَنْهُ وَيَقُولُ كَيْفَ يُفْلِحُ قَوْمٌ شَجُّوا نَبِيَّهُمْ وَكَسَرُوا رَبَاعِيَتَهُ وَهُوَ يَدْعُوهُمْ إِلَى اللَّهِ فَأَنْزَلَ اللَّهُ عَزَّ وَجَلَّ{ لَيْسَ لَكَ مِنْ الْأَمْرِ شَيْءٌ }","id":"Telah menceritakan kepada kami [Abdullah bin Maslamah bin Qa'nab] telah menceritakan kepada kami [Hammad bin Salamah] dari [Tsabit] dari [Anas], bahwa gigi geraham Rasulullah shallallahu 'alaihi wasallam pecah ketika perang Uhud, dan kepala beliau juga terluka hingga mengalirkan darah, beliau lalu bersabda: \"Bagaimana mungkin suatu kaum akan beruntung, sedangkan mereka melukai nabinya dan mematahkan gigi gerahamnya.\" Oleh karena itu beliau memohon kepada Allah untuk mengutuk mereka, lalu Allah Azza wa jalla menurunkan ayat: '(Kamu tidak memiliki wewenang apa-apa terhadap urusan mereka…) ' (Qs. Ali Imran: 128)."},"3114":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ عَبْدِ اللَّهِ بْنِ نُمَيْرٍ حَدَّثَنَا وَكِيعٌ حَدَّثَنَا الْأَعْمَشُ عَنْ شَقِيقٍ عَنْ عَبْدِ اللَّهِ قَالَكَأَنِّي أَنْظُرُ إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَحْكِي نَبِيًّا مِنْ الْأَنْبِيَاءِ ضَرَبَهُ قَوْمُهُ وَهُوَ يَمْسَحُ الدَّمَ عَنْ وَجْهِهِ وَيَقُولُ رَبِّ اغْفِرْ لِقَوْمِي فَإِنَّهُمْ لَا يَعْلَمُونَحَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا وَكِيعٌ وَمُحَمَّدُ بْنُ بِشْرٍ عَنْ الْأَعْمَشِ بِهَذَا الْإِسْنَادِ غَيْرَ أَنَّهُ قَالَ فَهُوَ يَنْضِحُ الدَّمَ عَنْ جَبِينِهِ","id":"Telah menceritakan kepada kami [Muhammad bin Abdullah bin Numair] telah menceritakan kepada kami [Waki'] telah menceritakan kepada kami [Al A'masy] dari [Syaqiq] dari [Abdullah] dia berkata, \"Aku seakan-akan masih melihat Rasulullah shallallahu 'alaihi wasallam menceritakan seorang Nabi dari para Nabi yang dilukai oleh kaumnya, lalu beliau mengusap darah dari mukanya sambil mengatakan: \"Wahai Rabbku, ampunilah kaumku, karena mereka tidak mengetahui.\" Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] telah menceritakan kepada kami [Waki'] dan [Muhammad bin Bisyr] dari [Al A'masy] dengan isnad ini, namun dia menyebutkan, \"Dan beliau mengusap darah yang mengalir di pelipisnya.\""},"3115":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ رَافِعٍ حَدَّثَنَا عَبْدُ الرَّزَّاقِ حَدَّثَنَا مَعْمَرٌ عَنْ هَمَّامِ بْنِ مُنَبِّهٍ قَالَ هَذَا مَا حَدَّثَنَا أَبُو هُرَيْرَةَ عَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَذَكَرَ أَحَادِيثَ مِنْهَاوَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ اشْتَدَّ غَضَبُ اللَّهِ عَلَى قَوْمٍ فَعَلُوا هَذَا بِرَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَهُوَ حِينَئِذٍ يُشِيرُ إِلَى رَبَاعِيَتِهِ وَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ اشْتَدَّ غَضَبُ اللَّهِ عَلَى رَجُلٍ يَقْتُلُهُ رَسُولُ اللَّهِ فِي سَبِيلِ اللَّهِ عَزَّ وَجَلَّ","id":"Telah menceritakan kepada kami [Muhammad bin Rafi'] telah menceritakan kepada kami [Abdurrazaq] telah menceritakan kepada kami [Ma'mar] dari [Hammam bin Munabbih] dia berkata, \"Ini seperti sesuatu yang pernah diceritakan oleh [Abu Hurairah] kepada kami dari Rasulullah shallallahu 'alaihi wasallam, kemudian dia menyebutkan di antaranya, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Allah sangat marah terhadap suatu kaum yang melakukan perbuatan ini terhadap Rasulullah shallallahu 'alaihi wasallam.\" Dan ketika itu beliau sambil menunjuk taringnya yang patah. Dan beliau juga bersabda: \"Allah sangat marah terhadap orang yang dibunuh Rasulullah shallallahu 'alaihi wasallam dalam perang fi sabilillah Azza Wa Jalla.\""},"3116":{"ar":"و حَدَّثَنَا عَبْدُ اللَّهِ بْنُ عُمَرَ بْنِ مُحَمَّدِ بْنِ أَبَانَ الْجُعْفِيُّ حَدَّثَنَا عَبْدُ الرَّحِيمِ يَعْنِي ابْنَ سُلَيْمَانَ عَنْ زَكَرِيَّاءَ عَنْ أَبِي إِسْحَقَ عَنْ عَمْرِو بْنِ مَيْمُونٍ الْأَوْدِيِّ عَنْ ابْنِ مَسْعُودٍ قَالَبَيْنَمَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُصَلِّي عِنْدَ الْبَيْتِ وَأَبُو جَهْلٍ وَأَصْحَابٌ لَهُ جُلُوسٌ وَقَدْ نُحِرَتْ جَزُورٌ بِالْأَمْسِ فَقَالَ أَبُو جَهْلٍ أَيُّكُمْ يَقُومُ إِلَى سَلَا جَزُورِ بَنِي فُلَانٍ فَيَأْخُذُهُ فَيَضَعُهُ فِي كَتِفَيْ مُحَمَّدٍ إِذَا سَجَدَ فَانْبَعَثَ أَشْقَى الْقَوْمِ فَأَخَذَهُ فَلَمَّا سَجَدَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَضَعَهُ بَيْنَ كَتِفَيْهِ قَالَ فَاسْتَضْحَكُوا وَجَعَلَ بَعْضُهُمْ يَمِيلُ عَلَى بَعْضٍ وَأَنَا قَائِمٌ أَنْظُرُ لَوْ كَانَتْ لِي مَنَعَةٌ طَرَحْتُهُ عَنْ ظَهْرِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَالنَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ سَاجِدٌ مَا يَرْفَعُ رَأْسَهُ حَتَّى انْطَلَقَ إِنْسَانٌ فَأَخْبَرَ فَاطِمَةَ فَجَاءَتْ وَهِيَ جُوَيْرِيَةٌ فَطَرَحَتْهُ عَنْهُ ثُمَّ أَقْبَلَتْ عَلَيْهِمْ تَشْتِمُهُمْ فَلَمَّا قَضَى النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ صَلَاتَهُ رَفَعَ صَوْتَهُ ثُمَّ دَعَا عَلَيْهِمْ وَكَانَ إِذَا دَعَا دَعَا ثَلَاثًا وَإِذَا سَأَلَ سَأَلَ ثَلَاثًا ثُمَّ قَالَ اللَّهُمَّ عَلَيْكَ بِقُرَيْشٍ ثَلَاثَ مَرَّاتٍ فَلَمَّا سَمِعُوا صَوْتَهُ ذَهَبَ عَنْهُمْ الضِّحْكُ وَخَافُوا دَعْوَتَهُ ثُمَّ قَالَ اللَّهُمَّ عَلَيْكَ بِأَبِي جَهْلِ بْنِ هِشَامٍ وَعُتْبَةَ بْنِ رَبِيعَةَ وَشَيْبَةَ بْنِ رَبِيعَةَ وَالْوَلِيدِ بْنِ عُقْبَةَ وَأُمَيَّةَ بْنِ خَلَفٍ وَعُقْبَةَ بْنِ أَبِي مُعَيْطٍ وَذَكَرَ السَّابِعَ وَلَمْ أَحْفَظْهُ فَوَالَّذِي بَعَثَ مُحَمَّدًا صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِالْحَقِّ لَقَدْ رَأَيْتُ الَّذِينَ سَمَّى صَرْعَى يَوْمَ بَدْرٍ ثُمَّ سُحِبُوا إِلَى الْقَلِيبِ قَلِيبِ بَدْرٍقَالَ أَبُو إِسْحَقَ الْوَلِيدُ بْنُ عُقْبَةَ غَلَطٌ فِي هَذَا الْحَدِيثِ","id":"Dan telah menceritakan kepada kami [Abdullah bin Umar bin Muhammad bin Aban Al Ja'fi] telah menceritakan kepada kami [Abdurrahim] -yaitu Ibnu Sulaiman- dari [Zakaria] dari [Abu Ishaq] dari ['Amru bin Maimun Al Audi] dari [Ibnu Mas'ud] dia berkata, \"Ketika Rasulullah shallallahu 'alaihi wasallam shalat dekat Ka'bah, Abu Jahal dan kawan-kawannya sedang duduk-duduk, sementara ada bekas unta yang disembelih pada hari sebelumnya. Abu Jahal berkata, \"Siapa di antara kalian yang sanggup mengambil perut unta sembelihan bani Fulan itu, lalu meletakkannya di bahu Muhammad apabila dia sujud.\" Dan orang yang paling jahat di antara mereka pergi mengambil isi perut unta tersebut, ketika Nabi shallallahu 'alaihi wasallam sujud, dia meletakkannya di bahu beliau.\" Ibnu Mas'ud berkata, \"Setelah itu mereka tertawa terbahak-bahak, dan dorong-mendorong antara satu sama lain. Aku berdiri saja melihat peristiwa tersebut. Sekiranya aku anggup, tentu aku akan membuang isi perut unta tersebut dari sisi Rasulullah shallallahu 'alaihi wasallam, Nabi shallallahu 'alaihi wasallam terus saja sujud, beliau tidak mengangkat kepalanya hingga ada orang yang lewat, lalu orang tersebut memberitahukannya kepada Fathimah -ketika itu dia masih gadis kecil-. Fatimah datang dan membuang isi perut unta itu dari punggung beliau, sesudah itu Fatimah menghampiri mereka dan memaki-makinya. Seusainya Nabi shallallahu 'alaihi wasallam shalat, beliau mengeraskan suaranya dan mendo'akan kejelekan terhadap mereka. Apabila beliau berdo'a, biasanya beliau mengulanginya sampai tiga kali, dan apabila beliau meminta, beliau juga mengucapkan tiga kali, kemudian beliau berucap: \"Allahumma 'alaika bi Quraisy (Ya Allah, binasakanlah orang-orang Quraisy).\" Beliau mengucapkannya tiga kali. Tatkala mereka mendengar suara beliau, mereka berhenti tertawa dan merasa khawatir dengan do'a beliau, kemudian beliau melanjutkan do'anya: \"ALLAHUMMA 'ALAIKA BI ABI JAHAL BIN HISYAM, WA 'UTBAH BIN RABI'AH WA SYAIBAH BIN RABI'AH WA WALID BIN 'UQBAH WA 'UMAYYAH BIN KHALAF WA 'UQBAH BIN ABI MU'ITH.\" (Ya Allah, binasakanlah Abu Jahal bin Hisyam, 'Utbah bin Rabi'ah, Syaibah bin Rabi'ah, Walid bin 'Uqbah, 'Umayyah bin Khalaf dan 'Uqbah bin Abu Mu'ith).\" -Ibnu Mas'ud menyebutkan yang ketujuh, namun perawi lupa namanya- Maka demi dzat yang telah mengutus Muhammad shallallahu 'alaihi wasallam dengan kebenaran, sungguh aku telah melihat orang-orang yang namanya disebut oleh beliau, mereka mati tergeletak dalam perang Badar. Kemudian mereka diseret ke sumur Badar.\" Abu Ishaq berkata, \"Al Walid bin 'Uqbah masih ada kekeliruan dalam hadits ini.\""},"3117":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ الْمُثَنَّى وَمُحَمَّدُ بْنُ بَشَّارٍ وَاللَّفْظُ لِابْنِ الْمُثَنَّى قَالَا حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ حَدَّثَنَا شُعْبَةُ قَالَ سَمِعْتُ أَبَا إِسْحَقَ يُحَدِّثُ عَنْ عَمْرِو بْنِ مَيْمُونٍ عَنْ عَبْدِ اللَّهِ قَالَبَيْنَمَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ سَاجِدٌ وَحَوْلَهُ نَاسٌ مِنْ قُرَيْشٍ إِذْ جَاءَ عُقْبَةُ بْنُ أَبِي مُعَيْطٍ بِسَلَا جَزُورٍ فَقَذَفَهُ عَلَى ظَهْرِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَلَمْ يَرْفَعْ رَأْسَهُ فَجَاءَتْ فَاطِمَةُ فَأَخَذَتْهُ عَنْ ظَهْرِهِ وَدَعَتْ عَلَى مَنْ صَنَعَ ذَلِكَ فَقَالَ اللَّهُمَّ عَلَيْكَ الْمَلَأَ مِنْ قُرَيْشٍ أَبَا جَهْلِ بْنَ هِشَامٍ وَعُتْبَةَ بْنَ رَبِيعَةَ وَعُقْبَةَ بْنَ أَبِي مُعَيْطٍ وَشَيْبَةَ بْنَ رَبِيعَةَ وَأُمَيَّةَ بْنَ خَلَفٍ أَوْ أُبَيَّ بْنَ خَلَفٍ شُعْبَةُ الشَّاكُّ قَالَ فَلَقَدْ رَأَيْتُهُمْ قُتِلُوا يَوْمَ بَدْرٍ فَأُلْقُوا فِي بِئْرٍ غَيْرَ أَنَّ أُمَيَّةَ أَوْ أُبَيًّا تَقَطَّعَتْ أَوْصَالُهُ فَلَمْ يُلْقَ فِي الْبِئْرِو حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا جَعْفَرُ بْنُ عَوْنٍ أَخْبَرَنَا سُفْيَانُ عَنْ أَبِي إِسْحَقَ بِهَذَا الْإِسْنَادِ نَحْوَهُ وَزَادَ وَكَانَ يَسْتَحِبُّ ثَلَاثًا يَقُولُ اللَّهُمَّ عَلَيْكَ بِقُرَيْشٍ اللَّهُمَّ عَلَيْكَ بِقُرَيْشٍ اللَّهُمَّ عَلَيْكَ بِقُرَيْشٍ ثَلَاثًا وَذَكَرَ فِيهِمْ الْوَلِيدَ بْنَ عُتْبَةَ وَأُمَيَّةَ بْنَ خَلَفٍ وَلَمْ يَشُكَّ قَالَ أَبُو إِسْحَقَ وَنَسِيتُ السَّابِعَ","id":"Telah menceritakan kepada kami [Muhammad bin Al Mutsanna] dan [Muhammad bin Basyar] sedangkan lafadznya dari Ibnu Mutsanna keduanya berkata; telah menceritakan kepada kami [Muhammad bin Ja'far] telah menceritakan kepada kami [Syu'bah] dia berkata; aku mendengar [Abu Ishaq] menceritakan dari ['Amru bin Maimun] dari [Abdullah] dia berkata, \"Pada suatu ketika Rasulullah shallallahu 'alaihi wasallam sedang sujud, sementara di sekitar beliau ada beberapa orang Quraisy, tiba-tiba 'Uqbah bin Abu Mu'th datang dengan membawa sekarung bekas sembilhan anak unta yang telah membusuk, lalu ia melemparnya tepat mengenai punggung Rasulullah shallallahu 'alaihi wasallam, karena itu beliau tidak mau mengangkat kepalanya. Setelah Fatimah datang, maka dia mengambil karung tersebut dari punggung beliau. Lantas beliau mendo'akan kebinasaan terhadap orang-orang yang telah melakukan perbuatan tersebut, beliau bersabda: \"Ya Allah, binasakanlah orang-orang Quraisy; Abu Jahal bin Hisyam, 'Utbah bin Rabi'ah, 'Uqbah bin Abu Mu'ith, Syaibah bin Rabi'ah, Umayyah bin Khalaf dan Ubay bin Khalaf.\" Sungguh aku telah melihat dalam perang Badar, mereka semua binasa, lalu jasad mereka dilemparkan ke dalam sumur selain Umayah atau mungkin Ubay, karena persendiannya banyak yang putus, maka ia tidak dilemparkan ke dalam sumur.\" Dan telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] telah menceritakan kepada kami [Ja'far bin 'Aun] telah mengabarkan kepada kami [Sufyan] dari [Abu Ishaq] dengan isnad seperti ini, dengan sedikit tambahan, \"Apabila beliau berdo'a, beliau lebih suka mengulanginya sampai tiga kali, beliau bersabda: \"Ya Allah, binasakanlah orang-orang Quraisy, Ya Allah, binasakanlah orang-orang Quraisy, Ya Allah, binasakanlah orang-orang Quraisy -hingga tiga kali-.\" Dan dia menyebutkan dalam hadits tersebut nama 'Al Walid bin 'Utbah dan Umayyah bin Khalaf - tanpa ada keragu-raguan-, Abu Ishaq berkata, \"Dan aku lupa yang ketujuh.\""},"3118":{"ar":"و حَدَّثَنِي سَلَمَةُ بْنُ شَبِيبٍ حَدَّثَنَا الْحَسَنُ بْنُ أَعْيَنَ حَدَّثَنَا زُهَيْرٌ حَدَّثَنَا أَبُو إِسْحَقَ عَنْ عَمْرِو بْنِ مَيْمُونٍ عَنْ عَبْدِ اللَّهِ قَالَاسْتَقْبَلَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْبَيْتَ فَدَعَا عَلَى سِتَّةِ نَفَرٍ مِنْ قُرَيْشٍ فِيهِمْ أَبُو جَهْلٍ وَأُمَيَّةُ بْنُ خَلَفٍ وَعُتْبَةُ بْنُ رَبِيعَةَ وَشَيْبَةُ بْنُ رَبِيعَةَ وَعُقْبَةُ بْنُ أَبِي مُعَيْطٍ فَأُقْسِمُ بِاللَّهِ لَقَدْ رَأَيْتُهُمْ صَرْعَى عَلَى بَدْرٍ قَدْ غَيَّرَتْهُمْ الشَّمْسُ وَكَانَ يَوْمًا حَارًّا","id":"Dan telah menceritakan kepadaku [Salamah bin Syabib] telah menceritakan kepada kami [Al Hasan bin A'yan] telah menceritakan kepada kami [Zuhair] telah menceritakan kepada kami [Abu Ishaq] dari ['Amru bin Maimun] dari [Abdullah] dia berkata, \"Rasulullah shallallahu 'alaihi wasallam pernah mendo'akan kebinasaan kepada enam tokoh Quraisy dengan menghadap ke Ka'bah, di natara mereka adalah Abu Jahal, Umayyah bin Khalaf, 'Utbah bin Rabi'ah, Syaibah bin Rabi'ah dan 'Uqbah bin Abu Mu'ith. Demi Allah, sungguh aku telah melihat mereka tewas bergelimpangan di Badar di bawah terik Matahari yang sangat panas.\""},"3119":{"ar":"و حَدَّثَنِي أَبُو الطَّاهِرِ أَحْمَدُ بْنُ عَمْرِو بْنِ سَرْحٍ وَحَرْمَلَةُ بْنُ يَحْيَى وَعَمْرُو بْنُ سَوَّادٍ الْعَامِرِيُّ وَأَلْفَاظُهُمْ مُتَقَارِبَةٌ قَالُوا حَدَّثَنَا ابْنُ وَهْبٍ قَالَ أَخْبَرَنِي يُونُسُ عَنْ ابْنِ شِهَابٍ حَدَّثَنِي عُرْوَةُ بْنُ الزُّبَيْرِ أَنَّ عَائِشَةَ زَوْجَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حَدَّثَتْهُأَنَّهَا قَالَتْ لِرَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَا رَسُولَ اللَّهِ هَلْ أَتَى عَلَيْكَ يَوْمٌ كَانَ أَشَدَّ مِنْ يَوْمِ أُحُدٍ فَقَالَ لَقَدْ لَقِيتُ مِنْ قَوْمِكِ وَكَانَ أَشَدَّ مَا لَقِيتُ مِنْهُمْ يَوْمَ الْعَقَبَةِ إِذْ عَرَضْتُ نَفْسِي عَلَى ابْنِ عَبْدِ يَالِيلَ بْنِ عَبْدِ كُلَالٍ فَلَمْ يُجِبْنِي إِلَى مَا أَرَدْتُ فَانْطَلَقْتُ وَأَنَا مَهْمُومٌ عَلَى وَجْهِي فَلَمْ أَسْتَفِقْ إِلَّا بِقَرْنِ الثَّعَالِبِ فَرَفَعْتُ رَأْسِي فَإِذَا أَنَا بِسَحَابَةٍ قَدْ أَظَلَّتْنِي فَنَظَرْتُ فَإِذَا فِيهَا جِبْرِيلُ فَنَادَانِي فَقَالَ إِنَّ اللَّهَ عَزَّ وَجَلَّ قَدْ سَمِعَ قَوْلَ قَوْمِكَ لَكَ وَمَا رُدُّوا عَلَيْكَ وَقَدْ بَعَثَ إِلَيْكَ مَلَكَ الْجِبَالِ لِتَأْمُرَهُ بِمَا شِئْتَ فِيهِمْ قَالَ فَنَادَانِي مَلَكُ الْجِبَالِ وَسَلَّمَ عَلَيَّ ثُمَّ قَالَ يَا مُحَمَّدُ إِنَّ اللَّهَ قَدْ سَمِعَ قَوْلَ قَوْمِكَ لَكَ وَأَنَا مَلَكُ الْجِبَالِ وَقَدْ بَعَثَنِي رَبُّكَ إِلَيْكَ لِتَأْمُرَنِي بِأَمْرِكَ فَمَا شِئْتَ إِنْ شِئْتَ أَنْ أُطْبِقَ عَلَيْهِمْ الْأَخْشَبَيْنِ فَقَالَ لَهُ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بَلْ أَرْجُو أَنْ يُخْرِجَ اللَّهُ مِنْ أَصْلَابِهِمْ مَنْ يَعْبُدُ اللَّهَ وَحْدَهُ لَا يُشْرِكُ بِهِ شَيْئًا","id":"Dan telah menceritakan kepadaku [Abu At Thahir Ahmad bin 'Amru bin Sarh] dan [Harmalah bin Yahya] serta ['Amru bin Sawad Al 'Amiri], sedangkan lafadz mereka saling berdekatan, mereka berkata; telah menceritakan kepada kami [Ibnu Wahb] dia berkata; telah mengabarkan kepadaku [Yunus] dari [Ibnu Syihab] telah menceritakan kepadaku ['Urwah bin Zubair] bahwa ['Aisyah] isteri Nabi shallallahu 'alaihi wasallam, telah menceritakan kepadanya bahwa suatu ketika ia pernah berkata kepada Rasulullah shallallahu 'alaihi wasallam, \"Wahai Rasulullah, pernahkah anda merasakan kesulitan yang paling sulit daripada hari perang uhud?\" Beliau menjawab: \"Aku pernah mengalami kesulitan dari kaummu, dan itulah kesulitan yang paling sulit yang pernah ku alamai dari mereka, yaitu peristiwa di hari 'aqabah. Ketika itu aku mendatangi Ibnu 'Abd Yaaliil bin 'Abd Kulal, tapi ia tidak mau memenuhi harapanku sehingga aku pergi meninggalkannya dengan penuh kecemasan, dan aku baru sadarkan diri ketika aku sampai di Qarnits Tsa'alib. Lalu aku mendongakkan kepalaku dan ternyata aku sedang dinaungi oleh awan, setelah kuperhatikan, ternyata malaikat Jibril ada di sana. dia memanggilku dan berkata: 'Sesungguhnya Allah 'azza wajalla telah mendengar perkataan kaummu terhadapmu dan penolakan mereka terhadap ajakanmu. Dan Dia telah mengutus malaikat penjaga gunung agar anda dapat menyuruhnya untuk menghancurkan mereka sekehendak hatimu'.\" Beliau bersabda: \"Lalu malaikat penjaga gunungpun memanggilku dan mengucap salam kepadaku sambil berkata: 'Wahai Muhammad, Sungguh Allah telah mendengar perkataan kaummu terhadapmu, dan aku malaikat penjaga gunung telah diutus oleh Rabbmu untuk menemuimu guna melaksanakan apa yang anda kehendaki. Jika anda menghendaki, maka aku akan menutupkan dua gunung ini kepada mereka'.\" Rasulullah shallallahu 'alaihi wasallam bersabda kepadanya: \"Bahkan aku sangat berharap semoga Allah mengeluarkan dari tulang-tulang sulbi mereka orang yang mau beribadah kepada Allah dan tidak menyekutukan-Nya dengan sesuatupun.\""},"3120":{"ar":"حَدَّثَنَا يَحْيَى بْنُ يَحْيَى وَقُتَيْبَةُ بْنُ سَعِيدٍ كِلَاهُمَا عَنْ أَبِي عَوَانَةَ قَالَ يَحْيَى أَخْبَرَنَا أَبُو عَوَانَةَ عَنْ الْأَسْوَدِ بْنِ قَيْسٍ عَنْ جُنْدُبِ بْنِ سُفْيَانَ قَالَدَمِيَتْ إِصْبَعُ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي بَعْضِ تِلْكَ الْمَشَاهِدِ فَقَالَ هَلْ أَنْتِ إِلَّا إِصْبَعٌ دَمِيتِوَفِي سَبِيلِ اللَّهِ مَا لَقِيتِو حَدَّثَنَاه أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ وَإِسْحَقُ بْنُ إِبْرَاهِيمَ جَمِيعًا عَنْ ابْنِ عُيَيْنَةَ عَنْ الْأَسْوَدِ بْنِ قَيْسٍ بِهَذَا الْإِسْنَادِ وَقَالَ كَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي غَارٍ فَنُكِبَتْ إِصْبَعُهُ","id":"Telah menceritakan kepada kami [Yahya bin Yahya] dan [Qutaibah bin Sa'id] keduanya dari [Abu 'Awanah], [Yahya] berkata; telah mengabarkan kepada kami [Abu 'Awanah] dari [Al Aswad bin Qais] dari [Jundub bin Sufyan] dia berkata, \"Jari Rasulullah shallallahu 'alaihi wasallam pernah terluka dalam suatu peperangan, maka beliau bersabda: \"Bukankah engkau hanya sebatang jari yang berdarah? Dan ini terjadi ketika engkau ikut berjihad fi sabilillah.\" Dan telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] dan [Ishaq bin Ibrahim] semuanya dari [Ibnu 'Uyainah] dari [Al Aswad bin Qais] dengan isnad ini, dia berkata, \"Rasulullah shallallahu 'alaihi wasallam pernah masuk ke dalam goa, tiba-tiba salah satu jari beliau mengalirkan darah.\""},"3121":{"ar":"حَدَّثَنَا إِسْحَقُ بْنُ إِبْرَاهِيمَ أَخْبَرَنَا سُفْيَانُ عَنْ الْأَسْوَدِ بْنِ قَيْسٍ أَنَّهُ سَمِعَ جُنْدُبًا يَقُولُاأَبْطَأَ جِبْرِيلُ عَلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ الْمُشْرِكُونَ قَدْ وُدِّعَ مُحَمَّدٌ فَأَنْزَلَ اللَّهُ عَزَّ وَجَلَّ{ وَالضُّحَى وَاللَّيْلِ إِذَا سَجَى مَا وَدَّعَكَ رَبُّكَ وَمَا قَلَى }","id":"Telah menceritakan kepada kami [Ishaq bin Ibrahim] telah mengabarkan kepada kami [Sufyan] dari [Al Aswad bin Qais] bahwa dia mendengar [Jundub] berkata, \"Jibril terlambat datang kepada Rasulullah shallallahu 'alaihi wasallam, lalu orang-orang Musyrik berkata, \"Muhammad telah ditinggalkannya.\" Maka Allah Azza Wa Jalla menurunkan ayat: '(Demi waktu Dluha, dan demi malam apabila telah sunyi, Rabbmu tiada mennggalkanmu dan tiada benci terhadapmu) ' (Qs. Adl Dluha: 1-3)."},"3122":{"ar":"حَدَّثَنَا إِسْحَقُ بْنُ إِبْرَاهِيمَ وَمُحَمَّدُ بْنُ رَافِعٍ وَاللَّفْظُ لِابْنِ رَافِعٍ قَالَ إِسْحَقُ أَخْبَرَنَا و قَالَ ابْنُ رَافِعٍ حَدَّثَنَا يَحْيَى بْنُ آدَمَ حَدَّثَنَا زُهَيْرٌ عَنْ الْأَسْوَدِ بْنِ قَيْسٍ قَالَ سَمِعْتُ جُنْدُبَ بْنَ سُفْيَانَ يَقُولُااشْتَكَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَلَمْ يَقُمْ لَيْلَتَيْنِ أَوْ ثَلَاثًا فَجَاءَتْهُ امْرَأَةٌ فَقَالَتْ يَا مُحَمَّدُ إِنِّي لَأَرْجُو أَنْ يَكُونَ شَيْطَانُكَ قَدْ تَرَكَكَ لَمْ أَرَهُ قَرِبَكَ مُنْذُ لَيْلَتَيْنِ أَوْ ثَلَاثٍ قَالَ فَأَنْزَلَ اللَّهُ عَزَّ وَجَلَّ{ وَالضُّحَى وَاللَّيْلِ إِذَا سَجَى مَا وَدَّعَكَ رَبُّكَ وَمَا قَلَى }و حَدَّثَنَا أَبُو بَكْرِ بْنِ أَبِي شَيْبَةَ وَمُحَمَّدُ بْنُ الْمُثَنَّى وَابْنُ بَشَّارٍ قَالُوا حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ عَنْ شُعْبَةَ ح و حَدَّثَنَا إِسْحَقُ بْنُ إِبْرَاهِيمَ أَخْبَرَنَا الْمُلَائِيُّ حَدَّثَنَا سُفْيَانُ كِلَاهُمَا عَنْ الْأَسْوَدِ بْنِ قَيْسٍ بِهَذَا الْإِسْنَادِ نَحْوَ حَدِيثِهِمَا","id":"Telah menceritakan kepada kami [Ishaq bin Ibrahim] dan [Muhammad bin Rafi'] sedangkan lafadznya dari Ibnu Rafi'. [Ishaq] berkata; telah mengabarkan kepada kami, sedangkan [Ibnu Rafi'] mengatakan; telah menceritakan kepada kami [Yahya bin Adam] telah menceritakan kepada kami [Zuhair] dari [Al Aswad bin Qais] dia berkata; aku mendengar [Jundub bin Sufyan] berkata, \"Rasulullah shallallahu 'alaihi wasallam pernah mengalami sakit, oleh karena itu beliau tidak kuat bangun untuk melaksanakan shalat selama dua atau tiga hari, maka seorang perempuan datang kepada beliau lalu berkata, \"Ya Muhammad, aku berharap mudah-mudahan setanmu betul-betul telah meninggalkanmu. Telah dua malam atau tiga malam aku tidak melihatnya menghampirimu. Maka Allah Azza Wa Jalla menurunkan ayat: '(Demi waktu Dluha, dan demi malam apabila telah sunyi, Rabbmu tiada mennggalkanmu dan tiada benci terhadapmu) ' (Qs. Adl Dluha; 1-3). Dan telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] dan [Muhammad bin Al Mutsanna] serta [Ibnu Basyar] mereka mengatakan; telah menceritakan kepada kami [Muhammad bin Ja'far] dari [Syu'bah]. (dalam jalur lain disebutkan) Telah menceritakan kepada kami [Ishaq bin Ibrahim] telah mengabarkan kepada kami [Al Mula`i] telah menceritakan kepada kami [Sufyan] keduanya dari [Al Aswad bin Qais] dengan isnad ini seperti kedits keduanya.\""},"3123":{"ar":"حَدَّثَنَا إِسْحَقُ بْنُ إِبْرَاهِيمَ الْحَنْظَلِيُّ وَمُحَمَّدُ بْنُ رَافِعٍ وَعَبْدُ بْنُ حُمَيْدٍ وَاللَّفْظُ لِابْنِ رَافِعٍ قَالَ ابْنُ رَافِعٍ حَدَّثَنَا و قَالَ الْآخَرَانِ أَخْبَرَنَا عَبْدُ الرَّزَّاقِ أَخْبَرَنَا مَعْمَرٌ عَنْ الزُّهْرِيِّ عَنْ عُرْوَةَ أَنَّ أُسَامَةَ بْنَ زَيْدٍ أَخْبَرَهُأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ رَكِبَ حِمَارًا عَلَيْهِ إِكَافٌ تَحْتَهُ قَطِيفَةٌ فَدَكِيَّةٌ وَأَرْدَفَ وَرَاءَهُ أُسَامَةَ وَهُوَ يَعُودُ سَعْدَ بْنَ عُبَادَةَ فِي بَنِي الْحَارِثِ بْنِ الْخَزْرَجِ وَذَاكَ قَبْلَ وَقْعَةِ بَدْرٍ حَتَّى مَرَّ بِمَجْلِسٍ فِيهِ أَخْلَاطٌ مِنْ الْمُسْلِمِينَ وَالْمُشْرِكِينَ عَبَدَةِ الْأَوْثَانِ وَالْيَهُودِ فِيهِمْ عَبْدُ اللَّهِ بْنُ أُبَيٍّ وَفِي الْمَجْلِسِ عَبْدُ اللَّهِ بْنُ رَوَاحَةَ فَلَمَّا غَشِيَتْ الْمَجْلِسَ عَجَاجَةُ الدَّابَّةِ خَمَّرَ عَبْدُ اللَّهِ بْنُ أُبَيٍّ أَنْفَهُ بِرِدَائِهِ ثُمَّ قَالَ لَا تُغَبِّرُوا عَلَيْنَا فَسَلَّمَ عَلَيْهِمْ النَّبِيُّ صَلَّى اللَّهُ عَلَ��ْهِ وَسَلَّمَ ثُمَّ وَقَفَ فَنَزَلَ فَدَعَاهُمْ إِلَى اللَّهِ وَقَرَأَ عَلَيْهِمْ الْقُرْآنَ فَقَالَ عَبْدُ اللَّهِ بْنُ أُبَيٍّ أَيُّهَا الْمَرْءُ لَا أَحْسَنَ مِنْ هَذَا إِنْ كَانَ مَا تَقُولُ حَقًّا فَلَا تُؤْذِنَا فِي مَجَالِسِنَا وَارْجِعْ إِلَى رَحْلِكَ فَمَنْ جَاءَكَ مِنَّا فَاقْصُصْ عَلَيْهِ فَقَالَ عَبْدُ اللَّهِ بْنُ رَوَاحَةَ اغْشَنَا فِي مَجَالِسِنَا فَإِنَّا نُحِبُّ ذَلِكَ قَالَ فَاسْتَبَّ الْمُسْلِمُونَ وَالْمُشْرِكُونَ وَالْيَهُودُ حَتَّى هَمُّوا أَنْ يَتَوَاثَبُوا فَلَمْ يَزَلْ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُخَفِّضُهُمْ ثُمَّ رَكِبَ دَابَّتَهُ حَتَّى دَخَلَ عَلَى سَعْدِ بْنِ عُبَادَةَ فَقَالَ أَيْ سَعْدُ أَلَمْ تَسْمَعْ إِلَى مَا قَالَ أَبُو حُبَابٍ يُرِيدُ عَبْدَ اللَّهِ بْنَ أُبَيٍّ قَالَ كَذَا وَكَذَا قَالَ اعْفُ عَنْهُ يَا رَسُولَ ال��َّهِ وَاصْفَحْ فَوَاللَّهِ لَقَدْ أَعْطَاكَ اللَّهُ الَّذِي أَعْطَاكَ وَلَقَدْ اصْطَلَحَ أَهْلُ هَذِهِ الْبُحَيْرَةِ أَنْ يُتَوِّجُوهُ فَيُعَصِّبُوهُ بِالْعِصَابَةِ فَلَمَّا رَدَّ اللَّهُ ذَلِكَ بِالْحَقِّ الَّذِي أَعْطَاكَهُ شَرِقَ بِذَلِكَ فَذَلِكَ فَعَلَ بِهِ مَا رَأَيْتَ فَعَفَا عَنْهُ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَحَدَّثَنِي مُحَمَّدُ بْنُ رَافِعٍ حَدَّثَنَا حُجَيْنٌ يَعْنِي ابْنَ الْمُثَنَّى حَدَّثَنَا لَيْثٌ عَنْ عُقَيْلٍ عَنْ ابْنِ شِهَابٍ فِي هَذَا الْإِسْنَادِ بِمِثْلِهِ وَزَادَ وَذَلِكَ قَبْلَ أَنْ يُسْلِمَ عَبْدُ اللَّهِ","id":"Telah menceritakan kepada kami [Ishaq bin Ibrahim Al Hanzhali] dan [Muhammad bin Rafi'] serta [Abd bin Humaid] sedangkan lafadznya dari Ibnu Rafi', [Ibnu Rafi'] berkata; telah menceritakan kepada kami, sedangkan yang dua mengatakan; telah mengabarkan kepada kami [Abdurrazaq] telah mengabarkan kepada kami [Ma'mar] dari [Az Zuhri] dari ['Urwah] bahwa [Usamah bin Zaid] telah mengabarkan kepadanya, bahwa Nabi shallallahu 'alaihi wasallam menaiki keledai yang berpelana dan di bawahnya ada kain selimut usang hasil produksi Fadakiyah. Sedangkan Usamah membonceng di belakang beliau. Ketika itu beliau pergi hendak menjenguk Sa'd bin Ubadah di perkampungan Bani Harits bin Khazraj sebelum terjadi perang Badar. (Di tengah perjalanan) beliau melewati suatu majlis yang terdiri dari orang-orang Muslim, orang-orang Musyrik penyembah berhala dan orang-orang Yahudi, dan di antara mereka terdapat Abdullah bin Ubay dan Abdullah bin Rawahah. Ketika melihat debu bekas derap langkah kami, maka Abdullah bin Ubay menutup hidungnya dengan kain cadar, sambil berkata, \"Janganlah kalian taburkan debu kepada kami.\" Maka Nabi shallallahu 'alaihi wasallam memberi salam kepada mereka, kemudian berhenti dan turun. Beliau mengajak mereka kepada Allah dengan membacakan ayat-ayat Al Qur'an kepada mereka, justru Abdullah bin Ubay berkata, \"Heh...tidak adakah yang lebih baik daripada ini?\" jika apa yang kamu katakan benar, maka kalian jangan mengganggu dalam majlis kami, pulanglah ke rumahmu, dan bacakanlah kepada orang yang datang kepadamu.\" Maka Abdullah bin Rawahah angkat bicara, \"Datanglah ke Majlis kami, sesungguhnya kami menyukai hal itu.\" Usamah mengatakan, \"Maka terjadilah perang mulut antara orang-orang Muslim, orang-orang Musyrik dan orang-orang Yahudi, hingga hampir terjadi perkelahian. Akan tetapi Nabi shallallahu 'alaihi wasallam dapat menenangkan mereka, lalu beliau menaiki kendaraannya dan pergi ke rumah Sa'ad bin Ubadah. Kemudan beliau bersabda: \"Hai Sa'd, tahukah kamu apa yang baru diucapkan oleh Abu Hubab? -maksudnya adalah Abdullah bin Ubay- dia telah mengatakan begini dan begini.\" Sa'd lalu berkata, \"Ma'afkanlah dia wahai Rasulullah, demi Allah, sesungguhnya Allah telah memberi Anda apa yang telah diberi-Nya, sebelum kedatangan Anda, penduduk negeri ini telah sepakat hendak memakaikan mahkota dan melilitkan surban kepadanya. Tetapi Allah menggagalkannya dengan kebenaran yang diberikan-Nya kepada Anda. Karena itu, dia merasa iri terhadap anda. Itulah sebabnya dia banyak membuat ulah seperti yang anda saksikan.\" Maka Nabi shallallahu 'alaihi wasallam memaafkannya.\" Dan telah menceritakan kepadaku [Muhammad bin Rafi'] telah menceritakan kepada kami [Hujjain] -yaitu Ibnu Al Mutsanna- telah menceritakan kepada kami [Laits] dari ['Uqail] dari [Ibnu Syihab] dengan isnad seperti ini, dengan sedikit tambahan, \"Hal itu terjadi sebelum Abdullah masuk Islam.\""},"3124":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ عَبْدِ الْأَعْلَى الْقَيْسِيُّ حَدَّثَنَا الْمُعْتَمِرُ عَنْ أَبِيهِ عَنْ أَنَسِ بْنِ مَالِكٍ قَالَقِيلَ لِلنَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَوْ أَتَيْتَ عَبْدَ اللَّهِ بْنَ أُبَيٍّ قَالَ فَانْطَلَقَ إِلَيْهِ وَرَكِبَ حِمَارًا وَانْطَلَقَ الْمُسْلِمُونَ وَهِيَ أَرْضٌ سَبَخَةٌ فَلَمَّا أَتَاهُ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِلَيْكَ عَنِّي فَوَاللَّهِ لَقَدْ آذَانِي نَتْنُ حِمَارِكَ قَالَ فَقَالَ رَجُلٌ مِنْ الْأَنْصَارِ وَاللَّهِ لَحِمَارُ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَطْيَبُ رِيحًا مِنْكَ قَالَ فَغَضِبَ لِعَبْدِ اللَّهِ رَجُلٌ مِنْ قَوْمِهِ قَالَ فَغَضِبَ لِكُلِّ وَاحِدٍ مِنْهُمَا أَصْحَابُهُ قَالَ فَكَانَ بَيْنَهُمْ ضَرْبٌ بِالْجَرِيدِ وَبِالْأَيْدِي وَبِالنِّعَالِ قَالَ فَبَلَغَنَا أَنَّهَا نَزَلَتْ فِيهِمْ{ وَإِنْ طَائِفَتَانِ مِنْ الْمُؤْمِنِينَ اقْتَتَلُوا فَأَصْلِحُوا بَيْنَهُمَا }","id":"Telah menceritakan kepada kami [Muhammad bin Abdul A'la Al Qaisi] telah menceritakan kepada kami [Al Mu'tamir] dari [ayahnya] dari [Anas bin Malik] dia berkata, \"Seseorang mengusulkan kepada Nabi shallallahu 'alaihi wasallam, \"Alangkah baiknya seandainya anda datang menjenguk Abdullah bin Ubay.\" Anas berkata, \"Kemudian beliau pergi menjenguknya dengan mengendarai keledainya bersama-sama dengan beberapa orang Muslim, sementara Ubay tinggal di tanah yang gersang. Ketika Nabi shallallahu 'alaihi wasallam mendatanginya, dia berkata, \"Menjauhlah kamu dariku, demi Allah bau keledaimu telah menyakitiku.\" Seorang laki-laki dari Anshar menyahut, \"Demi Allah, bau keledai Rasulullah shallallahu 'alaihi wasallam lebih harum daripada baumu sendiri.\" Anas berkata, \"Lalu seorang laki-laki dari kaumnya (Ubay) angkat bicara hingga masing-masing pihak sama-sama marah dan hampir terjadi perkelahian antara mereka.\" Anas melanjutkan, \"Mereka saling pukul memukul dengan pelepah kurma, dengan tangan dan dengan sepatu atau sandal. Anas berkata, \"Berkenaan dengan mereka, maka turunlah ayat: '(Jika dua golongan antara orang-orang Mukmin berkelahi, maka damaikanlah mereka…) ' (Qs. Al Hujurat: 9)."},"3125":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ حُجْرٍ السَّعْدِيُّ أَخْبَرَنَا إِسْمَعِيلُ يَعْنِي ابْنَ عُلَيَّةَ حَدَّثَنَا سُلَيْمَانُ التَّيْمِيُّ حَدَّثَنَا أَنَسُ بْنُ مَالِكٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ يَنْظُرُ لَنَا مَا صَنَعَ أَبُو جَهْلٍ فَانْطَلَقَ ابْنُ مَسْعُودٍ فَوَجَدَهُ قَدْ ضَرَبَهُ ابْنَا عَفْرَاءَ حَتَّى بَرَكَ قَالَ فَأَخَذَ بِلِحْيَتِهِ فَقَالَ آنْتَ أَبُو جَهْلٍ فَقَالَ وَهَلْ فَوْقَ رَجُلٍ قَتَلْتُمُوهُ أَوْ قَالَ قَتَلَهُ قَوْمُهُ قَالَ وَقَالَ أَبُو مِجْلَزٍ قَالَ أَبُو جَهْلٍ فَلَوْ غَيْرُ أَكَّارٍ قَتَلَنِيحَدَّثَنَا حَامِدُ بْنُ عُمَرَ الْبَكْرَاوِيُّ حَدَّثَنَا مُعْتَمِرٌ قَالَ سَمِعْتُ أَبِي يَقُولُ حَدَّثَنَا أَنَسٌ قَالَ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ يَعْلَمُ لِي مَا فَعَلَ أَبُو جَهْلٍ بِمِثْلِ حَدِيثِ ابْنِ عُلَيَّةَ وَقَوْلِ أَبِي مِجْلَزٍ كَمَا ذَكَرَهُ إِسْمَعِيلُ","id":"Telah menceritakan kepada kami [Ali bin Hujr As Sa'di] telah mengabarkan kepada kami [Isma'il] -yaitu Ibnu 'Ulayah- telah menceritakan kepada kami [Sulaiman At Taimi] telah menceritakan kepada kami [Anas bin Malik] dia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Siapakah yang sanggup mengabarkan kepadaku keadaan Abu Jahal?\" Maka berangkatlah Ibnu Mas'ud, dan dipatinya Abu Jahal telah dipukul rubuh oleh dua orang anak Afra' sehingga tidak berdaya. Kemudian dia memegang jenggotnya seraya berkata, \"Kamukah Abu Jahal?\" Abu Jahal menjawab, \"Apakah ada yang kebih mulia dari orang yang telah kalian bunuh selain aku, atau orang yang dibunuh oleh kaumnya.\" Abu Mijlas berkata, \"Abu Jahal mengatakan, \"Asal aku tidak di bunuh oleh anak seorang petani.\" Telah menceritakan kepada kami [Hamid bin 'Umar Al Bakrawi] telah menceritakan kepada kami [Mu'tamir] dia berkata; saya mendengar [ayahku] berkata; telah menceritakan kepada kami [Anas] dia berkata, \"Rasulullah bersabda: \"Siapakah yang sanggup memperlihatkanku apa yang diperbuat Abu Jahal?....seperti hadits Ibnu 'Ulayyah, perkatan Abu Mijlas itu seperti yang disebutkan oleh Isma'il.\""},"3126":{"ar":"حَدَّثَنَا إِسْحَقُ بْنُ إِبْرَاهِيمَ الْحَنْظَلِيُّ وَعَبْدُ اللَّهِ بْنُ مُحَمَّدِ بْنِ عَبْدِ الرَّحْمَنِ بْنِ الْمِسْوَرِ الزُّهْرِيُّ كِلَاهُمَا عَنْ ابْنِ عُيَيْنَةَ وَاللَّفْظُ لِلزُّهْرِيِّ حَدَّثَنَا سُفْيَانُ عَنْ عَمْرٍو سَمِعْتُ جَابِرًا يَقُولُاقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ لِكَعْبِ بْنِ الْأَشْرَفِ فَإِنَّهُ قَدْ آذَى اللَّهَ وَرَسُولَهُ فَقَالَ مُحَمَّدُ بْنُ مَسْلَمَةَ يَا رَسُولَ اللَّهِ أَتُحِبُّ أَنْ أَقْتُلَهُ قَالَ نَعَمْ قَالَ ائْذَنْ لِي فَلْأَقُلْ قَالَ قُلْ فَأَتَاهُ فَقَالَ لَهُ وَذَكَرَ مَا بَيْنَهُمَا وَقَالَ إِنَّ هَذَا الرَّجُلَ قَدْ أَرَادَ صَدَقَةً وَقَدْ عَنَّانَا فَلَمَّا سَمِعَهُ قَالَ وَأَيْضًا وَاللَّهِ لَتَمَلُّنَّهُ قَالَ إِنَّا قَدْ اتَّبَعْنَاهُ الْآنَ وَنَكْرَهُ أَنْ نَدَعَهُ حَتَّى نَنْظُرَ إِلَى أَيِّ شَيْءٍ يَصِيرُ أَمْرُهُ قَالَ وَقَدْ أَرَدْتُ أَنْ تُسْلِفَنِي سَلَفًا قَالَ فَمَا تَرْهَنُنِي قَالَ مَا تُرِيدُ قَالَ تَرْهَنُنِي نِسَاءَكُمْ قَالَ أَنْتَ أَجْمَلُ الْعَرَبِ أَنَرْهَنُكَ نِسَاءَنَا قَالَ لَهُ تَرْهَنُونِي أَوْلَادَكُمْ قَالَ يُسَبُّ ابْنُ أَحَدِنَا فَيُقَالُ رُهِنَ فِي وَسْقَيْنِ مِنْ تَمْرٍ وَلَكِنْ نَرْهَنُكَ اللَّأْمَةَ يَعْنِي السِّلَاحَ قَالَ فَنَعَمْ وَوَاعَدَهُ أَنْ يَأْتِيَهُ بِالْحَارِثِ وَأَبِي عَبْسِ بْنِ جَبْرٍ وَعَبَّادِ بْنِ بِشْرٍ قَالَ فَجَاءُوا فَدَعَوْهُ لَيْلًا فَنَزَلَ إِلَيْهِمْ قَالَ سُفْيَانُ قَالَ غَيْرُ عَمْرٍو قَالَتْ لَهُ امْرَأَتُهُ إِنِّي لَأَسْمَعُ صَوْتًا كَأَنَّهُ صَوْتُ دَمٍ قَالَ إِنَّمَا هَذَا مُحَمَّدُ بْنُ مَسْلَمَةَ وَرَضِيعُهُ وَأَبُو نَائِلَةَ إِنَّ الْكَرِيمَ لَوْ دُعِيَ إِلَى طَعْنَةٍ لَيْلًا لَأَجَابَ قَالَ مُحَمَّدٌ إِنِّي إِذَا جَاءَ فَسَوْفَ أَمُدُّ يَدِي إِلَى رَأْسِهِ فَإِذَا اسْتَمْكَنْتُ مِنْهُ فَدُونَكُمْ قَالَ فَلَمَّا نَزَلَ نَزَلَ وَهُوَ مُتَوَشِّحٌ فَقَالُوا نَجِدُ مِنْكَ رِيحَ الطِّيبِ قَالَ نَعَمْ تَحْتِي فُلَانَةُ هِيَ أَعْطَرُ نِسَاءِ الْعَرَبِ قَالَ فَتَأْذَنُ لِي أَنْ أَشُمَّ مِنْهُ قَالَ نَعَمْ فَشُمَّ فَتَنَاوَلَ فَشَمَّ ثُمَّ قَالَ أَتَأْذَنُ لِي أَنْ أَعُودَ قَالَ فَاسْتَمْكَنَ مِنْ رَأْسِهِ ثُمَّ قَالَ دُونَكُمْ قَالَ فَقَتَلُوهُ","id":"Telah menceritakan kepada kami [Ishaq bin Ibrahim Al hanzhali] dan [Abdullah bin Muhammad bin Abdurrahman bin Miswar Az Zuhri] keduanya dari [Ibnu 'Uyainah] sedangkan lafadznya dari Az Zuhri, telah menceritakan kepada kami Sufyan dari ['Amru] aku mendengar [Jabir] berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Siapakah di antara kalian yang sanggup membunuh Ka'ab bin Ashraf? Sebab dia telah menyakiti Allah dan Rasul-Nya.\" Maka Muhammad bin Maslamah berkata, \"Wahai Rasulullah, setujukah anda jika aku yang akan membunuhnya?\" beliau bersabda: \"Ya, setuju.\" Maslamah berkata, \"Tetapi, izinkanlah aku terlebih dahulu untuk mengatakan sesuatu kepada anda.\" Beliau menjawab: \"Silahkan.\" Kemudian Dia mendekati beliau untuk menyampaikan sesuatu, akhirnya keduanya terlibat dengan pembicaraan yang serius. Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sebenarnya Ka'ab memang pernah berniat untuk bersedekah, akan tetapi ia justru menyusahkan kami.\" Mendengar keterangan beliau, Muhammad bin Maslamah berkata, \"Demi Allah sungguh aku tidak merasa lebih geram daripada kejengkelanku ini.\" Muhammad bin Maslamah berkata, \"Kami sekarang akan membuntutinya, dan kami tidak suka membiarkan begitu saja sehingga kami mengetahui akhir kesudahannya.\" Maslamah berkata (kepada Ka'ab), \"Wahai Ka'ab, aku hendak meminjam sesuatu darimu!\" Ka'ab bertanya, \"Lalu apa yang hendak kamu gadaikan kepadaku sebagai jaminanannya?\" Ibnu Maslamah balik bertanya, \"Apa yang kamu inginkan?\" Ka'ab berkata, \"Bagaimana menurutmu jika aku ingin agar kamu menggadaikan isteri-isterimu kepadaku?\" Ibnu Maslamah menjawab, \"Kamu adalah orang arab yang berpenampilan sangat menarik dan gagah, jadi bagaimana mungkin aku akan menggadaikan isteri-isteriku?\" Ka'ab kembali bertanya, \"kalau begitu, bagaimana kalau kamu gadaikan anak-anakmu kepadaku.\" Ibnu Maslamah menjawab, \"Itu tidak mungkin aku lakukan, tetapi aku akan menggadaikan senjataku kepadamu.\" Ka'ab menjawab, \"Baiklah aku setuju.\" Kemudian Muhammad bin Maslamah berjanji akan datang ke rumah Ka'ab bin Al Ashraf dengan ditemani Al Harits, Abu Abbas bin Jabr dan Abbad bin Bisyr. Akhirnya keempat orang tersebut datang ke rumah Ka'ab pada malam hari. Sufyan berkata; selain 'Amru berkata, \"Lalu isterinya Ka'ab berkata, \"Sepertinya aku mendengar suara orang yang akan menumpahkan darah.\" Ka'ab menjawab, \"Itu hanya suara Muhammad bin Maslamah dan Abu Nailah, saudara sesusuanku. Sebagai seorang yang terhormat maka aku akan menemuinya walaupun di malam hari.\" Sementara itu Muhammad bin Maslamah berkata (kepada temanya), \"Apabila di keluar, maka aku akan mengulurkan tanganku ke kepalanya, apabila aku telah berhasil membekuknya, maka kamu maju untuk membunuhnya.\" Maslamah berkata, \"Ketika Ka'ab keluar dengan meletakkan senjatanya, mereka (temannya Maslamah) berkata, \"Sepertinya kami mencium bau harum darimu.\" Ka'ab menjawab, \"Memang, sebab isteriku adalah wanita yang pandai berhias dan merawat diri.\" Muhammad bin Maslamah berkata, \"Kalau kamu berkenan, bolehkah aku mencium bau harum yang ada pada dirimu?\" Ka'ab berkata, \"Silahkan.\" Kemudian Muhammad menciumnya dan berusaha menciumnya lagi, lalu dia berkata, \"Kalau kamu berkenan, bolehkah aku mengulanginya lagi?\" rupanya Ka'ab tidak merasa keberatan dan menyodorkan kepalanya kepada Muhammad bin Maslamah. Kemudian Muhammad bin Maslamah berkata kepada temannya, \"Giliran kalian.\" Dia berkata, \"Kemudian mereka membunuh Ka'ab bin Al Ashraf.\""},"3127":{"ar":"و حَدَّثَنِي زُهَيْرُ بْنُ حَرْبٍ حَدَّثَنَا إِسْمَعِيلُ يَعْنِي ابْنَ عُلَيَّةَ عَنْ عَبْدِ الْعَزِيزِ بْنِ صُهَيْبٍ عَنْ أَنَسٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ غَزَا خَيْبَرَ قَالَ فَصَلَّيْنَا عِنْدَهَا صَلَاةَ الْغَدَاةِ بِغَلَسٍ فَرَكِبَ نَبِيُّ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَرَكِبَ أَبُو طَلْحَةَ وَأَنَا رَدِيفُ أَبِي طَلْحَةَ فَأَجْرَى نَبِيُّ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي زُقَاقِ خَيْبَرَ وَإِنَّ رُكْبَتِي لَتَمَسُّ فَخِذَ نَبِيِّ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَانْحَسَرَ الْإِزَارُ عَنْ فَخِذِ نَبِيِّ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَإِنِّي لَأَرَى بَيَاضَ فَخِذَ نَبِيِّ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَلَمَّا دَخَلَ الْقَرْيَةَ قَالَ اللَّهُ أَكْبَرُ خَرِبَتْ خَيْبَرُ إِنَّا إِذَا نَزَلْنَا بِسَاحَةِ قَوْمٍ{ فَسَاءَ صَبَاحُ الْمُنْذَرِينَ }قَالَهَا ثَلَاثَ مِرَارٍ قَالَ وَقَدْ خَرَجَ الْقَوْمُ إِلَى أَعْمَالِهِمْ فَقَالُوا مُحَمَّدٌ قَالَ عَبْدُ الْعَزِيزِ وَقَالَ بَعْضُ أَصْحَابِنَا وَالْخَمِيسَ قَالَ وَأَصَبْنَاهَا عَنْوَةً","id":"Dan telah menceritakan kepadaku [Zuhair bin Harb] telah menceritakan kepada kami [Isma'il] -yaitu Ibnu 'Ulayyah- dari [Abdul 'Aziz bin Shuhaib] dari [Anas], bahwa Rasulullah shallallahu 'alaihi wasallam hendak memerangi Khaibar, ketika kami hampir tiba di kota terebut, kami melaksanakan shalat subuh sementara hari masih agak gelap. Lantas Nabi shallallahu 'alaihi wasallam menaiki kendaraannya kemudian diikuti oleh Abu Thalhah, sedangkan aku membonceng di belakang Abu Thalhah. Nabi shallallahu 'alaihi wasallam terus saja berjalan memasuki jalan-jalan kecil di Khaibar, sehingga lututku bersentuhan dengan paha Nabi shallallahu 'alaihi wasallam, bahkan pernah kain beliau sampai tersingkap, sehingga kelihatan olehku putih paha Nabi shallallahu 'alaihi wasallam. Ketika memasuki perkampungan, beliau bersabda: \"Allahu Akbar, takluklah Khaibar, takluklah Khaibar, apabila kami menduduki suatu negeri, '(maka amat buruklah pagi hari yang di alami oleh orang-orang yang di peringatkan itu).\" Beliau mengulanginya hingga tiga kali.\" Anas berkata, \"Ketika orang-orang kampung keluar menuju tempat mereka bekerja, mereka lalu berteriak, \"Muhammad telah tiba.\" Abdul Aziz berkata, \"Sebagian sahabat kami menyebutkan, \"Dan tentaranya.\" Anas mengatakan, \"(Khaibar) kami rebut dengan kekerasan.\""},"3128":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا عَفَّانُ حَدَّثَنَا حَمَّادُ بْنُ سَلَمَةَ حَدَّثَنَا ثَابِتٌ عَنْ أَنَسٍ قَالَكُنْتُ رِدْفَ أَبِي طَلْحَةَ يَوْمَ خَيْبَرَ وَقَدَمِي تَمَسُّ قَدَمَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ فَأَتَيْنَاهُمْ حِينَ بَزَغَتْ الشَّمْسُ وَقَدْ أَخْرَجُوا مَوَاشِيَهُمْ وَخَرَجُوا بِفُؤُوسِهِمْ وَمَكَاتِلِهِمْ وَمُرُورِهِمْ فَقَالُوا مُحَمَّدٌ وَالْخَمِيسَ قَالَ وَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ خَرِبَتْ خَيْبَرُ إِنَّا إِذَا نَزَلْنَا بِسَاحَةِ قَوْمٍ{ فَسَاءَ صَبَاحُ الْمُنْذَرِينَ }قَالَ فَهَزَمَهُمْ اللَّهُ عَزَّ وَجَلَّ","id":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] telah menceritakan kepada kami ['Affan] telah menceritakan kepada kami [Hammad bin Salamah] telah menceritakan kepada kami [Tsabit] dari [Anas] dia berkata, \"Aku pernah membonceng Abu Thalhah ketika hari penaklukan khaibar, sendangkan kakiku bersentuhan dengan kaki Rasulullah shallallahu 'alaihi wasallam.\" Anas berkata, \"Kami tiba ketika matahari belum muncul. Ketika para penduduknya keluar dengan membawa kempak dan keranjang menuju tempat mereka bekerja, maka mereka berteriak, \"Muhammad dan tentaranya telah datang…!\" Anas berkata, \"Lalu Rasulullah shallallahu 'alaihi wasallam bersabda: \"Takluklah Khaibar, dan apabila kami menduduki suatu negeri, '(maka amat buruklah pagi hari yang di alami oleh orang-orang yang di peringatkan itu) ' '(Qs. Asy Syaffat: 177). Anas berkata, \"Maka Allah Azza Wa Jalla telah mengalahkan mereka.\""},"3129":{"ar":"حَدَّثَنَا إِسْحَقُ بْنُ إِبْرَاهِيمَ وَإِسْحَقُ بْنُ مَنْصُورٍ قَالَا أَخْبَرَنَا النَّضْرُ بْنُ شُمَيْلٍ أَخْبَرَنَا شُعْبَةُ عَنْ قَتَادَةَ عَنْ أَنَسِ بْنِ مَالِكٍ قَالَلَمَّا أَتَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ خَيْبَرَ قَالَ إِنَّا إِذَا نَزَلْنَا بِسَاحَةِ قَوْمٍ{ فَسَاءَ صَبَاحُ الْمُنْذَرِينَ }","id":"Telah menceritakan kepada kami [Ishaq bin Ibrahim] dan [Ishaq bin Manshur] keduanya berkata; telah mengabarkan kepada kami [An Nadlr bin Syumail] telah mengabarkan kepada kami [Syu'bah] dari [Qatadah] dari [Anas bin Malik] dia berkata, \"Ketika Rasulullah shallallahu 'alaihi wasallam tiba di Khaibar, beliau mengucapkan: \"Apabila kami menduduki suatu negeri, '(maka amat buruklah pagi hari yang dialami oleh orang-orang yang diperingatkan itu) ' (Qs. Asy Syaffat: 177).\""},"3130":{"ar":"حَدَّثَنَا قُتَيْبَةُ بْنُ سَعِيدٍ وَمُحَمَّدُ بْنُ عَبَّادٍ وَاللَّفْظُ لِابْنِ عَبَّادٍ قَالَا حَدَّثَنَا حَاتِمٌ وَهُوَ ابْنُ إِسْمَعِيلَ عَنْ يَزِيدَ بْنِ أَبِي عُبَيْدٍ مَوْلَى سَلَمَةَ بْنِ الْأَكْوَعِ عَنْ سَلَمَةَ بْنِ الْأَكْوَعِ قَالَخَرَجْنَا مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِلَى خَيْبَرَ فَتَسَيَّرْنَا لَيْلًا فَقَالَ رَجُلٌ مِنْ الْقَوْمِ لِعَامِرِ بْنِ الْأَكْوَعِ أَلَا تُسْمِعُنَا مِنْ هُنَيْهَاتِكَ وَكَانَ عَامِرٌ رَجُلًا شَاعِرًا فَنَزَلَ يَحْدُو بِالْقَوْمِ يَقُولُ اللَّهُمَّ لَوْلَا أَنْتَ مَا اهْتَدَيْنَاوَلَا تَصَدَّقْنَا وَلَا صَلَّيْنَافَاغْفِرْ فِدَاءً لَكَ مَا اقْتَفَيْنَاوَثَبِّتْ الْأَقْدَامَ إِنْ لَاقَيْنَاوَأَلْقِيَنْ سَكِينَةً عَلَيْنَاإِنَّا إِذَا صِيحَ بِنَا أَتَيْنَاوَبِالصِّيَاحِ عَوَّلُوا عَلَيْنَافَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ هَذَا السَّائِقُ قَالُوا عَامِرٌ قَالَ يَرْحَمُهُ اللَّهُ فَقَالَ رَجُلٌ مِنْ الْقَوْمِ وَجَبَتْ يَا رَسُولَ اللَّهِ لَوْلَا أَمْتَعْتَنَا بِهِ قَالَ فَأَتَيْنَا خَيْبَرَ فَحَاصَرْنَاهُمْ حَتَّى أَصَابَتْنَا مَخْمَصَةٌ شَدِيدَةٌ ثُمَّ قَالَ إِنَّ اللَّهَ فَتَحَهَا عَلَيْكُمْ قَالَ فَلَمَّا أَمْسَى النَّاسُ مَسَاءَ الْيَوْمِ الَّذِي فُتِحَتْ عَلَيْهِمْ أَوْقَدُوا نِيرَانًا كَثِيرَةً فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَا هَذِهِ النِّيرَانُ عَلَى أَيِّ شَيْءٍ تُوقِدُونَ فَقَالُوا عَلَى لَحْمٍ قَالَ أَيُّ لَحْمٍ قَالُوا لَحْمُ حُمُرِ الْإِنْسِيَّةِ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَهْرِيقُوهَا وَاكْسِرُوهَا فَقَالَ رَجُلٌ أَوْ يُهْرِيقُوهَا وَيَغْسِلُوهَا فَقَالَ أَوْ ذَاكَ قَالَ فَلَمَّا تَصَافَّ الْقَوْمُ كَانَ سَيْفُ عَامِرٍ فِيهِ قِصَرٌ فَتَنَاوَلَ بِهِ سَاقَ يَهُودِيٍّ لِيَضْرِبَهُ وَيَرْجِعُ ذُبَابُ سَيْفِهِ فَأَصَابَ رُكْبَةَ عَامِرٍ فَمَاتَ مِنْهُ قَالَ فَلَمَّا قَفَلُوا قَالَ سَلَمَةُ وَهُوَ آخِذٌ بِيَدِي قَالَ فَلَمَّا رَآنِي رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ سَاكِتًا قَالَ مَا لَكَ قُلْتُ لَهُ فَدَاكَ أَبِي وَأُمِّي زَعَمُوا أَنَّ عَامِرًا حَبِطَ عَمَلُهُ قَالَ مَنْ قَالَهُ قُلْتُ فُلَانٌ وَفُلَانٌ وَأُسَيْدُ بْنُ حُضَيْرٍ الْأَنْصَارِيُّ فَقَالَ كَذَبَ مَنْ قَالَهُ إِنَّ لَهُ لَأَجْرَيْنِ وَجَمَعَ بَيْنَ إِصْبَعَيْهِ إِنَّهُ لَجَاهِدٌ مُجَاهِدٌ قَلَّ عَرَبِيٌّ مَشَى بِهَا مِثْلَهُ وَخَالَفَ قُتَيْبَةُ مُحَمَّدًا فِي الْحَدِيثِ فِي حَرْفَيْنِ وَفِي رِوَايَةِ ابْنِ عَبَّادٍ وَأَلْقِ سَكِينَةً عَلَيْنَا","id":"Telah menceritakan kepada kami [Qutaibah bin Sa'id] dan [Muhammad bin 'Abbad] sedangkan lafadznya dari Ibnu 'Abbad, keduanya berkata; telah menceritakan kepada kami [Hatim] -yaitu Ibnu Isma'il- dari [Yazid bin Abu 'Ubaid] bekas budak Salamh bin Al Akwa', dari [Salamah bin Al Akwa'] dia berkata, \"Kami pergi berperang ke khaibar bersama-sama dengan Rasulullah shallallahu 'alaihi wasallam, maka kami mengadakan perjalanan di malam hari. Seorang anggota pasukan lalu berkata kepada 'Amir bin Al Akwa', \"Bacakanlah kepada kami sajak-sajakmu!\" -'Amir memang seorang penyair- kemudian dia turun sambil menghalau unta dan berkata, \"Ya Allah, kalau bukan karena (Hidayah-Mu) maka tidaklah kami akan mendapat petunjuk, kami tidak akan bersedekah, dan kami tidak akan mendirikan shalat. Oleh karena itu, ampunilah kami sebagai, selaku tebusan Engkau atas kesalahan kami. Dan teguhkanlah pendirian kami jika bertemu denga musuh. Tanamkanlah ketenangan di hati kami, apabila di teriaki kami kan datang. Dan dengan teriakan, mereka kan menangis kepada kami.\" Maka Rasulullah shallallahu 'alaihi wasallam bertanya: \"Siapakah orang yang menghalau unta sambil bersyair itu?\" mereka menjawab, \"Amir.\" Beliau bersabda: \"Semoga Allah memberinya rahmat.\" Lalu seorang anggota pasukan bertanya, \"Betulkah begitu ya Rasulullah? alangkah baiknya sekiranya anda menyuruhnya supaya menghibur kami terus.\" Kiranya saat itu kami telah sampa di Khaibar, kemudian kami mengepung penduduknya, sehingga perut kami terasa sangat lapar, lalu Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sesungguhnya Allah menaklukkan negeri itu kepada kalian.\" Salamah berkata, \"Setelah hari mulai petang di hari penaklukan Khaibar, mereka mulai menyalakan api, maka Rasulullah shallallahu 'alaihi wasallam bertanya: \"Nyala api apakah itu? Dan untuk apakah mereka menyalakan api tersebut?\" mereka menjawab, \"Untuk membakar daging.\" Beliau bertanya: \"Daging apa?\" mereka menjawab, \"Daging keledai jinak.\" Maka Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tumpahkan dan pecahkanlah (periuknya).\" Lantas ada seorang laki-laki berkata, \"Tumpahkan lalu di cuci.\" Beliau menjawab: \"Atau seperti itu.\" Tatkala dua pasukan saling berhadapan, ternyata 'Amir hanya mempunyai pedang pendek. Dengan pedang itu maka ia menikamkannya di betis orang Yahudi, tetapi malang baginya, ujung pedang itu terus meluncur hingga berbalik mengenai lutut 'Amir, dan 'Amir pun gugur karenanya.\" Salamah berkata, \"Tatkala mereka telah kembali pulang, Rasulullah shallallahu 'alaihi wasallam memegang tanganku, ketika beliau melihat aku diam.\" Beliau bertanya: \"Ada apa denganmu?\" Aku menjawab, \"Ayah dan ibuku menjadi tebusan anda, mereka mengatakan, 'Pahala 'Amir telah terhapus'.\" Beliau bertanya: \"Siapa yang mengatakannya?\" Aku menjawab, \"Fulan, fulan dan Usaid bin Hudlair Al Anshari.\" Beliau bersabda: \"Orang yang telah mengatakannya telah berdusta, sesungguhnya dia memperoleh pahala ganda -sambil beliau memberi isyarat dengan jemarinya- dialah pejuang sesungguhnya, dan sedikit sekali orang Arab yang pergi berperang seperti dia.\""},"3131":{"ar":"و حَدَّثَنِي أَبُو الطَّاهِرِ أَخْبَرَنَا ابْنُ وَهْبٍ أَخْبَرَنِي يُونُسُ عَنْ ابْنِ شِهَابٍ أَخْبَرَنِي عَبْدُ الرَّحْمَنِ وَنَسَبَهُ غَيْرُ ابْنِ وَهْبٍ فَقَالَ ابْنُ عَبْدِ اللَّهِ بْنِ كَعْبِ بْنِ مَالِكٍ أَنَّ سَلَمَةَ بْنَ الْأَكْوَعِ قَالَلَمَّا كَانَ يَوْمُ خَيْبَرَ قَاتَلَ أَخِي قِتَالًا شَدِيدًا مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَارْتَدَّ عَلَيْهِ سَيْفُهُ فَقَتَلَهُ فَقَالَ أَصْحَابُ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي ذَلِكَ وَشَكُّوا فِيهِ رَجُلٌ مَاتَ فِي سِلَاحِهِ وَشَكُّوا فِي بَعْضِ أَمْرِهِ قَالَ سَلَمَةُ فَقَفَلَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِنْ خَيْبَرَ فَقُلْتُ يَا رَسُولَ اللَّهِ ائْذَنْ لِي أَنْ أَرْجُزَ لَكَ فَأَذِنَ لَهُ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ عُمَرُ بْنُ الْخَطَّابِ أَعْلَمُ مَا تَقُولُ قَالَ فَقُلْتُ وَاللَّهِ لَوْلَا اللَّهُ مَا اهْتَدَيْنَاوَلَا تَصَدَّقْنَا وَلَا صَلَّيْنَافَقَالَ رَسُول�� اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ صَدَقْتَ وَأَنْزِلَنْ سَكِينَةً عَلَيْنَاوَثَبِّتْ الْأَقْدَامَ إِنْ لَاقَيْنَاوَالْمُشْرِكُونَ قَدْ بَغَوْا عَلَيْنَاقَالَ فَلَمَّا قَضَيْتُ رَجَزِي قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ قَالَ هَذَا قُلْتُ قَالَهُ أَخِي فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَرْحَمُهُ اللَّهُ قَالَ فَقُلْتُ يَا رَسُولَ اللَّهِ إِنَّ نَاسًا لَيَهَابُونَ الصَّلَاةَ عَلَيْهِ يَقُولُونَ رَجُلٌ مَاتَ بِسِلَاحِهِ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَاتَ جَاهِدًا مُجَاهِدًاقَالَ ابْنُ شِهَابٍ ثُمَّ سَأَلْتُ","id":"Dan telah menceritakan kepadaku [Abu At Thahir] telah mengabarkan kepada kami [Ibnu Wahb] telah mengabarkan kepadaku [Yunus] dari [Ibnu Syihab] telah mengabarkan kepadaku [Abdurrahman] -selain Ibnu Wahb menisbatkan kepada selainnya, Ibnu Abdullah bin Ka'ab bin Malik berkata- [Salamah bin Al Akwa'] berkata, \"Ketika terjadi perang Khaibar, saudaraku berperang dengan dahsyatnya bersama-sama dengan Rasulullah shallallahu 'alaihi wasallam, namun malang baginya, pedang yang dipakainya berbalik dan mengenainya hingga ia meninggal. Maka [para sahabat] Rasulullah shallallahu 'alaihi wasallam berkomentar mengenai peristiwa itu, bahwa ada seseorang yang mati karena tertusuk pedangnya sendiri.\" Salamah berkata, \"Setelah Rasulullah shallallahu 'alaihi wasallam kembali pulang dari khaibar, maka aku bertanya kepada beliau, \"Wahai Rasulullah, izinkanlah aku untuk malantunkan beberapa bait syair untuk anda!\" Rasulullah shallallahu 'alaihi wasallam pun mengizinkannya, lantas Umar bin Khattab berkata, \"Aku lebih tahu apa yang akan kamu katakan.\" Salamah berkata, \"Lalu aku berkata (membacakan syair), \"Demi Allah, kalau bukan karena Allah, niscaya kami tidak akan mendapatkan petunjuk, kami tidak akan bersedekah, dan kami tidak akan mendirikan shalat.\" Maka Rasulullah shallallahu 'alaihi wasallam bersabda: \"Kamu benar.\" (Salamah melanjutkan senandungnya), \"Semoga Allah menurunkan ketenangan atas kita, dan teguhkanlah pendirian kami jika bertemu dengan musuh…salamah berkata, \"ketika aku selesai melatunkan beberapa bait syair tersebut, Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sebenarnya siapakah yang melantunkan bait syair ini?\" Aku menjawab, \"Saudaraku.\" Maka Rasulullah shallallahu 'alaihi wasallam bersabda: \"Semoga Allah merahmatinya.\" Salamah berkata, \"Maka aku bertanya, \"Wahai Rasulullah, sesungguhnya orang-orang enggan mendo'akan dia, justru mereka mengatakan bahwa ada seorang laki-laki mati karena pedangnya sendiri.\" Maka Rasulullah shallallahu 'alaihi wasallam bersabda: \"Dia telah gugur sebagai seorang Mujahid.\" [Ibnu Syihab] berkata, \"Setelah itu baru aku bertanya.\""},"3132":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ الْمُثَنَّى وَابْنُ بَشَّارٍ وَاللَّفْظُ لِابْنِ الْمُثَنَّى قَالَا حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ حَدَّثَنَا شُعْبَةُ عَنْ أَبِي إِسْحَقَ قَالَ سَمِعْتُ الْبَرَاءَ قَالَكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَوْمَ الْأَحْزَابِ يَنْقُلُ مَعَنَا التُّرَابَ وَلَقَدْ وَارَى التُّرَابُ بَيَاضَ بَطْنِهِ وَهُوَ يَقُولُ وَاللَّهِ لَوْلَا أَنْتَ مَا اهْتَدَيْنَاوَلَا تَصَدَّقْنَا وَلَا صَلَّيْنَافَأَنْزِلَنْ سَكِينَةً عَلَيْنَاإِنَّ الْأُلَى قَدْ أَبَوْا عَلَيْنَاقَالَ وَرُبَّمَا قَالَ إِنَّ الْمَلَا قَدْ أَبَوْا عَلَيْنَاإِذَا أَرَادُوا فِتْنَةً أَبَيْنَاوَيَرْفَعُ بِهَا صَوْتَهُحَدَّثَنَا مُحَمَّدُ بْنُ الْمُثَنَّى حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ مَهْدِيٍّ حَدَّثَنَا شُعْبَةُ عَنْ أَبِي إِسْحَقَ قَالَ سَمِعْتُ الْبَرَاءَ فَذَكَرَ مِثْلَهُ إِلَّا أَنَّهُ قَالَ إِنَّ الْأُلَى قَدْ بَغَوْا عَلَيْنَا","id":"Telah menceritakan kepada kami [Muhammad bin Mutsanna] dan [Ibnu Basyar] sedangkan lafadznya dari Ibnu Mutsanna, keduanya berkata; telah menceritakan kepada kami [Muhammad bin Ja'far] telah menceritakan kepada kami [Syu'bah] dari [Abu Ishaq] dia berkata; aku mendengar [Al Barra`] berkata, \"Ketika terjadi perang Ahzab, Rasulullah shallallahu 'alaihi wasallam turut bersama-sama dengan kami mengangkat tanah. Sehingga perut putih beliau kotor dengan tanah, beliau bersenandung: \"Ya Allah, sekiranya bukan karena Engkau, tidaklah kami mendapatkan petunjuk, tidaklah kami bersedekah, dan tidak pula kami akan mendirikan shalat. Tanamkanlah ketenangan di hati kami, karena sesungguhnya para pembesar kaum tidak menyukai kami.\" Al Barra` berkata, \"Mungkin juga beliau bersajak: \"Sesungguhnya para pembesar tidak menyukai kami, namun bila mereka hendak berbuat firnah, maka mereka enggan kepada kami.\" Sambil mengerasnya bacaannya.\" Telah menceritakan kepada kami [Muhammad bin Al Mutsanna] telah menceritakan kepada kami [Abdurrahman bin Mahdi] telah menceritakan kepada kami [Syu'bah] dari [Abu Ishaq] dia berkata; aku mendengar [Al Barra`]...kemdian dia menyebutkan yang semisalnya, namun dia menyebutkan, \"Sesungguhnya para pembesar berlaku congkak terhadap kami.\""},"3133":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ مَسْلَمَةَ الْقَعْنَبِيُّ حَدَّثَنَا عَبْدُ الْعَزِيزِ بْنُ أَبِي حَازِمٍ عَنْ أَبِيهِ عَنْ سَهْلِ بْنِ سَعْدٍ قَالَجَاءَنَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَنَحْنُ نَحْفِرُ الْخَنْدَقَ وَنَنْقُلُ التُّرَابَ عَلَى أَكْتَافِنَا فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ اللَّهُمَّ لَا عَيْشَ إِلَّا عَيْشُ الْآخِرَةِ فَاغْفِرْ لِلْمُهَاجِرِينَ وَالْأَنْصَارِ","id":"Telah menceritakan kepada kami [Abdullah bin Maslamah Al Qa'nabi] telah menceritakan kepada kami [Abdul Aziz bin Abu Hazim] dari [ayahnya] dari [Sahl bin Sa'd] dia berkata; \"Rasulullah shallallahu 'alaihi wasallam datang kepada kami saat kami sedang menggali khandaq (parit) dan mengangkut tanah di pundak kami, Rasulullah shallallahu 'alaihi wasallam kemudian bersabda: \"Ya Allah, tidak ada kehidupan yang hakiki selain kehidupan Akhirat, maka ampunilah orang-orang Muhajirin dan Anshar.\""},"3134":{"ar":"و حَدَّثَنَا مُحَمَّدُ بْنُ الْمُثَنَّى وَابْنُ بَشَّارٍ وَاللَّفْظُ لِابْنِ الْمُثَنَّى حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ حَدَّثَنَا شُعْبَةُ عَنْ مُعَاوِيَةَ بْنِ قُرَّةَ عَنْ أَنَسِ بْنِ مَالِكٍعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهُ قَالَ اللَّهُمَّ لَا عَيْشَ إِلَّا عَيْشُ الْآخِرَهْفَاغْفِرْ لِلْأَنْصَارِ وَالْمُهَاجِرَهْ","id":"Dan telah menceritakan kepada kami [Muhammad bin Al Mutsanna] dan [Ibnu Basyar] sedangkan lafadznya dari Ibnu Mutsanna, telah menceritakan kepada kami [Muhammad bin Ja'far] telah menceritakan kepada kami [Syu'bah] dari [Mu'awiyah bin Qurrah] dari [Anas bin Malik] dari Nabi shallallahu 'alaihi wasallam, bahwa beliau bersabda: \"Ya Allah, tidak ada kehidupan yang hakiki melainkan kehidupan Akhirat, maka ampunilah kaum Anshar dan Muhajirin.\""},"3135":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ الْمُثَنَّى وَابْنُ بَشَّارٍ قَالَ ابْنُ الْمُثَنَّى حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ أَخْبَرَنَا شُعْبَةُ عَنْ قَتَادَةَ حَدَّثَنَا أَنَسُ بْنُ مَالِكٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يَقُولُ اللَّهُمَّ إِنَّ الْعَيْشَ عَيْشُ الْآخِرَةِ قَالَ شُعْبَةُ أَوْ قَالَ اللَّهُمَّ لَا عَيْشَ إِلَّا عَيْشُ الْآخِرَهْفَأَكْرِمْ الْأَنْصَارَ وَالْمُهَاجِرَهْ","id":"Telah menceritakan kepada kami [Muhammad bin Al Mutsanna] dan [Ibnu Basyar], [bnu Mutsanna] berkata, telah menceritakan kepada kami [Muhammad bin Ja'far] telah mengabarkan kepada kami [Syu'bah] dari [Qatadah] telah menceritakan kepada kami [Anas bin Malik], bahwa Rasulullah shallallahu 'alaihi wasallam pernah bersabda: \"Ya Allah, sesungguhnya kehidupan yang hakiki adalah kehidupan akhirat.\" Syu'bah berkata, \"Atau, beliau bersabda: \"Ya Allah, tidak ada kehidupan yang hakiki melainkan kehidupan akhirat, maka muliakanlah kaum Anshar dan Muhajirin.\""},"3136":{"ar":"و حَدَّثَنَا يَحْيَى بْنُ يَحْيَى وَشَيْبَانُ بْنُ فَرُّوخَ قَالَ يَحْيَى أَخْبَرَنَا و قَالَ شَيْبَانُ حَدَّثَنَا عَبْدُ الْوَارِثِ عَنْ أَبِي التَّيَّاحِ حَدَّثَنَا أَنَسُ بْنُ مَالِكٍ قَالَكَانُوا يَرْتَجِزُونَ وَرَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَعَهُمْ وَهُمْ يَقُولُونَ اللَّهُمَّ لَا خَيْرَ إِلَّا خَيْرُ الْآخِرَهْفَانْصُرْ الْأَنْصَارَ وَالْمُهَاجِرَهْوَفِي حَدِيثِ شَيْبَانَ بَدَلَ فَانْصُرْ فَاغْفِرْ","id":"Dan telah menceritakan kepada kami [Yahya bin Yahya] dan [Syaiban bin Farruh], Yahya berkata; telah mengabarkan kepada kami, sedangkan Syaiban berkata; telah menceritakan kepada kami [Abdul Warits] dari [Abu At Tayyah] telah menceritakan kepada kami [Anas bin Malik] dia berkata, \"Para sahabat sedang bersenandung sedangkan Rasulullah shallallahu 'alaihi wasallam bersama-sama dengan mereka, mereka mengatakan, \"Ya Allah, tidak ada kebaikan yang abadi melainkan kebaikan akhirat, maka tolonglah kaum Anshar dan Muhajirin.\" Dan dalam haditsnya Syaiban kalimat 'Maka tolonglah', diganti dengan kalimat 'Maka ampunilah'.\""},"3137":{"ar":"حَدَّثَنِي مُحَمَّدُ بْنُ حَاتِمٍ حَدَّثَنَا بَهْزٌ حَدَّثَنَا حَمَّادُ بْنُ سَلَمَةَ حَدَّثَنَا ثَابِتٌ عَنْ أَنَسٍأَنَّ أَصْحَابَ مُحَمَّدٍ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانُوا يَقُولُونَ يَوْمَ الْخَنْدَقِ نَحْنُ الَّذِينَ بَايَعُوا مُحَمَّدًاعَلَى الْإِسْلَامِ مَا بَقِينَا أَبَدًاأَوْ قَالَ عَلَى الْجِهَادِ شَكَّ حَمَّادٌ وَالنَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ اللَّهُمَّ إِنَّ الْخَيْرَ خَيْرُ الْآخِرَهْفَاغْفِرْ لِلْأَنْصَارِ وَالمُهَاجِرَهْ","id":"Dan telah menceritakan kepadaku [Muhammad bin Hatim] telah menceritakan kepada kami [Bahz] telah menceritakan kepada kami [Hammad bin Salamah] telah menceritakan kepada kami [Tsabit] dari [Anas], bahwa ketika perang Khandaq para sahabat Muhammad shallallahu 'alaihi wasallam pernah mengatakan, \"Kami adalah orang-orang yang pernah berbaiat kepada muhammad atas Islam, sehingga hayat masih dikandung badan, -atau dia mengatakan- 'atas jihad, ' Hammad ragu-ragu. Sedangkan Nabi shallallahu 'alaihi wasallam bersabda: \"Ya Allah, sesungguhnya tidak ada kebaikan yang abadi melainkan kebaikan akhirat, maka ampunilah kaum Anshar dan Muhajirin.\""},"3138":{"ar":"حَدَّثَنَا قُتَيْبَةُ بْنُ سَعِيدٍ حَدَّثَنَا حَاتِمٌ يَعْنِي ابْنَ إِسْمَعِيلَ عَنْ يَزِيدَ بْنِ أَبِي عُبَيْدٍ قَالَ سَمِعْتُ سَلَمَةَ بْنَ الْأَكْوَعِ يَقُولُاخَرَجْتُ قَبْلَ أَنْ يُؤَذَّنَ بِالْأُولَى وَكَانَتْ لِقَاحُ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ تَرْعَى بِذِي قَرَدٍ قَالَ فَلَقِيَنِي غُلَامٌ لِعَبْدِ الرَّحْمَنِ بْنِ عَوْفٍ فَقَالَ أُخِذَتْ لِقَاحُ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقُلْتُ مَنْ أَخَذَهَا قَالَ غَطَفَانُ قَالَ فَصَرَخْتُ ثَلَاثَ صَرَخَاتٍ يَا صَبَاحَاهْ قَالَ فَأَسْمَعْتُ مَا بَيْنَ لَابَتَيِ الْمَدِينَةِ ثُمَّ انْدَفَعْتُ عَلَى وَجْهِي حَتَّى أَدْرَكْتُهُمْ بِذِي قَرَدٍ وَقَدْ أَخَذُوا يَسْقُونَ مِنْ الْمَاءِ فَجَعَلْتُ أَرْمِيهِمْ بِنَبْلِي وَكُنْتُ رَامِيًا وَأَقُولُ أَنَا ابْنُ الْأَكْوَعِوَالْيَوْمُ يَوْمُ الرُّضَّعِفَأَرْتَجِزُ حَتَّى اسْتَنْقَذْتُ اللِّقَاحَ مِنْهُمْ وَاسْتَلَبْتُ مِنْهُمْ ثَلَاثِينَ بُرْدَةً قَالَ وَجَاءَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَالنَّاسُ فَقُلْتُ يَا نَبِيَّ اللَّهِ إِنِّي قَدْ حَمَيْتُ الْقَوْمَ الْمَاءَ وَهُمْ عِطَاشٌ فَابْعَثْ إِلَيْهِمْ السَّاعَةَ فَقَالَ يَا ابْنَ الْأَكْوَعِ مَلَكْتَ فَأَسْجِحْ قَالَ ثُمَّ رَجَعْنَا وَيُرْدِفُنِي رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَلَى نَاقَتِهِ حَتَّى دَخَلْنَا الْمَدِينَةَ","id":"Telah menceritakan kepada kami [Qutaibah bin Sa'id] telah menceritakan kepada kami [Hatim] -yaitu Ibnu Isma'il- dari [Yazid bin Abu 'Ubaid] dia berkata; aku mendengar [Salamah bin Al Akwa'] berkata, \"Aku keluar kota sebelum adzan pertama dikumandangkan, sedangkan unta-unta Rasulullah shallallahu 'alaihi wasallam digembalakan di Dzu Qard.\" Salamah berkata, \"Tiba-tiba budak Abdurrahman bin Auf mendatangiku seraya berkata, \"Unta-unta Rasulullah shallallahu 'alaihi wasallam telah dirampok.\" Maka aku bertanya, \"Siapa yang merampoknya?\" dia menjawab, \"Bani Ghathafan.\" Salamah berkata, \"Kemudian aku berteriak hingga tiga kali, \"Tolooong...!\" Salamah berkata, \"Hingga suaraku terdengar hingga ke seluruh pojok kota Madinah, kemudian aku bertolak hingga menemui mereka di Dzu Qard, sedangkan mereka baru minum dari sumber air, maka aku melempari mereka dengan panah sambil bersenandung, 'Aku adalah Ibnu Al Akwa', pada hari ini adalah hari kebinasana.' Aku masih bersenandung hingga aku dapat mengambil kembali unta-unta beliau dari mereka, dan membawa tiga puluh kain burdah dari mereka.\" Salamah berkata, \"Kemudian Nabi shallallahu 'alaihi wasallam datang disertai dengan beberapa orang, aku lalu berkata, 'Wahai Nabi Allah, sesungguhnya aku telah menghalau mereka dari sumber air, padahal mereka sangat kehausan, maka utuslah kepada mereka sekarang juga.' Maka beliau bersabda: \"Wahai Al Akwa', kamu telah melakukan suatu hal yang sangat tepat.\" Kemudian kami kembali pulang dengan membonceng di belakang Rasulullah shallallahu 'alaihi wasallam di atas untanya, hingga kami memasuki kota Madinah.\""},"3139":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا هَاشِمُ بْنُ الْقَاسِمِ ح و حَدَّثَنَا إِسْحَقُ بْنُ إِبْرَاهِيمَ أَخْبَرَنَا أَبُو عَامِرٍ الْعَقَدِيُّ كِلَاهُمَا عَنْ عِكْرِمَةَ بْنِ عَمَّارٍ ح و حَدَّثَنَا عَبْدُ اللَّهِ بْنُ عَبْدِ الرَّحْمَنِ الدَّارِمِيُّ وَهَذَا حَدِيثُهُ أَخْبَرَنَا أَبُو عَلِيٍّ الْحَنَفِيُّ عُبَيْدُ اللَّهِ بْنُ عَبْدِ الْمَجِيدِ حَدَّثَنَا عِكْرِمَةُ وَهُوَ ابْنُ عَمَّارٍ حَدَّثَنِي إِيَاسُ بْنُ سَلَمَةَ حَدَّثَنِي أَبِي قَالَقَدِمْنَا الْحُدَيْبِيَةَ مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَنَحْنُ أَرْبَعَ عَشْرَةَ مِائَةً وَعَلَيْهَا خَمْسُونَ شَاةً لَا تُرْوِيهَا قَالَ فَقَعَدَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَلَى جَبَا الرَّكِيَّةِ فَإِمَّا دَعَا وَإِمَّا بَصَقَ فِيهَا قَالَ فَجَاشَتْ فَسَقَيْنَا وَاسْتَقَيْنَا قَالَ ثُمَّ إِنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ دَعَانَا لِلْبَيْعَةِ فِي أَصْلِ الشَّجَرَةِ قَالَ فَبَايَعْتُهُ أَوَّلَ النَّاسِ ثُمَّ بَايَعَ وَبَايَعَ حَتَّى إِذَا كَانَ فِي وَسَطٍ مِنْ النَّاسِ قَالَ بَايِعْ يَا سَلَمَةُ قَالَ قُلْتُ قَدْ بَايَعْتُكَ يَا رَسُولَ اللَّهِ فِي أَوَّلِ النَّاسِ قَالَ وَأَيْضًا قَالَ وَرَآنِي رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَزِلًا يَعْنِي لَيْسَ مَعَهُ سِلَاحٌ قَالَ فَأَعْطَانِي رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حَجَفَةً أَوْ دَرَقَةً ثُمَّ بَايَعَ حَتَّى إِذَا كَانَ فِي آخِرِ النَّاسِ قَالَ أَلَا تُبَايِعُنِي يَا سَلَمَةُ قَالَ قُلْتُ قَدْ بَايَعْتُكَ يَا رَسُولَ اللَّهِ فِي أَوَّلِ النَّاسِ وَفِي أَوْسَطِ النَّاسِ قَالَ وَأَيْضًا قَالَ فَبَايَعْتُهُ الثَّالِثَةَ ثُمَّ قَالَ لِي يَا سَلَمَةُ أَيْنَ حَجَفَتُكَ أَوْ دَرَقَتُكَ الَّتِي أَعْطَيْتُكَ قَالَ قُلْتُ يَا رَسُولَ اللَّهِ لَقِيَنِي عَمِّي عَامِرٌ عَزِلًا فَأَعْطَيْتُهُ إِيَّاهَا قَالَ فَضَحِكَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَقَالَ إِنَّكَ كَالَّذِي قَالَ الْأَوَّلُ اللَّهُمَّ أَبْغِنِي حَبِيبًا هُوَ أَحَبُّ إِلَيَّ مِنْ نَفْسِي ثُمَّ إِنَّ الْمُشْرِكِينَ رَاسَلُونَا الصُّلْحَ حَتَّى مَشَى بَعْضُنَا فِي بَعْضٍ وَاصْطَلَحْنَا قَالَ وَكُنْتُ تَبِيعًا لِطَلْحَةَ بْنِ عُبَيْدِ اللَّهِ أَسْقِي فَرَسَهُ وَأَحُسُّهُ وَأَخْدِمُهُ وَآكُلُ مِنْ طَعَامِهِ وَتَرَكْتُ أَهْلِي وَمَالِي مُهَاجِرًا إِلَى اللَّهِ وَرَسُولِهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ فَلَمَّا اصْطَلَحْنَا نَحْنُ وَأَهْلُ مَكَّةَ وَاخْتَلَطَ بَعْضُنَا بِبَعْضٍ أَتَيْتُ شَجَرَةً فَكَسَحْتُ شَوْكَهَا فَاضْطَجَعْتُ فِي أَصْلِهَا قَالَ فَأَتَانِي أَرْبَعَةٌ مِنْ الْمُشْرِكِينَ مِنْ أَهْلِ مَكَّةَ فَجَعَلُوا يَقَعُونَ فِي رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَبْغَضْتُهُمْ فَتَحَوَّلْتُ إِلَى شَجَرَةٍ أُخْرَى وَعَلَّقُوا سِلَاحَهُمْ وَاضْطَجَعُوا فَبَيْنَمَا هُمْ كَذَلِكَ إِذْ نَادَى مُنَادٍ مِنْ أَسْفَلِ الْوَادِي يَا لِلْمُهَاجِرِينَ قُتِلَ ابْنُ زُنَيْمٍ قَالَ فَاخْتَرَطْتُ سَيْفِي ثُمَّ شَدَدْتُ عَلَى أُولَئِكَ الْأَرْبَعَةِ وَهُمْ رُقُودٌ فَأَخَذْتُ سِلَاحَهُمْ فَجَعَلْتُهُ ضِغْثًا فِي يَدِي قَالَ ثُمَّ قُلْتُ وَالَّذِي كَرَّمَ وَجْهَ مُحَمَّدٍ لَا يَرْفَعُ أَحَدٌ مِنْكُمْ رَأْسَهُ إِلَّا ضَرَبْتُ الَّذِي فِيهِ عَيْنَاهُ قَالَ ثُمَّ جِئْتُ بِهِمْ أَسُوقُهُمْ إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ وَجَاءَ عَمِّي عَامِرٌ بِرَجُلٍ مِنْ الْعَبَلَاتِ يُقَالُ لَهُ مِكْرَزٌ يَقُودُهُ إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَلَى فَرَسٍ مُجَفَّفٍ فِي سَبْعِينَ مِنْ الْمُشْرِكِينَ فَنَظَرَ إِلَيْهِمْ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ دَعُوهُمْ يَكُنْ لَهُمْ بَدْءُ الْفُجُورِ وَثِنَاهُ فَعَفَا عَنْهُمْ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَأَنْزَلَ اللَّهُ{ وَهُوَ الَّذِي كَفَّ أَيْدِيَهُمْ عَنْكُمْ وَأَيْدِيَكُمْ عَنْهُمْ بِبَطْنِ مَكَّةَ مِنْ بَعْدِ أَنْ أَظْفَرَكُمْ عَلَيْهِمْ }الْآيَةَ كُلَّهَا قَالَ ثُمَّ خَرَجْنَا رَاجِعِينَ إِلَى الْمَدِينَةِ فَنَزَلْنَا مَنْزِلًا بَيْنَنَا وَبَيْنَ بَنِي لَحْيَانَ جَبَلٌ وَهُمْ الْمُشْرِكُونَ فَاسْتَغْفَرَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لِمَنْ رَقِيَ هَذَا الْجَبَلَ اللَّيْلَةَ كَأَنَّهُ طَلِيعَةٌ لِلنَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَأَصْحَابِهِ قَالَ سَلَمَةُ فَرَقِيتُ تِلْكَ اللَّيْلَةَ مَرَّتَيْنِ أَوْ ثَلَاثًا ثُمَّ قَدِمْنَا الْمَدِينَةَ فَبَعَثَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِظَهْرِهِ مَعَ رَبَاحٍ غُلَامِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَأَنَا مَعَهُ وَخَرَجْتُ مَعَهُ بِفَرَسِ طَلْحَةَ أُنَدِّيهِ مَعَ الظَّهْرِ فَلَمَّا أَصْبَحْنَا إِذَا عَبْدُ الرَّحْمَنِ الْفَزَارِيُّ قَدْ أَغَارَ عَلَى ظَهْرِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَاسْتَاقَهُ أَجْمَعَ وَقَتَلَ رَاعِيَهُ قَالَ فَقُلْتُ يَا رَبَاحُ خُذْ هَذَا الْفَرَسَ فَأَبْلِغْهُ طَلْحَةَ بْنَ عُبَيْدِ اللَّهِ وَأَخْبِرْ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّ الْمُشْرِكِينَ قَدْ أَغَارُوا عَلَى سَرْحِهِ قَالَ ثُمَّ قُمْتُ عَلَى أَكَمَةٍ فَاسْتَقْبَلْتُ الْمَدِينَةَ فَنَادَيْتُ ثَلَاثًا يَا صَبَاحَاهْ ثُمَّ خَرَجْتُ فِي آثَارِ الْقَوْمِ أَرْمِيهِمْ بِالنَّبْلِ وَأَرْتَجِزُ أَقُولُ أَنَا ابْنُ الْأَكْوَعِوَالْيَوْمُ يَوْمُ الرُّضَّعِفَأَلْحَقُ رَجُلًا مِنْهُمْ فَأَصُكُّ سَهْمًا فِي رَحْلِهِ حَتَّى خَلَصَ نَصْلُ السَّهْمِ إِلَى كَتِفِهِ قَالَ قُلْتُ خُذْهَا وَأَنَا ابْنُ الْأَكْوَعِوَالْيَوْمُ يَوْمُ الرُّضَّعِقَالَ فَوَاللَّهِ مَا زِلْتُ أَرْمِيهِمْ وَأَعْقِرُ بِهِمْ فَإِذَا رَجَعَ إِلَيَّ فَارِسٌ أَتَيْتُ شَجَرَةً فَجَلَسْتُ فِي أَصْلِهَا ثُمَّ رَمَيْتُهُ فَعَقَرْتُ بِهِ حَتَّى إِذَا تَضَايَقَ الْجَبَلُ فَدَخَلُوا فِي تَضَايُقِهِ عَلَوْتُ الْجَبَلَ فَجَعَلْتُ أُرَدِّيهِمْ بِالْحِجَارَةِ قَالَ فَمَا زِلْتُ كَذَلِكَ أَتْبَعُهُمْ حَتَّى مَا خَلَقَ اللَّهُ مِنْ بَعِيرٍ مِنْ ظَهْرِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِلَّا خَلَّفْتُهُ وَرَاءَ ظَهْرِي وَخَلَّوْا بَيْنِي وَبَيْنَهُ ثُمَّ اتَّبَعْتُهُمْ أَرْمِيهِمْ حَتَّى أَلْقَوْا أَكْثَرَ مِنْ ثَلَاثِينَ بُرْدَةً وَثَلَاثِينَ رُمْحًا يَسْتَخِفُّونَ وَلَا يَطْرَحُونَ شَيْئًا إِلَّا جَعَلْتُ عَلَيْهِ آرَامًا مِنْ الْحِجَارَةِ يَعْرِفُهَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَأَصْحَابُهُ حَتَّى أَتَوْا مُتَضَايِقًا مِنْ ثَنِيَّةٍ فَإِذَا هُمْ قَدْ أَتَاهُمْ فُلَانُ بْنُ بَدْرٍ الْفَزَارِيُّ فَجَلَسُوا يَتَضَحَّوْنَ يَعْنِي يَتَغَدَّوْنَ وَجَلَسْتُ عَلَى رَأْسِ قَرْنٍ قَالَ الْفَزَارِيُّ مَا هَذَا الَّذِي أَرَى قَالُوا لَقِينَا مِنْ هَذَا الْبَرْحَ وَاللَّهِ مَا فَارَقَنَا مُنْذُ غَلَسٍ يَرْمِينَا حَتَّى انْتَزَعَ كُلَّ شَيْءٍ فِي أَيْدِينَا قَالَ فَلْيَقُمْ إِلَيْهِ نَفَرٌ مِنْكُمْ أَرْبَعَةٌ قَالَ فَصَعِدَ إِلَيَّ مِنْهُمْ أَرْبَعَةٌ فِي الْجَبَلِ قَالَ فَلَمَّا أَمْكَنُونِي مِنْ الْكَلَامِ قَالَ قُلْتُ هَلْ تَعْرِفُونِي قَالُوا لَا وَمَنْ أَنْتَ قَالَ قُلْتُ أَنَا سَلَمَةُ بْنُ الْأَكْوَعِ وَالَّذِي كَرَّمَ وَجْهَ مُحَمَّدٍ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا أَطْلُبُ رَجُلًا مِنْكُمْ إِلَّا أَدْرَكْتُهُ وَلَا يَطْلُبُنِي رَجُلٌ مِنْكُمْ فَيُدْرِكَنِي قَالَ أَحَدُهُمْ أَنَا أَظُنُّ قَالَ فَرَجَعُوا فَمَا بَرِحْتُ مَكَانِي حَتَّى رَأَيْتُ فَوَارِسَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَتَخَلَّلُونَ الشَّجَرَ قَالَ فَإِذَا أَوَّلُهُمْ الْأَخْرَمُ الْأَسَدِيُّ عَلَى إِثْرِهِ أَبُو قَتَادَةَ الْأَنْصَارِيُّ وَعَلَى إِثْرِهِ الْمِقْدَادُ بْنُ الْأَسْوَدِ الْكِنْدِيُّ قَالَ فَأَخَذْتُ بِعِنَانِ الْأَخْرَمِ قَالَ فَوَلَّوْا مُدْبِرِينَ قُلْتُ يَا أَخْرَمُ احْذَرْهُمْ لَا يَقْتَطِعُوكَ حَتَّى يَلْحَقَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَأَصْحَابُهُ قَالَ يَا سَلَمَةُ إِنْ كُنْتَ تُؤْمِنُ بِاللَّهِ وَالْيَوْمِ الْآخِرِ وَتَعْلَمُ أَنَّ الْجَنَّةَ حَقٌّ وَالنَّارَ حَقٌّ فَلَا تَحُلْ بَيْنِي وَبَيْنَ الشَّهَادَةِ قَالَ فَخَلَّيْتُهُ فَالْتَقَى هُوَ وَعَبْدُ الرَّحْمَنِ قَالَ فَعَقَرَ بِعَبْدِ الرَّحْمَنِ فَرَسَهُ وَطَعَنَهُ عَبْدُ الرَّحْمَنِ فَقَتَلَهُ وَتَحَوَّلَ عَلَى فَرَسِهِ وَلَحِقَ أَبُو قَتَادَةَ فَارِسُ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِعَبْدِ الرَّحْمَنِ فَطَعَنَهُ فَقَتَلَهُ فَوَالَّذِي كَرَّمَ وَجْهَ مُحَمَّدٍ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَتَبِعْتُهُمْ أَعْدُو عَلَى رِجْلَيَّ حَتَّى مَا أَرَى وَرَائِي مِنْ أَصْحَابِ مُحَمَّدٍ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَلَا غُبَارِهِمْ شَيْئًا حَتَّى يَعْدِلُوا قَبْلَ غُرُوبِ الشَّمْسِ إِلَى شِعْبٍ فِيهِ مَاءٌ يُقَالُ لَهُ ذَو قَرَدٍ لِيَشْرَبُوا مِنْهُ وَهُمْ عِطَاشٌ قَالَ فَنَظَرُوا إِلَيَّ أَعْدُو وَرَاءَهُمْ فَخَلَّيْتُهُمْ عَنْهُ يَعْنِي أَجْلَيْتُهُمْ عَنْهُ فَمَا ذَاقُوا مِنْهُ قَطْرَةً قَالَ وَيَخْرُجُونَ فَيَشْتَدُّونَ فِي ثَنِيَّةٍ قَالَ فَأَعْدُو فَأَلْحَقُ رَجُلًا مِنْهُمْ فَأَصُكُّهُ بِسَهْمٍ فِي نُغْضِ كَتِفِهِ قَالَ قُلْتُ خُذْهَا وَأَنَا ابْنُ الْأَكْوَعِوَالْيَوْمُ يَوْمُ الرُّضَّعِقَالَ يَا ثَكِلَتْهُ أُمُّ��ُ أَكْوَعُهُ بُكْرَةَ قَالَ قُلْتُ نَعَمْ يَا عَدُوَّ نَفْسِهِ أَكْوَعُكَ بُكْرَةَ قَالَ وَأَرْدَوْا فَرَسَيْنِ عَلَى ثَنِيَّةٍ قَالَ فَجِئْتُ بِهِمَا أَسُوقُهُمَا إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ وَلَحِقَنِي عَامِرٌ بِسَطِيحَةٍ فِيهَا مَذْقَةٌ مِنْ لَبَنٍ وَسَطِيحَةٍ فِيهَا مَاءٌ فَتَوَضَّأْتُ وَشَرِبْتُ ثُمَّ أَتَيْتُ رَسُولَ اللّ","id":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] telah menceritakan kepada kami [Hasyim Ibnul Qasim]. (dalam jalur lain disebutkan) Telah menceritakan kepada kami [Ishaq bin Ibrahim] telah mengabarkan kepada kami [Abu Amir Al Aqadi] keduanya dari [Ikrimah bin Ammar]. (dalam jalur lain disebutkan) Telah menceritakan kepada kami [Abdullah bin 'Abdurrahman Ad Darimi] dan ini adalah haditsnya. Telah mengabarkan kepada kami [Abu Ali Al Hanafi Ubaidullah bin Abdul Majid] telah menceritakan kepada kami [Ikrimah] -yaitu Ibnu Ammar- telah menceritakan kepadaku [Iyas bin Salamah] dari [ayahnya] dia berkata, \"Kami pernah ikut perang bersama Rasulullah shallallahu 'alaihi wasallam ke Hudaibiyah, pada saat itu kami berjumlah seribu empat ratus orang, dan kami hanya membawa lima puluh ekor kambing, sehingga air susu kambing sejumlah itu tidak cukup untuk kami minum. Setelah itu, Rasulullah shallallahu 'alaihi wasallam duduk di dekat sumur sambil berdo'a atau meludahinya. Berkat do'a yang dibacakan Rasulullah shallallahu 'alaihi wasallam kepada air susu kambing tersebut, maka kami semua dapat meminum air susu dengan sepuas-puasnya. Kemudian Rasulullah shallallahu 'alaihi wasallam mengajak kami untuk berbai'at kepada beliau di bawah pohon. Aku berbaiat kepada Rasulullah shallallahu 'alaihi wasallam pada rombongan pertama. Kemudian beliau terus menerima pembaiatan dari para sahabat yang hadir pada saat itu. Ketika sampai pada rombongan yang berada di tengah, Rasulullah shallallahu 'alaihi wasallam bersabda kepadaku: \"Barbaiatlah wahai Salamah.\" Aku pun berkata kepada beliau, \"Aku telah berbaiat kepada anda pada rombongan pertama wahai Rasulullah.\" Namun beliau justru bersabda kepadaku: \"Berbaiatlah lagi waahi Salamah.\" Aku akhirnya menuruti permintaan beliau. Ketika beliau melihat aku tidak membawa senjata sama sekali, maka Rasulullah shallallahu 'alaihi wasallam memberikan tameng atau perisai kepadaku. Selanjutnya beliau menerima pembaiatan lagi dari rombongan yang terakhir. Pada saat itu, beliau kembali bertanya kepada aku: \"Mengapa kamu tidak ikut berbaiat kepadaku wahai Salamah?\" Aku menjawab, \"Aku telah berbaiat kepadamu wahai Rasulullah, bahkan tadi aku telah berbaiat kepada anda hingga dua kali, yaitu pada rombongan pertama dan rombongan pertengahan.\" Lalu Rasulullah shallallahu 'alaihi wasallam bersabda: \"Berbaiatlah sekali lagi wahai Salamah!\" Akhirnya aku ikut berbaiat kepada beliau untuk yang ketiga kalinya. Selesai berbaiat, Rasulullah shallallahu 'alaihi wasallam bertanya kepadaku: \"Wahai Salamah, mana tameng dan perisai yang aku berikan kepadamu?\" aku mencoba menjelaskan pertanyaan beliau, \"Wahai Rasulullah, tadi aku bertemu dengan pamanku, Amir, ternyata dia juga tidak mempunyai senjata sama sekali, maka tameng itu aku berikan kepadanya.\" Mendengar penjelasan itu, Rasulullah shallallahu 'alaihi wasallam tersenyum sambil bersabda: \"Sesungguhnya kamu seperti apa yang dikatakan oleh orang-orang dahulu, 'Ya Allah, ya Rabbku, berikanlah aku seorang kekasih yang lebih aku cintai daripada diriku sendiri'.\" Beberapa hari kemudian, kaum Musyrikin mengajak kami berdamai dengan cara mengirim kurir terlebih dahulu. Setelah mengalami proses yang tidak begitu lama, akhirnya kami sepakat untuk berdamai. Dahulu aku adalah pelayan Thalhah bin Ubaidillah, tugasku memberi minum kuda dan memandikannya. Sebagai imbalan dari pelayanannya tersebut, aku mendapatkan makan darinya. Aku memang bertekat untuk meninggalkan keluarga dan hartaku untuk berhijrah di jalan Allah dan Rasul-Nya. Ketika kesepakatan perjanjian damai antara kami dengan penduduk Makkah telah terjalin, hingga kami sudah bisa saling berbaur, maka suatu hari aku pergi menuju pepohonan untuk beristirahat di bawahnya. Pada saat berbaring di bawah pohon itulah, tiba-tiba datang empat orang Musyrikin dari peduduk kota Makkah yang tengah menggunjing Rasulullah shallallahu 'alaihi wasallam hingga membuat aku geram terhadap mereka. Lalu aku pidah ke batang pohon lainnya sambil melihat mereka menggantungkan senjatanya dan setelah itu mereka tertidur. Pada saat itulah, tiba-tiba terdengar suara orang yang menyeru dari dasar jurang, \"Hai kaum Muhajirin, Ibnu Zunaim telah terbunuh.\" Seketika itu juga aku cabut sambil mendatangi keempat orang musyrikin yang tengah tidur tersebut, aku ambil senjata mereka.\" Salamah melanjutkan, \"Setelah itu aku berkata kepada mereka, 'Demi dzat yang telah memuliakan wajah Muhammad, barangsiapa ada di antara kalian berani mengangkat kepalanya, maka akan kutebas lehernya.' Akhirnya keempat orang kafir Qurasiy tersebut aku giring ke hadapan Rasulullah shallallahu 'alaihi wasallam. Pada saat yang bersamaan aku melihat Amir, paman aku. Ternyata dia juga tengah menggiring seorang laki-laki Quraisy yang bernama Mikraz untuk di ajukan ke hadapan Rasulullah shallallahu 'alaihi wasallam. Lelaki Quraisy yang bernama Mikraz tersebut dibiarkan mengendarai seekor kuda yang ternyata diikuti sekitar tiga puluh orang musyrikin dari anak buahnya. Sejenak Rasulullah shallallahu 'alaihi wasallam memandangi mereka sambil bersabda: \"Biarkanlah mereka, karena mereka akan menaggung kezalimannya dari awal sampai akhir.\" Kemudian Rasulullah shallallahu 'alaihi wasallam memaafkan mereka, maka Allah menurunkan ayat: '(Dan Dialah yang menahan tangan mereka dari (membinasakan) kamu dan (menahan) tangan kamu dari (membinasakan) mereka di tengah kota Makkah setelah Allah memenangkan kamu atas mereka) ' (Qs. Al Fath: 24). Setelah kejadian itu, kami kembali pulang bersama-sama ke kota Madinah dengan membawa kemenangan. Namun sebelumnya, kami berhenti di suatu tempat. Sedangkan jarak kami dengan Bani Lihyan saat itu hanya dipisahkan oleh gunung, menurut informasi yang aku ketahui, kaum Bani Lihyan juga termasuk dari orang-orang Musyrik. Kemudian Rasulullah shallallahu 'alaihi wasallam menyatakan bahwa beliau akan mengampuni seseorang yang sanggup mendaki gunung tersebut pada malam hari. Memang, gunung yang ada di hadapan mereka itu seakan-akan sedang menantang Rasulullah shallallahu 'alaihi wasallam dan para sahabat yang hadir saat itu. Pada malam itu juga, aku berhasil mendaki gunung tersebut sebanyak dua atau tiga kali. Akhirnya kami tiba di kota Madinah. Lalu Rasulullah shallallahu 'alaihi wasallam mengutus Rabbah -pelayan beliau- untuk mengawal unta yang tengah membawa muatan yang cukup besar, lalu aku juga ikut menyertai Rabbah dengan menaiki kuda milik Thalhah. Keesokan harinya, aku mendengar informasi bahwa Abdurrahman Al Fazari hendak mencegat rombongan kami. Ternyata informasi itu benar, Abdurrahman dapat menawan unta Rasulullah shallallahu 'alaihi wasallam beserta muatannya. Bahkan kami dengar, dia berhasil membunuh orang yang mengendarai unta tersebut. Saat itu aku telah mengatakannya kepada Rabbah, 'Wahai Rabbah, ambillah kuda ini dan serahkanlah kepada Thalhah bin Ubaidullah, jangan sampai lupa, beritahukan kepada Rasulullah shallallahu 'alaihi wasallam bahwa orang-orang Musyrikin telah menawan rombongan unta yang beliau utus.' Setelah itu, aku naik ke atas bukit, sambil menghadap kota Madinah, aku berteriak dengan suara lantang, 'Wahai para penduduk! ' Sebanyak tiga kali berturut-turut. Kemudian aku turun dari atas bukit sambil terus melepaskan anak panah ke arah sasaran musuh, sementara itu untuk menghibur hati, aku bersenandung, 'Aku adalah putra Al Akwa', hari ini adalah hari kebinasaan! ' Dalam perjelanan mengejar musuh, aku bertemu seorang laki-laki dari kaum Musyrikin. Lalu aku mulai membidikkan anak panah ke arahnya. Tidak lama kemudian, aku berhasil menancapkan sebatang anak panah tepat mengenai bahunya, dari kejauhan aku katakan kepadanya, 'Rasakanlah anak panah itu, aku adalah putra Al Akwa', hari ini adalah hari kebinasaan'.\" Salamah berkata, \"Demi Allah, aku tetap terus melancarkan anak panah ke arah musuh. Tiba-tiba dari arah depan, aku melihat seorang musuh yang sedang menunggang kuda menuju ke arahku. Lalu aku bersembunyi di balik pohon yang rimbun. Begitu musuh yang menunggang kuda itu melintas, segera aku melepaskan anak panahku hingga berhasil melukainya. Tidak beberapa lama, datang lagi beberapa pasukan musuh. Namun seperti sebelumnya, aku langsung memanjat ke atas bukit. Dari atas bukit tersebut aku berupaya menahan laju mereka dengan cara melemparkan bebatuan ke arah mereka, dan ternyata cara tersebut berhasil. Mereka mundur secara teratur dan membiarkan aku terus mengejarnya. Karena merasa keberatan dengan beban yang mereka bawa, akhirnya mereka menjatuhkan sebagian besar perbekalan mereka dari unta Rasulullah shallallahu 'alaihi wasallam yang mereka ambil, agar lebih ringan dan dapat melarikan kendaraannya. Aku pun terus mengikuti laju mereka sambil melemparkan anak panah. Aku juga membuat jejak di jalan-jalan dengan bebatuan supaya dapat diketahui oleh Rasulullah shallallahu 'alaihi wasallam dan para sahabatnya, dari apa yang telah aku lakukan terhadap musuh-musuh tersebut. Dengan berhimpit-himpitan, pasukan kaum Musyrikin berusaha turun dari bukit dengan melewati jalan sempit yang ada di bukit. Untungnya, Fulan bin Badri Al Fazari telah siap menanti di bawah untuk membantu mereka. Kemudian mereka duduk sambil beristirahat karena kelelahan, sementara aku duduk di atas bukit. Dari atas bukit, aku mendengar Al Fazari bertanya kepada teman-temannya yang baru saja turun dari bukit, 'Ada apa ini? Apa yang telah terjadi pada kalian? ' mereka menjawab, 'Kami telah mengalami kepayahan, demi Allah, tidaklah kami melalui akhir malam, melainkan kami selalu dihujani anak panah, sehingga kami membuang sebagian besar perbekalan kami.' Lalu Al Fazari memerintahkan empat orang dari mereka untuk menghadapiku, akhirnya keempat orang tersebut bergegas naik ke atas bukit untuk menghadapiku. Ketika jarak antara aku dengan mereka sudah semakin dekat, hingga memungkinkan mereka mendengar suara aku, maka aku berseru, \"Hai kalian berempat, apakah kalian mengenalku? ' mereka menjawab, 'Tidak, kami tidak mengenalmu, siapa sebenarnya kamu? ' aku menjawab, 'Aku adalah Salamah bin Al Akwa', demi dzat yang memuliakan wajah Muhammad, aku tidak akan membiarkan kalian hidup, mungkin begitu pula dengan kalian yang tidak mungkin membiarkan aku hidup.' Lalu aku mendengar salah seorang dari keempat orang tersebut menjawab seperti yang aku katakan. Belum sampai aku pindah tempat, tiba-tiba aku melihat beberapa orang sahabat Rasulullah shallallahu 'alaihi wasallam yang tengah mengendarai kuda keluar dari balik semak-semak pepohonan menuju arah tempat aku berada.\" Salamah berkata, \"Pertama kali yang aku lihat adalah Akhram Al Asadi, disusul oleh Abu Qatadah Al Anshari. Setelah itu, muncullah Miqdad bin Aswad Al Kindi.\" Salamah melanjutkan, \"Lalu aku memegang tali kekang kuda milik akhram, ternyata mereka bergegas hendak maju membantu aku, segera aku berkata, \"Wahai Akhram, hati-hatilah terhadap mereka, jangan sampai mereka melukai atau mencelakaimu, hingga datang bala bantuan dari Rasulullah shallallahu 'alaihi wasallam dan para sahabat yang lain.\" Dia menjawab, \"Wahai Salamah, jika kamu benar-benar beriman kepada Allah dan Allah dan hari Kiamat, serta kamu yakin bahwa surga dan neraka itu sesuatu yang benar, maka janganlah kamu menghalangiku untuk memperoleh syahid.\" Salamah berkata, \"Kemudian aku membiarkannya maju untuk bertempur satu lawan satu, lalu Abdurrahman maju ke hadapan menghadapi Akhram, pada awalnya dia dapat melukai kuda Abdurrahman, namun akhirnya Abdurrahman dapat menikam akhram hingga dia gugur. Abdurrahman lantas menaiki kudanya. Setelah itu, majulah Abu Qatadah -prajurit penunggang kuda Rasulullah shallallahu 'alaihi wasallam- menghadapi Abdurrahman. Lalu Abu Qatadah dapat menikam Abdurrahman dan membunuhnya, demi dzat yang memuliakan wajah Muhammad shallallahu 'alaihi wasallam, aku terus membuntuti mereka dengan berjalan kaki hingga tak kulihat satupun sahabat Muhammad shallallahu 'alaihi wasallam dan tidak juga debunya. Menjelang matahari terbenam, mereka menuju ke jalan di bukit yang terdapat mata airnya bernama Dzu Qard, untuk mereka minum karena kehausan.\" Salamah berkata, \"Kemudian mereka melihatku berlari membuntuti mereka, kuhalangi mereka dari telaga itu sehingga mereka tak bisa meneguk setetes air.\" Salamah berkata, \"Lantas mereka meninggalkan tempat tersebut dengan bersusah payah menyusuri lereng-lereng bukit.\" Salamah melanjutkan, \"Lalu aku berlari dan menjumpai seseorang dari mereka, lantas kutusuk dengan anak panah tepat mengenai ujung tulang bahu.\" Salamah melanjutkan, \"Lalu kukatakan dengan nada mengejek, 'Coba kau cabut anak panah yang kutusukkan, aku adalah putra Al Akwa', hari ini adalah hari kebinasaan.' Sang musuh berujar, 'Pagi yang sial, betulkah kamu Akwa'? ' Aku menjawab, 'Betul hai musuh Allah, akulah Akwa' yang pagi dini membawa kesialan bagimu.' Akwa' meneruskan, \"Musuh mencelakai dua ekor kudanya di lereng gunung. Kugiring keduanya kepada Rasulullah shallallahu 'alaihi wasallam. Amir menyusulku dengan membawa geriba kulit berkantung dua, satu berisi susu campuran, dan satunya berisi air murni. Aku berwudlu dan minum, lantas kutemui Rasulullah shallallahu 'alaihi wasallam yang beliau tengah berada di sumber air yang kuhalangi musuh meminumnya. Ternyata Rasulullah telah mengambil seluruh unta dan segala yang kuselamatkan dari pasukan musyrik, juga tombak dan kain burdah. Saat itu, Bilal telah menyembelih seekor unta dari beberapa unta yang aku selamatkan dari orang Musyrik, kemudian dia mengambil hatinya dan punuknya dan membakarnya, setelah itu ia mempersembahkannya kepada Rasulullah shallallahu 'alaihi wasallam.\" Salamah melanjutkan, 'Aku berkata, 'Wahai Rasulullah, biarkanlah aku memilih seratus orang dari pasukan musuh, kemudian aku mengikuti mereka hingga tidak ada lagi yang menginformasikan posisi kita melainkan aku tebas batang lehernya'.\" Salamah berkata, \"Maka Rasulullah shallallahu 'alaihi wasallam tersenyum sehingga gigi geraham beliau terlihat jelas siang hari itu. Kemudian beliau bertanya: \"Wahai Salamah, apakah kamu telah siap dengan apa yang akan kamu lakukan itu?\" aku menjawab, \"Tentu, demi dzat yang telah memuliakan anda.\" Selanjutnya beliau bersabda: \"Ketahuilah wahai Salamah, sesungguhnya mereka sekarang sedang berada di wilayah kekuasaan orang-orang Ghathafan.\" Salamah berkata, \"Lalu datanglah seorang laki-laki dari Ghathafan seraya berkata, \"Si fulan telah menyembelih unta untuk mereka, ketika mereka menguliti hewan tersebut, tiba-tiba mereka melihat debu mengepul, hingga mereka lari terbirit-birit.\" Keesokan harinya Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sebaik-baik prajurit penunggang kuda saat ini adalah Abu Qatadah, sedangkan sebaik-baik prajurit pejalan kaki adalah salamah.\" Salamah melanjutkan, \"Kemudian Rasulullah shallallahu 'alaihi wasallam memberikan dua batang tombak kepadaku, yaitu; tombak untuk pasukan berkuda dan tombak untuk pejalan kaki, dan saat itu aku menggabungkan menjadi satu. Kemudian kami kembali ke Madinah dan aku membonceng di belakang Rasulullah shallallahu 'alaihi wasallam dengan menaiki Adzba`.\" Salamah berkata, \"Ketika kami berada di tengah jalan, -Salamah berkata- ada seorang sahabat Anshar yang mengajak kami untuk lomba lari cepat. Salamah berkata, \"Lalu sahabat Anshar itu berkata, 'Tidakkah ada orang yang mau berlomba lari menuju Madinah? ' dan ia mengulanginya sampai beberapa kali.\" Salamah melanjutkan, \"Setelah aku mendengar perkataannya, aku berkata, 'Apakah kamu hendak memuliakan orang yang mulia, ataukah hendak memperoleh wibawa di hadapan orang yang terpandang? ' dia menjawab, \"Tidak, namun untuk Rasulullah shallallahu 'alaihi wasallam.\" Salamah melanjutkan, \"Aku berkata, \"Wahai Rasulullah, demi ayah dan ibuku, biarkanlah aku melayani tantangan lomba lari laki-laki itu!\" Beliau menjawab: \"Silahkan jika kamu mau.\" Salamah berkata, \"Ayo mulai.\" Lalu aku berlari dengan kakiku, memang aku sengaja membiarkan dia hingga ia mendaki satu atau dua bukit, sebab aku khawatir akan kehabisan tenaga, kemudian aku berlari melewati jejaknya dan aku masih membiarkan dia mendaki satu atau dua bukit. Kemudian aku pacu lagi lariku sekencang-kencangnya sehingga aku dapat menjumpainya.\" Salamah berkata, \"Kemudian aku menepuk di antara pundaknya.\" Salamah melanjutkan, \"Aku berkata, 'Demi Allah, kamu telah didahului'.\" -Iyasy berkata; aku kira Salamah berkata- \"aku telah mendahuluinya ke Madinah.\" Salamah melanjutkan, \"Demi Allah, kami waktu i"},"3140":{"ar":"حَدَّثَنِي عَمْرُو بْنُ مُحَمَّدٍ النَّاقِدُ حَدَّثَنَا يَزِيدُ بْنُ هَارُونَ أَخْبَرَنَا حَمَّادُ بْنُ سَلَمَةَ عَنْ ثَابِتٍ عَنْ أَنَسِ بْنِ مَالِكٍأَنَّ ثَمَانِينَ رَجُلًا مِنْ أَهْلِ مَكَّةَ هَبَطُوا عَلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِنْ جَبَلِ التَّنْعِيمِ مُتَسَلِّحِينَ يُرِيدُونَ غِرَّةَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَأَصْحَابِهِ فَأَخَذَهُمْ سِلْمًا فَاسْتَحْيَاهُمْ فَأَنْزَلَ اللَّهُ عَزَّ وَجَلَّ{ وَهُوَ الَّذِي كَفَّ أَيْدِيَهُمْ عَنْكُمْ وَأَيْدِيَكُمْ عَنْهُمْ بِبَطْنِ مَكَّةَ مِنْ بَعْدِ أَنْ أَظْفَرَكُمْ عَلَيْهِمْ }","id":"Telah menceritakan kepadaku [Amru bin Muhammad An Naqid] telah menceritakan kepada kami [Yazid bin Harun] telah mengabarkan kepada kami [Hammad bin Salamah] dari [Tsabit] dari [Anas bin Malik], bahwa delapan puluh orang dari penduduk Makkah turun dari bukit Tan'im kepada Rasulullah shallallahu 'alaihi wasallam dengan persenjataan yang lengkap. Mereka hendak menyerang Nabi shallallahu 'alaihi wasallam dan para sahabatnya karena bentuk permusuhannya terhadap beliau. Namun akhirnya mereka menyerah dan beliau membiarkan mereka hidup, maka Allah Azza Wa Jalla menurunkan ayatnya: '(Dan Dialah yang menahan tangan mereka dari (membinasakan) kamu dan (menahan) tangan kamu dari (membinasakan) mereka di tengah kota Makkah sesudah Allah memenangkan kamu atas mereka) ' (Qs. Al Fath: 24)."},"3141":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا يَزِيدُ بْنُ هَارُونَ أَخْبَرَنَا حَمَّادُ بْنُ سَلَمَةَ عَنْ ثَابِتٍ عَنْ أَنَسٍأَنَّ أُمَّ سُلَيْمٍ اتَّخَذَتْ يَوْمَ حُنَيْنٍ خِنْجَرًا فَكَانَ مَعَهَا فَرَآهَا أَبُو طَلْحَةَ فَقَالَ يَا رَسُولَ اللَّهِ هَذِهِ أُمُّ سُلَيْمٍ مَعَهَا خِنْجَرٌ فَقَالَ لَهَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَا هَذَا الْخِنْجَرُ قَالَتْ اتَّخَذْتُهُ إِنْ دَنَا مِنِّي أَحَدٌ مِنْ الْمُشْرِكِينَ بَقَرْتُ بِهِ بَطْنَهُ فَجَعَلَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَضْحَكُ قَالَتْ يَا رَسُولَ اللَّهِ اقْتُلْ مَنْ بَعْدَنَا مِنْ الطُّلَقَاءِ انْهَزَمُوا بِكَ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَا أُمَّ سُلَيْمٍ إِنَّ اللَّهَ قَدْ كَفَى وَأَحْسَنَو حَدَّثَنِيهِ مُحَمَّدُ بْنُ حَاتِمٍ حَدَّثَنَا بَهْزٌ حَدَّثَنَا حَمَّادُ بْنُ سَلَمَةَ أَخْبَرَنَا إِسْحَقُ بْنُ عَبْدِ اللَّهِ بْنِ أَبِي طَلْحَةَ عَنْ أَنَسِ بْنِ مَالِكٍ فِي قِصَّةِ أُمِّ سُلَيْمٍ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِثْلَ حَدِيثِ ثَابِتٍ","id":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] telah menceritakan kepada kami [Yazid bin Harun] telah mengabarkan kepada kami [Hammad bin Salamah] dari [Tsabit] dari [Anas], bahwa Ummu Sulaim selalu membawa parang ketika perang Hunain, lalu Abu Thalhah melihatnya sehingga ia pun mengadu, \"Wahai Rasulullah, Ummu Sulaim selalu membawa parang.\" Beliau lalu bertanya kepada Ummu Sulaim: \"Untuk apakah kamu selalu membawa parang?\" Ummu Sulaim membawa, \"Jika ada orang Musyrik mendekatiku, maka aku akan membelah perutnya.\" Rasulullah shallallahu 'alaihi wasallam tertawa mendengarnya. Ummu Sulaim berkata, \"Wahai Rasulullah, bunuhlah orang-orang yang anda bebaskan di hari penaklukan kota Makkah, sekarang mereka telah lari dari Anda.\" Maka Rasulullah shallallahu 'alaihi wasallam bersabda: \"Wahai Ummu Sulaim, sesungguhnya Allah telah mencukupi dan memperbaiki.\" Dan telah menceritakan kepadaku [Muhammad bin Hatim] telah menceritakan kepada kami [Bahz] telah menceritakan kepada kami [Hammad bin Salamah] telah mengabarkan kepada kami [Ishaq bin Abdullah bin Abu Thalhah] dari [Anas bin Malik] tentang kisah Ummu Sulaim, dari Nabi shallallahu 'alaihi wasallam seperti haditsnya Tsabit.\""},"3142":{"ar":"حَدَّثَنَا يَحْيَى بْنُ يَحْيَى أَخْبَرَنَا جَعْفَرُ بْنُ سُلَيْمَانَ عَنْ ثَابِتٍ عَنْ أَنَسِ بْنِ مَالِكٍ قَالَكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَغْزُو بِأُمِّ سُلَيْمٍ وَنِسْوَةٍ مِنْ الْأَنْصَارِ مَعَهُ إِذَا غَزَا فَيَسْقِينَ الْمَاءَ وَيُدَاوِينَ الْجَرْحَى","id":"Telah menceritakan kepada kami [Yahya bin Yahya] telah mengabarkan kepada kami [Ja'far bin Sulaiman] dari [Tsabit] dari [Anas bin Malik] dia berkata, \"Rasulullah shallallahu 'alaihi wasallam pernah berperang bersama-sama dengan Ummu Sulaim dan beberap wanita Anshar, ketika perang berkecamuk, mereka memberi minum dan mengobati tentara yang terluka.\""},"3143":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ عَبْدِ الرَّحْمَنِ الدَّارِمِيُّ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ عَمْرٍو وَهُوَ أَبُو مَعْمَرٍ الْمِنْقَرِيُّ حَدَّثَنَا عَبْدُ الْوَارِثِ حَدَّثَنَا عَبْدُ الْعَزِيزِ وَهُوَ ابْنُ صُهَيْبٍ عَنْ أَنَسِ بْنِ مَالِكٍ قَالَلَمَّا كَانَ يَوْمُ أُحُدٍ انْهَزَمَ نَاسٌ مِنْ النَّاسِ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَأَبُو طَلْحَةَ بَيْنَ يَدَيْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مُجَوِّبٌ عَلَيْهِ بِحَجَفَةٍ قَالَ وَكَانَ أَبُو طَلْحَةَ رَجُلًا رَامِيًا شَدِيدَ النَّزْعِ وَكَسَرَ يَوْمَئِذٍ قَوْسَيْنِ أَوْ ثَلَاثًا قَالَ فَكَانَ الرَّجُلُ يَمُرُّ مَعَهُ الْجَعْبَةُ مِنْ النَّبْلِ فَيَقُولُ انْثُرْهَا لِأَبِي طَلْحَةَ قَالَ وَيُشْرِفُ نَبِيُّ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَنْظُرُ إِلَى الْقَوْمِ فَيَقُولُ أَبُو طَلْحَةَ يَا نَبِيَّ اللَّهِ بِأَبِي أَنْتَ وَأُمِّي لَا تُشْرِفْ لَا يُصِبْكَ سَهْمٌ مِنْ سِهَامِ الْقَوْمِ نَحْرِي دُونَ نَحْرِكَ قَالَ وَلَقَدْ رَأَيْتُ عَائِشَةَ بِنْتَ أَبِي بَكْرٍ وَأُمَّ سُلَيْمٍ وَإِنَّهُمَا لَمُشَمِّرَتَانِ أَرَى خَدَمَ سُوقِهِمَا تَنْقُلَانِ الْقِرَبَ عَلَى مُتُونِهِمَا ثُمَّ تُفْرِغَانِهِ فِي أَفْوَاهِهِمْ ثُمَّ تَرْجِعَانِ فَتَمْلَآَنِهَا ثُمَّ تَجِيئَانِ تُفْرِغَانِهِ فِي أَفْوَاهِ الْقَوْمِ وَلَقَدْ وَقَعَ السَّيْفُ مِنْ يَدَيْ أَبِي طَلْحَةَ إِمَّا مَرَّتَيْنِ وَإِمَّا ثَلَاثًا مِنْ النُّعَاسِ","id":"Telah menceritakan kepada kami [Abdullah bin Abdurrahman Ad Darimi] telah menceritakan kepada kami [Abdullah bin 'Amru] -yaitu Abu Ma'mar Al Minqari- telah menceritakan kepada kami [Abdul Warits] telah menceritakan kepada kami [Abdul Aziz] -yaitu Ibnu Shuhaib- dari [Anas bin Malik] dia berkata, \"Ketika perang Uhud berkecamuk, beberapa orang dari pasukan Islam lari meninggalkan Nabi shallallahu 'alaihi wasallam, sedangkan Abu Thalhah adalah seorang pamanah yang terampil. Pada hari itu, dia sampai mematahkan dua atau tiga busur panah.\" Anas mengatakan, \"Saat itu ada seseorang yang lewat di hadapan temannya dengan membawa panah, maka temanya berkata, \"Berikanlah itu kepada Abu Thalhah!\" Anas melanjutkan, \"Nabi shallallahu 'alaihi wasallam sendiri berdiri tegak memperhatikan seluruh pasukan. Lalu Abu Thalhah berkata, \"Wahai Nabi Allah, demi ayah dan ibuku sebagai tebusannya, aku memohon anda tidak berdiri tegak supaya tidak terkena panah musuh, biarlah leherku yang terkena asal bukan leher anda.\" Kata Anas selanjutnya, \"Sungguh, aku melihat 'Aisyah binti Abu Bakar dan Ummu Sulaim, keduanya menyingsingkan pakainnya sehingga terlihat olehku gelang kakinya, keduanya membawa geribah di punggung mereka, kemudian dituangkannya di mulut kaum Muslimin. Sesudah itu mereka pergi lagi mengisi geribah mereka dan datang lagi untuk menuangkannya ke mulut anggota pasukan. Seusai pertempuran, pedang Abu Thalhah sampai terjatuh dua hingga tiga kali karena sangat mengantuknya.\""},"3144":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ مَسْلَمَةَ بْنِ قَعْنَبٍ حَدَّثَنَا سُلَيْمَانُ يَعْنِي ابْنَ بِلَالٍ عَنْ جَعْفَرِ بْنِ مُحَمَّدٍ عَنْ أَبِيهِ عَنْ يَزِيدَ بْنِ هُرْمُزَ أَنَّ نَجْدَةَ كَتَبَ إِلَى ابْنِ عَبَّاسٍ يَسْأَلُهُ عَنْ خَمْسِ خِلَالٍ فَقَالَ ابْنُ عَبَّاسٍ لَوْلَا أَنْ أَكْتُمَ عِلْمًا مَا كَتَبْتُ إِلَيْهِ كَتَبَ إِلَيْهِ نَجْدَةُ أَمَّا بَعْدُ فَأَخْبِرْنِيهَلْ كَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَغْزُو بِالنِّسَاءِ وَهَلْ كَانَ يَضْرِبُ لَهُنَّ بِسَهْمٍ وَهَلْ كَانَ يَقْتُلُ الصِّبْيَانَ وَمَتَى يَنْقَضِي يُتْمُ الْيَتِيمِ وَعَنْ الْخُمْسِ لِمَنْ هُوَ فَكَتَبَ إِلَيْهِ ابْنُ عَبَّاسٍ كَتَبْتَ تَسْأَلُنِي هَلْ كَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَغْزُو بِالنِّسَاءِ وَقَدْ كَانَ يَغْزُو بِهِنَّ فَيُدَاوِينَ الْجَرْحَى وَيُحْذَيْنَ مِنْ الْغَنِيمَةِ وَأَمَّا بِسَهْمٍ فَلَمْ يَضْرِبْ لَهُنَّ وَإِنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَمْ يَكُنْ يَقْتُلُ الصِّبْيَانَ فَلَا تَقْتُلْ الصِّبْيَانَ وَكَتَبْتَ تَسْأَلُنِي مَتَى يَنْقَضِي يُتْمُ الْيَتِيمِ فَلَعَمْرِي إِنَّ ا��رَّجُلَ لَتَنْبُتُ لِحْيَتُهُ وَإِنَّهُ لَضَعِيفُ الْأَخْذِ لِنَفْسِهِ ضَعِيفُ الْعَطَاءِ مِنْهَا فَإِذَا أَخَذَ لِنَفْسِهِ مِنْ صَالِحِ مَا يَأْخُذُ النَّاسُ فَقَدْ ذَهَبَ عَنْهُ الْيُتْمُ وَكَتَبْتَ تَسْأَلُنِي عَنْ الْخُمْسِ لِمَنْ هُوَ وَإِنَّا كُنَّا نَقُولُ هُوَ لَنَا فَأَبَى عَلَيْنَا قَوْمُنَا ذَاكَحَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ وَإِسْحَقُ بْنُ إِبْرَاهِيمَ كِلَاهُمَا عَنْ حَاتِمِ بْنِ إِسْمَعِيلَ عَنْ جَعْفَرِ بْنِ مُحَمَّدٍ عَنْ أَبِيهِ عَنْ يَزِيدَ بْنِ هُرْمُزَ أَنَّ نَجْدَةَ كَتَبَ إِلَى ابْنِ عَبَّاسٍ يَسْأَلُهُ عَنْ خِلَالٍ بِمِثْلِ حَدِيثِ سُلَيْمَانَ بْنِ بِلَالٍ غَيْرَ أَنَّ فِي حَدِيثِ حَاتِمٍ وَإِنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَمْ يَكُنْ يَقْتُلُ الصِّبْيَانَ فَلَا تَقْتُلْ الصِّبْيَانَ إِلَّا أَنْ تَكُونَ تَعْلَمُ مَا عَلِمَ الْخَضِرُ مِنْ الصَّبِيِّ الَّذِي قَتَلَ وَزَادَ إِسْحَقُ فِي حَدِيثِهِ عَنْ حَاتِمٍ وَتُمَيِّزَ الْمُؤْمِنَ فَتَقْتُلَ الْكَافِرَ وَتَدَعَ الْمُؤْمِنَ","id":"Telah menceritakan kepada kami [Abdullah bin Maslamah bin Qa'nab] telah menceritakan kepada kami [Sulaiman] -yaitu Ibnu Bilal- dari [Ja'far bin Muhammad] dari [ayahnya] dari [Yazid bin Hurmuz] bahwa Najdah pernah menulis surat kepada [Ibnu Abbas] dan menanyakan mengenai lima masalah. Ibnu Abbas berkata, \"Kalaulah aku tidak khawatir akan dianggap menyembunyikan ilmu, maka tidak akan kubalas suratnya.\" (surat 'Abdah -red): \"Amma Ba'd, tolonglah kabarkan kepadaku, adakah kaum wanita yang pergi berperang bersama-sama dengan Rasulullah shallallahu 'alaihi wasallam? Apakah mereka juga diberi ghanimah? Apakah beliau membunuh anak-anak? Kapankah seorang anak tidak lagi dikatakan yatim? Dan untuk siapakah diberikan seperlima pembagian harta ghanimah?\" Ibnu Abbas membalas suratnya: \"Anda menanyakan kepadaku, apakah para wanita ikut berperang bersama-sama dengan Rasulullah shallallahu 'alaihi wasallam? Betul, beliau pergi berperang bersama dengan para wanita. Mereka bertugas mengobati pasukan yang terluka, dan mereka diberi harta ghanimah ala kadarnya, tetapi mereka tidak diberi jumlah tertentu. Dan sesungguhnya beliau tidak pernah membunuh anak-anak, oleh karena itu, tahanlah kalian dari membunuh anak-anak. Kamu menanyakan kepadaku, mengenai kapan masa habisnya keyatiman anak yatim? Demi Dzat yang memanjangkan umurku, ada orang yang telah tumbuh jenggotnya, namun dia masih lemah mengurus dirinya, lemah mengambil dirinya sendiri atau memberi kepada dirinya sendiri. Maka apabila dia sudah sanggup mengurus dirinya sendiri, mengambil apa yang baik bagi dirinya seperti halnya orang lain. Maka ketika itu dia habis masa keyatimannya. Dan anda menanyakan pula tentang untuk siapa seperlima harta ghanimah tersebut?, sesungguhnya kami pernah mengatakan, itu untuk kami (Bani Hasyim), namun keluarga kami keberatan atas kami.\" Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] dan [Ishaq bin Ibrahim] keduanya dari [Hatim bin Isma'il] dari [Ja'far bin Muhammad] dari [ayahnya] dari [Yazid bin Hurmuz] bahwa Najdah pernah menulis surat kepada [Ibnu Abbas] untuk menanyakan mengenai hal itu sebagaimana hadits Sulaiman bin Bilal, namun dalam hadits Hatim, Rasulullah shallallahu 'alaihi wasallam tidak pernah membunuh anak-anak, oleh karena itu janganlah kamu membunuh anak-anak, kecuali jika kamu mengetahui seorang anak tersebut ikut dalam berperang.\" Dan Ishaq menyebutkan dalam haditsnya dari Hatim, bahwa 'Kamu dapat membedakan antara yang mukmin, kemudian kamu bunuh yang kafir dan tinggalkanlah yang mukmin'.\""},"3145":{"ar":"و حَدَّثَنَا ابْنُ أَبِي عُمَرَ حَدَّثَنَا سُفْيَانُ عَنْ إِسْمَعِيلَ بْنِ أُمَيَّةَ عَنْ سَعِيدٍ الْمَقْبُرِيِّ عَنْ يَزِيدَ بْنِ هُرْمُزَ قَالَ كَتَبَ نَجْدَةُ بْنُ عَامِرٍ الْحَرُورِيُّ إِلَى ابْنِ عَبَّاسٍ يَسْأَلُهُ عَنْ الْعَبْدِ وَالْمَرْأَةِ يَحْضُرَانِ الْمَغْنَمَ هَلْ يُقْسَمُ لَهُمَا وَعَنْ قَتْلِ الْوِلْدَانِ وَعَنْ الْيَتِيمِ مَتَى يَنْقَطِعُ عَنْهُ الْيُتْمُ وَعَنْ ذَوِي الْقُرْبَى مَنْ هُمْ فَقَالَ لِيَزِيدَ اكْتُبْ إِلَيْهِ فَلَوْلَا أَنْ يَقَعَ فِي أُحْمُوقَةٍ مَا كَتَبْتُ إِلَيْهِاكْتُبْ إِنَّكَ كَتَبْتَ تَسْأَلُنِي عَنْ الْمَرْأَةِ وَالْعَبْدِ يَحْضُرَانِ الْمَغْنَمَ هَلْ يُقْسَمُ لَهُمَا شَيْءٌ وَإِنَّهُ لَيْسَ لَهُمَا شَيْءٌ إِلَّا أَنْ يُحْذَيَا وَكَتَبْتَ تَسْأَلُنِي عَنْ قَتْلِ الْوِلْدَانِ وَإِنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَمْ يَقْتُلْهُمْ وَأَنْتَ فَلَا تَقْتُلْهُمْ إِلَّا أَنْ تَعْلَمَ مِنْهُمْ مَا عَلِمَ صَاحِبُ مُوسَى مِنْ الْغُلَامِ الَّذِي قَتَلَهُ وَكَتَبْتَ تَسْأَلُنِي عَنْ الْيَتِيمِ مَتَى يَنْقَطِعُ عَنْهُ اسْمُ الْيُتْمِ وَإِنَّهُ لَا يَنْقَطِعُ عَنْهُ اسْمُ الْيُتْمِ حَتَّى يَبْلُغَ وَيُؤْنَسَ مِنْهُ رُشْدٌ وَكَتَبْتَ تَسْأَلُنِي عَنْ ذَوِي الْقُرْبَى مَنْ هُمْ وَإِنَّا زَعَمْنَا أَنَّا هُمْ فَأَبَى ذَلِكَ عَلَيْنَا قَوْمُنَاو حَدَّثَنَاه عَبْدُ الرَّحْمَنِ بْنُ بِشْرٍ الْعَبْدِيُّ حَدَّثَنَا سُفْيَانُ حَدَّثَنَا إِسْمَعِيلُ بْنُ أُمَيَّةَ عَنْ سَعِيدِ بْنِ أَبِي سَعِيدٍ عَنْ يَزِيدَ بْنِ هُرْمُزَ قَالَ كَتَبَ نَجْدَةُ إِلَى ابْنِ عَبَّاسٍ وَسَاقَ الْحَدِيثَ بِمِثْلِهِ قَالَ أَبُو إِسْحَقَ حَدَّثَنِي عَبْدُ الرَّحْمَنِ بْنُ بِشْرٍ حَدَّثَنَا سُفْيَانُ بِهَذَا الْحَدِيثِ بِطُولِهِ","id":"Dan telah menceritakan kepada kami [Ibnu Abu Umar] telah menceritakan kepada kami [Sufyan] dari [Isma'il bin Umayyah] dari [Sa'id Al Maqbiri] dari [Yazid bin Hurmuz] dia berkata, \"Najdah bin 'Amir pernah menulis surat kepada [Ibnu Abbas], dia bertanya mengenai seorang budak dan seorang wanita yang ikut serta dalam peperangan, apakah keduanya diberi bagian khsusus? Dan mengenai membunuh anak-anak, masa habis keyatiman seorang anak yatim dan mengenai dzawil qurba, siapakah mereka itu?\" maka Ibnu Abbas berkata kepada Yazid, \"Balaslah suratnya, sekiranya aku tidak khawatir ia mengiraku berpura-pura bodoh, niscaya aku tidak akan membalas suratnya, tulislah; 'Sesungguhnya kamu bertanya kepadaku mengenai seorang wanita dan budak yang ikut mengumpulkan ghanimah, apakah dia mendapatkan bagian yang khusus? Dia tidak mendapatkan bagian tertentu melainkan ia diberi sebatas ala kadarnya. Dan bertanya mengenai membunuh anak-anak, sesungguhnya Rasulullah shallallahu 'alaihi wasallam tidak membunuh anak-anak, oleh karena itu, janganlah kamu membunuh anak-anak, kecuali sebagaimana yang telah kamu ketahui apa yang diperbuat oleh sahabatnya Musa -(Khidzir -red) yang telah membunuh seorang anak. Dan kamu menulis surat untuk bertanya kepadaku mengenai batasan anak yatim, kapankah terputus keyatimannya? Bahwa keyatiman belum terputus dari seorang anak yatim hingga dia baligh dan matang kecerdasannya (sanggup menurus dirinya sendiri). Kamu menulis surat untuk bertanya kepadaku mengenai dzawil qurba, siapakah sebenarnya mereka? aku kira bahwa aku termasuk dari mereka, namun kaumku keberatan atas kami.\" Dan telah menceritakan kepada kami [Abdurrahman bin Bisyr Al 'Abdi] telah menceritakan kepada kami [Sufyan] telah menceritakan kepada kami [Isma'il bin Umayyah] dari [Sa'id bin Abu Sa'id] dari [Yazid bin Hurmuz] dia berkata, \"Najdah pernah menulis surat kepada [Ibnu Abbas]... kemudian dia melanjutkan hadits tersebut seperti hadits di atas.\" Abu Ihsaq berkata; telah menceritakan kepadaku Abdurrahman bin Bisyr telah menceritakan kepada kami Sufyan dengan hadits yang sangat panjang ini.\""},"3146":{"ar":"حَدَّثَنَا إِسْحَقُ بْنُ إِبْرَاهِيمَ أَخْبَرَنَا وَهْبُ بْنُ جَرِيرِ بْنِ حَازِمٍ حَدَّثَنِي أَبِي قَالَ سَمِعْتُ قَيْسًا يُحَدِّثُ عَنْ يَزِيدَ بْنِ هُرْمُزَ ح و حَدَّثَنِي مُحَمَّدُ بْنُ حَاتِمٍ وَاللَّفْظُ لَهُ قَالَ حَدَّثَنَا بَهْزٌ حَدَّثَنَا جَرِيرُ بْنُ حَازِمٍ حَدَّثَنِي قَيْسُ بْنُ سَعْدٍ عَنْ يَزِيدَ بْنِ هُرْمُزَ قَالَ كَتَبَ نَجْدَةُ بْنُ عَامِرٍ إِلَى ابْنِ عَبَّاسٍ قَالَفَشَهِدْتُ ابْنَ عَبَّاسٍ حِينَ قَرَأَ كِتَابَهُ وَحِينَ كَتَبَ جَوَابَهُ وَقَالَ ابْنُ عَبَّاسٍ وَاللَّهِ لَوْلَا أَنْ أَرُدَّهُ عَنْ نَتْنٍ يَقَعُ فِيهِ مَا كَتَبْتُ إِلَيْهِ وَلَا نُعْمَةَ عَيْنٍ قَالَ فَكَتَبَ إِلَيْهِ إِنَّكَ سَأَلْتَ عَنْ سَهْمِ ذِي الْقُرْبَى الَّذِي ذَكَرَ اللَّهُ مَنْ هُمْ وَإِنَّا كُنَّا نَرَى أَنَّ قَرَابَةَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ هُمْ نَحْنُ فَأَبَى ذَلِكَ عَلَيْنَا قَوْمُنَا وَسَأَلْتَ عَنْ الْيَتِيمِ مَتَى يَنْقَضِي يُتْمُهُ وَإِنَّهُ إِذَا بَلَغَ النِّكَاحَ وَأُونِسَ مِنْهُ رُشْدٌ وَدُفِعَ إِلَيْهِ مَالُهُ فَقَدْ انْقَضَى يُتْمُهُ وَسَأَلْتَ هَلْ كَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقْتُلُ مِنْ صِبْيَانِ الْمُشْرِكِينَ أَحَدًا فَإِنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَمْ يَكُنْ يَقْتُلُ مِنْهُمْ أَحَدًا وَأَنْتَ فَلَا تَقْتُلْ مِنْهُمْ أَحَدًا إِلَّا أَنْ تَكُونَ تَعْلَمُ مِنْهُمْ مَا عَلِمَ الْخَضِرُ مِنْ الْغُلَامِ حِينَ قَتَلَهُ وَسَأَلْتَ عَنْ الْمَرْأَةِ وَالْعَبْدِ هَلْ كَانَ لَهُمَا سَهْمٌ مَعْلُومٌ إِذَا حَضَرُوا الْبَأْسَ فَإِنَّهُمْ لَمْ يَكُنْ لَهُمْ سَهْمٌ مَعْلُومٌ إِلَّا أَنْ يُحْذَيَا مِنْ غَنَائِمِ الْقَوْمِو حَدَّثَنِي أَبُو كُرَيْبٍ حَدَّثَنَا أَبُو أُسَامَةَ حَدَّثَنَا زَائِدَةُ حَدَّثَنَا سُلَيْمَانُ الْأَعْمَشُ عَنْ الْمُخْتَارِ بْنِ صَيْفِيٍّ عَنْ يَزِيدَ بْنِ هُرْمُزَ قَالَ كَتَبَ نَجْدَةُ إِلَى ابْنِ عَبَّاسٍ فَذَكَرَ بَعْضَ الْحَدِيثِ وَلَمْ يُتِمَّ الْقِصَّةَ كَإِتْمَامِ مَنْ ذَكَرْنَا حَدِيثَهُمْ","id":"Telah menceritakan kepada kami [Ishaq bin Ibrahim] telah mengabarkan kepada kami [Wahb bin Jarir bin Hazim] telah menceritakan kepadaku [ayahku] dia berkata; aku mendengar [Qias] menceritakan dari [Yazid bin Hurmuz]. (dalam jalur lain disebutkan) Telah menceritakan kepadaku [Muhammad bin Hatim] sedangkan lafadznya dari dia, dia berkata; telah menceritakan kepada kami [Bahz] telah menceritakan kepada kami [Jarir bin Hazim] telah menceritakan kepadaku [Qais bin Sa'd] dari [Yazid bin Hurmuz] dia berkata, \"Najdah bin 'Amir pernah mengirim surat kepada [Ibnu Abbas].\" Yazid bin Hurmuz berkata, \"Aku menyaksikan Ibnu Abbas ketika dia membaca suratnya dan ketika dia membalas suratnya, Ibnu Abbas berkata, \"Demi Allah, sekiranya aku tidak khawatir dia akan memandang jelek aku, niscaya aku tidak akan membalas suratnya dan juga memuliakannya.\" Yazid berkata, \"Lantas Ibnu Abbas membalas suratnya, \"Sesungguhnya kamu telah menanyakan mengenai bagian Dzawil Qurba sebagaimana yang telah disebutkan Allah, siapakah sebenarnya mereka? Sesungguhnya kami berpendapat bahwa kerabat Rasulullah shallallahu 'alaihi wasallam adalah kami, namun kaum kami keberatan atas kami. Kamu bertanya mengenai kapankah terputusnya keyatiman? Sesungguhnya terputusnya keyatiman adalah jika seseorang itu telah menikah dan telah matang kecerdasannya (dapat mengurus diri -red), dan dapat mempergunakan hartanya dengan semestinya, maka keyatiman telah terputus darinya. Dan kamu bertanya mengenai apakah Rasulullah shallallahu 'alaihi wasallam pernah membunuh anak-anak orang Musyrik? Sesungguhnya Rasulullah shallallahu 'alaihi wasallam tidak pernah sama sekali membunuh anak-anak mereka, oleh karena itu janganlah kamu membunuh anak-anak melainkan jika kamu mengetahui dari mereka sebagaimana yang diketahui oleh Khidzir yang membunuh seorang anak kecil. Kamu bertanya mengenai seorang budak dan wanita, apakah keduanya dapat bagian tertentu jika keduanya ikut serta perang? Sesungguhnya mereka tidak mendapatkan bagian tertentu melainkan ia mendapatkan bagian ala kadarnya dari harta ghanimah.\" Dan telah menceritakan kepadaku [Abu Kuraib] telah menceritakan kepada kami [Abu Usamah] telah menceritakan kepada kami [Za`idah] telah menceritakan kepada kami [Sulaiman, Al A'masy] dari [Al Mukhtar bin Shaifi] dari [Yazid bin Hurmuz] dia berkata, \"Najdah pernah mengirim surat kepada [Ibnu Abbas]...kemudian dia menyebutkan sebagian hadits, namun tidak sampai sempurna, sebagaimana sempurnanya hadits yang telah kami sebutkan dari hadits mereka.\""},"3147":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا عَبْدُ الرَّحِيمِ بْنُ سُلَيْمَانَ عَنْ هِشَامٍ عَنْ حَفْصَةَ بِنْتِ سِيرِينَ عَنْ أُمِّ عَطِيَّةَ الْأَنْصَارِيَّةِ قَالَتْغَزَوْتُ مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ سَبْعَ غَزَوَاتٍ أَخْلُفُهُمْ فِي رِحَالِهِمْ فَأَصْنَعُ لَهُمْ الطَّعَامَ وَأُدَاوِي الْجَرْحَى وَأَقُومُ عَلَى الْمَرْضَىو حَدَّثَنَا عَمْرٌو النَّاقِدُ حَدَّثَنَا يَزِيدُ بْنُ هَارُونَ حَدَّثَنَا هِشَامُ بْنُ حَسَّانَ بِهَذَا الْإِسْنَادِ نَحْوَهُ","id":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] telah menceritakan kepada kami [Abdurrahim bin Sulaiman] dari [Hisyam] dari [Hafshah binti Sirin] dari [Ummu 'Athiyah Al Anshariyah] dia berkata, \"Aku pernah ikut berperang bersama-sama dengan Rasulullah shallallahu 'alaihi wasallam sebanyak tujuh kali peperangan, aku tinggal di perkemahan mereka, memasak makanan untuk mereka, mengobati yang luka dan merawat orang-orang yang sakit.\" Dan telah menceritakan kepada kami ['Amru An Naqid] telah menceritakan kepada kami [Yazid bin Harun] telah menceritakan kepada kami [Hisyam bin Hasan] dengan isnad seperti ini.\""},"3148":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ الْمُثَنَّى وَابْنُ بَشَّارٍ وَاللَّفْظُ لِابْنِ الْمُثَنَّى قَالَا حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ حَدَّثَنَا شُعْبَةُ عَنْ أَبِي إِسْحَقَ أَنَّ عَبْدَ اللَّهِ بْنَ يَزِيدَ خَرَجَ يَسْتَسْقِي بِالنَّاسِ فَصَلَّى رَكْعَتَيْنِ ثُمَّ اسْتَسْقَى قَالَ فَلَقِيتُ يَوْمَئِذٍ زَيْدَ بْنَ أَرْقَمَ وَقَالَ لَيْسَ بَيْنِي وَبَيْنَهُ غَيْرُ رَجُلٍ أَوْ بَيْنِي وَبَيْنَهُ رَجُلٌ قَالَ فَقُلْتُ لَهُكَمْ غَزَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ تِسْعَ عَشْرَةَ فَقُلْتُ كَمْ غَزَوْتَ أَنْتَ مَعَهُ قَالَ سَبْعَ عَشْرَةَ غَزْوَةً قَالَ فَقُلْتُ فَمَا أَوَّلُ غَزْوَةٍ غَزَاهَا قَالَ ذَاتُ الْعُسَيْرِ أَوْ الْعُشَيْرِ","id":"Telah menceritakan kepada kami [Muhammad bin Al Mutsanna] dan [Ibnu Al Basyar] sedangkan lafadznya dari Ibnu Al Mutsanna, keduanya berkata; telah menceritakan kepada kami [Muhammad bin Ja'far] telah menceritakan kepada kami [Syu'bah] dari [Abu Ishaq] bahwa [Abdullah bin Yazid] keluar untuk shalat istisqa' bersama-sama dengan manusia, kemudian dia shalat dua rakaat dan beristisqa' (do'a minta hujan), dia berkata, \"Saat itu aku bertemu dengan Zaid bin Arqam.\" Dia melanjutkan, \"Dan tidak ada seorang pun antara kami dengan dia melainkan ada seorang laki-laki, atau mengatakan, \"antara aku dengan dia ada seorang laki-laki.\" Abdullah bin Yazid berkata, \"Lantas aku bertanya kepadanya, \"Berapa kalikah Rasulullah ikut berperang?\" dia menjawab, \"Sembilan belas kali.\" Aku bertanya lagi, \"Berapa kalikah kamu ikut berperang bersama-sama dengan Rasulullah shallallahu 'alaihi wasallam?\" dia menjawab, \"Tujuh belas kali peperangan.\" Abdullah berkata, \"Lantas aku bertanya, 'Peperangan apa yang pertama kali beliau ikuti? dia menjawab, \"Perang Dzatul 'Usair atau 'Usyair.\""},"3149":{"ar":"و حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا يَحْيَى بْنُ آدَمَ حَدَّثَنَا زُهَيْرٌ عَنْ أَبِي إِسْحَقَ عَنْ زَيْدِ بْنِ أَرْقَمَ سَمِعَهُ مِنْهُأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ غَزَا تِسْعَ عَشْرَةَ غَزْوَةً وَحَجَّ بَعْدَ مَا هَاجَرَ حَجَّةً لَمْ يَحُجَّ غَيْرَهَا حَجَّةَ الْوَدَاعِ","id":"Dan telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] telah menceritakan kepada kami [Yahya bin Adam] telah menceritakan kepada kami [Zuhair] dari [Abu Ishaq] dari [Zaid bin Arqam] ia mendengarnya darinya, bahwa Rasulullah shallallahu 'alaihi wasallam pernah berperang sebanyak sembilan belas kali peperangan. Dan setelah hijrah, beliau hanya melakukan haji hanya sekali, beliau belum pernah melakukan haji selain haji Wada'.\""},"3150":{"ar":"حَدَّثَنَا زُهَيْرُ بْنُ حَرْبٍ حَدَّثَنَا رَوْحُ بْنُ عُبَادَةَ حَدَّثَنَا زَكَرِيَّاءُ أَخْبَرَنَا أَبُو الزُّبَيْرِ أَنَّهُ سَمِعَ جَابِرَ بْنَ عَبْدِ اللَّهِ يَقُولُاغَزَوْتُ مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ تِسْعَ عَشْرَةَ غَزْوَةً قَالَ جَابِرٌ لَمْ أَشْهَدْ بَدْرًا وَلَا أُحُدًا مَنَعَنِي أَبِي فَلَمَّا قُتِلَ عَبْدُ اللَّهِ يَوْمَ أُحُدٍ لَمْ أَتَخَلَّفْ عَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي غَزْوَةٍ قَطُّ","id":"Telah menceritakan kepada kami [Zuhair bin Harb] telah menceritakan kepada kami [Rauh bin 'Ubadah] telah menceritakan kepada kami [Zakaria] telah mengabarkan kepada kami [Abu Az Zubair] bahwa dia pernah mendengar [Jabir bin Abdullah] berkata, \"Aku pernah mengikuti peperangan bersama Rasulullah shallallahu 'alaihi wasallam sebanyak sembilan belas kali peperangan.\" Jabir berkata, \"Namun aku tidak ikut dalam perang Badar dan perang Uhud, sebab ayahku melarangku untuk mengikutinya, ketika Abdullah terbunuh pada waktu perang Uhud, maka aku tidak pernah ketinggalan sekali pun untuk ikut perang bersama Rasulullah shallallahu 'alaihi wasallam.\""},"3151":{"ar":"و حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا زَيْدُ بْنُ الْحُبَابِ ح و حَدَّثَنَا سَعِيدُ بْنُ مُحَمَّدٍ الْجَرْمِيُّ حَدَّثَنَا أَبُو تُمَيْلَةَ قَالَا جَمِيعًا حَدَّثَنَا حُسَيْنُ بْنُ وَاقِدٍ عَنْ عَبْدِ اللَّهِ بْنِ بُرَيْدَةَ عَنْ أَبِيهِ قَالَغَزَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ تِسْعَ عَشْرَةَ غَزْوَةً قَاتَلَ فِي ثَمَانٍ مِنْهُنَّوَلَمْ يَقُلْ أَبُو بَكْرٍ مِنْهُنَّ وَقَالَ فِي حَدِيثِهِ حَدَّثَنِي عَبْدُ اللَّهِ بْنُ بُرَيْدَةَ","id":"Dan telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] telah menceritakan kepada kami [Zaid bin Al Hubab]. (dalam jalur lain disebutkan) Telah menceritakan kepada kami [Sa'id bin Muhammad Al Jarmi] telah menceritakan kepada kami [Abu Tumailah] dia berkata; telah menceritakan kepada kami [Husain bin Waqid] dari [Abdullah bin Buraidah] dari [ayahnya] dia berkata, \"Rasulullah shallallahu 'alaihi wasallam ikut serta dalam peperangan sebanyak sembilan balas kali, delapan kali di antaranya (beliau) terjun langsung dalam kancah peperangan tersebut.\" Namun Abu Bakar tidak menyebutkan, \"di antaranya.\" Dan haditsnya ia menyebutkan, \"Telah menceritakan kepadaku, Abdullah bin Buraidah.\""},"3152":{"ar":"و حَدَّثَنِي أَحْمَدُ بْنُ حَنْبَلٍ حَدَّثَنَا مُعْتَمِرُ بْنُ سُلَيْمَانَ عَنْ كَهْمَسٍ عَنْ ابْنِ بُرَيْدَةَ عَنْ أَبِيهِ أَنَّهُ قَالَغَزَا مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ سِتَّ عَشْرَةَ غَزْوَةً","id":"Dan telah menceritakan kepadaku [Ahmad bin Hanbal] telah menceritakan kepada kami [Mu'tamir bin Sulaiman] dari [Kahmas] dari [Ibnu Buraidah] dari [ayahnya], bahwa dia berkata, bahwa dia pernah ikut berperang bersama Rasulullah shallallahu 'alaihi wasallam sebanyak enam belas kali peperangan.\""},"3153":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ عَبَّادٍ حَدَّثَنَا حَاتِمٌ يَعْنِي ابْنَ إِسْمَعِيلَ عَنْ يَزِيدَ وَهُوَ ابْنُ أَبِي عُبَيْدٍ قَالَ سَمِعْتُ سَلَمَةَ يَقُولُاغَزَوْتُ مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ سَبْعَ غَزَوَاتٍ وَخَرَجْتُ فِيمَا يَبْعَثُ مِنْ الْبُعُوثِ تِسْعَ غَزَوَاتٍ مَرَّةً عَلَيْنَا أَبُو بَكْرٍ وَمَرَّةً عَلَيْنَا أُسَامَةُ بْنُ زَيْدٍو حَدَّثَنَا قُتَيْبَةُ بْنُ سَعِيدٍ حَدَّثَنَا حَاتِمٌ بِهَذَا الْإِسْنَادِ غَيْرَ أَنَّهُ قَالَ فِي كِلْتَيْهِمَا سَبْعَ غَزَوَاتٍ","id":"Telah menceritakan kepada kami [Muhammad bin 'Abbad] telah menceritakan kepada kami [Hatim] -yaitu Ibnu Isma'il- dari [Yazid] -yaitu Ibnu Abu 'Ubaid- dia berkata; aku mendengar [Salamah] berkata, \"Aku pernah berperang bersama-sama dengan Rasulullah shallallahu 'alaihi wasallam sebanyak tujuh kali, kemudian aku juga pernah ikut dalam pasukan yang dikirim oleh beliau sebanyak sembilan kali peperangan, sekali dipimpin oleh Abu Bakar dan satu kali di bawah pimpinan Usamah bin Zaid.\" Dan telah menceritakan kepada kami [Qutaibah bin Sa'id] telah menceritakan kepada kami [Hatim] dengan isnad ini, namun dia mengatakan dalam kedua hadits tersebut sebanyak tujuh kali peperangan.\""},"3154":{"ar":"حَدَّثَنَا أَبُو عَامِرٍ عَبْدُ اللَّهِ بْنُ بَرَّادٍ الْأَشْعَرِيُّ وَمُحَمَّدُ بْنُ الْعَلَاءِ الْهَمْدَانِيُّ وَاللَّفْظُ لِأَبِي عَامِرٍ قَالَا حَدَّثَنَا أَبُو أُسَامَةَ عَنْ بُرَيْدِ بْنِ أَبِي بُرْدَةَ عَنْ أَبِي بُرْدَةَ عَنْ أَبِي مُوسَى قَالَخَرَجْنَا مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي غَزَاةٍ وَنَحْنُ سِتَّةُ نَفَرٍ بَيْنَنَا بَعِيرٌ نَعْتَقِبُهُ قَالَ فَنَقِبَتْ أَقْدَامُنَا فَنَقِبَتْ قَدَمَايَ وَسَقَطَتْ أَظْفَارِي فَكُنَّا نَلُفُّ عَلَى أَرْجُلِنَا الْخِرَقَ فَسُمِّيَتْ غَزْوَةَ ذَاتِ الرِّقَاعِ لِمَا كُنَّا نُعَصِّبُ عَلَى أَرْجُلِنَا مِنْ الْخِرَقِقَالَ أَبُو بُرْدَةَ فَحَدَّثَ أَبُو مُوسَى بِهَذَا الْحَدِيثِ ثُمَّ كَرِهَ ذَلِكَ قَالَ كَأَنَّهُ كَرِهَ أَنْ يَكُونَ شَيْئًا مِنْ عَمَلِهِ أَفْشَاهُ قَالَ أَبُو أُسَامَةَ وَزَادَنِي غَيْرُ بُرَيْدٍ وَاللَّهُ يُجْزِي بِهِ","id":"Telah menceritakan kepada kami [Abu 'Amir Abdullah bin Barrad Al Asy'ari] dan [Muhammad bin Al 'Ala Al Hamdani] sedangkan lafadznya dari 'Amir, keduanya berkata; telah menceritakan kepada kami [Abu Usamah] dari [Buraid bin Abu Burdah] dari [Abu Burdah] dari [Abu Musa] dia berkata, \"Kami pernah keluar bersama Rasulullah shallallahu 'alaihi wasallam untuk menghadapi beberapa orang yang hendak menyerbu, saat itu kami berjumlah sekitar enam orang, dengan mengendarai seekor unta yang kami naiki secara bergantian.\" Abu Musa berkata, \"Lalu kaki kamipun terluka, demikian juga dengan kakiku, bahkan kuku kakiku ada yang terlepas satu-persatu. Kami bersama-sama membalut kaki-kaki kami dengan secarik kain. Karena kami membalut kaki kami yang terluka dengan secarik kain, maka peperangan tersebut dinamai dengan perang Dzatu Ar Riqa'.\" Abu Burdah mengatakan, \"Abu Musa pernah menceritakan hadits ini kepadaku, tetapi kemudian dia membencinya. Sepertinya dia membenci kalau amal perbuatannya disebarluaskan.\" Abu Usamah mengatakan, \"Dan selain Buraid ada juga seseorang yang menambahkan kepadaku, yaitu, 'Semoga Allah memberikan pahala'.\""},"3155":{"ar":"حَدَّثَنِي زُهَيْرُ بْنُ حَرْبٍ حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ مَهْدِيٍّ عَنْ مَالِكٍ ح و حَدَّثَنِيهِ أَبُو الطَّاهِرِ وَاللَّفْظُ لَهُ حَدَّثَنِي عَبْدُ اللَّهِ بْنُ وَهْبٍ عَنْ مَالِكِ بْنِ أَنَسٍ عَنْ الْفُضَيْلِ بْنِ أَبِي عَبْدِ اللَّهِ عَنْ عَبْدِ اللَّهِ بْنِ نِيَارٍ الْأَسْلَمِيِّ عَنْ عُرْوَةَ بْنِ الزُّبَيْرِ عَنْ عَائِشَةَ زَوْجِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهَا قَالَتْخَرَجَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قِبَلَ بَدْرٍ فَلَمَّا كَانَ بِحَرَّةِ الْوَبَرَةِ أَدْرَكَهُ رَجُلٌ قَدْ كَانَ يُذْكَرُ مِنْهُ جُرْأَةٌ وَنَجْدَةٌ فَفَرِحَ أَصْحَابُ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حِينَ رَأَوْهُ فَلَمَّا أَدْرَكَهُ قَالَ لِرَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ جِئْتُ لِأَتَّبِعَكَ وَأُصِيبَ مَعَكَ قَالَ لَهُ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ تُؤْمِنُ بِاللَّهِ وَرَسُولِهِ قَالَ لَا قَالَ فَارْجِعْ فَلَنْ أَسْتَعِينَ بِمُشْرِكٍ قَالَتْ ثُمَّ مَضَى حَتَّى إِذَا كُنَّا بِالشَّجَرَةِ أَدْرَكَهُ الرَّجُلُ فَقَالَ لَهُ كَمَا قَالَ أَوَّلَ مَرَّةٍ فَقَالَ لَهُ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَمَا قَالَ أَوَّلَ مَرَّةٍ قَالَ فَارْجِعْ فَلَنْ أَسْتَعِينَ بِمُشْرِكٍ قَالَ ثُمَّ رَجَعَ فَأَدْرَكَهُ بِالْبَيْدَاءِ فَقَالَ لَهُ كَمَا قَالَ أَوَّلَ مَرَّةٍ تُؤْمِنُ بِاللَّهِ وَرَسُولِهِ قَالَ نَعَمْ فَقَالَ لَهُ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَانْطَلِقْ","id":"Telah menceritakan kepadaku [Zuhair bin Harb] telah menceritakan kepada kami [Abdurrahman bin Mahdi] dari [Malik]. (dalam jalur lain disebutkan) Telah menceritakan kepadaku [Abu At Thahir] sedangkan lafadznya dari dia, telah menceritakan kepadaku [Abdullah bin Wahb] dari [Malik bin Anas] dari [Al Fudlail bin Abu Abdullah] dari [Abdullah bin Niyar Al Aslami] dari ['Urwah bin Az Zubair] dari ['Aisyah] isteri Nabi shallallahu 'alaihi wasallam, bahwa dia berkata, \"Rasulullah shallallahu 'alaihi wasallam pergi ke Badar, tatkala beliau sampai di Harratul Wabarah, beliau ditemui oleh seorang laki-laki yang terkenal gagah berani. Maka para sahabat Rasulullah shallallahu 'alaihi wasallam merasa gembira ketika melihat kedatangannya. Laki-laki tersebut berkata kepada Rasulullah shallallahu 'alaihi wasallam, \"Aku sengaja mengikuti anda karena hendak ikut berperang dipihak anda dan bersama-sama dengan anda.\" Rasulullah shallallahu 'alaihi wasallam bertanya kepadanya: \"Apakah kamu sudah beriman kepada Allah dan Rasul-Nya?\" dia menjawab, \"Tidak.\" Beliau bersabda: \"Jika demikian, kembalilah kamu pulang, sebab kami tidak membutuhkan pertolongan orang-orang Musyrik.\" 'Aisyah berkata, \"Maka pergilah orang itu, namun ketika kami dekat dengan sebatang pohon, orang itu datang kembali menemui Rasulullah shallallahu 'alaihi wasallam dan berkata seperti semula, sementara Nabi shallallahu 'alaihi wasallam juga bertanya seperti semula. Selanjutnya beliau bersabda: \"Jika demikian, kembalilah kamu pulang, sebab kami tidak membutuhkan pertolongan orang-orang Musyrik.\" Dia berkata, \"Maka pergilah dia, kemudian ketika kami sampai di baida`, dia datang kembali, Rasulullah shallallahu 'alaihi wasallam bertanya pula kepadanya seperti semula: \"Apakah anda sudah beriman kepada Allah dan Rasul-Nya?\" jawab orang itu, \"Ya aku beriman.\" Maka Rasulullah shallallahu 'alaihi wasallam bersabda kepadanya: \"Mari, teruslah jalan.\""},"3156":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ مَسْلَمَةَ بْنِ قَعْنَبٍ وَقُتَيْبَةُ بْنُ سَعِيدٍ قَالَا حَدَّثَنَا الْمُغِيرَةُ يَعْنِيَانِ الْحِزَامِيَّ ح و حَدَّثَنَا زُهَيْرُ بْنُ حَرْبٍ وَعَمْرٌو النَّاقِدُ قَالَا حَدَّثَنَا سُفْيَانُ بْنُ عُيَيْنَةَ كِلَاهُمَا عَنْ أَبِي الزِّنَادِ عَنْ الْأَعْرَجِ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَفِي حَدِيثِ زُهَيْرٍ يَبْلُغُ بِهِ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ و قَالَ عَمْرٌو رِوَايَةً النَّاسُ تَبَعٌ لِقُرَيْشٍ فِي هَذَا الشَّأْنِ مُسْلِمُهُمْ لِمُسْلِمِهِمْ وَكَافِرُهُمْ لِكَافِرِهِمْ","id":"Telah menceritakan kepada kami [Abdullah bin Maslamah Al Qa'nab] dan [Qutaibah bin Sa'id] keduanya berkata; telah menceritakan kepada kami? [Al Mughirah] -yaitu Al Hizami-. (dalam jalur lain disebutkan) Telah menceritakan kepada kami [Zuhair bin Harb] dan ['Amru An Naqid] keduanya berkata; telah menceritakan kepada kami [Sufyan bin 'Uyainah] keduanya dari [Abu Az Zinnad] dari [Al A'raj] dari [Abu Hurairah] dia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda, dan dalam hadits Zuhair dan sampai kepada Nabi shallallahu 'alaihi wasallam. Dan 'Amru juag menyebutkan secara riwayat, \"Manusia itu mengikuti Quraisy dalam permasalahan ini (kepemimpinan), Muslim mereka mengikuti Muslim (Quraisy), dan kafir mereka mengikuti kafir mereka (Quraisy).\""},"3157":{"ar":"و حَدَّثَنَا مُحَمَّدُ بْنُ رَافِعٍ حَدَّثَنَا عَبْدُ الرَّزَّاقِ حَدَّثَنَا مَعْمَرٌ عَنْ هَمَّامِ بْنِ مُنَبِّهٍ قَالَ هَذَا مَا حَدَّثَنَا أَبُو هُرَيْرَةَ عَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَذَكَرَ أَحَادِيثَ مِنْهَاوَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ النَّاسُ تَبَعٌ لِقُرَيْشٍ فِي هَذَا الشَّأْنِ مُسْلِمُهُمْ تَبَعٌ لِمُسْلِمِهِمْ وَكَافِرُهُمْ تَبَعٌ لِكَافِرِهِمْ","id":"Dan telah menceritakan kepada kami [Muhammad bin Rafi'] telah menceritakan kepada kami [Abdurrazaq] telah menceritakan kepada kami [Ma'mar] dari [Hammam bin Munabbih] dia berkata; ini seperti yang pernah diceritakan oleh [Abu Hurairah] kepada kami dari Rasulullah shallallahu 'alaihi wasallam, kemudian dia menyebutkan beberap hadits yang di antaranya adalah, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Manusia itu mengikuti Quraisy dalam permasalahan ini (kepemimpinan), Muslim mereka mengikuti Muslim (Quraisy), dan kafir mereka mengikuti kafir mereka (Quraisy).\""},"3158":{"ar":"و حَدَّثَنِي يَحْيَى بْنُ حَبِيبٍ الْحَارِثِيُّ حَدَّثَنَا رَوْحٌ حَدَّثَنَا ابْنُ جُرَيْجٍ حَدَّثَنِي أَبُو الزُّبَيْرِ أَنَّهُ سَمِعَ جَابِرَ بْنَ عَبْدِ اللَّهِ يَقُولُاقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ النَّاسُ تَبَعٌ لِقُرَيْشٍ فِي الْخَيْرِ وَالشَّرِّ","id":"Dan telah menceritakan kepadaku [Yahya bin Habib Al Haritsi] telah menceritakan kepada kami [Rauh] telah menceritakan kepada kami [Ibnu Juraij] telah menceritakan kepadaku [Abu Az Zubair] bahwa dia mendengar [Jabir bin Abdullah] berkata, \"Nabi shallallahu 'alaihi wasallam bersabda: \"Manusia itu mengikuti Quraisy dalam kebaikan dan keburukan.\""},"3159":{"ar":"و حَدَّثَنَا أَحْمَدُ بْنُ عَبْدِ اللَّهِ بْنِ يُونُسَ حَدَّثَنَا عَاصِمُ بْنُ مُحَمَّدِ بْنِ زَيْدٍ عَنْ أَبِيهِ قَالَ قَالَ عَبْدُ اللَّهِقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا يَزَالُ هَذَا الْأَمْرُ فِي قُرَيْشٍ مَا بَقِيَ مِنْ النَّاسِ اثْنَانِ","id":"Dan telah menceritakan kepada kami [Ahmad bin Abdullah bin Yunus] telah menceritakan kepada kami ['Ashim bin Muhammad bin Zaid] dari [ayahnya] dia berkata, \" [Abdullah] berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Perkara ini (kepemimpinan) akan senantiasa dipegang oleh orang-orang Quraisy sekalipun manusia hanya tinggal dua.\""},"3160":{"ar":"حَدَّثَنَا قُتَيْبَةُ بْنُ سَعِيدٍ حَدَّثَنَا جَرِيرٌ عَنْ حُصَيْنٍ عَنْ جَابِرِ بْنِ سَمُرَةَ قَالَ سَمِعْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ ح و حَدَّثَنَا رِفَاعَةُ بْنُ الْهَيْثَمِ الْوَاسِطِيُّ وَاللَّفْظُ لَهُ حَدَّثَنَا خَالِدٌ يَعْنِي ابْنَ عَبْدِ اللَّهِ الطَّحَّانَ عَنْ حُصَيْنٍ عَنْ جَابِرِ بْنِ سَمُرَةَ قَالَدَخَلْتُ مَعَ أَبِي عَلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَسَمِعْتُهُ يَقُولُ إِنَّ هَذَا الْأَمْرَ لَا يَنْقَضِي حَتَّى يَمْضِيَ فِيهِمْ اثْنَا عَشَرَ خَلِيفَةً قَالَ ثُمَّ تَكَلَّمَ بِكَلَامٍ خَفِيَ عَلَيَّ قَالَ فَقُلْتُ لِأَبِي مَا قَالَ قَالَ كُلُّهُمْ مِنْ قُرَيْشٍ","id":"Telah menceritakan kepada kami [Qutaibah bin Sa'id] telah menceritakan kepada kami [Jarir] dari [Hushain] dari [Jabir bin Samurah] dia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda. (dalam jalur lain disebutkan) Telah menceritakan kepada kami [Rifa'ah bin Al haitsam Al Wasithi] sedangkan lafadznya dari dia, telah menceritakan kepada kami [Khalid] -yaitu Ibnu Abdullah At Thahan- dari [Hushain] dari [Jabir bin Samurah] dia berkata, \"Aku pernah menemui Nabi shallallahu 'alaihi wasallam bersama dengan ayahku, maka aku mendengar beliau bersabda: \"Sesungguhnya pemerintahan ini tidak akan runtuh hingga kedua belas orang khalifah memerintah.\" Kemudian beliau mengucapkan kata-kata yang kurang jelas bagiku, Jabir berkata, \"Lalu aku bertanya kepada ayahku, 'Apa yang dikatakan beliau?\" [ayahku] menjawab, \"(beliau mengatakan) Semuanya dari bangsa Quraisy.\""},"3161":{"ar":"حَدَّثَنَا ابْنُ أَبِي عُمَرَ حَدَّثَنَا سُفْيَانُ عَنْ عَبْدِ الْمَلِكِ بْنِ عُمَيْرٍ عَنْ جَابِرِ بْنِ سَمُرَةَ قَالَسَمِعْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ لَا يَزَالُ أَمْرُ النَّاسِ مَاضِيًا مَا وَلِيَهُمْ اثْنَا عَشَرَ رَجُلًا ثُمَّ تَكَلَّمَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِكَلِمَةٍ خَفِيَتْ عَلَيَّ فَسَأَلْتُ أَبِي مَاذَا قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ كُلُّهُمْ مِنْ قُرَيْشٍو حَدَّثَنَا قُتَيْبَةُ بْنُ سَعِيدٍ حَدَّثَنَا أَبُو عَوَانَةَ عَنْ سِمَاكٍ عَنْ جَابِرِ بْنِ سَمُرَةَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِهَذَا الْحَدِيثِ وَلَمْ يَذْكُرْ لَا يَزَالُ أَمْرُ النَّاسِ مَاضِيًا","id":"Telah menceritakan kepada kami [Ibnu Abu Umar] telah menceritakan kepada kami [Sufyan] dari [Abdul Malik bin 'Umair] dari [Jabir bin Samurah] dia berkata, \"Aku mendengar Nabi shallallahu 'alaihi wasallam bersabda: \"Perkara manusia akan tetap berlalu (jaya) selagi mereka masih tetap diperintahkan oleh dua belas orang laki-laki.\" Kemudian Nabi shallallahu 'alaihi wasallam mengucapkan kata-kata yang tidak jelas bagiku, maka aku aku bertanya kepada [ayahku], \"Apa yang dikatakan oleh Rasulullah shallallahu 'alaihi wasallam?\" dia menjawab, \"Mereka semua dari Quraisy.\" Dan telah menceritakan kepada kami [Qutaibah bin Sa'id] telah menceritakan kepada kami [Abu 'Awanah] dari [Simak] dari [Jabir bin Samurah] dari Nabi shallallahu 'alaihi wasallam dengan hadits ini, namun dia tidak menyebutkan, \"Dan perkara manusia akan senantiasa berlalu.\""},"3162":{"ar":"حَدَّثَنَا هَدَّابُ بْنُ خَالِدٍ الْأَزْدِيُّ حَدَّثَنَا حَمَّادُ بْنُ سَلَمَةَ عَنْ سِمَاكِ بْنِ حَرْبٍ قَالَ سَمِعْتُ جَابِرَ بْنَ سَمُرَةَ يَقُولُاسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ لَا يَزَالُ الْإِسْلَامُ عَزِيزًا إِلَى اثْنَيْ عَشَرَ خَلِيفَةً ثُمَّ قَالَ كَلِمَةً لَمْ أَفْهَمْهَا فَقُلْتُ لِأَبِي مَا قَالَ فَقَالَ كُلُّهُمْ مِنْ قُرَيْشٍ","id":"Telah menceritakan kepada kami [Haddab bin Khalid Al Azdi] telah menceritakan kepada kami [Hammad bin Salamah] dari [Simak bin Harb] dia berkata; aku mendengar [Jabir bin Samurah] berkata, \"Aku mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Islam senantiasa kuat dan berkuasa sampai kedua belas khalifah.\" Kemudian beliau mengucapkan kata-kata yang tidak aku fahami, lantas aku bertanya kepada [ayahku], \"Apa yang dikatakan beliau?\" dia menjawab, \"Mereka semua dari bangsa Quraisy.\""},"3163":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا أَبُو مُعَاوِيَةَ عَنْ دَاوُدَ عَنْ الشَّعْبِيِّ عَنْ جَابِرِ بْنِ سَمُرَةَ قَالَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا يَزَالُ هَذَا الْأَمْرُ عَزِيزًا إِلَى اثْنَيْ عَشَرَ خَلِيفَةً قَالَ ثُمَّ تَكَلَّمَ بِشَيْءٍ لَمْ أَفْهَمْهُ فَقُلْتُ لِأَبِي مَا قَالَ فَقَالَ كُلُّهُمْ مِنْ قُرَيْشٍ","id":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] telah menceritakan kepada kami [Abu Mu'awiyah] dari [Daud] dari [As Sya'bi] dari [Jabir bin Samurah] dia berkata, \"Nabi shallallahu 'alaihi wasallam bersabda: \"Perkara (kepemimpinan) ini akan senantiasa kuat sampai kedua belas khilafah (pemimpin).\" Jabir berkata, \"Kemudian beliau mengucapkan kata-kata yang tidak aku fahami, maka aku bertanya kepada [ayahku], \"Apa yang dikatakan beliau?\" dia menjawab, \"Mereka semua dari bangsa Quraisy.\""},"3164":{"ar":"حَدَّثَنَا نَصْرُ بْنُ عَلِيٍّ الْجَهْضَمِيُّ حَدَّثَنَا يَزِيدُ بْنُ زُرَيْعٍ حَدَّثَنَا ابْنُ عَوْنٍ ح و حَدَّثَنَا أَحْمَدُ بْنُ عُثْمَانَ النَّوْفَلِيُّ وَاللَّفْظُ لَهُ حَدَّثَنَا أَزْهَرُ حَدَّثَنَا ابْنُ عَوْنٍ عَنْ الشَّعْبِيِّ عَنْ جَابِرِ بْنِ سَمُرَةَ قَالَانْطَلَقْتُ إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَمَعِي أَبِي فَسَمِعْتُهُ يَقُولُ لَا يَزَالُ هَذَا الدِّينُ عَزِيزًا مَنِيعًا إِلَى اثْنَيْ عَشَرَ خَلِيفَةً فَقَالَ كَلِمَةً صَمَّنِيهَا النَّاسُ فَقُلْتُ لِأَبِي مَا قَالَ قَالَ كُلُّهُمْ مِنْ قُرَيْشٍ","id":"Telah menceritakan kepada kami [Nahsr bin Ali Al Jahdlami] telah menceritakan kepada kami [Yazid bin Zurai'] telah menceritakan kepada kami [Ibnu 'Aun]. (dalam jalur lain disebutkan) Telah menceritakan kepada kami [Ahmad bin Utsman An Naufali] sedangkan lafadznya dari dia, telah menceritakan kepada kami [Azhar] telah menceritakan kepada kami [Ibnu 'Aun] dari [Asy Sya'bi] dari [Jabir bin Samurah] dia berkata, \"Aku pernah datang kepada Rasulullah shallallahu 'alaihi wasallam bersama dengan [ayahku], lalu aku mendengar beliau bersabda: \"Agama ini akan senantiasa kuat dan kokoh hingga kedua belas khalifah (pemipin).\" Kemudian beliau mengucapkan kata-kata yang lirih hingga tidak terdengar oleh orang-orang, maka aku bertanya kepada ayahku, \"Apa yang dikatakan beliau?\" dia menjawab, \"Mereka semua dari suku Quraisy.\""},"3165":{"ar":"حَدَّثَنَا قُتَيْبَةُ بْنُ سَعِيدٍ وَأَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ قَالَا حَدَّثَنَا حَاتِمٌ وَهُوَ ابْنُ إِسْمَعِيلَ عَنْ الْمُهَاجِرِ بْنِ مِسْمَارٍ عَنْ عَامِرِ بْنِ سَعْدِ بْنِ أَبِي وَقَّاصٍ قَالَكَتَبْتُ إِلَى جَابِرِ بْنِ سَمُرَةَ مَعَ غُلَامِي نَافِعٍ أَنْ أَخْبِرْنِي بِشَيْءٍ سَمِعْتَهُ مِنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ فَكَتَبَ إِلَيَّ سَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَوْمَ جُمُعَةٍ عَشِيَّةَ رُجِمَ الْأَسْلَمِيُّ يَقُولُ لَا يَزَالُ الدِّينُ قَائِمًا حَتَّى تَقُومَ السَّاعَةُ أَوْ يَكُونَ عَلَيْكُمْ اثْنَا عَشَرَ خَلِيفَةً كُلُّهُمْ مِنْ قُرَيْشٍ وَسَمِعْتُهُ يَقُولُ عُصَيْبَةٌ مِنْ الْمُسْلِمِينَ يَفْتَتِحُونَ الْبَيْتَ الْأَبْيَضَ بَيْتَ كِسْرَى أَوْ آلِ كِسْرَى وَسَمِعْتُهُ يَقُولُ إِنَّ بَيْنَ يَدَيْ السَّاعَةِ كَذَّابِينَ فَاحْذَرُوهُمْ وَسَمِعْتُهُ يَقُولُ إِذَا أَعْطَى اللَّهُ أَحَدَكُمْ خَيْرًا فَلْيَبْدَأْ بِنَفْسِهِ وَأَهْلِ بَيْتِهِ وَسَمِعْتُهُ يَقُولُ أَنَا الْفَرَطُ عَلَى الْحَوْضِحَدَّثَنَا مُحَمَّدُ بْنُ رَافِعٍ حَدَّثَنَا ابْنُ أَبِي فُدَيْكٍ حَدَّثَنَا ابْنُ أَبِي ذِئْبٍ عَنْ مُهَاجِرِ بْنِ مِسْمَارٍ عَنْ عَامِرِ بْنِ سَعْدٍ أَنَّهُ أَرْسَلَ إِلَى ابْنِ سَمُرَةَ الْعَدَوِيِّ حَدِّثْنَا مَا سَمِعْتَ مِنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ سَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ فَذَكَرَ نَحْوَ حَدِيثِ حَاتِمٍ","id":"Telah menceritakan kepada kami [Qutaibah bin Sa'id] dan [Abu Bakar bin Abu Syaibah] keduanya berkata; telah menceritakan kepada kami [Hatim] -yaitu Ibnu Isma'il- dari [Al Muhajir bin Mismar] dari ['Amir bin Sa'd bin Abu Waqahs] dia berkata, \"Aku mengirim surat kepada [Jabir bin Samurah] melalui pelayanku, Nafi', supaya dia mengabarkan kepadaku hadits yang pernah didengarnya dari Rasulullah shallallahu 'alaihi wasallam.\" 'Amir berkata, \"Kemudian dia membalas suratku: \"Aku mendengar Rasulullah shallallahu 'alaihi wasallam bersabda pada hari Jum'at petang, yaitu ketika seorang suku Aslam sedang dirajam, beliau bersabda: \"Agama ini (Islam) akan senantiasa tegak hingga hari Kiamat atau sampai habis dua belas khalifah memerintah kalian, semuanya dari suku Quraisy.\" Dan saya juga mnendengar beliau bersabda: \"Sekelompok kaum Muslimin akan menaklukkan istana putih Kisra (Persia).\" Dan aku juga mendengar beliau bersabda: \"Sebelum terjadi hari Kiamat, akan muncul para pembohong (Dajjal), maka waspadalah terhadap mereka.\" Aku mendengar pula beliau bersabda: \"Jika Allah mengaruniaimu suatu kebaikan (kekayaan), pertama-tama manfaatkanlah untuk dirimu sendiri dan keluargamu.\" Aku mendengar pula beliau bersabda: \"Aku lebih dahulu dan menunggu di telaga.\" Telah menceritakan kepada kami [Muhammad bin Rafi'] telah menceritakan kepada kami [Ibnu Abu Fudaik] telah menceritakan kepada kami [Ibnu Abu Dzi`b] dari [Muhajir bin Mismar] dari ['Amir bin Sa'd] bahwa dia pernah mengirim surat kepada [Ibnu Samurah Al 'Adawi]: \"Ceritakanlah kepada kami apa yang pernah kamu dengar dari Rasulullah shallallahu 'alaihi wasallam!.\" Maka dia menjawab: \"Aku mendengar Rasulullah shallallahu 'alaihi wasallam bersabda…seperti hadit Hatim.\""},"3166":{"ar":"حَدَّثَنَا أَبُو كُرَيْبٍ مُحَمَّدُ بْنُ الْعَلَاءِ حَدَّثَنَا أَبُو أُسَامَةَ عَنْ هِشَامِ بْنِ عُرْوَةَ عَنْ أَبِيهِ عَنْ ابْنِ عُمَرَ قَالَ حَضَرْتُ أَبِي حِينَ أُصِيبَ فَأَثْنَوْا عَلَيْهِ وَقَالُوا جَزَاكَ اللَّهُ خَيْرًا فَقَالَ رَاغِبٌ وَرَاهِبٌ قَالُوا اسْتَخْلِفْ فَقَالَ أَتَحَمَّلُ أَمْرَكُمْ حَيًّا وَمَيِّتًا لَوَدِدْتُ أَنَّ حَظِّي مِنْهَا الْكَفَافُ لَا عَلَيَّ وَلَا لِي فَإِنْ أَسْتَخْلِفْ فَقَدْ اسْتَخْلَفَ مَنْ هُوَ خَيْرٌ مِنِّي يَعْنِي أَبَا بَكْرٍوَإِنْ أَتْرُكْكُمْ فَقَدْ تَرَكَكُمْ مَنْ هُوَ خَيْرٌ مِنِّي رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ عَبْدُ اللَّهِ فَعَرَفْتُ أَنَّهُ حِينَ ذَكَرَ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ غَيْرُ مُسْتَخْلِفٍ","id":"Telah menceritakan kepada kami [Abu Kuraib Muhammad bin Al 'Ala] telah menceritakan kepada kami [Abu Usamah] dari [Hisyam bin 'Urwah] dari [ayahnya] dari [Ibnu Umar] dia berkata, \"Aku ikut hadir ketika ayahku kena musibah (ditikam oleh seseorang). Para sahabat beliau yang hadir ketika itu turut menghiburnya, kata mereka, \"Semoga Allah membalas anda dengan kebaikan.\" Umar menjawab, \"Aku penuh harap dan juga merasa cemas.\" Mereka berkata, \"Tunjukkanlah pengganti anda (sebagai Khalifah)!\" Umar menjawab, \"Apakah aku juga harus memikul urusan pemerintahanmu waktu hidup dan metiku? Aku ingin tugasku sudah selesai, tidak kurang dan tidak lebih. Jika aku menunjuk penggantiku, maka itu pernah dilakukan oleh orang yang lebih baik daripadaku, yaitu Abu Bakar As Shidiq. Dan jika pengankatan itu aku serahkan kepada kalian, maka itu pun pernah dilakukan oleh orang yang lebih baik dari aku, yaitu Rasulullah shallallahu 'alaihi wasallam.\" Abdullah berkata, \"Dari penuturannya itu, tahulah aku bahwa dia tidak akan menunjuk penggantinya untuk menjadi Khalifah.\""},"3167":{"ar":"حَدَّثَنَا إِسْحَقُ بْنُ إِبْرَاهِيمَ وَابْنُ أَبِي عُمَرَ وَمُحَمَّدُ بْنُ رَافِعٍ وَعَبْدُ بْنُ حُمَيْدٍ وَأَلْفَاظُهُمْ مُتَقَارِبَةٌ قَالَ إِسْحَقُ وَعَبْدٌ أَخْبَرَنَا و قَالَ الْآخَرَانِ حَدَّثَنَا عَبْدُ الرَّزَّاقِ أَخْبَرَنَا مَعْمَرٌ عَنْ الزُّهْرِيِّ أَخْبَرَنِي سَالِمٌ عَنْ ابْنِ عُمَرَ قَالَ دَخَلْتُ عَلَى حَفْصَةَ فَقَالَتْ أَعَلِمْتَ أَنَّ أَبَاكَ غَيْرُ مُسْتَخْلِفٍ قَالَ قُلْتُ مَا كَانَ لِيَفْعَلَ قَالَتْ إِنَّهُ فَاعِلٌ قَالَ فَحَلَفْتُ أَنِّي أُكَلِّمُهُ فِي ذَلِكَ فَسَكَتُّ حَتَّى غَدَوْتُ وَلَمْ أُكَلِّمْهُ قَالَ فَكُنْتُ كَأَنَّمَا أَحْمِلُ بِيَمِينِي جَبَلًا حَتَّى رَجَعْتُ فَدَخَلْتُ عَلَيْهِ فَسَأَلَنِي عَنْ حَالِ النَّاسِ وَأَنَا أُخْبِرُهُ قَالَ ثُمَّ قُلْتُ لَهُ إِنِّي سَمِعْتُ النَّاسَ يَقُولُونَ مَقَالَةً فَآلَيْتُ أَنْ أَقُولَهَا لَكَ زَعَمُوا أَنَّكَ غَيْرُ مُسْتَخْلِفٍ وَإِنَّهُ لَوْ كَانَ لَكَ رَاعِي إِبِلٍ أَوْ رَاعِي غَنَمٍ ثُمَّ جَاءَكَ وَتَرَكَهَا رَأَيْتَ أَنْ قَدْ ضَيَّعَ فَرِعَايَةُ النَّاسِ أَشَدُّ قَالَ فَوَافَقَهُ قَوْلِي فَوَضَعَ رَأْسَهُ سَاعَةً ثُمَّ رَفَعَهُ إِلَيَّ فَقَالَ إِنَّ اللَّهَ عَزَّ وَجَلَّ يَحْفَظُ دِينَهُوَإِنِّي لَئِنْ لَا أَسْتَخْلِفْ فَإِنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَمْ يَسْتَخْلِفْ وَإِنْ أَسْتَخْلِفْ فَإِنَّ أَبَا بَكْرٍ قَدْ اسْتَخْلَفَ قَالَ فَوَاللَّهِ مَا هُوَ إِلَّا أَنْ ذَكَرَ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَأَبَا بَكْرٍ فَعَلِمْتُ أَنَّهُ لَمْ يَكُنْ لِيَعْدِلَ بِرَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَحَدًا وَأَنَّهُ غَيْرُ مُسْتَخْلِفٍ","id":"Telah menceritakan kepada kami [Ishaq bin Ibrahim] dan [Ibnu Abu Umar] dan [Muhammad bin Rafi'] dan [Abd bin Humaid] sedangkan lafadz mereka saling berdekatan, Ishaq dan Abd berkata; telah mengabarkan kepada kami, sedangkan yang dua mengatakan; telah menceritakan kepada kami [Abdurrazaq] telah menceritakan kepada kami [Ma'mar] dari [Az Zuhri] telah mengabarkan kepadaku [Salim] dari [Ibnu Umar] dia berkata, \"Aku pernah menemui Hafshah, lalu dia bertanya, \"Apakah kamu tahu bahwa ayahmu tidak mau menunjuk seorang Khalifah?\" Abdullah berkata, \"Lalu aku berkata, 'Sepertinya dia tidak mau melakukan hal itu.' Hafshah berkata, \"Ia (Umar bin Khattab) harus melakukan hal itu.\" Lalu aku bersumpah untuk meyakinkan (Umar) akan hal itu, namun dia hanya terdiam sehingga aku merasa tidak ingin untuk membicarakannya lagi. Akan tetapi, aku merasa seakan-akan aku sedang memikul gunung di pundak kanan aku, hingga akhirnya aku menemuinya lagi. Umar bertanya kepadaku tentang keadaan manusia, maka aku pun menjawab seadanya. Lalu aku berkata kepadanya, \"Aku mendengar masyarakat sedang membicarakan tentang sesuatu dan aku bersumpah untuk menyampaikan berita ini kepadamu, menurut pandangan mereka selama ini, kamu adalah seorang Khalifah yang tidak ingin menunjuk seorang Khalifah atau pengganti. Bagaimana pendapatmu sekiranya kamu seorang penggembala unta atau kambing, kemudian dia datang kepadamu dengan meninggalkan hewan gembalannya, maka bukankah kamu melihat bahwa ia telah menyia-nyiakannya? Terlebih lagi, gembala yang akan kamu atur itu adalah manusia.\" Abdullah berkata, \"Ternyata Umar menyutujui pendapatku. Sejenak dia menundukkan kepalanya dan mengangkatnya kembali mengarah kepadaku serata berkata, \"Sesungguhnya Allah Azza Wa Jalla akan menjaga agama-Nya, sekiranya saat ini aku tidak menunjuk seorang Khalifa, maka bukankah Rasulullah shallallahu 'alaihi wasallam sendiri sudah pernah melakukannya? Dan sekiranya nanti aku menunjuk seorang Khalifah penggantiku, maka bukankah hak itu juga pernah dilakukan oleh Abu Bakar?\" Abdullah berkata, \"Demi Allah, ketika dia menyinggung nama Rasulullah shallallahu 'alaihi wasallam dan Abu Bakar, maka sadarlah aku bahwa dia memang tidak bermaksud seperti Rasulullah shallallahu 'alaihi wasallam, bahwa dia tidak menunjuk secara langsung orang yang akan menggantikannya menjadi Khalifah.\""},"3168":{"ar":"حَدَّثَنَا شَيْبَانُ بْنُ فَرُّوخَ حَدَّثَنَا جَرِيرُ بْنُ حَازِمٍ حَدَّثَنَا الْحَسَنُ حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ سَمُرَةَ قَالَقَالَ لِي رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَا عَبْدَ الرَّحْمَنِ لَا تَسْأَلْ الْإِمَارَةَ فَإِنَّكَ إِنْ أُعْطِيتَهَا عَنْ مَسْأَلَةٍ أُكِلْتَ إِلَيْهَا وَإِنْ أُعْطِيتَهَا عَنْ غَيْرِ مَسْأَلَةٍ أُعِنْتَ عَلَيْهَاو حَدَّثَنَا يَحْيَى بْنُ يَحْيَى حَدَّثَنَا خَالِدُ بْنُ عَبْدِ اللَّهِ عَنْ يُونُسَ ح و حَدَّثَنِي عَلِيُّ بْنُ حُجْرٍ السَّعْدِيُّ حَدَّثَنَا هُشَيْمٌ عَنْ يُونُسَ وَمَنْصُورٍ وَحُمَيْدٍ ح و حَدَّثَنَا أَبُو كَامِلٍ الْجَحْدَرِيُّ حَدَّثَنَا حَمَّادُ بْنُ زَيْدٍ عَنْ سِمَاكِ بْنِ عَطِيَّةَ وَيُونُسَ بْنِ عُبَيْدٍ وَهِشَامِ بْنِ حَسَّانَ كُلُّهُمْ عَنْ الْحَسَنِ عَنْ عَبْدِ الرَّحْمَنِ بْنِ سَمُرَةَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِمِثْلِ حَدِيثِ جَرِيرٍ","id":"Telah menceritakan kepada kami [Syaiban bin Faruh] telah menceritakan kepada kami [Jarir bin Hazim] telah menceritakan kepada kami [Al Hasan] telah menceritakan kepada kami [Abdurrahman bin Samurah] dia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda kepadaku: \"Wahai Abdurrahman, janganlah kamu meminta jabatan, sebab jika kamu diberi jabatan karena permintaan maka tanggung jawabnya akan dibebannya kepadamu. Namun jika kamu diangkat tanpa permintaan, maka kamu akan diberi pertolongan.\" Dan telah menceritakan kepada kami [Yahya bin Yahya] telah menceritakan kepada kami [Khalid bin 'Abdullah] dari [Yunus]. (dalam jalur lain disebutkan) Telah menceritakan kepadaku ['Ali bin Khujr As Sa'di] telah menceritakan kepada kami [Husyaim] dari [Yunus] dan [Manshur] dan [Khumaid]. (dalam jalur lain disebutkan) Telah menceritakan kepada kami [Abu Kamil Al Jahdari] telah menceritakan kepada kami [Hammad bin Zaid] dari [Simak bin 'Athiah] dan [Yunus bin 'Ubaid] dan [Hisyam bin Hassan] mereka semua dari [Al Hasan] dari [Abdurrahman bin Sumarah] dari Nabi shallallahu 'alaihi wasallam seperti hadits Jarir.\""},"3169":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ وَمُحَمَّدُ بْنُ الْعَلَاءِ قَالَا حَدَّثَنَا أَبُو أُسَامَةَ عَنْ بُرَيْدِ بْنِ عَبْدِ اللَّهِ عَنْ أَبِي بُرْدَةَ عَنْ أَبِي مُوسَى قَالَدَخَلْتُ عَلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَا وَرَجُلَانِ مِنْ بَنِي عَمِّي فَقَالَ أَحَدُ الرَّجُلَيْنِ يَا رَسُولَ اللَّهِ أَمِّرْنَا عَلَى بَعْضِ مَا وَلَّاكَ اللَّهُ عَزَّ وَجَلَّ وَقَالَ الْآخَرُ مِثْلَ ذَلِكَ فَقَالَ إِنَّا وَاللَّهِ لَا نُوَلِّي عَلَى هَذَا الْعَمَلِ أَحَدًا سَأَلَهُ وَلَا أَحَدًا حَرَصَ عَلَيْهِ","id":"Telah menceritakan kepada kami [Abu Bakar bin Abi Syaibah] dan [Muhammad bin Ala'] dia berkata, telah menceritakan kepada kami [Abu Usamah] dari [Buraid bin Abdullah] dari [Abu Burdah] dari [Abu Musa] dia berkata, \"Saya dan dua orang anak pamanku menemui Nabi shallallahu 'alaihi wasallam, salah seorang dari keduanya lalu berkata, \"Wahai Rasulullah, angkatlah kami sebagai pemimpin atas sebagian wilayah yang telah diberikan Allah Azza Wa Jalla kepadamu.\" Dan seorang lagi mengucapkan perkataan serupa, maka beliau bersabda: \"Demi Allah, sesungguhnya kami tidak akan memberikan jabatan bagi orang yang meminta dan yang rakus terhadapnya.\""},"3170":{"ar":"حَدَّثَنَا عُبَيْدُ اللَّهِ بْنُ سَعِيدٍ وَمُحَمَّدُ بْنُ حَاتِمٍ وَاللَّفْظُ لِابْنِ حَاتِمٍ قَالَا حَدَّثَنَا يَحْيَى بْنُ سَعِيدٍ الْقَطَّانُ حَدَّثَنَا قُرَّةُ بْنُ خَالِدٍ حَدَّثَنَا حُمَيْدُ بْنُ هِلَالٍ حَدَّثَنِي أَبُو بُرْدَةَ قَالَ قَالَ أَبُو مُوسَىأَقْبَلْتُ إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَمَعِي رَجُلَانِ مِنْ الْأَشْعَرِيِّينَ أَحَدُهُمَا عَنْ يَمِينِي وَالْآخَرُ عَنْ يَسَارِي فَكِلَاهُمَا سَأَلَ الْعَمَلَ وَالنَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَسْتَاكُ فَقَالَ مَا تَقُولُ يَا أَبَا مُوسَى أَوْ يَا عَبْدَ اللَّهِ بْنَ قَيْسٍ قَالَ فَقُلْتُ وَالَّذِي بَعَثَكَ بِالْحَقِّ مَا أَطْلَعَانِي عَلَى مَا فِي أَنْفُسِهِمَا وَمَا شَعَرْتُ أَنَّهُمَا يَطْلُبَانِ الْعَمَلَ قَالَ وَكَأَنِّي أَنْظُرُ إِلَى سِوَاكِهِ تَحْتَ شَفَتِهِ وَقَدْ قَلَصَتْ فَقَالَ لَنْ أَوْ لَا نَسْتَعْمِلُ عَلَى عَمَلِنَا مَنْ أَرَادَهُ وَلَكِنْ اذْهَبْ أَنْتَ يَا أَبَا مُوسَى أَوْ يَا عَبْدَ اللَّهِ بْنَ قَيْسٍ فَبَعَثَهُ عَلَى الْيَمَنِ ثُمَّ أَتْبَعَهُ مُعَاذَ بْنَ جَبَلٍ فَلَمَّا قَدِمَ عَلَيْهِ قَالَ انْزِلْ وَأَلْقَى لَهُ وِسَادَةً وَإِذَا رَجُلٌ عِنْدَهُ مُوثَقٌ قَالَ مَا هَذَا قَالَ هَذَا كَانَ يَهُودِيًّا فَأَسْلَمَ ثُمَّ رَاجَعَ دِينَهُ دِينَ السَّوْءِ فَتَهَوَّدَ قَالَ لَا أَجْلِسُ حَتَّى يُقْتَلَ قَضَاءُ اللَّهِ وَرَسُولِهِ فَقَالَ اجْلِسْ نَعَمْ قَالَ لَا أَجْلِسُ حَتَّى يُقْتَلَ قَضَاءُ اللَّهِ وَرَسُولِهِ ثَلَاثَ مَرَّاتٍ فَأَمَرَ بِهِ فَقُتِلَ ثُمَّ تَذَاكَرَا الْقِيَامَ مِنْ اللَّيْلِ فَقَالَ أَحَدُهُمَا مُعَاذٌ أَمَّا أَنَا فَأَنَامُ وَأَقُومُ وَأَرْجُو فِي نَوْمَتِي مَا أَرْجُو فِي قَوْمَتِي","id":"Telah menceritakan kepada kami [Ubaidillah bin Sa'id] dan [Muhammad bin Hatim] dan ini adalah lafadz Ibnu Hatim, keduanya berkata, telah menceritakan kepada kami [Yahya bin Sa'id Al Qatthan] telah menceritakan kepada kami [Qurrah bin Khalid] telah menceritakan kepada kami [Humaid bin Hilal] telah menceritakan kepadaku [Abu Burdah] dia berkata, [Abu Musa] berkata, \"Saya menemui Nabi shallallahu 'alaihi wasallam bersama dengan dua orang dari bani Al Asy'ariyin, seorang berada di sisi kananku dan seorang lagi di sisi kiriku. Keduanya meminta diberi jabatan, sementara saat itu beliau sedang bersiwak. Beliau lalu bersabda: \"Wahai Abu Musa, atau Abdullah bin Qais, bagaimana menurutmu mengenai hal ini?\" Abu Musa berkata, \"Saya menjawab, \"Demi dzat yang menutusmu dengan kebenaran, sungguh saya tidak tahu apa yang ada dalam hati mereka berdua, dan saya tidak menduga bahwa keduanya akan meminta jabatan dari anda wahai Rasulullah.\" Abu Musa berkata, \"Seakan-akan saya melihat siwak beliau yang sudah usang berada di bawah bibirnya.\" Kemudian beliau bersabda: \"Ketahuilah, sesungguhnya saya tidak akan memberikan jabatan kepada orang yang justru menginginkannya, sekarang pergilah kamu wahai Abu Musa atau Abdullah bin Qais!\" Akhirnya beliau mengutusnya ke negeri Yaman diikuti oleh Mu'adz bin Jabal. Ketika Mu'adz menemui Abu Musa, maka -sambil memberikan bantal kepadanya- Abu Musa berkata, \"Silahkan duduk!\" Ketika hendak duduk, Mu'adz bin Jabal melihat seorang laki-laki yang terikat, lalu Mu'dz berkata, \"Siapakah laki-laki ini?\" Abu Musa menjawab, \"Dulunya dia adalah seorang Yahudi yang telah masuk Islam, tetapi setelah itu ia kembali lagi kepada agamanya yang semula, agama Yahudi.\" Mu'adz langsung berkata, \"Saya tidak akan duduk sebelum orang ini dibunuh sesuai dengan ketentuan hukum Allah dan rasul-Nya.\" Abu Musa berkata, \"Duduklah dulu.\" Mu'az menjawab, \"Saya tidak akan duduk sebelum orang ini dibunuh sesuai dengan ketentuan hukum Allah dan rasul-Nya.\" Abu Musa tetap berkata, \"Duduklah terlebih dahulu.\" Mu'adz tetap bersikeras menjawab, \"Saya tidak akan duduk sebelum orang ini dibunuh sesuai dengan ketentuan hukum Allah dan rasul-Nya.\" Hingga ia mengulanginya tiga kali. Akhirnya Abu Musa memerintahkan supaya laki-laki Yahudi itu dibunuh, kemudian keduanya saling mengingatkan untuk selalu melakukan shalat malam. Salah satu dari keduanya, yaitu Mu'adz berkata, \"Kalau saya sendiri tetap akan tidur dan juga akan melaksanakan shalat, saya berharap bahwa dalam tidurku ini saya akan memperoleh pahala yang sama seperti saya melakukan shalat.\""},"3171":{"ar":"حَدَّثَنَا عَبْدُ الْمَلِكِ بْنُ شُعَيْبِ بْنِ اللَّيْثِ حَدَّثَنِي أَبِي شُعَيْبُ بْنُ اللَّيْثِ حَدَّثَنِي اللَّيْثُ بْنُ سَعْدٍ حَدَّثَنِي يَزِيدُ بْنُ أَبِي حَبِيبٍ عَنْ بَكْرِ بْنِ عَمْرٍو عَنْ الْحَارِثِ بْنِ يَزِيدَ الْحَضْرَمِيِّ عَنْ ابْنِ حُجَيْرَةَ الْأَكْبَرِ عَنْ أَبِي ذَرٍّ قَالَقُلْتُ يَا رَسُولَ اللَّهِ أَلَا تَسْتَعْمِلُنِي قَالَ فَضَرَبَ بِيَدِهِ عَلَى مَنْكِبِي ثُمَّ قَالَ يَا أَبَا ذَرٍّ إِنَّكَ ضَعِيفٌ وَإِنَّهَا أَمَانَةُ وَإِنَّهَا يَوْمَ الْقِيَامَةِ خِزْيٌ وَنَدَامَةٌ إِلَّا مَنْ أَخَذَهَا بِحَقِّهَا وَأَدَّى الَّذِي عَلَيْهِ فِيهَا","id":"Telah menceritakan kepada kami [Abdul Malik bin Syu'aib bin Laits] telah menceritakan kepadaku bapakku [Syu'aib bin Laits] telah menceritakan kepadaku [Laits bin Sa'ad] telah menceritakan kepadaku [Yazid bin Abu Habib] dari [Bakr bin 'Amru] dari [Al Harits bin Yazid Al Hadhrami] dari [Ibnu Hujairah Al Akbar] dari [Abu Dzar] dia berkata, saya berkata, \"Wahai Rasulullah, tidakkah anda menjadikanku sebagai pegawai (pejabat)?\" Abu Dzar berkata, \"Kemudian beliau menepuk bahuku dengan tangan beliau seraya bersabda: \"Wahai Abu Dzar, kamu ini lemah (untuk memegang jabatan) padahal jabatan merupakan amanah. Pada hari kiamat ia adalah kehinaan dan penyesalan, kecuali bagi siapa yang mengambilnya dengan haq dan melaksanakan tugas dengan benar.\""},"3172":{"ar":"حَدَّثَنَا زُهَيْرُ بْنُ حَرْبٍ وَإِسْحَقُ بْنُ إِبْرَاهِيمَ كِلَاهُمَا عَنْ الْمُقْرِئِ قَالَ زُهَيْرٌ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ يَزِيدَ حَدَّثَنَا سَعِيدُ بْنُ أَبِي أَيُّوبَ عَنْ عُبَيْدِ اللَّهِ بْنِ أَبِي جَعْفَرٍ الْقُرَشِيِّ عَنْ سَالِمِ بْنِ أَبِي سَالِمٍ الْجَيْشَانِيِّ عَنْ أَبِيهِ عَنْ أَبِي ذَرٍّأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ يَا أَبَا ذَرٍّ إِنِّي أَرَاكَ ضَعِيفًا وَإِنِّي أُحِبُّ لَكَ مَا أُحِبُّ لِنَفْسِي لَا تَأَمَّرَنَّ عَلَى اثْنَيْنِ وَلَا تَوَلَّيَنَّ مَالَ يَتِيمٍ","id":"Telah menceritakan kepada kami [Zuhair bin Harb] dan [Ishaq bin Ibrahim] keduanya dari [Al Muqri'i], [Zuhair] berkata; telah menceritakan kepada kami [Abdullah bin Yazid] telah menceritakan kepada kami [Sa'id bin Abu Ayyub] dari [Ubaidullah bin Abi Ja'far Al Qurasyi] dari [Salim bin Abu Salim Al Jaisyani] dari [ayahnya] dari [Abu Dzar] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Wahai Abu Dzar, sungguh saya melihatmu sangat lemah, dan saya menginginkan untukmu seperti yang saya inginkan untuk kamu. Jangan kamu menjadi pemimpin di antara dua orang dan jangan kami menguasai harta anak yatim.\""},"3173":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ وَزُهَيْرُ بْنُ حَرْبٍ وَابْنُ نُمَيْرٍ قَالُوا حَدَّثَنَا سُفْيَانُ بْنُ عُيَيْنَةَ عَنْ عَمْرٍو يَعْنِي ابْنَ دِينَارٍ عَنْ عَمْرِو بْنِ أَوْسٍ عَنْ عَبْدِ اللَّهِ بْنِ عَمْرٍو قَالَ ابْنُ نُمَيْرٍ وَأَبُو بَكْرٍ يَبْلُغُ بِهِ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَفِي حَدِيثِ زُهَيْرٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّ الْمُقْسِطِينَ عِنْدَ اللَّهِ عَلَى مَنَابِرَ مِنْ نُورٍ عَنْ يَمِينِ الرَّحْمَنِ عَزَّ وَجَلَّ وَكِلْتَا يَدَيْهِ يَمِينٌ الَّذِينَ يَعْدِلُونَ فِي حُكْمِهِمْ وَأَهْلِيهِمْ وَمَا وَلُوا","id":"Telah menceritakan kepada kami [Abu Bakar bin Abi Syaibah] dan [Zuhair bin Harb] dan [Ibnu Numair] mereka berkata; telah menceritakan kepada kami [Sufyan bin 'Uyainah] dari ['Amru] -yaitu Ibnu Dinar- dari ['Amru bin Aus] dari [Abdullah bin 'Amru], -dan Ibnu Numair dan Abu Bakar mengatakan sesuatu yang sampai kepada Nabi shallallahu 'alaihi wasallam, dan dalam haditsnya Zuhair- dia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Orang-orang yang berlaku adil berada di sisi Allah di atas mimbar (panggung) yang terbuat dari cahaya, di sebelah kanan Ar Rahman 'azza wajalla -sedangkan kedua tangan Allah adalah kanan semua-, yaitu orang-orang yang berlaku adil dalam hukum, adil dalam keluarga dan adil dalam melaksanakan tugas yang di bebankan kepada mereka.\""},"3174":{"ar":"حَدَّثَنِي هَارُونُ بْنُ سَعِيدٍ الْأَيْلِيُّ حَدَّثَنَا ابْنُ وَهْبٍ حَدَّثَنِي حَرْمَلَةُ عَنْ عَبْدِ الرَّحْمَنِ بْنِ شِمَاسَةَ قَالَ أَتَيْتُ عَائِشَةَ أَسْأَلُهَا عَنْ شَيْءٍ فَقَالَتْ مِمَّنْ أَنْتَ فَقُلْتُ رَجُلٌ مِنْ أَهْلِ مِصْرَ فَقَالَتْ كَيْفَ كَانَ صَاحِبُكُمْ لَكُمْ فِي غَزَاتِكُمْ هَذِهِ فَقَالَ مَا نَقَمْنَا مِنْهُ شَيْئًا إِنْ كَانَ لَيَمُوتُ لِلرَّجُلِ مِنَّا الْبَعِيرُ فَيُعْطِيهِ الْبَعِيرَ وَالْعَبْدُ فَيُعْطِيهِ الْعَبْدَ وَيَحْتَاجُ إِلَى النَّفَقَةِ فَيُعْطِيهِ النَّفَقَةَ فَقَالَتْ أَمَا إِنَّهُ لَا يَمْنَعُنِي الَّذِي فَعَلَ فِي مُحَمَّدِ بْنِ أَبِي بَكْرٍ أَخِي أَنْ أُخْبِرَكَ مَاسَمِعْتُ مِنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ فِي بَيْتِي هَذَا اللَّهُمَّ مَنْ وَلِيَ مِنْ أَمْرِ أُمَّتِي شَيْئًا فَشَقَّ عَلَيْهِمْ فَاشْقُقْ عَلَيْهِ وَمَنْ وَلِيَ مِنْ أَمْرِ أُمَّتِي شَيْئًا فَرَفَقَ بِهِمْ فَارْفُقْ بِهِو حَدَّثَنِي مُحَمَّدُ بْنُ حَاتِمٍ حَدَّثَنَا ابْنُ مَهْدِيٍّ حَدَّثَنَا جَرِيرُ بْنُ حَازِمٍ عَنْ حَرْمَلَةَ الْمِصْرِيِّ عَنْ عَبْدِ الرَّحْمَنِ بْنِ شِمَاسَةَ عَنْ عَائِشَةَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِمِثْلِهِ","id":"Telah menceritakan kepadaku [Harun bin Sa'id Al Aili] telah menceritakan kepada kami [Ibnu Wahb] telah menceritakan kepadaku [Harmalah] dari [Abdurrahman bin Syimasah] dia berkata, \"Saya mendatangi ['Aisyah] untuk menanyakan tentang sesuatu, maka dia balik bertanya, \"Dari manakah kamu?\" Saya menjawab, \"Seorang dari penduduk Mesir.\" Aisyah berkata, \"Bagaimana keadaan sahabat kalian yang berperang bersama kalian dalam peperangan ini?\" dia menjawab, \"Kami tidak pernah membencinya sedikitpun, jika keledai salah seorang dari kami mati maka dia menggantinya, jika yang mati budak maka dia akan mengganti seorang budak, dan jika salah seorang dari kami membutuhkan kebutuhan hidup maka ia akan memberinya.\" 'Aisyah berkata, \"Tidak layak bagiku jika saya tidak mengutarakan keutamaan saudaraku, Muhammad bin Abu Bakar, saya akan memberitahukanmu sesuatu yang pernah saya dengar dari Rasulullah shallallahu 'alaihi wasallam. Beliau berdo'a ketika berada di rumahku ini: \"Ya Allah, siapa yang menjabat suatu jabatan dalam pemerintahan ummatku lalu dia mempersulit urusan mereka, maka persulitlah dia. Dan siapa yang menjabat suatu jabatan dalam pemerintahan ummatku lalu dia berusaha menolong mereka, maka tolong pulalah dia.\" Dan telah menceritakan kepadaku [Muhammad bin Hatim] telah menceritakan kepada kami [Ibnu Mahdi] telah menceritakan kepada kami [Jarir bin Hazim] dari [Harmalah Al Mishri] dari [Abdurrahman bin Syimasaah] dari ['Aisyah] dari Nabi shallallahu 'alaihi wasallam seperti hadits di atas.\""},"3175":{"ar":"حَدَّثَنَا قُتَيْبَةُ بْنُ سَعِيدٍ حَدَّثَنَا لَيْثٌ ح و حَدَّثَنَا مُحَمَّدُ بْنُ رُمْحٍ حَدَّثَنَا اللَّيْثُ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهُ قَالَ أَلَا كُلُّكُمْ رَاعٍ وَكُلُّكُمْ مَسْئُولٌ عَنْ رَعِيَّتِهِ فَالْأَمِيرُ الَّذِي عَلَى النَّاسِ رَاعٍ وَهُوَ مَسْئُولٌ عَنْ رَعِيَّتِهِ وَالرَّجُلُ رَاعٍ عَلَى أَهْلِ بَيْتِهِ وَهُوَ مَسْئُولٌ عَنْهُمْ وَالْمَرْأَةُ رَاعِيَةٌ عَلَى بَيْتِ بَعْلِهَا وَوَلَدِهِ وَهِيَ مَسْئُولَةٌ عَنْهُمْ وَالْعَبْدُ رَاعٍ عَلَى مَالِ سَيِّدِهِ وَهُوَ مَسْئُولٌ عَنْهُ أَلَا فَكُلُّكُمْ رَاعٍ وَكُلُّكُمْ مَسْئُولٌ عَنْ رَعِيَّتِهِو حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا مُحَمَّدُ بْنُ بِشْرٍ ح و حَدَّثَنَا ابْنُ نُمَيْرٍ حَدَّثَنَا أَبِي ح و حَدَّثَنَا ابْنُ الْمُثَنَّى حَدَّثَنَا خَالِدٌ يَعْنِي ابْنَ الْحَارِثِ ح و حَدَّثَنَا عُبَيْدُ اللَّهِ بْنُ سَعِيدٍ حَدَّثَنَا يَحْيَى يَعْنِي الْقَطَّانَ كُلُّهُمْ عَنْ عُبَيْدِ اللَّهِ بْنِ عُمَرَ ح و حَدَّثَنَا أَبُو الرَّبِيعِ وَأَبُو كَامِلٍ قَالَا حَدَّثَنَا حَمَّادُ بْنُ زَيْدٍ ح و حَدَّثَنِي زُهَيْرُ بْنُ حَرْبٍ حَدَّثَنَا إِسْمَعِيلُ جَمِيعًا عَنْ أَيُّوبَ ح و حَدَّثَنِي مُحَمَّدُ بْنُ رَافِعٍ حَدَّثَنَا ابْنُ أَبِي فُدَيْكٍ أَخْبَرَنَا الضَّحَّاكُ يَعْنِي ابْنَ عُثْمَانَ ح و حَدَّثَنَا هَارُونُ بْنُ سَعِيدٍ الْأَيْلِيُّ حَدَّثَنَا ابْنُ وَهْبٍ حَدَّثَنِي أُسَامَةُ كُلُّ هَؤُلَاءِ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَ مِثْلَ حَدِيثِ اللَّيْثِ عَنْ نَافِعٍ قَالَ أَبُو إِسْحَقَ وَحَدَّثَنَا الْحَسَنُ بْنُ بِشْرٍ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ نُمَيْرٍ عَنْ عُبَيْدِ اللَّهِ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَ بِهَذَا مِثْلَ حَدِيثِ اللَّيْثِ عَنْ نَافِعٍ و حَدَّثَنَا يَحْيَى بْنُ يَحْيَى وَيَحْيَى بْنُ أَيُّوبَ وَقُتَيْبَةُ بْنُ سَعِيدٍ وَابْنُ حُجْرٍ كُلُّهُمْ عَنْ إِسْمَعِيلَ بْنِ جَعْفَرٍ عَنْ عَبْدِ اللَّهِ بْنِ دِينَارٍ عَنْ ابْنِ عُمَرَ قَالَ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ح و حَدَّثَنِي حَرْمَلَةُ بْنُ يَحْيَى أَخْبَرَنَا ابْنُ وَهْبٍ أَخْبَرَنِي يُونُسُ عَنْ ابْنِ شِهَابٍ عَنْ سَالِمِ بْنِ عَبْدِ اللَّهِ عَنْ أَبِيهِ قَالَ سَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ بِمَعْنَى حَدِيثِ نَافِعٍ عَنْ ابْنِ عُمَرَ وَزَادَ فِي حَدِيثِ الزُّهْرِيِّ قَالَ وَحَسِبْتُ أَنَّهُ قَدْ قَالَ الرَّجُلُ رَاعٍ فِي مَالِ أَبِيهِ وَمَسْئُولٌ عَنْ رَعِيَّتِهِ و حَدَّثَنِي أَحْمَدُ بْنُ عَبْدِ الرَّحْمَنِ بْنِ وَهْبٍ أَخْبَرَنِي عَمِّي عَبْدُ اللَّهِ بْنُ وَهْبٍ أَخْبَرَنِي رَجُلٌ سَمَّاهُ وَعَمْرُو بْنُ الْحَارِثِ عَنْ بُكَيْرٍ عَنْ بُسْرِ بْنِ سَعِيدٍ حَدَّثَهُ عَنْ عَبْدِ اللَّهِ بْنِ عُمَرَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِهَذَا الْمَعْنَى","id":"Telah menceritakan kepada kami [Qutaibah bin Sa'id] telah menceritakan kepada kami [Laits]. (dalam jalur lain disebutkan) Telah menceritakan kepada kami [Muhammad bin Rumh] telah menceritakan kepada kami [Laits] dari [Nafi'] dari [Ibnu Umar] dari Nabi shallallahu 'alaihi wasallam, bahwa beliau bersabda: \"Ketahuilah, setiap kalian adalah pemimpin, dan setiap kalian bertanggung jawab atas apa yang dipimpinnya. Seorang pemimpin yang memimpin manusia akan bertanggung jawab atas rakyatnya, seorang laki-laki adalah pemimpin atas keluarganya, dan dia bertanggung jawab atas mereka semua, seorang wanita juga pemimpin atas rumah suaminya dan anak-anaknya, dan dia bertanggung jawab atas mereka semua, seorang budak adalah pemimpin atas harta tuannya, dan dia bertanggung jawab atas harta tersebut. Setiap kalian adalah pemimpin dan akan bertanggung jawab atas kepemimpinannya.\" Dan telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] telah menceritakan kepada kami [Muhammad bin Bisyr]. (dalam jalur lain disebutkan) Telah menceritakan kepada kami [Ibnu Numair] telah menceritakan kepada kami [ayahku]. (dalam jalur lain disebutkan) Telah menceritakan kepada kami [Ibnu Al Mutsanna] telah menceritakan kepada kami [Khalid] -yaitu Ibnu Harits. (dalam jalur lain disebutkan) Telah menceritakan kepada kami [Ubaidullah bin Sa'id] telah menceritakan kepada kami [Yahya] -yaitu Al Qatthan- semuanya dari [Ubaidullah bin Umar]. (dalam jalur lain disebutkan) telah menceritakan kepada kami [Abu Ar Rabi'] dan [Abu Kamil] keduanya berkata; telah menceritakan kepada kami [Hammad bin Zaid]. (dalam jalur lain disebutkan) Telah menceritakan kepadaku [Zuhair bin Harb] telah menceritakan kepada kami [Isma'il] semuanya dari [Ayyub]. (dalam jalur lain disebutkan) Telah menceritakan kepadaku [Muhammad bin Rafi'] telah menceritakan kepada kami [Ibnu Abi Fudaik] telah mengabarkan kepada kami [Ad Dlahak] -yaitu Ibnu 'Utsman-. (dalam jalur lain disebutkan) Telah menceritakan kepada kami [Harun bin Sa'id Al Aili] telah menceritakan kepada kami [Ibnu Wahb] telah menceritakan kepadaku [Usamah] semuanya dari [Nafi'] dari [Ibnu Umar] seperti haditsnya Laits dari Nafi', Abu Ishaq berkata; telah menceritakan kepada kami Al Hasan bin Bisyr telah menceritakan kepada kami Abdullah bin Numair dari Ubaidullah dari Nafi' dari Ibnu Umar seperti haditsnya Laits dari Nafi'.\" Telah menceritakan kepada kami [Yahya bin Yahya] dan [Yahya bin Ayyub] dan [Qutaibah bin Sa'id] dan [Ibnu Hujr] semuanya dari [Isma'il bin Ja'far] dari [Abdullah bin dinar] dari [Ibnu Umar] dia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda.\" (dalam jalur lain disebutkan) Telah menceritakan kepadaku [Harmalah bin Yahya] telah mengabarkan kepada kami [Ibnu Wahb] telah mengabarkan kepadaku [Yunus] dari [Ibnu Syihab] dari [Salim bin Abdullah] dari [ayahnya] dia berkata, \"Saya pernah mendengar Rasulullah shallallahu 'alaihi wasallam bersabda semakna dengan haditsnya Nafi' dari Ibnu Umar. Dan dalam haditsnya Zuhri ada tambahan, dia berkata, \"Saya mengira bahwa beliau telah bersabda: \"Seseorang pemimpin atas harta benda ayahnya, dan dia bertanggung jawab akan kepemimpinannya.\" Dan telah menceritakan kepadaku [Ahmad bin Abdurrahman bin Wahb] telah mengabarkan kepadaku pamanku [Abdullah bin Wahb] telah mengabarkan kepadaku seorang laki-laki yang bernama ['Amru bin Harits] dari [Bukair] dari [Busr bin Sa'id] dia telah menceritakan dari [Abdullah bin Umar] dari Nabi shallallahu 'alaihi wasallam dengan makna seperti ini.\""},"3176":{"ar":"و حَدَّثَنَا شَيْبَانُ بْنُ فَرُّوخَ حَدَّثَنَا أَبُو الْأَشْهَبِ عَنْ الْحَسَنِ قَالَعَادَ عُبَيْدُ اللَّهِ بْنُ زِيَادٍ مَعْقِلَ بْنَ يَسَارٍ الْمُزَنِيَّ فِي مَرَضِهِ الَّذِي مَاتَ فِيهِ فَقَالَ مَعْقِلٌ إِنِّي مُحَدِّثُكَ حَدِيثًا سَمِعْتُهُ مِنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَوْ عَلِمْتُ أَنَّ لِي حَيَاةً مَا حَدَّثْتُكَإِنِّي سَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ مَا مِنْ عَبْدٍ يَسْتَرْعِيهِ اللَّهُ رَعِيَّةً يَمُوتُ يَوْمَ يَمُوتُ وَهُوَ غَاشٌّ لِرَعِيَّتِهِ إِلَّا حَرَّمَ اللَّهُ عَلَيْهِ الْجَنَّةَو حَدَّثَنَاه يَحْيَى بْنُ يَحْيَى أَخْبَرَنَا يَزِيدُ بْنُ زُرَيْعٍ عَنْ يُونُسَ عَنْ الْحَسَنِ قَالَ دَخَلَ ابْنُ زِيَادٍ عَلَى مَعْقِلِ بْنِ يَسَارٍ وَهُوَ وَجِعٌ بِمِثْلِ حَدِيثِ أَبِي الْأَشْهَبِ وَزَادَ قَالَ أَلَّا كُنْتَ حَدَّثْتَنِي هَذَا قَبْلَ الْيَوْمِ قَالَ مَا حَدَّثْتُكَ أَوْ لَمْ أَكُنْ لِأُحَدِّثَكَ","id":"Telah menceritakan kepada kami [Syaiban bin Farruh] telah menceritakan kepada kami [Abu Al Ayshab] dari [Hasan] dia berkata, \"Ubaidullah bin Ziyad menjenguk [Ma'qil bin Yasar Al Muzanni] ketika dia sedang sakit yang mengantarkan kepada kematiannya, maka Ma'qil lalu berkata, \"Sungguh saya akan menceritakan kepadamu suatu hadits yang pernah saya dengar langsung dari Rasulullah shallallahu 'alaihi wasallam, sekiranya saya masih hidup lama niscaya tidak akan saya ceritakan hal ini kepadamu. Sesungguhnya saya pernah mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tidaklah seorang pemimpin yang Allah serahi untuk memimpin rakyatnya, ketika meninggal dalam keadaan menipu rakyatnya, melainkan Allah akan mengharamkan surga untuknya.\" Dan telah menceritakan kepada kami [Yahya bin Yahya] telah mengabarkan kepada kami [Yazid bin Zurai'] dari [Yunus] dari [Hasan] dia berkata, \"Ibnu Ziyad menemui [Ma'qil bin Yasar] yang sedang sakit, seperti haditsnya Abu Al Asyhab, lalu ia menambahkan, \"Ibnu Ziyad bertanya, \"Tidakkah sebelumnya kamu telah menceritakan hal ini kepadaku?\" Dia menjawab, \"Saya belim pernah menceritakan hal ini kepadamu atau belum pernah bercerita kepadamu.\""},"3177":{"ar":"و حَدَّثَنَا أَبُو غَسَّانَ الْمِسْمَعِيُّ وَإِسْحَقُ بْنُ إِبْرَاهِيمَ وَمُحَمَّدُ بْنُ الْمُثَنَّى قَالَ إِسْحَقُ أَخْبَرَنَا و قَالَ الْآخَرَانِ حَدَّثَنَا مُعَاذُ بْنُ هِشَامٍ حَدَّثَنِي أَبِي عَنْ قَتَادَةَ عَنْ أَبِي الْمَلِيحِ أَنَّ عُبَيْدَ اللَّهِ بْنَ زِيَادٍ دَخَلَ عَلَى مَعْقِلِ بْنِ يَسَارٍ فِي مَرَضِهِ فَقَالَ لَهُ مَعْقِلٌ إِنِّي مُحَدِّثُكَ بِحَدِيثٍ لَوْلَا أَنِّي فِي الْمَوْتِ لَمْ أُحَدِّثْكَ بِهِسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ مَا مِنْ أَمِيرٍ يَلِي أَمْرَ الْمُسْلِمِينَ ثُمَّ لَا يَجْهَدُ لَهُمْ وَيَنْصَحُ إِلَّا لَمْ يَدْخُلْ مَعَهُمْ الْجَنَّةَو حَدَّثَنَا عُقْبَةُ بْنُ مُكْرَمٍ الْعَمِّيُّ حَدَّثَنَا يَعْقُوبُ بْنُ إِسْحَقَ أَخْبَرَنِي سَوَادَةُ بْنُ أَبِي الْأَسْوَدِ حَدَّثَنِي أَبِي أَنَّ مَعْقِلَ بْنَ يَسَارٍ مَرِضَ فَأَتَاهُ عُبَيْدُ اللَّهِ بْنُ زِيَادٍ يَعُودُهُ نَحْوَ حَدِيثِ الْحَسَنِ عَنْ مَعْقِلٍ","id":"Dan telah menceritakan kepada kami [Abu Ghassan Al Misma'i] dan [Ishaq bin Ibrahim] dan [Muhammad bin Mutsanna], Ishaq berkata; telah mengabarkan kepada kami, sedangkan yang dua mengatakan; telah menceritakan kepada kami [Mu'adz bin Hisyam] telah menceritakan kepadaku [ayahku] dari [Qatadah] dari [Abu Al Malih], bahwa Ubaidullah bin Yizad menjenguk [Ma'qil bin Yasar] ketika sakit, Ma'qil lalu berkata kepadanya, \"Sungguh saya akan menceritakan kepadamu suatu hadits, sekiranya saya tidak diambang kematian niscaya saya tidak akan menceritakannya kepadamu. Saya pernah mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tidaklah seorang pemimpin yang mengurusi perkara kaum Muslimin sedang dia tidak bersungguh-sungguh dan tidak jujur, melainkan ia tidak akan dimasukkan bersama mereka ke dalam surga.\" Dan telah menceritakan kepada kami ['Uqbah bin Mukram Al 'Ammi] telah menceritakan kepada kami [Ya'qub bin Ishaq] telah mengabarkan kepadaku [Sawadah bin Abu Al Aswad] telah menceritakan kepadaku [ayahku] bahwa [Ma'qil bin Yasar] jatuh sakit, lantas Ubaidullah bin Ziyad datang menjenguknya… seperti haditsnya Hasan dari Ma'qil.\""},"3178":{"ar":"حَدَّثَنَا شَيْبَانُ بْنُ فَرُّوخَ حَدَّثَنَا جَرِيرُ بْنُ حَازِمٍ حَدَّثَنَا الْحَسَنُأَنَّ عَائِذَ بْنَ عَمْرٍو وَكَانَ مِنْ أَصْحَابِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ دَخَلَ عَلَى عُبَيْدِ اللَّهِ بْنِ زِيَادٍ فَقَالَ أَيْ بُنَيَّ إِنِّي سَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ إِنَّ شَرَّ الرِّعَاءِ الْحُطَمَةُ فَإِيَّاكَ أَنْ تَكُونَ مِنْهُمْ فَقَالَ لَهُ اجْلِسْ فَإِنَّمَا أَنْتَ مِنْ نُخَالَةِ أَصْحَابِ مُحَمَّدٍ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ وَهَلْ كَانَتْ لَهُمْ نُخَالَةٌ إِنَّمَا كَانَتْ النُّخَالَةُ بَعْدَهُمْ وَفِي غَيْرِهِمْ","id":"Telah menceritakan kepada kami [Syaiban bin Farruh] telah menceritakan kepada kami [Jarir bin Hazim] telah menceritakan kepada kami [Al Hasan] bahwa ['Aidz bin 'Amru] salah seorang sahabat Rasulullah shallallahu 'alaihi wasallam, menemui Ubaidullah bin Ziyad sambil berkata, \"Wahai anakkku, sesungguhnya saya pernah mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sesungguhnya seburuk-buruk penguasa adalah penguasa yang zhalim, maka janganlah kamu termasuk dari mereka.\" Lalu 'Ubaidullah berkata kepadanya, \"Duduklah, kamu ini hanyalah sahabat Muhammad shallallahu 'alaihi wasallam yang masih yunior (rendahan).\" Maka 'Aidz pun ganti berkata, \"Apakah di antara mereka ada yang disebut sebagai sahabat kelas yunior?\" Sebenarnya yang pantas disebut sahabat kelas rendahan adalah orang-orang setelah mereka dan juga yang selain mereka.\""},"3179":{"ar":"و حَدَّثَنِي زُهَيْرُ بْنُ حَرْبٍ حَدَّثَنَا إِسْمَعِيلُ بْنُ إِبْرَاهِيمَ عَنْ أَبِي حَيَّانَ عَنْ أَبِي زُرْعَةَ عَنْ أَبِي هُرَيْرَةَ قَالَقَامَ فِينَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ذَاتَ يَوْمٍ فَذَكَرَ الْغُلُولَ فَعَظَّمَهُ وَعَظَّمَ أَمْرَهُ ثُمَّ قَالَ لَا أُلْفِيَنَّ أَحَدَكُمْ يَجِيءُ يَوْمَ الْقِيَامَةِ عَلَى رَقَبَتِهِ بَعِيرٌ لَهُ رُغَاءٌ يَقُولُ يَا رَسُولَ اللَّهِ أَغِثْنِي فَأَقُولُ لَا أَمْلِكُ لَكَ شَيْئًا قَدْ أَبْلَغْتُكَ لَا أُلْفِيَنَّ أَحَدَكُمْ يَجِيءُ يَوْمَ الْقِيَامَةِ عَلَى رَقَبَتِهِ فَرَسٌ لَهُ حَمْحَمَةٌ فَيَقُولُ يَا رَسُولَ اللَّهِ أَغِثْنِي فَأَقُولُ لَا أَمْلِكُ لَكَ شَيْئًا قَدْ أَبْلَغْتُكَ لَا أُلْفِيَنَّ أَحَدَكُمْ يَجِيءُ يَوْمَ الْقِيَامَةِ عَلَى رَقَبَتِهِ شَاةٌ لَهَا ثُغَاءٌ يَقُولُ يَا رَسُولَ اللَّهِ أَغِثْنِي فَأَقُولُ لَا أَمْلِكُ لَكَ شَيْئًا قَدْ أَبْلَغْتُكَ لَا أُلْفِيَنَّ أَحَدَكُمْ يَجِيءُ يَوْمَ الْقِيَامَةِ عَلَى رَقَبَتِهِ نَفْسٌ لَهَا صِيَاحٌ فَيَقُولُ يَا رَسُولَ اللَّهِ أَغِثْنِي فَأَقُولُ لَا أَمْلِكُ لَكَ شَيْئًا قَدْ أَبْلَغْتُكَ لَا أُلْفِيَنَّ أَحَدَكُمْ يَجِيءُ يَوْمَ الْقِيَامَةِ عَلَى رَقَبَتِهِ رِقَاعٌ تَخْفِقُ فَيَقُولُ يَا رَسُولَ اللَّهِ أَغِثْنِي فَأَقُولُ لَا أَمْلِكُ لَكَ شَيْئًا قَدْ أَبْلَغْتُكَ لَا أُلْفِيَنَّ أَحَدَكُمْ يَجِيءُ يَوْمَ الْقِيَامَةِ عَلَى رَقَبَتِهِ صَامِتٌ فَيَقُولُ يَا رَسُولَ اللَّهِ أَغِثْنِي فَأَقُولُ لَا أَمْلِكُ لَكَ شَيْئًا قَدْ أَبْلَغْتُكَو حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا عَبْدُ الرَّحِيمِ بْنُ سُلَيْمَانَ عَنْ أَبِي حَيَّانَ ح و حَدَّثَنِي زُهَيْرُ بْنُ حَرْبٍ حَدَّثَنَا جَرِيرٌ عَنْ أَبِي حَيَّانَ وَعُمَارَةَ بْنِ الْقَعْقَاعِ جَمِيعًا عَنْ أَبِي زُرْعَةَ عَنْ أَبِي هُرَيْرَةَ بِمِثْلِ حَدِيثِ إِسْمَعِيلَ عَنْ أَبِي حَيَّانَ و حَدَّثَنِي أَحْمَدُ بْنُ سَعِيدِ بْنِ صَخْرٍ الدَّارِمِيُّ حَدَّثَنَا سُلَيْمَانُ بْنُ حَرْبٍ حَدَّثَنَا حَمَّادٌ يَعْنِي ابْنَ زَيْدٍ عَنْ أَيُّوبَ عَنْ يَحْيَى بْنِ سَعِيدٍ عَنْ أَبِي زُرْعَةَ بْنِ عَمْرِو بْنِ جَرِيرٍ عَنْ أَبِي هُرَيْرَةَ قَالَ ذَكَرَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْغُلُولَ فَعَظَّمَهُ وَاقْتَصَّ الْحَدِيثَ قَالَ حَمَّادٌ ثُمَّ سَمِعْتُ يَحْيَى بَعْدَ ذَلِكَ يُحَدِّثُهُ فَحَدَّثَنَا بِنَحْوِ مَا حَدَّثَنَا عَنْهُ أَيُّوبُ و حَدَّثَنِي أَحْمَدُ بْنُ الْحَسَنِ بْنِ خِرَاشٍ حَدَّثَنَا أَبُو مَعْمَرٍ حَدَّثَنَا عَبْدُ الْوَارِثِ حَدَّثَنَا أَيُّوبُ عَنْ يَحْيَى بْنِ سَعِيدِ بْنِ حَيَّانَ عَنْ أَبِي زُرْعَةَ عَنْ أَبِي هُرَيْرَةَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِنَحْوِ حَدِيثِهِمْ","id":"Telah menceritakan kepadaku [Zuhair bin Harb] telah menceritakan kepada kami [Isma'il bin Ibrahim] dari [Abu Hayyan] dari [Abu Zur'ah] dari [Abu Hurairah] dia berkata, \"Suatu hari Rasulullah shallallahu 'alaihi wasallam berdiri di tengah-tengah kami, lalu beliau menyebutkan-nyebut tentang ghulul dan membesarkan perkaranya, kemudian beliau bersabda: \"Jangan sampai pada hari kiamat aku dapati salah seorang dari kalian datang dengan memikul unta yang sedang melenguh-lenguh.\" Lalu dia berkata, \"Ya Rasulullah, tolonglah aku!\" Aku lalu menjawab: \"Aku tidak kuasa sedikitpun untuk menolongmu. Aku telah sampaikan itu padamu. Jangan sampai pada hari kiamat kelak, aku dapati salah seorang dari kalian datang dengan memikul kuda yang meringkik-ringkik.\" Lalu dia berkata, \"Ya Rasulullah, tolonglah aku!\" Jawab beliau: \"Aku tidak sedikitpun menolong kamu. Bukankah dahulu pernah ku katakan kepadamu. Di hari kiamat kelak, jangalah kudapati salah seorang di antara kalian memikul di kuduknya kambing yang mengembek-embek.\" Lalu dia berkata, \"Ya Rasulullah, tolonglah aku!\" Jawab beliau: \"Aku tidak kuasa sedikitpun untuk menolongmu. Aku telah sampaikan itu kepadamu. Jangan sampai pada hari kiamat kelak aku dapati salah seorang dari kalian datang dengan memikul orang yang berteriak-teriak di kuduknya.\" Lalu dia berkata, \"Ya Rasulullah, tolonglah aku!\" Jawab beliau: \"Aku tidak dapat sedikitpun menolongmu. Aku telah sampaikan itu. Pada hari kiamat jangan sampai aku dapati salah seaorang dari kalian datang dengan kepadaku membawa selembar kain berkibar-kibar di kuduknya.\" Lalu dia berkata, \"Ya Rasulullah, tolonglah aku!\" Lalu jawab beliau: \"Aku tidak sedikitpun kuasa menolongmu. Aku telah sampaikan itu kepadamu. Pada hari kiamat kelak janganlah kudapati salah seorang di antara kalian memikul harta kekayaan berupa emas dan perak di kuduknya.\" Lalu dia berkata, \"Ya Rasulullah, tolonglah aku!\" Jawab beliau: \"Aku tidak kuasa sedikitpun menolongmu. Aku telah sampaikan itu kepadamu.\" Dan telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] telah menceritakan kepada kami ['Abdurrahim bin Sulaiman] dari [Abu Hayyan]. (dalam jalur lain disebutkan) Telah menceritakan kepadaku [Zuhair bin Harb] telah menceritakan kepada kami [Jarir] dari [Abu Haiyan] dan ['Umarah bin Al Qa'qa'] semuanya dari [Abu Zur'ah] dari [Abu Hurairah] seperti hadits Isma'il dari Abu haiyan.\" Dan telah menceritakan kepadaku [Ahmad bin Sa'id bin Shakhr Ad Darami] telah menceritakan kepada kami [Sulaiman bin Harb] telah menceritakan kepada kami [Hammad] -yaitu Ibnu Zaid- dari [Ayyub] dari [Yahya bin Sa'id] dari [Abu Zur'ah bin 'Amru Jarir] dari [Abu Hurairah] dia berkata, \"Rasulullah shallallahu 'alaihi wasallam menyebutkan tentang ghulul….lalu dia melanjutkan hadits tersebut. Hammad berkata, \"Setelah itu saya mendengar Yahya menceritakan kepadanya, maka ia kemudian menceritakan kepada kami sebagaimana Ayyub menceritakannya kepada kami.\" Dan telah menceritakan kepada kami [Ahmad bin Al Hasan bin Khirasy] telah menceritakan kepada kami [Abu Ma'mar] telah menceritakan kepada kami [Abdul Warits] telah menceritakan kepada kami [Ayyub] dari [Yahya bin Sa'id bin Hayyan] dari [Abu Zur'ah] dari [Abu Hurairah] dari Nabi shallallahu 'alaihi wasallam seperti hadits mereka.\" "},"3180":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ وَعَمْرٌو النَّاقِدُ وَابْنُ أَبِي عُمَرَ وَاللَّفْظُ لِأَبِي بَكْرٍ قَالُوا حَدَّثَنَا سُفْيَانُ بْنُ عُيَيْنَةَ عَنْ الزُّهْرِيِّ عَنْ عُرْوَةَ عَنْ أَبِي حُمَيْدٍ السَّاعِدِيِّ قَالَاسْتَعْمَلَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ رَجُلًا مِنْ الْأَسْدِ يُقَالُ لَهُ ابْنُ اللُّتْبِيَّةِ قَالَ عَمْرٌو وَابْنُ أَبِي عُمَرَ عَلَى الصَّدَقَةِ فَلَمَّا قَدِمَ قَالَ هَذَا لَكُمْ وَهَذَا لِي أُهْدِيَ لِي قَالَ فَقَامَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَلَى الْمِنْبَرِ فَحَمِدَ اللَّهَ وَأَثْنَى عَلَيْهِ وَقَالَ مَا بَالُ عَامِلٍ أَبْعَثُهُ فَيَقُولُ هَذَا لَكُمْ وَهَذَا أُهْدِيَ لِي أَفَلَا قَعَدَ فِي بَيْتِ أَبِيهِ أَوْ فِي بَيْتِ أُمِّهِ حَتَّى يَنْظُرَ أَيُهْدَى إِلَيْهِ أَمْ لَا وَالَّذِي نَفْسُ مُحَمَّدٍ بِيَدِهِ لَا يَنَالُ أَحَدٌ مِنْكُمْ مِنْهَا شَيْئًا إِلَّا جَاءَ بِهِ يَوْمَ الْقِيَامَةِ يَحْمِلُهُ عَلَى عُنُقِهِ بَعِيرٌ لَهُ رُغَاءٌ أَوْ بَقَرَةٌ لَهَا خُوَارٌ أَوْ شَاةٌ تَيْعِرُ ثُمَّ رَفَعَ يَدَيْهِ حَتَّى رَأَيْنَا عُفْرَتَيْ إِبْطَيْهِ ثُمَّ قَالَ اللَّهُمَّ هَلْ بَلَّغْتُ مَرَّتَيْنِحَدَّثَنَا إِسْحَقُ بْنُ إِبْرَاهِيمَ وَعَبْدُ بْنُ حُمَيْدٍ قَالَا أَخْبَرَنَا عَبْدُ الرَّزَّاقِ حَدَّثَنَا مَعْمَرٌ عَنْ الزُّهْرِيِّ عَنْ عُرْوَةَ عَنْ أَبِي حُمَيْدٍ السَّاعِدِيِّ قَالَ اسْتَعْمَلَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ابْنَ اللُّتْبِيَّةِ رَجُلًا مِنْ الْأَزْدِ عَلَى الصَّدَقَةِ فَجَاءَ بِالْمَالِ فَدَفَعَهُ إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ هَذَا مَالُكُمْ وَهَذِهِ هَدِيَّةٌ أُهْدِيَتْ لِي فَقَالَ لَهُ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَفَلَا قَعَدْتَ فِي بَيْتِ أَبِيكَ وَأُمِّكَ فَتَنْظُرَ أَيُهْدَى إِلَيْكَ أَمْ لَا ثُمَّ قَامَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ خَطِيبًا ثُمَّ ذَكَرَ نَحْوَ حَدِيثِ سُفْيَانَ","id":"Telah menceritakan kepada kami [Abu Bakar bin Abi Syaibah] dan ['Amru An Naqid] serta [Ibnu Abi Umar] sedangkan lafadznya dari Abu Bakar, mereka berkata; telah menceritakan kepada kami [Sufyan bin Uyainah] dari [Az Zuhri] dari ['Urwah] dari [Abu Humaid As Sa'idi] dia berkata, \"Rasulullah shallallahu 'alaihi wasallam memperkerjakan seorang laki-laki dari suku Al Asad bernama Ibnu Luthbiyah -Amru dan Ibnu Abu 'Umar berkata- untuk mengumpulkan harta sedekat (zakat). Ketika menyetorkan zakat yang dipungutnya, dia berkata, \"Zakat ini kuserahkan kepada anda, dan ini pemberian orang kepadaku.\" Abu Humaid berkata, \"Rasulullah shallallahu 'alaihi wasallam lalu berpidato di atas mimbar, setelah beliau memuji dan menyanjung Allah, beliau sampaikan: \"Ada seorang petugas yang aku tugaskan memungut zakat, dia berkata, 'Zakat ini yang kuberikan (setorkan) kepada anda, dan ini pemberian orang kepadaku.' Mengapa dia tidak duduk saja di rumah ibu bapaknya menunggu orang mengantarkan hadiah kepadanya? Demi Allah yang jiwa Muhammad berada di tangannya, tidak ada seorangpun di antara kalian yang menggelapkan zakat ketika ia ditugaskan untuk memungutnya, melainkan pada hari kiamat kelak dia akan memikul unta yang digelapkannya itu melenguh-lenguh di lehernya, atau sapi (lembu) yang melenguh, atau kambing yang mengembek-embek.\" Kemudian beliau mengangkat kedua tangannya sehingga kami melihat putih kedua ketiaknya, kemudian beliau bersabda: 'Ya Allah, telah aku sampaikan.' Beliau mengatakannya dua kali.\" Telah menceritakan kepada kami [Ishaq bin Ibrahim] dan [Abd bin Humaid] keduanya berkata; telah mengabarkan kepada kami [Abdurrazaq] telah menceritakan kepada kami [Ma'mar] dari [Az Zuhri] dari ['Urwah] dari [Abu Humaid As Sa'idi] dia berkata, \"Nabi shallallahu 'alaihi wasallam pernah mengangkat Ibnu Lutbiyah, yaitu seorang laki-laki dari Asd (menjadi seorang pegawai), untuk memungut zakat, kemudian dia datang kepada Nabi shallallahu 'alaihi wasallam dan menyerahkan zakat yang di pungutnya, lalu dia berkata, \"Ini adalah zakat yang aku setorkan kepada anda, dan ini adalah pemberian orang kepadaku.\" Kemudian beliau bersabda: \"Mengapa dia tidak duduk saja di rumah ibu bapaknya sambil menunggu apakah ada orang yang hendak mengantarkan hadiah kepadanya ataukah tidak.\" Setelah itu Nabi shallallahu 'alaihi wasallam berdiri berkhutbah.\" Kemudian dia menyebutkan hadits seperti Sufyan.\""},"3181":{"ar":"حَدَّثَنَا أَبُو كُرَيْبٍ مُحَمَّدُ بْنُ الْعَلَاءِ حَدَّثَنَا أَبُو أُسَامَةَ حَدَّثَنَا هِشَامٌ عَنْ أَبِيهِ عَنْ أَبِي حُمَيْدٍ السَّاعِدِيِّ قَالَاسْتَعْمَلَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ رَجُلًا مِنْ الْأَزْدِ عَلَى صَدَقَاتِ بَنِي سُلَيْمٍ يُدْعَى ابْنَ الْأُتْبِيَّةِ فَلَمَّا جَاءَ حَاسَبَهُ قَالَ هَذَا مَالُكُمْ وَهَذَا هَدِيَّةٌ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَهَلَّا جَلَسْتَ فِي بَيْتِ أَبِيكَ وَأُمِّكَ حَتَّى تَأْتِيَكَ هَدِيَّتُكَ إِنْ كُنْتَ صَادِقًا ثُمَّ خَطَبَنَا فَحَمِدَ اللَّهَ وَأَثْنَى عَلَيْهِ ثُمَّ قَالَ أَمَّا بَعْدُ فَإِنِّي أَسْتَعْمِلُ الرَّجُلَ مِنْكُمْ عَلَى الْعَمَلِ مِمَّا وَلَّانِي اللَّهُ فَيَأْتِي فَيَقُولُ هَذَا مَالُكُمْ وَهَذَا هَدِيَّةٌ أُهْدِيَتْ لِي أَفَلَا جَلَسَ فِي بَيْتِ أَبِيهِ وَأُمِّهِ حَتَّى تَأْتِيَهُ هَدِيَّتُهُ إِنْ كَانَ صَادِقًا وَاللَّهِ لَا يَأْخُذُ أَحَدٌ مِنْكُمْ مِنْهَا شَيْئًا بِغَيْرِ حَقِّهِ إِلَّا لَقِيَ اللَّهَ تَعَالَى يَحْمِلُهُ يَوْمَ الْقِيَامَةِ فَلَأَعْرِفَنَّ أَحَدًا مِنْكُمْ لَقِيَ اللَّهَ يَحْمِلُ بَعِيرًا لَهُ رُغَاءٌ أَوْ بَقَرَةً لَهَا خُوَارٌ أَوْ شَاةً تَيْعَرُ ثُمَّ رَفَعَ يَدَيْهِ حَتَّى رُئِيَ بَيَاضُ إِبْطَيْهِ ثُمَّ قَالَ اللَّهُمَّ هَلْ بَلَّغْتُ بَصُرَ عَيْنِي وَسَمِعَ أُذُنِيو حَدَّثَنَا أَبُو كُرَيْبٍ حَدَّثَنَا عَبْدَةُ وَابْنُ نُمَيْرٍ وَأَبُو مُعَاوِيَةَ ح و حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا عَبْدُ الرَّحِيمِ بْنُ سُلَيْمَانَ ح و حَدَّثَنَا ابْنُ أَبِي عُمَرَ حَدَّثَنَا سُفْيَانُ كُلُّهُمْ عَنْ هِشَامٍ بِهَذَا الْإِسْنَادِ وَفِي حَدِيثِ عَبْدَةَ وَابْنِ نُمَيْرٍ فَلَمَّا جَاءَ حَاسَبَهُ كَمَا قَالَ أَبُو أُسَامَةَ وَفِي حَدِيثِ ابْنِ نُمَيْرٍ تَعْلَمُنَّ وَاللَّهِ وَالَّذِي نَفْسِي بِيَدِهِ لَا يَأْخُذُ أَحَدُكُمْ مِنْهَا شَيْئًا وَزَادَ فِي حَدِيثِ سُفْيَانَ قَالَ بَصُرَ عَيْنِي وَسَمِعَ أُذُنَايَ وَسَلُوا زَيْدَ بْنَ ثَابِتٍ فَإِنَّهُ كَانَ حَاضِرًا مَعِي و حَدَّثَنَاه إِسْحَقُ بْنُ إِبْرَاهِيمَ أَخْبَرَنَا جَرِيرٌ عَنْ الشَّيْبَانِيِّ عَنْ عَبْدِ اللَّهِ بْنِ ذَكْوَانَ وَهُوَ أَبُو الزِّنَادِ عَنْ عُرْوَةَ بْنِ الزُّبَيْرِ عَنْ أَبِي حُمَيْدٍ السَّاعِدِيِّ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ اسْتَعْمَلَ رَجُلًا عَلَى الصَّدَقَةِ فَجَاءَ بِسَوَادٍ كَثِيرٍ فَجَعَلَ يَقُولُ هَذَا لَكُمْ وَهَذَا أُهْدِيَ إِلَيَّ فَذَكَرَ نَحْوَهُ قَالَ عُرْوَةُ فَقُلْتُ لِأَبِي حُمَيْدٍ السَّاعِدِيِّ أَسَمِعْتَهُ مِنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ مِنْ فِيهِ إِلَى أُذُنِي","id":"Telah menceritakan kepada kami [Abu Kuraib, Muhammad bin Al 'Ala'] telah menceritakan kepada kami [Abu Usamah] telah menceritakan kepada kami [Hisyam] dari [ayahnya] dari [Abu Humaid As Sa'idi] dia berkata, \"Rasulullah shallallahu 'alaihi wasallam pernah mengangkat seorang laki-laki dari Azd yang bernama Ibnu Al Atbiyah untuk memungut zakat Bani Sulaim, ketika sekretarisnya datang dia berkata, \"Ini adalah harta kalian sedangkan ini adalah hadiah untukku.\" Maka Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tidakkah kamu duduk-duduk saja di rumah ibu atau bapakmu sehingga datang orang yang memberi hadiah kepadamu, jika kamu benar demikian.\" Setelah itu beliau berkhutbah, setelah beliau memuji dan menyanjung Allah, beliau sampaikan: \"Amma ba'du. Sesungguhnya saya telah meemngangkat seseorang dari kalian sebagai pegawai untuk suatu pekerjaan yang Allah bebankan kepadaku, kemudian dia datang seraya berkata, 'Ini adalah hartamu, sedangkan yang ini adalah hadiah yang diberikan kepadaku, tidakkah dia duduk-duduk saja di rumah ayah atau ibunya menunggu sampai ada orang yang memberi hadiah kepadanya, jika dia orang yang benar. Demi Allah, tidaklah salah seorang dari kalian mengambil sesuatu darinta tanpa hak, kecuali ia akan bertemu Allah Ta'ala pada hari Kiamat dengan membawa (harta tersebut). Dan sungguh saya akan mengenal salah seorang dari kalian saat ia datang menemui Allah dengan membawa unta atau sapi yang melenguh-lenguh, atau kambing yang mengembek-embek.\" Setelah itu beliau mengangkat kedua tangannya hingga terlihat putih kedua ketiaknya, kemudian beliau mengucapkan: \"Ya Allah, telah saya sampaikan. Mataku telah melihatnya dan kedua telingaku telah mendengarnya.\" Dan telah menceritakan kepada kami [Abu Kuraib] telah menceritakan kepada kami ['Abdah] dan [Ibnu Numair] serta [Abu Mu'awiyah]. (dalam jalur lain disebutkan) Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] telah menceritakan kepada kami [Abdurrahim bin Sulaiman]. (dalam jalur lain disebutkan) Telah menceritakan kepada kami [Ibnu Abu 'Umar] telah menceritakan kepada kami [Sufyan] mereka semua dari [Hisyam] dengan isnad ini, dan dalam hadits 'Abdah dan Ibnu Numair disebutkan, 'Kemudian pencatatnya (sekretarisnya) datang, ' seperti yang disebutkan oleh Abu Usamah. Dan dalam hadits Ibnu Numair disebutkan, 'Sungguh kalian telah mengetahuinya, demi Allah yang jiwaku berada di tangan-Nya, tidaklah salah seorang dari kalian mengambil sesuatupun darinya …', dan dalam hadits Sufyan ditambahkan, 'Beliau bersabda: \"Mataku telah melihatnya dan kedua telingaku juga telah mendengarnya.\" Kemudian mereka bertanya kepada Zaid bin Tsabit yang saat itu dia menyaksikan peristiwa tersebut bersamaku.\" Dan telah menceritakan kepada kami [Ishaq bin Ibrahim] telah mengabarkan kepada kami [Jarir] dari [Asy Syaibani] dari [Abdullah bin Dzakwan] -yaitu Abu Az Zinnad- dari ['Urwah bin Zubair] dari [Abu Humaid As Sa'idi] bahwa Rasulullah shallallahu 'alaihi wasallam pernah mengangkat seorang laki-laki untuk memungut zakat, tidak lama kemudian dia datang dengan membawa hasil yang banyak, lalu dia berkata, 'Ini adalah harta anda sedangkan yang ini adalah hadiah untukku…kemudian dia menyebutkan hadits seperti itu.\" 'Urwah berkata, \"Lalu saya bertanya kepada Abu Humaid As Sa'idi, \"Apakah kamu mendengarnya dari Rasulullah shallallahu 'alaihi wasallam?\" dia menjawab, \"Dari mulut beliau ke kedua telingaku.\""},"3182":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا وَكِيعُ بْنُ الْجَرَّاحِ حَدَّثَنَا إِسْمَعِيلُ بْنُ أَبِي خَالِدٍ عَنْ قَيْسِ بْنِ أَبِي حَازِمٍ عَنْ عَدِيِّ بْنِ عَمِيرَةَ الْكِنْدِيِّ قَالَسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ مَنْ اسْتَعْمَلْنَاهُ مِنْكُمْ عَلَى عَمَلٍ فَكَتَمْنَا مِخْيَطًا فَمَا فَوْقَهُ كَانَ غُلُولًا يَأْتِي بِهِ يَوْمَ الْقِيَامَةِ قَالَ فَقَامَ إِلَيْهِ رَجُلٌ أَسْوَدُ مِنْ الْأَنْصَارِ كَأَنِّي أَنْظُرُ إِلَيْهِ فَقَالَ يَا رَسُولَ اللَّهِ اقْبَلْ عَنِّي عَمَلَكَ قَالَ وَمَا لَكَ قَالَ سَمِعْتُكَ تَقُولُ كَذَا وَكَذَا قَالَ وَأَنَا أَقُولُهُ الْآنَ مَنْ اسْتَعْمَلْنَاهُ مِنْكُمْ عَلَى عَمَلٍ فَلْيَجِئْ بِقَلِيلِهِ وَكَثِيرِهِ فَمَا أُوتِيَ مِنْهُ أَخَذَ وَمَا نُهِيَ عَنْهُ انْتَهَىو حَدَّثَنَاه مُحَمَّدُ بْنُ عَبْدِ اللَّهِ بْنِ نُمَيْرٍ حَدَّثَنَا أَبِي وَمُحَمَّدُ بْنُ بِشْرٍ ح و حَدَّثَنِي مُحَمَّدُ بْنُ رَافِعٍ حَدَّثَنَا أَبُو أُسَامَةَ قَالُوا حَدَّثَنَا إِسْمَعِيلُ بِهَذَا الْإِسْنَادِ بِمِثْلِهِ و حَدَّثَنَاه إِسْحَقُ بْنُ إِبْرَاهِيمَ الْحَنْظَلِيُّ أَخْبَرَنَا الْفَضْلُ بْنُ مُوسَى حَدَّثَنَا إِسْمَعِيلُ بْنُ أَبِي خَالِدٍ أَخْبَرَنَا قَيْسُ بْنُ أَبِي حَازِمٍ قَالَ سَمِعْتُ عَدِيَّ بْنَ عَمِيرَةَ الْكِنْدِيَّ يَقُولُ سَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ بِمِثْلِ حَدِيثِهِمْ","id":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] telah menceritakan kepada kami [Waki' bin Jarrah] telah menceritakan kepada kami [Isma'il bin Abi Khalid] dari [Qais bin Abu Hazim] dari ['Adi bin Amirah Al Kindi] dia berkata, \"Saya mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa dari kalian yang aku angkat atas suatu amal, kemudian dia menyembunyikan dari kami (meskipun) sebuah jarum, atau sesuatu yang lebih kecil dari itu, maka itu adalah ghulul (pencurian) yang pada hari kiamat akan ia bawa.\" 'Adi bin 'Amirah berkata, \"Kemudian seorang laki-laki hitam dari Anshar -sepertinya saya pernah melihatnya- berdiri sambil berkata, \"Wahai Rasulullah, kalau begitu saya akan tarik kembali tugas yang pernah anda bebankan kepada saya!\" Beliau balik bertanya: \"Ada apa denganmu?\" dia menjawab, \"Saya telah mendengar bahwa Anda pernah bersabda seperti ini dan seperti ini.\" Beliau bersabda: \"Sekarang saya sampaikan, bahwa barangsiapa dari kalian yang aku tugasi atas suatu amal hendaklah ia datang baik dengan sedikit atau banyaknya, apa yang memang diberikan untuknya ia boleh mengambilnya, dan apa yang memang dilarang untuknya, maka ia harus dapat menahan diri.\" Dan telah menceritakan kepada kami [Muhammad bin Abdullah bin Numair] telah menceritakan kepada kami [ayahku] dan [Muhammad bin Bisyr]. (dalam jalur lain disebutkan) Telah menceritakan kepadaku [Muhammad bin Rafi'] telah menceritakan kepada kami [Abu Usamah] mereka berkata; telah menceritakan kepada kami [Isma'il] dengan isnad seperti ini.\" Dan telah menceritakan kepada kami [Ishaq bin Ibrahim Al Handlali] telah mengabarkan kepada kami [Al Fadl bin Musa] telah menceritakan kepada kami [Isma'il bin Abu Khalid] telah mengabarkan kepada kami [Qais bin Abu Hazim] dia berkata, \"Saya pernah mendengar ['Adi bin 'Amirah Al Kindi] berkata, \"Saya mendengar Rasulullah shallallahu 'alaihi wasallam bersabda… seperti hadits mereka.\""},"3183":{"ar":"حَدَّثَنِي زُهَيْرُ بْنُ حَرْبٍ وَهَارُونُ بْنُ عَبْدِ اللَّهِ قَالَا حَدَّثَنَا حَجَّاحُ بْنُ مُحَمَّدٍ قَالَ قَالَ ابْنُ جُرَيْجٍنَزَلَ{ يَا أَيُّهَا الَّذِينَ آمَنُوا أَطِيعُوا اللَّهَ وَأَطِيعُوا الرَّسُولَ وَأُولِي الْأَمْرِ مِنْكُمْ }فِي عَبْدِ اللَّهِ بْنِ حُذَافَةَ بْنِ قَيْسِ بْنِ عَدِيٍّ السَّهْمِيِّ بَعَثَهُ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي سَرِيَّةٍأَخْبَرَنِيهِ يَعْلَى بْنُ مُسْلِمٍ عَنْ سَعِيدِ بْنِ جُبَيْرٍ عَنْ ابْنِ عَبَّاسٍ","id":"Telah menceritakan kepada kami [Zuhair bin Harb] dan [Harun bin Abdullah] keduanya berkata; telah menceritakan kepada kami [Hajjaj bin Muhahammad] dia berkata; [Ibnu Juraij] berkata (Ayat): '(Hai orang-orang yang beriman, ta'atilah Allah dan ta'atilah Rasul (Nya), dan ulil amri di antara kamu …) ' (Qs. An Nisaa': 59), turun berkenaan dengan Abdullah bin Hudzafah bin Qais bin 'Adiy As Sahmiy, ketika Nabi shallallahu 'alaihi wasallam mengutusnya dalam sebuah ekspedisi militer.\" [Ya'la bin Muslim] memberitahukan hadits ini kepadaku, dari [Sa'id bin Jubair] dari [Ibnu Abbas].\""},"3184":{"ar":"حَدَّثَنَا يَحْيَى بْنُ يَحْيَى أَخْبَرَنَا الْمُغِيرَةُ بْنُ عَبْدِ الرَّحْمَنِ الْحِزَامِيُّ عَنْ أَبِي الزِّنَادِ عَنْ الْأَعْرَجِ عَنْ أَبِي هُرَيْرَةَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ أَطَاعَنِي فَقَدْ أَطَاعَ اللَّهَ وَمَنْ يَعْصِنِي فَقَدْ عَصَى اللَّهَ وَمَنْ يُطِعْ الْأَمِيرَ فَقَدْ أَطَاعَنِي وَمَنْ يَعْصِ الْأَمِيرَ فَقَدْ عَصَانِيو حَدَّثَنِيهِ زُهَيْرُ بْنُ حَرْبٍ حَدَّثَنَا ابْنُ عُيَيْنَةَ عَنْ أَبِي الزِّنَادِ بِهَذَا الْإِسْنَادِ وَلَمْ يَذْكُرْ وَمَنْ يَعْصِ الْأَمِيرَ فَقَدْ عَصَانِي","id":"Telah menceritakan kepada kami [Yahya bin Yahya] telah mengabarkan kepada kami [Al Mughirah bin Abdurrahman Al Hizami] dari [Abu Az Zannad] dari [Al A'raj] dari [Abu Hurairah] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Barang siapa mentaatiku sungguh dia telah mentaati Allah, dan barangsiapa bermaksiat kepadaku maka dia telah bermaksiat kepada Allah. Barangsiapa metaati seorang pemimpin sungguh dia telah mentaatiku, dan siapa saja bermaksiat kepada seorang pemimpin maka dia telah bermaksiat kepadaku.\" Dan telah menceritakan kepadaku [Zuhair bin Harb] telah menceritakan kepada kami [Ibnu 'Uyainah] dari [Abu Az Zinad] dengan isnad ini, namun dia tidak menyebutkan, 'Barangsiapa bermaksiat kepada seorang pemimpin'.\""},"3185":{"ar":"و حَدَّثَنِي حَرْمَلَةُ بْنُ يَحْيَى أَخْبَرَنَا ابْنُ وَهْبٍ أَخْبَرَنِي يُونُسُ عَنْ ابْنِ شِهَابٍ أَخْبَرَهُ قَالَ حَدَّثَنَا أَبُو سَلَمَةَ بْنُ عَبْدِ الرَّحْمَنِ عَنْ أَبِي هُرَيْرَةَعَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهُ قَالَ مَنْ أَطَاعَنِي فَقَدْ أَطَاعَ اللَّهَ وَمَنْ عَصَانِي فَقَدْ عَصَى اللَّهَ وَمَنْ أَطَاعَ أَمِيرِي فَقَدْ أَطَاعَنِي وَمَنْ عَصَى أَمِيرِي فَقَدْ عَصَانِيو حَدَّثَنِي مُحَمَّدُ بْنُ حَاتِمٍ حَدَّثَنَا مَكِّيُّ بْنُ إِبْرَاهِيمَ حَدَّثَنَا ابْنُ جُرَيْجٍ عَنْ زِيَادٍ عَنْ ابْنِ شِهَابٍ أَنَّ أَبَا سَلَمَةَ بْنَ عَبْدِ الرَّحْمَنِ أَخْبَرَهُ أَنَّهُ سَمِعَ أَبَا هُرَيْرَةَ يَقُولُا قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِمِثْلِهِ سَوَاءً و حَدَّثَنِي أَبُو كَامِلٍ الْجَحْدَرِيُّ حَدَّثَنَا أَبُو عَوَانَةَ عَنْ يَعْلَى بْنِ عَطَاءٍ عَنْ أَبِي عَلْقَمَةَ قَالَ حَدَّثَنِي أَبُو هُرَيْرَةَ مِنْ فِيهِ إِلَى فِيَّ قَالَ سَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ح و حَدَّثَنِي عُبَيْدُ اللَّهِ بْنُ مُعَاذٍ حَدَّثَنَا أَبِي ح و حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ قَالَا حَدَّثَنَا شُعْبَةُ عَنْ يَعْلَى بْنِ عَطَاءٍ سَمِعَ أَبَا عَلْقَمَةَ سَمِعَ أَبَا هُرَيْرَةَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَحْوَ حَدِيثِهِمْ و حَدَّثَنَا مُحَمَّدُ بْنُ رَافِعٍ حَدَّثَنَا عَبْدُ الرَّزَّاقِ حَدَّثَنَا مَعْمَرٌ عَنْ هَمَّامِ بْنِ مُنَبِّهٍ عَنْ أَبِي هُرَيْرَةَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِمِثْلِ حَدِيثِهِمْ و حَدَّثَنِي أَبُو الطَّاهِرِ أَخْبَرَنَا ابْنُ وَهْبٍ عَنْ حَيْوَةَ أَنَّ أَبَا يُونُسَ مَوْلَى أَبِي هُرَيْرَةَ حَدَّثَهُ قَالَ سَمِعْتُ أَبَا هُرَيْرَةَ يَقُولُا عَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِذَلِكَ وَقَالَ مَنْ أَطَاعَ الْأَمِيرَ وَلَمْ يَقُلْ أَمِيرِي وَكَذَلِكَ فِي حَدِيثِ هَمَّامٍ عَنْ أَبِي هُرَيْرَةَ","id":"Dan telah menceritakan kepadaku [Harmalah bin Yahya] telah mengabarkan kepada kami [Ibnu Wahb] telah mengabarkan kepadaku [Yunus] dari [Ibnu Syihab] telah mengabarkan kepadanya, ia berkata; telah menceritakan kepada kami [Abu Salamah bin Abdurrahman] dari [Abu Hurairah] dari Rasulullah shallallahu 'alaihi wasallam, bahwa beliau bersabda: \"Barangsiapa mentaatiku sungguh dia telah mentaati Allah, barangsiapa bermaksiat kepadaku maka dia telah bermaksiat kepada Allah. Dan barangsiapa mentaati pemimpinku sungguh dia telah mentaatiku, barangsiapa bermaksiat kepada pemimpinku maka dia telah bermaksiat kepadaku.\" Dan telah menceritakan kepadaku [Muhammad bin Hatim] telah menceritakan kepada kami [Makki bin Ibrahim] telah menceritakan kepada kami [Ibnu Juraij] dari [Ziyad] dari [Ibnu Syihab] bahwa [Abu Salamah bin Abdurrahman] telah mengabarkan kepadanya, bahwa dia pernah mendengar [Abu Hurairah] berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda seperti hadits di atas.\" Dan telah menceritakan kepadaku [Abu Kamil Al Jahdari] telah menceritakan kepada kami [Abu 'Awanah] dari [Ya'la bin 'Atha'] dari [Abu 'Alqamah] dia berkata, telah menceritakan kepadaku, dari mulutnya ke mulutku (secara lisan), dia berkata, \"Saya mendengar Rasulullah shallallahu 'alaihi wasallam…\" (dalam jalur lain disebutkan) Telah menceritakan kepadaku ['Ubaidullah bin Mu'adz] telah menceritakan kepada kami [ayahku]. (dalam jalur lain disebutkan) Telah menceritakan kepada kami [Muhammad bin Basysyar] telah menceritakan kepada kami [Muhammad bin Ja'far] dia berkata, telah menceritakan kepada kami [Syu'bah] dari [Ya'la bin 'Atha] bahwa dia pernah mendengar [Abu 'Alqamah] mendengar dari [Abu Hurairah] dari Nabi shallallahu 'alaihi wasallam seperti hadits mereka.\" Dan telah menceritakan kepada kami [Muhammad bin Rafi'] telah menceritakan kepada kami [Abdur Razaq] telah menceritakan kepada kami [Ma'mar] dari [Hammam bin Munabbih] dari [Abu Hurairah] dari Nabi shallallahu 'alaihi wasallam seperti hadits mereka.\" Dan telah menceritakan kepadaku [Abu At Thahir] telah mengabarkan kepada kami [Ibnu Wahb] dari [Haiwah] bahwa [Abu Yunus] budak Abu Hurairah, telah bercerita kepadanya, dia berkata; saya pernah mendengar [Abu Hurairah] berkata, dari Rasulullah shallallahu 'alaihi wasallam seperti itu. Beliau bersabda: 'Barangsiapa mentaati seorang pemimpin…', tidak mengatakan, 'Barangsiapa mentaati kepemimpinanku'. begitu juga dalam hadits riwayat Hammam dari Abu Hurairah.\""},"3186":{"ar":"و حَدَّثَنَا سَعِيدُ بْنُ مَنْصُورٍ وَقُتَيْبَةُ بْنُ سَعِيدٍ كِلَاهُمَا عَنْ يَعْقُوبَ قَالَ سَعِيدٌ حَدَّثَنَا يَعْقُوبُ بْنُ عَبْدِ الرَّحْمَنِ عَنْ أَبِي حَازِمٍ عَنْ أَبِي صَالِحٍ السَّمَّانِ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَلَيْكَ السَّمْعَ وَالطَّاعَةَ فِي عُسْرِكَ وَيُسْرِكَ وَمَنْشَطِكَ وَمَكْرَهِكَ وَأَثَرَةٍ عَلَيْكَ","id":"Dan telah menceritakan kepada kami [Sa'id bin Manshur] dan [Qutaibah bin Sa'id] keduanya dari [Ya'qub], [Sa'id] mengatakan; telah menceritakan kepada kami [Ya'qub bin Abdurrahman] dari [Abu Hazim] dari [Abu Shalih As Samman] dari [Abu Hurairah] dia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Wajib bagi kalian untuk mendengar dan taat baik dalam keadaan susah maupun senang, dalam perkara yang disukai dan dibenci dan biarpun merugikan kepentinganmu.\""},"3187":{"ar":"و حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ وَعَبْدُ اللَّهِ بْنُ بَرَّادٍ الْأَشْعَرِيُّ وَأَبُو كُرَيْبٍ قَالُوا حَدَّثَنَا ابْنُ إِدْرِيسَ عَنْ شُعْبَةَ عَنْ أَبِي عِمْرَانَ عَنْ عَبْدِ اللَّهِ بْنِ الصَّامِتِ عَنْ أَبِي ذَرٍّ قَالَإِنَّ خَلِيلِي أَوْصَانِي أَنْ أَسْمَعَ وَأُطِيعَ وَإِنْ كَانَ عَبْدًا مُجَدَّعَ الْأَطْرَافِو حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ ح و حَدَّثَنَا إِسْحَقُ أَخْبَرَنَا النَّضْرُ بْنُ شُمَيْلٍ جَمِيعًا عَنْ شُعْبَةَ عَنْ أَبِي عِمْرَانَ بِهَذَا الْإِسْنَادِ وَقَالَا فِي الْحَدِيثِ عَبْدًا حَبَشِيًّا مُجَدَّعَ الْأَطْرَافِ و حَدَّثَنَاه عُبَيْدُ اللَّهِ بْنُ مُعَاذٍ حَدَّثَنَا أَبِي حَدَّثَنَا شُعْبَةُ عَنْ أَبِي عِمْرَانَ بِهَذَا الْإِسْنَادِ كَمَا قَالَ ابْنُ إِدْرِيسَ عَبْدًا مُجَدَّعَ الْأَطْرَافِ","id":"Telah menceritakan kepada kami [Abu Bakar bin Abi Syaibah] dan [Abdullah bin Barrad Al Asy'ari] dan [Abu Kuraib] mereka berkata; telah menceritakan kepada kami [Ibnu Idris] dari [Syu'bah] dari [Abu Imran] dari [Abdullah bin Shamit] dari [Abu Dzar] dia berkata, \"Sesungguhnya kekasihku (Rasulullah) berwasiat kepadaku untuk selalu mendengar dan taat walaupun terhadap budak yang pesek hidungnya.\" Dan telah menceritakan kepada kami [Muhammad bin Basyar] telah menceritakan kepada kami [Muhammad bin Ja'far]. (dalam jalur lain disebutkan) Telah menceritakan kepada kami [Ishaq] telah mengabarkan kepada kami [An Nadlr bin Syumail] mereka semua dari [Syu'bah] dari [Abu 'Imran] dengan isnad ini, dan dia menyebutkan dalam haditsnya, \"Seorang budak Habsyi yang berhidung pesek.\" Dan telah menceritakan kepada kami ['Ubaidullah bin Mu'adz] telah menceritakan kepada kami [ayahku] telah menceritakan kepada kami [Syu'bah] dari [Abu 'Imran] dengan isnad ini, sebagaimana perkataan Ibnu Idris, yaitu, \"Seorang budak yang berhidung pesek.\""},"3188":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ الْمُثَنَّى حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ حَدَّثَنَا شُعْبَةُ عَنْ يَحْيَى بْنِ حُصَيْنٍ قَالَ سَمِعْتُ جَدَّتِي تُحَدِّثُأَنَّهَا سَمِعَتْ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَخْطُبُ فِي حَجَّةِ الْوَدَاعِ وَهُوَ يَقُولُ وَلَوْ اسْتُعْمِلَ عَلَيْكُمْ عَبْدٌ يَقُودُكُمْ بِكِتَابِ اللَّهِ فَاسْمَعُوا لَهُ وَأَطِيعُواو حَدَّثَنَاه ابْنُ بَشَّارٍ حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ وَعَبْدُ الرَّحْمَنِ بْنُ مَهْدِيٍّ عَنْ شُعْبَةَ بِهَذَا الْإِسْنَادِ وَقَالَ عَبْدًا حَبَشِيًّا و حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا وَكِيعُ بْنُ الْجَرَّاحِ عَنْ شُعْبَةَ بِهَذَا الْإِسْنَادِ وَقَالَ عَبْدًا حَبَشِيًّا مُجَدَّعًا و حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ بِشْرٍ حَدَّثَنَا بَهْزٌ حَدَّثَنَا شُعْبَةُ بِهَذَا الْإِسْنَادِ وَلَمْ يَذْكُرْ حَبَشِيًّا مُجَدَّعًا وَزَادَ أَنَّهَا سَمِعَتْ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِمِنًى أَوْ بِعَرَفَاتٍ","id":"Telah menceritakan kepada kami [Muhammad bin Mutsanna] telah menceritakan kepada kami [Muhammad bin Ja'far] telah menceritakan kepada kami [Syu'bah] dari [Yahya bin Hushain] dia berkata, saya mendengar [nenekku] menceritakan bahwa dia mendengar Nabi shallallahu 'alaihi wasallam berkhutbah ketika haji wada', beliau bersabda: \"Seandainya kalian dipimpin oleh seorang budak yang memimpinmu dengan kitabullah, maka dengarkanlah dan ta'atilah dia.\" Dan telah menceritakan kepada kami [Ibnu Basyar] telah menceritakan kepada kami [Muhammad bin Ja'far] dan [Abdurrahman bin Mahdi] dari [Syu'bah] dengan isnad seperti ini, dan beliau bersabda: \"Seorang budak Habsyi.\" Dan telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] telah menceritakan kepada kami [Waki' bin Jarrah] dari [Syu'bah] dengan isnad ini, namun dia tidak menyebutkan, \"Seorang budak Habsyi yang berhidung pesek.\" Dan telah menceritakan kepada kami [Abdurrahman bin Bisyr] telah menceritakan kepada kami [Bahz] telah menceritakan kepada kami [Syu'bah] dengan sanad ini, namun tidak menyebutkan: \"…Orang Habsyi yang berhidung pesek.\" dia menambahkan, bahwa neneknya mendengar Rasulullah shallallahu 'alaihi wasallam ketika di Mina atau di 'Arafah.\""},"3189":{"ar":"حَدَّثَنَا قُتَيْبَةُ بْنُ سَعِيدٍ حَدَّثَنَا لَيْثٌ عَنْ عُبَيْدِ اللَّهِ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهُ قَالَ عَلَى الْمَرْءِ الْمُسْلِمِ السَّمْعُ وَالطَّاعَةُ فِيمَا أَحَبَّ وَكَرِهَ إِلَّا أَنْ يُؤْمَرَ بِمَعْصِيَةٍ فَإِنْ أُمِرَ بِمَعْصِيَةٍ فَلَا سَمْعَ وَلَا طَاعَةَو حَدَّثَنَاه زُهَيْرُ بْنُ حَرْبٍ وَمُحَمَّدُ بْنُ الْمُثَنَّى قَالَا حَدَّثَنَا يَحْيَى وَهُوَ الْقَطَّانُ ح و حَدَّثَنَا ابْنُ نُمَيْرٍ حَدَّثَنَا أَبِي كِلَاهُمَا عَنْ عُبَيْدِ اللَّهِ بِهَذَا الْإِسْنَادِ مِثْلَهُ","id":"Telah menceritakan kepada kami [Qutaibah bin Sa'id] telah menceritakan kepada kami [Laits] dari ['Ubaidullah] dari [Nafi'] dari [Ibnu Umar] dari Nabi shallallahu 'alaihi wasallam, bahwa beliau bersabda: \"Wajib setiap orang untuk mendengar dan taat, baik terhadap sesuatu yang dia suka atau benci, kecuali jika dia diperintahkan untuk bermaksiat, maka tidak ada kewajiban baginya untuk mendengar dan taat.\" Dan telah menceritakan kepada kami [Zuhair bin Harb] dan [Muhammad bin Al Mutsanna] keduanya berkata; telah menceritakan kepada kami [Yahya] -yaitu Al Qatthan-. (dalam jalur lain disebutkan) Telah menceritakan kepada kami [Ibnu Numair] telah menceritakan kepada kami [ayahku] keduanya dari ['Ubaidullah] dengan isnad seperti ini.\""},"3190":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ الْمُثَنَّى وَابْنُ بَشَّارٍ وَاللَّفْظُ لِابْنِ الْمُثَنَّى قَالَا حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ حَدَّثَنَا شُعْبَةُ عَنْ زُبَيْدٍ عَنْ سَعْدِ بْنِ عُبَيْدَةَ عَنْ أَبِي عَبْدِ الرَّحْمَنِ عَنْ عَلِيٍّأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بَعَثَ جَيْشًا وَأَمَّرَ عَلَيْهِمْ رَجُلًا فَأَوْقَدَ نَارًا وَقَالَ ادْخُلُوهَا فَأَرَادَ نَاسٌ أَنْ يَدْخُلُوهَا وَقَالَ الْآخَرُونَ إِنَّا قَدْ فَرَرْنَا مِنْهَا فَذُكِرَ ذَلِكَ لِرَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ لِلَّذِينَ أَرَادُوا أَنْ يَدْخُلُوهَا لَوْ دَخَلْتُمُوهَا لَمْ تَزَالُوا فِيهَا إِلَى يَوْمِ الْقِيَامَةِ وَقَالَ لِلْآخَرِينَ قَوْلًا حَسَنًا وَقَالَ لَا طَاعَةَ فِي مَعْصِيَةِ اللَّهِ إِنَّمَا الطَّاعَةُ فِي الْمَعْرُوفِ","id":"Telah menceritakan kepada kami [Muhammad bin Mutsanna] dan [Ibnu Basyar] sedangkan lafadznya dari Ibnu Mutsanna, keduanya berkata; telah menceritakan kepada kami [Muhammad bin Ja'far] telah menceritakan kepada kami [Syu'bah] dari [Zubaid] dari [Sa'd bin 'Ubaidah] dari [Abu Abdurrahman] dari [Ali], bahwa Rasulullah shallallahu 'alaihi wasallam pernah mengirim suatu pasukan dan mengangkat seorang laki-laki menjadi komandannya. Kemudian ia menyalakan api (unggun) seraya berkata, \"Masuklah kalian ke dalam api tersebut.\" Maka sebagian anak buahnya hendak masuk ke dalam api tersebut, sedangkan sebagian anak buahnya yang lain mengatakan, \"Kita harus menjauhi api tersebut.\" Kemudian peristiwa tersebut dilaporkan kepada Rasulullah shallallahu 'alaihi wasallam, lantas beliau bersabda kepada orang-orang yang hendak melompat ke dalam api tersebut: \"Sekiranya kalian masuk ke dalam api tersebut, maka kalian akan senantiasa di dalamnya hingga hari Kiamat.\" Kemudian beliau berkata pula kepada yang lain dengan lemah lembut, sabdanya: \"Tidak ada ketaatan dalam kemaksiatan kepada Allah, hanyasanya ketaatan itu di dalam kebajikan.\""},"3191":{"ar":"و حَدَّثَنَا مُحَمَّدُ بْنُ عَبْدِ اللَّهِ بْنِ نُمَيْرٍ وَزُهَيْرُ بْنُ حَرْبٍ وَأَبُو سَعِيدٍ الْأَشَجُّ وَتَقَارَبُوا فِي اللَّفْظِ قَالُوا حَدَّثَنَا وَكِيعٌ حَدَّثَنَا الْأَعْمَشُ عَنْ سَعْدِ بْنِ عُبَيْدَةَ عَنْ أَبِي عَبْدِ الرَّحْمَنِ عَنْ عَلِيٍّ قَالَبَعَثَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ سَرِيَّةً وَاسْتَعْمَلَ عَلَيْهِمْ رَجُلًا مِنْ الْأَنْصَارِ وَأَمَرَهُمْ أَنْ يَسْمَعُوا لَهُ وَيُطِيعُوا فَأَغْضَبُوهُ فِي شَيْءٍ فَقَالَ اجْمَعُوا لِي حَطَبًا فَجَمَعُوا لَهُ ثُمَّ قَالَ أَوْقِدُوا نَارًا فَأَوْقَدُوا ثُمَّ قَالَ أَلَمْ يَأْمُرْكُمْ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنْ تَسْمَعُوا لِي وَتُطِيعُوا قَالُوا بَلَى قَالَ فَادْخُلُوهَا قَالَ فَنَظَرَ بَعْضُهُمْ إِلَى بَعْضٍ فَقَالُوا إِنَّمَا فَرَرْنَا إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِنْ النَّارِ فَكَانُوا كَذَلِكَ وَسَكَنَ غَضَبُهُ وَطُفِئَتِ النَّارُ فَلَمَّا رَجَعُوا ذَكَرُوا ذَلِكَ لِلنَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ لَوْ دَخَلُوهَا مَا خَرَجُوا مِنْهَا إِنَّمَا الطَّاعَةُ فِي الْمَعْرُوفِو حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا وَكِيعٌ وَأَبُو مُعَاوِيَةَ عَنْ الْأَعْمَشِ بِهَذَا الْإِسْنَادِ نَحْوَهُ","id":"Dan telah menceritakan kepada kami [Muhammad bin Abdullah bin Numair] dan [Zuhair bin Harb] dan [Abu Sa'id Al Asyaj] sedangkan lafadznya saling berdekatan, mereka berkata; telah menceritakan kepada kami [Waki'] telah menceritakan kepada kami [Al A'masy] dari [Sa'd bin 'Ubaidah] dari [Abu Abdurrahman] dari ['Ali] dia berkata, \"Rasulullah shallallahu 'alaihi wasallam pernah mengutus suatu ekspedisi dan mengangkat seorang laki-laki dari Anshar sebagai pemimpinnya, mereka diperintahkan untuk taat dan mendengar kepadanya, suatu ketikan pemimpinnya marah terhadap anak buahnya karena suatu perkara, dia berkata, \"Kumpulkanlah kayu bakar.\" Setelah kayu bakar terkumpul dia berkata, \"Bukankah Rasulullah shallallahu 'alaihi wasallam telah memerintahkan kepada kalian untuk mendengarkanku dan mentaatiku?\" mereka menjawab, \"Ya.\" Dia berkata, \"Oleh karena itu, masuklah kalian ke dalam api tersebut.\" Ali berkata, \"Lalu sebagian yang lain saling memandang kepada yang lainnya, sambil berkata, \"Kita harus lari kepada Rasulullah shallallahu 'alaihi wasallam dari api tersebut.\" Anak buahnya masih saja (dalam kebimbangan) seperti itu, hingga kemarahannya mereda dan api dimatikan. Ketika mereka kembali, mereka memberitahukan peristiwa itu kepada Nabi shallallahu 'alaihi wasallam, lalu beliau bersabda: \"Sekiranya kalian masuk ke dalamnya, niscaya kalian tidak akan dapat keluar dari api tersebut, ketaatan itu hanya dalam kebajikan.\" Dan telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] telah menceritakan kepada kami [Waki'] dan [Abu Mu'awiyah] dari [Al A'masy] dengan isnad seperti ini.\""},"3192":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ عَبْدِ الرَّحْمَنِ بْنِ وَهْبِ بْنِ مُسْلِمٍ حَدَّثَنَا عَمِّي عَبْدُ اللَّهِ بْنُ وَهْبٍ حَدَّثَنَا عَمْرُو بْنُ الْحَارِثِ حَدَّثَنِي بُكَيْرٌ عَنْ بُسْرِ بْنِ سَعِيدٍ عَنْ جُنَادَةَ بْنِ أَبِي أُمَيَّةَ قَالَدَخَلْنَا عَلَى عُبَادَةَ بْنِ الصَّامِتِ وَهُوَ مَرِيضٌ فَقُلْنَا حَدِّثْنَا أَصْلَحَكَ اللَّهُ بِحَدِيثٍ يَنْفَعُ اللَّهُ بِهِ سَمِعْتَهُ مِنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ دَعَانَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَبَايَعْنَاهُ فَكَانَ فِيمَا أَخَذَ عَلَيْنَا أَنْ بَايَعَنَا عَلَى السَّمْعِ وَالطَّاعَةِ فِي مَنْشَطِنَا وَمَكْرَهِنَا وَعُسْرِنَا وَيُسْرِنَا وَأَثَرَةٍ عَلَيْنَا وَأَنْ لَا نُنَازِعَ الْأَمْرَ أَهْلَهُ قَالَ إِلَّا أَنْ تَرَوْا كُفْرًا بَوَاحًا عِنْدَكُمْ مِنْ اللَّهِ فِيهِ بُرْهَانٌ","id":"Telah menceritakan kepada kami [Ahmad bin Abdurrahman bin Wahb bin Muslim] telah menceritakan kepada kami pamanku [Abdullah bin Wahb] telah menceritakan kepada kami [Amru bin Al Harits] telah menceritakan kepadaku [Bukair] dari [Busr bin Sa'id] dari [Junadah bin Abu Umayyah] dia berkata, \"Kami pernah menjenguk ['Ubadah bin Shamit] yang sedang sakit, kami lalu berkata, \"Semoga Allah memperbaiki keadaanmu, ceritakanlah kepadaku suatu hadits yang kamu dengar dari Rasulullah shallallahu 'alaihi wasallam.\" Dia menjawab, \"Rasulullah shallallahu 'alaihi wasallam pernah memanggil kami, lantas kami membai'at beliau. Dan di antara yang kami ambil janji adalah, berbai'at untuk selalu taat dan mendengar baik dalam keadaan lapang atau terpaksa, mementingkan kepentingannya dari pada kepentingan diri sendiri, dan tidak memberontak pemerintahan yang berwenang.\" Beliau bersabda: \"Kecuali jika kalian melihat ia telah melakukan kekufuran yang jelas, dan kalian memiliki hujjah di sisi Allah.\""},"3193":{"ar":"حَدَّثَنَا إِبْرَاهِيمُ عَنْ مُسْلِمٍ حَدَّثَنِى زُهَيْرُ بْنُ حَرْبٍ حَدَّثَنَا شَبَابَةُ حَدَّثَنِي وَرْقَاءُ عَنْ أَبِي الزِّنَادِ عَنْ الْأَعْرَجِ عَنْ أَبِي هُرَيْرَةَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِنَّمَا الْإِمَامُ جُنَّةٌ يُقَاتَلُ مِنْ وَرَائِهِ وَيُتَّقَى بِهِ فَإِنْ أَمَرَ بِتَقْوَى اللَّهِ عَزَّ وَجَلَّ وَعَدَلَ كَانَ لَهُ بِذَلِكَ أَجْرٌ وَإِنْ يَأْمُرْ بِغَيْرِهِ كَانَ عَلَيْهِ مِنْهُ","id":"Telah menceritakan kepada kami Ibrahim dari Muslim telah menceritakan kepadaku [Zuhair bin Harb] telah menceritakan kepada kami [Syababah] telah menceritakan kepadaku [Warqa`] dari [Abu Az Zinad] dari [Al A'raj] dari [Abu Hurairah] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Seorang imam itu ibarat perisai, seseorang berperang di belakangnya (mendukung) dan berlindung (dari musuh) dengan (kekuasaan) nya. Jika seorang imam (pemimpin) memerintahkan supaya takwa kepada Allah 'azza wajalla dan berlaku adil, maka dia (imam) akan mendapatkan pahala karenanya, dan jika dia (imam) memerintahkan selain itu, maka ia akan mendapatkan siksa.\""},"3194":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ حَدَّثَنَا شُعْبَةُ عَنْ فُرَاتٍ الْقَزَّازِ عَنْ أَبِي حَازِمٍ قَالَقَاعَدْتُ أَبَا هُرَيْرَةَ خَمْسَ سِنِينَ فَسَمِعْتُهُ يُحَدِّثُ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ كَانَتْ بَنُو إِسْرَائِيلَ تَسُوسُهُمْ الْأَنْبِيَاءُ كُلَّمَا هَلَكَ نَبِيٌّ خَلَفَهُ نَبِيٌّ وَإِنَّهُ لَا نَبِيَّ بَعْدِي وَسَتَكُونُ خُلَفَاءُ تَكْثُرُ قَالُوا فَمَا تَأْمُرُنَا قَالَ فُوا بِبَيْعَةِ الْأَوَّلِ فَالْأَوَّلِ وَأَعْطُوهُمْ حَقَّهُمْ فَإِنَّ اللَّهَ سَائِلُهُمْ عَمَّا اسْتَرْعَاهُمْحَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ وَعَبْدُ اللَّهِ بْنُ بَرَّادٍ الْأَشْعَرِيُّ قَالَا حَدَّثَنَا عَبْدُ اللَّهِ بْنُ إِدْرِيسَ عَنْ الْحَسَنِ بْنِ فُرَاتٍ عَنْ أَبِيهِ بِهَذَا الْإِسْنَادِ مِثْلَهُ","id":"Telah menceritakan kepada kami [Muhammad bin Basyar] telah menceritakan kepada kami [Muhammad bin Ja'far] telah menceritakan kepada kami [Syu'bah] dari [Furat Al Qazzaz] dari [Abu Hazim] dia berkata, \"Saya pernah duduk (menjadi murid) [Abu Hurairah] selama lima tahun, saya pernah mendengar dia menceritakan dari Rasulullah shallallahu 'alaihi wasallam, beliau bersabda: \"Dahulu Bani Israil selalu dipimpin oleh para Nabi, setiap Nabi meninggal maka akan digantikan oleh Nabi yang lain sesudahnya. Dan sungguh, tidak akan ada Nabi lagi setelahku, namun yang ada adalah para khalifah (kepala pemerintahan) yang merekan akan banyak berbuat dosa.\" Para sahabat bertanya, \"Apa yang anda perintahkan untuk kami jika itu terjadi?\" beliau menjawab: \"Tepatilah baiat yang pertama, kemudian yang sesudah itu. Dan penuhilah hak mereka, kerana Allah akan meminta pertanggung jawaban mereka tentang pemerintahan mereka.\" Dan telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] dan [Abdullah bin Barrad Al Asy'ari] keduanya berkata; telah menceritakan kepada kami [Abdullah bin Idris] dari [Al Hasan bin Furrat] dari [ayahnya] dengan isnad seperti ini.\""},"3195":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا أَبُو الْأَحْوَصِ وَوَكِيعٌ ح و حَدَّثَنِي أَبُو سَعِيدٍ الْأَشَجُّ حَدَّثَنَا وَكِيعٌ ح و حَدَّثَنَا أَبُو كُرَيْبٍ وَابْنُ نُمَيْرٍ قَالَا حَدَّثَنَا أَبُو مُعَاوِيَةَ ح و حَدَّثَنَا إِسْحَقُ بْنُ إِبْرَاهِيمَ وَعَلِيُّ بْنُ خَشْرَمٍ قَالَا أَخْبَرَنَا عِيسَى بْنُ يُونُسَ كُلُّهُمْ عَنْ الْأَعْمَشِ ح و حَدَّثَنَا عُثْمَانُ بْنُ أَبِي شَيْبَةَ وَاللَّفْظُ لَهُ حَدَّثَنَا جَرِيرٌ عَنْ الْأَعْمَشِ عَنْ زَيْدِ بْنِ وَهْبٍ عَنْ عَبْدِ اللَّهِ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّهَا سَتَكُونُ بَعْدِي أَثَرَةٌ وَأُمُورٌ تُنْكِرُونَهَا قَالُوا يَا رَسُولَ اللَّهِ كَيْفَ تَأْمُرُ مَنْ أَدْرَكَ مِنَّا ذَلِكَ قَالَ تُؤَدُّونَ الْحَقَّ الَّذِي عَلَيْكُمْ وَتَسْأَلُونَ اللَّهَ الَّذِي لَكُمْ","id":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] telah menceritakan kepada kami [Abu Al Ahwash] dan [Waki']. (dalam jalur lain disebutkan) Telah menceritakan kepadaku [Abu Sa'id Al Asyaj] telah menceritakan kepada kami [Waki']. (dalam jalur lain disebutkan) Telah menceritakan kepada kami [Abu Kuraib] dan [Ibnu Numair] keduanya berkata; telah menceritakan kepada kami [Abu Mu'awiyah]. (dalam jalur lain disebutkan) Telah menceritakan kepada kami [Ishaq bin Ibrahim] dan [Ali bin Khasyram] keduanya berkata; telah menceritakan kepada kami [Isa bin Yunus] semuanya dari [Al A'masy]. (dalam jalur lain disebutkan) Telah menceritakan kepada kami [Utsman bin Abu Syaibah] sedangkan lafadznya dari dia, telah menceritakan kepada kami [Jarir] dari [Al A'masy] dari [Zaid bin Wahb] dari [Abdullah] dia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sungguh, sepeninggalku akan ada penguasa-penguasa negara yang mementingkan diri sendiri dan membuat kebijaksanaan-kebjiksanaan yang tidak kalian sukai.\" Para sahabat bertanya, \"Wahai Rasulullah, lantas apa yang anda perintahkan kepada kami ketika mengalami peristiwa tersebut?\" beliau menjawab: \"Tunaikanlah kewajiban kalian dan mintalah hak kalian kepada Allah.\""},"3196":{"ar":"حَدَّثَنَا زُهَيْرُ بْنُ حَرْبٍ وَإِسْحَقُ بْنُ إِبْرَاهِيمَ قَالَ إِسْحَقُ أَخْبَرَنَا و قَالَ زُهَيْرٌ حَدَّثَنَا جَرِيرٌ عَنْ الْأَعْمَشِ عَنْ زَيْدِ بْنِ وَهْبٍ عَنْ عَبْدِ الرَّحْمَنِ بْنِ عَبْدِ رَبِّ الْكَعْبَةِ قَالَ دَخَلْتُ الْمَسْجِدَ فَإِذَا عَبْدُ اللَّهِ بْنُ عَمْرِو بْنِ الْعَاصِ جَالِسٌ فِي ظِلِّ الْكَعْبَةِ وَالنَّاسُ مُجْتَمِعُونَ عَلَيْهِ فَأَتَيْتُهُمْ فَجَلَسْتُ إِلَيْهِ فَقَالَكُنَّا مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي سَفَرٍ فَنَزَلْنَا مَنْزِلًا فَمِنَّا مَنْ يُصْلِحُ خِبَاءَهُ وَمِنَّا مَنْ يَنْتَضِلُ وَمِنَّا مَنْ هُوَ فِي جَشَرِهِ إِذْ نَادَى مُنَادِي رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الصَّلَاةَ جَامِعَةً فَاجْتَمَعْنَا إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ إِنَّهُ لَمْ يَكُنْ نَبِيٌّ قَبْلِي إِلَّا كَانَ حَقًّا عَلَيْهِ أَنْ يَدُلَّ أُمَّتَهُ عَلَى خَيْرِ مَا يَعْلَمُهُ لَهُمْ وَيُنْذِرَهُمْ شَرَّ مَا يَعْلَمُهُ لَهُمْ وَإِنَّ أُمَّتَكُمْ هَذِهِ جُعِلَ عَافِيَتُهَا فِي أَوَّلِهَا وَسَيُصِيبُ آخِرَهَا بَلَاءٌ وَأُمُورٌ تُنْكِرُونَهَا وَتَجِيءُ فِتْنَةٌ فَيُرَقِّقُ بَعْضُهَا بَعْضًا وَتَجِيءُ الْفِتْنَةُ فَيَقُولُ الْمُؤْمِنُ هَذِهِ مُهْلِكَتِي ثُمَّ تَنْكَشِفُ وَتَجِيءُ الْفِتْنَةُ فَيَقُولُ الْمُؤْمِنُ هَذِهِ هَذِهِ فَمَنْ أَحَبَّ أَنْ يُزَحْزَحَ عَنْ النَّارِ وَيُدْخَلَ الْجَنَّةَ فَلْتَأْتِهِ مَنِيَّتُهُ وَهُوَ يُؤْمِنُ بِاللَّهِ وَالْيَوْمِ الْآخِرِ وَلْيَأْتِ إِلَى النَّاسِ الَّذِي يُحِبُّ أَنْ يُؤْتَى إِلَيْهِ وَمَنْ بَايَعَ إِمَامًا فَأَعْطَاهُ صَفْقَةَ يَدِهِ وَثَمَرَةَ قَلْبِهِ فَلْيُطِعْهُ إِنْ اسْتَطَاعَ فَإِنْ جَاءَ آخَرُ يُنَازِعُهُ فَاضْرِبُوا عُنُقَ الْآخَرِفَدَنَوْتُ مِنْهُ فَقُلْتُ لَهُ أَنْشُدُكَ اللَّهَ آنْتَ سَمِعْتَ هَذَا مِنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَهْوَى إِلَى أُذُنَيْهِ وَقَلْبِهِ بِيَدَيْهِ وَقَالَ سَمِعَتْهُ أُذُنَايَ وَوَعَاهُ قَلْبِي فَقُلْتُ لَهُ هَذَا ابْنُ عَمِّكَ مُعَاوِيَةُ يَأْمُرُنَا أَنْ نَأْكُلَ أَمْوَالَنَا بَيْنَنَا بِالْبَاطِلِ وَنَقْتُلَ أَنْفُسَنَا وَاللَّهُ يَقُولُ{ يَا أَيُّهَا الَّذِينَ آمَنُوا لَا تَأْكُلُوا أَمْوَالَكُمْ بَيْنَكُمْ بِالْبَاطِلِ إِلَّا أَنْ تَكُونَ تِجَارَةً عَنْ تَرَاضٍ مِنْكُمْ وَلَا تَقْتُلُوا أَنْفُسَكُمْ إِنَّ اللَّهَ كَانَ بِكُمْ رَحِيمًا }قَالَ فَسَكَتَ سَاعَةً ثُمَّ قَالَ أَطِعْهُ فِي طَاعَةِ اللَّهِ وَاعْصِهِ فِي مَعْصِيَةِ اللَّهِ و حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ وَابْنُ نُمَيْرٍ وَأَبُو سَعِيدٍ الْأَشَجُّ قَالُوا حَدَّثَنَا وَكِيعٌ ح و حَدَّثَنَا أَبُو كُرَيْبٍ حَدَّثَنَا أَبُو مُعَاوِيَةَ كِلَاهُمَا عَنْ الْأَعْمَشِ بِهَذَا الْإِسْنَادِ نَحْوَهُ و حَدَّثَنِي مُحَمَّدُ بْنُ رَافِعٍ حَدَّثَنَا أَبُو الْمُنْذِرِ إِسْمَعِيلُ بْنُ عُمَرَ حَدَّثَنَا يُونُسُ بْنُ أَبِي إِسْحَقَ الْهَمْدَانِيُّ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ أَبِي السَّفَرِ عَنْ عَامِرٍ عَنْ عَبْدِ الرَّحْمَنِ بْنِ عَبْدِ رَبِّ الْكَعْبَةِ الصَّائِدِيِّ قَالَ رَأَيْتُ جَمَاعَةً عِنْدَ الْكَعْبَةِ فَذَكَرَ نَحْوَ حَدِيثِ الْأَعْمَشِ","id":"Telah menceritakan kepada kami [Zuhair bin Harb] dan [Ishaq bin Ibrahim], Ishaq berkata; telah mengabarkan kepada kami, sedangkan Zuhair berkata; telah menceritakan kepada kami [Jarir] dari [Al A'masy] dari [Zaid bin Wahb] dari [Abdurrahman bin Abd Rabbil Ka'bah] dia berkata, \"Ketika saya masuk masjid, maka terlihat olehku [Abdullah bin 'Amru bin 'Ash] duduk di bawah naungan ka'bah di kelilingi orang banyak. Lalu aku datangi mereka dan duduk di dekat Abadullah. Dia berkata, \"Kami pernah mengadakan suatu perjalanan bersama Rasulullah shallallahu 'alaihi wasallam, lalu di suatu tempat pemberhentian kami berhenti. Sebagian kami ada yang memperbaiki tempat tidur, sebagian lagi berlatih memanah, sebagian lagi memberi makan hewan dan sebagainya. Tiba-tiba terdengar utusan Rasulullah shallallahu 'alaihi wasallam menyeru, memanggil kami untuk shalat berjama'ah, lalu kami berkumpul di dekat beliau. Beliau bersabda: \"Para Nabi sebelum saya diutus menuntun umatnya kepada kebaikan yang telah diajarkan Allah kepada mereka, dan memingatkan bahaya yang mengancam mereka. Ummatku yang sempurna dan selamat ialah angkatan yang pertama-tama, angkatan sesudah itu akan ditimpa berbagai cobaan berupa hal-hal yang tidak disenanginya, seperti timbulnya fitnah. Di mana-mana sebagian mereka menghina sebagian yang lain, oleh karena itu timbullah bencana. Orang-orang mukmin berkata, 'Inilah kiranya yang membinasakanku', Setelah hilang bencana tersebut, timbul pula bencana yang lain. Dan orang mukmin berkata, 'Ini..! Ini..!\" Siapa yang ingin bebas dari neraka dan ingin masuk ke surga, hendaklah dia menemui kematiannya dalam keimanan kepada Allah dan hari akhirat, dan hendaklah dia berjasa kepada ummat manusia sesuai dengan yang diinginkan oleh masyarakat itu. Siapa yang baik dengan seorang pemimpin (penguasa) lalu dia memenuhi bai'atnya dengan sepenuh hati, hendaklah dia mematuhi pemimpin itu semampunya. Jika yang lain datang memberontak, penggallah lehernya.\" Abdurrahman berkata, \"Aku lebih mendekat lagi kepada 'Amru, lalu saya berkata, \"Dengan nama Allah, saya bertanya kepada anda, 'Apakah kamu mendengar sendiri hadits ini dari Rasulullah shallallahu 'alaihi wasallam? ' dia menunjuk tangannya ke telinga dan hatinya seraya berkata, \"Saya mendengarnya dengan kedua telingaku dan kusimpan ke dalam hatiku.\" Lalu kukatakan kepadanya, \"Ini anak pamanmu, Mu'awiyah! Dia menyuruh kami memakan harta sesama dengan cara yang haram dan memerintahkan untuk saling membunuh sesama. Padahal Allah telah berfirman: '(Wahai orang-orang yang beriman, janganlah kamu memakan harta sesamamu dengan cara yang haram, kecuali berjual beli dengan cara suka sama suka sesamamu, dan janganlah kamu membunuh saudaramu (sesama muslim). Sesungguhnya Allah Maha penyayang kepadamu) ' (Qs. An Nisaa`: 29). 'Amru diam sebentar kemudian dia berkata, \"Patuhilah perintahnya bila sesuai dengan perintah Allah dan langgarlah perintahnya bila melanggar perintah Allah!\" Dan telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] dan [Ibnu Numair] serta [Abu Sa'id Al Asyaj] mereka berkata; telah menceritakan kepada kami [Waki']. (dalam jalur lain disebutkan) Telah menceritakan kepada kami [Abu Kuraib] telah menceritakan kepada kami [Abu Mu'awiyah] keduanya dari [Al A'masy] dengan isnad seperti ini.\" Dan telah menceritakan kepadaku [Muhammad bin Rafi'] telah menceritakan kepada kami [Abu Al Mundzir Isma'il bin 'Umar] telah menceritakan kepada kami [Yunus bin Abu Ishaq Al Hamdani] telah menceritakan kepada kami [Abdullah bin Abu As Safar] dari ['Amir] dari [Abdurrahman bin Abd Rabbil Ka'bah Ash Sha`idi] dia berkata, \"Saya melihat sekelompok orang di sisi Ka'bah…kemudian dia menyebutkan seperti hadits Al A'masy.\""},"3197":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ الْمُثَنَّى وَمُحَمَّدُ بْنُ بَشَّارٍ قَالَا حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ حَدَّثَنَا شُعْبَةُ قَالَ سَمِعْتُ قَتَادَةَ يُحَدِّثُ عَنْ أَنَسِ بْنِ مَالِكٍ عَنْ أُسَيْدِ بْنِ حُضَيْرٍأَنَّ رَجُلًا مِنْ الْأَنْصَارِ خَلَا بِرَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ أَلَا تَسْتَعْمِلُنِي كَمَا اسْتَعْمَلْتَ فُلَانًا فَقَالَ إِنَّكُمْ سَتَلْقَوْنَ بَعْدِي أَثَرَةً فَاصْبِرُوا حَتَّى تَلْقَوْنِي عَلَى الْحَوْضِو حَدَّثَنِي يَحْيَى بْنُ حَبِيبٍ الْحَارِثِيُّ حَدَّثَنَا خَالِدٌ يَعْنِي ابْنَ الْحَارِثِ حَدَّثَنَا شُعْبَةُ بْنُ الْحَجَّاجِ عَنْ قَتَادَةَ قَالَ سَمِعْتُ أَنَسًا يُحَدِّثُ عَنْ أُسَيْدِ بْنِ حُضَيْرٍ أَنَّ رَجُلًا مِنْ الْأَنْصَارِ خَلَا بِرَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِمِثْلِهِ و حَدَّثَنِيهِ عُبَيْدُ اللَّهِ بْنُ مُعَاذٍ حَدَّثَنَا أَبِي حَدَّثَنَا شُعْبَةُ بِهَذَا الْإِسْنَادِ وَلَمْ يَقُلْ خَلَا بِرَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah menceritakan kepada kami [Muhammad bin Al Mutsanna] dan [Muhammad bin Basyar] keduanya berkata; telah menceritakan kepada kami [Muhammad bin Ja'far] telah menceritakan kepada kami [Syu'bah] dia berkata; saya pernah mendengar [Qatadah] menceritakan dari [Anas bin Malik] dari [Usaid bin Khudlair], bahwa seorang laki-laki Anshar menemui Rasulullah shallallahu 'alaihi wasallam seraya berkata, \"Tidakkah anda mengangkatku menjadi pegawai sebagaimana anda mengangkat fulan (menjadi pegawai)?\" beliau bersabda: \"Sesungguhnya sepeninggalanku kelak, kamu akan menjumpai (penguasa) yang mementingkan diri sendiri. Maka sabarlah hingga kalian berjumpa denganku di telaga.\" Dan telah menceritakan kepadaku [Yahya bin Habib Al Haritsi] telah menceritakan kepada kami [Khalid] -yaitu Ibnu Al Harits- telah menceritakan kepada kami [Syu'bah bin Al Hajaj] dari [Qatadah] dia berkata; saya mendengar [Anas] bercerita dari [Usaid bin Hudlair], bahwa seorang laki-laki Anshar menemui Rasulullah shallallahu 'alaihi wasallam sendirian…seperti hadits di atas.\" Dan telah menceritakan kepadaku ['Ubaidullah bin Mu'ad] telah menceritakan kepada kami [ayahku] telah menceritakan kepada kami [Syu'bah] dengan isnad ini, namun dia tidak menyebutkan, \"Ia menemui Rasulullah shallallahu 'alaihi wasallam sendirian.\""},"3198":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ الْمُثَنَّى وَمُحَمَّدُ بْنُ بَشَّارٍ قَالَا حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ حَدَّثَنَا شُعْبَةُ عَنْ سِمَاكِ بْنِ حَرْبٍ عَنْ عَلْقَمَةَ بْنِ وَائِلٍ الْحَضْرَمِيِّ عَنْ أَبِيهِ قَالَسَأَلَ سَلَمَةُ بْنُ يَزِيدَ الْجُعْفِيُّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ يَا نَبِيَّ اللَّهِ أَرَأَيْتَ إِنْ قَامَتْ عَلَيْنَا أُمَرَاءُ يَسْأَلُونَا حَقَّهُمْ وَيَمْنَعُونَا حَقَّنَا فَمَا تَأْمُرُنَا فَأَعْرَضَ عَنْهُ ثُمَّ سَأَلَهُ فَأَعْرَضَ عَنْهُ ثُمَّ سَأَلَهُ فِي الثَّانِيَةِ أَوْ فِي الثَّالِثَةِ فَجَذَبَهُ الْأَشْعَثُ بْنُ قَيْسٍ وَقَالَ اسْمَعُوا وَأَطِيعُوا فَإِنَّمَا عَلَيْهِمْ ��َا حُمِّلُوا وَعَلَيْكُمْ مَا حُمِّلْتُمْو حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا شَبَابَةُ حَدَّثَنَا شُعْبَةُ عَنْ سِمَاكٍ بِهَذَا الْإِسْنَادِ مِثْلَهُ وَقَالَ فَجَذَبَهُ الْأَشْعَثُ بْنُ قَيْسٍ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ اسْمَعُوا وَأَطِيعُوا فَإِنَّمَا عَلَيْهِمْ مَا حُمِّلُوا وَعَلَيْكُمْ مَا حُمِّلْتُمْ","id":"Telah menceritakan kepada kami [Muhammad bin Al Mutsanna] dan [Muhammad bin Basyar] keduanya berkata; telah menceritakan kepada kami [Muhammad bin Ja'far] telah menceritakan kepada kami [Syu'bah] dari [Simak bin Harb] dari ['Alqamah bin Al Wa`il Al Hadlrami] dari [ayahnya] dia berkata, \"Salamah bin Yazid Al Ja'fi pernah bertanya kepada Rasulullah shallallahu 'alaihi wasallam, \"Wahai Nabi Allah, bagaimanakah pendapatmu jika para penguasa yang memimpin kami selalu menuntut hak mereka atas kami tapi mereka tidak mau memenuhi hak kami, sikap apa yang anda anjurkan kepada kami?\" Maka beliau berpaling, lalu ditanyakan lagi kepada beliau dan beliaupun tetap enggan menjawabnya hingga dua atau tiga kali pertanyaan itu diajukan kepada beliau, kemudian Al Aty'ats bin Qa`is menarik Salamah bin Zayid. Beliau lalu bersabda: \"Dengarkan dan taatilah, sesungguhnya mereka akan mempertanggung jawabkan atas semua perbuatan mereka sebagaimana kalian juga akan mempertanggung jawabkan semua perbuatan kalian.\" Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] telah menceritakan kepada kami [Syababah] telah menceritakan kepada kami [Syu'bah] dari [Simak] dengan sanad seperti ini, ia mengatakan, \"Lalu Al Asy'ats bin Qa`is menarik Usamah bin Zayid, lantas beliau menjawab: \"Dengarkan dan taatilah, sesungguhnya mereka akan mempertanggung jawabkan semua perbuatan mereka sebagaimana kalian juga akan mempertanggung jawabkan semua perbuatan kalian.\""},"3199":{"ar":"حَدَّثَنِي مُحَمَّدُ بْنُ الْمُثَنَّى حَدَّثَنَا الْوَلِيدُ بْنُ مُسْلِمٍ حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ يَزِيدَ بْنِ جَابِرٍ حَدَّثَنِي بُسْرُ بْنُ عُبَيْدِ اللَّهِ الْحَضْرَمِيُّ أَنَّهُ سَمِعَ أَبَا إِدْرِيسَ الْخَوْلَانِيَّ يَقُولُ سَمِعْتُ حُذَيْفَةَ بْنَ الْيَمَانِ يَقُولُاكَانَ النَّاسُ يَسْأَلُونَ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ الْخَيْرِ وَكُنْتُ أَسْأَلُهُ عَنْ الشَّرِّ مَخَافَةَ أَنْ يُدْرِكَنِي فَقُلْتُ يَا رَسُولَ اللَّهِ إِنَّا كُنَّا فِي جَاهِلِيَّةٍ وَشَرٍّ فَجَاءَنَا اللَّهُ بِهَذَا الْخَيْرِ فَهَلْ بَعْدَ هَذَا الْخَيْرِ شَرٌّ قَالَ نَعَمْ فَقُلْتُ هَلْ بَعْدَ ذَلِكَ الشَّرِّ مِنْ خَيْرٍ قَالَ نَعَمْ وَفِيهِ دَخَنٌ قُلْتُ وَمَا دَخَنُهُ قَالَ قَوْمٌ يَسْتَنُّونَ بِغَيْرِ سُنَّتِي وَيَهْدُونَ بِغَيْرِ هَدْيِي تَعْرِفُ مِنْهُمْ وَتُنْكِرُ فَقُلْتُ هَلْ بَعْدَ ذَلِكَ الْخَيْرِ مِنْ شَرٍّ قَالَ نَعَمْ دُعَاةٌ عَلَى أَبْوَابِ جَهَنَّمَ مَنْ أَجَابَهُمْ إِلَيْهَا قَذَفُوهُ فِيهَا فَقُلْتُ يَا رَسُولَ اللَّهِ صِفْهُمْ لَنَا قَالَ نَعَمْ قَوْمٌ مِنْ جِلْدَتِنَا وَيَتَكَلَّمُونَ بِأَلْسِنَتِنَا قُلْتُ يَا رَسُولَ اللَّهِ فَمَا تَرَى إِنْ أَدْرَكَنِي ذَلِكَ قَالَ تَلْزَمُ جَمَاعَةَ الْمُسْلِمِينَ وَإِمَامَهُمْ فَقُلْتُ فَإِنْ لَمْ تَكُنْ لَهُمْ جَمَاعَةٌ وَلَا إِمَامٌ قَالَ فَاعْتَزِلْ تِلْكَ الْفِرَقَ كُلَّهَا وَلَوْ أَنْ تَعَضَّ عَلَى أَصْلِ شَجَرَةٍ حَتَّى يُدْرِكَكَ الْمَوْتُ وَأَنْتَ عَلَى ذَلِكَ","id":"Telah menceritakan kepadaku [Muhammad bin Al Mutsanna] telah menceritakan kepada kami [Al Walid bin Maslim] telah menceritakan kepada kami [Abdurrahman bin Yazid bin Jabir] telah menceritakan kepadaku [Busr bin 'Ubaidullah Al Hadlrami] bahwa dia mendengar [Abu Idris Al Haulani] berkata; saya mendengar [Hudzaifah bin Yaman] berkata, \"Biasanya orang-orang bertanya kepada Rasulullah shallallahu 'alaihi wasallam tentang kebajikan. Namun justru saya bertanya kepada beliau tentang kejahatan, karena saya khawatir akan menimpaku. Lalu saya bertanya, \"Wahai Rasulullah! Kami dahulu berada dalam kejahilan dan kejahatan, karena itu Allah Ta'ala menurunkan kebaikan (agama) ini kepada kami. Mungkinkah sesudah ini timbul lagi kejahatan?\" beliau menjawab: \"Ya.\" Saya bertanya lagi, \"Apakah setelah itu ada lagi kebaikan?\" beliau menjawab: \"Ya, akan tetapi ada cacatnya! saya bertanya, \"Apa cacatnya?\" Beliau bersabda: \"Kaum yang mengamal sunnah selain dari sunnahku, dan memimpin tanpa hidayahku, kamu tahu mereka tapi kamu ingkari.\" Saya bertanya, \"Apakah setelah itu akan ada kejahatan lagi?\" Jawab beliau: \"Ya. Yaitu orang-orang yang menyeru menuju neraka Jahannam, barangsiapa memenuhi seruannya maka ia akan dilemparkan ke dalam neraka itu.\" Maka saya bertanya lagi, \"Wahai Rasulullah! Tunjukanlah kepada kami ciri-ciri mereka.\" Beliau menjawab: \"Baik. Kulit mereka seperti kulit kita dan berbicara dengan bahasa kita.\" Aku bertanya lagi, \"Wahai Rasulullah, bagaimana petunjuk anda seandainya saya menemui hal yang demikian?\" Jawab beliau: \"Tetaplah kamu bersama jama'ah kaum muslimin dan imam (pemimpin) mereka.\" Saya bertanya lagi, \"Jika tidak ada jama'ah dan imam?\" beliau menjawab: \"Tinggalkan semua kelompok meskipun kamu menggigit akar kayu sampai ajal menjemput, dan kamu masih tetap pada pendirianmu.\""},"3200":{"ar":"و حَدَّثَنِي مُحَمَّدُ بْنُ سَهْلِ بْنِ عَسْكَرٍ التَّمِيمِيُّ حَدَّثَنَا يَحْيَى بْنُ حَسَّانَ ح و حَدَّثَنَا عَبْدُ اللَّهِ بْنُ عَبْدِ الرَّحْمَنِ الدَّارِمِيُّ أَخْبَرَنَا يَحْيَى وَهُوَ ابْنُ حَسَّانَ حَدَّثَنَا مُعَاوِيَةُ يَعْنِي ابْنَ سَلَّامٍ حَدَّثَنَا زَيْدُ بْنُ سَلَّامٍ عَنْ أَبِي سَلَّامٍ قَالَ قَالَ حُذَيْفَةُ بْنُ الْيَمَانِقُلْتُ يَا رَسُولَ اللَّهِ إِنَّا كُنَّا بِشَرٍّ فَجَاءَ اللَّهُ بِخَيْرٍ فَنَحْنُ فِيهِ فَهَلْ مِنْ وَرَاءِ هَذَا الْخَيْرِ شَرٌّ قَالَ نَعَمْ قُلْتُ هَلْ وَرَاءَ ذَلِكَ الشَّرِّ خَيْرٌ قَالَ نَعَمْ قُلْتُ فَهَلْ وَرَاءَ ذَلِكَ الْخَيْرِ شَرٌّ قَالَ نَعَمْ قُلْتُ كَيْفَ قَالَ يَكُونُ بَعْدِي أَئِمَّةٌ لَا يَهْتَدُونَ بِهُدَايَ وَلَا يَسْتَنُّونَ بِسُنَّتِي وَسَيَقُومُ فِيهِمْ رِجَالٌ قُلُوبُهُمْ قُلُوبُ الشَّيَاطِينِ فِي جُثْمَانِ إِنْسٍ قَالَ قُلْتُ كَيْفَ أَصْنَعُ يَا رَسُولَ اللَّهِ إِنْ أَدْرَكْتُ ذَلِكَ قَالَ تَسْمَعُ وَتُطِيعُ لِلْأَمِيرِ وَإِنْ ضُرِبَ ظَهْرُكَ وَأُخِذَ مَالُكَ فَاسْمَعْ وَأَطِعْ","id":"Telah menceritakan kepadaku [Muhammad Ibnu Sahl bin 'Askar At Tamimi] telah menceritakan kepada kami [Yahya bin Hasan]. (dalam jalur lain disebutkan) Telah menceritakan kepada kami [Abdullah bin Abdurrahman Ad Darimi] telah mengabarkan kepada kami [Yahya] -yaitu Ibnu Hassan- telah menceritakan kepada kami [Mu'awiyah] -yaitu Ibnu Salam- telah menceritakan kepada kami [Zaid bin Sallam] dari [Abu Sallam] dia berkata; [Hudzaifah bin Yaman] berkata, \"Saya bertanya, \"Wahai Rasulullah, dahulu saya berada dalam kejahatan, kemudian Allah menurunkan kebaikan (agama Islam) kepada kami, apakah setelah kebaikan ini timbul lagi kejatahan?\" beliau menjawab: \"Ya.\" Saya bertanya lagi, \"Apakah setelah kejahatan tersebut akan timbul lagi kebaikan?\" beliau menjawab: \"Ya.\" Saya bertanya lagi, \"Apakah setelah kebaikan ini timbul lagi kejahatan?\" beliau menjawab: \"Ya.\" Aku bertanya, \"Bagaimana hal itu?\" beliau menjawab: \"Setelahku nanti akan ada pemimpin yang memimpin tidak dengan petunjukku dan mengambil sunah bukan dari sunahku, lalu akan datang beberapa laki-laki yang hati mereka sebagaimana hatinya setan dalam rupa manusia.\" Hudzaifah berkata; saya betanya, \"Wahai Rasulullah, jika hal itu menimpaku apa yang anda perintahkan kepadaku?\" beliau menjawab: \"Dengar dan patuhilah kepada pemimpinmu, walaupun ia memukulmu dan merampas harta bendamu, dengar dan patuhilah dia.\""},"3201":{"ar":"حَدَّثَنَا شَيْبَانُ بْنُ فَرُّوخَ حَدَّثَنَا جَرِيرٌ يَعْنِي ابْنَ حَازِمٍ حَدَّثَنَا غَيْلَانُ بْنُ جَرِيرٍ عَنْ أَبِي قَيْسِ بْنِ رِيَاحٍ عَنْ أَبِي هُرَيْرَةَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهُ قَالَ مَنْ خَرَجَ مِنْ الطَّاعَةِ وَفَارَقَ الْجَمَاعَةَ فَمَاتَ مَاتَ مِيتَةً جَاهِلِيَّةً وَمَنْ قَاتَلَ تَحْتَ رَايَةٍ عِمِّيَّةٍ يَغْضَبُ لِعَصَبَةٍ أَوْ يَدْعُو إِلَى عَصَبَةٍ أَوْ يَنْصُرُ عَصَبَةً فَقُتِلَ فَقِتْلَةٌ جَاهِلِيَّةٌ وَمَنْ خَرَجَ عَلَى أُمَّتِي يَضْرِبُ بَرَّهَا وَفَاجِرَهَا وَلَا يَتَحَاشَى مِنْ مُؤْمِنِهَا وَلَا يَفِي لِذِي عَهْدٍ عَهْدَهُ فَلَيْسَ مِنِّي وَلَسْتُ مِنْهُو حَدَّثَنِي عُبَيْدُ اللَّهِ بْنُ عُمَرَ الْقَوَارِيرِيُّ حَدَّثَنَا حَمَّادُ بْنُ زَيْدٍ حَدَّثَنَا أَيُّوبُ عَنْ غَيْلَانَ بْنِ جَرِيرٍ عَنْ زِيَادِ بْنِ رِيَاحٍ الْقَيْسِيِّ عَنْ أَبِي هُرَيْرَةَ قَالَ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِنَحْوِ حَدِيثِ جَرِيرٍ وَقَالَ لَا يَتَحَاشَ مِنْ مُؤْمِنِهَا","id":"Telah menceritakan kepada kami [Syaiban bin Farruh] telah menceritakan kepada kami [Jarir] -yaitu Ibnu Hazim- telah menceritakan kepada kami [Ghailan bin Jarir] dari [Abu Qais bin Riyah] dari [Abu Hurairah] dari Nabi shallallahu 'alaihi wasallam, bahwa beliau bersabda: \"Barangsiapa keluar dari ketaatan dan tidak mau bergabung dengan Jama'ah kemudian ia mati, maka matinya seperti mati jahiliyah. Dan barangsiapa mati di bawah bendera kefanatikan, dia marah karena fanatik kesukuan atau karena ingin menolong kebangsaan kemudian dia mati, maka matinya seperti mati jahiliyah. Dan barangsiapa keluar dari ummatku, kemudian menyerang orang-orang yang baik maupun yang fajir tanpa memperdulikan orang mukmin, dan tidak pernah mengindahkan janji yang telah di buatnya, maka dia tidak termasuk dari golonganku dan saya tidak termasuk dari golongannya.\" Dan telah menceritakan kepadaku ['Ubaidullah bin Umar Al Qawariri] telah menceritakan kepada kami [Hammad bin Zaid] telah menceritakan kepada kami [Ayyub] dari [Ghailan bin Jarir] dari [Ziyad bin Riyah Al Qaisi] dari [Abu Hurairah] dia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda seperti hadits Jarir, dia berkata, \"Dan tidak memperdulikan orang mukminnya.\""},"3202":{"ar":"و حَدَّثَنِي زُهَيْرُ بْنُ حَرْبٍ حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ مَهْدِيٍّ حَدَّثَنَا مَهْدِيُّ بْنُ مَيْمُونٍ عَنْ غَيْلَانَ بْنِ جَرِيرٍ عَنْ زِيَادِ بْنِ رِيَاحٍ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ خَرَجَ مِنْ الطَّاعَةِ وَفَارَقَ الْجَمَاعَةَ ثُمَّ مَاتَ مَاتَ مِيتَةً جَاهِلِيَّةً وَمَنْ قُتِلَ تَحْتَ رَايَةٍ عِمِّيَّةٍ يَغْضَبُ لِلْعَصَبَةِ وَيُقَاتِلُ لِلْعَصَبَةِ فَلَيْسَ مِنْ أُمَّتِي وَمَنْ خَرَجَ مِنْ أُمَّتِي عَلَى أُمَّتِي يَضْرِبُ بَرَّهَا وَفَاجِرَهَا لَا يَتَحَاشَ مِنْ مُؤْمِنِهَا وَلَا يَفِي بِذِي عَهْدِهَا فَلَيْسَ مِنِّيو حَدَّثَنَا مُحَمَّدُ بْنُ الْمُثَنَّى وَابْنُ بَشَّارٍ قَالَا حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ حَدَّثَنَا شُعْبَةُ عَنْ غَيْلَانَ بْنِ جَرِيرٍ بِهَذَا الْإِسْنَادِ أَمَّا ابْنُ الْمُثَنَّى فَلَمْ يَذْكُرْ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي الْحَدِيثِ وَأَمَّا ابْنُ بَشَّارٍ فَقَالَ فِي رِوَايَتِهِ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِنَحْوِ حَدِيثِهِمْ","id":"Dan telah menceritakan kepadaku [Zuhair bin Harb] telah menceritakan kepada kami [Abdurrahman bin Mahdi] telah menceritakan kepada kami [Mahdi bin Maimun] dari [Ghailan bin Jarir] dari [Ziyad bin Riyah] dari [Abu Hurairah] dia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barang siapa keluar dari keta'atan dan memisahkan diri dari Jama'ah kemudian dia mati, maka matinya seperti mati jahiliyah. Barangsiapa terbunuh di bawah bendera kefanatikan, balas dendam karena kefanatikan, dan berperang karena kebangsaan, maka dia tidak termasuk dari ummatku. Dan barangsiapa keluar dari ummatku lalu (menyerang) ummatku dan membunuh orang yang baik maupun yang fajir, dan tidak memperdulikan orang mukminnya serta tidak pernah mengindahkan janji yang telah dibuatnya, maka dia tidak termasuk dari golonganku.\" Dan telah menceritakan kepada kami [Muhammad bin Al Mutsanna] dan [Ibnu Basyar] keduanya berkata; telah menceritakan kepada kami [Muhammad bin Ja'far] telah menceritakan kepada kami [Syu'bah] dari [Ghailan bin Jarir] dengan isnad ini, namun dalam hadits Ibnu Mutsanna tidak disebutkan, \"Nabi shallallahu 'alaihi wasallam. Sedangkan dalam riwayat Ibnu Basyar dia menyebutkan, \"Rasulullah shallallahu 'alaihi wasallam bersabda….sebagaimana hadits mereka.\""},"3203":{"ar":"حَدَّثَنَا حَسَنُ بْنُ الرَّبِيعِ حَدَّثَنَا حَمَّادُ بْنُ زَيْدٍ عَنْ الْجَعْدِ أَبِي عُثْمَانَ عَنْ أَبِي رَجَاءٍ عَنْ ابْنِ عَبَّاسٍ يَرْوِيهِ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ رَأَى مِنْ أَمِيرِهِ شَيْئًا يَكْرَهُهُ فَلْيَصْبِرْ فَإِنَّهُ مَنْ فَارَقَ الْجَمَاعَةَ شِبْرًا فَمَاتَ فَمِيتَةٌ جَاهِلِيَّةٌ","id":"Telah menceritakan kepada kami [Hasan bin Rabi'] telah menceritakan kepada kami [Hammad bin Zaid] dari [Al Ja'd Abu Utsman] dari [Abu Raja`] dari riwayatnya [Ibnu Abbas] dia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa melihat pada diri pemimpinnya ada sesuatu yang ia benci hendaknya ia bersabar, sebab siapa yang memisahkan diri dari Jama'ah walau sejengkal kemudian dia mati, maka matinya seperti mati Jahiliyyah.\""},"3204":{"ar":"و حَدَّثَنَا شَيْبَانُ بْنُ فَرُّوخَ حَدَّثَنَا عَبْدُ الْوَارِثِ حَدَّثَنَا الْجَعْدُ حَدَّثَنَا أَبُو رَجَاءٍ الْعُطَارِدِيُّ عَنْ ابْنِ عَبَّاسٍعَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ كَرِهَ مِنْ أَمِيرِهِ شَيْئًا فَلْيَصْبِرْ عَلَيْهِ فَإِنَّهُ لَيْسَ أَحَدٌ مِنْ النَّاسِ خَرَجَ مِنْ السُّلْطَانِ شِبْرًا فَمَاتَ عَلَيْهِ إِلَّا مَاتَ مِيتَةً جَاهِلِيَّةً","id":"Dan telah menceritakan kepada kami [Syaiban bin Farruh] telah menceritakan kepada kami [Abdul Warits] telah menceritakan kepada kami [Al Ja'd] telah menceritakan kepada kami [Abu Raja Al 'Utharidi] dari [Ibnu Abbas] dari Rasulullah shallallahu 'alaihi wasallam, beliau bersabda: \"Barangsiapa membenci sesuatu pada diri pemimpinnya, hendaknya ia bersabar sebab tidaklah seseorang keluar dari kepemimpinan (kaum Muslimin) walau sejengkal, kemudian mati kecuali ia mati seperti mati jahiliyah.\""},"3205":{"ar":"حَدَّثَنَا هُرَيْمُ بْنُ عَبْدِ الْأَعْلَى حَدَّثَنَا الْمُعْتَمِرُ قَالَ سَمِعْتُ أَبِي يُحَدِّثُ عَنْ أَبِي مِجْلَزٍ عَنْ جُنْدَبِ بْنِ عَبْدِ اللَّهِ الْبَجَلِيِّ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ قُتِلَ تَحْتَ رَايَةٍ عِمِّيَّةٍ يَدْعُو عَصَبِيَّةً أَوْ يَنْصُرُ عَصَبِيَّةً فَقِتْلَةٌ جَاهِلِيَّةٌ","id":"Telah menceritakan kepada kami [Huraim bin Abdul A'la] telah menceritakan kepada kami [Al Mu'tamir] dia berkata; saya mendengar [ayahku] menyebutkan dari [Abu Mijlaz] dari [Jundab bin Abdullah Al Bajali] dia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa terbunuh karena membela bendera kefanatikan yang menyeru kepada kebangsaan atau mendukungnya, maka matinya seperti mati Jahiliyah.\""},"3206":{"ar":"حَدَّثَنَا عُبَيْدُ اللَّهِ بْنُ مُعَاذٍ الْعَنْبَرِيُّ حَدَّثَنَا أَبِي حَدَّثَنَا عَاصِمٌ وَهُوَ ابْنُ مُحَمَّدِ بْنِ زَيْدٍ عَنْ زَيْدِ بْنِ مُحَمَّدٍ عَنْ نَافِعٍ قَالَ جَاءَ عَبْدُ اللَّهِ بْنُ عُمَرَ إِلَى عَبْدِ اللَّهِ بْنِ مُطِيعٍ حِينَ كَانَ مِنْ أَمْرِ الْحَرَّةِ مَا كَانَ زَمَنَ يَزِيدَ بْنِ مُعَاوِيَةَ فَقَالَ اطْرَحُوا لِأَبِي عَبْدِ الرَّحْمَنِ وِسَادَةً فَقَالَ إِنِّي لَمْ آتِكَ لِأَجْلِسَأَتَيْتُكَ لِأُحَدِّثَكَ حَدِيثًا سَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُهُ سَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ مَنْ خَلَعَ يَدًا مِنْ طَاعَةٍ لَقِيَ اللَّهَ يَوْمَ الْقِيَامَةِ لَا حُجَّةَ لَهُ وَمَنْ مَاتَ وَلَيْسَ فِي عُنُقِهِ بَيْعَةٌ مَاتَ مِيتَةً جَاهِلِيَّةًو حَدَّثَنَا ابْنُ نُمَيْرٍ حَدَّثَنَا يَحْيَى بْنُ عَبْدِ اللَّهِ بْنِ بُكَيْرٍ حَدَّثَنَا لَيْثٌ عَنْ عُبَيْدِ اللَّهِ بْنِ أَبِي جَعْفَرٍ عَنْ بُكَيْرِ بْنِ عَبْدِ اللَّهِ بْنِ الْأَشَجِّ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَ أَنَّهُ أَتَى ابْنَ مُطِيعٍ فَذَكَرَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَحْوَهُ حَدَّثَنَا عَمْرُو بْنُ عَلِيٍّ حَدَّثَنَا ابْنُ مَهْدِيٍّ ح و حَدَّثَنَا مُحَمَّدُ بْنُ عَمْرِو بْنِ جَبَلَةَ حَدَّثَنَا بِشْرُ بْنُ عُمَرَ قَالَا جَمِيعًا حَدَّثَنَا هِشَامُ بْنُ سَعْدٍ عَنْ زَيْدِ بْنِ أَسْلَمَ عَنْ أَبِيهِ عَنْ ابْنِ عُمَرَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِمَعْنَى حَدِيثِ نَافِعٍ عَنْ ابْنِ عُمَرَ","id":"Telah menceritakan kepada kami [Ubaidullah bin Mu'adz Al 'Anbari] telah menceritakan kepada kami [ayahku] telah menceritakan kepada kami ['Ashim] -yaitu Ibnu Muhammad bin Zaid- dari [Zaid bin Muhammad] dari [Nafi'] dia berkata, \" [Abdullah bin Umar] pernah datang kepada Abdullah bin Muthi' ketika ia menjabat sebagai penguasa negeri Harrah di zaman kekhalifahan Yazid bin Mu'awiyah. Abdullah bin Muthi' berkata, \"Berilah Abu Abdurrahman bantal.\" Maka Abu Abdurrahman berkata, \"Saya datang kepadamu tidak untuk duduk, saya datang kepadamu untuk menceritakan kepadamu suatu hadits yang pernah saya dengar dari Rasulullah shallallahu 'alaihi wasallam. Saya mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa melepas tangannya dari ketaatan, maka ia akan menemui Allah di hari Kiamat dalam keadaan tidak memiliki hujjah, danbarang siapa mati dalam keadaan tidak berbaiat, maka ia mati seperti mati jahiliyyah.\" Dan telah menceritakan kepada kami [Ibnu Numair] telah menceritakan kepada kami [Yahya bin Abdullah bin Bukair] telah menceritakan kepada kami [Laits] dari Rasulullah ['Ubaidullah bin Abu Ja'far] dari [Bukair bin Abdullah bin Al Asyaj] dari [Nafi'] dari [Ibnu Umar], bahwa dia mendatangi Ibnu Muthi' lalu menyebutkan dari Nabi shallallahu 'alaihi wasallam seperti hadits di atas.\" Dan telah menceritakan kepada kami ['Amru bin Ali] telah menceritakan kepada kami [Ibnu Mahdi]. (dalam jalur lain disebutkan) Telah menceritakan kepada kami [Muhammad bin 'Amru bin Jabalah] telah menceritakan kepada kami [Bisyr bin Umar] semuanya berkata; telah menceritakan kepada kami [Hisyam bin Sa'd] dari [Zaid bin Aslam] dari [ayahnya] dari [Ibnu Umar] dari Nabi shallallahu 'alaihi wasallam semakna dengan hadits Nafi' dari Ibnu Umar.\""},"3207":{"ar":"حَدَّثَنِي أَبُو بَكْرِ بْنُ نَافِعٍ وَمُحَمَّدُ بْنُ بَشَّارٍ قَالَ ابْنُ نَافِعٍ حَدَّثَنَا غُنْدَرٌ و قَالَ ابْنُ بَشَّارٍ حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ حَدَّثَنَا شُعْبَةُ عَنْ زِيَادِ بْنِ عِلَاقَةَ قَالَ سَمِعْتُ عَرْفَجَةَ قَالَسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ إِنَّهُ سَتَكُونُ هَنَاتٌ وَهَنَاتٌ فَمَنْ أَرَادَ أَنْ يُفَرِّقَ أَمْرَ هَذِهِ الْأُمَّةِ وَهِيَ جَمِيعٌ فَاضْرِبُوهُ بِالسَّيْفِ كَائِنًا مَنْ كَانَو حَدَّثَنَا أَحْمَدُ بْنُ خِرَاشٍ حَدَّثَنَا حَبَّانُ حَدَّثَنَا أَبُو عَوَانَةَ ح و حَدَّثَنِي الْقَاسِمُ بْنُ زَكَرِيَّاءَ حَدَّثَنَا عُبَيْدُ اللَّهِ بْنُ مُوسَى عَنْ شَيْبَانَ ح و حَدَّثَنَا إِسْحَقُ بْنُ إِبْرَاهِيمَ أَخْبَرَنَا الْمُصْعَبُ بْنُ الْمِقْدَامِ الْخَثْعَمِيُّ حَدَّثَنَا إِسْرَائِيلُ ح و حَدَّثَنِي حَجَّاجٌ حَدَّثَنَا عَارِمُ بْنُ الْفَضْلِ حَدَّثَنَا حَمَّادُ بْنُ زَيْدٍ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ الْمُخْتَارِ وَرَجُلٌ سَمَّاهُ كُلُّهُمْ عَنْ زِيَادِ بْنِ عِلَاقَةَ عَنْ عَرْفَجَةَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِمِثْلِهِ غَيْرَ أَنَّ فِي حَدِيثِهِمْ جَمِيعًا فَاقْتُلُوهُ","id":"Telah menceritakan kepadaku [Abu Bakar bin Nafi'] dan [Muhammad bin Basyar], [Ibnu Nafi'] berkata; telah menceritakan kepada kami [Ghundar], dan [Ibnu Basyar] berkata; telah menceritakan kepada kami [Muhammad bin Ja'far] telah menceritakan kepada kami [Syu'bah] dari [Ziyad bin 'Ilaqah] dia berkata; saya mendengar ['Arfajah] berkata, \"Saya mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Suatu saat nanti akan terjadi bencana dan kekacauan, maka siapa saja yang hendak memecah belah persatuan ummat ini penggallah dengan pedangmu, siapa pun orangnya.\" Dan telah menceritakan kepada kami [Ahmad bin Khirasy] telah menceritakan kepada kami [Habban] telah menceritakan kepada kami [Abu 'Awanah]. (dalam jalur lain disebutkan) Telah menceritakan kepadaku [Al Qasim bin Zakaria] telah menceritakan kepada kami ['Ubaidullah bin Musa] dari [Syaiban]. (dalam jalur lain disebutkan) Telah menceritakan kepadaku [Ishaq bin Ibrahim] telah mengabarkan kepada kami [Al Mush'ab bin Al Miqdam Al Khats'ami] telah menceritakan kepada kami [Isra'il] (dalam jalur lain disebutkan) Telah menceritakan kepadaku [Hajjaj] telah menceritakan kepada kami ['Arim bin Fadhl] telah menceritakan kepada kami [Hammad bin Zaid] telah menceritakan kepada kami ['Abdullah bin Al Mukhtar] dan seorang laki-laki, mereka semua dari [Ziyad bin 'Ilaqah] dari ['Arfajah] dari Nabi shallallahu 'alaihi wasallam seperti hadits di atas, namun dalam hadits mereka disebutkan, \"Maka bunuhlah ia.\""},"3208":{"ar":"و حَدَّثَنِي عُثْمَانُ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا يُونُسُ بْنُ أَبِي يَعْفُورٍ عَنْ أَبِيهِ عَنْ عَرْفَجَةَ قَالَسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ مَنْ أَتَاكُمْ وَأَمْرُكُمْ جَمِيعٌ عَلَى رَجُلٍ وَاحِدٍ يُرِيدُ أَنْ يَشُقَّ عَصَاكُمْ أَوْ يُفَرِّقَ جَمَاعَتَكُمْ فَاقْتُلُوهُ","id":"Dan telah menceritakan kepadaku [Utsman bin Abu Syaibah] telah menceritakan kepada kami [Yunus bin Abu Ya'fur] dari [ayahnya] dari ['Arfajah] dia berkata, \"Saya mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Bila datang kepadamu seseorang yang hendak mematahkan tongkatmu (memecah belah jama'ah) atau memecah belah persatuan kalian, maka bunuhlah dia.\""},"3209":{"ar":"و حَدَّثَنِي وَهْبُ بْنُ بَقِيَّةَ الْوَاسِطِيُّ حَدَّثَنَا خَالِدُ بْنُ عَبْدِ اللَّهِ عَنْ الْجُرَيْرِيِّ عَنْ أَبِي نَضْرَةَ عَنْ أَبِي سَعِيدٍ الْخُدْرِيِّ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا بُويِعَ لِخَلِيفَتَيْنِ فَاقْتُلُوا الْآخَرَ مِنْهُمَا","id":"Dan telah menceritakan kepadaku [Wahb bin Baqiyah Al Wasithi] telah menceritakan kepada kami [Khalid bin Abdullah] dari [Al Jurairi] dari [Abu Nadlrah] dari [Abu Sa'id Al Khudri] dia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Apabila ada dua khalifah yang dibaiat, maka bunuhlah yang paling terakhir dari keduanya.\""},"3210":{"ar":"حَدَّثَنَا هَدَّابُ بْنُ خَالِدٍ الْأَزْدِيُّ حَدَّثَنَا هَمَّامُ بْنُ يَحْيَى حَدَّثَنَا قَتَادَةُ عَنْ الْحَسَنِ عَنْ ضَبَّةَ بْنِ مِحْصَنٍ عَنْ أُمِّ سَلَمَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ سَتَكُونُ أُمَرَاءُ فَتَعْرِفُونَ وَتُنْكِرُونَ فَمَنْ عَرَفَ بَرِئَ وَمَنْ أَنْكَرَ سَلِمَ وَلَكِنْ مَنْ رَضِيَ وَتَابَعَ قَالُوا أَفَلَا نُقَاتِلُهُمْ قَالَ لَا مَا صَلَّوْا","id":"Telah menceritakan kepada kami [Haddab bin Khalid Al Azdi] telah menceritakan kepada kami [Hammam bin Yahya] telah menceritakan kepada kami [Qatadah] dari [Al Hasan] dari [Dlabbah bin Mihshan] dari [Ummu Salamah] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Akan datang para penguasa, kalian mengenal mereka namun kalian mengingkari (perbuatan mereka), siapa yang tahu (kemungkarannya) hendaklah berlepas diri, dan barangsiapa mengingkari maka ia telah selamat. Tetapi bagai yang ridla dan mengikuti, para sahabat langsung menyelah, \"Bagaimana jika kiat perangi saja?\" beliau menjawab: \"Tidak! Selama mereka masih shalat.\""},"3211":{"ar":"و حَدَّثَنِي أَبُو غَسَّانَ الْمِسْمَعِيُّ وَمُحَمَّدُ بْنُ بَشَّارٍ جَمِيعًا عَنْ مُعَاذٍ وَاللَّفْظُ لِأَبِي غَسَّانَ حَدَّثَنَا مُعَاذٌ وَهُوَ ابْنُ هِشَامٍ الدَّسْتَوَائِيُّ حَدَّثَنِي أَبِي عَنْ قَتَادَةَ حَدَّثَنَا الْحَسَنُ عَنْ ضَبَّةَ بْنِ مِحْصَنٍ الْعَنَزِيِّ عَنْ أُمِّ سَلَمَةَ زَوْجِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهُ قَالَ إِنَّهُ يُسْتَعْمَلُ عَلَيْكُمْ أُمَرَاءُ فَتَعْرِفُونَ وَتُنْكِرُونَ فَمَنْ كَرِهَ فَقَدْ بَرِئَ وَمَنْ أَنْكَرَ فَقَدْ سَلِمَ وَلَكِنْ مَنْ رَضِيَ وَتَابَعَ قَالُوا يَا رَسُولَ اللَّهِ أَلَا نُقَاتِلُهُمْ قَالَ لَا مَا صَلَّوْاأَيْ مَنْ كَرِهَ بِقَلْبِهِ وَأَنْكَرَ بِقَلْبِهِ و حَدَّثَنِي أَبُو الرَّبِيعِ الْعَتَكِيُّ حَدَّثَنَا حَمَّادٌ يَعْنِي ابْنَ زَيْدٍ حَدَّثَنَا الْمُعَلَّى بْنُ زِيَادٍ وَهِشَامٌ عَنْ الْحَسَنِ عَنْ ضَبَّةَ بْنِ مِحْصَنٍ عَنْ أُمِّ سَلَمَةَ قَالَتْ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِنَحْوِ ذَلِكَ غَيْرَ أَنَّهُ قَالَ فَمَنْ أَنْكَرَ فَقَدْ بَرِئَ وَمَنْ كَرِهَ فَقَدْ سَلِمَ و حَدَّثَنَاه حَسَنُ بْنُ الرَّبِيعِ الْبَجَلِيُّ حَدَّثَنَا ابْنُ الْمُبَارَكِ عَنْ هِشَامٍ عَنْ الْحَسَنِ عَنْ ضَبَّةَ بْنِ مِحْصَنٍ عَنْ أُمِّ سَلَمَةَ قَالَتْ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَذَكَرَ مِثْلَهُ إِلَّا قَوْلَهُ وَلَكِنْ مَنْ رَضِيَ وَتَابَعَ لَمْ يَذْكُرْهُ","id":"Dan telah menceritakan kepada kami [Abu Ghassan Al Misma'i] dan [Muhammad bin Basyar] semuanya dari [Mu'adz] sedangkan lafadznya dari Abu Ghassan, telah menceritakan kepada kami Mu'adz dan dia Ibnu Hisyam Ad Dastawa`i telah menceritakan kepadaku [Bapakku] dari [Qatadah] telah menceritakan kepada kami [Al Hasan] dari [Dlabbah bin Mihshan Al 'Anazi] dari [Ummu Salamah] isteri Nabi shallallahu 'alaihi wasallam, dari Nabi shallallahu 'alaihi wasallam bahwa beliau bersabda: \"Kalian akan dipimpin oleh para penguasa, kalian mengenal mereka namun kalian mengingkari (perbuatan mereka), barangsiapa membenci kemungkarannya maka ia telah berlepas diri, dan barangsiapa mengingkari berarti ia telah selamat. Tetapi bagi orang yang ridla dan mengikuti, para sahabat langsung bertanya, \"Wahai Rasulullah, tidakkah kita perangi saja?\" beliau menjawab: \"Tidak! Selama mereka masih melaksanakan shalat.\" -maksudnya barang siapa membenci dan mengingkari dengan hatinya- Dan telah menceritakan kepadaku [Abu Ar Rabi' Al 'Ataki] telah menceritakan kepada kami [Hammad] -yaitu Ibnu Zaid- telah menceritakan kepada kami [Al Mu'alli bin Ziyad] dan [Hisyam] dari [Al Hasan] dari [Dlabbah bin Mihshan] dari [Ummu Salamah] dia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda seperti hadits di atas, namun dia menyebutkan, \"Barangsiapa mengingkarinya maka ia akan selamat, dan barangsiapa memebencinya maka ia akan selamat.\" Dan telah menceritakan kepada kami [Hasan bin Ar Rabi' Al Bajali] telah menceritakan kepada kami [Ibnu Al Mubarrak] dari [Hisyam] dari [Al Hasan] dari [Dlabbah bin Mihshan] dari [Ummu Salamah] dia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda…kemudian dia menyebutkan hadits seperti di atas sampai perkataannya, 'Akan tetapi barangsiapa rela dan mengikutinya, ' namun dia tidak menyebutkan yang seperti itu.\""},"3212":{"ar":"حَدَّثَنَا إِسْحَقُ بْنُ إِبْرَاهِيمَ الْحَنْظَلِيُّ أَخْبَرَنَا عِيسَى بْنُ يُونُسَ حَدَّثَنَا الْأَوْزَاعِيُّ عَنْ يَزِيدَ بْنِ يَزِيدَ بْنِ جَابِرٍ عَنْ رُزَيْقِ بْنِ حَيَّانَ عَنْ مُسْلِمِ بْنِ قَرَظَةَ عَنْ عَوْفِ بْنِ مَالِكٍعَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ خِيَارُ أَئِمَّتِكُمْ الَّذِينَ تُحِبُّونَهُمْ وَيُحِبُّونَكُمْ وَيُصَلُّونَ عَلَيْكُمْ وَتُصَلُّونَ عَلَيْهِمْ وَشِرَارُ أَئِمَّتِكُمْ الَّذِينَ تُبْغِضُونَهُمْ وَيُبْغِضُونَكُمْ وَتَلْعَنُونَهُمْ وَيَلْعَنُونَكُمْ قِيلَ يَا رَسُولَ اللَّهِ أَفَلَا نُنَابِذُهُمْ بِالسَّيْفِ فَقَالَ لَا مَا أَقَامُوا فِيكُمْ الصَّلَاةَ وَإِذَا رَأَيْتُمْ مِنْ وُلَاتِكُمْ شَيْئًا تَكْرَهُونَهُ فَاكْرَهُوا عَمَلَهُ وَلَا تَنْزِعُوا يَدًا مِنْ طَاعَةٍ","id":"Telah menceritakan kepada kami [Ishaq bin Ibrahim Al Handlali] telah mengabarkan kepada kami [Isa bin Yunus] telah menceritakan kepada kami [Al Auza'i] dari [Yazid bin Yazid bin Jabir] dari [Ruzaiq bin Hayyan] dari [Muslim bin Qaradlah] dari ['Auf bin Malik] dari Rasulullah shallallahu 'alaihi wasallam, beliau bersabda: \"Sebaik-baik pemimpin kalian adalah mereka mencintai kalian dan kalian mencintai mereka, mereka mendo'akan kalian dan kalian mendo'akan mereka. Dan sejelek-jelek pemimpin kalian adalah mereka yang membenci kalian dan kalian membenci mereka, mereka mengutuk kalian dan kalian mengutuk mereka.\" Beliau ditanya, \"Wahai Rasulullah, tidakkah kita memerangi mereka?\" maka beliau bersabda: \"Tidak, selagi mereka mendirikan shalat bersama kalian. Jika kalian melihat dari pemimpin kalian sesuatu yang tidak baik maka bencilah tindakannya, dan janganlah kalian melepas dari ketaatan kepada mereka.\""},"3213":{"ar":"حَدَّثَنَا دَاوُدُ بْنُ رُشَيْدٍ حَدَّثَنَا الْوَلِيدُ يَعْنِي ابْنَ مُسْلِمٍ حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ يَزِيدَ بْنِ جَابِرٍ أَخْبَرَنِي مَوْلَى بَنِي فَزَارَةَ وَهُوَ رُزَيْقُ بْنُ حَيَّانَ أَنَّهُ سَمِعَ مُسْلِمَ بْنَ قَرَظَةَ ابْنَ عَمِّ عَوْفِ بْنِ مَالِكٍ الْأَشْجَعِيِّ يَقُولُ سَمِعْتُ عَوْفَ بْنَ مَالِكٍ الْأَشْجَعِيَّ يَقُولُاسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ خِيَارُ أَئِمَّتِكُمْ الَّذِينَ تُحِبُّونَهُمْ وَيُحِبُّونَكُمْ وَتُصَلُّونَ عَلَيْهِمْ وَيُصَلُّونَ عَلَيْكُمْ وَشِرَارُ أَئِمَّتِكُمْ الَّذِينَ تُبْغِضُونَهُمْ وَيُبْغِضُونَكُمْ وَتَلْعَنُونَهُمْ وَيَلْعَنُونَكُمْ قَالُوا قُلْنَا يَا رَسُولَ اللَّهِ أَفَلَا نُنَابِذُهُمْ عِنْدَ ذَلِكَ قَالَ لَا مَا أَقَامُوا فِيكُمْ الصَّلَاةَ لَا مَا أَقَامُوا فِيكُمْ الصَّلَاةَ أَلَا مَنْ وَلِيَ عَلَيْهِ وَالٍ فَرَآهُ يَأْتِي شَيْئًا مِنْ مَعْصِيَةِ اللَّهِ فَلْيَكْرَهْ مَا يَأْتِي مِنْ مَعْصِيَةِ اللَّهِ وَلَا يَنْزِعَنَّ يَدًا مِنْ طَاعَةٍقَالَ ابْنُ جَابِرٍ فَقُلْتُ يَعْنِي لِرُزَيْقٍ حِينَ حَدَّثَنِي بِهَذَا الْحَدِيثِ آللَّهِ يَا أَبَا الْمِقْدَامِ لَحَدَّثَكَ بِهَذَا أَوْ سَمِعْتَ هَذَا مِنْ مُسْلِمِ بْنِ قَرَظَةَ يَقُولُ سَمِعْتُ عَوْفًا يَقُولُ سَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ فَجَثَا عَلَى رُكْبَتَيْهِ وَاسْتَقْبَلَ الْقِبْلَةَ فَقَالَ إِي وَاللَّهِ الَّذِي لَا إِلَهَ إِلَّا هُوَ لَسَمِعْتُهُ مِنْ مُسْلِمِ بْنِ قَرَظَةَ يَقُولُ سَمِعْتُ عَوْفَ بْنَ مَالِكٍ يَقُولُ سَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ و حَدَّثَنَا إِسْحَقُ بْنُ مُوسَى الْأَنْصَارِيُّ حَدَّثَنَا الْوَلِيدُ بْنُ مُسْلِمٍ حَدَّثَنَا ابْنُ جَابِرٍ بِهَذَا الْإِسْنَادِ وَقَالَ رُزَيْقٌ مَوْلَى بَنِي فَزَارَةَ قَالَ مُسْلِم وَرَوَاهُ مُعَاوِيَةُ بْنُ صَالِحٍ عَنْ رَبِيعَةَ بْنِ يَزِيدَ عَنْ مُسْلِمِ بْنِ قَرَظَةَ عَنْ عَوْفِ بْنِ مَالِكٍ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِمِثْلِهِ","id":"Telah menceritakan kepada kami [Daud bin Rusyaid] telah menceritakan kepada kami [Al Walid] -yaitu Ibnu Muslim- telah menceritakan kepada kami [Abdurrahman bin Yazid bin jabir] telah mengabarkan kepadaku bekas budak Bani Fazarah [Ruzaiq bin Hayyan] bahwa dia mendengar [Muslim bin Qardzah bin 'Ammi 'Auf bin Malik Al Asyja'i] dia berkata; saya mendengar ['Auf bin Malik Al Asyja'i] berkata, \"Saya mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sebaik-baik pemimpin kalian adalah kalian mencintai mereka dan mereka mencintai kalian, kalian mendo'akan mereka dan mereka mendo'akan kalian. Sedangkan sejelek-jelek pemimpin kalian adalah kalian membenci mereka dan mereka membenci kalian, kalian mengutuk mereka dan mereka pun mengutuk kalian.\" Mereka berkata, \"Kemudian kami bertanya, \"Wahai Rasulullah, tidakkah kami memerangi mereka ketika itu?\" beliau menjawab: \"Tidak, selagi mereka mendirikan shalat bersama kalian, tidak selagi mereka masih mendirikan shalat bersama kalian. Dan barangsiapa dipimpin oleh seorang pemimpin, kemudian dia melihat pemimpinnya bermaksiat kepada Allah, hendaknya ia membenci dari perbuatannya dan janganlah ia melepas dari ketaatan kepadanya.\" Ibnu Jabir berkata, \"Lalu aku bertanya kepada Ruzaiq, yaitu ketika dia menceritakan kepadaku hadits ini, 'Demi Allah wahai Abu Miqdam, apakah dia menceritakan ini kepadamu? ', Atau, Apakah kamu mendengar ini dari Muslim bin Qardlah, bahwa dia berkata, 'Saya mendengar 'Auf berkata, 'Saya mendengar Rasulullah shallallahu 'alaihi wasallam? ' dia menjawab, \"kemudian dia duduk bertumpu di atas kedua lututnya dan menghadapkan ke kiblat sambil berkata, \"Demi Allah yang tidak ada tuhan yang berhak disembah selain Dia, sungguh saya pernah mendengarnya dari Muslim bin Qardlah berkata, 'Saya mendengar 'Auf bin Malik berkata, 'Saya mendengar Rasulullah shallallahu 'alaihi wasallam.\" Dan telah menceritakan kepada kami [Ishaq bin Musa Al Anshari] telah menceritakan kepada kami [Al Walid bin Muslim] telah menceritakan kepada kami [Ibnu Jabir] dengan isnad ini, Ruzaiq bekas budak Bani Fazarah. Muslim berkata; dan telah meriwayatkannya [Mu'awiyah bin Shalih] dari [Rabi'ah bin Yazid] dari [Muslim bin Qardlah] dari ['Auf bin Malik] dari Nabi shallallahu 'alaihi wasallam.\""},"3214":{"ar":"حَدَّثَنَا قُتَيْبَةُ بْنُ سَعِيدٍ حَدَّثَنَا لَيْثُ بْنُ سَعْدٍ ح و حَدَّثَنَا مُحَمَّدُ بْنُ رُمْحٍ أَخْبَرَنَا اللَّيْثُ عَنْ أَبِي الزُّبَيْرِ عَنْ جَابِرٍ قَالَكُنَّا يَوْمَ الْحُدَيْبِيَةِ أَلْفًا وَأَرْبَعَ مِائَةً فَبَايَعْنَاهُ وَعُمَرُ آخِذٌ بِيَدِهِ تَحْتَ الشَّجَرَةِ وَهِيَ سَمُرَةٌ وَقَالَ بَايَعْنَاهُ عَلَى أَنْ لَا نَفِرَّ وَلَمْ نُبَايِعْهُ عَلَى الْمَوْتِ","id":"Telah menceritakan kepada kami [Qutaibah bin Sa'id] telah menceritakan kepada kami [Laits bin Sa'd]. (dalam jalur lain disebutkan) Telah menceritakan kepada kami [Muhammad bin Rumh] telah mengabarkan kepada kami [Al Laits] dari [Abu Az Zubair] dari [Jabir] dia berkata, \"Di hari Hudaibiyyah kami berjumlah seribu empat ratus orang, kami berbaiat kepada beliau. Umar memegang tangan beliau di bawah pohon Samurah sambil berkata, \"Kami berbai'at kepada beliau bahwa kami tidak akan lari (dari peperangan) dan kami tidak berbai'at atas kematian.\""},"3215":{"ar":"و حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا ابْنُ عُيَيْنَةَ ح و حَدَّثَنَا ابْنُ نُمَيْرٍ حَدَّثَنَا سُفْيَانُ عَنْ أَبِي الزُّبَيْرِ عَنْ جَابِرٍ قَالَلَمْ نُبَايِعْ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَلَى الْمَوْتِ إِنَّمَا بَايَعْنَاهُ عَلَى أَنْ لَا نَفِرَّ","id":"Dan telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] telah menceritakan kepada kami [Ibnu 'Uyainah]. Telah menceritakan kepada kami [Ibnu Numair] telah menceritakan kepada kami [Sufyan] dari [Abu Az Zubair] dari [Jabir] dia berkata, \"Kami tidak berbai'at kepada Rasulullah shallallahu 'alaihi wasallam di atas kematian, hanyasanya kami berbai'at kepada beliau untuk tidak lari (dari peperangan).\""},"3216":{"ar":"و حَدَّثَنِي إِبْرَاهِيمُ بْنُ دِينَارٍ حَدَّثَنَا حَجَّاجُ بْنُ مُحَمَّدٍ الْأَعْوَرُ مَوْلَى سُلَيْمَانَ بْنِ مُجَالِدٍ قَالَ قَالَ ابْنُ جُرَيْجٍ وَأَخْبَرَنِي أَبُو الزُّبَيْرِ أَنَّهُ سَمِعَ جَابِرًا يَسْأَلُهَلْ بَايَعَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِذِي الْحُلَيْفَةِ فَقَالَ لَا وَلَكِنْ صَلَّى بِهَا وَلَمْ يُبَايِعْ عِنْدَ شَجَرَةٍ إِلَّا الشَّجَرَةَ الَّتِي بِالْحُدَيْبِيَةِقَالَ ابْنُ جُرَيْجٍ وَأَخْبَرَنِي أَبُو الزُّبَيْرِ أَنَّهُ سَمِعَ جَابِرَ بْنَ عَبْدِ اللَّهِ يَقُولُا دَعَا النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَلَى بِئْرِ الْحُدَيْبِيَةِ","id":"Dan telah menceritakan kepadaku [Ibrahim bin Dinar] telah menceritakan kepada kami [Hajjaj bin Muhammad Al A'war] bekas budak Sulaiman bin Mujalid, dia berkata; [Ibnu Juraij] berkata; dan telah mengabarkan kepadaku [Abu Az Zubair] bahwa dia mendengar [Jabir] pernah bertanya, \"Apakah Nabi shallallahu 'alaihi wasallam dibai'at di Dzul Khulaifah?\" Dia menjawab, \"Tidak, beliau hanya shalat mengadap ke arahnya, dan beliau tidak pernah dibaiat di bawah pohon kecuali pohon yang ada di Khudaibiah.\" [Ibnu Juraij] berkata; dan telah mengabarkan kepadaku [Abu Az Zubair] bahwa dia mendengar [Jabir bin Abdullah] berkata, \"Nabi shallallahu 'alaihi wasallam pernah shalat di dekat sumur Hudaibiyah.\""},"3217":{"ar":"حَدَّثَنَا سَعِيدُ بْنُ عَمْرٍو الْأَشْعَثِيُّ وَسُوَيْدُ بْنُ سَعِيدٍ وَإِسْحَقُ بْنُ إِبْرَاهِيمَ وَأَحْمَدُ بْنُ عَبْدَةَ وَاللَّفْظُ لِسَعِيدٍ قَالَ سَعِيدٌ وَإِسْحَقُ أَخْبَرَنَا و قَالَ الْآخَرَانِ حَدَّثَنَا سُفْيَانُ عَنْ عَمْرٍو عَنْ جَابِرٍ قَالَكُنَّا يَوْمَ الْحُدَيْبِيَةِ أَلْفًا وَأَرْبَعَ مِائَةٍ فَقَالَ لَنَا النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنْتُمْ الْيَوْمَ خَيْرُ أَهْلِ الْأَرْضِو قَالَ جَابِرٌ لَوْ كُنْتُ أُبْصِرُ لَأَرَيْتُكُمْ مَوْضِعَ الشَّجَرَةِ","id":"Telah menceritakan kepada kami [Sa'id bin 'Amru Al Asy'atsi] dan [Suwaid bin Sa'id] dan [Ishaq bin Ibrahim] serta [Ahmad bin 'Abdah], dan ini adalah lafadz Sa'id, Sa'id dan Ishaq berkata; telah mengabarkan kepada kami, sedangkan yang dua mengatakan; telah menceritakan kepada kami [Sufyan] dari ['Amru] dari [Jabir] dia berkata, \"Ketika peristiwa Hudaibiyyah kami berjumlah seribu empat ratus orang, lalu Nabi shallallahu 'alaihi wasallam bersabda kepada kami: \"Kalian pada hari ini merupakan makhluk terbaik yang ada di permukaan bumi ini.\" Dan [Jabir] mengatakan, \"Sekiranya saya melihatnya, sungguh saya akan memberitahu kepada kalian tempat pohon tersebut berada.\""},"3218":{"ar":"و حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ وَابْنُ نُمَيْرٍ قَالَا حَدَّثَنَا عَبْدُ اللَّهِ بْنُ إِدْرِيسَ ح و حَدَّثَنَا رِفَاعَةُ بْنُ الْهَيْثَمِ حَدَّثَنَا خَالِدٌ يَعْنِي الطَّحَّانَ كِلَاهُمَا يَقُولُ عَنْ حُصَيْنٍ عَنْ سَالِمِ بْنِ أَبِي الْجَعْدِ عَنْ جَابِرٍ قَالَلَوْ كُنَّا مِائَةَ أَلْفٍ لَكَفَانَا كُنَّا خَمْسَ عَشْرَةَ مِائَةً","id":"Dan telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] dan [Ibnu Numair] keduanya berkata; telah menceritakan kepada kami [Abdullah bin Idris]. (dalam jalur lain disebutkan) Telah menceritakan kepada kami [Rifa'ah bin Al Haitsam] telah menceritakan kepada kami [Khalid] -yaitu At Thahan- keduanya berkata; dari [Hushain] dari [Salim bin Abu Al Ja'd] dari [Jabir] dia berkata, \"Sekiranya kami saat itu berjumlah ratusan ribu orang maka telah cukup buat kami, namun jumlah kami hanya seribu lima ratus.\""},"3219":{"ar":"و حَدَّثَنَا عُثْمَانُ بْنُ أَبِي شَيْبَةَ وَإِسْحَقُ بْنُ إِبْرَاهِيمَ قَالَ إِسْحَقُ أَخْبَرَنَا و قَالَ عُثْمَانُ حَدَّثَنَا جَرِيرٌ عَنْ الْأَعْمَشِ حَدَّثَنِي سَالِمُ بْنُ أَبِي الْجَعْدِ قَالَ قُلْتُ لِجَابِرٍكَمْ كُنْتُمْ يَوْمَئِذٍ قَالَ أَلْفًا وَأَرْبَعَ مِائَةٍ","id":"Dan telah menceritakan kepada kami ['Utsman bin Abu Syaibah] dan [Ishaq bin Ibrahim], Ishaq berkata; telah mengabarkan kepada kami, dan 'Utsman mengatakan; telah menceritakan kepada kami [Jarir] dari [Al A'masy] telah menceritakan kepadaku [Salim bin Abu Al Ja'd] dia berkata, \"Saya bertanya kepada [Jabir], \"Berapakah jumlah kalian saat itu?\" dia menjawab, \"Seribu empat ratus orang.\""},"3220":{"ar":"حَدَّثَنَا عُبَيْدُ اللَّهِ بْنُ مُعَاذٍ حَدَّثَنَا أَبِي حَدَّثَنَا شُعْبَةُ عَنْ عَمْرٍو يَعْنِي ابْنَ مُرَّةَ حَدَّثَنِي عَبْدُ اللَّهِ بْنُ أَبِي أَوْفَى قَالَكَانَ أَصْحَابُ الشَّجَرَةِ أَلْفًا وَثَلَاثَ مِائَةٍ وَكَانَتْ أَسْلَمُ ثُمْنَ الْمُهَاجِرِينَو حَدَّثَنَا ابْنُ الْمُثَنَّى حَدَّثَنَا أَبُو دَاوُدَ ح و حَدَّثَنَاه إِسْحَقُ بْنُ إِبْرَاهِيمَ أَخْبَرَنَا النَّضْرُ بْنُ شُمَيْلٍ جَمِيعًا عَنْ شُعْبَةَ بِهَذَا الْإِسْنَادِ مِثْلَهُ","id":"Telah menceritakan kepada kami ['Ubaidullah bin Mu'adz] telah menceritakan kepada kami [ayahku] telah menceritakan kepada kami [Syu'bah] dari ['Amru] -yaitu Ibnu Murrah- telah menceritakan kepadaku [Abdullah bin Abu Aufa] dia berkata, \"Sahabat yang menyaksikan bai'at di bawah pohon berjumlah seribu tiga ratus orang, dan suku Aslam (jumlahnya) seperdelapan kaum muhajirin.\" Dan telah menceritakan kepada kami [Ibnu Al Mutsanna] telah menceritakan kepada kami [Abu Daud]. (dalam jalur lain disebutkan) Telah menceritakan kepada kami [Ishaq bin Ibrahim] telah mengabarkan kepada kami [An Nadlr bin Syumail] semuanya dari [Syu'bah] dengan isnad seperti ini.\""},"3221":{"ar":"و حَدَّثَنَاه حَامِدُ بْنُ عُمَرَ حَدَّثَنَا أَبُو عَوَانَةَ عَنْ طَارِقٍ عَنْ سَعِيدِ بْنِ الْمُسَيَّبِ قَالَكَانَ أَبِي مِمَّنْ بَايَعَ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عِنْدَ الشَّجَرَةِ قَالَ فَانْطَلَقْنَا فِي قَابِلٍ حَاجِّينَ فَخَفِيَ عَلَيْنَا مَكَانُهَا فَإِنْ كَانَتْ تَبَيَّنَتْ لَكُمْ فَأَنْتُمْ أَعْلَمُ","id":"Dan Telah menceritakan kepada kami [Hamid bin Umar] telah menceritakan kepada kami [Abu 'Awanah] dari [Thariq] dari [Sa'id bin Musayyab] dia berkata, \"[Ayahku] termasuk salah seorang yang pernah berbai'at kepada Rasulullah shallallahu 'alaihi wasallam ketika peristiwa pembaiatan di bawah pohon.\" Dia berkata, \"Kemudian kami hendak mengunjungi (pohon tersebut) di musim haji tahun depannya, ternyata (pohon tersebut) sudah tidak kami dapati, jika ia masih ada tentu kalian lebih mengetahui.\""},"3222":{"ar":"و حَدَّثَنِيهِ مُحَمَّدُ بْنُ رَافِعٍ حَدَّثَنَا أَبُو أَحْمَدَ قَالَ وَقَرَأْتُهُ عَلَى نَصْرِ بْنِ عَلِيٍّ عَنْ أَبِي أَحْمَدَ حَدَّثَنَا سُفْيَانُ عَنْ طَارِقِ بْنِ عَبْدِ الرَّحْمَنِ عَنْ سَعِيدِ بْنِ الْمُسَيَّبِ عَنْ أَبِيهِأَنَّهُمْ كَانُوا عِنْدَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَامَ الشَّجَرَةِ قَالَ فَنَسُوهَا مِنْ الْعَامِ الْمُقْبِلِ","id":"Dan telah menceritakan kepadaku [Muhammad bin Rafi'] telah menceritakan kepada kami [Abu Ahmad] dia berkata; dan saya telah membacanya di hadapan [Nashr bin Ali]; dari [Abu Ahmad] telah menceritakan kepada kami [Sufyan] dari [Thariq bin Abdurrahman] dari [Sa'id bin Musayyab] dari [ayahnya], bahwa para sahabat berada di sisi Rasulullah shallallahu 'alaihi wasallam ketika peristiwa pembaiatan di bawah pohon.\" Dia berkata, \"Ternyata pohon tersebut sudah tidak ada ketika ditahun depannya.\""},"3223":{"ar":"و حَدَّثَنَا قُتَيْبَةُ بْنُ سَعِيدٍ حَدَّثَنَا حَاتِمٌ يَعْنِي ابْنَ إِسْمَعِيلَ عَنْ يَزِيدَ بْنِ أَبِي عُبَيْدٍ مَوْلَى سَلَمَةَ بْنِ الْأَكْوَعِ قَالَقُلْتُ لِسَلَمَةَ عَلَى أَيِّ شَيْءٍ بَايَعْتُمْ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَوْمَ الْحُدَيْبِيَةِ قَالَ عَلَى الْمَوْتِو حَدَّثَنَاه إِسْحَقُ بْنُ إِبْرَاهِيمَ حَدَّثَنَا حَمَّادُ بْنُ مَسْعَدَةَ حَدَّثَنَا يَزِيدُ عَنْ سَلَمَةَ بِمِثْلِهِ","id":"Telah menceritakan kepada kami [Qutaibah bin Sa'id] telah menceritakan kepada kami [Hatim] -yaitu Ibnu Isma'il- dari [Yazid bin Abu 'Ubaid] bekas budak Salmah bin Al Akwa', dia berkata, \"Saya bertanya kepada [Salamah], \"Atas dasar apakah kalian berbai'at kepada Rasulullah shallallahu 'alaihi wasallam ketika peristiwa Hudaibiyyah?\" dia menjawab, \"Atas kematian.\" Dan telah menceritakan kepada kami [Ishaq bin Ibrahim] telah menceritakan kepada kami [Hammad bin Mas'adah] telah menceritakan kepada kami [Yazid] dari [Salamah] seperti hadits di atas.\""},"3224":{"ar":"حَدَّثَنَا قُتَيْبَةُ بْنُ سَعِيدٍ حَدَّثَنَا حَاتِمٌ يَعْنِي ابْنَ إِسْمَعِيلَ عَنْ يَزِيدَ بْنِ أَبِي عُبَيْدٍ عَنْ سَلَمَةَ بْنِ الْأَكْوَعِأَنَّهُ دَخَلَ عَلَى الْحَجَّاجِ فَقَالَ يَا ابْنَ الْأَكْوَعِ ارْتَدَدْتَ عَلَى عَقِبَيْكَ تَعَرَّبْتَ قَالَ لَا وَلَكِنْ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَذِنَ لِي فِي الْبَدْوِ","id":"Telah menceritakan kepada kami [Qutaibah bin Sa'id] telah menceritakan kepada kami [Hatim] -yaitu Ibnu Isma'il- dari [Yazid bin Abu 'Ubaid] dari [Salamah bin Al Akwa'] bahwa dia pernah menemui Al Hajjaj, lalu Hajjaj berkata, \"Wahai Ibnu Al Akwa', apakah kamu kembali murtad hingga kamu kembali menuju ke perkampunganmu? Dia menjawab, \"Tidak, akan tetapi Rasulullah shallallahu 'alaihi wasallam telah mengizinkanku untuk tinggal di dusun.\""},"3225":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ الصَّبَّاحِ أَبُو جَعْفَرٍ حَدَّثَنَا إِسْمَعِيلُ بْنُ زَكَرِيَّاءَ عَنْ عَاصِمٍ الْأَحْوَلِ عَنْ أَبِي عُثْمَانَ النَّهْدِيِّ حَدَّثَنِي مُجَاشِعُ بْنُ مَسْعُودٍ السُّلَمِيُّ قَالَأَتَيْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أُبَايِعُهُ عَلَى الْهِجْرَةِ فَقَالَ إِنَّ الْهِجْرَةَ قَدْ مَضَتْ لِأَهْلِهَا وَلَكِنْ عَلَى الْإِسْلَامِ وَالْجِهَادِ وَالْخَيْرِ","id":"Telah menceritakan kepada kami [Muhammad bin As Shabbah Abu Ja'far] telah menceritakan kepada kami [Isma'il bin Zakaria] dari ['Ashim Al Ahwal] dari [Abu Utsman An Nahdi] telah menceritakan kepadaku [Mujasyi' bin Mas'ud As Sulami] dia berkata, \"Saya pernah menemui Nabi shallallahu 'alaihi wasallam untuk berbai'at kepadanya atas Hijrah, namun beliau bersabda: \"Sesungguhnya hijrah telah berlalu, akan tetapi (berbaiatlah) atas Islam, Jihad dan kebaikan.\""},"3226":{"ar":"و حَدَّثَنِي سُوَيْدُ بْنُ سَعِيدٍ حَدَّثَنَا عَلِيُّ بْنُ مُسْهِرٍ عَنْ عَاصِمٍ عَنْ أَبِي عُثْمَانَ قَالَ أَخْبَرَنِي مُجَاشِعُ بْنُ مَسْعُودٍ السُّلَمِيُّ قَالَجِئْتُ بِأَخِي أَبِي مَعْبَدٍ إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بَعْدَ الْفَتْحِ فَقُلْتُ يَا رَسُولَ اللَّهِ بَايِعْهُ عَلَى الْهِجْرَةِ قَالَ قَدْ مَضَتْ الْهِجْرَةُ بِأَهْلِهَا قُلْتُ فَبِأَيِّ شَيْءٍ تُبَايِعُهُ قَالَ عَلَى الْإِسْلَامِ وَالْجِهَادِ وَالْخَيْرِقَالَ أَبُو عُثْمَانَ فَلَقِيتُ أَبَا مَعْبَدٍ فَأَخْبَرْتُهُ بِقَوْلِ مُجَاشِعٍ فَقَالَ صَدَقَ حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا مُحَمَّدُ بْنُ فُضَيْلٍ عَنْ عَاصِمٍ بِهَذَا الْإِسْنَادِ قَالَ فَلَقِيتُ أَخَاهُ فَقَالَ صَدَقَ مُجَاشِعٌ وَلَمْ يَذْكُرْ أَبَا مَعْبَدٍ","id":"Dan telah menceritakan kepada kami [Suwaid bin Sa'id] telah menceritakan kepada kami ['Ali bin Mushir] dari ['Ashim] dari [Abu Utsman] dia berkata; telah mengabarkan kepadaku [Mujasyi' bin Masy'ud As Sulami] dia berkata, \"Aku datang bersama saudaraku, Abu Ma'bad, kepada Rasulullah shallallahu 'alaihi wasallam setelah penaklukan Makkah. Aku berkata kepada beliau, \"Ya Rasulullah! Bai'atlah dia untuk hijrah.\" Beliau lalu menjawab: \"Hijrah telah selesai bagi penduduknya.\" Aku lalu bertanya, \"Lalu atas apa ia harus berbai'at?\" Beliau menjawab: \"Untuk Islam, Jihad, dan Kebajikan.\" [Abu Utsman] berkata, \"Kemudian aku menemui [Abu Ma'bad] dan memberitahukan kepadanya apa yang dikatakan Mujasyi'. Maka ia pun berkata, \"Dia benar.\" Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] telah menceritakan kepada kami [Muhammad bin Fudlail] dari ['Ashim] dengan isnad, dia menyebutkan, 'Kemudian saya menemui saudaranya, saudaranya pun menjawab, 'Majasyi' benar.' Namun ia tidak menyebutkan Abu Ma'bad.\""},"3227":{"ar":"حَدَّثَنَا يَحْيَى بْنُ يَحْيَى وَإِسْحَقُ بْنُ إِبْرَاهِيمَ قَالَا أَخْبَرَنَا جَرِيرٌ عَنْ مَنْصُورٍ عَنْ مُجَاهِدٍ عَنْ طَاوُسٍ عَنْ ابْنِ عَبَّاسٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَوْمَ الْفَتْحِ فَتْحِ مَكَّةَ لَا هِجْرَةَ وَلَكِنْ جِهَادٌ وَنِيَّةٌ وَإِذَا اسْتُنْفِرْتُمْ فَانْفِرُواو حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ وَأَبُو كُرَيْبٍ قَالَا حَدَّثَنَا وَكِيعٌ عَنْ سُفْيَانَ ح و حَدَّثَنَا إِسْحَقُ بْنُ مَنْصُورٍ وَابْنُ رَافِعٍ عَنْ يَحْيَى بْنِ آدَمَ حَدَّثَنَا مُفَضَّلٌ يَعْنِي ابْنَ مُهَلْهِلٍ ح و حَدَّثَنَا عَبْدُ بْنُ حُمَيْدٍ أَخْبَرَنَا عُبَيْدُ اللَّهِ بْنُ مُوسَى عَنْ إِسْرَائِيلَ كُلُّهُمْ عَنْ مَنْصُورٍ بِهَذَا الْإِسْنَادِ مِثْلَهُ","id":"Telah menceritakan kepada kami [Yahya bin Yahya] dan [Ishaq bin Ibrahim] dia berkata; telah mengabarkan kepada kami [Jarir] dari [Mansyur] dari [Mujahid] dari [Thawus] dari [Ibnu Abbas] Rasulullah shallallahu 'alaihi wasallam bersabda pada waktu penaklukan kota Makkah: \"Tidak ada hijrah lagi setelah penaklukan kota Makkah, yang ada adalah Jihad dan Niat. Jika kamu diperintahkan untuk berjihad (berjuang atau berperang) maka patuhilah!\" Dan telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] dan [Abu Kuraib] dia berkata; telah menceritakan kepada kami [Waki'] dari [Sufyan]. (dalam jalur lain disebutkan) Telah menceritakan kepada kami [Ishaq bin Mansyur] dan [Ibnu Rafi'] dari [Yahya bin Adam] telah menceritakan kepada kami [Mufadlal] -yaitu Ibnu Muhalhil-. (dalam jalur lain disebutkan) Telah menceritakan kepada kami ['Abd bin Humaid] telah mengabarkan kepada kami ['Ubaidullah bin Musa] dari [Isra'il] semuanya dari [Mansyur] dengan sanad ini, seprti hadits tersebut.\""},"3228":{"ar":"و حَدَّثَنَا مُحَمَّدُ بْنُ عَبْدِ اللَّهِ بْنِ نُمَيْرٍ حَدَّثَنَا أَبِي حَدَّثَنَا عَبْدُ اللَّهِ بْنُ حَبِيبِ بْنِ أَبِي ثَابِتٍ عَنْ عَبْدِ اللَّهِ بْنِ عَبْدِ الرَّحْمَنِ بْنِ أَبِي حُسَيْنٍ عَنْ عَطَاءٍ عَنْ عَائِشَةَ قَالَتْسُئِلَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ الْهِجْرَةِ فَقَالَ لَا هِجْرَةَ بَعْدَ الْفَتْحِ وَلَكِنْ جِهَادٌ وَنِيَّةٌ وَإِذَا اسْتُنْفِرْتُمْ فَانْفِرُوا","id":"Telah menceritakan kepada kami [Muhammad bin Abdullah bin Numair] telah menceritakan kepada kami [ayahku] telah menceritakan kepada kami [Abdullah bin Habib bin Abu Tsabit] dari [Abdullah bin Abdurrahman bin Abu Husain] dari ['Atha] dari ['Aisyah] dia berkata, \"Rasulullah shallallahu 'alaihi wasallam pernah ditanya perihal hijrah.\" Beliau menjawab: \"Tidak ada hijrah setelah Fathu Makkah, namun yang ada hanyalah jihad dan niat (yang baik-pent). Dan apabila kalian diminta untuk pergi berperang, maka pergilah kalian ke medan perang.\""},"3229":{"ar":"و حَدَّثَنَا أَبُو بَكْرِ بْنُ خَلَّادٍ الْبَاهِلِيُّ حَدَّثَنَا الْوَلِيدُ بْنُ مُسْلِمٍ حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ عَمْرٍو الْأَوْزَاعِيُّ حَدَّثَنِي ابْنُ شِهَابٍ الزُّهْرِيِّ حَدَّثَنِي عَطَاءُ بْنُ يَزِيدَ اللَّيْثِيُّ أَنَّهُ حَدَّثَهُمْ قَالَ حَدَّثَنِي أَبُو سَعِيدٍ الْخُدْرِيُّأَنَّ أَعْرَابِيًّا سَأَلَ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ الْهِجْرَةِ فَقَالَ وَيْحَكَ إِنَّ شَأْنَ الْهِجْرَةِ لَشَدِيدٌ فَهَلْ لَكَ مِنْ إِبِلٍ قَالَ نَعَمْ قَالَ فَهَلْ تُؤْتِي صَدَقَتَهَا قَالَ نَعَمْ قَالَ فَاعْمَلْ مِنْ وَرَاءِ الْبِحَارِ فَإِنَّ اللَّهَ لَنْ يَتِرَكَ مِنْ عَمَلِكَ شَيْئًاو حَدَّثَنَاه عَبْدُ اللَّهِ بْنُ عَبْدِ الرَّحْمَنِ الدَّارِمِيُّ حَدَّثَنَا مُحَمَّدُ بْنُ يُوسُفَ عَنْ الْأَوْزَاعِيِّ بِهَذَا الْإِسْنَادِ مِثْلَهُ غَيْرَ أَنَّهُ قَالَ إِنَّ اللَّهَ لَنْ يَتِرَكَ مِنْ عَمَلِكَ شَيْئًا وَزَادَ فِي الْحَدِيثِ قَالَ فَهَلْ تَحْلُبُهَا يَوْمَ وِرْدِهَا قَالَ نَعَمْ","id":"Dan telah menceritakan kepada kami [Abu Bakr bin Khallad Al Bahili] telah menceritakan kepada kami [Al Walid bin Muslim] telah menceritakan kepada kami [Abdurrahman bin 'Amr Al Auza'i] telah menceritakan kepadaku [Ibnu Syihab Az Zuhri] telah menceritakan kepadaku ['Atha bin Yazid Al Laitsi], bahwa dia telah menceritakan kepada mereka, dia berkata; telah menceritakan kepadaku [Abu Sa'id Al Khudri] dia berkata, \"Seorang arab badui bertanya kepada Rasulullah shallallahu 'alaihi wasallam mengenai hijrah.\" Beliau lalu menjawab: \"Celaka kamu! Sesungguhnya perkara hijrah itu sangat berat. Apakah kamu mempunyai unta?\" Badui itu menjawab: \"Ada.\" Beliau bertanya: \"Apakah kamu telah membayar zakatnya?\" dia menjawab, \"Ya!\" beliau bersabda: \"Kalau begitu beramallah di negerimu, sesungguhnya Allah Ta'ala tidak akan menyia-nyiakan pahala amalmu sedikitpun juga.\" Dan telah menceritakan kepada kami ['Abdullah bin 'Abdurrahman Ad Darami] telah menceritakan kepada kami [Muhammad bin Yusuf] dari [Auza'i] dengan isnad seperti ini, namun dia menyebutkan, 'Sesungguhnya Allah tidak menyia-nyiakan dari amalanmu sedikitpun.' Dan dalam hadits tersebut juga ditambahkan, beliau bersabda: \"Apakah kamu telah memerah susunya?\" dia menjawab, \"Ya.\""},"3230":{"ar":"حَدَّثَنِي أَبُو الطَّاهِرِ أَحْمَدُ بْنُ عَمْرِو بْنِ سَرْحٍ أَخْبَرَنَا ابْنُ وَهْبٍ أَخْبَرَنِي يُونُسُ بْنُ يَزِيدَ قَالَ قَالَ ابْنُ شِهَابٍ أَخْبَرَنِي عُرْوَةُ بْنُ الزُّبَيْرِ أَنَّ عَائِشَةَ زَوْجَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَتْكَانَتْ الْمُؤْمِنَاتُ إِذَا هَاجَرْنَ إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُمْتَحَنَّ بِقَوْلِ اللَّهِ عَزَّ وَجَلَّ{ يَا أَيُّهَا النَّبِيُّ إِذَا جَاءَكَ الْمُؤْمِنَاتُ يُبَايِعْنَكَ عَلَى أَنْ لَا يُشْرِكْنَ بِاللَّهِ شَيْئًا وَلَا يَسْرِقْنَ وَلَا يَزْنِينَ }إِلَى آخِرِ الْآيَةِ قَالَتْ عَائِشَةُ فَمَنْ أَقَرَّ بِهَذَا مِنْ الْمُؤْمِنَاتِ فَقَدْ أَقَرَّ بِالْمِحْنَةِ وَكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا أَقْرَرْنَ بِذَلِكَ مِنْ قَوْلِهِنَّ قَالَ لَهُنَّ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ انْطَلِقْنَ فَقَدْ بَايَعْتُكُنَّ وَلَا وَاللَّهِ مَا مَسَّتْ يَدُ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَدَ امْرَأَةٍ قَطُّ غَيْرَ أَنَّهُ يُبَايِعُهُنَّ بِالْكَلَامِ قَالَتْ عَائِشَةُ وَاللَّهِ مَا أَخَذَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَلَى النِّسَاءِ قَطُّ إِلَّا بِمَا أَمَرَهُ اللَّهُ تَعَالَى وَمَا مَسَّتْ كَفُّ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَفَّ امْرَأَةٍ قَطُّ وَكَانَ يَقُولُ لَهُنَّ إِذَا أَخَذَ عَلَيْهِنَّ قَدْ بَايَعْتُكُنَّ كَلَامًا","id":"Telah menceritakan kepadaku [Abu At Thahir Ahmad bin 'Amru bin Sarh] telah mengabarkan kepada kami [Ibnu Wahb] telah mengabarkan kepadaku [Yunus bin Yazid] dia berkata; [Ibnu Syihab] berkata; telah mengabarkan kepadaku ['Urwah bin Az Zubair] bahwa ['Aisyah] isteri Nabi shallallahu 'alaihi wasallam, bertanya, \"Apabila para wanita yang beriman hijrah kepada Rasulullah shallallahu 'alaihi wasallam, mereka selalu diuji sebagaimana dalam firman Allah 'azza wajalla: '(Hai nabi, apabila datang kepadamu perempuan-perempuan yang beriman untuk mengadakan 'janji setia, bahwa mereka tiada akan menyekutukan Allah, tidak akan mencuri, tidak akan berzina …) ' (Qs. Mumtahanah: 12). 'Aisyah berkata, \"Siapa yang memegang teguh janji-janji tersebut dengan setia, berarti mereka lulus dari ujian, dan apabila mereka telah mengingrarkan janji tersebut dengan ucapan mereka di hadapan Rasulullah shallallahu 'alaihi wasallam, maka Rasulullah shallallahu 'alaihi wasallam bersabda kepada mereka: \"Pergilah, sesungguhnya kalian telah berbai'at kepadaku.\" Demi Allah, Rasulullah shallallahu 'alaihi wasallam tidak pernah memegang tangan seorang wanita pun, beliau membaiat mereka dengan ucapan. Aisyah melanjutkan, \"Demi Allah, Rasulullah shallallahu 'alaihi wasallam tidak pernah mengambil sumpah kepada kaum wanita kecuali atas apa yang diperintahkan oleh Allah, dan beliau tidak pernah menyentuh telapak seorang wanita pun, apabila beliau membai'at mereka, beliau hanya mengucapkan; \"Sesungguhnya saya telah membai'at kalian.\""},"3231":{"ar":"و حَدَّثَنِي هَارُونُ بْنُ سَعِيدٍ الْأَيْلِيُّ وَأَبُو الطَّاهِرِ قَالَ أَبُو الطَّاهِرِ أَخْبَرَنَا و قَالَ هَارُونُ حَدَّثَنَا ابْنُ وَهْبٍ حَدَّثَنِي مَالِكٌ عَنْ ابْنِ شِهَابٍ عَنْ عُرْوَةَ أَنَّ عَائِشَةَ أَخْبَرَتْهُعَنْ بَيْعَةِ النِّسَاءِ قَالَتْ مَا مَسَّ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِيَدِهِ امْرَأَةً قَطُّ إِلَّا أَنْ يَأْخُذَ عَلَيْهَا فَإِذَا أَخَذَ عَلَيْهَا فَأَعْطَتْهُ قَالَ اذْهَبِي فَقَدْ بَايَعْتُكِ","id":"Dan telah menceritakan kepadaku [Harun bin Sa'id Al Aili] dan [Abu At Thahir], [Abu At Thahir] berkata; telah mengabarkan kepada kami, dan [Harun] berkata; telah menceritakan kepada kami [Ibnu Wahb] telah menceritakan kepadaku [Malik] dari [Ibnu Syihab] dari ['Urwah], bahwa ['Aisyah] telah mengabarkan kepadanya mengenai proses pembai'atan terhadap kaum wanita, dia berkata, \"Rasulullah shallallahu 'alaihi wasallam tidak pernah menyentuh tangan seorang wanita manapun, beliau hanya mengambil baiat dari mereka. Ketika mereka telah memberikan baiatnya kepada beliau, maka beliau bersabda: \"Pergilah, sungguh aku telah membaiat kamu.\""},"3232":{"ar":"حَدَّثَنَا يَحْيَى بْنُ أَيُّوبَ وَقُتَيْبَةُ وَابْنُ حُجْرٍ وَاللَّفْظُ لِابْنِ أَيُّوبَ قَالُوا حَدَّثَنَا إِسْمَعِيلُ وَهُوَ ابْنُ جَعْفَرٍ أَخْبَرَنِي عَبْدُ اللَّهِ بْنُ دِينَارٍ أَنَّهُ سَمِعَ عَبْدَ اللَّهِ بْنَ عُمَرَ يَقُولُاكُنَّا نُبَايِعُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَلَى السَّمْعِ وَالطَّاعَةِ يَقُولُ لَنَا فِيمَا اسْتَطَعْتَ","id":"Telah menceritakan kepada kami [Yahya bin Ayyub] dan [Qutaibah] dan [Ibnu Hujr] dan ini adalah lafadz Ibnu Ayyub, mereka berkata; telah menceritakan kepada kami [Isma'il] -yaitu Ibnu Ja'far- telah mengabarkan kepadaku [Abdullah bin Dinar] bahwa dia mendengar [Abdullah bin Umar] berkata, \"Kami berbai'at kepada Rasulullah shallallahu 'alaihi wasallam untuk selalu mendengar dan taat, beliau bersabda: \"Sesuai dengan kemampuan kamu.\""},"3233":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ عَبْدِ اللَّهِ بْنِ نُمَيْرٍ حَدَّثَنَا أَبِي حَدَّثَنَا عُبَيْدُ اللَّهِ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَ قَالَعَرَضَنِي رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَوْمَ أُحُدٍ فِي الْقِتَالِ وَأَنَا ابْنُ أَرْبَعَ عَشْرَةَ سَنَةً فَلَمْ يُجِزْنِي وَعَرَضَنِي يَوْمَ الْخَنْدَقِ وَأَنَا ابْنُ خَمْسَ عَشْرَةَ سَنَةً فَأَجَازَنِيقَالَ نَافِعٌ فَقَدِمْتُ عَلَى عُمَرَ بْنِ عَبْدِ الْعَزِيزِ وَهُوَ يَوْمَئِذٍ خَلِيفَةٌ فَحَدَّثْتُهُ هَذَا الْحَدِيثَ فَقَالَ إِنَّ هَذَا لَحَدٌّ بَيْنَ الصَّغِيرِ وَالْكَبِيرِ فَكَتَبَ إِلَى عُمَّالِهِ أَنْ يَفْرِضُوا لِمَنْ كَانَ ابْنَ خَمْسَ عَشْرَةَ سَنَةً وَمَنْ كَانَ دُونَ ذَلِكَ فَاجْعَلُوهُ فِي الْعِيَالِ و حَدَّثَنَاه أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ إِدْرِيسَ وَعَبْدُ الرَّحِيمِ بْنُ سُلَيْمَانَ ح و حَدَّثَنَا مُحَمَّدُ بْنُ الْمُثَنَّى حَدَّثَنَا عَبْدُ الْوَهَّابِ يَعْنِي الثَّقَفِيَّ جَمِيعًا عَنْ عُبَيْدِ اللَّهِ بِهَذَا الْإِسْنَادِ غَيْرَ أَنَّ فِي حَدِيثِهِمْ وَأَنَا ابْنُ أَرْبَعَ عَشْرَةَ سَنَةً فَاسْتَصْغَرَنِي","id":"Telah menceritakan kepada kami [Muhammad bin Abdullah bin Numair] telah menceritakan kepada kami [ayahku] telah menceritakan kepada kami ['Ubaidullah] dari [Nafi'] dari [Ibnu Umar] dia berkata, \"Rasulullah shallallahu 'alaihi wasallam memeriksaku ketika hendak berangkat perang Uhud, ketika itu saya baru berusai empat belas tahun, sehingga beliau pun tidak membolehkan aku ikut pergi berperang. ketika hendak berangkat ke medan perang (Khandaq), beliau memeriksaku pula. Ketika itu saya telah berusai lima belas tahun, dan beliau membolehkanku ikut berperang.\" Nafi' berkata, \"Maka saya mendatangi 'Umar bin Abdul Aziz -ketika itu dia telah menjabat sebagai Khalifah-, lalu saya menyampaikan kepadanya hadits tersebut. dia berkata, \"Sesungguhnya itu adalah batas antara usia kecil dan usia dewasa.\" Lalu dia menulis surat kepada pegawainya supaya mereka mewajibkan pelaksanaan tugas-tugas agama (Mukallaf) bagi setiap anak yang telah mencapai usia lima belas tahun. Anak yang kurang dari usia tersebut menjadi tanggung jawab keluarganya.\" Dan telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] telah menceritakan kepada kami [Abdullah bin Idris] dan [Abdurrahim bin Sulaiman]. (dalam jalur lain disebutkan) Telah menceritakan kepada kami [Muhammad bin Al Mutsanna] telah menceritakan kepada kami [Abdul Wahab] -yaitu At Tsaqafi- semuanya dari ['Ubaidullah] dengan isnad ini, namun dalam hadits mereka disebutkan, \"Sedangkan saya berusia empat belas tahun, maka beliau menganggapku masih kecil.\""},"3234":{"ar":"حَدَّثَنَا يَحْيَى بْنُ يَحْيَى قَالَ قَرَأْتُ عَلَى مَالِكٍ عَنْ نَافِعٍ عَنْ عَبْدِ اللَّهِ بْنِ عُمَرَ قَالَنَهَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنْ يُسَافَرَ بِالْقُرْآنِ إِلَى أَرْضِ الْعَدُوِّ","id":"Telah menceritakan kepada kami [Yahya bin Yahya] dia berkata; saya membacakan di hadapan [Malik]; dari [Nafi'] dari [Abdullah bin Umar] dia berkata, \"Rasulullah shallallahu 'alaihi wasallam melarang membawa mushaf Al Qur'an ke daerah musuh.\""},"3235":{"ar":"و حَدَّثَنَا قُتَيْبَةُ حَدَّثَنَا لَيْثٌ ح و حَدَّثَنَا ابْنُ رُمْحٍ أَخْبَرَنَا اللَّيْثُ عَنْ نَافِعٍ عَنْ عَبْدِ اللَّهِ بْنِ عُمَرَعَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهُ كَانَ يَنْهَى أَنْ يُسَافَرَ بِالْقُرْآنِ إِلَى أَرْضِ الْعَدُوِّ مَخَافَةَ أَنْ يَنَالَهُ الْعَدُوُّ","id":"Dan telah menceritakan kepada kami [Qutaibah] telah menceritakan kepada kami [Laits]. (dalam jalur lain disebutkan) Telah menceritakan kepada kami [Ibnu Rumh] telah mengabarkan kepada kami [Al Laits] dari [Nafi'] dari [Abdullah bin Umar] dari Rasulullah shallallahu 'alaihi wasallam, bahwa beliau melarang membawa Mushaf Al Qur'an ke negeri musuh, karena beliau khawatir apabila nantinya akan diambil musuh.\""},"3236":{"ar":"و حَدَّثَنَا أَبُو الرَّبِيعِ الْعَتَكِيُّ وَأَبُو كَامِلٍ قَالَا حَدَّثَنَا حَمَّادٌ عَنْ أَيُّوبَ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا تُسَافِرُوا بِالْقُرْآنِ فَإِنِّي لَا آمَنُ أَنْ يَنَالَهُ الْعَدُوُّقَالَ أَيُّوبُ فَقَدْ نَالَهُ الْعَدُوُّ وَخَاصَمُوكُمْ بِهِ حَدَّثَنِي زُهَيْرُ بْنُ حَرْبٍ حَدَّثَنَا إِسْمَعِيلُ يَعْنِي ابْنَ عُلَيَّةَ ح و حَدَّثَنَا ابْنُ أَبِي عُمَرَ حَدَّثَنَا سُفْيَانُ وَالثَّقَفِيُّ كُلُّهُمْ عَنْ أَيُّوبَ ح و حَدَّثَنَا ابْنُ رَافِعٍ حَدَّثَنَا ابْنُ أَبِي فُدَيْكٍ أَخْبَرَنَا الضَّحَّاكُ يَعْنِي ابْنَ عُثْمَانَ جَمِيعًا عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي حَدِيثِ ابْنِ عُلَيَّةَ وَالثَّقَفِيِّ فَإِنِّي أَخَافُ وَفِي حَدِيثِ سُفْيَانَ وَحَدِيثِ الضَّحَّاكِ بْنِ عُثْمَانَ مَخَافَةَ أَنْ يَنَالَهُ الْعَدُوُّ","id":"Dan telah menceritakan kepada kami [Abu Ar Rabi' Al Ataki] dan [Abu Kamil] keduanya berkata; telah menceritakan kepada kami [Hammad] dari [Ayyub] dari [Nafi'] dari [Ibnu Umar] dia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Janganlah kalian bepergian dengan membawa Mushaf Al Qur'an saat safar (ke negeri musuh), sebab saya merasa khawatir diambil musuh.\" Ayyub berkata, \"Mereka akan mengambilnya lalu memusuhi kalian dengannya.\" Dan telah menceritakan kepadaku [Zuhair bin harb] telah menceritakan kepada kami [Isma'il] -yaitu Ibnu 'Ulaiyah-. (dalam jalur lain disebutkan) Telah menceritakan kepada kami [Ibnu Abu Umar] telah menceritakan kepada kami [Sufyan] dan [Ats Tsaqafi] semuanya dari [Ayyub]. (dalam jalur lain disebutkan) Telah menceritakan kepada kami [Ibnu Rafi'] telah menceritakan kepada kami [Ibnu Abu Fudaik] telah mengabarkan kepada kami [Adl Dlahak] -yaitu Ibnu Utsman- semuanya dari [Nafi'] dari [Ibnu Umar] dari Nabi shallallahu 'alaihi wasallam dalam hadits Ibnu 'Ulayyah dan Ats Tsaqafi disebutkan, \"Sesungguhnya saya khawatir.\" Sedangkan dalam hadits Sufyan dan hadits Dlahak bin Utsman disebutkan, \"Khawatir akan diambil oleh musuh.\""},"3237":{"ar":"حَدَّثَنَا يَحْيَى بْنُ يَحْيَى التَّمِيمِيُّ قَالَ قَرَأْتُ عَلَى مَالِكٍ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ سَابَقَ بِالْخَيْلِ الَّتِي قَدْ أُضْمِرَتْ مِنْ الْحَفْيَاءِ وَكَانَ أَمَدُهَا ثَنِيَّةَ الْوَدَاعِ وَسَابَقَ بَيْنَ الْخَيْلِ الَّتِي لَمْ تُضْمَرْ مِنْ الثَّنِيَّةِ إِلَى مَسْجِدِ بَنِي زُرَيْقٍوَكَانَ ابْنُ عُمَرَ فِيمَنْ سَابَقَ بِهَا و حَدَّثَنَا يَحْيَى بْنُ يَحْيَى وَمُحَمَّدُ بْنُ رُمْحٍ وَقُتَيْبَةُ بْنُ سَعِيدٍ عَنْ اللَّيْثِ بْنِ سَعْدٍ ح و حَدَّثَنَا خَلَفُ بْنُ هِشَامٍ وَأَبُو الرَّبِيعِ وَأَبُو كَامِلٍ قَالُوا حَدَّثَنَا حَمَّادٌ وَهُوَ ابْنُ زَيْدٍ عَنْ أَيُّوبَ ح و حَدَّثَنَا زُهَيْرُ بْنُ حَرْبٍ حَدَّثَنَا إِسْمَعِيلُ عَنْ أَيُّوبَ ح و حَدَّثَنَا ابْنُ نُمَيْرٍ حَدَّثَنَا أَبِي ح و حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا أَبُو أُسَامَةَ ح و حَدَّثَنَا مُحَمَّدُ بْنُ الْمُثَنَّى وَعُبَيْدُ اللَّهِ بْنُ سَعِيدٍ قَالَا حَدَّثَنَا يَحْيَى وَهُوَ الْقَطَّانُ جَمِيعًا عَنْ عُبَيْدِ اللَّهِ ح و حَدَّثَنِي عَلِيُّ بْنُ حُجْرٍ وَأَحْمَدُ بْنُ عَبْدَةَ وَابْنُ أَبِي عُمَرَ قَالُوا حَدَّثَنَا سُفْيَانُ عَنْ إِسْمَعِيلَ بْنِ أُمَيَّةَ ح و حَدَّثَنِي مُحَمَّدُ بْنُ رَافِعٍ حَدَّثَنَا عَبْدُ الرَّزَّاقِ أَخْبَرَنَا ابْنُ جُرَيْجٍ أَخْبَرَنِي مُوسَى بْنُ عُقْبَةَ ح و حَدَّثَنَا هَارُونُ بْنُ سَعِيدٍ الْأَيْلِيُّ حَدَّثَنَا ابْنُ وَهْبٍ أَخْبَرَنِي أُسَامَةُ يَعْنِي ابْنَ زَيْدٍ كُلُّ هَؤُلَاءِ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَ بِمَعْنَى حَدِيثِ مَالِكٍ عَنْ نَافِعٍ وَزَادَ فِي حَدِيثِ أَيُّوبَ مِنْ رِوَايَةِ حَمَّادٍ وَابْنِ عُلَيَّةَ قَالَ عَبْدُ اللَّهِ فَجِئْتُ سَابِقًا فَطَفَّفَ بِي الْفَرَسُ الْمَسْجِدَ","id":"Telah menceritakan kepada kami [Yahya bin Yahya At Tamimi] dia berkata; saya membacakan di hadapan [Malik]; dari [Nafi'] dari [Ibnu Umar], bahwa Rasulullah shallallahu 'alaihi wasallam pernah mengadakan lomba pacuan kuda yang telah mengkabarkan kepada kamilah dilatih dari Haifa sampai ke Tsaniyatul Wada', dankuda yang belum dilatih dari Tsaniyah hingga Masjid Bani zurai'. Dan Ibnu'Umar sendiri turut dalam perlombaan itu.\" Dan telah menceritakan kepada kami [Yahya bin Yahya] dan [Muhammad bin Rumh] dan [Qutaibah bin Sa'id] dari [Al Laits bin Sa'd]. (dalam jalur lain disebutkan) Telah menceritakan kepada kami [Khalaf bin Hisyam] dan [Abu Ar Rabi'] dan [Abu Kamil] mereka berkata; telah menceritakan kepada kami [Hammad] -yaitu Ibnu Zaid- dari [Ayyub]. (dalam jalur lain disebutkan) Telah menceritakan kepada kami [Zuhair bin Harb] Telah menceritakan kepada kami [Isma'il] dari [Ayyub]. (Dalam jalur lain disebutkan) telah menceritakan kepada kami [Ibnu Numair] telah menceritakan kepada kami [ayahku]. (dalam jalur lain disebutkan) Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] telah menceritakan kepada kami [Abu Usamah]. (dalam jalur lain disebutkan) Telah menceritakan kepada kami [Muhammad bin Al Mutsanna] dan ['Ubaidullah bin Sa'id] keduanya berkata; telah menceritakan kepada kami [Yahya] -yaitu Al Qatthan- semuanya dari ['Ubaidullah]. (dalam jalur lain disebutkan) Telah menceritakan kepadaku [Ali bin Hujr] dan [Ahmad bin 'Abdah] dan [Ibnu Abu Umar] mereka berkata; telah menceritakan kepada kami [Sufyan] dari [Isma'il bin Umayyah]. (dalam jalur lain disebutkan) Telah menceritakan kepadaku [Muhammad bin Rafi'] telah menceritakan kepada kami [Abdurrazaq] telah mengabarkan kepada kami [Ibnu Juraij] telah mengabarkan kepadaku [Musa bin 'Uqbah]. (dalam jalur lain disebutkan) Telah menceritakan kepada kami [Harun bin Sa'id Al Aili] telah menceritakan kepada kami [Ibnu Wahb] telah mengabarkan kepadaku [Usamah] -yaitu Ibnu Zaid- semuanya dari [Nafi'] dari [Ibnu Umar] semakna dengan hadits Malik dari Nafi'. Dan ia menambahkan dalam hadits Ayyub dari riwayatnya Hammad dan Ibnu Ulayyah. Abdullah menyebutkan, \"Akhirnya aku sebagai pemenang, kuda itu sedemikian cepat menghantarkanku ke masjid dengan kecepatan langkah dan lompatnya.\""},"3238":{"ar":"حَدَّثَنَا يَحْيَى بْنُ يَحْيَى قَالَ قَرَأْتُ عَلَى مَالِكٍ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ الْخَيْلُ فِي نَوَاصِيهَا الْخَيْرُ إِلَى يَوْمِ الْقِيَامَةِو حَدَّثَنَا قُتَيْبَةُ وَابْنُ رُمْحٍ عَنْ اللَّيْثِ بْنِ سَعْدٍ ح و حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا عَلِيُّ بْنُ مُسْهِرٍ وَعَبْدُ اللَّهِ بْنُ نُمَيْرٍ ح و حَدَّثَنَا ابْنُ نُمَيْرٍ حَدَّثَنَا أَبِي ح و حَدَّثَنَا عُبَيْدُ اللَّهِ بْنُ سَعِيدٍ حَدَّثَنَا يَحْيَى كُلُّهُمْ عَنْ عُبَيْدِ اللَّهِ ح و حَدَّثَنَا هَارُونُ بْنُ سَعِيدٍ الْأَيْلِيُّ حَدَّثَنَا ابْنُ وَهْبٍ حَدَّثَنِي أُسَامَةُ كُلُّهُمْ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِمِثْلِ حَدِيثِ مَالِكٍ عَنْ نَافِعٍ","id":"Telah menceritakan kepada kami [Yahya bin Yahya] dia berkata; saya membacakan di hadapan [Malik]; dari [Nafi'] dari [Ibnu Umar], bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Pada ubun-ubun setiap kuda tertulis kebaikan hingga hari kiamat.\" Dan telah menceritakan kepada kami [Qutaibah] dan [Ibnu Rumh] dari [Al Laits bin Sa'd]. (dalam jalur lain disebutkan) Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] telah menceritakan kepada kami [Ali bin Mushir] dan [Abdullah bin Numair]. (dalam jalur lain disebutkan) Telah menceritakan kepada kami [Ibnu Numair] telah menceritakan kepada kami [ayahku]. (dalam jalur lain disebutkan) Telah menceritakan kepada kami ['Ubaidullah bin Sa'id] telah menceritakan kepada kami [Yahya] semuanya dari ['Ubaidullah]. (dalam jalur lain disebutkan) Telah menceritakan kepada kami [Harun bin Sa'id Al Aili] telah menceritakan kepada kami [Ibnu Wahb] telah menceritakan kepadaku [Usamah] semuanya dari [Nafi'] dari [Ibnu Umar] dari Nabi shallallahu 'alaihi wasallam seperti hadits Malik dari Nafi'.\""},"3239":{"ar":"و حَدَّثَنَا نَصْرُ بْنُ عَلِيٍّ الْجَهْضَمِيُّ وَصَالِحُ بْنُ حَاتِمِ بْنِ وَرْدَانَ جَمِيعًا عَنْ يَزِيدَ قَالَ الْجَهْضَمِيُّ حَدَّثَنَا يَزِيدُ بْنُ زُرَيْعٍ حَدَّثَنَا يُونُسُ بْنُ عُبَيْدٍ عَنْ عَمْرِو بْنِ سَعِيدٍ عَنْ أَبِي زُرْعَةَ بْنِ عَمْرِو بْنِ جَرِيرٍ عَنْ جَرِيرِ بْنِ عَبْدِ اللَّهِ قَالَرَأَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَلْوِي نَاصِيَةَ فَرَسٍ بِإِصْبَعِهِ وَهُوَ يَقُولُ الْخَيْلُ مَعْقُودٌ بِنَوَاصِيهَا الْخَيْرُ إِلَى يَوْمِ الْقِيَامَةِ الْأَجْرُ وَالْغَنِيمَةُو حَدَّثَنِي زُهَيْرُ بْنُ حَرْبٍ حَدَّثَنَا إِسْمَعِيلُ بْنُ إِبْرَاهِيمَ ح و حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا وَكِيعٌ عَنْ سُفْيَانَ كِلَاهُمَا عَنْ يُونُسَ بِهَذَا الْإِسْنَادِ مِثْلَهُ","id":"Dan telah menceritakan kepada kami [Nashr bin Ali Al Jahdlami] dan [Shalih bin Hatim bin Wardan] semuanya dari [Yazid], [Al Jahdlami] berkata; telah menceritakan kepada kami [Yazid bin Zurai'] telah menceritakan kepada kami [Yunus bin 'Ubaid] dari ['Amru bin Sa'id] dari [Abu Zur'ah bin 'Amru bin Jarir] dari [Jarir bin Abdullah] dia berkata, \"Saya pernah melihat Rasulullah shallallahu 'alaihi wasallam mengusap-usap ubun-ubun kuda dengan jari-jari beliau sambil bersabda: \"Setiap kuda pada ubun-ubunnya telah tertulis dengan kebaikan hingga datangnya hari kiamat, yakni pahala dan rampasan perang.\" Dan telah menceritakan kepadaku [Zuhair bin Harb] telah menceritakan kepada kami [Isma'il bin Ibrahim]. (dalam jalur lain disebutkan) Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] telah menceritakan kepada kami [Waki'] dari [Sufyan] keduanya dari [Yunus] dengan isnad seperti ini.\""},"3240":{"ar":"و حَدَّثَنَا مُحَمَّدُ بْنُ عَبْدِ اللَّهِ بْنِ نُمَيْرٍ حَدَّثَنَا أَبِي حَدَّثَنَا زَكَرِيَّاءُ عَنْ عَامِرٍ عَنْ عُرْوَةَ الْبَارِقِيِّ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْخَيْلُ مَعْقُودٌ فِي نَوَاصِيهَا الْخَيْرُ إِلَى يَوْمِ الْقِيَامَةِ الْأَجْرُ وَالْمَغْنَمُ","id":"Dan telah menceritakan kepada kami [Muhammad bin Abdullah bin Numair] telah menceritakan kepada kami [ayahku] telah menceritakan kepada kami [Zakaria] dari ['Amir] dari ['Urwah Al Bariqi] dia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Pada ubun-ubun kuda telah ditulis kebaikan hingga datangnya hari kiamat; pahala dan ghanimah.\""},"3241":{"ar":"و حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا ابْنُ فُضَيْلٍ وَابْنُ إِدْرِيسَ عَنْ حُصَيْنٍ عَنْ الشَّعْبِيِّ عَنْ عُرْوَةَ الْبَارِقِيِّ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْخَيْرُ مَعْقُوصٌ بِنَوَاصِي الْخَيْلِ قَالَ فَقِيلَ لَهُ يَا رَسُولَ اللَّهِ بِمَ ذَاكَ قَالَ الْأَجْرُ وَالْمَغْنَمُ إِلَى يَوْمِ الْقِيَامَةِو حَدَّثَنَاه إِسْحَقُ بْنُ إِبْرَاهِيمَ أَخْبَرَنَا جَرِيرٌ عَنْ حُصَيْنٍ بِهَذَا الْإِسْنَادِ غَيْرَ أَنَّهُ قَالَ عُرْوَةُ بْنُ الْجَعْدِ حَدَّثَنَا يَحْيَى بْنُ يَحْيَى وَخَلَفُ بْنُ هِشَامٍ وَأَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ جَمِيعًا عَنْ أَبِي الْأَحْوَصِ ح و حَدَّثَنَا إِسْحَقُ بْنُ إِبْرَاهِيمَ وَابْنُ أَبِي عُمَرَ كِلَاهُمَا عَنْ سُفْيَانَ جَمِيعًا عَنْ شَبِيبِ بْنِ غَرْقَدَةَ عَنْ عُرْوَةَ الْبَارِقِيِّ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَلَمْ يَذْكُرْ الْأَجْرَ وَالْمَغْنَمَ وَفِي حَدِيثِ سُفْيَانَ سَمِعَ عُرْوَةَ الْبَارِقِيَّ سَمِعَ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ و حَدَّثَنَا عُبَيْدُ اللَّهِ بْنُ مُعَاذٍ حَدَّثَنَا أَبِي ح و حَدَّثَنَا ابْنُ الْمُثَنَّى وَابْنُ بَشَّارٍ قَالَا حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ كِلَاهُمَا عَنْ شُعْبَةَ عَنْ أَبِي إِسْحَقَ عَنْ الْعَيْزَارِ بْنِ حُرَيْثٍ عَنْ عُرْوَةَ بْنِ الْجَعْدِ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِهَذَا وَلَمْ يَذْكُرْ الْأَجْرَ وَالْمَغْنَمَ","id":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] telah menceritakan kepada kami [Ibnu Fudlail] dan [Ibnu Idris] dari [Hushain] dari [As Sya'bi] dari ['Urwah Al Bariqi] dia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Keberkahan itu tertulis pada ubun-ubun kuda.\" Beliau ditanya, \"Wahai Rasulullah, kebaikan yang bagaimana itu?\" beliau menjawab: \"Berupa pahala dan ghanimah hingga hari Kiamat.\" Dan telah menceritakan kepada kami [Ishaq bin Ibrahim] telah mengabarkan kepada kami [Jarir] dari [Hushain] dengan isnad ini, namun 'Urwah bin Ja'd berkata; telah menceritakan kepada kami [Yahya bin Yahya] dan [Khalaf bin Hisyam] serta [Abu Bakar bin Abu Syaibah] semuanya dari [Abu Al Ahwash]. (dalam jalur lain disebutkan) Telah menceritakan kepada kami [Ishaq bin Ibrahim] dan [Ibnu Abu Umar] keduanya dari [Sufyan] semuanya dari [Syabib bin Ghurqadah] dari ['Urwah Al Bariqi] dari Nabi shallallahu 'alaihi wasallam, dan dia tidak menyebutkan, \"Berupa pahala dan ghanimah.\" Dan dalam hadits Sufyan dia mendengar Urwah Al Bariqi, bahwa dia mendengar Nabi shallallahu 'alaihi wasallam.\" Dan telah menceritakan kepada kami ['Ubaidullah bin Mu'adz] telah menceritakan kepada kami [ayahku]. (dalam jalur lain disebutkan) Telah menceritakan kepada kami [Ibnu Al Mutsanna] dan [Ibnu Basyar] keduanya berkata; telah menceritakan kepada kami [Muhammad bin Ja'far] keduanya dari [Syu'bah] dari [Abu Ishaq] dari [Al 'Aizar bin Huraits] dari ['Urwah bin Al Ja'd] dari Nabi shallallahu 'alaihi wasallam, dengan tidak menyebutkan, \"Berupa pahala dan ghanimah.\""},"3242":{"ar":"و حَدَّثَنَا عُبَيْدُ اللَّهِ بْنُ مُعَاذٍ حَدَّثَنَا أَبِي ح و حَدَّثَنَا مُحَمَّدُ بْنُ الْمُثَنَّى وَابْنُ بَشَّارٍ قَالَا حَدَّثَنَا يَحْيَى بْنُ سَعِيدٍ كِلَاهُمَا عَنْ شُعْبَةَ عَنْ أَبِي التَّيَّاحِ عَنْ أَنَسِ بْنِ مَالِكٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْبَرَكَةُ فِي نَوَاصِي الْخَيْلِو حَدَّثَنَا يَحْيَى بْنُ حَبِيبٍ حَدَّثَنَا خَالِدٌ يَعْنِي ابْنَ الْحَارِثِ ح و حَدَّثَنِي مُحَمَّدُ بْنُ الْوَلِيدِ حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ قَالَا حَدَّثَنَا شُعْبَةُ عَنْ أَبِي التَّيَّاحِ سَمِعَ أَنَسًا يُحَدِّثُ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِمِثْلِهِ","id":"Dan telah menceritakan kepada kami ['Ubaidullah bin Mu'adz] telah menceritakan kepada kami [ayahku]. (dalam jalur lain disebutkan) Telah menceritakan kepada kami [Muhammad bin Al Mutsanna] dan [Ibnu Basyar] dia berkata; telah menceritakan kepada kami [Yahya bin Sa'id] keduanya dari [Syu'bah] dari [Abu At Tayah] dari [Anas bin Malik] dia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Keberkahan itu (telah) tertulis pada ubun-ubun kuda.\" Telah menceritakan kepada kami [Yahya bin Habib] telah menceritakan kepada kami [Khalid] -yaitu Ibnu Al Harits-. (dalam jalur lain disebutkan) Telah menceritakan kepadaku [Muhammad bin Al Walid] telah menceritakan kepada kami [Muhammad bin Ja'far] dia berkata; telah menceritakan kepada kami [Syu'bah] dari [Abu At Tayah] dia mendengar [Anas] menceritakan dari Nabi shallallahu 'alaihi wasallam seperti hadits di atas.\""},"3243":{"ar":"و حَدَّثَنَا يَحْيَى بْنُ يَحْيَى وَأَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ وَزُهَيْرُ بْنُ حَرْبٍ وَأَبُو كُرَيْبٍ قَالَ يَحْيَى أَخْبَرَنَا و قَالَ الْآخَرُونَ حَدَّثَنَا وَكِيعٌ عَنْ سُفْيَانَ عَنْ سَلْمِ بْنِ عَبْدِ الرَّحْمَنِ عَنْ أَبِي زُرْعَةَ عَنْ أَبِي هُرَيْرَةَ قَالَكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَكْرَهُ الشِّكَالَ مِنْ الْخَيْلِو حَدَّثَنَاه مُحَمَّدُ بْنُ نُمَيْرٍ حَدَّثَنَا أَبِي ح و حَدَّثَنِي عَبْدُ الرَّحْمَنِ بْنُ بِشْرٍ حَدَّثَنَا عَبْدُ الرَّزَّاقِ جَمِيعًا عَنْ سُفْيَانَ بِهَذَا الْإِسْنَادِ مِثْلَهُ وَزَادَ فِي حَدِيثِ عَبْدِ الرَّزَّاقِ وَالشِّكَالُ أَنْ يَكُونَ الْفَرَسُ فِي رِجْلِهِ الْيُمْنَى بَيَاضٌ وَفِي يَدِهِ الْيُسْرَى أَوْ فِي يَدِهِ الْيُمْنَى وَرِجْلِهِ الْيُسْرَى حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا مُحَمَّدٌ يَعْنِي ابْنَ جَعْفَرٍ ح و حَدَّثَنَا مُحَمَّدُ بْنُ الْمُثَنَّى حَدَّثَنِي وَهْبُ بْنُ جَرِيرٍ جَمِيعًا عَنْ شُعْبَةَ عَنْ عَبْدِ اللَّهِ بْنِ يَزِيدَ النَّخَعِيِّ عَنْ أَبِي زُرْعَةَ عَنْ أَبِي هُرَيْرَةَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِمِثْلِ حَدِيثِ وَكِيعٍ وَفِي رِوَايَةِ وَهْبٍ عَنْ عَبْدِ اللَّهِ بْنِ يَزِيدَ وَلَمْ يَذْكُرْ النَّخَعِيَّ","id":"Dan telah menceritakan kepada kami [Yahya bin Yahya] dan [Abu Bakr bin Abu Syaibah] dan [Zuhair bin Harb] dan [Abu Kuraib], Yahya berkata; telah mengabarkan kepada kami, dan yang lain mengatakan; telah menceritakan kepada kami [Waki'] dari [Sufyan] dari [Salm bin 'Abdurrahman] dari [Abu Zur'ah] dari [Abu Hurairah] dia berkata, \"Rasulullah shallallahu 'alaihi wasallam tidak menyukai belang putih pada kaki kuda.\" Dan telah menceritakan kepada kami [Muhammad bin Numair] telah menceritakan kepada kami [ayahku]. (dalam jalur lain disebutkan) Telah menceritakan kepadaku ['Abdurrahman bin Bisyr] telah menceritakan kepada kami ['Abdurrazaq] semuanya dari [Sufyan] dengan isnad seperti ini, dan di dalam hadits Abdurrazaq ditambahkan, \"Syikal adalah seekor kuda yang di kaki kanannya dan tangan kirinya terdapat belang putih, atau pada tangan kanan dan kaki kirinya.\" Telah menceritakan kepada kami [Muhammad bin Basyar] telah menceritakan kepada kami [Muhammad yaitu Ibnu Ja'far]. (dalam jalur lain disebutkan) Telah menceritakan kepada kami [Muhammad bin Mutsanna] telah menceritakan kepadaku [Wahb bin Jarir] semuanya dari [Syu'bah] dari ['Abdullah bin Yazid An Nakha'i] dari [Abu Zur'ah] dari [Abu Hurairah] dari Nabi shallallahu 'alaihi wasallam seperti hadits Waki'. Dan dalam riwayat Wahb dari 'Abdullah bin Yazid tidak disebutkan An Nakha'i.\""},"3244":{"ar":"و حَدَّثَنِي زُهَيْرُ بْنُ حَرْبٍ حَدَّثَنَا جَرِيرٌ عَنْ عُمَارَةَ وَهُوَ ابْنُ الْقَعْقَاعِ عَنْ أَبِي زُرْعَةَ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ تَضَمَّنَ اللَّهُ لِمَنْ خَرَجَ فِي سَبِيلِهِ لَا يُخْرِجُهُ إِلَّا جِهَادًا فِي سَبِيلِي وَإِيمَانًا بِي وَتَصْدِيقًا بِرُسُلِي فَهُوَ عَلَيَّ ضَامِنٌ أَنْ أُدْخِلَهُ الْجَنَّةَ أَوْ أَرْجِعَهُ إِلَى مَسْكَنِهِ الَّذِي خَرَجَ مِنْهُ نَائِلًا مَا نَالَ مِنْ أَجْرٍ أَوْ غَنِيمَةٍ وَالَّذِي نَفْسُ مُحَمَّدٍ بِيَدِهِ مَا مِنْ كَلْمٍ يُكْلَمُ فِي سَبِيلِ اللَّهِ إِلَّا جَاءَ يَوْمَ الْقِيَامَةِ كَهَيْئَتِهِ حِينَ كُلِمَ لَوْنُهُ لَوْنُ دَمٍ وَرِيحُهُ مِسْكٌ وَالَّذِي نَفْسُ مُحَمَّدٍ بِيَدِهِ لَوْلَا أَنْ يَشُقَّ عَلَى الْمُسْلِمِينَ مَا قَعَدْتُ خِلَافَ سَرِيَّةٍ تَغْزُو فِي سَبِيلِ اللَّهِ أَبَدًا وَلَكِنْ لَا أَجِدُ سَعَةً فَأَحْمِلَهُمْ وَلَا يَجِدُونَ سَعَةً وَيَشُقُّ عَلَيْهِمْ أَنْ يَتَخَلَّفُوا عَنِّي وَالَّذِي نَفْسُ مُحَمَّدٍ بِيَدِهِ لَوَدِدْتُ أَنِّي أَغْزُو فِي سَبِيلِ اللَّهِ فَأُقْتَلُ ثُمَّ أَغْزُو فَأُقْتَلُ ثُمَّ أَغْزُو فَأُقْتَلُو حَدَّثَنَاه أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ وَأَبُو كُرَيْبٍ قَالَا حَدَّثَنَا ابْنُ فُضَيْلٍ عَنْ عُمَارَةَ بِهَذَا الْإِسْنَادِ","id":"Dan telah menceritakan kepadaku [Zuhair bin Harb] telah menceritakan kepada kami [Jarir] dari ['Amarah] -yaitu Ibnu Al Qa'qa'- dari [Abu Zur'ah] dari [Abu Hurairah] dia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Allah menjamin bagi orang yang berperang di jalan-Nya, tidak ada yang mendorongnya keluar kecuali karena ingin jihad di jalan-Ku, ia iman dengan Aku dan membenarkan para rasul-Ku, maka Aku menjamin akan memasukkannya ke dalam surga atau mengembalikannya pulang ke rumahnya dengan membawa kemenangan berupa pahala dan ghanimah. Demi dzat yang jiwa Muhammad berada di tangan-Nya, tidak ada seseorang pun yang terluka dalam perang fi sabilillah, melainkan kelak di hari Kiamat ia akan datang dalam keadaan luka seperti semula, warna warna darah dan baunya bau minyak kesturi. Demi dzat yang jiwa Muhammad berada di tangan-Nya, sekiranya tidak memberatkan kaum Muslimin, sungguh selamanya aku tidak ingin tertinggal di belakang ekspedisi berperang menegakkan agama Allah, namun saya tidak mampu untuk menanggung biaya mereka, sedangkan mereka juga tidak memiliki kelapangan, padahal mereka merasa kecewa tidak ikut berperang bersamaku. Demi dzat yang jiwa Muhammad berada ditangan-Nya, sesungguhnya saya ingin sekali berperang fi sabilillah, kemudian saya terbunuh, lalu saya berperang lagi lalu saya terbunuh, setelah itu saya berperang lagi dan terbunuh.\" Dan telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] dan [Abu Kuraib] berkata; telah menceritakan kepada kami [Ibnu Fudlail] dari ['Umarah] dengan sanad diatas."},"3245":{"ar":"و حَدَّثَنَا يَحْيَى بْنُ يَحْيَى أَخْبَرَنَا الْمُغِيرَةُ بْنُ عَبْدِ الرَّحْمَنِ الْحِزَامِيُّ عَنْ أَبِي الزِّنَادِ عَنْ الْأَعْرَجِ عَنْ أَبِي هُرَيْرَةَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ تَكَفَّلَ اللَّهُ لِمَنْ جَاهَدَ فِي سَبِيلِهِ لَا يُخْرِجُهُ مِنْ بَيْتِهِ إِلَّا جِهَادٌ فِي سَبِيلِهِ وَتَصْدِيقُ كَلِمَتِهِ بِأَنْ يُدْخِلَهُ الْجَنَّةَ أَوْ يَرْجِعَهُ إِلَى مَسْكَنِهِ الَّذِي خَرَجَ مِنْهُ مَعَ مَا نَالَ مِنْ أَجْرٍ أَوْ غَنِيمَةٍ","id":"Dan telah menceritakan kepada kami [Yahya bin Yahya] telah mengabarkan kepada kami [Al Mughirah bin Abdurrahman Al Hizami] dari [Abu Az Zinnad] dari [Al A'raj] dari [Abu Hurairah] dari Nabi shallallahu 'alaihi wasallam beliau bersabda: \"Allah akan menjamin bagi siapa yang berjihad (berjuang) di jalan-Nya, ia tidak keluar dari rumahnya kecuali untuk berjuang di jalan-Nya dan menegakkan kalimat-Nya, (maka Saya menjamin baginya) untuk masuk kedalam surga atau mengembalikannya pulang ke rumahnya dengan membawa sesuatu yang ia dapat berupa pahala dan ghanimah.\""},"3246":{"ar":"حَدَّثَنَا عَمْرٌو النَّاقِدُ وَزُهَيْرُ بْنُ حَرْبٍ قَالَا حَدَّثَنَا سُفْيَانُ بْنُ عُيَيْنَةَ عَنْ أَبِي الزِّنَادِ عَنْ الْأَعْرَجِ عَنْ أَبِي هُرَيْرَةَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَا يُكْلَمُ أَحَدٌ فِي سَبِيلِ اللَّهِ وَاللَّهُ أَعْلَمُ بِمَنْ يُكْلَمُ فِي سَبِيلِهِ إِلَّا جَاءَ يَوْمَ الْقِيَامَةِ وَجُرْحُهُ يَثْعَبُ اللَّوْنُ لَوْنُ دَمٍ وَالرِّيحُ رِيحُ مِسْكٍ","id":"Telah menceritakan kepada kami ['Amru An Naqid] dan [Zuhair bin Harb] keduanya berkata; telah menceritakan kepada kami [Sufyan bin 'Uyainah] dari [Abu Az Zinad] dari [Al A'raj] dari [Abu Hurairah] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Tidak ada seorang pun yang terluka dalam perang fi sabilillah -dan Allah lebih mengetahui bagi siapa yang terluka di jalan-Nya- kecuali ia akan datang di hari kiamat kelak dengan luka yang mengucurkan darah berwarna merah dan baunya seperti bau kesturi.\""},"3247":{"ar":"و حَدَّثَنَا مُحَمَّدُ بْنُ رَافِعٍ حَدَّثَنَا عَبْدُ الرَّزَّاقِ حَدَّثَنَا مَعْمَرٌ عَنْ هَمَّامِ بْنِ مُنَبِّهٍ قَالَ هَذَا مَا حَدَّثَنَا أَبُو هُرَيْرَةَ عَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَذَكَرَ أَحَادِيثَ مِنْهَاوَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كُلُّ كَلْمٍ يُكْلَمُهُ الْمُسْلِمُ فِي سَبِيلِ اللَّهِ ثُمَّ تَكُونُ يَوْمَ الْقِيَامَةِ كَهَيْئَتِهَا إِذَا طُعِنَتْ تَفَجَّرُ دَمًا اللَّوْنُ لَوْنُ دَمٍ وَالْعَرْفُ عَرْفُ الْمِسْكِ وَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَالَّذِي نَفْسُ مُحَمَّدٍ فِي يَدِهِ لَوْلَا أَنْ أَشُقَّ عَلَى الْمُؤْمِنِينَ مَا قَعَدْتُ خَلْفَ سَرِيَّةٍ تَغْزُو فِي سَبِيلِ اللَّهِ وَلَكِنْ لَا أَجِدُ سَعَةً فَأَحْمِلَهُمْ وَلَا يَجِدُونَ سَعَةً فَيَتَّبِعُونِي وَلَا تَطِيبُ أَنْفُسُهُمْ أَنْ يَقْعُدُوا بَعْدِيو حَدَّثَنَا ابْنُ أَبِي عُمَرَ حَدَّثَنَا سُفْيَانُ عَنْ أَبِي الزِّنَادِ عَنْ الْأَعْرَجِ عَنْ أَبِي هُرَيْرَةَ قَالَ سَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ لَوْلَا أَنْ أَشُقَّ عَلَى الْمُؤْمِنِينَ مَا قَعَدْتُ خِلَافَ سَرِيَّةٍ بِمِثْلِ حَدِيثِهِمْ وَبِهَذَا الْإِسْنَادِ وَالَّذِي نَفْسِي بِيَدِهِ لَوَدِدْتُ أَنِّي أُقْتَلُ فِي سَبِيلِ اللَّهِ ثُمَّ أُحْيَا بِمِثْلِ حَدِيثِ أَبِي زُرْعَةَ عَنْ أَبِي هُرَيْرَةَ و حَدَّثَنَا مُحَمَّدُ بْنُ الْمُثَنَّى حَدَّثَنَا عَبْدُ الْوَهَّابِ يَعْنِي الثَّقَفِيَّ ح و حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا أَبُو مُعَاوِيَةَ ح و حَدَّثَنَا ابْنُ أَبِي عُمَرَ حَدَّثَنَا مَرْوَانُ بْنُ مُعَاوِيَةَ كُلُّهُمْ عَنْ يَحْيَى بْنِ سَعِيدٍ عَنْ أَبِي صَالِحٍ عَنْ أَبِي هُرَيْرَةَ قَالَ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَوْلَا أَنْ أَشُقَّ عَلَى أُمَّتِي لَأَحْبَبْتُ أَنْ لَا أَتَخَلَّفَ خَلْفَ سَرِيَّةٍ نَحْوَ حَدِيثِهِمْ حَدَّثَنِي زُهَيْرُ بْنُ حَرْبٍ حَدَّثَنَا جَرِيرٌ عَنْ سُهَيْلٍ عَنْ أَبِيهِ عَنْ أَبِي هُرَيْرَةَ قَالَ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ تَضَمَّنَ اللَّهُ لِمَنْ خَرَجَ فِي سَبِيلِهِ إِلَى قَوْلِهِ مَا تَخَلَّفْتُ خِلَافَ سَرِيَّةٍ تَغْزُو فِي سَبِيلِ اللَّهِ تَعَالَى","id":"Dan telah menceritakan kepada kami [Muhammad bin Rafi'] telah menceritakan kepada kami [Abdurrazaq] telah menceritakan kepada kami [Ma'mar] dari [Hammam bin Munabbih] dia berkata; hadits ini seperti yang telah diceritakan kepada kami oleh [Abu Hurairah] dari Rasulullah shallallahu 'alaihi wasallam -kemudian dia menyebutkan beberapa hadits darinya-, Rasulullah shallallahu 'alaihi wasallam bersabda: \"Setiap luka yang menimpa seorang Muslim dalam jihad fi sabilillah, maka di hari Kiamat ia akan mengucurkan darah berwarna merah dan baunya bau kesturi.\" Dan Rasulullah shallallahu 'alaihi wasallam bersabda: \"Demi dzat yang jiwaku berada ditangan-Nya, sekiranya tidak memberatkan terhadap orang-orang mukmin, niscaya saya tidak akan membolehkan seseorang untuk tidak ikut berperang fi sabilillah, akan tetapi saya tidak mampu memberi kelapangan dan membawa mereka, begitu pula mereka tidak memiliki kelapangan untuk ikut bersamaku (berparang), dan jiwa mereka tidak nyaman untuk duduk-duduk (tidak ikut perang) sepeninggalku.\" Dan telah menceritakan kepada kami [Ibnu Abu Umar] telah menceritakan kepada kami [Sufyan] dari [Abu Az Zinnad] dari [Al A'raj] dari [Abu Hurairah] dia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sekiranya tidak memberatkan terhadap orang-orang Mukmin, niscaya saya tidak akan tertinggal di belakang ekspedisi …sebagaimana hadits mereka dengan isnad ini, \"Demi dzat yang jiwaku berada di tangan-Nya, sungguh saya ingin sekali terbunuh kemudian di hidupkan… seperti hadits Abu Zur'ah dari Abu Hurairah.\" Dan telah menceritakan kepada kami [Muhammad bin Al Mutsanna] telah menceritakan kepada kami [Abdul Wahhab] -yaitu At Tsaqafi-. (dalam jalur lain disebutkan) Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] telah menceritakan kepada kami [Abu Mu'awiyah]. (dalam jalur lain disebutkan) Telah menceritakan kepada kami [Ibnu Abu Umar] telah menceritakan kepada kami [Marwan bin Mu'awiyah] semuanya dari [Yahya bin Sa'id] dari [Abu Shalih] dari [Abu Hurairah] dia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sekiranya tidak memberatkan terhadap ummatku, sungguh saya lebih suka tidak tertinggal dari ekspedisi…..sebagaimana hadits mereka.\" Telah menceritakan kepadaku [Zuhair bin Harb] telah menceritakan kepada kami [Jarir] dari [Suhail] dari [ayahnya] dari [Abu Hurairah] dia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Allah akan menjamin bagi siapa yang keluar berperang fi sabilillah… hingga sabdanya: \"Saya tidak akan tertinggal di belakang ekspedisi di jalan Allah.\""},"3248":{"ar":"و حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا أَبُو خَالِدٍ الْأَحْمَرُ عَنْ شُعْبَةَ عَنْ قَتَادَةَ وَحُمَيْدٍ عَنْ أَنَسِ بْنِ مَالِكٍعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَا مِنْ نَفْسٍ تَمُوتُ لَهَا عِنْدَ اللَّهِ خَيْرٌ يَسُرُّهَا أَنَّهَا تَرْجِعُ إِلَى الدُّنْيَا وَلَا أَنَّ لَهَا الدُّنْيَا وَمَا فِيهَا إِلَّا الشَّهِيدُ فَإِنَّهُ يَتَمَنَّى أَنْ يَرْجِعَ فَيُقْتَلَ فِي الدُّنْيَا لِمَا يَرَى مِنْ فَضْلِ الشَّهَادَةِ","id":"Dan telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] telah menceritakan kepada kami [Abu Khalid Al Ahmar] dari [Syu'bah] dari [Qatadah] dan [Humaid] dari [Anas bin Malik] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Tidak seorang pun yang meninggal dunia, dan di sisi Allah ia memiliki kebaikan yang membuatnya bahagia, lalu ia ingin kembali ke dunia selain orang yang mati syahid. Sesungguhnya ia berangan-anagn untuk kembali (ke dunia) kemudian terbunuh lagi di dunia karena ia melihat keutamaan mati syahid.\""},"3249":{"ar":"و حَدَّثَنَا مُحَمَّدُ بْنُ الْمُثَنَّى وَابْنُ بَشَّارٍ قَالَا حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ حَدَّثَنَا شُعْبَةُ عَنْ قَتَادَةَ قَالَ سَمِعْتُ أَنَسَ بْنَ مَالِكٍ يُحَدِّثُعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَا مِنْ أَحَدٍ يَدْخُلُ الْجَنَّةَ يُحِبُّ أَنْ يَرْجِعَ إِلَى الدُّنْيَا وَأَنَّ لَهُ مَا عَلَى الْأَرْضِ مِنْ شَيْءٍ غَيْرُ الشَّهِيدِ فَإِنَّهُ يَتَمَنَّى أَنْ يَرْجِعَ فَيُقْتَلَ عَشْرَ مَرَّاتٍ لِمَا يَرَى مِنْ الْكَرَامَةِ","id":"Dan telah menceritakan kepada kami [Muhammad bin Al Mutsanna] dan [Ibnu Basyar] keduanya berkata; telah menceritakan kepada kami [Muhammad bin Ja'far] telah menceritakan kepada kami [Syu'bah] dari [Qatadah] dia berkata, \"Saya mendengar [Anas bin Malik] menceritakan dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Tidak satupun seseorang yang masuk surga ingin kembali ke dunia, sekalipun seluruh dunia dan isinya diberikan kepadanya, kecuali orang yang mati syahid. Sesungguhnya ia berangan-angan hendak kembali (ke dunia) kemudian terbunuh hingga sepuluh kali, karena ia melihat mulianya mati syahid.\""},"3250":{"ar":"حَدَّثَنَا سَعِيدُ بْنُ مَنْصُورٍ حَدَّثَنَا خَالِدُ بْنُ عَبْدِ اللَّهِ الْوَاسِطِيُّ عَنْ سُهَيْلِ بْنِ أَبِي صَالِحٍ عَنْ أَبِيهِ عَنْ أَبِي هُرَيْرَةَ قَالَقِيلَ لِلنَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَا يَعْدِلُ الْجِهَادَ فِي سَبِيلِ اللَّهِ عَزَّ وَجَلَّ قَالَ لَا تَسْتَطِيعُونَهُ قَالَ فَأَعَادُوا عَلَيْهِ مَرَّتَيْنِ أَوْ ثَلَاثًا كُلُّ ذَلِكَ يَقُولُ لَا تَسْتَطِيعُونَهُ وَقَالَ فِي الثَّالِثَةِ مَثَلُ الْمُجَاهِدِ فِي سَبِيلِ اللَّهِ كَمَثَلِ الصَّائِمِ الْقَائِمِ الْقَانِتِ بِآيَاتِ اللَّهِ لَا يَفْتُرُ مِنْ صِيَامٍ وَلَا صَلَاةٍ حَتَّى يَرْجِعَ الْمُجَاهِدُ فِي سَبِيلِ اللَّهِ تَعَالَىحَدَّثَنَا قُتَيْبَةُ بْنُ سَعِيدٍ حَدَّثَنَا أَبُو عَوَانَةَ ح و حَدَّثَنِي زُهَيْرُ بْنُ حَرْبٍ حَدَّثَنَا جَرِيرٌ ح و حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا أَبُو مُعَاوِيَةَ كُلُّهُمْ عَنْ سُهَيْلٍ بِهَذَا الْإِسْنَادِ نَحْوَهُ","id":"Telah menceritakan kepada kami [Sa'id bin Manshur] telah menceritakan kepada kami [Khalid bin Abdullah Al Wasithi] dari [Suhail bin Abu Shalih] dari [ayahnya] dari [Abu Hurairah] dia berkata, \"Nabi shallallahu 'alaihi wasallam pernah ditanya, \"Amalan apakah yang (pahalanya) sebanding dengan jihad di jalan Allah?\" beliau menjawab, \"Kamu tidak akan sanggup melakukannya.\" Orang itu bertanya lagi sampai dua atau tiga kali. Namun beliau tetap menjawab: \"Kamu tidak akan mampu melakukannya.\" Dan pada kali yang ketiga beliau bersabda: \"Perbandingan seorang mujahid fi sabilillah seperti orang yang berpuasa, mendirikan shalat dengan menjalankan ayat-ayat Allah dan ia tidak berhenti dari puasa dan shalatnya, sehingga seorang Mujahid fi sabilillah Ta'ala tersebut pulang dari medan perjuangan.\" Telah menceritakan kepada kami [Qutaibah bin Sa'id] telah menceritakan kepada kami [Abu 'Awanah]. (dalam jalur lain disebutkan) Telah menceritakan kepadaku [Zuhair bin Harb] telah menceritakan kepada kami [Jarir]. (dalam jalur lain disebutkan) Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] telah menceritakan kepada kami [Abu Mu'awiyah] semuanya dari [Suhail] dengan isnad seperti ini.\""},"3251":{"ar":"حَدَّثَنِي حَسَنُ بْنُ عَلِيٍّ الْحُلْوَانِيُّ حَدَّثَنَا أَبُو تَوْبَةَ حَدَّثَنَا مُعَاوِيَةُ بْنُ سَلَّامٍ عَنْ زَيْدِ بْنِ سَلَّامٍ أَنَّهُ سَمِعَ أَبَا سَلَّامٍ قَالَ حَدَّثَنِي النُّعْمَانُ بْنُ بَشِيرٍ قَالَكُنْتُ عِنْدَ مِنْبَرِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ رَجُلٌ مَا أُبَالِي أَنْ لَا أَعْمَلَ عَمَلًا بَعْدَ الْإِسْلَامِ إِلَّا أَنْ أُسْقِيَ الْحَاجَّ وَقَالَ آخَرُ مَا أُبَالِي أَنْ لَا أَعْمَلَ عَمَلًا بَعْدَ الْإِسْلَامِ إِلَّا أَنْ أَعْمُرَ الْمَسْجِدَ الْحَرَامَ وَقَالَ آخَرُ الْجِهَادُ فِي سَبِيلِ اللَّهِ أَفْضَلُ مِمَّا قُلْتُمْ فَزَجَرَهُمْ عُمَرُ وَقَالَ لَا تَرْفَعُوا أَصْوَاتَكُمْ عِنْدَ مِنْبَرِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَهُوَ يَوْمُ الْجُمُعَةِ وَلَكِنْ إِذَا صَلَّيْتُ الْجُمُعَةَ دَخَلْتُ فَاسْتَفْتَيْتُهُ فِيمَا اخْتَلَفْتُمْ فِيهِ فَأَنْزَلَ اللَّهُ عَزَّ وَجَلَّ{ أَجَعَلْتُمْ سِقَايَةَ الْحَاجِّ وَعِمَارَةَ الْمَسْجِدِ الْحَرَامِ كَمَنْ آمَنَ بِاللَّهِ وَالْيَوْمِ الْآخِرِ }الْآيَةَ إِلَى آخِرِهَاو حَدَّثَنِيهِ عَبْدُ اللَّهِ بْنُ عَبْدِ الرَّحْمَنِ الدَّارِمِيُّ حَدَّثَنَا يَحْيَى بْنُ حَسَّانَ حَدَّثَنَا مُعَاوِيَةُ أَخْبَرَنِي زَيْدٌ أَنَّهُ سَمِعَ أَبَا سَلَّامٍ قَالَ حَدَّثَنِي النُّعْمَانُ بْنُ بَشِيرٍ قَالَ كُنْتُ عِنْدَ مِنْبَرِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِمِثْلِ حَدِيثِ أَبِي تَوْبَةَ","id":"Telah menceritakan kepadaku [Hasan bin Ali Al Khulwani] telah menceritakan kepada kami [Abu Taubah] telah menceritakan kepada kami [Mu'awiyah bin Salam] dari [Zaid bin Salam] bahwa dia mendengar [Abu Salam] berkata; telah menceritakan kepadaku [An Nu'man bin Basyir] dia berkata, \"Saya pernah berada di sisi mimbar Rasulullah shallallahu 'alaihi wasallam, tiba-tiba saya mendengar seorang laki-laki berkata, \"Saya tidak mementingkan suatu amalan setelah saya masuk Islam kecuali menjamu para Jama'ah haji.\" Sedangkan yang lain mengatakan, \"Saya tidak mementingkan suatu amalan setelah saya masuk Islam kecuali memakmurkan Masjidil Haram.\" Dan yang lainnya lagi mengatakan, \"Jihad fi sabilillah itu lebih baik dari apa yang kalian katakan tadi.\" Lalu mereka ditegur oleh Umar saraya berkata, \"Janganlah kalian meninggikan suara kalian di sisi mimbar Rasulullah shallallahu 'alaihi wasallam, bukankah hari ini adalah hari Jum'at?\" Setelah selesai shalat Jum'at, saya datang menemui beliau untuk meminta fatwa tentang apa yang diperselisihkan mereka, maka turunkah ayat: '(Apakah (orang-orang) yang memberi minuman orang-orang yang mengerjakan haji dan mengurus Masjidilharam kamu samakan dengan orang-orang yang beriman kepada Allah dan hari Kemudian serta bejihad di jalan Allah? …) ' (Qs. At Taubah: 19) sampai akhir ayat.\" Dan telah menceritakan kepadaku [Abdullah bin Abdurrahman Ad Darimi] telah menceritakan kepada kami [Yahya bin Hasan] telah menceritakan kepada kami [Mu'awiyah] telah mengabarkan kepadaku [Zaid] bahwa dia mendengar [Abu Salam] berkata; telah menceritakan kepadaku [An Nu'man bin Basyir] dia berkata, \"Ketika saya berada di sisi mimbar Rasulullah shallallahu 'alaihi wasallam…seperti hadits Abu Taubah.\""},"3252":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ مَسْلَمَةَ بْنِ قَعْنَبٍ حَدَّثَنَا حَمَّادُ بْنُ سَلَمَةَ عَنْ ثَابِتٍ عَنْ أَنَسِ بْنِ مَالِكٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَغَدْوَةٌ فِي سَبِيلِ اللَّهِ أَوْ رَوْحَةٌ خَيْرٌ مِنْ الدُّنْيَا وَمَا فِيهَا","id":"Telah menceritakan kepada kami [Abdullah bin Maslamah bin Qa'nab] telah menceritakan kepada kami [Hammad bin Salamah] dari [Tsabit] dari [Anas bin Malik] dia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Keluar di jalan Allah (jihad) di pagi hari atau di sore hari lebih baik dari pada dunia dan seisinya.\""},"3253":{"ar":"حَدَّثَنَا يَحْيَى بْنُ يَحْيَى أَخْبَرَنَا عَبْدُ الْعَزِيزِ بْنُ أَبِي حَازِمٍ عَنْ أَبِيهِ عَنْ سَهْلِ بْنِ سَعْدٍ السَّاعِدِيِّعَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ وَالْغَدْوَةَ يَغْدُوهَا الْعَبْدُ فِي سَبِيلِ اللَّهِ خَيْرٌ مِنْ الدُّنْيَا وَمَا فِيهَا","id":"Telah menceritakan kepada kami [Yahya bin Yahya] telah mengabarkan kepada kami [Abdul Aziz bin Abu Hazim] dari [ayahnya] dari [Sahl bin Sa'd As Sa'idi] dari Rasulullah shallallahu 'alaihi wasallam, beliau bersabda: \"Keluarnya seorang hamba yang berjuang di jalan Allah di pagi hari lebih baik daripada dunia dan seisinya.\""},"3254":{"ar":"و حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ وَزُهَيْرُ بْنُ حَرْبٍ قَالَا حَدَّثَنَا وَكِيعٌ عَنْ سُفْيَانَ عَنْ أَبِي حَازِمٍ عَنْ سَهْلِ بْنِ سَعْدٍ السَّاعِدِيِّعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ غَدْوَةٌ أَوْ رَوْحَةٌ فِي سَبِيلِ اللَّهِ خَيْرٌ مِنْ الدُّنْيَا وَمَا فِيهَاحَدَّثَنَا ابْنُ أَبِي عُمَرَ حَدَّثَنَا مَرْوَانُ بْنُ مُعَاوِيَةَ عَنْ يَحْيَى بْنِ سَعِيدٍ عَنْ ذَكْوَانَ أَبِي صَالِحٍ عَنْ أَبِي هُرَيْرَةَ قَالَ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَوْلَا أَنَّ رِجَالًا مِنْ أُمَّتِي وَسَاقَ الْحَدِيثَ وَقَالَ فِيهِ وَلَرَوْحَةٌ فِي سَبِيلِ اللَّهِ أَوْ غَدْوَةٌ خَيْرٌ مِنْ الدُّنْيَا وَمَا فِيهَا","id":"Dan telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] dan [Zuhair bin Harb] keduanya berkata; telah menceritakan kepada kami [Waki'] dari [Sufyan] dari [Abu Hazim] dari [Sahl bin Sa'd As Sa'idi] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Berjuang di jalan Allah di pagi hari atau sore hari lebih baik dari pada dunia seisinya.\" Telah menceritakan kepada kami [Ibnu Abu Umar] telah menceritakan kepada kami [Marwan bin Mu'awiyah] dari [Yahya bin Sa'id] dari [Dzakwan Abu Shalih] dari [Abu Hurairah] dia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sekiranya beberapa orang dari umatku…. … kemudian dia melanjutkan hadits tersebut, beliau juga bersabda: \"Sungguh berjuang di jalan Allah di pagi hari atau sore hari, lebih baik daripada dunia seisinya.\""},"3255":{"ar":"و حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ وَإِسْحَقُ بْنُ إِبْرَاهِيمَ وَزُهَيْرُ بْنُ حَرْبٍ وَاللَّفْظُ لِأَبِي بَكْرٍ وَإِسْحَقَ قَالَ إِسْحَقُ أَخْبَرَنَا و قَالَ الْآخَرَانِ حَدَّثَنَا الْمُقْرِئُ عَبْدُ اللَّهِ بْنُ يَزِيدَ عَنْ سَعِيدِ بْنِ أَبِي أَيُّوبَ حَدَّثَنِي شُرَحْبِيلُ بْنُ شَرِيكٍ الْمَعَافِرِيُّ عَنْ أَبِي عَبْدِ الرَّحْمَنِ الْحُبُلِيِّ قَالَ سَمِعْتُ أَبَا أَيُّوبَ يَقُولُاقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ غَدْوَةٌ فِي سَبِيلِ اللَّهِ أَوْ رَوْحَةٌ خَيْرٌ مِمَّا طَلَعَتْ عَلَيْهِ الشَّمْسُ وَغَرَبَتْحَدَّثَنِي مُحَمَّدُ بْنُ عَبْدِ اللَّهِ بْنِ قُهْزَاذَ حَدَّثَنَا عَلِيُّ بْنُ الْحَسَنِ عَنْ عَبْدِ اللَّهِ بْنِ الْمُبَارَكِ أَخْبَرَنَا سَعِيدُ بْنُ أَبِي أَيُّوبَ وَحَيْوَةُ بْنُ شُرَيْحٍ قَالَ كُلُّ وَاحِدٍ مِنْهُمَا حَدَّثَنِي شُرَحْبِيلُ بْنُ شَرِيكٍ عَنْ أَبِي عَبْدِ الرَّحْمَنِ الْحُبُلِيِّ أَنَّهُ سَمِعَ أَبَا أَيُّوبَ الْأَنْصَارِيَّ يَقُولُا قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِمِثْلِهِ سَوَاءً","id":"Dan telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] dan [Ishaq bin Ibrahim] dan [Zuhair bin Harb] dan ini adalah lafadz Abu Bakar dan Ishaq, Ishaq berkata; telah mengabarkan kepada kami, sedangkan yang dua mengatakan; telah menceritakan kepada kami [Al Muqri` Abdullah bin Yazid] dari [Sa'id Abu Ayyub] telah menceritakan kepadaku [Syurahbil bin Syarik bin Syarik Al Ma'arifi] dari [Abu Abdurrahman Al Hubuli] dia berkata; saya mendengar [Abu Ayyub] berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Keluar (jihad) di jalan Allah di pagi hari atau sore hari, lebih baik daripada terbitnya dan terbenamnya matahari.\" Dan telah menceritakan kepadaku [Muhammad bin Abdullah bin Qahzadz] telah menceritakan kepada kami [Ali bin Al Hasan] dari [Abdullah bin Mubarak] telah mengabarkan kepada kami [Sa'id bin Abu Ayyub] dan [Haiwah bin Syuraih] dia berkata; setiap dari keduanya mengatakan; telah menceritakan kepadaku [Syurahbil bin Syarik] dari [Abu Abdurrahman Al Hubuli] bahwa dia mendengar [Abu Ayyub Al Anshari] berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda…. seperti hadits di atas.\""},"3256":{"ar":"حَدَّثَنَا سَعِيدُ بْنُ مَنْصُورٍ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ وَهْبٍ حَدَّثَنِي أَبُو هَانِئٍ الْخَوْلَانِيُّ عَنْ أَبِي عَبْدِ الرَّحْمَنِ الْحُبُلِيِّ عَنْ أَبِي سَعِيدٍ الْخُدْرِيِّأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ يَا أَبَا سَعِيدٍ مَنْ رَضِيَ بِاللَّهِ رَبًّا وَبِالْإِسْلَامِ دِينًا وَبِمُحَمَّدٍ نَبِيًّا وَجَبَتْ لَهُ الْجَنَّةُ فَعَجِبَ لَهَا أَبُو سَعِيدٍ فَقَالَ أَعِدْهَا عَلَيَّ يَا رَسُولَ اللَّهِ فَفَعَلَ ثُمَّ قَالَ وَأُخْرَى يُرْفَعُ بِهَا الْعَبْدُ مِائَةَ دَرَجَةٍ فِي الْجَنَّةِ مَا بَيْنَ كُلِّ دَرَجَتَيْنِ كَمَا بَيْنَ السَّمَاءِ وَالْأَرْضِ قَالَ وَمَا هِيَ يَا رَسُولَ اللَّهِ قَالَ الْجِهَادُ فِي سَبِيلِ اللَّهِ الْجِهَادُ فِي سَبِيلِ اللَّهِ","id":"Telah menceritakan kepada kami [Sa'id bin Manshur] telah menceritakan kepada kami [Abdullah bin Wahb] telah menceritakan kepadaku [Abu Hani`Al Khaulani] dari [Abu Abdirrahman Al Hubuli] dari [Abu Sa'id Al Khudri], bahwa Rasulullah shallallahu 'alaihi wasallam pernah bersabda kepadanya: \"Wahai Abu Sa'id, barangsiapa ridla Allah sebagai Rabbnya, Islam sebagai agamanya dan Muhammad sebagai Nabinya, maka ia pasti masuk surga.\" Abu Sa'id takjub serya berkata, \"Wahai Rasulullah, sudikah anda mengulanginya lagi untukku?\" Beliau pun mengulanginya, kemudian beliau melanjutkan: \"Dan ada satu amalan yang dengannya seorang hamba akan diangkat derajatnya di surga sebanyak seratus derajat, antara derajat satu dengan derajat yang lain seperti jarak antara langit dan bumi.\" Abu Sa'id berkata, \"Amalan apakah itu wahai Rasulullah?\" Beliau menjawab: \"Jihad di jalan Allah, Jihad di jalan Allah.\""},"3257":{"ar":"حَدَّثَنَا قُتَيْبَةُ بْنُ سَعِيدٍ حَدَّثَنَا لَيْثٌ عَنْ سَعِيدِ بْنِ أَبِي سَعِيدٍ عَنْ عَبْدِ اللَّهِ بْنِ أَبِي قَتَادَةَ عَنْ أَبِي قَتَادَةَ أَنَّهُ سَمِعَهُ يُحَدِّثُعَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهُ قَامَ فِيهِمْ فَذَكَرَ لَهُمْ أَنَّ الْجِهَادَ فِي سَبِيلِ اللَّهِ وَالْإِيمَانَ بِاللَّهِ أَفْضَلُ الْأَعْمَالِ فَقَامَ رَجُلٌ فَقَالَ يَا رَسُولَ اللَّهِ أَرَأَيْتَ إِنْ قُتِلْتُ فِي سَبِيلِ اللَّهِ تُكَفَّرُ عَنِّي خَطَايَايَ فَقَالَ لَهُ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَعَمْ إِنْ قُتِلْتَ فِي سَبِيلِ اللَّهِ وَأَنْتَ صَابِرٌ مُحْتَسِبٌ مُقْبِلٌ غَيْرُ مُدْبِرٍ ثُمَّ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَيْفَ قُلْتَ قَالَ أَرَأَيْتَ إِنْ قُتِلْتُ فِي سَبِيلِ اللَّهِ أَتُكَفَّرُ عَنِّي خَطَايَايَ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَعَمْ وَأَنْتَ صَابِرٌ مُحْتَسِبٌ مُقْبِلٌ غَيْرُ مُدْبِرٍ إِلَّا الدَّيْنَ فَإِنَّ جِبْرِيلَ عَلَيْهِ السَّلَام قَالَ لِي ذَلِكَحَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ وَمُحَمَّدُ بْنُ الْمُثَنَّى قَالَا حَدَّثَنَا يَزِيدُ بْنُ هَارُونَ أَخْبَرَنَا يَحْيَى يَعْنِي ابْنَ سَعِيدٍ عَنْ سَعِيدِ بْنِ أَبِي سَعِيدٍ الْمَقْبُرِيِّ عَنْ عَبْدِ اللَّهِ بْنِ أَبِي قَتَادَةَ عَنْ أَبِيهِ قَالَ جَاءَ رَجُلٌ إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ أَرَأَيْتَ إِنْ قُتِلْتُ فِي سَبِيلِ اللَّهِ بِمَعْنَى حَدِيثِ اللَّيْثِ و حَدَّثَنَا سَعِيدُ بْنُ مَنْصُورٍ حَدَّثَنَا سُفْيَانُ عَنْ عَمْرِو بْنِ دِينَارٍ عَنْ مُحَمَّدِ بْنِ قَيْسٍ ح قَالَ وَحَدَّثَنَا مُحَمَّدُ بْنُ عَجْلَانَ عَنْ مُحَمَّدِ بْنِ قَيْسٍ عَنْ عَبْدِ اللَّهِ بْنِ أَبِي قَتَادَةَ عَنْ أَبِيهِ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَزِيدُ أَحَدُهُمَا عَلَى صَاحِبِهِ أَنَّ رَجُلًا أَتَى النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَهُوَ عَلَى الْمِنْبَرِ فَقَالَ أَرَأَيْتَ إِنْ ضَرَبْتُ بِسَيْفِي بِمَعْنَى حَدِيثِ الْمَقْبُرِيِّ","id":"Telah menceritakan kepada kami [Qutaibah bin Sa'id] telah menceritakan kepada kami [Laits] dari [Sa'id bin Abu Sa'id] dari [Abdullah bin Abu Qatadah] dari [Abu Qatadah] bahwa dia mendengarnya menceritakan dari Rasulullah shallallahu 'alaihi wasallam, bahwa suatu ketika beliau berdiri di tengah-tengah para sahabat, lalu beliau bersabda: \"Sesungguhnya jihad fi sabilillah serta iman kepada Allah, adalah amalan yang paling utama.\" Maka seorang laki-laki berdiri seraya bertanya, \"Wahai Rasulullah, bagaimana jika saya terbunuh dalam jihad fi sabilillah, apakah dosa-dosaku akan terampuni?\" Rasulullah shallallahu 'alaihi wasallam menjawab: \"Ya, jika kamu terbunuh di jalan Allah, sabar dan mengharap pahala, maju ke depan dan tidak lari ke belakang.\" Kemudian beliau bertanya: \"Apa yang kamu tanyakan tadi?\" dia mengulangi pertanyaannya, \"Bagaimana jika saya terbunuh dalam jihad fi sabilillah, apakah dosa-dosaku akan terampuni?\" beliau menjawab: \"Ya, jika kamu sabar dan mengharap pahala, maju ke depan dan tidak lari ke belakang. Begitulah Jibril mengatakannya kepadaku.\" Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] dan [Muhammad bin Al Mutsanna] keduanya berkata; telah menceritakan kepada kami [Yazid bin Harun] telah mengabarkan kepada kami [Yahya] -yaitu Ibnu Sa'id- dari [Sa'id bin Abu Sa'id Al Muqbiri] dari [Abdullah bin Abu Qatadah] dari [ayahnya] dia berkata, \"Seorang laki-laki datang kepada Rasulullah shallallahu 'alaihi wasallam seraya berkata, \"Bagaimana pendapatmu jika saya terbunuh di jalan Allah…semakna dengan hadits Laits.\" Dan telah menceritakan kepada kami [Sa'id bin Manshur] telah menceritakan kepada kami [Sufyan] dari ['Amru bin Dinar] dari [Muhammad bin Qais]. (dalam jalur lain disebutkan) Perawi berkata; telah menceritakan kepada kami [Muhammad bin 'Ajlan] dari [Muhammad bin Qais] dari [Abdullah bin Abu Qatadah] dari [ayahnya] dari Nabi shallallahu 'alaihi wasallam… lalu salah seorang dari keduanya menambahkan riwayat temannya, bahwa seorang laki-laki datang kepada Nabi shallallahu 'alaihi wasallam ketika beliau berada di atas mimbar, dia bertanya, \"Bagaimana pendapat anda jika saya menghunus pedangku (berperang) …semakna dengan hadits Al Maqburi.\""},"3258":{"ar":"حَدَّثَنَا زَكَرِيَّاءُ بْنُ يَحْيَى بْنِ صَالِحٍ الْمِصْرِيُّ حَدَّثَنَا الْمُفَضَّلُ يَعْنِي ابْنَ فَضَالَةَ عَنْ عَيَّاشٍ وَهُوَ ابْنُ عَبَّاسٍ الْقِتْبَانِيُّ عَنْ عَبْدِ اللَّهِ بْنِ يَزِيدَ أَبِي عَبْدِ الرَّحْمَنِ الْحُبُلِيِّ عَنْ عَبْدِ اللَّهِ بْنِ عَمْرِو بْنِ الْعَاصِأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ يُغْفَرُ لِلشَّهِيدِ كُلُّ ذَنْبٍ إِلَّا الدَّيْنَ","id":"Telah menceritakan kepada kami [Zakaria bin Yahya bin Shalih Al Mishri] telah menceritakan kepada kami [Al Mufadlal] -yaitu Ibnu Fadlalah- dari ['Ayyasy] -yaitu Ibnu 'Ayyasy Al Qitbani- dari [Abdullah bin Yazid Abu Abdurrahman Al Hubuli] dari [Abdullah bin 'Amru bin 'Ash], bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Seorang yang mati syahid akan diampuni segala dosa-dosanya kecuali hutang.\""},"3259":{"ar":"و حَدَّثَنِي زُهَيْرُ بْنُ حَرْبٍ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ يَزِيدَ الْمُقْرِئُ حَدَّثَنَا سَعِيدُ بْنُ أَبِي أَيُّوبَ حَدَّثَنِي عَيَّاشُ بْنُ عَبَّاسٍ الْقِتْبَانِيُّ عَنْ أَبِي عَبْدِ الرَّحْمَنِ الْحُبُلِيِّ عَنْ عَبْدِ اللَّهِ بْنِ عَمْرِو بْنِ الْعَاصِأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ الْقَتْلُ فِي سَبِيلِ اللَّهِ يُكَفِّرُ كُلَّ شَيْءٍ إِلَّا الدَّيْنَ","id":"Dan telah menceritakan kepadaku [Zuhair bin harb] telah menceritakan kepada kami [Abdullah bin Yazid Al Muqri`i] telah menceritakan kepada kami [Sa'id bin Abu Ayyub] telah menceritakan kepadaku ['Ayyasy bin Abbas Al Qitbani] dari [Abu Abdurrahman Al Hubuli] dari [Abdullah bin 'Amru bin 'Ash], bahwa Nabi shallallahu 'alaihi wasallam bersabda: \"Syahid di jalan Allah akan melebur setiap dosa kecuali hutang.\""},"3260":{"ar":"حَدَّثَنَا يَحْيَى بْنُ يَحْيَى وَأَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ كِلَاهُمَا عَنْ أَبِي مُعَاوِيَةَ ح و حَدَّثَنَا إِسْحَقُ بْنُ إِبْرَاهِيمَ أَخْبَرَنَا جَرِيرٌ وَعِيسَى بْنُ يُونُسَ جَمِيعًا عَنْ الْأَعْمَشِ ح و حَدَّثَنَا مُحَمَّدُ بْنُ عَبْدِ اللَّهِ بْنِ نُمَيْرٍ وَاللَّفْظُ لَهُ حَدَّثَنَا أَسْبَاطٌ وَأَبُو مُعَاوِيَةَ قَالَا حَدَّثَنَا الْأَعْمَشُ عَنْ عَبْدِ اللَّهِ بْنِ مُرَّةَ عَنْ مَسْرُوقٍ قَالَسَأَلْنَا عَبْدَ اللَّهِ عَنْ هَذِهِ الْآيَةِ{ وَلَا تَحْسَبَنَّ الَّذِينَ قُتِلُوا فِي سَبِيلِ اللَّهِ أَمْوَاتًا بَلْ أَحْيَاءٌ عِنْدَ رَبِّهِمْ يُرْزَقُونَ }قَالَ أَمَا إِنَّا قَدْ سَأَلْنَا عَنْ ذَلِكَ فَقَالَ أَرْوَاحُهُمْ فِي جَوْفِ طَيْرٍ خُضْرٍ لَهَا قَنَادِيلُ مُعَلَّقَةٌ بِالْعَرْشِ تَسْرَحُ مِنْ الْجَنَّةِ حَيْثُ شَاءَتْ ثُمَّ تَأْوِي إِلَى تِلْكَ الْقَنَادِيلِ فَاطَّلَعَ إِلَيْهِمْ رَبُّهُمْ اطِّلَاعَةً فَقَالَ هَلْ تَشْتَهُونَ شَيْئًا قَالُوا أَيَّ شَيْءٍ نَشْتَهِي وَنَحْنُ نَسْرَحُ مِنْ الْجَنَّةِ حَيْثُ شِئْنَا فَفَعَلَ ذَلِكَ بِهِمْ ثَلَاثَ مَرَّاتٍ فَلَمَّا رَأَوْا أَنَّهُمْ لَنْ يُتْرَكُوا مِنْ أَنْ يُسْأَلُوا قَالُوا يَا رَبِّ نُرِيدُ أَنْ تَرُدَّ أَرْوَاحَنَا فِي أَجْسَادِنَا حَتَّى نُقْتَلَ فِي سَبِيلِكَ مَرَّةً أُخْرَى فَلَمَّا رَأَى أَنْ لَيْسَ لَهُمْ حَاجَةٌ تُرِكُوا","id":"Telah menceritakan kepada kami [Yahya bin Yahya] dan [Abu Bakar bin Abu Syaibah] keduanya dari [Abu Mu'awiyah]. (dalam jalur lain disebutkan) Telah menceritakan kepada kami [Ishaq bin Ibrahim] telah mengabarkan kepada kami [Jarir] dan [Isa bin Yunus] semuanya dari [Al A'masy]. (dalam jalur lain disebutkan) Telah menceritakan kepada kami [Muhammad bin Abdullah bin Numair] sedangkan lafadznya dari dia, telah menceritakan kepada kami [Asbath] dan [Abu Mu'awiyah] keduanya berkata; telah menceritakan kepada kami [Al A'masy] dari [Abdullah bin Murrah] dari [Masruq] dia berkata, \"Kami pernah bertanya kepada [Abdullah] perihal ayat ini: '(Dan janganlah kalian mengira bahwa orang-orang yang terbunuh di jalan Allah itu (memang) mati, akan tetapi sebenarnya mereka itu hidup di sisi Rabb mereka dan diberi rezeki (yang melimpah) ' (Qs. Ali Imran: 169) Dia berkata, \"Kami dulu pernah menanyakan hal itu, dan beliau menjawab: \"Ruh mereka berada di dalam rongga burung hijau yang mempunyai banyak pelita yang bergantungan di 'Arsy, ia dapat keluar masuk surga sesuka hati kemudian beristirahat lagi di pelita-pelita itu, kemudian Rabb mereka menengok mereka seraya berkata: 'Apakah kalian menginginkan sesuatu? ' Mereka menjawab, 'Apa lagi yang kami inginkan kalau kami sudah dapat keluar masuk ke surga sesuka hati kami? ' Lalu Allah terus mengulangi pertanyaan itu hingga tiga kali. Ketika mereka melihat kalau mereka tidak akan ditinggalkan sebelum menjawab pertanyaan itu, maka merekapun menjawab, 'Duhai Rabb, kami menginginkan ruh kami dikembalikan lagi ke jasad kami hingga kami dapat berperang lagi di jalan-Mu untuk kesekian kalinya.' Ketika Allah melihat kalau mereka tidak lagi membutuhkan sesuatu, akhirnya mereka ditinggal pergi.\""},"3261":{"ar":"حَدَّثَنَا مَنْصُورُ بْنُ أَبِي مُزَاحِمٍ حَدَّثَنَا يَحْيَى بْنُ حَمْزَةَ عَنْ مُحَمَّدِ بْنِ الْوَلِيدِ الزُّبَيْدِيِّ عَنْ الزُّهْرِيِّ عَنْ عَطَاءِ بْنِ يَزِيدَ اللَّيْثِيِّ عَنْ أَبِي سَعِيدٍ الْخُدْرِيِّأَنَّ رَجُلًا أَتَى النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ أَيُّ النَّاسِ أَفْضَلُ فَقَالَ رَجُلٌ يُجَاهِدُ فِي سَبِيلِ اللَّهِ بِمَالِهِ وَنَفْسِهِ قَالَ ثُمَّ مَنْ قَالَ مُؤْمِنٌ فِي شِعْبٍ مِنْ الشِّعَابِ يَعْبُدُ اللَّهَ رَبَّهُ وَيَدَعُ النَّاسَ مِنْ شَرِّهِ","id":"Telah menceritakan kepada kami [Manshur bin Muzahim] telah menceritakan kepada kami [Yahya bin Hamzah] dari [Muhammad bin Walid Az Zubaidi] dari [Az Zuhri] dari ['Atha' bin Yazid Al Laitsi] dari [Abu Sa'id Al Khudri], bahwa seorang laki-laki mendatangi Nabi shallallahu 'alaihi wasallam seraya bertanya, \"Siapakah manusia yang paling utama?\" Beliau pun menjawab: \"Seorang laki-laki yang berjihad di jalan Allah dengan harta dan jiwanya.\" Dia bertanya lagi, \"Kemudian siapa?\" beliau menjawab: \"Orang mukmin yang berada di suatu bukit beribadah kepada Allah dan meninggalkan untuk menghindari kejahatannya.\""},"3262":{"ar":"حَدَّثَنَا عَبْدُ بْنُ حُمَيْدٍ أَخْبَرَنَا عَبْدُ الرَّزَّاقِ أَخْبَرَنَا مَعْمَرٌ عَنْ الزُّهْرِيِّ عَنْ عَطَاءِ بْنِ يَزِيدَ اللَّيْثِيِّ عَنْ أَبِي سَعِيدٍ قَالَقَالَ رَجُلٌ أَيُّ النَّاسِ أَفْضَلُ يَا رَسُولَ اللَّهِ قَالَ مُؤْمِنٌ يُجَاهِدُ بِنَفْسِهِ وَمَالِهِ فِي سَبِيلِ اللَّهِ قَالَ ثُمَّ مَنْ قَالَ ثُمَّ رَجُلٌ مُعْتَزِلٌ فِي شِعْبٍ مِنْ الشِّعَابِ يَعْبُدُ رَبَّهُ وَيَدَعُ النَّاسَ مِنْ شَرِّهِو حَدَّثَنَا عَبْدُ اللَّهِ بْنُ عَبْدِ الرَّحْمَنِ الدَّارِمِيُّ أَخْبَرَنَا مُحَمَّدُ بْنُ يُوسُفَ عَنْ الْأَوْزَاعِيِّ عَنْ ابْنِ شِهَابٍ بِهَذَا الْإِسْنَادِ فَقَالَ وَرَجُلٌ فِي شِعْبٍ وَلَمْ يَقُلْ ثُمَّ رَجُلٌ","id":"Telah menceritakan kepada kami [Abd bin Humaid] telah mengabarkan kepada kami [Abdurrazaq] menceritakan kepada kami [Ma'mar] dari [Az Zuhri] dari ['Atha bin Yazid Al Laitsi] dari [Abu Sa'id] dia berkata, \"Seorang laki-laki berkata, \"Wahai Rasulullah, siapakah manusia yang paling utama?\" beliau menjawab: \"Seorang mukmin yang berjihad di jalan Allah dengan jiwa dan hartanya.\" Dia bertanya lagi, \"Kemudian siapa?\" beliau menjawab: \"Kemudian seorang laki-laki yang pergi menyendiri ke suatu bukit untuk beribadah kepada Rabbnya dan meninggalkan dari kejahatan manusia.\" Telah menceritakan kepada kami [Abdullah bin Abdurrahman Ad Darimi] telah mengabarkan kepada kami [Muhammad bin Yusuf] dari [Al Auza'i] dari [Ibnu Syihab] dengan sanad ini, dengan mengatakan; lalu ada seorang laki-laki dari suatu kaum tidak hanya kata seorang laki-laki."},"3263":{"ar":"حَدَّثَنَا يَحْيَى بْنُ يَحْيَى التَّمِيمِيُّ حَد��َثَنَا عَبْدُ الْعَزِيزِ بْنُ أَبِي حَازِمٍ عَنْ أَبِيهِ عَنْ بَعْجَةَ عَنْ أَبِي هُرَيْرَةَعَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهُ قَالَ مِنْ خَيْرِ مَعَاشِ النَّاسِ لَهُمْ رَجُلٌ مُمْسِكٌ عِنَانَ فَرَسِهِ فِي سَبِيلِ اللَّهِ يَطِيرُ عَلَى مَتْنِهِ كُلَّمَا سَمِعَ هَيْعَةً أَوْ فَزْعَةً طَارَ عَلَيْهِ يَبْتَغِي الْقَتْلَ وَالْمَوْتَ مَظَانَّهُ أَوْ رَجُلٌ فِي غُنَيْمَةٍ فِي رَأْسِ شَعَفَةٍ مِنْ هَذِهِ الشَّعَفِ أَوْ بَطْنِ وَادٍ مِنْ هَذِهِ الْأَوْدِيَةِ يُقِيمُ الصَّلَاةَ وَيُؤْتِي الزَّكَاةَ وَيَعْبُدُ رَبَّهُ حَتَّى يَأْتِيَهُ الْيَقِينُ لَيْسَ مِنْ النَّاسِ إِلَّا فِي خَيْرٍو حَدَّثَنَاه قُتَيْبَةُ بْنُ سَعِيدٍ عَنْ عَبْدِ الْعَزِيزِ بْنِ أَبِي حَازِمٍ وَيَعْقُوبُ يَعْنِي ابْنَ عَبْدِ الرَّحْمَنِ الْقَارِيَّ كِلَاهُمَا عَنْ أَبِي حَازِمٍ بِهَذَا الْإِسْنَادِ مِثْلَهُ وَقَالَ عَنْ بَعْجَةَ بْنِ عَبْدِ اللَّهِ بْنِ بَدْرٍ وَقَالَ فِي شِعْبَةٍ مِنْ هَذِهِ الشِّعَابِ خِلَافَ رِوَايَةِ يَحْيَى و حَدَّثَنَاه أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ وَزُهَيْرُ بْنُ حَرْبٍ وَأَبُو كُرَيْبٍ قَالُوا حَدَّثَنَا وَكِيعٌ عَنْ أُسَامَةَ بْنِ زَيْدٍ عَنْ بَعْجَةَ بْنِ عَبْدِ اللَّهِ الْجُهَنِيِّ عَنْ أَبِي هُرَيْرَةَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِمَعْنَى حَدِيثِ أَبِي حَازِمٍ عَنْ بَعْجَةَ وَقَالَ فِي شِعْبٍ مِنْ الشِّعَابِ","id":"Telah menceritakan kepada kami [Yahya bin Yahya At Tamimi] telah menceritakan kepada kami [Abdul Aziz bin Abu Hazim] dari [Ayahnya] dari [Ba'jah] dari [Abu Hurairah] dari Rasulullah shallallahu 'alaihi wasallam, beliau bersabda: \"Sebaik-baik kehidupan manusia adalah seorang laki-laki yang memegang kendali kudanya dan bergegas untuk berjuang di jalan Allah, setiap kali mendengar suara musuh yang menakutkan atau sangat mengerikan, ia melompat ke atas punggung kudanya untuk mengharapkan kematian. Atau seorang laki-laki yang berada dalam kumpulan kambing yang berada di puncak gunung atau berada di pedalaman lembah ini, ia mendirikan shalat, menunaikan zakat dan beribadah kepada Rabbnya sampai menemui ajalnya, tidaklah ia menjadi manusia kecuali dalam kebaikan.\" Telah menceritakan kepada kami [Qutaibah bin Sa'id] dari [Abdul Aziz bin Abu Hazim] dan [Ya'qub yaitu Ibnu Abdurrahman Al Qari] keduanya dari [Abu Hazim] dengan sanad ini, seperti hadits tersebut. Dia (perawi) berkata; dari Ba'jah bin Abdullah bin Badr, beliau bersabda: 'Di bukit dari bukit-bukit ini, ' berbeda dengan riwayatnya Yahya.\" Dan telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] dan [Zuhair bin Harb] dan [Abu Kuraib] mereka berkata, telah menceritakan kepada kami [Waki'] dari [Usamah bin Zaid] dari [Ba'jah bin Abdullah Al Juhani] dari [Abu Hurairah] dari Nabi shallallahu 'alaihi wasallam semakna dengan hadits Abu Hazm dari Ba'jah, dia berkata, \"Di suatu bukit dari beberapa bukit.\""},"3264":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ أَبِي عُمَرَ الْمَكِّيُّ حَدَّثَنَا سُفْيَانُ عَنْ أَبِي الزِّنَادِ عَنْ الْأَعْرَجِ عَنْ أَبِي هُرَيْرَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ يَضْحَكُ اللَّهُ إِلَى رَجُلَيْنِ يَقْتُلُ أَحَدُهُمَا الْآخَرَ كِلَاهُمَا يَدْخُلُ الْجَنَّةَ فَقَالُوا كَيْفَ يَا رَسُولَ اللَّهِ قَالَ يُقَاتِلُ هَذَا فِي سَبِيلِ اللَّهِ عَزَّ وَجَلَّ فَيُسْتَشْهَدُ ثُمَّ يَتُوبُ اللَّهُ عَلَى الْقَاتِلِ فَيُسْلِمُ فَيُقَاتِلُ فِي سَبِيلِ اللَّهِ عَزَّ وَجَلَّ فَيُسْتَشْهَدُو حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ وَزُهَيْرُ بْنُ حَرْبٍ وَأَبُو كُرَيْبٍ قَالُوا حَدَّثَنَا وَكِيعٌ عَنْ سُفْيَانَ عَنْ أَبِي الزِّنَادِ بِهَذَا الْإِسْنَادِ مِثْلَهُ","id":"Telah menceritakan kepada kami [Muhammad bin Abu Umar Al Maki] telah menceritakan kepada kami [Sufyan] dari [Abu Az Zinad] dari [Al A'raj] dari [Abu Hurairah] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Allah tertawa terhadap dua orang yang saling membunuh, dan kedua-duanya masuk surga.\" Maka para sahabat bertanya; \"Bagaimana hal itu bisa terjadi wahai Rasulullah?\" beliau menjawab: \"Salah seorang darinya berperang di jalan Allah 'azza wajalla lalu dia mati syahid, kemudian Allah menerima taubat si pembunuh, lalu ia masuk Islam dan berperang di jalan Allah 'azza wajalla hingga mati syahid.\" Dan telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] dan [Zuhair bin Harb] dan [Abu Kuraib] mereka berkata; telah menceritakan kepada kami [Waki'] dari [Sufyan] dari [Abu Az Zinad] dengan sanad seperti ini.\""},"3265":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ رَافِعٍ حَدَّثَنَا عَبْدُ الرَّزَّاقِ أَخْبَرَنَا مَعْمَرٌ عَنْ هَمَّامِ بْنِ مُنَبِّهٍ قَالَ هَذَا مَا حَدَّثَنَا أَبُو هُرَيْرَةَ عَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَذَكَرَ أَحَادِيثَ مِنْهَاوَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَضْحَكُ اللَّهُ لِرَجُلَيْنِ يَقْتُلُ أَحَدُهُمَا الْآخَرَ كِلَاهُمَا يَدْخُلُ الْجَنَّةَ قَالُوا كَيْفَ يَا رَسُولَ اللَّهِ قَالَ يُقْتَلُ هَذَا فَيَلِجُ الْجَنَّةَ ثُمَّ يَتُوبُ اللَّهُ عَلَى الْآخَرِ فَيَهْدِيهِ إِلَى الْإِسْلَامِ ثُمَّ يُجَاهِدُ فِي سَبِيلِ اللَّهِ فَيُسْتَشْهَدُ","id":"Telah menceritakan kepada kami [Muhammad bin Rafi'] telah menceritakan kepada kami [Abdurrazaq] telah mengabarkan kepada kami [Ma'mar] dari [Hammam bin Munabbih] dia berkata; ini sebagaimana yang pernah diceritakan oleh [Abu Hurairah] kepada kami dari Rasulullah shallallahu 'alaihi wasallam, lalu dia menyebutkan beberapa hadits yang di antaranya adalah, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Allah tertawa terhadap dua orang yang saling membunuh, namun keduanya masuk surga.\" Para sahabat bertanya, \"Bagaimana hal itu bisa terjadi wahai Rasulullah?\" beliau menjawab: \"Seseorang terbunuh kemudian dia masuk surga, kemudian Allah menerima taubatnya si pembunuh dan menunjukinya untuk masuk Islam, setelah itu dia berjihad di jalan Allah dan akhirnya mati syahid.\""},"3266":{"ar":"حَدَّثَنَا يَحْيَى بْنُ أَيُّوبَ وَقُتَيْبَةُ وَعَلِيُّ بْنُ حُجْرٍ قَالُوا حَدَّثَنَا إِسْمَعِيلُ يَعْنُونَ ابْنَ جَعْفَرٍ عَنْ الْعَلَاءِ عَنْ أَبِيهِ عَنْ أَبِي هُرَيْرَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَا يَجْتَمِعُ كَافِرٌ وَقَاتِلُهُ فِي النَّارِ أَبَدًا","id":"Telah menceritakan kepada kami [Yahya bin Ayyub] dan [Qutaibah] serta [Ali bin Hujr] mereka berkata; telah menceritakan kepada kami [Isma'il] -yaitu Ibnu Ja'far- dari [Al 'Ala] dari [ayahnya] dari [Abu Hurairah], bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Orang kafir tidak akan berkumpul dengan pembunuhnya (Mukmin) dalam neraka.\""},"3267":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ عَوْنٍ الْهِلَالِيُّ حَدَّثَنَا أَبُو إِسْحَقَ الْفَزَارِيُّ إِبْرَاهِيمُ بْنُ مُحَمَّدٍ عَنْ سُهَيْلِ بْنِ أَبِي صَالِحٍ عَنْ أَبِيهِ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا يَجْتَمِعَانِ فِي النَّارِ اجْتِمَاعًا يَضُرُّ أَحَدُهُمَا الْآخَرَ قِيلَ مَنْ هُمْ يَا رَسُولَ اللَّهِ قَالَ مُؤْمِنٌ قَتَلَ كَافِرًا ثُمَّ سَدَّدَ","id":"Telah menceritakan kepada kami [Abdullah bin 'Aun Al Hilali] telah menceritakan kepada kami [Abu Ishaq Al Fazari Ibrahim bin Muhammad] dari [Suhail bin Abu Shalih] dari [ayahnya] dari [Abu Hurairah] dia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tidak akan berkumpul dalam neraka, yang salah satunya dapat membahayakan yang lain.\" Beliau ditanya, \"Siapa mereka wahai Rasulullah?\" Beliau menjawab: \"Seorang mukmin yang membunuh orang kafir, lalu dia konsisten dalam perlakuannya yang benar itu.\""},"3268":{"ar":"حَدَّثَنَا إِسْحَقُ بْنُ إِبْرَاهِيمَ الْحَنْظَلِيُّ أَخْبَرَنَا جَرِيرٌ عَنْ الْأَعْمَشِ عَنْ أَبِي عَمْرٍو الشَّيْبَانِيِّ عَنْ أَبِي مَسْعُودٍ الْأَنْصَارِيِّ قَالَجَاءَ رَجُلٌ بِنَاقَةٍ مَخْطُومَةٍ فَقَالَ هَذِهِ فِي سَبِيلِ اللَّهِ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَكَ بِهَا يَوْمَ الْقِيَامَةِ سَبْعُ مِائَةِ نَاقَةٍ كُلُّهَا مَخْطُومَةٌحَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا أَبُو أُسَامَةَ عَنْ زَائِدَةَ ح و حَدَّثَنِي بِشْرُ بْنُ خَالِدٍ حَدَّثَنَا مُحَمَّدٌ يَعْنِي ابْنَ جَعْفَرٍ حَدَّثَنَا شُعْبَةُ كِلَاهُمَا عَنْ الْأَعْمَشِ بِهَذَا الْإِسْنَادِ","id":"Telah menceritakan kepada kami [Ishaq bin Ibrahim Al Hanzhali] telah mengabarkan kepada kami [Jarir] dari [Al A'masy] dari [Abu 'Amru As Syaibani] dari [Abu Mas'ud Al Anshari] dia berkata, \"Seorang laki-laki datang dengan menuntun seekor unta yang telah diikat dengan tali kekangnya seraya berkata, \"Ini saya berikan untuk berjuang di jalan Allah.\" Lantas Rasulullah shallallahu 'alaihi wasallam bersabda: \"Mudah-mudahan pada hari kiamat kamu akan mendapatkan tujuh ratus unta beserta tali kekangnya.\" Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] telah menceritakan kepada kami [Abu Usamah] dari [Zaidah]. (Dalam jalur lain disebutkan) Telah menceritakan kepadaku [Bisyr bin Khalid] telah menceritakan kepada kami [Muhammad] -yaitu Ibnu Ja'far- telah menceritakan kepada kami [Syu'bah] keduanya dari [Al A'masy] dengan sanad ini.\""},"3269":{"ar":"و حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ وَأَبُو كُرَيْبٍ وَابْنُ أَبِي عُمَرَ وَاللَّفْظُ لِأَبِي كُرَيْبٍ قَالُوا حَدَّثَنَا أَبُو مُعَاوِيَةَ عَنْ الْأَعْمَشِ عَنْ أَبِي عَمْرٍو الشَّيْبَانِيِّ عَنْ أَبِي مَسْعُودٍ الْأَنْصَارِيِّ قَالَجَاءَ رَجُلٌ إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ إِنِّي أُبْدِعَ بِي فَاحْمِلْنِي فَقَالَ مَا عِنْدِي فَقَالَ رَجُلٌ يَا رَسُولَ اللَّهِ أَنَا أَدُلُّهُ عَلَى مَنْ يَحْمِلُهُ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ دَلَّ عَلَى خَيْرٍ فَلَهُ مِثْلُ أَجْرِ فَاعِلِهِو حَدَّثَنَا إِسْحَقُ بْنُ إِبْرَاهِيمَ أَخْبَرَنَا عِيسَى بْنُ يُونُسَ ح و حَدَّثَنِي بِشْرُ بْنُ خَالِدٍ أَخْبَرَنَا مُحَمَّدُ بْنُ جَعْفَرٍ عَنْ شُعْبَةَ ح و حَدَّثَنِي مُحَمَّدُ بْنُ رَافِعٍ حَدَّثَنَا عَبْدُ الرَّزَّاقِ أَخْبَرَنَا سُفْيَانُ كُلُّهُمْ عَنْ الْأَعْمَشِ بِهَذَا الْإِسْنَادِ","id":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] dan [Abu Kuraib] dan [Ibnu Abu Umar] dan ini adalah lafadz Abu Kuraib, mereka berkata; telah menceritakan kepada kami [Abu Mu'awiyah] dari [Al A'masy] dari [Abu 'Amru As Syaibani] dari [Abu Mas'ud Al Anshari] dia berkata, \"Seorang laki-laki datang kepada Nabi shallallahu 'alaihi wasallam seraya berkata, \"Wahai Rasulullah, jalan kami telah terputus karena hewan tungganganku telah mati, oleh karena itu bawalah saya dengan hewan tunggangan yang lain.\" Maka beliau bersabda: \"Saya tidak memiliki (hewan tunggangan yang lain).\" Tiba-tiba ada seorang laki-laki yang berkata, \"Wahai Rasulullah, saya dapat menunjukkan seseorang yang dapat membawanya (memperoleh penggantinya).\" Maka beliau bersabda: \"Barangsiapa dapat menunjukkan suatu kebaikan, maka dia akan mendapatkan pahala seperti orang yang melakukannya.\" Dan telah menceritakan kepada kami [Ishaq bin Ibrahim] telah mengabarkan kepada kami [Isa bin Yunus]. (dalam jalur lain disebutkan) Telah menceritakan kepadaku [Bisyr bin Khalid] telah mengabarkan kepada kami [Muhammad bin Ja'far] dari [Syu'bah]. (dalam jalur lain disebutkan) Telah menceritakan kepadaku [Muhammad bin Rafi'] telah menceritakan kepada kami [Abdurrazaq] telah mengabarkan kepada kami [Sufyan] semuanya dari [Al A'masy] dengan sanad ini.\""},"3270":{"ar":"و حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا عَفَّانُ حَدَّثَنَا حَمَّادُ بْنُ سَلَمَةَ حَدَّثَنَا ثَابِتٌ عَنْ أَنَسِ بْنِ مَالِكٍ ح و حَدَّثَنِي أَبُو بَكْرِ بْنُ نَافِعٍ وَاللَّفْظُ لَهُ حَدَّثَنَا بَهْزٌ حَدَّثَنَا حَمَّادُ بْنُ سَلَمَةَ حَدَّثَنَا ثَابِتٌ عَنْ أَنَسِ بْنِ مَالِكٍأَنَّ فَتًى مِنْ أَسْلَمَ قَالَ يَا رَسُولَ اللَّهِ إِنِّي أُرِيدُ الْغَزْوَ وَلَيْسَ مَعِي مَا أَتَجَهَّزُ قَالَ ائْتِ فُلَانًا فَإِنَّهُ قَدْ كَانَ تَجَهَّزَ فَمَرِضَ فَأَتَاهُ فَقَالَ إِنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُقْرِئُكَ السَّلَامَ وَيَقُولُ أَعْطِنِي الَّذِي تَجَهَّزْتَ بِهِ قَالَ يَا فُلَانَةُ أَعْطِيهِ الَّ��ِي تَجَهَّزْتُ بِهِ وَلَا تَحْبِسِي عَنْهُ شَيْئًا فَوَاللَّهِ لَا تَحْبِسِي مِنْهُ شَيْئًا فَيُبَارَكَ لَكِ فِيهِ","id":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] telah menceritakan kepada kami ['Affan] telah menceritakan kepada kami [Hammad bin Salamah] telah menceritakan kepada kami [Tsabit] dari [Anas bin Malik]. (dalam jalur lain disebutkan) Telah menceritakan kepadaku [Abu Bakar bin Nafi'] dan ini adalah lafadz dia, telah menceritakan kepada kami [Bahz] telah menceritakan kepada kami [Hammad bin Salamah] telah menceritakan kepada kami [Tsabit] dari [Anas bin Malik], bahwa seorang pemuda dari suku Aslam berkata, \"Wahai Rasulullah, sesungguhnya saya ingin ikut berperang, namun saya tidak memiliki perlengkapan.\" Beliau bersabda: \"Datangilah si fulan, sebab dia telah mempersiapkan perlengkapannya namun dia jatuh sakit.\" Maka datanglah pemuda itu kepada Fulan seraya berkata, \"Sesungguhnya Rasulullah shallallahu 'alaihi wasallam mengirim salam untuk anda, dan menyuruh anda memberikan perlengkapan anda kepadaku.\" Lalu orang yang sakit itu berkata, \"Wahai fulanah, berikanlah perlengkapan yang telah aku persiapkan kepadanya, dan jangan sampai ada yang ketinggalan satu pun. Demi Allah, jangan sampai ada yang ketinggalan satupun! Semoga Allah memberikan berkah kepadamu karenanya.\""},"3271":{"ar":"و حَدَّثَنَا سَعِيدُ بْنُ مَنْصُورٍ وَأَبُو الطَّاهِرِ قَالَ أَبُو الطَّاهِرِ أَخْبَرَنَا ابْنُ وَهْبٍ و قَالَ سَعِيدٌ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ وَهْبٍ أَخْبَرَنِي عَمْرُو بْنُ الْحَارِثِ عَنْ بُكَيْرِ بْنِ الْأَشَجِّ عَنْ بُسْرِ بْنِ سَعِيدٍ عَنْ زَيْدِ بْنِ خَالِدٍ الْجُهَنِيِّعَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهُ قَالَ مَنْ جَهَّزَ غَازِيًا فِي سَبِيلِ اللَّهِ فَقَدْ غَزَا وَمَنْ خَلَفَهُ فِي أَهْلِهِ بِخَيْرٍ فَقَدْ غَزَا","id":"Telah menceritakan kepada kami [Sa'id bin Manshur] dan [Abu At Thahir], Abu At Thahir berkata; telah mengabarkan kepada kami Wahb, dan Sa'id berkata; telah menceritakan kepada kami [Abdullah bin Wahb] telah mengabarkan kepadaku [Amru bin Al Harits] dari [Bukair bin Al Asyaj] dari [Busr bin Sa'id] dari [Zaid bin Khalid Al Juhani] dari Rasulullah shallallahu 'alaihi wasallam, bahwa beliau bersabda: \"Barangsiapa menyiapkan perlengkapan perang untuk orang yang akan berjuang di jalan Allah, berarti dia ikut berperang. Barangsiapa mengurusi keluarga yang ditinggalkan orang yang pergi berperang, berarti dia telah berperang.\""},"3272":{"ar":"حَدَّثَنَا أَبُو الرَّبِيعِ الزَّهْرَانِيُّ حَدَّثَنَا يَزِيدُ يَعْنِي ابْنَ زُرَيْعٍ حَدَّثَنَا حُسَيْنٌ الْمُعَلِّمُ حَدَّثَنَا يَحْيَى بْنُ أَبِي كَثِيرٍ عَنْ أَبِي سَلَمَةَ بْنِ عَبْدِ الرَّحْمَنِ عَنْ بُسْرِ بْنِ سَعِيدٍ عَنْ زَيْدِ بْنِ خَالِدٍ الْجُهَنِيِّ قَالَقَالَ نَبِيُّ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ جَهَّزَ غَازِيًا فَقَدْ غَزَا وَمَنْ خَلَفَ غَازِيًا فِي أَهْلِهِ فَقَدْ غَزَا","id":"Telah menceritakan kepada kami [Abu Ar Rabi' Az Zahrani] telah menceritakan kepada kami [Yazid] -yaitu Ibnu Zurai'- telah menceritakan kepada kami [Husain Al Mu'allim] telah menceritakan kepada kami [Yahya bin Abu Katsir] dari [Abu Salamah bin Abdurrahman] dari [Busr bin Sa'id] dari [Zaid bin Khalid Al Juhani] dia berkata, \"Nabi Allah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa mempersiapkan perlengkapan seseorang yang hendak berperang berarti dia ikut berperang, dan barangsiapa mengurusi keluarga orang yang berperang berarti dia telah ikut berperang.\""},"3273":{"ar":"و حَدَّثَنَا زُهَيْرُ بْنُ حَرْبٍ حَدَّثَنَا إِسْمَعِيلُ ابْنُ عُلَيَّةَ عَنْ عَلِيِّ بْنِ الْمُبَارَكِ حَدَّثَنَا يَحْيَى بْنُ أَبِي كَثِيرٍ حَدَّثَنِي أَبُو سَعِيدٍ مَوْلَى الْمَهْرِيِّ عَنْ أَبِي سَعِيدٍ الْخُدْرِيِّأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بَعَثَ بَعْثًا إِلَى بَنِي لَحْيَانَ مِنْ هُذَيْلٍ فَقَالَ لِيَنْبَعِثْ مِنْ كُلِّ رَجُلَيْنِ أَحَدُهُمَا وَالْأَجْرُ بَيْنَهُمَاو حَدَّثَنِيهِ إِسْحَقُ بْنُ مَنْصُورٍ أَخْبَرَنَا عَبْدُ الصَّمَدِ يَعْنِي ابْنَ عَبْدِ الْوَارِثِ قَالَ سَمِعْتُ أَبِي يُحَدِّثُ حَدَّثَنَا الْحُسَيْنُ عَنْ يَحْيَى حَدَّثَنِي أَبُو سَعِيدٍ مَوْلَى الْمَهْرِيِّ حَدَّثَنِي أَبُو سَعِيدٍ الْخُدْرِيُّ أَنَّ رَسُولَ اللَّهِ بَعَثَ بَعْثًا بِمَعْنَاهُ و حَدَّثَنِي إِسْحَقُ بْنُ مَنْصُورٍ أَخْبَرَنَا عُبَيْدُ اللَّهِ يَعْنِي ابْنَ مُوسَى عَنْ شَيْبَانَ عَنْ يَحْيَى بِهَذَا الْإِسْنَادِ مِثْلَهُ","id":"Dan telah menceritakan kepada kami [Zuhair bin Harb] telah menceritakan kepada kami [Isma'il bin 'Ulayyah] dari [Ali bin Mubarak] telah menceritakan kepada kami [Yahya bin Abu Katsir] telah menceritakan kepadaku [Abu Sa'id] bekas budak Al Mahri, dari [Abu Sa'id Al Khudri], bahwa Rasulullah shallallahu 'alaihi wasallam pernah mengirim utusan Bani Lahyan dari suku Hudzail, lalu beliau bersabda: \"Hendaknya setiap dua orang (dalam keluarga) keluar salah satunya, sedangkan pahala antara keduanya sama.\" Dan telah menceritakan kepadaku [Ishaq bin Manshur] telah mengabarkan kepada kami [Abdush Shamad] -yaitu Ibnu Abdul Warits- dia berkata; saya pernah mendengar [ayahku] berkata; telah menceritakan kepada kami [Al Husain] dari [Yahya] telah menceritakan kepadaku [Abu Sa'id] bekas budak Al Mahri, telah menceritakan kepadaku [Abu Sa'id Al Khudri], bahwa Rasulullah pernah mengirim suatu pasukan…, seperti makna hadits di atas.\" Dan telah menceritakan kepadaku [Ishaq bin Manshur] telah mengabarkan kepada kami ['Ubaidullah] -yaitu Ibnu Musa- dari [Syaiban] dari [Yahya] dengan sanad seperti ini.\""},"3274":{"ar":"و حَدَّثَنَا سَعِيدُ بْنُ مَنْصُورٍ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ وَهْبٍ أَخْبَرَنِي عَمْرُو بْنُ الْحَارِثِ عَنْ يَزِيدَ بْنِ أَبِي حَبِيبٍ عَنْ يَزِيدَ بْنِ أَبِي سَعِيدٍ مَوْلَى الْمَهْرِيِّ عَنْ أَبِيهِ عَنْ أَبِي سَعِيدٍ الْخُدْرِيِّأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بَعَثَ إِلَى بَنِي لَحْيَانَ لِيَخْرُجْ مِنْ كُلِّ رَجُلَيْنِ رَجُلٌ ثُمَّ قَالَ لِلْقَاعِدِ أَيُّكُمْ خَلَفَ الْخَارِجَ فِي أَهْلِهِ وَمَالِهِ بِخَيْرٍ كَانَ لَهُ مِثْلُ نِصْفِ أَجْرِ الْخَارِجِ","id":"Dan telah menceritakan kepada kami [Sa'id bin Manshur] telah menceritakan kepada kami [Abdullah bin Wahb] telah mengabarkan kepadaku [Amru bin Harits] dari [Yazid bin Abu Habib] dari [Yazid bin Abu Sa'id bekas budak Al Mahri] dari [ayahnya] dari [Abu Sa'id Al Khudri], bahwa Rasulullah shallallahu 'alaihi wasallam pernah mengirim utusan ke Bani Lahyan, agar setiap dua orang laki-laki (dari satu rumah) keluar satu orang laki-laki (untuk berperang), kemudian beliau bersabda kepada orang yang tidak ikut berperang: \"Kalian yang tidak ikut berperang, hendaknya mengurusi keluarga dan harta orang yang ikut berperang dengan baik, maka ia akan mendapatkan pahala setengah dari orang yang ikut berperang.\""},"3275":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا وَكِيعٌ عَنْ سُفْيَانَ عَنْ عَلْقَمَةَ بْنِ مَرْثَدٍ عَنْ سُلَيْمَانَ بْنِ بُرَيْدَةَ عَنْ أَبِيهِ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حُرْمَةُ نِسَاءِ الْمُجَاهِدِينَ عَلَى الْقَاعِدِينَ كَحُرْمَةِ أُمَّهَاتِهِمْ وَمَا مِنْ رَجُلٍ مِنْ الْقَاعِدِينَ يَخْلُفُ رَجُلًا مِنْ الْمُجَاهِدِينَ فِي أَهْلِهِ فَيَخُونُهُ فِيهِمْ إِلَّا وُقِفَ لَهُ يَوْمَ الْقِيَامَةِ فَيَأْخُذُ مِنْ عَمَلِهِ مَا شَاءَ فَمَا ظَنُّكُمْو حَدَّثَنِي مُحَمَّدُ بْنُ رَافِعٍ حَدَّثَنَا يَحْيَى بْنُ آدَمَ حَدَّثَنَا مِسْعَرٌ عَنْ عَلْقَمَةَ بْنِ مَرْثَدٍ عَنْ ابْنِ بُرَيْدَةَ عَنْ أَبِيهِ قَالَ قَالَ يَعْنِي النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِمَعْنَى حَدِيثِ الثَّوْرِيِّ و حَدَّثَنَاه سَعِيدُ بْنُ مَنْصُورٍ حَدَّثَنَا سُفْيَانُ عَنْ قَعْنَبٍ عَنْ عَلْقَمَةَ بْنِ مَرْثَدٍ بِهَذَا الْإِسْنَادِ فَقَالَ فَخُذْ مِنْ حَسَنَاتِهِ مَا شِئْتَ فَالْتَفَتَ إِلَيْنَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ فَمَا ظَنُّكُمْ","id":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] telah menceritakan kepada kami [Waki'] dari [Sufyan] dari ['Alqamah bin Martsad] dari [Sulaiman bin Buraidah] dari [ayahnya] dia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Kehormatan isteri-isteri para pejuang bagi mereka yang tidak ikut berjuang, seperti kehormatan ibu-ibu mereka. Tidaklah seseorang yang tidak ikut berperang karena suatu udzur, lalu dia diberi amanat oleh saudaranya yang ikut berperang untuk menjaga keluarganya, namun dia justru mengkhianatinya, melainkan di hari Kiamat kelak amalannya akan diambil oleh saudaranya dengan sesuka hatinya, lalu bagaimana dengan pendapat kalian?\" Dan telah menceritakan kepadaku [Muhammad bin Rafi'] telah menceritakan kepada kami [Yahya bin Adam] telah menceritakan kepada kami [Mis'ar] dari ['Alqamah bin Martsad] dari [Ibnu Buraidah] dari [ayahnya] dia berkata, \"Nabi shallallahu 'alaihi wasallam bersabda semakna dengan hadits At Tsauri.\" Dan telah menceritakan kepada kami [Sa'id bin Manshur] telah menceritakan kepada kami [Sufyan] dari [Qa'nab] dari ['Alqamah bin Martsad] dengan sanad ini, ia menyebutkan, \"Ambillah kebaikannya sesuka hatimu.\" Kemudian Rasulullah shallallahu 'alaihi wasallam menoleh kepada kami seraya bersabda: \"Bagaimana pendapatmu?\""},"3276":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ الْمُثَنَّى وَمُحَمَّدُ بْنُ بَشَّارٍ وَاللَّفْظُ لِابْنِ الْمُثَنَّى قَالَا حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ حَدَّثَنَا شُعْبَةُ عَنْ أَبِي إِسْحَقَ أَنَّهُ سَمِعَ الْبَرَاءَ يَقُولُا فِي هَذِهِ الْآيَةِ{ لَا يَسْتَوِي الْقَاعِدُونَ مِنْ الْمُؤْمِنِينَ }وَالْمُجَاهِدُونَ فِي سَبِيلِ اللَّهِ فَأَمَرَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ زَيْدًا فَجَاءَ بِكَتِفٍ يَكْتُبُهَا فَشَكَا إِلَيْهِ ابْنُ أُمِّ مَكْتُومٍ ضَرَارَتَهُ فَنَزَلَتْ{ لَا يَسْتَوِي الْقَاعِدُونَ مِنْ الْمُؤْمِنِينَ غَيْرُ أُولِي الضَّرَرِ }قَالَ شُعْبَةُ وَأَخْبَرَنِي سَعْدُ بْنُ إِبْرَاهِيمَ عَنْ رَجُلٍ عَنْ زَيْدِ بْنِ ثَابِتٍ فِي هَذِهِ الْآيَةِ{ لَا يَسْتَوِي الْقَاعِدُونَ مِنْ الْمُؤْمِنِينَ }بِمِثْلِ حَدِيثِ الْبَرَاءِ و قَالَ ابْنُ بَشَّارٍ فِي رِوَايَتِهِ سَعْدُ بْنُ إِبْرَاهِيمَ عَنْ أَبِيهِ عَنْ رَجُلٍ عَنْ زَيْدِ بْنِ ثَابِتٍ","id":"Telah menceritakan kepada kami [Muhammad bin Mutsanna] dan [Muhammad bin Basysyar] dan ini adalah lafadz Ibnu Mutsanna, keduanya berkata; telah menceritakan kepada kami [Muhammad bin Ja'far] telah menceritakan kepada kami [Syu'bah] dari [Abu Ishaq] bahwa dia pernah mendengar [Al Barra] berkomentar sehubungan dengan ayat ini: '(Tidaklah sama antara mukmin yang duduk (yang tidak ikut berperang) dengan orang-orang yang berjihad di jalan Allah …) ' (Qs. An Nisaa: 95), dan orang-orang yang berjihad di jalan Allah, kemudian Rasulullah shallallahu 'alaihi wasallam memerintahkan Zaid bin Tsabit untuk menulis ayat tersebut. Lalu Zaid datang dengan membawa tulang (pundak) kambing untuk menulis ayat tersebut. Tiba-tiba datanglah Ibnu Ummi Maktum mengadukan kesulitannya, tidak dapat turut berperang karena buta. Kemudian turunlah ayat: '(Tidaklah sama antara mukmin yang duduk (yang tidak ikut berperang) yang tidak mempunyai 'uzur dengan orang-orang yang berjihad di jalan Allah…) ' [Syu'bah] berkata; dan telah mengabarkan kepadaku [Sa'd bin Ibrahim] dari [seorang laki-laki] dari [Zaid bin Tsabit] berhubungan dengan ayat ini: '(Tidaklah sama antara mukmin yang duduk (yang tidak ikut berperang) …) ' seperti hadits Al Barra.\" Dan [Ibnu Basysyar] menyebutkan dalam riwayatnya; [Sa'd bin Ibrahim] dari [ayahnya] dari [seorang laki-laki] dari [Zaid bin Tsabit].\""},"3277":{"ar":"و حَدَّثَنَا أَبُو كُرَيْبٍ حَدَّثَنَا ابْنُ بِشْرٍ عَنْ مِسْعَرٍ حَدَّثَنِي أَبُو إِسْحَقَ عَنْ الْبَرَاءِ قَالَلَمَّا نَزَلَتْ{ لَا يَسْتَوِي الْقَاعِدُونَ مِنْ الْمُؤْمِنِينَ }كَلَّمَهُ ابْنُ أُمِّ مَكْتُومٍ فَنَزَلَتْ{ غَيْرُ أُولِي الضَّرَرِ }","id":"Dan telah menceritakan kepada kami [Abu Kuraib] telah menceritakan kepada kami [Ibnu Bisyr] dari [Mis'ar] telah menceritakan kepadaku [Abu Ishaq] dari [Al Barra] dia berkata, \"Tatkala turunnya ayat: '(Tidaklah sama antara mukmin yang duduk (yang tidak ikut berperang) …' (Qs. An Nisaa: 95), lalu Ibnu Ummi Maktum protes, maka setelah itu turunlah: '(yang tidak mempunyai 'uzur).\""},"3278":{"ar":"حَدَّثَنَا سَعِيدُ بْنُ عَمْرٍو الْأَشْعَثِيُّ وَسُوَيْدُ بْنُ سَعِيدٍ وَاللَّفْظُ لِسَعِيدٍ أَخْبَرَنَا سُفْيَانُ عَنْ عَمْرٍو سَمِعَ جَابِرًا يَقُولُاقَالَ رَجُلٌ أَيْنَ أَنَا يَا رَسُولَ اللَّهِ إِنْ قُتِلْتُ قَالَ فِي الْجَنَّةِ فَأَلْقَى تَمَرَاتٍ كُنَّ فِي يَدِهِ ثُمَّ قَاتَلَ حَتَّى قُتِلَ وَفِي حَدِيثِ سُوَيْدٍ قَالَ رَجُلٌ لِلنَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَوْمَ أُحُدٍ","id":"Telah menceritakan kepada kami [Sa'id bin 'Amru Al Asy'atsi] dan [Suwaid bin Sa'id] dan ini adalah lafadz Sa'id, telah mengabarkan kepada kami [Sufyan] dari ['Amru] dia mendengar [Jabir] berkata, \"Seorang laki-laki bertanya, \"Dimanakah tempatku jika saya terbunuh ya Rasulullah?\" beliau menjawab: \"Di surga.\" Setelah mendengar itu, dia membuang buah kurma yang ada di tangannya kemudian maju bertempur sampai meninggal.\" Dan dalam hadits Suwaid disebutkan, \"Seorang laki-laki bertanya kepada Nabi shallallahu 'alaihi wasallam pada waktu perang uhud.\""},"3279":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا أَبُو أُسَامَةَ عَنْ زَكَرِيَّاءَ عَنْ أَبِي إِسْحَقَ عَنْ الْبَرَاءِ قَالَ جَاءَ رَجُلٌ مِنْ بَنِي النَّبِيتِ إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ح و حَدَّثَنَا أَحْمَدُ بْنُ جَنَابٍ الْمِصِّيصِيُّ حَدَّثَنَا عِيسَى يَعْنِي ابْنَ يُونُسَ عَنْ زَكَرِيَّاءَ عَنْ أَبِي إِسْحَقَ عَنْ الْبَرَاءِ قَالَجَاءَ رَجُلٌ مِنْ بَنِي النَّبِيتِ قَبِيلٍ مِنْ الْأَنْصَارِ فَقَالَ أَشْهَدُ أَنْ لَا إِلَهَ إِلَّا اللَّهُ وَأَنَّكَ عَبْدُهُ وَرَسُولُهُ ثُمَّ تَقَدَّمَ فَقَاتَلَ حَتَّى قُتِلَ فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَمِلَ هَذَا يَسِيرًا وَأُجِرَ كَثِيرًا","id":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] telah menceritakan kepada kami [Abu Usamah] dari [Zakaria] dari [Abu Ishaq] dari [Al Barra] dia berkata, \"Seorang laki-laki dari Bani Nabit datang kepada Nabi shallallahu 'alaihi wasallam.\" (dalam jalur lain disebutkan) Telah menceritakan kepada kami [Ahmad bin Janab Al Mishshishi] telah menceritakan kepada kami [Isa] -yaitu Ibnu Yunus- dari [Zakaria] dari [Abu Ishaq] dari [Al Bara] dia berkata, \"Seorang laki-laki dari Bani Nabit dari kabilah Anshar datang seraya berkata, \"Saya bersaksi bahwa tidak ada tuhan yang berhak disembah kecuali Allah, dan sesungguhnya kamu adalah hamba dan utusan-Nya. Kemudian laki-laki itu maju bertempur hingga meninggal, maka Nabi shallallahu 'alaihi wasallam bersabda: \"(Orang ini) sedekit beramal, namun diganjar dengan pahala yang banyak.\""},"3280":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ النَّضْرِ بْنِ أَبِي النَّضْرِ وَهَارُونُ بْنُ عَبْدِ اللَّهِ وَمُحَمَّدُ بْنُ رَافِعٍ وَعَبْدُ بْنُ حُمَيْدٍ وَأَلْفَاظُهُمْ مُتَقَارِبَةٌ قَالُوا حَدَّثَنَا هَاشِمُ بْنُ الْقَاسِمِ حَدَّثَنَا سُلَيْمَانُ وَهُوَ ابْنُ الْمُغِيرَةِ عَنْ ثَابِتٍ عَنْ أَنَسِ بْنِ مَالِكٍ قَالَبَعَثَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بُسَيْسَةَ عَيْنًا يَنْظُرُ مَا صَنَعَتْ عِيرُ أَبِي سُفْيَانَ فَجَاءَ وَمَا فِي الْبَيْتِ أَحَدٌ غَيْرِي وَغَيْرُ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَا أَدْرِي مَا اسْتَثْنَى بَعْضَ نِسَائِهِ قَالَ فَحَدَّثَهُ الْحَدِيثَ قَالَ فَخَرَجَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَتَكَلَّمَ فَقَالَ إِنَّ لَنَا طَلِبَةً فَمَنْ كَانَ ظَهْرُهُ حَاضِرًا فَلْيَرْكَبْ مَعَنَا فَجَعَلَ رِجَالٌ يَسْتَأْذِنُونَهُ فِي ظُهْرَانِهِمْ فِي عُلْوِ الْمَدِينَةِ فَقَالَ لَا إِلَّا مَنْ كَانَ ظَهْرُهُ حَاضِرًا فَانْطَلَقَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَأَصْحَابُهُ حَتَّى سَبَقُوا الْمُشْرِكِينَ إِلَى بَدْرٍ وَجَاءَ الْمُشْرِكُونَ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا يُقَدِّمَنَّ أَحَدٌ مِنْكُمْ إِلَى شَيْءٍ حَتَّى أَكُونَ أَنَا دُونَهُ فَدَنَا الْمُشْرِكُونَ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قُومُوا إِلَى جَنَّةٍ عَرْضُهَا السَّمَوَاتُ وَالْأَرْضُ قَالَ يَقُولُ عُمَيْرُ بْنُ الْحُمَامِ الْأَنْصَارِيُّ يَا رَسُولَ اللَّهِ جَنَّةٌ عَرْضُهَا السَّمَوَاتُ وَالْأَرْضُ قَالَ نَعَمْ قَالَ بَخٍ بَخٍ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَا يَحْمِلُكَ عَلَى قَوْلِكَ بَخٍ بَخٍ قَالَ لَا وَاللَّهِ يَا رَسُولَ اللَّهِ إِلَّا رَجَاءَةَ أَنْ أَكُونَ مِنْ أَهْلِهَا قَالَ فَإِنَّكَ مِنْ أَهْلِهَا فَأَخْرَجَ تَمَرَاتٍ مِنْ قَرَنِهِ فَجَعَلَ يَأْكُلُ مِنْهُنَّ ثُمَّ قَالَ لَئِنْ أَنَا حَيِيتُ حَتَّى آكُلَ تَمَرَاتِي هَذِهِ إِنَّهَا لَحَيَاةٌ طَوِيلَةٌ قَالَ فَرَمَى بِمَا كَانَ مَعَهُ مِنْ التَّمْرِ ثُمَّ قَاتَلَهُمْ حَتَّى قُتِلَ","id":"Telah menceritakan kepada kami [Abu Bakar bin Nadlr bin Abu Nadlr] dan [Harun bin Abdullah] dan [Muhammad bin Rafi'] dan [Abd bin Humaid] dan lafadz mereka saling berdekatan, mereka berkata; telah menceritakan kepada kami [Hasyim bin Al Qasim] telah menceritakan kepada kami [Sulaiman] -yaitu Ibnu Al Mughirah- dari [Tsabit] dari [Anas bin Malik] dia berkata, \"Rasulullah shallallahu 'alaihi wasallam pernah mengutus Busaisah sebagai mata-mata, mengintai gerak-gerik kafilah Abu Sufyan. Busaisah lalu datang sedangkan di rumah tidak ada seorangpun selain saya dan Rasulullah shallallahu 'alaihi wasallam.\" Anas berkata, \"Saya tidak tahu apakah beliau mengistimewakan sebagian dari isterinya (untuk mendengar berita rahasia).\" Anas melanjutkan, \"Lantas Busaisah menyampaikan laporannya. Kemudian Rasulullah shallallahu 'alaihi wasallam keluar sambil bersabda: \"Kita berangkat sekarang untuk suatu tujuan, siapa yang telah siap kendaraannya, maka berangkatlah bersama kami.\" Lantas beberapa orang laki-laki meminta izin kepada beliau untuk mengambil kendaraannya di luar kota Madinah, namun beliau bersabda: \"Tidak, cukup orang-orang yang kendaraanya telah siap saja.\" Kemudian Rasulullah shallallahu 'alaihi wasallam dan para sahabatnya berangkat sehingga mereka lebih dahulu tiba di Badar daripada kaum Musyrikin. Tidak lama kemudian kaum Musyrikin tiba, maka Rasulullah shallallahu 'alaihi wasallam bersabda: \"Janganlah kalian bertindak sebelum ada perintah dariku.\" Ketika kaum Musyrikin semakin dekat, maka Rasulullah shallallahu 'alaihi wasallam bersabda: \"Majulah kalian ke surga, yang luasnya seluas langit dan bumi.\" Anas berkata, \"Tiba-tiba 'Umair bin Al Hammam Al Anshari berkata, \"Ya Rasulullah, surga yang luasnya seluas langit dan bumi!\" Beliau menjawab: \"Ya.\" 'Umair berkata, \"Wah, wah..!\" Maka Rasulullah shallallahu 'alaihi wasallam bersabda: \"Mengapa kamu mengatakan wah...wah..?\" Umair menjawab, \"Tidak, demi Allah wahai Rasulullah, saya mengharap semoga saya menjadi penghuninya.\" Beliau bersabda: \"Ya, sesungguhnya kamu termasuk dari penghuninya.\" Kemudian dia mengeluarkan kurma dari dalam sakunya dan memakannya sebagian. Sesudah itu dia berkata, \"Sungguh kehidupan yang lama bagiku, seandainya aku menghabiskan kurmaku ini.\" Anas berkata, \"Maka kurma yang masih tersisa di tangannya ia lemparkan begitu saja kemudian dia bertempur hingga gugur.\""},"3281":{"ar":"حَدَّثَنَا يَحْيَى بْنُ يَحْيَى التَّمِيمِيُّ وَقُتَيْبَةُ بْنُ سَعِيدٍ وَاللَّفْظُ لِيَحْيَى قَالَ قُتَيْبَةُ حَدَّثَنَا و قَالَ يَحْيَى أَخْبَرَنَا جَعْفَرُ بْنُ سُلَيْمَانَ عَنْ أَبِي عِمْرَانَ الْجَوْنِيِّ عَنْ أَبِي بَكْرِ بْنِ عَبْدِ اللَّهِ بْنِ قَيْسٍ عَنْ أَبِيهِ قَالَ سَمِعْتُ أَبِي وَهُوَ بِحَضْرَةِ الْعَدُوِّ يَقُولُاقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّ أَبْوَابَ الْجَنَّةِ تَحْتَ ظِلَالِ السُّيُوفِ فَقَامَ رَجُلٌ رَثُّ الْهَيْئَةِ فَقَالَ يَا أَبَا مُوسَى آنْتَ سَمِعْتَ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ هَذَا قَالَ نَعَمْقَالَ فَرَجَعَ إِلَى أَصْحَابِهِ فَقَالَ أَقْرَأُ عَلَيْكُمْ السَّلَامَ ثُمَّ كَسَرَ جَفْنَ سَيْفِهِ فَأَلْقَاهُ ثُمَّ مَشَى بِسَيْفِهِ إِلَى الْعَدُوِّ فَضَرَبَ بِهِ حَتَّى قُتِلَ","id":"Telah menceritakan kepada kami [Yahya bin Yahya At Tamimi] dan [Qutaibah bin Sa'id] dan ini adalah lafadz Yahya, Qutaibah berkata; telah menceritakan kepada kami, dan Yahya berkata; telah mengabarkan kepada kami [Ja'far bin Sulaiman] dari [Abu Imran Al Jauni] dari [Abu Bakar bin Abdullah bin Qais] dari ayahnya dia berkata, \"Saya pernah mendengar [ayahku] ketika dia sedang berhadapan dengan musuh, dia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sesungguhnya pintu-pintu surga terletak di bawah bayangan pedang.\" Tiba-tiba seorang laki-laki berdiri sambil menangis, katanya, \"Hai Abu Musa, apakah anda pernah mendengar Rasulullah shallallahu 'alaihi wasallam bersabda seperti itu?\" dia menjawab, \"Ya.\" Kakeknya Qais berkata, \"Kemudian dia kembali menemui kawan-kawannya seraya berkata, \"Saya menyampaikan salam buat kalian.\" Kemudian dia mengeluarkan pedang dari sarungnya lalu membuang sarung pedangnya, dengan pedang terhunus, dia lalu berjalan menemui musuh dan berperang dengan pedangnya hingga terbunuh.\""},"3282":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ حَاتِمٍ حَدَّثَنَا عَفَّانُ حَدَّثَنَا حَمَّادٌ أَخْبَرَنَا ثَابِتٌ عَنْ أَنَسِ بْنِ مَالِكٍ قَالَجَاءَ نَاسٌ إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالُوا أَنْ ابْعَثْ مَعَنَا رِجَالًا يُعَلِّمُونَا الْقُرْآنَ وَالسُّنَّةَ فَبَعَثَ إِلَيْهِمْ سَبْعِينَ رَجُلًا مِنْ الْأَنْصَارِ يُقَالُ لَهُمْ الْقُرَّاءُ فِيهِمْ خَالِي حَرَامٌ يَقْرَءُونَ الْقُرْآنَ وَيَتَدَارَسُونَ بِاللَّيْلِ يَتَعَلَّمُونَ وَكَانُوا بِالنَّهَارِ يَجِيئُونَ بِالْمَاءِ فَيَضَعُونَهُ فِي الْمَسْجِدِ وَيَحْتَطِبُونَ فَيَبِيعُونَهُ وَيَشْتَرُونَ بِهِ الطَّعَامَ لِأَهْلِ الصُّفَّةِ وَلِلْفُقَرَاءِ فَبَعَثَهُمْ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِلَيْهِمْ فَعَرَضُوا لَهُمْ فَقَتَلُوهُمْ قَبْلَ أَنْ يَبْلُغُوا الْمَكَانَ فَقَالُوا اللَّهُمَّ بَلِّغْ عَنَّا نَبِيَّنَا أَنَّا قَدْ لَقِينَاكَ فَرَضِينَا عَنْكَ وَرَضِيتَ عَنَّا قَالَ وَأَتَى رَجُلٌ حَرَامًا خَالَ أَنَسٍ مِنْ خَلْفِهِ فَطَعَنَهُ بِرُمْحٍ حَتَّى أَنْفَذَهُ فَقَالَ حَرَامٌ فُزْتُ وَرَبِّ الْكَعْبَةِ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لِأَصْحَابِهِ إِنَّ إِخْوَانَكُمْ قَدْ قُتِلُوا وَإِنَّهُمْ قَالُوا اللَّهُمَّ بَلِّغْ عَنَّا نَبِيَّنَا أَنَّا قَدْ لَقِينَاكَ فَرَضِينَا عَنْكَ وَرَضِيتَ عَنَّا","id":"Telah menceritakan kepada kami [Muhammad bin Hatim] telah menceritakan kepada kami ['Affan] telah menceritakan kepada kami [Hammad] telah mengabarkan kepada kami [Tsabit] dari [Anas bin Malik] dia berkata, \"Serombongan orang datang kepada Nabi shallallahu 'alaihi wasallam, lalu mereka berkata, \"Kirimkanlah bersama kami beberapa orang untuk mengajarkan Al Qur'an dan As Sunnah kepada kami.\" Maka beliau mengirim tujuh puluh orang laki-laki dari golongan Anshar, mereka di namakan Al Qurra (ahli dalam membaca Al-Qur'an). Mereka adalah orang-orang yang menjauhi perkara haram, selalu membaca dan mempelajari Al-Qur'an di malam hari, sedangkan di siang hari mereka mengangkut air ke masjid sehingga bisa digunakan untuk bersuci. Selain itu mereka juga mencari kayu bakar, setelah dijual, mereka gunakan uangnya untuk membeli makanan untuk ahli suffah dan orang-orang fakir. Nabi shallallahu 'alaihi wasallam lalu mengutus mereka menyertai rombongan tersebut. Di tengah perjalanan mereka diserang oleh rombongan tersebut, dan akhirnya mereka dibunuh sebelum sampai ke tempat tujuan. Namun mereka sempat berdo'a: \"Ya Allah, sampaikanlah kabar kami kepada Nabi kami, bahwa kami telah bertemu dengan-Mu. Kami ridla dengan-Mu dan Engkau ridla dengan kami.\" Anas melanjutkan, \"Ketika itu ada seseorang yang membuntuti Haram -paman Anas- dari belakang, rupanya Haram dapat menikamnya dengan tombak hingga ia berhasil membunuhnya. Setelah itu Haram berkata, \"Saya telah menang demi Rabb pemilik Ka'bah.\" Kemudian Rasulullah shallallahu 'alaihi wasallam bersabda kepada para sahabatnya: \"Sesungguhnya saudara-saudara kalian telah terbunuh, dan (sebelum terbunuh) mereka sempat berkata, \"Ya Allah, sampaikanlah kabar kami kepada Nabi kami, bahwa kami telah bertemu dengan-Mu. Kami ridla dengan-Mu dan Engkau ridla dengan kami'.\""},"3283":{"ar":"و حَدَّثَنِي مُحَمَّدُ بْنُ حَاتِمٍ حَدَّثَنَا بَهْزٌ حَدَّثَنَا سُلَيْمَانُ بْنُ الْمُغِيرَةِ عَنْ ثَابِتٍ قَالَ قَالَ أَنَسٌعَمِّيَ الَّذِي سُمِّيتُ بِهِ لَمْ يَشْهَدْ مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بَدْرًا قَالَ فَشَقَّ عَلَيْهِ قَالَ أَوَّلُ مَشْهَدٍ شَهِدَهُ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ غُيِّبْتُ عَنْهُ وَإِنْ أَرَانِيَ اللَّهُ مَشْهَدًا فِيمَا بَعْدُ مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَيَرَانِي اللَّهُ مَا أَصْنَعُ قَالَ فَهَابَ أَنْ يَقُولَ غَيْرَهَا قَالَ فَشَهِدَ مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَوْمَ أُحُدٍ قَالَ فَاسْتَقْبَلَ سَعْدُ بْنُ مُعَاذٍ فَقَالَ لَهُ أَنَسٌ يَا أَبَا عَمْرٍو أَيْنَ فَقَالَ وَاهًا لِرِيحِ الْجَنَّةِ أَجِدُهُ دُونَ أُحُدٍ قَالَ فَقَاتَلَهُمْ حَتَّى قُتِلَ قَالَ فَوُجِدَ فِي جَسَدِهِ بِضْعٌ وَثَمَانُونَ مِنْ بَيْنِ ضَرْبَةٍ وَطَعْنَةٍ وَرَمْيَةٍ قَالَ فَقَالَتْ أُخْتُهُ عَمَّتِيَ الرُّبَيِّعُ بِنْتُ النَّضْرِ فَمَا عَرَفْتُ أَخِي إِلَّا بِبَنَانِهِ وَنَزَلَتْ هَذِهِ الْآيَةُ{ رِجَالٌ صَدَقُوا مَا عَاهَدُوا اللَّهَ عَلَيْهِ فَمِنْهُمْ مَنْ قَضَى نَحْبَهُ وَمِنْهُمْ مَنْ يَنْتَظِرُ وَمَا بَدَّلُوا تَبْدِيلًا }قَالَ فَكَانُوا يُرَوْنَ أَنَّهَا نَزَلَتْ فِيهِ وَفِي أَصْحَابِهِ","id":"Dan telah menceritakan kepadaku [Muhammad bin Hatim] telah menceritakan kepada kami [Bahz] telah menceritakan kepada kami [Sulaiman bin Al Mughirah] dari [Tsabit] dia berkata; [Anas] berkata, \"Bahwa pamanku yang bernama seperti namaku tidak ikut perang bersama Rasulullah shallallahu 'alaihi wasallam ketika perang Badr.\" Anas berkata, \"Dengan perasaan menyesal dia berkata, \"Saya tidak hadir disaat pertempuran pertama kali yang diikuti Rasulullah shallallahu 'alaihi wasallam, jika Allah masih memberikan kesempatan kepadaku untuk berjuang bersama Rasulullah shallallahu 'alaihi wasallam setelah itu, sungguh Allah akan melihat apa yang akan saya perbuat.\" -sepertinya dia akan mengucapkan sesuatu selainnya- Anas berkata, \"Kemudian dia ikut serta bersama Rasulullah shallallahu 'alaihi wasallam pada perang uhud.\" Anas melanjutkan, \"Ketika Sa'ad bin Mu'adz menghampirinya, Anas bertanya kepadanya, 'Wahai Abu Amru, mau kemana anda? ' dia menjawab, 'Harumnya surga sudah aku cium dibalik gunung uhud.\" Anas bin Malik melanjutkan, \"Kemudian dia (pamanku) memerangi mereka (musuh) hingga terbunuh.\" Anas bin Malik berkata, \"Pada sekujur tubuhnya didapati delapan puluh lebih luka bekas sabetan pedang, tikaman tombak dan hujaman anak panah.\" Anas berkata, \"Maka saudara perempuannya -yaitu bibiku yang bernama Rubayi' binti An Nadlr- berkata, 'Saya tidak mengenali saudara laki-laki saya kecuali lewat jari jemarinya.' Kemudian turunlah ayat: '(Di antara orang-orang mukmin itu ada orang-orang yang menepati apa yang telah mereka janjikan kepada Allah; Maka di antara mereka ada yang gugur. dan di antara mereka ada (pula) yang menunggu- nunggu dan mereka tidak merubah (janjinya) '. (Qs. Al Ahzaab: 23). Anas berkata, \"Menurut mereka bahwa ayat tersebut turun berkenaan dengan dia dan para sahabat beliau yang lain.\""},"3284":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ الْمُثَنَّى وَابْنُ بَشَّارٍ وَاللَّفْظُ لِابْنِ الْمُثَنَّى قَالَا حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ حَدَّثَنَا شُعْبَةُ عَنْ عَمْرِو بْنِ مُرَّةَ قَالَ سَمِعْتُ أَبَا وَائِلٍ قَالَ حَدَّثَنَا أَبُو مُوسَى الْأَشْعَرِيُّأَنَّ رَجُلًا أَعْرَابِيًّا أَتَى النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ يَا رَسُولَ اللَّهِ الرَّجُلُ يُقَاتِلُ لِلْمَغْنَمِ وَالرَّجُلُ يُقَاتِلُ لِيُذْكَرَ وَالرَّجُلُ يُقَاتِلُ لِيُرَى مَكَانُهُ فَمَنْ فِي سَبِيلِ اللَّهِ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ قَاتَلَ لِتَكُونَ كَلِمَةُ اللَّهِ أَعْلَى فَهُوَ فِي سَبِيلِ اللَّهِ","id":"Telah menceritakan kepada kami [Muhammad bin Al Mutsanna] dan [Ibnu Basysyar] dan ini adalah lafadz Ibnu Mutsanna, keduanya berkata; telah menceritakan kepada kami [Muhammad bin Ja'far] telah menceritakan kepada kami [Syu'bah] dari ['Amru bin Murrah] dia berkata; saya pernah mendengar [Abu Wail] berkata; telah menceritakan kepada kami [Abu Musa Al Asy'ari], bahwa seorang laki-laki pedalaman datang kepada Nabi shallallahu 'alaihi wasallam seraya berkata, \"Wahai Rasulullah, ada seorang laki-laki yang berperang demi mendapatkan ghanimah, ada seorang laki-laki yang berperang supaya dirinya dikenal sebagai pahlawan, ada pula seorang laki-laki yang berperang agar dirinya dihormati, maka siapakah yang disebut berjuang di jalan Allah?\" maka Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa berjuang untuk menegakkan kalimat Allah setinggi-tingginya, maka itulah yang disebut berjuang di jalan Allah.\""},"3285":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ وَابْنُ نُمَيْرٍ وَإِسْحَقُ بْنُ إِبْرَاهِيمَ وَمُحَمَّدُ بْنُ الْعَلَاءِ قَالَ إِسْحَقُ أَخْبَرَنَا و قَالَ الْآخَرُونَ حَدَّثَنَا أَبُو مُعَاوِيَةَ عَنْ الْأَعْمَشِ عَنْ شَقِيقٍ عَنْ أَبِي مُوسَى قَالَسُئِلَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ الرَّجُلِ يُقَاتِلُ شَجَاعَةً وَيُقَاتِلُ حَمِيَّةً وَيُقَاتِلُ رِيَاءً أَيُّ ذَلِكَ فِي سَبِيلِ اللَّهِ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ قَاتَلَ لِتَكُونَ كَلِمَةُ اللَّهِ هِيَ الْعُلْيَا فَهُوَ فِي سَبِيلِ اللَّهِو حَدَّثَنَاه إِسْحَقُ بْنُ إِبْرَاهِيمَ أَخْبَرَنَا عِيسَى بْنُ يُونُسَ حَدَّثَنَا الْأَعْمَشُ عَنْ شَقِيقٍ عَنْ أَبِي مُوسَى قَالَ أَتَيْنَا رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقُلْنَا يَا رَسُولَ اللَّهِ الرَّجُلُ يُقَاتِلُ مِنَّا شَجَاعَةً فَذَكَرَ مِثْلَهُ","id":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] dan [Ibnu Numair] dan [Ishaq bin Ibrahim] dan [Muhammad bin Al 'Ala], Ishaq berkata; telah mengabarkan kepada kami, dan yang lainnya berkata; telah menceritakan kepada kami [Abu Mu'awiyah] dari [Al A'masy] dari [Syaqiq] dari [Abu Musa] dia berkata, \"Rasulullah shallallahu 'alaihi wasallam pernah ditanya mengenai seorang laki-laki yang berperang supaya dikatakan pemberani, berjuang karena membela kesukuan dan berjuang karena ingin dipuji, maka manakah yang disebut berjuang di jalan Allah?\" Rasulullah shallallahu 'alaihi wasallam lalu bersabda: \"Barangsiapa berjuang untuk menegakkan kalimat Allah setinggi-tingginya, maka itulah yang disebut berjuang di jalan Allah.\" Dan telah menceritakan kepada kami [Ishaq bin Ibrahim] telah mengabarkan kepada kami [Isa bin Yunus] telah menceritakan kepada kami [Al A'masy] dari [Syaqiq] dari [Abu Musa] dia berkata, \"Kami pernah mendatangi Rasulullah shallallahu 'alaihi wasallam, lalu kami bertanya, \"Wahai Rasulullah, di antara kami ada seseorang yang berjuang karena ingin dikatakan pemberani …\" kemudian dia menyebutkan hadits seperti di atas.\""},"3286":{"ar":"و حَدَّثَنَا إِسْحَقُ بْنُ إِبْرَاهِيمَ أَخْبَرَنَا جَرِيرٌ عَنْ مَنْصُورٍ عَنْ أَبِي وَائِلٍ عَنْ أَبِي مُوسَى الْأَشْعَرِيِّأَنَّ رَجُلًا سَأَلَ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ الْقِتَالِ فِي سَبِيلِ اللَّهِ عَزَّ وَجَلَّ فَقَالَ الرَّجُلُ يُقَاتِلُ غَضَبًا وَيُقَاتِلُ حَمِيَّةً قَالَ فَرَفَعَ رَأْسَهُ إِلَيْهِ وَمَا رَفَعَ رَأْسَهُ إِلَيْهِ إِلَّا أَنَّهُ كَانَ قَائِمًا فَقَالَ مَنْ قَاتَلَ لِتَكُونَ كَلِمَةُ اللَّهِ هِيَ الْعُلْيَا فَهُوَ فِي سَبِيلِ اللَّهِ","id":"Dan telah menceritakan kepada kami [Ishaq bin Ibrahim] telah mengabarkan kepada kami [Jarir] dari [Manshur] dari [Abu wail] dari [Abu Musa Al Asy'ari], bahwa seorang laki-laki bertanya kepada Rasulullah shallallahu 'alaihi wasallam tentang jihad di jalan Allah, dia berkata, \"Ada seseorang yang berjuang karena marah (balas dendam) dan berjuang karena membela kesukuan.\" Abu Musa berkata, \"Lalu dia mengangkat kepalanya menatap beliau, dan tidaklah dia mengangkat kepala melainkan saat itu karena beliau berdiri.\" Kemudian beliau menjawab: \"Barangsiapa berjuang untuk menegakkan kalimat Allah, maka itulah fi sabilillah.\""},"3287":{"ar":"حَدَّثَنَا يَحْيَى بْنُ حَبِيبٍ الْحَارِثِيُّ حَدَّثَنَا خَالِدُ بْنُ الْحَارِثِ حَدَّثَنَا ابْنُ جُرَيْجٍ حَدَّثَنِي يُونُسُ بْنُ يُوسُفَ عَنْ سُلَيْمَانَ بْنِ يَسَارٍ قَالَتَفَرَّقَ النَّاسُ عَنْ أَبِي هُرَيْرَةَ فَقَالَ لَهُ نَاتِلُ أَهْلِ الشَّامِ أَيُّهَا الشَّيْخُ حَدِّثْنَا حَدِيثًا سَمِعْتَهُ مِنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ نَعَمْ سَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ إِنَّ أَوَّلَ النَّاسِ يُقْضَى يَوْمَ الْقِيَامَةِ عَلَيْهِ رَجُلٌ اسْتُشْهِدَ فَأُتِيَ بِهِ فَعَرَّفَهُ نِعَمَهُ فَعَرَفَهَا قَالَ فَمَا عَمِلْتَ فِيهَا قَالَ قَاتَلْتُ فِيكَ حَتَّى اسْتُشْهِدْتُ قَالَ كَذَبْتَ وَلَكِنَّكَ قَاتَلْتَ لِأَنْ يُقَالَ جَرِيءٌ فَقَدْ قِيلَ ثُمَّ أُمِرَ بِهِ فَسُحِبَ عَلَى وَجْهِهِ حَتَّى أُلْقِيَ فِي النَّارِ وَرَجُلٌ تَعَلَّمَ الْعِلْمَ وَعَلَّمَهُ وَقَرَأَ الْقُرْآنَ فَأُتِيَ بِهِ فَعَرَّفَهُ نِعَمَهُ فَعَرَفَهَا قَالَ فَمَا عَمِلْتَ فِيهَا قَالَ تَعَلَّمْتُ الْعِلْمَ وَعَلَّمْتُهُ وَقَرَأْتُ فِيكَ الْقُرْآنَ قَالَ كَذَبْتَ وَلَكِنَّكَ تَعَلَّمْتَ الْعِلْمَ لِيُقَالَ عَالِمٌ وَقَرَأْتَ الْقُرْآنَ لِيُقَالَ هُوَ قَارِئٌ فَقَدْ قِيلَ ثُمَّ أُمِرَ بِهِ فَسُحِبَ عَلَى وَجْهِهِ حَتَّى أُلْقِيَ فِي النَّارِ وَرَجُلٌ وَسَّعَ اللَّهُ عَلَيْهِ وَأَعْطَاهُ مِنْ أَصْنَافِ الْمَالِ كُلِّهِ فَأُتِيَ بِهِ فَعَرَّفَهُ نِعَمَهُ فَعَرَفَهَا قَالَ فَمَا عَمِلْتَ فِيهَا قَالَ مَا تَرَكْتُ مِنْ سَبِيلٍ تُحِبُّ أَنْ يُنْفَقَ فِيهَا إِلَّا أَنْفَقْتُ فِيهَا لَكَ قَالَ كَذَبْتَ وَلَكِنَّكَ فَعَلْتَ لِيُقَالَ هُوَ جَوَادٌ فَقَدْ قِيلَ ثُمَّ أُمِرَ بِهِ فَسُحِبَ عَلَى وَجْهِهِ ثُمَّ أُلْقِيَ فِي النَّارِو حَدَّثَنَاه عَلِيُّ بْنُ خَشْرَمٍ أَخْبَرَنَا الْحَجَّاجُ يَعْنِي ابْنَ مُحَمَّدٍ عَنْ ابْنِ جُرَيْجٍ حَدَّثَنِي يُونُسُ بْنُ يُوسُفَ عَنْ سُلَيْمَانَ بْنِ يَسَارٍ قَالَ تَفَرَّجَ النَّاسُ عَنْ أَبِي هُرَيْرَةَ فَقَالَ لَهُ نَاتِلٌ الشَّامِىُّ وَاقْتَصَّ الْحَدِيثَ بِمِثْلِ حَدِيثِ خَالِدِ بْنِ الْحَارِثِ","id":"Telah menceritakan kepada kami [Yahya bin Habib Al Haritsi] telah menceritakan kepada kami [Khalid bin Al Harits] telah menceritakan kepada kami [Ibnu Juraij] telah menceritakan kepadaku [Yunus bin Yusuf] dari [Sulaiman bin Yasar] dia berkata, \"Orang-orang berpencar dari hadapan [Abu Hurairah], setelah itu Natil, seorang penduduk Syam, bertanya, \"Wahai Syaikh, ceritakanlah kepada kami hadits yang pernah kamu dengar dari Rasulullah shallallahu 'alaihi wasallam!\" dia menjawab, \"Ya, saya pernah mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sesungguhnya manusia yang pertama kali dihisap pada hari Kiamat ialah seseorang yang mati syahid, lalu diperlihatkan kepadanya kenikmatan sehingga ia mengetahuinya dengan jelas, lantas Dia bertanya: 'Apa yang telah kamu lakukan di dunia wahai hamba-Ku? Dia menjawab: 'Saya berjuang dan berperang demi Engkau ya Allah sehingga saya mati syahid.' Allah berfirman: 'Dusta kamu, sebenarnya kamu berperang bukan karena untuk-Ku, melainkan agar kamu disebut sebagai orang yang berani. Kini kamu telah menyandang gelar tersebut.' Kemudian diperintahkan kepadanya supaya dicampakkan dan dilemparkan ke dalam neraka. Dan didatangkan pula seseorang yang belajar Al-Qur'an dan mengajarkannya, lalu diperlihatkan kepadanya kenikmatan sehingga ia mengetahuinya dengan jelas, Allah bertanya: 'Apa yang telah kamu perbuat? ' Dia menjawab, 'Saya telah belajar ilmu dan mengajarkannya, saya juga membaca Al Qur'an demi Engkau.' Allah berfirman: 'Kamu dusta, akan tetapi kamu belajar ilmu dan mengajarkannya serta membaca Al Qur'an agar dikatakan seorang yang mahir dalam membaca, dan kini kamu telah dikatakan seperti itu, kemudian diperintahkan kepadanya supaya dia dicampakkan dan dilemparkan ke dalam neraka. Dan seorang laki-laki yang di beri keluasan rizki oleh Allah, kemudian dia menginfakkan hartanya semua, lalu diperlihatkan kepadanya kenikmatan sehingga ia mengetahuinya dengan jelas.' Allah bertanya: 'Apa yang telah kamu perbuat dengannya? ' dia menjawab, 'Saya tidak meninggalkannya sedikit pun melainkan saya infakkan harta benda tersebut di jalan yang Engkau ridlai.\" Allah berfirman: 'Dusta kamu, akan tetapi kamu melakukan hal itu supaya kamu dikatakan seorang yang dermawan, dan kini kamu telah dikatakan seperti itu.' Kemudian diperintahkan kepadanya supaya dia dicampakkan dan dilemparkan ke dalam neraka.\" Dan telah menceritakan kepadaku [Ali bin Khasyram] telah mengabarkan kepada kami [Al Hajjaj] -yaitu Ibnu Muhammad- dari [Ibnu Juraij] telah menceritakan kepadaku [Yunus bin Yusuf] dari [Sulaiman bin Yasar] dia berkata, \"Orang-orang berpencar dari hadapan [Abu Hurairah], lantas Natil As Syami …kemudian dia menyebutkan hadits tersebut seperti haditsnya Khalid bin Al Harits.\""},"3288":{"ar":"حَدَّثَنَا عَبْدُ بْنُ حُمَيْدٍ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ يَزِيدَ أَبُو عَبْدِ الرَّحْمَنِ حَدَّثَنَا حَيْوَةُ بْنُ شُرَيْحٍ عَنْ أَبِي هَانِئٍ عَنْ أَبِي عَبْدِ الرَّحْمَنِ الْحُبُلِيِّ عَنْ عَبْدِ اللَّهِ بْنِ عَمْرٍوأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَا مِنْ غَازِيَةٍ تَغْزُو فِي سَبِيلِ اللَّهِ فَيُصِيبُونَ الْغَنِيمَةَ إِلَّا تَعَجَّلُوا ثُلُثَيْ أَجْرِهِمْ مِنْ الْآخِرَةِ وَيَبْقَى لَهُمْ الثُّلُثُ وَإِنْ لَمْ يُصِيبُوا غَنِيمَةً تَمَّ لَهُمْ أَجْرُهُمْ","id":"Telah menceritakan kepada kami [Abd bin Humaid] telah menceritakan kepada kami [Abdullah bin Yazid Abu Abdurrahman] telah menceritakan kepada kami [Haiwah bin Syuraih] dari [Abu Hani`] dari [Abu Abdurrahman Al Hubuli] dari [Abdullah bin 'Amru] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tidaklah seseorang berperang di jalan Allah kemudian ia mengambil bagiannya dari harta ghanimah, melainkan sepertiga pahalanya telah terkurangi di akhirat kelak, namun jika dia tidak mengambil harta ghanimah tersebut, maka pahalanya menjadi sempurna.\""},"3289":{"ar":"حَدَّثَنِي مُحَمَّدُ بْنُ سَهْلٍ التَّمِيمِيُّ حَدَّثَنَا ابْنُ أَبِي مَرْيَمَ أَخْبَرَنَا نَافِعُ بْنُ يَزِيدَ حَدَّثَنِي أَبُو هَانِئٍ حَدَّثَنِي أَبُو عَبْدِ الرَّحْمَنِ الْحُبُلِيُّ عَنْ عَبْدِ اللَّهِ بْنِ عَمْرٍو قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَا مِنْ غَازِيَةٍ أَوْ سَرِيَّةٍ تَغْزُو فَتَغْنَمُ وَتَسْلَمُ إِلَّا كَانُوا قَدْ تَعَجَّلُوا ثُلُثَيْ أُجُورِهِمْ وَمَا مِنْ غَازِيَةٍ أَوْ سَرِيَّةٍ تُخْفِقُ وَتُصَابُ إِلَّا تَمَّ أُجُورُهُمْ","id":"Telah menceritakan kepadaku [Muhammad bin Sahl At Tamimi] telah menceritakan kepada kami [Ibnu Abu Maryam] telah mengabarkan kepada kami [Nafi' bin Yazid] telah menceritakan kepadaku [Abu Hani`] telah menceritakan kepadaku [Abu Abdurrahman Al Hubuli] dari [Abdullah bin 'Amru] dia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tidaklah seseorang yang berperang lalu dia memperoleh ghanimah dan mengambil (haknya), melainkan dia telah mengambil sepertiga dari pahalanya, dan tidaklah seseorang yang berperang dan mendapatkan ghanimah, namun ia tidak mengambil (haknya), melainkan pahalanya masih tetap sempurna.\""},"3290":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ مَسْلَمَةَ بْنِ قَعْنَبٍ حَدَّثَنَا مَالِكٌ عَنْ يَحْيَى بْنِ سَعِيدٍ عَنْ مُحَمَّدِ بْنِ إِبْرَاهِيمَ عَنْ عَلْقَمَةَ بْنِ وَقَّاصٍ عَنْ عُمَرَ بْنِ الْخَطَّابِ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّمَا الْأَعْمَالُ بِالنِّيَّةِ وَإِنَّمَا لِامْرِئٍ مَا نَوَى فَمَنْ كَانَتْ هِجْرَتُهُ إِلَى اللَّهِ وَرَسُولِهِ فَهِجْرَتُهُ إِلَى اللَّهِ وَرَسُولِهِ وَمَنْ كَانَتْ هِجْرَتُهُ لِدُنْيَا يُصِيبُهَا أَوْ امْرَأَةٍ يَتَزَوَّجُهَا فَهِجْرَتُهُ إِلَى مَا هَاجَرَ إِلَيْهِحَدَّثَنَا مُحَمَّدُ بْنُ رُمْحِ بْنِ الْمُهَاجِرِ أَخْبَرَنَا اللَّيْثُ ح و حَدَّثَنَا أَبُو الرَّبِيعِ الْعَتَكِيُّ حَدَّثَنَا حَمَّادُ ابْنُ زَيْدٍ ح و حَدَّثَنَا مُحَمَّدُ بْنُ الْمُثَنَّى حَدَّثَنَا عَبْدُ الْوَهَّابِ يَعْنِي الثَّقَفِيَّ ح و حَدَّثَنَا إِسْحَقُ بْنُ إِبْرَاهِيمَ أَخْبَرَنَا أَبُو خَالِدٍ الْأَحْمَرُ سُلَيْمَانُ بْنُ حَيَّانَ ح و حَدَّثَنَا مُحَمَّدُ بْنُ عَبْدِ اللَّهِ بْنِ نُمَيْرٍ حَدَّثَنَا حَفْصٌ يَعْنِي ابْنَ غِيَاثٍ وَيَزِيدُ بْنُ هَارُونَ ح و حَدَّثَنَا مُحَمَّدُ بْنُ الْعَلَاءِ الْهَمْدَانِيُّ حَدَّثَنَا ابْنُ الْمُبَارَكِ ح و حَدَّثَنَا ابْنُ أَبِي عُمَرَ حَدَّثَنَا سُفْيَانُ كُلُّهُمْ عَنْ يَحْيَى بْنِ سَعِيدٍ بِإِسْنَادِ مَالِكٍ وَمَعْنَى حَدِيثِهِ وَفِي حَدِيثِ سُفْيَانَ سَمِعْتُ عُمَرَ بْنَ الْخَطَّابِ عَلَى الْمِنْبَرِ يُخْبِرُ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah menceritakan kepada kami [Abdullah bin Maslamah bin Qa'nab] telah menceritakan kepada kami [Malik] dari [Yahya bin Sa'id] dari [Muhammad bin Ibrahim] dari ['Alqamah bin Waqash] dari [Umar bin Khattab] dia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sesungguhnya amalan itu tergantung dengan niatnya, dan sesungguhnya ia akan mendapatkan sesuatu yang diniatkannya, barangsiapa hijrahnya untuk Allah dan Rasul-Nya, maka hijrahnya untuk Allah dan Rasul-Nya, dan barangsiapa hijrahnya untuk memperoleh dunia atau seorang wanita yang akan dinikahinya, maka hijrahnya sesuai dengan apa yang diniatkannya.\" Dan telah menceritakan kepada kami [Muhammad bin Rumh bin Muhajir] telah mengabarkan kepada kami [Laits]. (dalam jalur lain disebutkan) Telah menceritakan kepada kami [Abu Ar Rabi' Al Ataki] telah menceritakan kepada kami [Hammad bin Zaid]. (dalam jalur lain disebutkan) Telah menceritakan kepada kami [Muhammad bin Al Mutsanna] telah menceritakan kepada kami [Abdul Wahhab] -yaitu Ats Tsaqafi-. (dalam jalur lain disebutkan) Telah menceritakan kepada kami [Ishaq bin Ibrahim] telah mengabarkan kepada kami [Abu Khalid Al Ahmar Sulaiman bin Hayyan]. (dalam jalur lain disebutkan) Telah menceritakan kepada kami [Muhammad bin Abdullah bin Numair] telah menceritakan kepada kami [Hafsh] -yaitu Ibnu Ghiyats- dan [Zaid bin Harun]. (dalam jalur lain disebutkan) Telah menceritakan kepada kami [Muhammad bin Al 'Ala Al Hamdani] telah menceritakan kepada kami [Ibnu Mubarak]. (dalam jalur lain disebutkan) Telah menceritakan kepada kami [Ibnu Abu Umar] telah menceritakan kepada kami [Sufyan] semuanya dari [Yahya bin Sa'id] dengan sanad makna seperti riwayat Malik. Dan dalam haditsnya Sufyan disebutkan, 'Saya mendengar Umar bin Khattab di atas mimbar mengabarkan dari Nabi shallallahu 'alaihi wasallam.\""},"3291":{"ar":"حَدَّثَنَا شَيْبَانُ بْنُ فَرُّوخَ حَدَّثَنَا حَمَّادُ بْنُ سَلَمَةَ حَدَّثَنَا ثَابِتٌ عَنْ أَنَسِ بْنِ مَالِكٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ طَلَبَ الشَّهَادَةَ صَادِقًا أُعْطِيَهَا وَلَوْ لَمْ تُصِبْهُ","id":"Telah menceritakan kepada kami [Syaiban bin Farruh] telah menceritakan kepada kami [Hammad bin Salamah] telah menceritakan kepada kami [Tsabit] dari [Anas bin Malik] dia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa memohon syahadah (mati dalam keadaan syahid) dengan sungguh-sungguh, maka sungguh ia akan diberi pahala seperti pahala mati syahid meskipun ia tidak mati syahid.\""},"3292":{"ar":"حَدَّثَنِي أَبُو الطَّاهِرِ وَحَرْمَلَةُ بْنُ يَحْيَى وَاللَّفْظُ لِحَرْمَلَةَ قَالَ أَبُو الطَّاهِرِ أَخْبَرَنَا و قَالَ حَرْمَلَةُ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ وَهْبٍ حَدَّثَنِي أَبُو شُرَيْحٍ أَنَّ سَهْلَ بْنَ أَبِي أُمَامَةَ بْنِ سَهْلِ بْنِ حُنَيْفٍ حَدَّثَهُ عَنْ أَبِيهِ عَنْ جَدِّهِأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ سَأَلَ اللَّهَ الشَّهَادَةَ بِصِدْقٍ بَلَّغَهُ اللَّهُ مَنَازِلَ الشُّهَدَاءِ وَإِنْ مَاتَ عَلَى فِرَاشِهِوَلَمْ يَذْكُرْ أَبُو الطَّاهِرِ فِي حَدِيثِهِ بِصِدْقٍ","id":"Telah menceritakan kepadaku [Abu At Thahir] dan [Harmalah bin Yahya] dan ini adalah lafadz Harmalah, Abu At Thahir berkata; telah mengabarkan kepada kami, sedangkan Harmalah mengatakan; telah menceritakan kepada kami [Abdullah bin Wahb] telah menceritakan kepadaku [Abu Syuraikh] bahwa [Sahl bin Abu Umamah bin Sahl bin Hunaif] telah menceritakan kepadanya dari [ayahnya] dari [kakeknya], bahwa Nabi shallallahu 'alaihi wasallam bersabda: \"Barangsiapa mengharapkan mati syahid dengan sungguh-sungguh, maka Allah akan mengangkatnya sampai ke derajat para syuhada' meski ia meninggal dunia di atas tempat tidur.\" Dan dalam hadits yang diriwayatkan Abu At Thahir tidak menyebutkan, 'Dengan sungguh-sungguh.'"},"3293":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ عَبْدِ الرَّحْمَنِ بْنِ سَهْمٍ الْأَنْطَاكِيُّ أَخْبَرَنَا عَبْدُ اللَّهِ بْنُ الْمُبَارَكِ عَنْ وُهَيْبٍ الْمَكِّيِّ عَنْ عُمَرَ بْنِ مُحَمَّدِ بْنِ الْمُنْكَدِرِ عَنْ سُمَيٍّ عَنْ أَبِي صَالِحٍ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ مَاتَ وَلَمْ يَغْزُ وَلَمْ يُحَدِّثْ بِهِ نَفْسَهُ مَاتَ عَلَى شُعْبَةٍ مِنْ نِفَاقٍقَالَ ابْنُ سَهْمٍ قَالَ عَبْدُ اللَّهِ بْنُ الْمُبَارَكِ فَنُرَى أَنَّ ذَلِكَ كَانَ عَلَى عَهْدِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah menceritakan kepada kami [Muhammad bin Abdurrahman bin Sahm Al Anthaki] telah mengabarkan kepada kami [Abdullah bin Mubarak] dari [Wuhaib Al Makki] dari [Umar bin Muhammad bin Al Munkadir] dari [Sumayyi] dari [Abu Shalih] dari [Abu Hurairah] dia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa meninggal sedang ia belum pernah ikut berperang atau belum pernah meniatkan dirinya untuk berperang, maka ia mati di atas cabang kemunafikan.\" Ibnu Sahm berkata; Abdullah bin Mubarak berkata, \"Lantas kami diberi pendapat bahwa hal itu berlaku di masa Rasulullah shallallahu 'alaihi wasallam.\""},"3294":{"ar":"حَدَّثَنَا عُثْمَانُ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا جَرِيرٌ عَنْ الْأَعْمَشِ عَنْ أَبِي سُفْيَانَ عَنْ جَابِرٍ قَالَكُنَّا مَعَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي غَزَاةٍ فَقَالَ إِنَّ بِالْمَدِينَةِ لَرِجَالًا مَا سِرْتُمْ مَسِيرًا وَلَا قَطَعْتُمْ وَادِيًا إِلَّا كَانُوا مَعَكُمْ حَبَسَهُمْ الْمَرَضُو حَدَّثَنَا يَحْيَى بْنُ يَحْيَى أَخْبَرَنَا أَبُو مُعَاوِيَةَ ح و حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ وَأَبُو سَعِيدٍ الْأَشَجُّ قَالَا حَدَّثَنَا وَكِيعٌ ح و حَدَّثَنَا إِسْحَقُ بْنُ إِبْرَاهِيمَ أَخْبَرَنَا عِيسَى بْنُ يُونُسَ كُلُّهُمْ عَنْ الْأَعْمَشِ بِهَذَا الْإِسْنَادِ غَيْرَ أَنَّ فِي حَدِيثِ وَكِيعٍ إِلَّا شَرِكُوكُمْ فِي الْأَجْرِ","id":"Telah menceritakan kepada kami [Utsman bin Abu Syaibah] telah menceritakan kepada kami [Jarir] dari [Al A'masy] dari [Abu Sufyan] dari [Jabir] dia berkata.\"Kami pernah ikut berperang bersama Nabi shallallahu 'alaihi wasallam dalam suatu peperangan, ketika itu beliau bersabda: \"Ada beberapa orang laki-laki di Madinah yang mereka tidak ikut serta dalam peperangan, biasanya jika kalian pergi berperang sedangkan kalian melewati suatu lembah, mereka tetap turut bersama-sama kamu, namun mereka sekarang terhalang karena sakit.\" Dan telah menceritakan kepada kami [Yahya bin Yahya] telah mengabarkan kepada kami [Abu Mu'awiyah]. (dalam jalur lain disebutkan) Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] dan [Abu Sa'id Al Asyaj] keduanya berkata; telah menceritakan kepada kami [Waki']. (dalam jalur lain disebutkan) Telah menceritakan kepada kami [Ishaq bin Ibrahim] telah mengabarkan kepada kami [Isa bin Yunus] semuanya dari [Al A'masy] dengan sanad ini, namun dalam haditsnya Waki' disebutkan; \"Melainkan mereka juga mendapatkan pahala seperti kalian.\""},"3295":{"ar":"حَدَّثَنَا يَحْيَى بْنُ يَحْيَى قَالَ قَرَأْتُ عَلَى مَالِكٍ عَنْ إِسْحَقَ بْنِ عَبْدِ اللَّهِ بْنِ أَبِي طَلْحَةَ عَنْ أَنَسِ بْنِ مَالِكٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يَدْخُلُ عَلَى أُمِّ حَرَامٍ بِنْتِ مِلْحَانَ فَتُطْعِمُهُ وَكَانَتْ أُمُّ حَرَامٍ تَحْتَ عُبَادَةَ بْنِ الصَّامِتِ فَدَخَلَ عَلَيْهَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَوْمًا فَأَطْعَمَتْهُ ثُمَّ جَلَسَتْ تَفْلِي رَأْسَهُ فَنَامَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ثُمَّ اسْتَيْقَظَ وَهُوَ يَضْحَكُ قَالَتْ فَقُلْتُ مَا يُضْحِكُكَ يَا رَسُولَ اللَّهِ قَالَ نَاسٌ مِنْ أُمَّتِي عُرِضُوا عَلَيَّ غُزَاةً فِي سَبِيلِ اللَّهِ يَرْكَبُونَ ثَبَجَ هَذَا الْبَحْرِ مُلُوكًا عَلَى الْأَسِرَّةِ أَوْ مِثْلَ الْمُلُوكِ عَلَى الْأَسِرَّةِ يَشُكُّ أَيَّهُمَا قَالَ قَالَتْ فَقُلْتُ يَا رَسُولَ اللَّهِ ادْعُ اللَّهَ أَنْ يَجْعَلَنِي مِنْهُمْ فَدَعَا لَهَا ثُمَّ وَضَعَ رَأْسَهُ فَنَامَ ثُمَّ اسْتَيْقَظَ وَهُوَ يَضْحَكُ قَالَتْ فَقُلْتُ مَا يُضْحِكُكَ يَا رَسُولَ اللَّهِ قَالَ نَاسٌ مِنْ أُمَّتِي عُرِضُوا عَلَيَّ غُزَاةً فِي سَبِيلِ اللَّهِ كَمَا قَالَ فِي الْأُولَى قَالَتْ فَقُلْتُ يَا رَسُولَ اللَّهِ ادْعُ اللَّهَ أَنْ يَجْعَلَنِي مِنْهُمْ قَالَ أَنْتِ مِنْ الْأَوَّلِينَ فَرَكِبَتْ أُمُّ حَرَامٍ بِنْتُ مِلْحَانَ الْبَحْرَ فِي زَمَنِ مُعَاوِيَةَ فَصُرِعَتْ عَنْ دَابَّتِهَا حِينَ خَرَجَتْ مِنْ الْبَحْرِ فَهَلَكَتْ","id":"Telah menceritakan kepada kami [Yahya bin Yahya] dia berkata; saya bacakan di hadapan [Malik]; dari [Ishaq bin Abdullah bin Abu Thalhah] dari [Anas bin Malik], bahwa Rasulullah shallallahu 'alaihi wasallam pernah menemui Ummu Haram binti Milhan -isteri Ubadah bin Shamit- kemudian ia menghidangkan makanan untuk beliau. Setelah itu Ummu Haram menyisir rambut Ummu Haram hingga Rasulullah shallallahu 'alaihi wasallam tertidur, tiba-tiba beliau terbangun sambil tertawa.\" Ummu Haram berkata, \"Apa yang menyebabkanmu tertawa wahai Rasulullah?\" beliau bersabda: 'Sekelompok umatku diperlihatkan Allah Ta'ala kepadaku, mereka berperang di jalan Allah mengarungi lautan dengan kapal, yaitu para raja di atas singgasana atau bagaikan para raja di atas singgasana.\" -perawi ragu antara keduanya- Ummu Haram berkata: \"Wahai Rasulullah, do'akanlah semoga saya termasuk di antara mereka.\" Kemudian beliau mendo'akannya. Setelah itu beliau meletakkan kepalanya hingga tertidur. Tiba-tiba beliau terbangun sambil tertawa.\" Ummu Haram berkata, \"Lalu saya bertanya: \"Wahai Rasulullah, apa yang membuatmu tertawa?\" beliau menjawab: \"Sekelompok umatku diperlihatkan Allah Ta'ala kepadaku, mereka berperang di jalan Allah…\" -sebagaimana sabda beliau yang pertama- Ummu Haram berkata; lalu saya berkata, \"Wahai Rasulullah, do'akanlah saya semoga termasuk di antara mereka!\" Beliau bersabda: \"Kamu termasuk dari rombongan pertama.\" Pada masa (pemerintahan) Mu'awiyah, Ummu Haram turut dalam pasukan Islam berlayar ke lautan (untuk berperang di jalan Allah), ketika mendarat, dia terjatuh dari kendaraannya hingga meninggal dunia.\""},"3296":{"ar":"حَدَّثَنَا خَلَفُ بْنُ هِشَامٍ حَدَّثَنَا حَمَّادُ بْنُ زَيْدٍ عَنْ يَحْيَى بْنِ سَعِيدٍ عَنْ مُحَمَّدِ بْنِ يَحْيَى بْنِ حَبَّانَ عَنْ أَنَسِ بْنِ مَالِكٍ عَنْ أُمِّ حَرَامٍ وَهِيَ خَالَةُ أَنَسٍ قَالَتْأَتَانَا النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَوْمًا فَقَالَ عِنْدَنَا فَاسْتَيْقَظَ وَهُوَ يَضْحَكُ فَقُلْتُ مَا يُضْحِكُكَ يَا رَسُولَ اللَّهِ بِأَبِي أَنْتَ وَأُمِّي قَالَ أُرِيتُ قَوْمًا مِنْ أُمَّتِي يَرْكَبُونَ ظَهْرَ الْبَحْرِ كَالْمُلُوكِ عَلَى الْأَسِرَّةِ فَقُلْتُ ادْعُ اللَّهَ أَنْ يَجْعَلَنِي مِنْهُمْ قَالَ فَإِنَّكِ مِنْهُمْ قَالَتْ ثُمَّ نَامَ فَاسْتَيْقَظَ أَيْضًا وَهُوَ يَضْحَكُ فَسَأَلْتُهُ فَقَالَ مِثْلَ مَقَالَتِهِ فَقُلْتُ ادْعُ اللَّهَ أَنْ يَجْعَلَنِي مِنْهُمْ قَالَ أَنْتِ مِنْ الْأَوَّلِينَ قَالَ فَتَزَوَّجَهَا عُبَادَةُ بْنُ الصَّامِتِ بَعْدُ فَغَزَا فِي الْبَحْرِ فَحَمَلَهَا مَعَهُ فَلَمَّا أَنْ جَاءَتْ قُرِّبَتْ لَهَا بَغْلَةٌ فَرَكِبَتْهَا فَصَرَعَتْهَا فَانْدَقَّتْ عُنُقُهَاو حَدَّثَنَاه مُحَمَّدُ بْنُ رُمْحِ بْنِ الْمُهَاجِرِ وَيَحْيَى بْنُ يَحْيَى قَالَا أَخْبَرَنَا اللَّيْثُ عَنْ يَحْيَى بْنِ سَعِيدٍ عَنْ ابْنِ حَبَّانَ عَنْ أَنَسِ بْنِ مَالِكٍ عَنْ خَالَتِهِ أُمِّ حَرَامٍ بِنْتِ مِلْحَانَ أَنَّهَا قَالَتْ نَامَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَوْمًا قَرِيبًا مِنِّي ثُمَّ اسْتَيْقَظَ يَتَبَسَّمُ قَالَتْ فَقُلْتُ يَا رَسُولَ اللَّهِ مَا أَضْحَكَكَ قَالَ نَاسٌ مِنْ أُمَّتِي عُرِضُوا عَلَيَّ يَرْكَبُونَ ظَهْرَ هَذَا الْبَحْرِ الْأَخْضَرِ ثُمَّ ذَكَرَ نَحْوَ حَدِيثِ حَمَّادِ بْنِ زَيْدٍ و حَدَّثَنِي يَحْيَى بْنُ أَيُّوبَ وَقُتَيْبَةُ وَابْنُ حُجْرٍ قَالُوا حَدَّثَنَا إِسْمَعِيلُ وَهُوَ ابْنُ جَعْفَرٍ عَنْ عَبْدِ اللَّهِ بْنِ عَبْدِ الرَّحْمَنِ أَنَّهُ سَمِعَ أَنَسَ بْنَ مَالِكٍ يَقُولُا أَتَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ابْنَةَ مِلْحَانَ خَالَةَ أَنَسٍ فَوَضَعَ رَأْسَهُ عِنْدَهَا وَسَاقَ الْحَدِيثَ بِمَعْنَى حَدِيثِ إِسْحَقَ بْنِ أَبِي طَلْحَةَ وَمُحَمَّدِ بْنِ يَحْيَى بْنِ حَبَّانَ","id":"Telah menceritakan kepada kami [Khalaf bin Hisyam] telah menceritakan kepada kami [Hammad bin Zaid] dari [Yahya bin Sa'id] dari [Muhammad bin Yahya bin Habban] dari [Anas bin Malik] dari [Ummu Haram] -dia adalah bibinya Anas- dia berkata, \"Suatu hari Nabi shallallahu 'alaihi wasallam menemui kami, ketika beliau bersada disamping kami tiba-tiba beliau terbangun sambil tertawa, maka saya bertanya, \"Demi ayah dan Ibuku, sebenarnya apa yang membuat anda tertawa wahai Rasulullah?\" beliau menjawab: \"Diperlihatkan kepadaku, sekelompok dari ummatku yang berperang mengarungi lautan sebagaimana para raja di atas singgasana.\" Lantas saya berkata, \"Do'akanlah semoga saya termasuk di antara kelompok tersebut!\" Beliau bersabda: \"Kamu termasuk di antara mereka.\" Ummu Haram melanjutkan, \"Kemudian beliau tidur lagi, tidak lama setelah itu tiba-tiba beliau terbangun sambil tertawa, maka saya bertanya, dan beliau pun menjawab sebagaimana jawaban beliau yang pertama. Maka saya berkata, \"Do'akanlah semoga saya termasuk di antara kelompok tersebut!\" Beliau bersabda: \"Kamu termasuk dari kelompok yang pertama.\" Anas berkata, \"Setelah itu dia menikah dengan Ubadah bin Shamit, lalu dia bersama suaminya ikut serta dalam peperangan di lautan, ketika hampir mendarat dia menaiki kendaraannya dan terpelanting hingga lehernya terbentur hingga mengakibatkan kematiannya.\" Dan telah menceritakan kepada kami [Muhammad bin Rumh Ibnu Muhajir] dan [Yahya bin Yahya] keduanya berkata; telah mengabarkan kepada kami [Laits] dari [Yahya bin Sa'id] dari [Ibnu Habban] dari [Anas bin Malik] dari bibinya, [Ummu Haram binti Milhan], bahwa dia berkata, \"Pada suatu hari Rasulullah shallallahu 'alaihi wasallam tertidur di dekatku, tiba-tiba beliau terbangun sambil tertawa.\" Ummu Haram melanjutkan, \"Lantas saya berkata, \"Apa yang membuatmu tertawa wahai Rasulullah?\" beliau menjawab: \"Diperlihatkan kepadaku sekelompok dari ummatku yang berperang di laut hijau ini…lalu dia menyebutkan seperti hadits riwayat [Hammad bin Zaid] dan telah menceritakan kepadaku [Yahya bin Ayyub] dan [Qutaibah] dan [Ibnu Hujr] mereka berkata; telah menceritakan kepada kami [Isma'il] -yaitu Ibnu Ja'far- dari [Abdullah bin Abdurrahman] bahwa dia pernah mendengar [Anas bin Malik] dia berkata, \"Rasulullah shallallahu 'alaihi wasallam pernah menemui puterinya Milhan -yaitu bibinya Anas- kemudian beliau menaruh kepalanya di sisi binti Milhan …lalu dia melanjutkan hadits tersebut semakna dengan hadits Ishaq bin Abu Thalhah dan Muhammad bin Yahya bin Habban.\""},"3297":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ عَبْدِ الرَّحْمَنِ بْنِ بَهْرَامٍ الدَّارِمِيُّ حَدَّثَنَا أَبُو الْوَلِيدِ الطَّيَالِسِيُّ حَدَّثَنَا لَيْثٌ يَعْنِي ابْنَ سَعْدٍ عَنْ أَيُّوبَ بْنِ مُوسَى عَنْ مَكْحُولٍ عَنْ شُرَحْبِيلَ بْنِ السِّمْطِ عَنْ سَلْمَانَ قَالَسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ رِبَاطُ يَوْمٍ وَلَيْلَةٍ خَيْرٌ مِنْ صِيَامِ شَهْرٍ وَقِيَامِهِ وَإِنْ مَاتَ جَرَى عَلَيْهِ عَمَلُهُ الَّذِي كَانَ يَعْمَلُهُ وَأُجْرِيَ عَلَيْهِ رِزْقُهُ وَأَمِنَ الْفَتَّانَحَدَّثَنِي أَبُو الطَّاهِرِ أَخْبَرَنَا ابْنُ وَهْبٍ عَنْ عَبْدِ الرَّحْمَنِ بْنِ شُرَيْحٍ عَنْ عَبْدِ الْكَرِيمِ بْنِ الْحَارِثِ عَنْ أَبِي عُبَيْدَةَ بْنِ عُقْبَةَ عَنْ شُرَحْبِيلَ بْنِ السِّمْطِ عَنْ سَلْمَانَ الْخَيْرِ عَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِمَعْنَى حَدِيثِ اللَّيْثِ عَنْ أَيُّوبَ بْنِ مُوسَى","id":"Telah menceritakan kepada kami [Abdullah bin Abdurrahman bin Bahram Ad Darimi] telah menceritakan kepada kami [Abu Al Walid At Thayalisi] telah menceritakan kepada kami [Laits] -yaitu Ibnu Sa'd- dari [Ayyub bin Musa] dari [Makhul] dari [Syurahbil bin As Simth] dari [Salman] dia berkata, \"Saya pernah mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Ribath (berjaga-jaga di perbatasan) sehari semalam lebih baik daripada puasa dan shalat malam sebulan penuh, jika dia meninggal maka amalannya senantiasa mengalir sebagaimana yang pernah dia amalkan, mengalir pula rizkinya dan terbebas dari fitnah.\" Telah menceritakan kepada kami [Abu At Thahir] telah mengabarkan kepada kami [Ibnu Wahb] dari [Abdurrahman bin Syuraih] dari [Abdul Karim bin Al Harits] dari [Abu 'Ubaidah bin 'Uqbah] dari [Syurahbil bin As Simth] dari [Salman Al Khair] dari Rasulullah shallallahu 'alaihi wasallam semakna dengan haditsnya Laits dari Ayyub bin Musa.\""},"3298":{"ar":"حَدَّثَنَا يَحْيَى بْنُ يَحْيَى قَالَ قَرَأْتُ عَلَى مَالِكٍ عَنْ سُمَيٍّ عَنْ أَبِي صَالِحٍ عَنْ أَبِي هُرَيْرَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ بَيْنَمَا رَجُلٌ يَمْشِي بِطَرِيقٍ وَجَدَ غُصْنَ شَوْكٍ عَلَى الطَّرِيقِ فَأَخَّرَهُ فَشَكَرَ اللَّهُ لَهُ فَغَفَرَ لَهُ وَقَالَ الشُّهَدَاءُ خَمْسَةٌ الْمَطْعُونُ وَالْمَبْطُونُ وَالْغَرِقُ وَصَاحِبُ الْهَدْمِ وَالشَّهِيدُ فِي سَبِيلِ اللَّهِ عَزَّ وَجَلَّ","id":"Telah menceritakan kepada kami [Yahya bin Yahya] dia berkata; saya bacakan di hadapan [Malik]; dari [Sumaiy] dari [Abu Shalih] dari [Abu Hurairah] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Ketika laki-laki sedang berjalan dan menemukan ranting berduri di tengah jalan, kemudian dia menyingkirkan ranting tersebut hingga Allah pun bersyukur kepadanya lalu mengampuni dosa-dosanya.\" Lalu beliau bersabda: \"Syuhada' itu ada lima macam; meninggal karena penyakit kolera, orang yang meninggal karena sakit perut, orang yang tenggelam, orang yang meninggal karena reruntuhan, dan orang yang syahid karena berjuang di jalan Allah 'azza wajalla.\""},"3299":{"ar":"و حَدَّثَنِي زُهَيْرُ بْنُ حَرْبٍ حَدَّثَنَا جَرِيرٌ عَنْ سُهَيْلٍ عَنْ أَبِيهِ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَا تَعُدُّونَ الشَّهِيدَ فِيكُمْ قَالُوا يَا رَسُولَ اللَّهِ مَنْ قُتِلَ فِي سَبِيلِ اللَّهِ فَهُوَ شَهِيدٌ قَالَ إِنَّ شُهَدَاءَ أُمَّتِي إِذًا لَقَلِيلٌ قَالُوا فَمَنْ هُمْ يَا رَسُولَ اللَّهِ قَالَ مَنْ قُتِلَ فِي سَبِيلِ اللَّهِ فَهُوَ شَهِيدٌ وَمَنْ مَاتَ فِي سَبِيلِ اللَّهِ فَهُوَ شَهِيدٌ وَمَنْ مَاتَ فِي الطَّاعُونِ فَهُوَ شَهِيدٌ وَمَنْ مَاتَ فِي الْبَطْنِ فَهُوَ شَهِيدٌقَالَ ابْنُ مِقْسَمٍ أَشْهَدُ عَلَى أَبِيكَ فِي هَذَا الْحَدِيثِ أَنَّهُ قَالَ وَالْغَرِيقُ شَهِيدٌ و حَدَّثَنِي عَبْدُ الْحَمِيدِ بْنُ بَيَانٍ الْوَاسِطِيُّ حَدَّثَنَا خَالِدٌ عَنْ سُهَيْلٍ بِهَذَا الْإِسْنَادِ مِثْلَهُ غَيْرَ أَنَّ فِي حَدِيثِهِ قَالَ سُهَيْلٌ قَالَ عُبَيْدُ اللَّهِ بْنُ مِقْسَمٍ أَشْهَدُ عَلَى أَخِيكَ أَنَّهُ زَادَ فِي هَذَا الْحَدِيثِ وَمَنْ غَرِقَ فَهُوَ شَهِيدٌ و حَدَّثَنِي مُحَمَّدُ بْنُ حَاتِمٍ حَدَّثَنَا بَهْزٌ حَدَّثَنَا وُهَيْبٌ حَدَّثَنَا سُهَيْلٌ بِهَذَا الْإِسْنَادِ وَفِي حَدِيثِهِ قَالَ أَخْبَرَنِي عُبَيْدُ اللَّهِ بْنُ مِقْسَمٍ عَنْ أَبِي صَالِحٍ وَزَادَ فِيهِ وَالْغَرِقُ شَهِيدٌ","id":"Telah menceritakan kepada kami [Zuhair bin Harb] telah menceritakan kepada kami [Jarir] dari [Suhail] dari [ayahnya] dari [Abu Hurairah] dia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Apa yang dimaksud orang yang mati syahid di antara kalian?\" para sahabat menjawab, \"Wahai Rasulullah, orang yang meninggal karena berjuang di jalan Allah itulah orang yang mati syahid.\" Beliau bersabda: \"Kalau begitu, sedikit sekali jumlah ummatku yang mati syahid.\" Para sahabat berkata, \"Lantas siapakah mereka ya Rasulullah?\" beliau bersabda: \"Barangsiapa terbunuh di jalan Allah maka dialah syahid, dan siapa yang mati di jalan Allah juga syahid, siapa yang mati karena penyakit kolera juga syahid, siapa yang mati karena sakit perut juga syahid.\" [Ibnu Miqsam] berkata, \"Saya bersaksi atas [bapakmu] mengenai hadits ini, bahwa beliau juga berkata, \"Orang yang meninggal karena tenggelam juga syahid.\" Dan telah menceritakan kepadaku [Abdul Hamid bin Bayan Al Wasithi] telah menceritakan kepada kami [Khalid] dari [Suhail] dengan sanad seperti ini, namun dalam haditsnya disebutkan; [Suhail] berkata; [Ubaidullah bin Miqsam] berkata, \"Saya bersaksi atas saudara laki-lakimu bahwa dalam hadits ini dia menambahkan, \"Barangsiapa meninggal karena tenggelam, maka ia syahid.\" Dan telah menceritakan kepadaku [Muhammad bin Hatim] telah menceritakan kepada kami [Bahz] telah menceritakan kepada kami [Wuhaib] telah menceritakan kepada kami [Suhail] dengan sanad ini, dan dalam haditsnya dia menyebutkan; telah mengabarkan kepadaku ['Ubaidullah bin Miqsam] dari [Abu Shalih] dan dia juga menambahkan, \"Dan orang yang meninggal karena tenggelam juga syahid.\""},"3300":{"ar":"حَدَّثَنَا حَامِدُ بْنُ عُمَرَ الْبَكْرَاوِيُّ حَدَّثَنَا عَبْدُ الْوَاحِدِ يَعْنِي ابْنَ زِيَادٍ حَدَّثَنَا عَاصِمٌ عَنْ حَفْصَةَ بِنْتِ سِيرِينَ قَالَتْ قَالَ لِي أَنَسُ بْنُ مَالِكٍبِمَ مَاتَ يَحْيَى بْنُ أَبِي عَمْرَةَ قَالَتْ قُلْتُ بِالطَّاعُونِ قَالَتْ فَقَالَ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الطَّاعُونُ شَهَادَةٌ لِكُلِّ مُسْلِمٍو حَدَّثَنَاه الْوَلِيدُ بْنُ شُجَاعٍ حَدَّثَنَا عَلِيُّ بْنُ مُسْهِرٍ عَنْ عَاصِمٍ فِي هَذَا الْإِسْنَادِ بِمِثْلِهِ","id":"Telah menceritakan kepada kami [Hamid bin Umar Al Bakrawi] telah menceritakan kepada kami [Abdul Wahid] -yaitu Ibnu Ziyad- telah menceritakan kepada kami ['Ashim] dari [Hafshah binti Sirin] dia berkata; [Anas bin Malik] pernah berkata kepadaku, \"Sebab apakah Yahya bin 'Amrah meninggal dunia?\" Hafshah berkata, \"Saya menjawab, \"Karena penyakit kolera.\" Hafshah melanjutkan, \"Lantas Anas berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Penyakit kolera dapat menjadikan mati syahid bagi setiap muslim.\" Dan telah menceritakan kepada kami [Al Walid bin Syuja'] telah menceritakan kepada kami [Ali bin Mushir] dari ['Ashim] dengan sanad seperti ini.\""},"3301":{"ar":"حَدَّثَنَا هَارُونُ بْنُ مَعْرُوفٍ أَخْبَرَنَا ابْنُ وَهْبٍ أَخْبَرَنِي عَمْرُو بْنُ الْحَارِثِ عَنْ أَبِي عَلِيٍّ ثُمَامَةَ بْنِ شُفَيٍّ أَنَّهُ سَمِعَ عُقْبَةَ بْنَ عَامِرٍ يَقُولُاسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَهُوَ عَلَى الْمِنْبَرِ يَقُولُ{ وَأَعِدُّوا لَهُمْ مَا اسْتَطَعْتُمْ مِنْ قُوَّةٍ }أَلَا إِنَّ الْقُوَّةَ الرَّمْيُ أَلَا إِنَّ الْقُوَّةَ الرَّمْيُ أَلَا إِنَّ الْقُوَّةَ الرَّمْيُ","id":"Telah menceritakan kepada kami [Harun bin Ma'ruf] telah mengabarkan kepada kami [Ibnu Wahb] telah mengabarkan kepadaku [Amru bin Al Harits] dari [Abu Ali Tsumamah bin Syufayi] bahwa dia mendengar ['Uqbah bin 'Amir] berkata, \"Saya pernah mendengar Rasulullah shallallahu 'alaihi wasallam menyampaikan ketika beliau di atas mimbar: '(Dan siapkanlah untuk menghadapi mereka kekuatan apa saja yang kamu sanggupi) ' (Qs. Al Anfaal: 60), ketahuilah sesungguhnya kekuatan itu adalah melempar, ketahuilah sesungguhnya kekuatan itu adalah melempar, ketahuilah sesungguhnya kekuatan itu adalah melempar.\""},"3302":{"ar":"حَدَّثَنَا هَارُونُ بْنُ مَعْرُوفٍ حَدَّثَنَا ابْنُ وَهْبٍ أَخْبَرَنِي عَمْرُو بْنُ الْحَارِثِ عَنْ أَبِي عَلِيٍّ عَنْ عُقْبَةَ بْنِ عَامِرٍ قَالَسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ سَتُفْتَحُ عَلَيْكُمْ أَرَضُونَ وَيَكْفِيكُمُ اللَّهُ فَلَا يَعْجِزُ أَحَدُكُمْ أَنْ يَلْهُوَ بِأَسْهُمِهِو حَدَّثَنَاه دَاوُدُ بْنُ رُشَيْدٍ حَدَّثَنَا الْوَلِيدُ عَنْ بَكْرِ بْنِ مُضَرَ عَنْ عَمْرِو بْنِ الْحَارِثِ عَنْ أَبِي عَلِيٍّ الْهَمْدَانِيِّ قَالَ سَمِعْتُ عُقْبَةَ بْنَ عَامِرٍ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِمِثْلِهِ","id":"Telah menceritakan kepada kami [Harun bin Ma'ruf] telah menceritakan kepada kami [Ibnu Wahb] telah mengabarkan kepadaku ['Amru bin Al Harits] dari [Abu 'Ali] dari ['Uqbah bin 'Amir] dia berkata, \"Saya mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Kalian akan menaklukkan banyak negeri dan Allah akan menyempurnakan (janji-Nya) kepada kalian, karena itu janganlah kalian bosan berlatih memanah.\" Dan telah menceritakan kepada kami [Daud bin Rusyaid] telah menceritakan kepada kami [Al Walid] dari [Bakr bin Mudlar] dari [Amru bin Al Harits] dari [Abu Ali Al Hamdani] dia berkata; saya pernah mendengar ['Uqbah bin 'Amir] dari Nabi shallallahu 'alaihi wasallam seperti hadits di atas.\""},"3303":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ رُمْحِ بْنِ الْمُهَاجِرِ أَخْبَرَنَا اللَّيْثُ عَنْ الْحَارِثِ بْنِ يَعْقُوبَ عَنْ عَبْدِ الرَّحْمَنِ بْنِ شِمَاسَةَ أَنَّ فُقَيْمًا اللَّخْمِيَّ قَالَ لِعُقْبَةَ بْنِ عَامِرٍ تَخْتَلِفُ بَيْنَ هَذَيْنِ الْغَرَضَيْنِ وَأَنْتَ كَبِيرٌ يَشُقُّ عَلَيْكَقَالَ عُقْبَةُ لَوْلَا كَلَامٌ سَمِعْتُهُ مِنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَمْ أُعَانِيهِ قَالَ الْحَارِثُ فَقُلْتُ لِابْنِ شَمَاسَةَ وَمَا ذَاكَ قَالَ إِنَّهُ قَالَ مَنْ عَلِمَ الرَّمْيَ ثُمَّ تَرَكَهُ فَلَيْسَ مِنَّا أَوْ قَدْ عَصَى","id":"Telah menceritakan kepada kami [Muhammad bin Rumh bin Al Muhajir] telah mengabarkan kepada kami [Al Laits] dari [Al Harits bin Ya'qub] dari [Abdurrahman bin Syimamah] bahwa Fuqaim Al Lakhmi berkata kepada ['Uqbah bin 'Amir], \"Kamu selalu bersungguh-sungguh antara dua target ini sedangkan kamu telah lanjut usia dan telah berat (sudah lemah).\" 'Uqbah berkata, \"Seandainya saya pernah mendengar sabda Rasulullah shallallahu 'alaihi wasallam niscaya saya tidak akan menjaganya.\" Lantas saya bertanya kepada Ibnu Syamasah, \"Apa yang disabdakan beliau itu?\" dia menjawab, \"Beliau bersabda: \"Tidak termasuk dari golongan kami -atau dia telah durhaka- siapa saja yang mengetahui ilmu memanah namun ia meninggalkannya.\""},"3304":{"ar":"حَدَّثَنَا سَعِيدُ بْنُ مَنْصُورٍ وَأَبُو الرَّبِيعِ الْعَتَكِيُّ وَقُتَيْبَةُ بْنُ سَعِيدٍ قَالُوا حَدَّثَنَا حَمَّادٌ وَهُوَ ابْنُ زَيْدٍ عَنْ أَيُّوبَ عَنْ أَبِي قِلَابَةَ عَنْ أَبِي أَسْمَاءَ عَنْ ثَوْبَانَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا تَزَالُ طَائِفَةٌ مِنْ أُمَّتِي ظَاهِرِينَ عَلَى الْحَقِّ لَا يَضُرُّهُمْ مَنْ خَذَلَهُمْ حَتَّى يَأْتِيَ أَمْرُ اللَّهِ وَهُمْ كَذَلِكَوَلَيْسَ فِي حَدِيثِ قُتَيْبَةَ وَهُمْ كَذَلِكَ","id":"Telah menceritakan kepada kami [Sa'id bin Manshur] dan [Abu Ar Rabi' Al 'Ataki] dan [Qutaibah bin Sa'id] mereka berkata; telah menceritakan kepada kami [Hammad] -yaitu Ibnu Zaid- dari [Ayyub] dari [Abu Qilabah] dari [Abu Asma'] dari [Tsauban] dia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Senantiasa ada sekelompok ummatku yang dimenangkan atas kebenaran, tidak akan membahayakannya orang yang memusuhinya hingga hari Kiamat sedangkan mereka tetap seperti itu.\" Namun dalam hadits Qutaibah tidak disebutkan, \"Sedangkan mereka tetap sepperti itu.\""},"3305":{"ar":"و حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا وَكِيعٌ ح و حَدَّثَنَا ابْنُ نُمَيْرٍ حَدَّثَنَا وَكِيعٌ وَعَبْدَةُ كِلَاهُمَا عَنْ إِسْمَعِيلَ بْنِ أَبِي خَالِدٍ ح و حَدَّثَنَا ابْنُ أَبِي عُمَرَ وَاللَّفْظُ لَهُ حَدَّثَنَا مَرْوَانُ يَعْنِي الْفَزَارِيَّ عَنْ إِسْمَعِيلَ عَنْ قَيْسٍ عَنْ الْمُغِيرَةِ قَالَسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ لَنْ يَزَالَ قَوْمٌ مِنْ أُمَّتِي ظَاهِرِينَ عَلَى النَّاسِ حَتَّى يَأْتِيَهُمْ أَمْرُ اللَّهِ وَهُمْ ظَاهِرُونَو حَدَّثَنِيهِ مُحَمَّدُ بْنُ رَافِعٍ حَدَّثَنَا أَبُو أُسَامَةَ حَدَّثَنِي إِسْمَعِيلُ عَنْ قَيْسٍ قَالَ سَمِعْتُ الْمُغِيرَةَ بْنَ شُعْبَةَ يَقُولُ سَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ بِمِثْلِ حَدِيثِ مَرْوَانَ سَوَاءً","id":"Dan telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] telah menceritakan kepada kami [Waki']. (dalam jalur lain disebutkan) Telah menceritakan kepada kami [Ibnu Numair] telah menceritakan kepada kami [Waki'] dan ['Abdah] keduanya dari [Isma'il bin Abu Khalid]. (dalam jalur lain disebutkan) Telah menceritakan kepada kami [Ibnu Abu 'Umar] dan ini adalah lafadz dia, telah menceritakan kepada kami [Marwan] -yaitu Al Fazari- dari [Isma'il] dari [Qais] dari [Al Mughirah] dia berkata, \"Saya mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Senantiasa ada sekelompok kaum dari ummatku yang dimenangkan atas manusia sehingga datang keputusan Allah (hari Kiamat).\" Dan telah menceritakan kepadaku [Muhammad bin Rafi'] telah menceritakan kepada kami [Abu Usamah] telah menceritakan kepadaku [Isma'il] dari [Qais] dia berkata; saya mendengar [Al Mughirah bin Syu'bah] berkata, \"Saya mendengar Rasulullah shallallahu 'alaihi wasallam bersabda seperti haditsnya Marwan.\""},"3306":{"ar":"و حَدَّثَنَا مُحَمَّدُ بْنُ الْمُثَنَّى وَمُحَمَّدُ بْنُ بَشَّارٍ قَالَا حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ حَدَّثَنَا شُعْبَةُ عَنْ سِمَاكِ بْنِ حَرْبٍ عَنْ جَابِرِ بْنِ سَمُرَةَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهُ قَالَ لَنْ يَبْرَحَ هَذَا الدِّينُ قَائِمًا يُقَاتِلُ عَلَيْهِ عِصَابَةٌ مِنْ الْمُسْلِمِينَ حَتَّى تَقُومَ السَّاعَةُ","id":"Dan telah menceritakan kepada kami [Muhammad bin Al Mutsanna] dan [Muhammad bin Basysyar] keduanya berkata; telah menceritakan kepada kami [Muhammad bin Ja'far] telah menceritakan kepada kami [Syu'bah] dari [Simak bin Harb] dari [Jabir bin Samurah] dari Nabi shallallahu 'alaihi wasallam, bahwa beliau bersabda: \"Agama ini akan senantiasa menang selagi masih ada sekelompok kaum Muslimin yang berperang (di jalan Allah) hingga datang hari Kiamat.\""},"3307":{"ar":"حَدَّثَنِي هَارُونُ بْنُ عَبْدِ اللَّهِ وَحَجَّاجُ بْنُ الشَّاعِرِ قَالَا حَدَّثَنَا حَجَّاجُ بْنُ مُحَمَّدٍ قَالَ قَالَ ابْنُ جُرَيْجٍ أَخْبَرَنِي أَبُو الزُّبَيْرِ أَنَّهُ سَمِعَ جَابِرَ بْنَ عَبْدِ اللَّهِ يَقُولُاسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ لَا تَزَالُ طَائِفَةٌ مِنْ أُمَّتِي يُقَاتِلُونَ عَلَى الْحَقِّ ظَاهِرِينَ إِلَى يَوْمِ الْقِيَامَةِ","id":"Telah menceritakan kepadaku [Harun bin Abdullah] dan [Hajjaj bin As Sya'ir] keduanya berkata; telah menceritakan kepada kami [Hajjaj bin Muhammad] dia berkata; [Ibnu Juraij] berkata; telah mengabarkan kepadaku [Abu Az Zubair] bahwa dia pernah mendengar [Jabir bin Abdullah] berkata, \"Saya pernah mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Senantiasa ada sekelompok dari ummatku yang selalu menang memperjuangkan kebenaran sampai hari Kiamat.\""},"3308":{"ar":"حَدَّثَنَا مَنْصُورُ بْنُ أَبِي مُزَاحِمٍ حَدَّثَنَا يَحْيَى بْنُ حَمْزَةَ عَنْ عَبْدِ الرَّحْمَنِ بْنِ يَزِيدَ بْنِ جَابِرٍ أَنَّ عُمَيْرَ بْنَ هَانِئٍ حَدَّثَهُ قَالَ سَمِعْتُ مُعَاوِيَةَ عَلَى الْمِنْبَرِ يَقُولُاسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ لَا تَزَالُ طَائِفَةٌ مِنْ أُمَّتِي قَائِمَةً بِأَمْرِ اللَّهِ لَا يَضُرُّهُمْ مَنْ خَذَلَهُمْ أَوْ خَالَفَهُمْ حَتَّى يَأْتِيَ أَمْرُ اللَّهِ وَهُمْ ظَاهِرُونَ عَلَى النَّاسِ","id":"Telah menceritakan kepada kami [Manshur bin Abu Muzahim] telah menceritakan kepada kami [Yahya bin Hamzah] dari [Abdurrahman bin Yazid bin Jabir] bahwa ['Umair bin Hani`] menceritakan kepadanya, dia berkata, \"Saya mendengar [Mu'awiyah] berkata di atas mimbar, \"Saya pernah mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Akan senantiasa ada sekelompok dari ummatku yang menegakkan perintah Allah, tidak ada yang membahayakannya orang yang menghinakan atau menyelisihi mereka sampai datangnya hari Kiamat, dan mereka akan selalu menang atas manusia.\""},"3309":{"ar":"و حَدَّثَنِي إِسْحَقُ بْنُ مَنْصُورٍ أَخْبَرَنَا كَثِيرُ بْنُ هِشَامٍ حَدَّثَنَا جَعْفَرٌ وَهُوَ ابْنُ بُرْقَانَ حَدَّثَنَا يَزِيدُ بْنُ الْأَصَمِّ قَالَ سَمِعْتُ مُعَاوِيَةَ بْنَ أَبِي سُفْيَانَ ذَكَرَ حَدِيثًا رَوَاهُ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَمْ أَسْمَعْهُ رَوَى عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَلَى مِنْبَرِهِ حَدِيثًا غَيْرَهُ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ يُرِدْ اللَّهُ بِهِ خَيْرًا يُفَقِّهْهُ فِي الدِّينِ وَلَا تَزَالُ عِصَابَةٌ مِنْ الْمُسْلِمِينَ يُقَاتِلُونَ عَلَى الْحَقِّ ظَاهِرِينَ عَلَى مَنْ نَاوَأَهُمْ إِلَى يَوْمِ الْقِيَامَةِ","id":"Dan telah menceritakan kepadaku [Ishaq bin Manshur] telah mengabarkan kepada kami [Katsir bin Hasyim] telah menceritakan kepada kami [Ja'far] -yaitu Ibnu Burqan- telah menceritakan kepada kami [Yazid bin Al Asham] dia berkata; saya pernah mendengar [Mu'awiyah bin Abu Sufyan] menyebutkan hadits yang ia riwayatkan dari Nabi shallallahu 'alaihi wasallam, saya belum pernah mendengar dia meriwayatkan sebuah hadits dari mimbar beliau selain hadits tersebut. Mu'awiyah berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa Allah kehendaki untuk menjadi baik, maka Allah akan pahamkan ia dalam masalah agama. Dan senantiasa ada sekelompok dari kaum Muslimin yang memperjuangkan kebenaran dan selalu menang atas orang yang memusuhinya sampai hari Kiamat.\""},"3310":{"ar":"حَدَّثَنِي أَحْمَدُ بْنُ عَبْدِ الرَّحْمَنِ بْنِ وَهْبٍ حَدَّثَنَا عَمِّي عَبْدُ اللَّهِ بْنُ وَهْبٍ حَدَّثَنَا عَمْرُو بْنُ الْحَارِثِ حَدَّثَنِي يَزِيدُ بْنُ أَبِي حَبِيبٍ حَدَّثَنِي عَبْدُ الرَّحْمَنِ بْنُ شِمَاسَةَ الْمَهْرِيُّ قَالَ كُنْتُ عِنْدَ مَسْلَمَةَ بْنِ مُخَلَّدٍ وَعِنْدَهُ عَبْدُ اللَّهِ بْنُ عَمْرِو بْنِ الْعَاصِ فَقَالَ عَبْدُ اللَّهِ لَا تَقُومُ السَّاعَةُ إِلَّا عَلَى شِرَارِ الْخَلْقِ هُمْ شَرٌّ مِنْ أَهْلِ الْجَاهِلِيَّةِ لَا يَدْعُونَ اللَّهَ بِشَيْءٍ إِلَّا رَدَّهُ عَلَيْهِمْ فَبَيْنَمَا هُمْ عَلَى ذَلِكَ أَقْبَلَ عُقْبَةُ بْنُ عَامِرٍ فَقَالَ لَهُ مَسْلَمَةُ يَا عُقْبَةُ اسْمَعْ مَا يَقُولُ عَبْدُ اللَّهِ فَقَالَ عُقْبَةُ هُوَ أَعْلَمُ وَأَمَّا أَنَافَسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ لَا تَزَالُ عِصَابَةٌ مِنْ أُمَّتِي يُقَاتِلُونَ عَلَى أَمْرِ اللَّهِ قَاهِرِينَ لِعَدُوِّهِمْ لَا يَضُرُّهُمْ مَنْ خَالَفَهُمْ حَتَّى تَأْتِيَهُمْ السَّاعَةُ وَهُمْ عَلَى ذَلِكَ فَقَالَ عَبْدُ اللَّهِ أَجَلْ ثُمَّ يَبْعَثُ اللَّهُ رِيحًا كَرِيحِ الْمِسْكِ مَسُّهَا مَسُّ الْحَرِيرِ فَلَا تَتْرُكُ نَفْسًا فِي قَلْبِهِ مِثْقَالُ حَبَّةٍ مِنْ الْإِيمَانِ إِلَّا قَبَضَتْهُ ثُمَّ يَبْقَى شِرَارُ النَّاسِ عَلَيْهِمْ تَقُومُ السَّاعَةُ","id":"Telah menceritakan kepadaku [Ahmad bin Abdurrahman bin Wahb] telah menceritakan kepada kami pamanku [Abdullah bin Wahb] telah menceritakan kepada kami ['Amru Al Harits] telah menceritakan kepadaku [Yazid bin Abu Habib] telah menceritakan kepadaku [Abdurrahman bin Syimamah Al Mahri] dia berkata, \"Ketika saya berada di tempat Maslamah bin Mukhallad yang saat itu ada [Abdullah bin 'Amru bin Al 'Ash]. Abdullah berkata, \"Hari Kiamat itu tidak akan menimpa kecuali atas makhluk yang paling jahat. Mereka lebih jahat daripada orang-orang yang hidup di masa jahiliyah. Tidaklah mereka memohon sesuatu kepada Allah kecuali Dia pasti akan menolaknya (tidak mengabulkannya).\" Ketika mereka bercakap-cakap demikian, tiba-tiba datanglah [Uqbah bin 'Amir]. Maka Maslamah berkata kepadanya, \"Wahai Uqbah, dengarkanlah apa yang dikatakan Abdullah.\" Lantas 'Uqbah berkata, \"Dia lebih mengetahui. Adapun saya, sesungguhnya saya juga pernah mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: 'Akan senantiasa ada dari umatku satu kelompok yang berperang di atas perkara Allah, mereka mengalahkan musuh-musuh mereka, dan orang-orang yang menyelisihi mereka tidak akan dapat membahayakan mereka sedikitpun hingga datang hari kiamat sedangkan mereka masih dalam keadaan seperti itu.\" Abdullah pun menimpali, \"Benar.\" Kemudian Allah mengirim sebuah angin yang baunya seperti bau misk dan lembutnya seperti lembut sutera, tidaklah ia melewati seseorang yang di dalam hatinya terdapat keimanan meskipun hanya seberat biji benih, kecuali ia pasti akan diwafatkannya. Maka tinggallah orang-orang jahat saja, lalu terjadilah hari kiamat.\""},"3311":{"ar":"حَدَّثَنَا يَحْيَى بْنُ يَحْيَى أَخْبَرَنَا هُشَيْمٌ عَنْ دَاوُدَ بْنِ أَبِي هِنْدٍ عَنْ أَبِي عُثْمَانَ عَنْ سَعْدِ بْنِ أَبِي وَقَّاصٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا يَزَالُ أَهْلُ الْغَرْبِ ظَاهِرِينَ عَلَى الْحَقِّ حَتَّى تَقُومَ السَّاعَةُ","id":"Telah menceritakan kepada kami [Yahya bin Yahya] telah mengabarkan kepada kami [Husyaim] dari [Daud bin Abu Hind] dari [Abu 'Utsman] dari [Sa'd bin Abu Waqqash] dia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Orang-orang Maghrib (Syam) akan terus nampak di atas kebenaran hingga datang hari kiamat\"."},"3312":{"ar":"حَدَّثَنِي زُهَيْرُ بْنُ حَرْبٍ حَدَّثَنَا جَرِيرٌ عَنْ سُهَيْلٍ عَنْ أَبِيهِ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا سَافَرْتُمْ فِي الْخِصْبِ فَأَعْطُوا الْإِبِلَ حَظَّهَا مِنْ الْأَرْضِ وَإِذَا سَافَرْتُمْ فِي السَّنَةِ فَأَسْرِعُوا عَلَيْهَا السَّيْرَ وَإِذَا عَرَّسْتُمْ بِاللَّيْلِ فَاجْتَنِبُوا الطَّرِيقَ فَإِنَّهَا مَأْوَى الْهَوَامِّ بِاللَّيْلِ","id":"Telah menceritakan kepadaku [Zuhair bin Harb] telah menceritakan kepada kami [Jarir] dari [Suhail] dari [ayahnya] dari [Abu Hurairah] dia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Apabila kalian melalui padang rumput yang subur maka berilah haknya unta (merumput) dari rerumputan di bumi, dan bila kamu berjalan di musim kemarau maka percepatlah perjalananmu (agar cepat sampai tujuan). Dan bila kamu istirahat dalam perjalanan malam hari maka jauhilah jalan raya, karena jalan raya itu tempat lewat serangga-serangga waktu malam.\""},"3313":{"ar":"حَدَّثَنَا قُتَيْبَةُ بْنُ سَعِيدٍ حَدَّثَنَا عَبْدُ الْعَزِيزِ يَعْنِي ابْنَ مُحَمَّدٍ عَنْ سُهَيْلٍ عَنْ أَبِيهِ عَنْ أَبِي هُرَيْرَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِذَا سَافَرْتُمْ فِي الْخِصْبِ فَأَعْطُوا الْإِبِلَ حَظَّهَا مِنْ الْأَرْضِ وَإِذَا سَافَرْتُمْ فِي السَّنَةِ فَبَادِرُوا بِهَا نِقْيَهَا وَإِذَا عَرَّسْتُمْ فَاجْتَنِبُوا الطَّرِيقَ فَإِنَّهَا طُرُقُ الدَّوَابِّ وَمَأْوَى الْهَوَامِّ بِاللَّيْلِ","id":"Telah menceritakan kepada kami [Qutaibah bin Sa'id] telah menceritakan kepada kami [Abdul Aziz] -yaitu Ibnu Muhammad- dari [Suhail] dari [ayahnya] dari [Abu Hurairah] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Jika kalian melewati padang rumput maka biarkanlah unta kalian memakan makanan di muka bumi, jika kalian mengadakan perjalanan di musim kemarau maka percepatlah perjalananmu (agar cepat sampai tujuan). Dan bila kamu istirahat dalam perjalanan malam hari, jauhilah jalan raya, karena jalan raya itu tempat lewat hewan melata dan serangga-serangga di waktu malam.\""},"3314":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ مَسْلَمَةَ بْنِ قَعْنَبٍ وَإِسْمَعِيلُ بْنُ أَبِي أُوَيْسٍ وَأَبُو مُصْعَبٍ الزُّهْرِيُّ وَمَنْصُورُ بْنُ أَبِي مُزَاحِمٍ وَقُتَيْبَةُ بْنُ سَعِيدٍ قَالُوا حَدَّثَنَا مَالِكٌ ح و حَدَّثَنَا يَحْيَى بْنُ يَحْيَى التَّمِيمِيُّ وَاللَّفْظُ لَهُ قَالَ قُلْتُ لِمَالِكٍ حَدَّثَكَ سُمَيٌّ عَنْ أَبِي صَالِحٍ عَنْ أَبِي هُرَيْرَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ السَّفَرُ قِطْعَةٌ مِنْ الْعَذَابِ يَمْنَعُ أَحَدَكُمْ نَوْمَهُ وَطَعَامَهُ وَشَرَابَهُ فَإِذَا قَضَى أَحَدُكُمْ نَهْمَتَهُ مِنْ وَجْهِهِ فَلْيُعَجِّلْ إِلَى أَهْلِهِ قَالَ نَعَمْ","id":"Telah menceritakan kepada kami [Abdullah bin Maslamah bin Qa'nab] dan [Isma'il bin Abu Uwais] dan [Abu Mus'ab Az Zuhri] dan [Manshur bin Abu Muzahim] dan [Qutaibah bin Sa'id], mereka berkata; telah menceritakan kepada kami [Malik]. (dalam jalur lain disebutkan) Telah menceritakan kepada kami [Yahya bin Yahya At Tamimi] dan ini adalah lafadz dari dia, dia berkata; saya pernah bertanya kepada [Malik], \"Apakah [Sumaiy] pernah menceritakan kepadamu dari [Abu Shalih] dari [Abu Hurairah] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Perjalanan itu setengah dari siksaan, sebab ia dapat mencegah salah seorang kalian dari tidurnya, makannya dan minumnya, oleh karena itu jika urusan kalian telah selesai, segeralah kembali kepada keluargamu.\" Malik menjawab, \"Betul.\""},"3315":{"ar":"حَدَّثَنِي أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا يَزِيدُ بْنُ هَارُونَ عَنْ هَمَّامٍ عَنْ إِسْحَقَ بْنِ عَبْدِ اللَّهِ بْنِ أَبِي طَلْحَةَ عَنْ أَنَسِ بْنِ مَالِكٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ لَا يَطْرُقُ أَهْلَهُ لَيْلًا وَكَانَ يَأْتِيهِمْ غُدْوَةً أَوْ عَشِيَّةًو حَدَّثَنِيهِ زُهَيْرُ بْنُ حَرْبٍ حَدَّثَنَا عَبْدُ الصَّمَدِ بْنُ عَبْدِ الْوَارِثِ حَدَّثَنَا هَمَّامٌ حَدَّثَنَا إِسْحَقُ بْنُ عَبْدِ اللَّهِ بْنِ أَبِي طَلْحَةَ عَنْ أَنَسِ بْنِ مَالِكٍ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِمِثْلِهِ غَيْرَ أَنَّهُ قَالَ كَانَ لَا يَدْخُلُ","id":"Telah menceritakan kepadaku [Abu Bakar bin Abu Syaibah] telah menceritakan kepada kami [Yazid bin Harun] dari [Hammam] dari [Ishaq bin Abdullah bin Abu Thalhah] dari [Anas bin Malik] bahwa Rasulullah shallallahu 'alaihi wasallam tidak pernah mendatangi (tiba dari perjalanan) keluarganya di malam hari, namun beliau datang ke keluarganya di pagi hari atau di petang hari.\" Dan telah menceritakan kepadaku [Zuhair bin Harb] telah menceritakan kepada kami [Abdush Shamad bin Abdul Warits] telah menceritakan kepada kami [Hammam] telah menceritakan kepada kami [Ishaq bin Abdullah bin Abu Thalhah] dari [Anas bin Malik] dari Nabi shallallahu 'alaihi wasallam seperti hadits di atas, hanya saja ia menyebutkan, \"Beliau tidak pernah masuk (menemui) ….\""},"3316":{"ar":"حَدَّثَنِي إِسْمَعِيلُ بْنُ سَالِمٍ حَدَّثَنَا هُشَيْمٌ أَخْبَرَنَا سَيَّارٌ ح و حَدَّثَنَا يَحْيَى بْنُ يَحْيَى وَاللَّفْظُ لَهُ حَدَّثَنَا هُشَيْمٌ عَنْ سَيَّارٍ عَنْ الشَّعْبِيِّ عَنْ جَابِرِ بْنِ عَبْدِ اللَّهِ قَالَكُنَّا مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي غَزَاةٍ فَلَمَّا قَدِمْنَا الْمَدِينَةَ ذَهَبْنَا لِنَدْخُلَ فَقَالَ أَمْهِلُوا حَتَّى نَدْخُلَ لَيْلًا أَيْ عِشَاءً كَيْ تَمْتَشِطَ الشَّعِثَةُ وَتَسْتَحِدَّ الْمُغِيبَةُ","id":"Telah menceritakan kepadaku [Isma'il bin Salim] telah menceritakan kepada kami [Husyaim] telah mengabarkan kepada kami [Sayyar]. (dalam jalur lain disebutkan) Telah menceritakan kepada kami [Yahya bin Yahya] dan ini adalah lafadz dia, telah menceritakan kepada kami [Husyaim] dari [Yasar] dari [As Sya'bi] dari [Jabir bin Abdullah] dia berkata, \"Kami pernah berperang bersama Nabi shallallahu 'alaihi wasallam, setelah kami tiba di Madinah, kami bermaksud hendak segera pulang ke rumah kami masing-masing. Namun beliau bersabda: \"Tunggulah dahulu hingga hari agak senja, sisirlah dahulu rambut kalian yang kusut, berilah kesempatan kepada keluarga kalian untuk bersiap-siap dan berhias (untuk menyambut kedatangan kalian).\""},"3317":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ الْمُثَنَّى حَدَّثَنِي عَبْدُ الصَّمَدِ حَدَّثَنَا شُعْبَةُ عَنْ سَيَّارٍ عَنْ عَامِرٍ عَنْ جَابِرٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا قَدِمَ أَحَدُكُمْ لَيْلًا فَلَا يَأْتِيَنَّ أَهْلَهُ طُرُوقًا حَتَّى تَسْتَحِدَّ الْمُغِيبَةُ وَتَمْتَشِطَ الشَّعِثَةُو حَدَّثَنِيهِ يَحْيَى بْنُ حَبِيبٍ حَدَّثَنَا رَوْحُ بْنُ عُبَادَةَ حَدَّثَنَا شُعْبَةُ حَدَّثَنَا سَيَّارٌ بِهَذَا الْإِسْنَادِ مِثْلَهُ","id":"Telah menceritakan kepada kami [Muhammad bin Al Mutsanna] telah menceritakan kepadaku [Abdush Shamad] telah menceritakan kepada kami [Syu'bah] dari [Yasar] dari ['Amir] dari [Jabir] dia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Jika salah seorang dari kalian tiba (dari perjalanan) janganlah kalian pulang ke rumah keluargamu tengah malam, supaya keluarga yang ditinggalkan dapat bersiap-siap dan menyisir rambut (menyambut kedatanganmu).\" Dan telah menceritakan kepadaku [Yahya bin Habib] telah menceritakan kepada kami [Rauh bin 'Ubadah] telah menceritakan kepada kami [Syu'bah] telah menceritakan kepada kami [Sayyar] dengan sanad seperti ini.\""},"3318":{"ar":"و حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا مُحَمَّدٌ يَعْنِي ابْنَ جَعْفَرٍ حَدَّثَنَا شُعْبَةُ عَنْ عَاصِمٍ عَنْ الشَّعْبِيِّ عَنْ جَابِرِ بْنِ عَبْدِ اللَّهِ قَالَنَهَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا أَطَالَ الرَّجُلُ الْغَيْبَةَ أَنْ يَأْتِيَ أَهْلَهُ طُرُوقًاو حَدَّثَنِيهِ يَحْيَى بْنُ حَبِيبٍ حَدَّثَنَا رَوْحٌ حَدَّثَنَا شُعْبَةُ بِهَذَا الْإِسْنَادِ","id":"Telah menceritakan kepada kami [Muhammad bin Basysyar] telah menceritakan kepada kami [Muhammad] -yaitu Ibnu Ja'far- telah menceritakan kepada kami [Syu'bah] dari ['Ashim] dari [Sya'bi] dari [Jabir bin Abdullah] dia berkata, \"Jika seorang laki-laki lama meninggalkan rumah, maka Rasulullah shallallahu 'alaihi wasallam melarangnya untuk masuk rumah (saat kembali) di waktu malam.\" Dan telah menceritakan kepadaku [Yahya bin Habib] telah menceritakan kepada kami [Rauh] telah menceritakan kepada kami [Syu'bah] dengan sanad ini.\""},"3319":{"ar":"و حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا وَكِيعٌ عَنْ سُفْيَانَ عَنْ مُحَارِبٍ عَنْ جَابِرٍ قَالَنَهَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنْ يَطْرُقَ الرَّجُلُ أَهْلَهُ لَيْلًا يَتَخَوَّنُهُمْ أَوْ يَلْتَمِسُ عَثَرَاتِهِمْو حَدَّثَنِيهِ مُحَمَّدُ بْنُ الْمُثَنَّى حَدَّثَنَا عَبْدُ الرَّحْمَنِ حَدَّثَنَا سُفْيَانُ بِهَذَا الْإِسْنَادِ قَالَ عَبْدُ الرَّحْمَنِ قَالَ سُفْيَانُ لَا أَدْرِي هَذَا فِي الْحَدِيثِ أَمْ لَا يَعْنِي أَنْ يَتَخَوَّنَهُمْ أَوْ يَلْتَمِسَ عَثَرَاتِهِمْ و حَدَّثَنَا مُحَمَّدُ بْنُ الْمُثَنَّى حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ ح و حَدَّثَنَا عُبَيْدُ اللَّهِ بْنُ مُعَاذٍ حَدَّثَنَا أَبِي قَالَا جَمِيعًا حَدَّثَنَا شُعْبَةُ عَنْ مُحَارِبٍ عَنْ جَابِرٍ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِكَرَاهَةِ الطُّرُوقِ وَلَمْ يَذْكُرْ يَتَخَوَّنُهُمْ أَوْ يَلْتَمِسُ عَثَرَاتِهِمْ","id":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] telah menceritakan kepada kami [Waki'] dari [Sufyan] dari [Muharib] dari [Jabir] dia berkata, \"Rasulullah shallallahu 'alaihi wasallam melarang seorang laki-laki mengetuk pintu rumah isterinya (saat kembali dari perjalanan) di waktu malam dengan maksud hendak memergoki atau mencari-cari kesalahan mereka.\" Dan telah menceritakan kepadaku [Muhammad bin Al Mutsanna] telah menceritakan kepada kami [Abdurrahman] telah menceritakan kepada kami [Sufyan] dengan sanad ini. [Abdurrahman] berkata; [Sufyan] berkata, \"Saya tidak tahu pernyataan ini ada dalam hadits ini atau tidak, yakni kalimat 'dengan maksud untuk memergoki mereka atau mencari-cari kesalahan mereka'. Dan telah menceritakan kepada kami [Muhammad bin Al Mutsanna] telah menceritakan kepada kami [Muhammad bin Ja'far]. (dalam jalur lain disebutkan) Telah menceritakan kepada kami [Ubaidullah bin Mu'adz] telah menceritakan kepada kami [ayahku] semuanya berkata; telah menceritakan kepada kami [Syu'bah] dari [Muharib] dari [Jabir] dari Nabi shallallahu 'alaihi wasallam, bahwa beliau membenci seseorang pulang tengah malam (secara tiba-tiba), dan tidak menyebutkan, 'Untuk memergoki mereka atau mencari-cari kesalahan mereka'.\""},"3320":{"ar":"حَدَّثَنَا إِسْحَقُ بْنُ إِبْرَاهِيمَ الْحَنْظَلِيُّ أَخْبَرَنَا جَرِيرٌ عَنْ مَنْصُورٍ عَنْ إِبْرَاهِيمَ عَنْ هَمَّامِ بْنِ الْحَارِثِ عَنْ عَدِيِّ بْنِ حَاتِمٍ قَالَقُلْتُ يَا رَسُولَ اللَّهِ إِنِّي أُرْسِلُ الْكِلَابَ الْمُعَلَّمَةَ فَيُمْسِكْنَ عَلَيَّ وَأَذْكُرُ اسْمَ اللَّهِ عَلَيْهِ فَقَالَ إِذَا أَرْسَلْتَ كَلْبَكَ الْمُعَلَّمَ وَذَكَرْتَ اسْمَ اللَّهِ عَلَيْهِ فَكُلْ قُلْتُ وَإِنْ قَتَلْنَ قَالَ وَإِنْ قَتَلْنَ مَا لَمْ يَشْرَكْهَا كَلْبٌ لَيْسَ مَعَهَا قُلْتُ لَهُ فَإِنِّي أَرْمِي بِالْمِعْرَاضِ الصَّيْدَ فَأُصِيبُ فَقَالَ إِذَا رَمَيْتَ بِالْمِعْرَاضِ فَخَزَقَ فَكُلْهُ وَإِنْ أَصَابَهُ بِعَرْضِهِ فَلَا تَأْكُلْهُ","id":"Telah menceritakan kepada kami [Ishaq bin Ibrahim Al Hanzhali] telah mengabarkan kepada kami [Jarir] dari [Manshur] dari [Ibrahim] dari [Hammam bin Al Harits] dari ['Adi bin Hatim] dia berkata; saya bertanya, \"Wahai Rasulullah, saya pernah melepas anjing pemburu yang terlatih lalu ia menangkap buruan untukku setelah saya menyebut nama Allah ketika melepasnya?\" Jawab Rasulullah shallallahu 'alaihi wasallam: \"Apabila kamu melepas anjing pemburu yang terlatih setelah kamu menyebut nama Allah ketika melepasnya, makanlah tangkapannya.\" Aku bertanya, \"Bagaimana jika buruan itu mati?\" beliau menjawab: \"Meskipun mati, selama tidak ada anjing lain yang menyertainya menangkap.\" Saya bertanya lagi, \"Bagaimana jika saya melempar buruan dengan Mi'radl dan mengenainya?\" Beliau menjawab: \"Apabila kamu melempar dengan Mi'radl dan dapat mengoyaknya maka makanlah buruanmu itu. Namun jika jika yang mengenai adalah pada bagian yang tumpul maka jangan kamu makan.\" "},"3321":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا ابْنُ فُضَيْلٍ عَنْ بَيَانٍ عَنْ الشَّعْبِيِّ عَنْ عَدِيِّ بْنِ حَاتِمٍ قَالَسَأَلْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قُلْتُ إِنَّا قَوْمٌ نَصِيدُ بِهَذِهِ الْكِلَابِ فَقَالَ إِذَا أَرْسَلْتَ كِلَابَكَ الْمُعَلَّمَةَ وَذَكَرْتَ اسْمَ اللَّهِ عَلَيْهَا فَكُلْ مِمَّا أَمْسَكْنَ عَلَيْكَ وَإِنْ قَتَلْنَ إِلَّا أَنْ يَأْكُلَ الْكَلْبُ فَإِنْ أَكَلَ فَلَا تَأْكُلْ فَإِنِّي أَخَافُ أَنْ يَكُونَ إِنَّمَا أَمْسَكَ عَلَى نَفْسِهِ وَإِنْ خَالَطَهَا كِلَابٌ مِنْ غَيْرِهَا فَلَا تَأْكُلْ","id":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] telah menceritakan kepada kami [Ibnu Fudlail] dari [Bayan] dari [Asy Sya'bi] dari ['Adi bin Hatim] dia berkata, \"Saya pernah bertanya kepada Rasulullah shallallahu 'alaihi wasallam, \"Saya katakan, 'Kami ini suatu kaum yang biasa hidup berburu dengan menggunakan anjing-anjing ini. Bagaimana itu? ' Nabi shallallahu 'alaihi wasallam menjawab: \"Apabila kamu melepas anjingmu yang terlatih dengan menyebut nama Allah, maka makanlah hasilnya sekalipun buruan itu mati dalam tangkapannya. Kecuali jika anjing-anjing itu memakan tangkapannya maka janganlah kamu makan pula, karena aku khawatir dia (anjing-anjing tersebut) menangkap buruan itu untuknya sendiri. Atau, jika ada anjing lain yang menyertainya menangkap (buruan tersebut), maka jangan kamu makan.\""},"3322":{"ar":"و حَدَّثَنَا عُبَيْدُ اللَّهِ بْنُ مُعَاذٍ الْعَنْبَرِيُّ حَدَّثَنَا أَبِي حَدَّثَنَا شُعْبَةُ عَنْ عَبْدِ اللَّهِ بْنِ أَبِي السَّفَرِ عَنْ الشَّعْبِيِّ عَنْ عَدِيِّ بْنِ حَاتِمٍ قَالَسَأَلْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ الْمِعْرَاضِ فَقَالَ إِذَا أَصَابَ بِحَدِّهِ فَكُلْ وَإِذَا أَصَابَ بِعَرْضِهِ فَقَتَلَ فَإِنَّهُ وَقِيذٌ فَلَا تَأْكُلْ وَسَأَلْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ الْكَلْبِ فَقَالَ إِذَا أَرْسَلْتَ كَلْبَكَ وَذَكَرْتَ اسْمَ اللَّهِ فَكُلْ فَإِنْ أَكَلَ مِنْهُ فَلَا تَأْكُلْ فَإِنَّهُ إِنَّمَا أَمْسَكَ عَلَى نَفْسِهِ قُلْتُ فَإِنْ وَجَدْتُ مَعَ كَلْبِي كَلْبًا آخَرَ فَلَا أَدْرِي أَيُّهُمَا أَخَذَهُ قَالَ فَلَا تَأْكُلْ فَإِنَّمَا سَمَّيْتَ عَلَى كَلْبِكَ وَلَمْ تُسَمِّ عَلَى غَيْرِهِو حَدَّثَنَا يَحْيَى بْنُ أَيُّوبَ حَدَّثَنَا ابْنُ عُلَيَّةَ قَالَ وَأَخْبَرَنِي شُعْبَةُ عَنْ عَبْدِ اللَّهِ بْنِ أَبِي السَّفَرِ قَالَ سَمِعْتُ الشَّعْبِيَّ يَقُولُ سَمِعْتُ عَدِيَّ بْنَ حَاتِمٍ يَقُولُا سَأَلْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ الْمِعْرَاضِ فَذَكَرَ مِثْلَهُ و حَدَّثَنِي أَبُو بَكْرِ بْنُ نَافِعٍ الْعَبْدِيُّ حَدَّثَنَا غُنْدَرٌ حَدَّثَنَا شُعْبَةُ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ أَبِي السَّفَرِ وَعَنْ نَاسٍ ذَكَرَ شُعْبَةُ عَنْ الشَّعْبِيِّ قَالَ سَمِعْتُ عَدِيَّ بْنَ حَاتِمٍ قَالَ سَأَلْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ الْمِعْرَاضِ بِمِثْلِ ذَلِكَ","id":"Dan telah menceritakan kepada kami ['Ubaidullah bin Mu'adz Al 'Anbari] telah menceritakan kepada kami [ayahku] telah menceritakan kepada kami [Syu'bah] dari [Abdullah bin Abu As Safar] dari [Asy Sya'bi] dari ['Adi bin Hatim] dia berkata, \"Saya bertanya kepada Rasulullah shallallahu 'alaihi wasallam mengenai Mi'radl, beliau lalu bersabda: \"Jika yang mengenai adalah bagian tajamnya maka makanlah, namun jika yang mengenai adalah bagian yang tumpul maka itu adalah binatang yang mati karena pukulan, maka jangan kamu makan.\" Lalu saya juga bertanya kepada Rasulullah shallallahu 'alaihi wasallam mengenai anjing buruan, beliau menjawab: \"Jika kamu melepas anjing buruanmu setelah menyebut nama Allah, maka makanlah buruan tersebut, selagi anjing buruanmu tidak memakannya.\" Dan telah menceritakan kepadaku [Yahya bin Ayyub] telah menceritakan kepada kami [Ibnu 'Ulayyah] berkata; dan telah mengabarkan kepadaku, [Syu'bah] dari [Abdullah bin Abu As Safar] berkata; saya telah mendengar [Asy Sya'bi] berkata; saya mendengar dari ['Adi bin Hatim] berkata; saya bertanya kepada Rasulullah shallallahu 'alaihi wasallam tentang mi'radl, lalu menyebutkan sama di atas. Dan telah menceritakan kepadaku [Abu Bakar bin Nafi' Al 'Abdi] telah menceritakan kepada kami [Ghundar] telah menceritakan kepada kami [Syu'bah] telah menceritakan kepada kami [Abdullah bin Abu As Safar] dan dari orang-orang yang disebutkan [Syu'bah] dari [Asy Sya'bi] berkata; saya mendengar dari ['Adi bin Hatim] berkata; saya bertanya kepada Rasulullah shallallahu 'alaihi wasallam tentang mi'radl, seperti di atas."},"3323":{"ar":"و حَدَّثَنَا مُحَمَّدُ بْنُ عَبْدِ اللَّهِ بْنِ نُمَيْرٍ حَدَّثَنَا أَبِي حَدَّثَنَا زَكَرِيَّاءُ عَنْ عَامِرٍ عَنْ عَدِيِّ بْنِ حَاتِمٍ قَالَسَأَلْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ صَيْدِ الْمِعْرَاضِ فَقَالَ مَا أَصَابَ بِحَدِّهِ فَكُلْهُ وَمَا أَصَابَ بِعَرْضِهِ فَهُوَ وَقِيذٌ وَسَأَلْتُهُ عَنْ صَيْدِ الْكَلْبِ فَقَالَ مَا أَمْسَكَ عَلَيْكَ وَلَمْ يَأْكُلْ مِنْهُ فَكُلْهُ فَإِنَّ ذَكَاتَهُ أَخْذُهُ فَإِنْ وَجَدْتَ عِنْدَهُ كَلْبًا آخَرَ فَخَشِيتَ أَنْ يَكُونَ أَخَذَهُ مَعَهُ وَقَدْ قَتَلَهُ فَلَا تَأْكُلْ إِنَّمَا ذَكَرْتَ اسْمَ اللَّهِ عَلَى كَلْبِكَ وَلَمْ تَذْكُرْهُ عَلَى غَيْرِهِو حَدَّثَنَا إِسْحَقُ بْنُ إِبْرَاهِيمَ أَخْبَرَنَا عِيسَى بْنُ يُونُسَ حَدَّثَنَا زَكَرِيَّاءُ بْنُ أَبِي زَائِدَةَ بِهَذَا الْإِسْنَادِ","id":"Dan telah menceritakan kepada kami [Muhammad bin Abdullah bin Numair] telah menceritakan kepada kami [ayahku] telah menceritakan kepada kami [Zakaria] dari ['Amir] dari [Adi bin Hatim] dia berkata, \"Saya bertanya kepada Rasulullah shallallahu 'alaihi wasallam tentang buruan yang mati dengan senjata Mi'radl.\" Beliau pun menjawab: \"Jika yang mengenai adalah pada bagian yang tajam maka makanlah, namun jika yang mengenai adalah pada sisi yang tumpul maka itu adalah buruan yang mati karena pukulan.\" Kemudian saya bertanya kepada beliau tentang anjing buruan, beliau menjawab: \"Apa yang ditangkap anjing itu sedangkan ia tidak memakannya, maka makanlah buruan tersebut sebab kamu telah menyembelih dengan cara yang syar'i, jika kamu mendapatinya bersama anjing yang lain, maka di khawatirkan yang membunuh buruan tersebut adalah anjing yang lain, maka janganlah kamu memakan buruan itu. Hanyasanya kamu menyebut nama Allah untuk anjingmu bukan untuk anjing yang lain.\" Dan telah menceritakan kepada kami [Ishaq bin Ibrahim] telah mengabarkan kepada kami [Isa bin Yunus] telah menceritakan kepada kami [Zakaria bin Abu Zaidah] dengan sanad ini."},"3324":{"ar":"و حَدَّثَنَا مُحَمَّدُ بْنُ الْوَلِيدِ بْنِ عَبْدِ الْحَمِيدِ حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ حَدَّثَنَا شُعْبَةُ عَنْ سَعِيدِ بْنِ مَسْرُوقٍ حَدَّثَنَا الشَّعْبِيُّ قَالَ سَمِعْتُ عَدِيَّ بْنَ حَاتِمٍ وَكَانَ لَنَا جَارًا وَدَخِيلًا وَرَبِيطًا بِالنَّهْرَيْنِأَنَّهُ سَأَلَ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ أُرْسِلُ كَلْبِي فَأَجِدُ مَعَ كَلْبِي كَلْبًا قَدْ أَخَذَ لَا أَدْرِي أَيُّهُمَا أَخَذَ قَالَ فَلَا تَأْكُلْ فَإِنَّمَا سَمَّيْتَ عَلَى كَلْبِكَ وَلَمْ تُسَمِّ عَلَى غَيْرِهِو حَدَّثَنَا مَحَمَّدُ بْنُ الْوَلِيدِ حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ حَدَّثَنَا شُعْبَةُ عَنْ الْحَكَمِ عَنْ الشَّعْبِيِّ عَنْ عَدِيِّ بْنِ حَاتِمٍ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِثْلَ ذَلِكَ","id":"Telah menceritakan kepada kami [Muhammad bin Al Walid bin Abdul Hamid] telah menceritakan kepada kami [Muhammad bin Ja'far] telah menceritakan kepada kami [Syu'bah] dari [Sa'id bin Masruq] telah menceritakan kepada kami [As Sya'bi] dia berkata; saya pernah mendengar ['Adi bin Hatim] -saat kami berada di Nahrain kami bertetangga dekat dengannya-, bahwa dia pernah bertanya kepada Nabi shallallahu 'alaihi wasallam, katanya, \"Saya pernah melepas anjing buruanku, ternyata ia menangkap buruan dengan anjing yang lain, saya tidak tahu yang manakah anjing yang telah menangkap binatang tersebut.\" Beliau bersabda: \"Janganlah kamu memakannya, karena kamu membacakan bismillah untuk anjingmu bukan untuk anjing yang lain.\" Dan telah menceritakan kepada kami [Muhammad bin Al Walid] telah menceritakan kepada kami [Muhammad bin Ja'far] telah menceritakan kepada kami [Syu'bah] dari [Al Hakam] dari [As Sya'bi] dari ['Adi bin Hatim] dari Nabi shallallahu 'alaihi wasallam seperti itu.\""},"3325":{"ar":"حَدَّثَنِي الْوَلِيدُ بْنُ شُجَاعٍ السَّكُونِيُّ حَدَّثَنَا عَلِيُّ بْنُ مُسْهِرٍ عَنْ عَاصِمٍ عَنْ الشَّعْبِيِّ عَنْ عَدِيِّ بْنِ حَاتِمٍ قَالَقَالَ لِي رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا أَرْسَلْتَ كَلْبَكَ فَاذْكُرْ اسْمَ اللَّهِ فَإِنْ أَمْسَكَ عَلَيْكَ فَأَدْرَكْتَهُ حَيًّا فَاذْبَحْهُ وَإِنْ أَدْرَكْتَهُ قَدْ قَتَلَ وَلَمْ يَأْكُلْ مِنْهُ فَكُلْهُ وَإِنْ وَجَدْتَ مَعَ كَلْبِكَ كَلْبًا غَيْرَهُ وَقَدْ قَتَلَ فَلَا تَأْكُلْ فَإِنَّكَ لَا تَدْرِي أَيُّهُمَا قَتَلَهُ وَإِنْ رَمَيْتَ سَهْمَكَ فَاذْكُرْ اسْمَ اللَّهِ فَإِنْ غَابَ عَنْكَ يَوْمًا فَلَمْ تَجِدْ فِيهِ إِلَّا أَثَرَ سَهْمِكَ فَكُلْ إِنْ شِئْتَ وَإِنْ وَجَدْتَهُ غَرِيقًا فِي الْمَاءِ فَلَا تَأْكُلْ","id":"Telah menceritakan kepadaku [Al Walid bin Syuja' As Sakuni] telah menceritakan kepada kami [Ali bin Mushir] dari ['Ashim] dari [As Sya'bi] dari ['Adi bin Hatim] dia berkata, \"Rasulullah shallallahu 'alaihi wasallam pernah bersabda kepadaku: \"Apabila kamu melepaskan anjing buruan maka sebutlah nama Allah, jika ia mendapatkan hewan buruan yang masih hidup maka sembelihlah dia, jika ia mendapatkan hewan buruan telah mati, sedangkan ia tidak memakannya, maka makanlah hewan buruan tersebut. Namun jika ternyata ia bersama dengan anjing yang lain, dan membawa hewan buruan yang telah mati, maka janganlah kamu memakannya, sebab kamu tidak mengetahui manakah di antara keduanya yang membunuh hewan buruan itu. Apabila kamu melempar anak panahmu, maka sebutlah nama Allah, jika kamu mendapatkan bekas tusukan anak panahmu (pada hewan buruan), jika kamu mau makanlah ia, namun jika kamu dapati hewan buruan tersebut mati tenggelam, maka janganlah kamu memakannya.\""},"3326":{"ar":"حَدَّثَنَا يَحْيَى بْنُ أَيُّوبَ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ الْمُبَارَكِ أَخْبَرَنَا عَاصِمٌ عَنْ الشَّعْبِيِّ عَنْ عَدِيِّ بْنِ حَاتِمٍ قَالَسَأَلْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ الصَّيْدِ قَالَ إِذَا رَمَيْتَ سَهْمَكَ فَاذْكُرْ اسْمَ اللَّهِ فَإِنْ وَجَدْتَهُ قَدْ قَتَلَ فَكُلْ إِلَّا أَنْ تَجِدَهُ قَدْ وَقَعَ فِي مَاءٍ فَإِنَّكَ لَا تَدْرِي الْمَاءُ قَتَلَهُ أَوْ سَهْمُكَ","id":"Telah menceritakan kepada kami [Yahya bin Ayyub] telah menceritakan kepada kami [Abdullah bin Mubarak] telah mengabarkan kepada kami ['Ashim] dari [As Sya'bi] dari ['Adi bin Hatim] dia berkata, \"Saya pernah bertanya kepada Rasulullah shallallahu 'alaihi wasallam mengenai hewan buruan, beliau menjawab: \"Apabila kamu memanah maka sebutlah nama Allah, jika kamu mendapatinya telah terbunuh maka makanlah (hewan buruan tersebut), kecuali jika kamu dapati ia tenggelam di air, sebab kamu tidak tahu apakah air itu yang membunuhnya ataukah panahmu.\""},"3327":{"ar":"حَدَّثَنَا هَنَّادُ بْنُ السَّرِيِّ حَدَّثَنَا ابْنُ الْمُبَارَكِ عَنْ حَيْوَةَ بْنِ شُرَيْحٍ قَالَ سَمِعْتُ رَبِيعَةَ بْنَ يَزِيدَ الدِّمَشْقِيَّ يَقُولُ أَخْبَرَنِي أَبُو إِدْرِيسَ عَائِذُ اللَّهِ قَالَ سَمِعْتُ أَبَا ثَعْلَبَةَ الْخُشَنِيَّ يَقُولُاأَتَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقُلْتُ يَا رَسُولَ اللَّهِ إِنَّا بِأَرْضِ قَوْمٍ مِنْ أَهْلِ الْكِتَابِ نَأْكُلُ فِي آنِيَتِهِمْ وَأَرْضِ صَيْدٍ أَصِيدُ بِقَوْسِي وَأَصِيدُ بِكَلْبِي الْمُعَلَّمِ أَوْ بِكَلْبِي الَّذِي لَيْسَ بِمُعَلَّمٍ فَأَخْبِرْنِي مَا الَّذِي يَحِلُّ لَنَا مِنْ ذَلِكَ قَالَ أَمَّا مَا ذَكَرْتَ أَنَّكُمْ بِأَرْضِ قَوْمٍ مِنْ أَهْلِ الْكِتَابِ تَأْكُلُونَ فِي آنِيَتِهِمْ فَإِنْ وَجَدْتُمْ غَيْرَ آنِيَتِهِمْ فَلَا تَأْكُلُوا فِيهَا وَإِنْ لَمْ تَجِدُوا فَاغْسِلُوهَا ثُمَّ كُلُوا فِيهَا وَأَمَّا مَا ذَكَرْتَ أَنَّكَ بِأَرْضِ صَيْدٍ فَمَا أَصَبْتَ بِقَوْسِكَ فَاذْكُرْ اسْمَ اللَّهِ ثُمَّ كُلْ وَمَا أَصَبْتَ بِكَلْبِكَ الْمُعَلَّمِ فَاذْكُرْ اسْمَ اللَّهِ ثُمَّ كُلْ وَمَا أَصَبْتَ بِكَلْبِكَ الَّذِي لَيْسَ بِمُعَلَّمٍ فَأَدْرَكْتَ ذَكَاتَهُ فَكُلْو حَدَّثَنِي أَبُو الطَّاهِرِ أَخْبَرَنَا ابْنُ وَهْبٍ ح و حَدَّثَنِي زُهَيْرُ بْنُ حَرْبٍ حَدَّثَنَا الْمُقْرِئُ كِلَاهُمَا عَنْ حَيْوَةَ بِهَذَا الْإِسْنَادِ نَحْوَ حَدِيثِ ابْنِ الْمُبَارَكِ غَيْرَ أَنَّ حَدِيثَ ابْنِ وَهْبٍ لَمْ يَذْكُرْ فِيهِ صَيْدَ الْقَوْسِ","id":"Telah menceritakan kepada kami [Hannad bin As Sari] telah menceritakan kepada kami [Ibnu Al Mubarak] dari [Haiwah bin Syuraih] dia berkata; saya mendengar [Rabi'ah bin Yazid Ad Dimasyqi] berkata; telah mengabarkan kepadaku [Abu Idris 'Aidzullah] dia berkata; saya mendengar [Abu Tsa'labah Al Khusani] berkata, \"Saya pernah mendatangi Rasulullah shallallahu 'alaihi wasallam seraya bertanya, 'Wahai Rasulullah, kami tinggal di negeri ahli kitab, dan kami memakan dengan menggunakan periuk mereka, sedangkan penghidupan mereka adalah berburu. Saya juga berburu dengan menggunakan panah dan anjing yang sudah terlatih dan juga belum terlatih, oleh karena itu beritahukanlah kepada kami sesuatu yang halal dari yang demikian itu?\" beliau menjawab: \"Adapun keadaanmu yang tinggal di negeri ahli kitab dan makan dengan piring-piring mereka, maka seandainya kamu bisa mendapatkan piring-piring selain piring mereka, maka janganlah menggunakan piring mereka. Namun jika kamu tidak mendapatkan piring selain piring mereka, basuhlah piring mereka dan makanlah dengan menggunakan piring tersebut. Adapun keadaanmu yang tinggal di negeri mereka yang mata pencahariannya berburu, jika kamu berburu dengan menggunakan panahmu, sebutlah nama Allah terlebih dahulu kemudian makanlah hasil buruan tersebut, dan jika kamu menangkap hewan buruan dengan menggunakan anjing pelatih, sebutlah nama Allah terlebih dahulu kemudian makanlah hasil buruan tersebut, dan jika kamu menangkap hewan buruan dengan menggunakan anjing yang tidak terlatih dan kamu masih sempat menyembelihnya, maka makanlah hewan buruan tersebut.\" Dan telah menceritakan kepadaku [Abu At Thahir] telah mengabarkan kepada kami [Ibnu Wahb]. (dalam jalur lain disebutkan) Telah menceritakan kepadaku [Zuhair bin Harb] telah menceritakan kepada kami [Al Muqri`] keduanya dari [Haiwah] dengan sanad ini seperti hadits Ibnu Mubarak, namun dalam hadits Ibnu Wahab dia tidak menyebutkan, 'Berburu dengan menggunakan panah'.\""},"3328":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ مِهْرَانَ الرَّازِيُّ حَدَّثَنَا أَبُو عَبْدِ اللَّهِ حَمَّادُ بْنُ خَالِدٍ الْخَيَّاطُ عَنْ مُعَاوِيَةَ بْنِ صَالِحٍ عَنْ عَبْدِ الرَّحْمَنِ بْنِ جُبَيْرٍ عَنْ أَبِيهِ عَنْ أَبِي ثَعْلَبَةَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِذَا رَمَيْتَ بِسَهْمِكَ فَغَابَ عَنْكَ فَأَدْرَكْتَهُ فَكُلْهُ مَا لَمْ يُنْتِنْ","id":"Telah menceritakan kepada kami [Muhammad bin Mihran Ar Razi] telah menceritakan kepada kami [Abu Abdullah Hammad bin Khalid Al Hiyyath] dari [Mu'awiyah bin Shalih] dari [Abdurrahman bin Jubair] dari [ayahnya] dari [Abu Tsa'labah] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Jika hewan buruan yang kamu panah hilang kemudian kamu mendapatinya kembali, maka makanlah buruan tersebut selagi belum membusuk.\""},"3329":{"ar":"و حَدَّثَنِي مُحَمَّدُ بْنُ أَحْمَدَ بْنِ أَبِي خَلَفٍ حَدَّثَنَا مَعْنُ بْنُ عِيسَى حَدَّثَنِي مُعَاوِيَةُ عَنْ عَبْدِ الرَّحْمَنِ بْنِ جُبَيْرِ بْنِ نُفَيْرٍ عَنْ أَبِيهِ عَنْ أَبِي ثَعْلَبَةَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي الَّذِي يُدْرِكُ صَيْدَهُ بَعْدَ ثَلَاثٍ فَكُلْهُ مَا لَمْ يُنْتِنْو حَدَّثَنِي مُحَمَّدُ بْنُ حَاتِمٍ حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ مَهْدِيٍّ عَنْ مُعَاوِيَةَ بْنِ صَالِحٍ عَنْ الْعَلَاءِ عَنْ مَكْحُولٍ عَنْ أَبِي ثَعْلَبَةَ الْخُشَنِيِّ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حَدِيثَهُ فِي الصَّيْدِ ثُمَّ قَالَ ابْنُ حَاتِمٍ حَدَّثَنَا ابْنُ مَهْدِيٍّ عَنْ مُعَاوِيَةَ عَنْ عَبْدِ الرَّحْمَنِ بْنِ جُبَيْرٍ وَأَبِي الزَّاهِرِيَّةِ عَنْ جُبَيْرِ بْنِ نُفَيْرٍ عَنْ أَبِي ثَعْلَبَةَ الْخُشَنِيِّ بِمِثْلِ حَدِيثِ الْعَلَاءِ غَيْرَ أَنَّهُ لَمْ يَذْكُرْ نُتُونَتَهُ وَقَالَ فِي الْكَلْبِ كُلْهُ بَعْدَ ثَلَاثٍ إِلَّا أَنْ يُنْتِنَ فَدَعْهُ","id":"Dan telah menceritakan kepadaku [Muhammad bin Ahmad bin Abu Khalaf] telah menceritakan kepada kami [Ma'n bin Isa] telah menceritakan kepadaku [Mu'awiyah] dari [Abdurrahman bin Jubair bin Nufair] dari [ayahnya] dari [Abu Tsa'labah] dari Nabi shallallahu 'alaihi wasallam mengenai orang yang mendapati hewan buruannya setelah tiga hari, maka beliau menyuruh untuk memakannya selagi belum membusuk.\" Dan telah menceritakan kepadaku [Muhammad bin Hatim] telah menceritakan kepada kami [Abdurrahman bin Mahdi] dari [Mu'awiyah bin Shalih] dari [Al 'Ala] dari [Makhul] dari [Abu Tsa'labah Al Khusani] dari Nabi shallallahu 'alaihi wasallam pada haditsnya mengenai hewan buruan, kemudian [Ibnu Hatim] berkata; telah menceritakan kepada kami [Ibnu Mahdi] dari [Mu'awiyah] dari [Abdurrahman bin Jubair] dan [Abu Az Zahiriyah] dari [Jubair bin Nufair] dari [Abu Tsa'labah Al Khusani] seperti Al 'Ala namun dia tidak menyebutkan, 'Selagi belum membusuk', dan dia menyebutkan mengenai anjing pemburu, \"Makanlah walaupun telah berlalu tiga hari kecuali jika telah membusuk, maka tinggalkanlah.\""},"3330":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ وَإِسْحَقُ بْنُ إِبْرَاهِيمَ وَابْنُ أَبِي عُمَرَ قَالَ إِسْحَقُ أَخْبَرَنَا و قَالَ الْآخَرَانِ حَدَّثَنَا سُفْيَانُ بْنُ عُيَيْنَةَ عَنْ الزُّهْرِيِّ عَنْ أَبِي إِدْرِيسَ عَنْ أَبِي ثَعْلَبَةَ قَالَنَهَى النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ أَكْلِ كُلِّ ذِي نَابٍ مِنْ السَّبُعِزَادَ إِسْحَقُ وَابْنُ أَبِي عُمَرَ فِي حَدِيثِهِمَا قَالَ الزُّهْرِيُّ وَلَمْ نَسْمَعْ بِهَذَا حَتَّى قَدِمْنَا الشَّامَ","id":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] dan [Ishaq bin Ibrahim] dan [Ibnu Abu Umar], Ishaq berkata; telah mengabarkan kepada kami, sedangkan yang dua mengatakan; telah menceritakan kepada kami [Sufyan bin 'Uyainah] dari [Az Zuhri] dari [Abu Idris] dari [Abu Tsa'labah] dia berkata, \"Nabi shallallahu 'alaihi wasallam melarang memakan binatang buas yang bertaring.\" Ishaq dan Ibnu Abu Umar menambahkan dalam haditsnya, Az Zuhri berkata, \"Kami tidak mendengar hadits ini hingga kami tiba di negeri Syam.\""},"3331":{"ar":"و حَدَّثَنِي حَرْمَلَةُ بْنُ يَحْيَى أَخْبَرَنَا ابْنُ وَهْبٍ أَخْبَرَنِي يُونُسُ عَنْ ابْنِ شِهَابٍ عَنْ أَبِي إِدْرِيسَ الْخَوْلَانِيِّ أَنَّهُ سَمِعَ أَبَا ثَعْلَبَةَ الْخُشَنِيَّ يَقُولُانَهَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ أَكْلِ كُلِّ ذِي نَابٍ مِنْ السِّبَاعِقَالَ ابْنُ شِهَابٍ وَلَمْ أَسْمَعْ ذَلِكَ مِنْ عُلَمَائِنَا بِالْحِجَازِ حَتَّى حَدَّثَنِي أَبُو إِدْرِيسَ وَكَانَ مِنْ فُقَهَاءِ أَهْلِ الشَّامِ","id":"Dan telah menceritakan kepadaku [Harmalah bin Yahya] telah mengabarkan kepada kami [Ibnu Wahb] telah mengabarkan kepadaku [Yunus] dari Ibnu Shihab dari [Abu Idris Al Khaulani] bahwa dia mendengar [Abu Tsa'labah Al Khusni] berkata, \"Rasulullah shallallahu 'alaihi wasallam melarang memakan setiap binatang buas yang bertaring.\" Ibnu Shihab berkata, \"Saya belum pernah mendengar hadits tersebut dari ulama-ulama kami di Hijaz hingga Abu Idris menceritakan kepadaku, sedangkan dia termasuk dari ulama negeri Syam.\""},"3332":{"ar":"و حَدَّثَنِي هَارُونُ بْنُ سَعِيدٍ الْأَيْلِيُّ حَدَّثَنَا ابْنُ وَهْبٍ أَخْبَرَنَا عَمْرٌو يَعْنِي ابْنَ الْحَارِثِ أَنَّ ابْنَ شِهَابٍ حَدَّثَهُ عَنْ أَبِي إِدْرِيسَ الْخَوْلَانِيِّ عَنْ أَبِي ثَعْلَبَةَ الْخُشَنِيِّأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَهَى عَنْ أَكْلِ كُلِّ ذِي نَابٍ مِنْ السِّبَاعِو حَدَّثَنِيهِ أَبُو الطَّاهِرِ أَخْبَرَنَا ابْنُ وَهْبٍ أَخْبَرَنِي مَالِكُ بْنُ أَنَسٍ وَابْنُ أَبِي ذِئْبٍ وَعَمْرُو بْنُ الْحَارِثِ وَيُونُسُ بْنُ يَزِيدَ وَغَيْرُهُمْ ح و حَدَّثَنِي مُحَمَّدُ بْنُ رَافِعٍ وَعَبْدُ بْنُ حُمَيْدٍ عَنْ عَبْدِ الرَّزَّاقِ عَنْ مَعْمَرٍ ح و حَدَّثَنَا يَحْيَى بْنُ يَحْيَى أَخْبَرَنَا يُوسُفُ بْنُ الْمَاجِشُونِ ح و حَدَّثَنَا الْحُلْوَانِيُّ وَعَبْدُ بْنُ حُمَيْدٍ عَنْ يَعْقُوبَ بْنِ إِبْرَاهِيمَ بْنِ سَعْدٍ حَدَّثَنَا أَبِي عَنْ صَالِحٍ كُلُّهُمْ عَنْ الزُّهْرِيِّ بِهَذَا الْإِسْنَادِ مِثْلَ حَدِيثِ يُونُسَ وَعَمْرٍو كُلُّهُمْ ذَكَرَ الْأَكْلَ إِلَّا صَالِحًا وَيُوسُفَ فَإِنَّ حَدِيثَهُمَا نَهَى عَنْ كُلِّ ذِي نَابٍ مِنْ السَّبُعِ","id":"Dan telah menceritakan kepadaku [Harun bin Sa'id Al Aili] telah mengabarkan kepada kami [Ibnu Wahb] telah mengabarkan kepada kami ['Amru] -yaitu Ibnu Al Harits- bahwa [Ibnu Syihab] telah mengabarkan kepadanya dari [Abu Idris Al Khaulani] dari [Abu Tsa'labah Al Khusyani], bahwa Rasulullah shallallahu 'alaihi wasallam melarang memakan setiap binatang buas yang bertaring.\" Dan telah menceritakan kepada kami [Abu At Thahir] telah mengabarkan kepada kami [Ibnu Wahb] telah mengabarkan kepadaku [Malik bin Anas] dan [Ibnu Abu Dzi`ib] dan ['Amru bin Harits] dan [Yunus bin Yazid] serta yang lain. (dalam jalur lain disebutkan) Telah menceritakan kepadaku [Muhammad bin Rafi'] dan ['Abdu bin Khumaid] dan ['Abdurrazaq] dari [Ma'mar]. (dalam jalur lain disebutkan) Telah menceritakan kepada kami [Yahya bin Yahya] telah mengabarkan kepada kami [Yusuf bin Majisyun]. (dalam jalur lain disebutkan) Telah menceritakan kepada kami [Al Khulwani] dan ['Abdu bin Khumaid] dari [Ya'qub bin Ibrahim bin Sa'ad] telah menceritakan kepada kami [Ayahku] dari [Shalih] mereka semua dari [Az Zuhri] dengan sanad ini seperti hadits Yunus dan 'Amru, semuanya menyebutkan Al Aklu (memakan), kecuali Shalih dan Yusuf. Dalam hadits keduanya disebutkan, 'Beliau melarang memakan setiap binatang buas yang bertaring'.\""},"3333":{"ar":"و حَدَّثَنِي زُهَيْرُ بْنُ حَرْبٍ حَدَّثَنَا عَبْدُ الرَّحْمَنِ يَعْنِي ابْنَ مَهْدِيٍّ عَنْ مَالِكٍ عَنْ إِسْمَعِيلَ بْنِ أَبِي حَكِيمٍ عَنْ عَبِيدَةَ بْنِ سُفْيَانَ عَنْ أَبِي هُرَيْرَةَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ كُلُّ ذِي نَابٍ مِنْ السِّبَاعِ فَأَكْلُهُ حَرَامٌو حَدَّثَنِيهِ أَبُو الطَّاهِرِ أَخْبَرَنَا ابْنُ وَهْبٍ أَخْبَرَنِي مَالِكُ بْنُ أَنَسٍ بِهَذَا الْإِسْنَادِ مِثْلَهُ","id":"Dan telah menceritakan kepadaku [Zuhair bin Harb] telah menceritakan kepada kami [Abdurrahman] -yaitu Ibnu Mahdi- dari [Malik] dari [Isma'il bin Abu Hakim] dari ['Abidah bin Sufyan] dari [Abu Hurairah] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Setiap binatang buas yang bertaring, maka memakannya adalah haram.\" Dan telah menceritakan kepadaku [Abu At Thahir] telah mengabarkan kepada kami [Ibnu Wahb] telah mengabarkan kepadaku [Malik bin Anas] dengan sanad seperti ini.\""},"3334":{"ar":"حَدَّثَنَا عُبَيْدُ اللَّهِ بْنُ مُعَاذٍ الْعَنْبَرِيُّ حَدَّثَنَا أَبِي حَدَّثَنَا شُعْبَةُ عَنْ الْحَكَمِ عَنْ مَيْمُونِ بْنِ مِهْرَانَ عَنْ ابْنِ عَبَّاسٍ قَالَنَهَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ كُلِّ ذِي نَابٍ مِنْ السِّبَاعِ وَعَنْ كُلِّ ذِي مِخْلَبٍ مِنْ الطَّيْرِو حَدَّثَنِي حَجَّاجُ بْنُ الشَّاعِرِ حَدَّثَنَا سَهْلُ بْنُ حَمَّادٍ حَدَّثَنَا شُعْبَةُ بِهَذَا الْإِسْنَادِ مِثْلَهُ","id":"Telah menceritakan kepada kami ['Ubaidullah bin Mu'adz Al 'Anbari] telah menceritakan kepada kami [ayahku] telah menceritakan kepada kami [Syu'bah] dari [Al Hakam] dari [Maimun bin Mihran] dari [Ibnu Abbas] dia berkata, \"Rasulullah shallallahu 'alaihi wasallam melarang memakan setiap binatang buas yang bertaring, dan setiap jenis burung yang mempunyai kuku untuk mencengkeram.\" Dan telah menceritakan kepadaku [Hajjaj bin As Sya'ir] telah menceritakan kepada kami [Sahl bin Hammad] telah menceritakan kepada kami [Syu'bah] dengan sanad seperti ini.\""},"3335":{"ar":"و حَدَّثَنَا أَحْمَدُ بْنُ حَنْبَلٍ حَدَّثَنَا سُلَيْمَانُ بْنُ دَاوُدَ حَدَّثَنَا أَبُو عَوَانَةَ حَدَّثَنَا الْحَكَمُ وَأَبُو بِشْرٍ عَنْ مَيْمُونِ بْنِ مِهْرَانَ عَنْ ابْنِ عَبَّاسٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَهَى عَنْ كُلِّ ذِي نَابٍ مِنْ السِّبَاعِ وَعَنْ كُلِّ ذِي مِخْلَبٍ مِنْ الطَّيْرِو حَدَّثَنَا يَحْيَى بْنُ يَحْيَى أَخْبَرَنَا هُشَيْمٌ عَنْ أَبِي بِشْرٍ ح و حَدَّثَنَا أَحْمَدُ بْنُ حَنْبَلٍ حَدَّثَنَا هُشَيْمٌ قَالَ أَبُو بِشْرٍ أَخْبَرَنَا عَنْ مَيْمُونِ بْنِ مِهْرَانَ عَنْ ابْنِ عَبَّاسٍ قَالَ نَهَى ح و حَدَّثَنِي أَبُو كَامِلٍ الْجَحْدَرِيُّ حَدَّثَنَا أَبُو عَوَانَةَ عَنْ أَبِي بِشْرٍ عَنْ مَيْمُونِ بْنِ مِهْرَانَ عَنْ ابْنِ عَبَّاسٍ قَالَ نَهَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِمِثْلِ حَدِيثِ شُعْبَةَ عَنْ الْحَكَمِ","id":"Dan telah menceritakan kepada kami [Ahmad bin Hanbal] telah menceritakan kepada kami [Sulaiman bin Daud] telah menceritakan kepada kami [Abu 'Awanah] telah menceritakan kepada kami [Al Hakam] dan [Abu Bisyr] dari [Maimun bin Mihran] dari [Ibnu Abbas], bahwa Rasulullah shallallahu 'alaihi wasallam melarang (memakan) dari setiap bintang buas yang bertaring dan setiap jenis burung yang memiliki kuku untuk mencengkeram.\" Dan telah menceritakan kepada kami [Yahya bin Yahya] telah mengabarkan kepada kami [Husyaim] dari [Abu Bisyr]. (dalam jalur lain disebutkan) Telah menceritakan kepada kami [Ahmad bin Hanbal] telah menceritakan kepada kami [Husyaim], [Abu Bisyr] berkata; telah mengabarkan kepada kami dari [Maimun bin Mihran] dari [Ibnu Abbas] dia berkata, \"Beliau melarang ….\" (dalam jalur lain disebutkan) Telah menceritakan kepadaku [Abu Kamil Al Jahdari] telah menceritakan kepada kami [Abu 'Awanah] dari [Abu Bisyr] dari [Maimun bin Mihran] dari [Ibnu Abbas] dia berkata, \"Rasulullah shallallahu 'alaihi wasallam melarang…seperti hadits Syu'bah dari Al Hakam.\""},"3336":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ يُونُسَ حَدَّثَنَا زُهَيْرٌ حَدَّثَنَا أَبُو الزُّبَيْرِ عَنْ جَابِرٍ ح و حَدَّثَنَاه يَحْيَى بْنُ يَحْيَى أَخْبَرَنَا أَبُو خَيْثَمَةَ عَنْ أَبِي الزُّبَيْرِ عَنْ جَابِرٍ قَالَبَعَثَنَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَأَمَّرَ عَلَيْنَا أَبَا عُبَيْدَةَ نَتَلَقَّى عِيرًا لِقُرَيْشٍ وَزَوَّدَنَا جِرَابًا مِنْ تَمْرٍ لَمْ يَجِدْ لَنَا غَيْرَهُ فَكَانَ أَبُو عُبَيْدَةَ يُعْطِينَا تَمْرَةً تَمْرَةً قَالَ فَقُلْتُ كَيْفَ كُنْتُمْ تَصْنَعُونَ بِهَا قَالَ نَمَصُّهَا كَمَا يَمَصُّ الصَّبِيُّ ثُمَّ نَشْرَبُ عَلَيْهَا مِنْ الْمَاءِ فَتَكْفِينَا يَوْمَنَا إِلَى اللَّيْلِ وَكُنَّا نَضْرِبُ بِعِصِيِّنَا الْخَبَطَ ثُمَّ نَبُلُّهُ بِالْمَاءِ فَنَأْكُلُهُ قَالَ وَانْطَلَقْنَا عَلَى سَاحِلِ الْبَحْرِ فَرُفِعَ لَنَا عَلَى سَاحِلِ الْبَحْرِ كَهَيْئَةِ الْكَثِيبِ الضَّخْمِ فَأَتَيْنَاهُ فَإِذَا هِيَ دَابَّةٌ تُدْعَى الْعَنْبَرَ قَالَ قَالَ أَبُو عُبَيْدَةَ مَيْتَةٌ ثُمَّ قَالَ لَا بَلْ نَحْنُ رُسُلُ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَفِي سَبِيلِ اللَّهِ وَقَدْ اضْطُرِرْتُمْ فَكُلُوا قَالَ فَأَقَمْنَا عَلَيْهِ شَهْرًا وَنَحْنُ ثَلَاثُ مِائَةٍ حَتَّى سَمِنَّا قَالَ وَلَقَدْ رَأَيْتُنَا نَغْتَرِفُ مِنْ وَقْبِ عَيْنِهِ بِالْقِلَالِ الدُّهْنَ وَنَقْتَطِعُ مِنْهُ الْفِدَرَ كَالثَّوْرِ أَوْ كَقَدْرِ الثَّوْرِ فَلَقَدْ أَخَذَ مِنَّا أَبُو عُبَيْدَةَ ثَلَاثَةَ عَشَرَ رَجُلًا فَأَقْعَدَهُمْ فِي وَقْبِ عَيْنِهِ وَأَخَذَ ضِلَعًا مِنْ أَضْلَاعِهِ فَأَقَامَهَا ثُمَّ رَحَلَ أَعْظَمَ بَعِيرٍ مَعَنَا فَمَرَّ مِنْ تَحْتِهَا وَتَزَوَّدْنَا مِنْ لَحْمِهِ وَشَائِقَ فَلَمَّا قَدِمْنَا الْمَدِينَةَ أَتَيْنَا رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَذَكَرْنَا ذَلِكَ لَهُ فَقَالَ هُوَ رِزْقٌ أَخْرَجَهُ اللَّهُ لَكُمْ فَهَلْ مَعَكُمْ مِنْ لَحْمِهِ شَيْءٌ فَتُطْعِمُونَا قَالَ فَأَرْسَلْنَا إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِنْهُ فَأَكَلَهُ","id":"Telah menceritakan kepada kami [Ahmad bin Yunus] telah menceritakan kepada kami [Zuhair] telah menceritakan kepada kami [Abu Az Zubair] dari [Jabir]. (dalam jalur lain disebutkan) Telah menceritakan kepada kami [Yahya bin Yahya] telah mengabarkan kepada kami [Abu Khaitsamah] dari [Abu Az Zubair] dari [Jabir] dia berkata, \"Rasulullah shallallahu 'alaihi wasallam pernah mengirim kami dengan Abu Ubaidah sebagai komandannya, untuk menghadang kafilah dagang Quraisy. Kami hanya dibekali dengan sekarung kurma, dan tidak ada lagi selain itu. Karena itu, Abu Ubaidah membagi-bagikannya kepada kami sebuah demi sebuah.\" Abu Az Zubair berkata, \"Lantas saya berkata, \"Apa yang dapat kalian perbuat dengan sebuah kurma itu?\" Jabir menjawab, \"Kami menghisap-hisapnya seperti bayi. Kemudian kami meminum air. Hal itu sudah cukup bagi kami untuk sehari sampai malam. Pernah juga kami gugurkan dedaunan dengan tongkat, kemudian kami siram dengan air lalu kami memakannya. Setelah kami sampai di pantai lautan, kami dihadapkan dengan suatu pemandangan yang tampaknya seperti gundukan air, ketika kami hampiri ternyata itu adalah hewan laut yang disebut 'anbar (sejenis ikan yang panjang dan besar kepalanya).\" Jabir berkata, \"Lalu Abu Ubaidah berkata, \"Itu adalah bangkai.\" kemudian dia melanjutkan, \"Namun tidak mengapa, kita adalah utusan Rasulullah shallallahu 'alaihi wasallam yang mengembang tugas fi sabilillah dan kalian dalam keadaan terpaksa, karena itu kalian boleh memakannya.\" Jabir berkata, \"Kami menetap di tempat itu selama sebulan, dan jumlah kami semuanya ada tiga ratus orang, dan kami menjadi gemuk semuanya (karena makan daging itu).\" Jabir melanjutkan, \"Sungguh kami telah mengetahui, saat itu kami mengambil minyaknya dari rongga matanya dan menampungnya dengan tempayan besar. Kemudian kami potong-potong dagingnya seperti memotong seekor lembu. Kemudian Abu Ubaidah memanggil tiga belas prajurit untuk masuk ke rongga mata ikan, lalu mereka mengambil kerangkanya dan menegakkannya, kemudian unta kami yang paling besar disuruh berjalan di bawah kerangka ikan tersebut. Kami lalu ambil daging ikan itu sebagai perbekalan kami dan untuk kami masak. Setelah kami tiba di Madinah, kami menemui Rasulullah shallallahu 'alaihi wasallam dan memberitahukan hal itu kepada beliau, maka beliau bersabda: \"Itu adalah rizki yang diberikan Allah kepada kalian, apakah kalian membawa sedikit dagingnya untuk kami makan?\" Jabir berkata, \"Lantas kami kirimkan daging tersebut kepada Rasulullah shallallahu 'alaihi wasallam lalu beliau memakannya.\""},"3337":{"ar":"حَدَّثَنَا عَبْدُ الْجَبَّارِ بْنُ الْعَلَاءِ حَدَّثَنَا سُفْيَانُ قَالَ سَمِعَ عَمْرٌو جَابِرَ بْنَ عَبْدِ اللَّهِ يَقُولُابَعَثَنَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَنَحْنُ ثَلَاثُ مِائَةِ رَاكِبٍ وَأَمِيرُنَا أَبُو عُبَيْدَةَ بْنُ الْجَرَّاحِ نَرْصُدُ عِيرًا لِقُرَيْشٍ فَأَقَمْنَا بِالسَّاحِلِ نِصْفَ شَهْرٍ فَأَصَابَنَا جُوعٌ شَدِيدٌ حَتَّى أَكَلْنَا الْخَبَطَ فَسُمِّيَ جَيْشَ الْخَبَطِ فَأَلْقَى لَنَا الْبَحْرُ دَابَّةً يُقَالُ لَهَا الْعَنْبَرُ فَأَكَلْنَا مِنْهَا نِصْفَ شَهْرٍ وَادَّهَنَّا مِنْ وَدَكِهَا حَتَّى ثَابَتْ أَجْسَامُنَا قَالَ فَأَخَذَ أَبُو عُبَيْدَةَ ضِلَعًا مِنْ أَضْلَاعِهِ فَنَصَبَهُ ثُمَّ نَظَرَ إِلَى أَطْوَلِ رَجُلٍ فِي الْجَيْشِ وَأَطْوَلِ جَمَلٍ فَحَمَلَهُ عَلَيْهِ فَمَرَّ تَحْتَهُ قَالَ وَجَلَسَ فِي حَجَاجِ عَيْنِهِ نَفَرٌ قَالَ وَأَخْرَجْنَا مِنْ وَقْبِ عَيْنِهِ كَذَا وَكَذَا قُلَّةَ وَدَكٍ قَالَ وَكَانَ مَعَنَا جِرَابٌ مِنْ تَمْرٍ فَكَانَ أَبُو عُبَيْدَةَ يُعْطِي كُلَّ رَجُلٍ مِنَّا قَبْضَةً قَبْضَةً ثُمَّ أَعْطَانَا تَمْرَةً تَمْرَةً فَلَمَّا فَنِيَ وَجَدْنَا فَقْدَهُ","id":"Telah menceritakan kepada kami [Abdul Jabbar bin Al 'Ala] telah mengabarkan kepada kami [Sufyan] dia berkata; ['Amru] pernah mendengar [Jabir bin Abdullah] berkata, \"Rasulullah shallallahu 'alaihi wasallam mengirim kami beserta tiga ratus prajurit penunggang kuda yang dipimpin oleh Abu 'Ubaidah bin Jarrah untuk mengintai kafilah dagang orang-orang Quraisy, maka kami bermukim di pantai selama setengah bulan hingga kami kelaparan. Kami kemudian memakan al Khabath (dedaunan) yang terjatuh dari pohonnya, sehingga kami pun disebut dengan pasukan al Khabath. Kemudian laut mendamparkan seekor ikan besar yang disebut Al 'Anbar kepada kami, kami lalu memakannya dan mengambil minyaknya hingga stamina kami pulih dan kuat kembali.\" Jabir menurutkan, \"Kemudian Abu Ubaidah mengambil tulang rusuknya dan mendirikannya, setelah itu dia menyuruh orang yang paling tinggi di antara kami dan yang paling tinggi untanya untuk berjalan lewat bawah rongga tersebut (tulang ikan tersebut).\" Jabir melanjutkan, \"Beberapa orang juga ada yang masuk ke rongga matanya.\" Jabir berkata, \"kemudian kami mengambil daging dari rongga matanya tersebut begini dan begini, yaitu sedikit dari minyaknya.\" Jabir berkata, \"Ketika itu kami juga membawa sekantong kurma, dan Abu 'Ubaidah memberi kurma segenggam-segenggam kepada setiap prajurit, hingga pernah hanya memberi kami satu biji kurma-satu biji kurma, ketika kurma tersebut habis kamipun mendapatkan gantinya (bangkai ikan).\""},"3338":{"ar":"و حَدَّثَنَا عَبْدُ الْجَبَّارِ بْنُ الْعَلَاءِ حَدَّثَنَا سُفْيَانُ قَالَ سَمِعَ عَمْرٌو جَابِرًايَقُولُ فِي جَيْشِ الْخَبَطِ إِنَّ رَجُلًا نَحَرَ ثَلَاثَ جَزَائِرَ ثُمَّ ثَلَاثًا ثُمَّ نَهَاهُ أَبُو عُبَيْدَةَ","id":"Dan telah menceritakan kepada kami ['Abdul Jabar bin Al 'Ala] telah mencerikan kepada kami [Sufyan] dia berkata; ['Amru] pernah mendengar [Jabir] berkata tentang Jaisul Khabath, \"Seorang laki-laki menyembelih tiga ekor unta kemudian menyembelih tiga unta lagi, setelah itu Abu 'Ubaidah melarangnya.\" "},"3339":{"ar":"و حَدَّثَنَا عُثْمَانُ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا عَبْدَةُ يَعْنِي ابْنَ سُلَيْمَانَ عَنْ هِشَامِ بْنِ عُرْوَةَ عَنْ وَهْبِ بْنِ كَيْسَانَ عَنْ جَابِرِ بْنِ عَبْدِ اللَّهِ قَالَبَعَثَنَا النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَنَحْنُ ثَلَاثُ مِائَةٍ نَحْمِلُ أَزْوَادَنَا عَلَى رِقَابِنَا","id":"Dan telah menceritakan kepada kami [Utsman bin Abu Syaibah] telah menceritakan kepada kami ['Abdah] -yaitu Ibnu Sulaiman- dari [Hisyam bin 'Urwah] dari [Wahb bin Kaisan] dari [Jabir bin Abdullah] dia berkata, \"Nabi shallallahu 'alaihi wasallam pernah mengirim kami dengan jumlah tiga ratus prajurit, dan kami membawa perbekalan di atas tunggangan kami.\""},"3340":{"ar":"و حَدَّثَنِي مُحَمَّدُ بْنُ حَاتِمٍ حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ مَهْدِيٍّ عَنْ مَالِكِ بْنِ أَنَسٍ عَنْ أَبِي نُعَيْمٍ وَهْبِ بْنِ كَيْسَانَ أَنَّ جَابِرَ بْنَ عَبْدِ اللَّهِ أَخْبَرَهُ قَالَبَعَثَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ سَرِيَّةً ثَلَاثَ مِائَةٍ وَأَمَّرَ عَلَيْهِمْ أَبَا عُبَيْدَةَ بْنَ الْجَرَّاحِ فَفَنِيَ زَادُهُمْ فَجَمَعَ أَبُو عُبَيْدَةَ زَادَهُمْ فِي مِزْوَدٍ فَكَانَ يُقَوِّتُنَا حَتَّى كَانَ يُصِيبُنَا كُلَّ يَوْمٍ تَمْرَةٌو حَدَّثَنَا أَبُو كُرَيْبٍ حَدَّثَنَا أَبُو أُسَامَةَ حَدَّثَنَا الْوَلِيدُ يَعْنِي ابْنَ كَثِيرٍ قَالَ سَمِعْتُ وَهْبَ بْنَ كَيْسَانَ يَقُولُ سَمِعْتُ جَابِرَ بْنَ عَبْدِ اللَّهِ يَقُولُا بَعَثَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ سَرِيَّةً أَنَا فِيهِمْ إِلَى سِيفِ الْبَحْرِ وَسَاقُوا جَمِيعًا بَقِيَّةَ الْحَدِيثِ كَنَحْوِ حَدِيثِ عَمْرِو بْنِ دِينَارٍ وَأَبِي الزُّبَيْرِ غَيْرَ أَنَّ فِي حَدِيثِ وَهْبِ بْنِ كَيْسَانَ فَأَكَلَ مِنْهَا الْجَيْشُ ثَمَانِيَ عَشْرَةَ لَيْلَةً و حَدَّثَنِي حَجَّاجُ بْنُ الشَّاعِرِ حَدَّثَنَا عُثْمَانُ بْنُ عُمَرَ ح و حَدَّثَنِي مُحَمَّدُ بْنُ رَافِعٍ حَدَّثَنَا أَبُو الْمُنْذِرِ الْقَزَّازُ كِلَاهُمَا عَنْ دَاوُدَ بْنِ قَيْسٍ عَنْ عُبَيْدِ اللَّهِ بْنِ مِقْسَمٍ عَنْ جَابِرِ بْنِ عَبْدِ اللَّهِ قَالَ بَعَثَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بَعْثًا إِلَى أَرْضِ جُهَيْنَةَ وَاسْتَعْمَلَ عَلَيْهِمْ رَجُلًا وَسَاقَ الْحَدِيثَ بِنَحْوِ حَدِيثِهِمْ","id":"Dan telah menceritakan kepadaku [Muhammad bin Hatim] telah menceritakan kepada kami [Abdurrahman bin Mahdi] dari [Malik bin Anas] dari [Abu Nu'aim Wahb bin Kaisan] bahwa [Jabir bin Abdullah] telah mengabarkan kepadanya, dia berkata, \"Rasulullah shallallahu 'alaihi wasallam pernah mengirim kami beserta tiga ratus prajurit yang dipimpin oleh Abu 'Ubaidah bin Jarrah. Ketika kehabisan bekal, maka Abu 'Ubaidah mengumpulkan perbekalan mereka dalam satu wadah, kemudian ia memberi makan kami dengan satu biji kurma setiap harinya.\" Dan telah menceritakan kepada kami [Abu Kuraib] telah menceritakan kepada kami [Abu Usamah] telah menceritakan kepada kami [Al Walid] -yaitu Ibnu Katsir- dia berkata; saya mendengar [Wahb bin Kaisan] berkata; saya mendengar [Jabir bin Abdullah] berkata, \"Rasulullah shallallahu 'alaihi wasallam pernah mengirim pasukan untuk suatu ekspedisi, sedangkan kami termasuk dari tentara tersebut, hingga kami tiba di pantai… kemudian mereka melanjutkan hadits tersebut sebagaimana hadits 'Amru bin Dinar dan Abu Az Zubair, namun dalam hadits Wahb bin Kaisan disebutkan, 'Kemudian tentara tersebut makan (dari daging binatang itu) selama delapan belas hari.\" Dan telah menceritakan kepadaku [Hajjaj bin As Sya'ir] telah menceritakan kepada kami [Utsman bin 'Umar]. (dalam jalur lain disebutkan) Telah menceritakan kepadaku [Muhammad bin Rafi'] telah menceritakan kepada kami [Abu Al Mundzir Al Qazzaz] keduanya dari [Daud bin Qais] dari ['Ubaidullah bin Miqsam] dari [Jabir bin Abdullah] dia berkata, \"Rasulullah shallallahu 'alaihi wasallam pernah mengirim (pasukan) menuju negeri Juhainah dengan dipimpin oleh seorang laki-laki…kemudian dia melanjutkan hadits tersebut sebagaimana hadits mereka.\""},"3341":{"ar":"و حَدَّثَنَا الْحَسَنُ بْنُ عَلِيٍّ الْحُلْوَانِيُّ وَعَبْدُ بْنُ حُمَيْدٍ كِلَاهُمَا عَنْ يَعْقُوبَ بْنِ إِبْرَاهِيمَ بْنِ سَعْدٍ حَدَّثَنَا أَبِي عَنْ صَالِحٍ عَنْ ابْنِ شِهَابٍ أَنَّ أَبَا إِدْرِيسَ أَخْبَرَهُ أَنَّ أَبَا ثَعْلَبَةَ قَالَحَرَّمَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لُحُومَ الْحُمُرِ الْأَهْلِيَّةِ","id":"Dan telah menceritakan kepada kami [Al Hasan bin 'Ali Al Hulwani] dan [Abd bin Humaid] keduanya dari [Ya'qub bin Ibrahim bin Sa'd] telah menceritakan kepada kami [ayahku] dari [Shalih] dari [Ibnu Shihab] bahwa [Abu Idris] telah mengabarkan kepadanya, bahwa [Abu Tsa'labah] telah berkata, \"Rasulullah shallallahu 'alaihi wasallam melarang memakan daging keledai jinak.\""},"3342":{"ar":"و حَدَّثَنَا مُحَمَّدُ بْنُ عَبْدِ اللَّهِ بْنِ نُمَيْرٍ حَدَّثَنَا أَبِي حَدَّثَنَا عُبَيْدُ اللَّهِ حَدَّثَنِي نَافِعٌ وَسَالِمٌ عَنْ ابْنِ عُمَرَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَهَى عَنْ أَكْلِ لُحُومِ الْحُمُرِ الْأَهْلِيَّةِ","id":"Dan telah menceritakan kepada kami [Muhammad bin Abdullah bin Numair] telah menceritakan kepada kami [ayahku] telah menceritakan kepada kami ['Ubaidullah] telah menceritakan kepadaku [Nafi'] dan [Salim] dari [Ibnu Umar], bahwa Rasulullah shallallahu 'alaihi wasallam melarang makan daging keledai jinak.\""},"3343":{"ar":"و حَدَّثَنِي هَارُونُ بْنُ عَبْدِ اللَّهِ حَدَّثَنَا مُحَمَّدُ بْنُ بَكْرٍ أَخْبَرَنَا ابْنُ جُرَيْجٍ أَخْبَرَنِي نَافِعٌ قَالَ قَالَ ابْنُ عُمَرَ ح و حَدَّثَنَا ابْنُ أَبِي عُمَرَ حَدَّثَنَا أَبِي وَمَعْنُ بْنُ عِيسَى عَنْ مَالِكِ بْنِ أَنَسٍ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَ قَالَنَهَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ أَكْلِ الْحِمَارِ الْأَهْلِيِّ يَوْمَ خَيْبَرَ وَكَانَ النَّاسُ احْتَاجُوا إِلَيْهَا","id":"Dan telah menceritakan kepadaku [Harun bin Abdullah] telah menceritakan kepada kami [Muhammad bin Bakar] telah menceritakan kepada kami [Ibnu Juraij] telah mengabarkan kepadaku [Nafi'] dia berkata; [Ibnu Umar] berkata; (dalam jalur lain disebutkan) Telah menceritakan kepada kami [Ibnu Abu Umar] telah menceritakan kepada kami [ayahku] dan [Ma'n bin Isa] dari [Malik bin Anas] dari [Nafi'] dari [Ibnu Umar] dia berkata, \"Rasulullah shallallahu 'alaihi wasallam melarang makan daging keledai jinak pada waktu perang Khaibar, sebab ketika itu orang-orang membutuhkan keledai jinak (untuk mengangkut barang).\""},"3344":{"ar":"و حَدَّثَنَا أَبُو كَامِلٍ فُضَيْلُ بْنُ حُسَيْنٍ حَدَّثَنَا عَبْدُ الْوَاحِدِ يَعْنِي ابْنَ زِيَادٍ حَدَّثَنَا سُلَيْمَانُ الشَّيْبَانِيُّ قَالَ سَمِعْتُ عَبْدَ اللَّهِ بْنَ أَبِي أَوْفَى يَقُولُاأَصَابَتْنَا مَجَاعَةٌ لَيَالِيَ خَيْبَرَ فَلَمَّا كَانَ يَوْمُ خَيْبَرَ وَقَعْنَا فِي الْحُمُرِ الْأَهْلِيَّةِ فَانْتَحَرْنَاهَا فَلَمَّا غَلَتْ بِهَا الْقُدُورُ نَادَى مُنَادِي رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنْ اكْفَئُوا الْقُدُورَ وَلَا تَأْكُلُوا مِنْ لُحُومِ الْحُمُرِ شَيْئًا قَالَ فَقَالَ نَاسٌ إِنَّمَا نَهَى عَنْهَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لِأَنَّهَا لَمْ تُخَمَّسْ وَقَالَ آخَرُونَ نَهَى عَنْهَا أَلْبَتَّةَ","id":"Dan telah menceritakan kepada kami [Abu Kamil Fudlail bin Husain] telah menceritakan kepada kami [Abdul Wahid yaitu Ibnu Ziyad] telah menceritakan kepada kami [Sulaiman As Syaibani] dia berkata; saya mendengar [Abdullah bin Abu Aufa] berkata, \"Ketika beberapa malam kami berada di Khaibar, kami pernah merasa sangat lapar, kemudian kami menangkap seekor keledai jinak dan menyembelihnya. Tatkala periuk kami telah mendidih, tiba-tiba seorang penyeru yang ternyata adalah utusan Rasulullah shallallahu 'alaihi wasallam berseru, katanya, \"Tumpahkanlah periuk kalian, dan janganlah kalian makan daging keledai sedikit pun.\" Abdullah bin Abu Aufa berkata, \"Kemudian orang-orang mengatakan bahwa Rasulullah shallallahu 'alaihi wasallam telah melarang makan daging keledai sebab ia sangat langka. Sedangkan yang lain mengatakan bahwa beliau melarangnya secara qath'I (benar-benar dilarang).\""},"3345":{"ar":"حَدَّثَنَا عُبَيْدُ اللَّهِ بْنُ مُعَاذٍ حَدَّثَنَا أَبِي حَدَّثَنَا شُعْبَةُ عَنْ عَدِيٍّ وَهُوَ ابْنُ ثَابِتٍ قَالَ سَمِعْتُ الْبَرَاءَ وَعَبْدَ اللَّهِ بْنَ أَبِي أَوْفَى يَقُولَانِأَصَبْنَا حُمُرًا فَطَبَخْنَاهَا فَنَادَى مُنَادِي رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ اكْفَئُوا الْقُدُورَ","id":"Telah menceritakan kepada kami ['Ubaidillah bin Mu'adz] telah menceritakan kepada kami [ayahku] telah menceritakan kepada kami [Syu'bah] dari ['Adi] -yaitu Ibnu Tsabit- dia berkata; saya mendengar [Al Barra] dan [Abdullah bin Abu Aufa] keduanya berkata, \"Kami pernah menangkap seekor keledai dan hendak memasaknya, tiba-tiba seorang penyeru yang ternyata utusan Rasulullah shallallahu 'alaihi wasallam berkata, \"Tumpahkanlah periuk kalian.\""},"3346":{"ar":"و حَدَّثَنَا أَبُو كُرَيْبٍ وَإِسْحَقُ بْنُ إِبْرَاهِيمَ قَالَ أَبُو كُرَيْبٍ حَدَّثَنَا ابْنُ بِشْرٍ عَنْ مِسْعَرٍ عَنْ ثَابِتِ بْنِ عُبَيْدٍ قَالَ سَمِعْتُ الْبَرَاءَ يَقُولُانُهِينَا عَنْ لُحُومِ الْحُمُرِ الْأَهْلِيَّةِ","id":"Dan telah menceritakan kepada kami [Abu Kuraib] dan [Ishaq bin Ibrahim], [Abu Kuraib] berkata; telah menceritakan kepada kami [Ibnu Bisyr] dari [Mis'ar] dari [Tsabit bin 'Ubaid] dia berkata; saya mendengar [Al Barra] berkata, \"Kami telah dilarang makan daging keledai jinak.\""},"3347":{"ar":"و حَدَّثَنَا زُهَيْرُ بْنُ حَرْبٍ حَدَّثَنَا جَرِيرٌ عَنْ عَاصِمٍ عَنْ الشَّعْبِيِّ عَنْ الْبَرَاءِ بْنِ عَازِبٍ قَالَأَمَرَنَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنْ نُلْقِيَ لُحُومَ الْحُمُرِ الْأَهْلِيَّةِ نِيئَةً وَنَضِيجَةً ثُمَّ لَمْ يَأْمُرْنَا بِأَكْلِهِو حَدَّثَنِيهِ أَبُو سَعِيدٍ الْأَشَجُّ حَدَّثَنَا حَفْصٌ يَعْنِي ابْنَ غِيَاثٍ عَنْ عَاصِمٍ بِهَذَا الْإِسْنَادِ نَحْوَهُ","id":"Dan telah menceritakan kepada kami [Zuhair bin Harb] telah menceritakan kepada kami [Jarir] dari ['Ashim] dari [As Sya'bi] dari [Al Barra bin 'Azib] dia berkata, \"Rasulullah shallallahu 'alaihi wasallam memerintahkan kami untuk membuang daging keledai jinak yang kami masak, baik yang belum matang atau yang sudah matang, setelah itu beliau juga tidak memerintahkan kami untuk memakannya.\" Dan telah menceritakan kepadaku [Abu Sa'id Al Asyaj] telah menceritakan kepada kami [Hafsh] -yaitu Ibnu Ghiyats- dari ['Ashim] dengan sanad seperti ini.\""},"3348":{"ar":"و حَدَّثَنِي أَحْمَدُ بْنُ يُوسُفَ الْأَزْدِيُّ حَدَّثَنَا عُمَرُ بْنُ حَفْصِ بْنِ غِيَاثٍ حَدَّثَنَا أَبِي عَنْ عَاصِمٍ عَنْ عَامِرٍ عَنْ ابْنِ عَبَّاسٍ قَالَلَا أَدْرِي إِنَّمَا نَهَى عَنْهُ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِنْ أَجْلِ أَنَّهُ كَانَ حَمُولَةَ النَّاسِ فَكَرِهَ أَنْ تَذْهَبَ حَمُولَتُهُمْ أَوْ حَرَّمَهُ فِي يَوْمِ خَيْبَرَ لُحُومَ الْحُمُرِ الْأَهْلِيَّةِ","id":"Dan telah menceritakan kepadaku [Ahmad bin Yusuf Al Azdi] telah menceritakan kepada kami [Umar bin Hafsh bin Ghiyast] telah menceritakan kepada kami [Bapakku] dari [Ashim] dari [Amir] dari [Ibnu Abbas] ia berkata, \"Aku tidak tahu, Rasulullah shallallahu 'alaihi wasallam melarang dari memakannya apakah karena ia adalah alat transportasi sehingga beliau tidak ingin ia punah, atau beliau telah mengharamkannya pada hari khaibar (daging keledai jinak).\""},"3349":{"ar":"و حَدَّثَنَا ابْنُ أَبِي عُمَرَ حَدَّثَنَا سُفْيَانُ عَنْ أَيُّوبَ عَنْ مُحَمَّدٍ عَنْ أَنَسٍ قَالَلَمَّا فَتَحَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ خَيْبَرَ أَصَبْنَا حُمُرًا خَارِجًا مِنْ الْقَرْيَةِ فَطَبَخْنَا مِنْهَا فَنَادَى مُنَادِي رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَلَا إِنَّ اللَّهَ وَرَسُولَهُ يَنْهَيَانِكُمْ عَنْهَا فَإِنَّهَا رِجْسٌ مِنْ عَمَلِ الشَّيْطَانِ فَأُكْفِئَتْ الْقُدُورُ بِمَا فِيهَا وَإِنَّهَا لَتَفُورُ بِمَا فِيهَا","id":"Dan telah menceritakan kepada kami [Ibnu Abu Umar] telah menceritakan kepada kami [Sufyan] dari [Ayyub] dari [Muhammad] dari [Anas] dia berkata, \"Ketika Rasulullah shallallahu 'alaihi wasallam menaklukkan Khaibar, kami menangkap keledai di luar kota lalu kami memasaknya. Tiba-tiba datang pesuruh Rasulullah shallallahu 'alaihi wasallam berseru, 'Perhatian! Sesungguhnya Allah dan Rasul-Nya melarang kalian semua memasak daging keledai, karena daging keledai itu najis, sesungguhnya itu termasuk perbuatan setan.' Maka salah seorang menumpahkan periuk sehingga isinya tertumpah.\""},"3350":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ مِنْهَالٍ الضَّرِيرُ حَدَّثَنَا يَزِيدُ بْنُ زُرَيْعٍ حَدَّثَنَا هِشَامُ بْنُ حَسَّانَ عَنْ مُحَمَّدِ بْنِ سِيرِينَ عَنْ أَنَسِ بْنِ مَالِكٍ قَالَلَمَّا كَانَ يَوْمُ خَيْبَرَ جَاءَ جَاءٍ فَقَالَ يَا رَسُولَ اللَّهِ أُكِلَتْ الْحُمُرُ ثُمَّ جَاءَ آخَرُ فَقَالَ يَا رَسُولَ اللَّهِ أُفْنِيَتْ الْحُمُرُ فَأَمَرَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَبَا طَلْحَةَ فَنَادَى إِنَّ اللَّهَ وَرَسُولَهُ يَنْهَيَانِكُمْ عَنْ لُحُومِ الْحُمُرِ فَإِنَّهَا رِجْسٌ أَوْ نَجِسٌ قَالَ فَأُكْفِئَتْ الْقُدُورُ بِمَا فِيهَا","id":"Telah menceritakan kepada kami [Muhammad bin Al Minhal Ad Dlarir] telah menceritakan kepada kami [Yazid bin Zurai'] telah menceritakan kepada kami [Hisyam bin Hasan] dari [Muhammad bin Sirin] dari [Anas bin Malik] dia berkata, \"Ketika penaklukan Khaibar, tiba-tiba seseorang datang seraya berkata, \"Wahai Rasulullah, daging keledai telah di makan!\" Tidak lama kemudian, datang lagi seseorang seraya berkata, \"Wahai Rasulullah, keledai hampir punah!\" Maka Rasulullah shallallahu 'alaihi wasallam memerintahkan Abu Thalhah, lalu dia menyeru, \"Sesungguhnya Allah dan Rasul-Nya melarang kalian memasak daging keledai, karena daging keledai itu najis termasuk perbuatan setan.\" Anas melanjutkan, \"Kemudian periuk-periuk yang ada di tumpahkan hingga isinya tertumpah.\""},"3351":{"ar":"حَدَّثَنَا يَحْيَى بْنُ يَحْيَى وَأَبُو الرَّبِيعِ الْعَتَكِيُّ وَقُتَيْبَةُ بْنُ سَعِيدٍ وَاللَّفْظُ لِيَحْيَى قَالَ يَحْيَى أَخْبَرَنَا و قَالَ الْآخَرَانِ حَدَّثَنَا حَمَّادُ بْنُ زَيْدٍ عَنْ عَمْرِو بْنِ دِينَارٍ عَنْ مُحَمَّدِ بْنِ عَلِيٍّ عَنْ جَابِرِ بْنِ عَبْدِ اللَّهِأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَهَى يَوْمَ خَيْبَرَ عَنْ لُحُومِ الْحُمُرِ الْأَهْلِيَّةِ وَأَذِنَ فِي لُحُومِ الْخَيْلِ","id":"Telah menceritakan kepada kami [Yahya bin Yahya] dan [Abu Ar rabi' Al 'Ataki] dan [Qutaibah bin Sa'id] dan ini adalah lafadz Yahya, Yahya berkata; telah mengabarkan kepada kami, sedangkan yang dua mengatakan; telah menceritakan kepada kami [Hammad bin Ziad] dari ['Amru bin Dinar] dari [Muhammad bin Ali] dari [Jabir bin Abdullah], bahwa ketika perang Khaibar, Rasulullah shallallahu 'alaihi wasallam melarang makan daging keledai jinak dan membolehkan memakan daging kuda.\""},"3352":{"ar":"و حَدَّثَنِي مُحَمَّدُ بْنُ حَاتِمٍ حَدَّثَنَا مُحَمَّدُ بْنُ بَكْرٍ أَخْبَرَنَا ابْنُ جُرَيْجٍ أَخْبَرَنِي أَبُو الزُّبَيْرِ أَنَّهُ سَمِعَ جَابِرَ بْنَ عَبْدِ اللَّهِ يَقُولُاأَكَلْنَا زَمَنَ خَيْبَرَ الْخَيْلَ وَحُمُرَ الْوَحْشِ وَنَهَانَا النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ الْحِمَارِ الْأَهْلِيِّو حَدَّثَنِيهِ أَبُو الطَّاهِرِ أَخْبَرَنَا ابْنُ وَهْبٍ ح و حَدَّثَنِي يَعْقُوبُ الدَّوْرَقِيُّ وَأَحْمَدُ بْنُ عُثْمَانَ النَّوْفَلِيُّ قَالَا حَدَّثَنَا أَبُو عَاصِمٍ كِلَاهُمَا عَنْ ابْنِ جُرَيْجٍ بِهَذَا الْإِسْنَادِ","id":"Dan telah menceritakan kepadaku [Muhammad bin Hatim] telah menceritakan kepada kami [Muhammad bin Bakr] telah mengabarkan kepada kami [Ibnu Juraij] telah mengabarkan kepadaku [Abu Az Zubair] bahwa dia mendengar [Jabir bin Abdullah] berkata, \"Pada waktu perang Khaibar kami pernah memakan daging kuda dan keledai liar, dan Nabi shallallahu 'alaihi wasallam melarang kami makan daging keledai jinak.\" Dan telah menceritakan kepadaku [Abu At Thahir] telah mengabarkan kepada kami [Ibnu Wahb]. (dalam jalur lain disebutkan) Telah menceritakan kepadaku [Ya'qub Ad Dauraqi] dan [Ahmad bin Utsman An Naufali] keduanya berkata; telah menceritakan kepada kami [Abu 'Ashim] keduanya dari [Ibnu Juraij] dengan sanad ini.\""},"3353":{"ar":"و حَدَّثَنَا مُحَمَّدُ بْنُ عَبْدِ اللَّهِ بْنِ نُمَيْرٍ حَدَّثَنَا أَبِي وَحَفْصُ بْنُ غِيَاثٍ وَوَكِيعٌ عَنْ هِشَامٍ عَنْ فَاطِمَةَ عَنْ أَسْمَاءَ قَالَتْنَحَرْنَا فَرَسًا عَلَى عَهْدِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَكَلْنَاهُو حَدَّثَنَاه يَحْيَى بْنُ يَحْيَى أَخْبَرَنَا أَبُو مُعَاوِيَةَ ح و حَدَّثَنَا أَبُو كُرَيْبٍ حَدَّثَنَا أَبُو أُسَامَةَ كِلَاهُمَا عَنْ هِشَامٍ بِهَذَا الْإِسْنَادِ","id":"Dan telah menceritakan kepada kami [Muhammad bin Abdullah bin Numair] telah menceritakan kepada kami [ayahku] dan [Hafsh bin Ghiyats] dan [Waki'] dari [Hisyam] dari [Fatimah] dari [Asma] dia berkata, \"Kami pernah menyembelih seekor kuda pada zaman Rasulullah shallallahu 'alaihi wasallam, lalu kami memakan dagingnya.\" Dan telah menceritakan kepada kami [Yahya bin Yahya] telah mengabarkan kepada kami [Abu Mu'awiyah]. (dalam jalur lain disebutkan) Telah menceritakan kepada kami [Abu Kuraib] telah menceritakan kepada kami [Abu Usamah] keduanya dari [Hisyam] dengan sanad ini.\""},"3354":{"ar":"حَدَّثَنَا يَحْيَى بْنُ يَحْيَى وَيَحْيَى بْنُ أَيُّوبَ وَقُتَيْبَةُ وَابْنُ حُجْرٍ عَنْ إِسْمَعِيلَ قَالَ يَحْيَى بْنُ يَحْيَى أَخْبَرَنَا إِسْمَعِيلُ بْنُ جَعْفَرٍ عَنْ عَبْدِ اللَّهِ بْنِ دِينَارٍ أَنَّهُ سَمِعَ ابْنَ عُمَرَ يَقُولُاسُئِلَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ الضَّبِّ فَقَالَ لَسْتُ بِآكِلِهِ وَلَا مُحَرِّمِهِ","id":"Telah menceritakan kepada kami [Yahya bin Yahya] dan [Yahya bin Ayyub] dan [Qutaibah] dan [Ibnu Hujr] dari [Isma'il], [Yahya bin Yahya] berkata; telah mengabarkan kepada kami [Isma'il bin Ja'far] dari [Abdullah bin Dinar] bahwa dia mendengar [Ibnu Umar] berkata, \"Nabi shallallahu 'alaihi wasallam pernah ditanya mengenai daging biawak, beliau menjawab: \"Saya tidak memakannya dan juga tidak mengharamkannya.\""},"3355":{"ar":"و حَدَّثَنَا قُتَيْبَةُ بْنُ سَعِيدٍ حَدَّثَنَا لَيْثٌ ح و حَدَّثَنِي مُحَمَّدُ بْنُ رُمْحٍ أَخْبَرَنَا اللَّيْثُ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَ قَالَسَأَلَ رَجُلٌ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ أَكْلِ الضَّبِّ فَقَالَ لَا آكُلُهُ وَلَا أُحَرِّمُهُ","id":"Dan telah menceritakan kepada kami [Qutaibah bin Sa'id] telah menceritakan kepada kami [Laits]. (dalam jalur lain disebutkan) Telah menceritakan kepadaku [Muhammad bin Rumh] telah mengabarkan kepada kami [Al Laits] dari [Nafi'] dari [Ibnu Umar] dia berkata, \"Seorang laki-laki bertanya kepada Rasulullah shallallahu 'alaihi wasallam mengenai makan daging biawak, beliau lalu menjawab: \"Saya tidak memakannya dan juga tidak mengharamkannya.\""},"3356":{"ar":"و حَدَّثَنَا مُحَمَّدُ بْنُ عَبْدِ اللَّهِ بْنِ نُمَيْرٍ حَدَّثَنَا أَبِي حَدَّثَنَا عُبَيْدُ اللَّهِ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَ قَالَسَأَلَ رَجُلٌ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَهُوَ عَلَى الْمِنْبَرِ عَنْ أَكْلِ الضَّبِّ فَقَالَ لَا آكُلُهُ وَلَا أُحَرِّمُهُو حَدَّثَنَا عُبَيْدُ اللَّهِ بْنُ سَعِيدٍ حَدَّثَنَا يَحْيَى عَنْ عُبَيْدِ اللَّهِ بِمِثْلِهِ فِي هَذَا الْإِسْنَادِ و حَدَّثَنَاه أَبُو الرَّبِيعِ وَقُتَيْبَةُ قَالَا حَدَّثَنَا حَمَّادٌ ح و حَدَّثَنِي زُهَيْرُ بْنُ حَرْبٍ حَدَّثَنَا إِسْمَعِيلُ كِلَاهُمَا عَنْ أَيُّوبَ ح و حَدَّثَنَا ابْنُ نُمَيْرٍ حَدَّثَنَا أَبِي حَدَّثَنَا مَالِكُ بْنُ مِغْوَلٍ ح و حَدَّثَنِي هَارُونُ بْنُ عَبْدِ اللَّهِ أَخْبَرَنَا مُحَمَّدُ بْنُ بَكْرٍ أَخْبَرَنَا ابْنُ جُرَيْجٍ ح و حَدَّثَنَا هَارُونُ بْنُ عَبْدِ اللَّهِ حَدَّثَنَا شُجَاعُ بْنُ الْوَلِيدِ قَالَ سَمِعْتُ مُوسَى بْنَ عُقْبَةَ ح و حَدَّثَنَا هَارُونُ بْنُ سَعِيدٍ الْأَيْلِيُّ حَدَّثَنَا ابْنُ وَهْبٍ أَخْبَرَنِي أُسَامَةُ كُلُّهُمْ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي الضَّبِّ بِمَعْنَى حَدِيثِ اللَّيْثِ عَنْ نَافِعٍ غَيْرَ أَنَّ حَدِيثَ أَيُّوبَ أُتِيَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِضَبٍّ فَلَمْ يَأْكُلْهُ وَلَمْ يُحَرِّمْهُ وَفِي حَدِيثِ أُسَامَةَ قَالَ قَامَ رَجُلٌ فِي الْمَسْجِدِ وَرَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَلَى الْمِنْبَرِ","id":"Dan telah menceritakan kepada kami [Muhammad bin Abdullah bin Numair] telah menceritakan kepada kami [ayahku] telah menceritakan kepada kami [Ubaidullah] dari [Nafi'] dari [Ibnu Umar] dia berkata, \"Seorang laki-laki bertanya kepada Rasulullah shallallahu 'alaihi wasallam tentang daging biawak saat beliau di atas mimbar. Beliau menjawab: \"Saya tidak memakannya dan juga tidak mengharamkannya.\" Dan telah menceritakan kepada kami [Ubaidullah bin Sa'id] telah menceritakan kepada kami [Yahya] dari [Ubaidullah] dengan sanad ini seperti hadits di atas.\" Dan telah menceritakan kepada kami [Abu Ar rabi'] dan [Qutaibah] keduanya berkata; telah menceritakan kepada kami [Hammad]. (dalam jalur lain disebutkan) Telah menceritakan kepadaku [Zuhair bin Harb] telah menceritakan kepada kami [Isma'il] keduanya dari [Ayyub]. (dalam jalur lain disebutkan) Telah menceritakan kepada kami [Ibnu Numair] telah menceritakan kepada kami [ayahku] telah menceritakan kepada kami [Malik bin Mighwal]. (dalam jalur lain disebutkan) Telah menceritakan kepadaku [Harun bin Abdullah] telah mengabarkan kepada kami [Muhammad bin Bakr] telah mengabarkan kepada kami [Ibnu Juraij]. (dalam jalur lain disebutkan) Telah menceritakan kepada kami [Harun bin Abdullah] telah menceritakan kepada kami [Syuja' bin Al Walid] dia berkata; saya mendengar [Musa bin 'Uqbah]. (dalam jalur lain disebutkan) Telah menceritakan kepada kami [Harun bin Sa'id Al Aili] telah menceritakan kepada kami [Ibnu Wahb] telah mengabarkan kepadaku [Usamah] semuanya dari [Nafi'] dari [Ibnu Umar] dari Nabi shallallahu 'alaihi wasallam mengenai daging biawak, beliau tidak memakannya dan tidak pula mengharamkannya.\" Dan dalam haditsnya Usamah, dia menyebutkan, \"Seorang laki-laki berdiri dalam Masjid, sedangkan Rasulullah shallallahu 'alaihi wasallam berada di atas mimbar.\""},"3357":{"ar":"و حَدَّثَنَا عُبَيْدُ اللَّهِ بْنُ مُعَاذٍ حَدَّثَنَا أَبِي حَدَّثَنَا شُعْبَةُ عَنْ تَوْبَةَ الْعَنْبَرِيِّ سَمِعَ الشَّعْبِيَّ سَمِعَ ابْنَ عُمَرَأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ مَعَهُ نَاسٌ مِنْ أَصْحَابِهِ فِيهِمْ سَعْدٌ وَأُتُوا بِلَحْمِ ضَبٍّ فَنَادَتْ امْرَأَةٌ مِنْ نِسَاءِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّهُ لَحْمُ ضَبٍّ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كُلُوا فَإِنَّهُ حَلَالٌ وَلَكِنَّهُ لَيْسَ مِنْ طَعَامِيو حَدَّثَنَا مُحَمَّدُ بْنُ الْمُثَنَّى حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ حَدَّثَنَا شُعْبَةُ عَنْ تَوْبَةَ الْعَنْبَرِيِّ قَالَ قَالَ لِي الشَّعْبِيُّ أَرَأَيْتَ حَدِيثَ الْحَسَنِ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَقَاعَدْتُ ابْنَ عُمَرَ قَرِيبًا مِنْ سَنَتَيْنِ أَوْ سَنَةٍ وَنِصْفٍ فَلَمْ أَسْمَعْهُ رَوَى عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ غَيْرَ هَذَا قَالَ كَانَ نَاسٌ مِنْ أَصْحَابِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِيهِمْ سَعْدٌ بِمِثْلِ حَدِيثِ مُعَاذٍ","id":"Dan telah menceritakan kepada kami [Ubaidullah bin Mua'dz] telah menceritakan kepada kami [ayahku] telah menceritakan kepada kami [Syu'bah] dari [Taubah Al 'Anbari] dia mendengar [Sya'bi] bahwa dia mendengar [Ibnu Umar], bahwa Nabi shallallahu 'alaihi wasallam bersama dengan para sahabatnya, termasuk di dalamnya adalah Sa'd. Lalu dihidangkan daging biawak untuk mereka, tiba-tiba seorang wanita dari isteri Nabi shallallahu 'alaihi wasallam menyeru, \"Itu adalah daging biawak.\" Maka Rasulullah shallallahu 'alaihi wasallam bersabda: \"Makanlah karena daging itu adalah halal, namun ia tidak dari makanan yang biasa saya makan.\" Dan telah menceritakan kepada kami [Muhammad bin Al Mutsanna] telah menceritakan kepada kami [Muhammad bin Ja'far] telah menceritakan kepada kami [Syu'bah] dari [Taubah Al 'Anbari] dia berkata; [As Sya'bi] pernah berkata kepadaku, \"Bagaimana pendapatmu mengenai hadits Al Hasan dari Nabi shallallahu 'alaihi wasallam? Padahal saya pernah mendampingi [Ibnu Umar] kurang lebih dua tahun atau setahun setengah, namun saya tidak pernah mendengar dia meriwayatkan dari Nabi shallallahu 'alaihi wasallam selain hadits ini.\" Dia menjawab, \"Sekelompok orang dari sahabat Nabi shallallahu 'alaihi wasallam yang di antaranya adalah Sa'd…seperti hadits Mu'adz.\""},"3358":{"ar":"حَدَّثَنَا يَحْيَى بْنُ يَحْيَى قَالَ قَرَأْتُ عَلَى مَالِكٍ عَنْ ابْنِ شِهَابٍ عَنْ أَبِي أُمَامَةَ بْنِ سَهْلِ بْنِ حُنَيْفٍ عَنْ عَبْدِ اللَّهِ بْنِ عَبَّاسٍ قَالَدَخَلْتُ أَنَا وَخَالِدُ بْنُ الْوَلِيدِ مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بَيْتَ مَيْمُونَةَ فَأُتِيَ بِضَبٍّ مَحْنُوذٍ فَأَهْوَى إِلَيْهِ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِيَدِهِ فَقَالَ بَعْضُ النِّسْوَةِ اللَّاتِي فِي بَيْتِ مَيْمُونَةَ أَخْبِرُوا رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِمَا يُرِيدُ أَنْ يَأْكُلَ فَرَفَعَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَدَهُ فَقُلْتُ أَحَرَامٌ هُوَ يَا رَسُولَ اللَّهِ قَالَ لَا وَلَكِنَّهُ لَمْ يَكُنْ بِأَرْضِ قَوْمِي فَأَجِدُنِي أَعَافُهُ قَالَ خَالِدٌ فَاجْتَرَرْتُهُ فَأَكَلْتُهُ وَرَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَنْظُرُ","id":"Telah menceritakan kepada kami [Yahya bin Yahya] berkata; saya telah bacakan di hadapan [Malik]; dari [Ibnu Syihab] dari [Abu Umamah bin Sahl bin Hunaif] dari [Abdullah bin Abbas] dia berkata, \"Saya dan Khalid bersama-sama dengan Rasulullah shallallahu 'alaihi wasallam datang ke rumah Maimunah, lalu dia menghidangkan kepada kami daging biawak yang telah dibakar, Rasulullah shallallahu 'alaihi wasallam lalu mengulurkan tangannya untuk mengambil daging tersebut, tiba-tiba sebagian dari wanita yang berada di rumah Maimunah berkata, \"Beritahukanlah kepada Rasulullah shallallahu 'alaihi wasallam tentang hidangan yang hendak dimakan oleh beliau.\" Karena itu, beliau menarik tangannya. Lantas saya bertanya, \"Apakah daging tersebut haram wahai Rasulullah?\" beliau menjawab: \"Tidak, tetapi karena ia tidak ada di negeri kaumku, maka saya merasa jijik untuk memakannya.\" Khalid berkata, \"Lalu saya ambil daging tersebut dan saya memakannya, sedangkan Rasulullah shallallahu 'alaihi wasallam melihat.\""},"3359":{"ar":"و حَدَّثَنِي أَبُو الطَّاهِرِ وَحَرْمَلَةُ جَمِيعًا عَنْ ابْنِ وَهْبٍ قَالَ حَرْمَلَةُ أَخْبَرَنَا ابْنُ وَهْبٍ أَخْبَرَنِي يُونُسُ عَنْ ابْنِ شِهَابٍ عَنْ أَبِي أُمَامَةَ بْنِ سَهْلِ بْنِ حُنَيْفٍ الْأَنْصَارِيِّ أَنَّ عَبْدَ اللَّهِ بْنَ عَبَّاسٍ أَخْبَرَهُ أَنَّ خَالِدَ بْنَ الْوَلِيدِ الَّذِي يُقَالُ لَهُ سَيْفُ اللَّهِ أَخْبَرَهُأَنَّهُ دَخَلَ مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَلَى مَيْمُونَةَ زَوْجِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَهِيَ خَالَتُهُ وَخَالَةُ ابْنِ عَبَّاسٍ فَوَجَدَ عِنْدَهَا ضَبًّا مَحْنُوذًا قَدِمَتْ بِهِ أُخْتُهَا حُفَيْدَةُ بِنْتُ الْحَارِثِ مِنْ نَجْدٍ فَقَدَّمَتْ الضَّبَّ لِرَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَكَانَ قَلَّمَا يُقَدَّمُ إِلَيْهِ طَعَامٌ حَتَّى يُحَدَّثَ بِهِ وَيُسَمَّى لَهُ فَأَهْوَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَدَهُ إِلَى الضَّبِّ فَقَالَتْ امْرَأَةٌ مِنْ النِّسْوَةِ الْحُضُورِ أَخْبِرْنَ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِمَا قَدَّمْتُنَّ لَهُ قُلْنَ هُوَ الضَّبُّ يَا رَسُولَ اللَّهِ فَرَفَعَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَدَهُ فَقَالَ خَالِدُ بْنُ الْوَلِيدِ أَحَرَامٌ الضَّبُّ يَا رَسُولَ اللَّهِ قَالَ لَا وَلَكِنَّهُ لَمْ يَكُنْ بِأَرْضِ قَوْمِي فَأَجِدُنِي أَعَافُهُ قَالَ خَالِدٌ فَاجْتَرَرْتُهُ فَأَكَلْتُهُ وَرَسُولُ اللَّهِ يَنْظُرُ فَلَمْ يَنْهَنِيو حَدَّثَنِي أَبُو بَكْرِ بْنُ النَّضْرِ وَعَبْدُ بْنُ حُمَيْدٍ قَالَ عَبْدٌ أَخْبَرَنِي و قَالَ أَبُو بَكْرٍ حَدَّثَنَا يَعْقُوبُ بْنُ إِبْرَاهِيمَ بْنِ سَعْدٍ حَدَّثَنَا أَبِي عَنْ صَالِحِ بْنِ كَيْسَانَ عَنْ ابْنِ شِهَابٍ عَنْ أَبِي أُمَامَةَ بْنِ سَهْلٍ عَنْ ابْنِ عَبَّاسٍ أَنَّهُ أَخْبَرَهُ أَنَّ خَالِدَ بْنَ الْوَلِيدِ أَخْبَرَهُ أَنَّهُ دَخَلَ مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَلَى مَيْمُونَةَ بِنْتِ الْحَارِثِ وَهِيَ خَالَتُهُ فَقُدِّمَ إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَحْمُ ضَبٍّ جَاءَتْ بِهِ أُمُّ حُفَيْدٍ بِنْتُ الْحَارِثِ مِنْ نَجْدٍ وَكَانَتْ تَحْتَ رَجُلٍ مِنْ بَنِي جَعْفَرٍ وَكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا يَأْكُلُ شَيْئًا حَتَّى يَعْلَمَ مَا هُوَ ثُمَّ ذَكَرَ بِمِثْلِ حَدِيثِ يُونُسَ وَزَادَ فِي آخِرِ الْحَدِيثِ وَحَدَّثَهُ ابْنُ الْأَصَمِّ عَنْ مَيْمُونَةَ وَكَانَ فِي حَجْرِهَا و حَدَّثَنَا عَبْدُ بْنُ حُمَيْدٍ أَخْبَرَنَا عَبْدُ الرَّزَّاقِ أَخْبَرَنَا مَعْمَرٌ عَنْ الزُّهْرِيِّ عَنْ أَبِي أُمَامَةَ بْنِ سَهْلِ بْنِ حُنَيْفٍ عَنْ ابْنِ عَبَّاسٍ قَالَ أُتِيَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَنَحْنُ فِي بَيْتِ مَيْمُونَةَ بِضَبَّيْنِ مَشْوِيَّيْنِ بِمِثْلِ حَدِيثِهِمْ وَلَمْ يَذْكُرْ يَزِيدَ بْنَ الْأَصَمِّ عَنْ مَيْمُونَةَ و حَدَّثَنَا عَبْدُ الْمَلِكِ بْنُ شُعَيْبِ بْنِ اللَّيْثِ حَدَّثَنَا أَبِي عَنْ جَدِّي حَدَّثَنِي خَالِدُ بْنُ يَزِيدَ حَدَّثَنِي سَعِيدُ بْنُ أَبِي هِلَالٍ عَنْ ابْنِ الْمُنْكَدِرِ أَنَّ أَبَا أُمَامَةَ بْنَ سَهْلٍ أَخْبَرَهُ عَنْ ابْنِ عَبَّاسٍ قَالَ أُتِيَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَهُوَ فِي بَيْتِ مَيْمُونَةَ وَعِنْدَهُ خَالِدُ بْنُ الْوَلِيدِ بِلَحْمِ ضَبٍّ فَذَكَرَ بِمَعْنَى حَدِيثِ الزُّهْرِيِّ","id":"Dan telah menceritakan kepadaku [Abu At Thahir] dan [Harmalah] semuanya dari [Ibnu Wahb]. [Harmalah] mengatakan; telah mengabarkan kepada kami [Ibnu Wahb] telah mengabarkan kepadaku [Yunus] dari [Ibnu bin Syihab] dari [Abu Umamah bin Sahl bin Hunaif Al Anshari] bahwa [Abdullah bin Abbas] pernah mengabarkan kepadanya bahwa [Khalid bin Walid] yang di juluki dengan pedang Allah telah mengabarkan kepadanya; bahwa dia bersama dengan Rasulullah shallallahu 'alaihi wasallam pernah menemui Maimunah isteri Nabi shallallahu 'alaihi wasallam -dia adalah bibinya Khalid dan juga bibinya Ibnu Abbas- lantas dia mendapati daging biawak yang telah di bakar, kiriman dari saudara perempuanya yaitu Hufaidah binti Al Harits dari Najd, lantas daging Biawak tersebut disuguhkan kepada Rasulullah shallallahu 'alaihi wasallam. Sangat jarang beliau disuguhi makanan hingga beliau diberitahu nama makanan yang disuguhkan, ketika Rasulullah shallallahu 'alaihi wasallam hendak mengambil daging biawak tersebut, seorang wanita dari beberapa wanita yang ikut hadir berkata, \"Beritahukanlah kepada Rasulullah shallallahu 'alaihi wasallam mengenai daging yang kalian suguhkan!\" Kami lalu mengatakan, \"Itu adalah daging biawak, wahai Rasulullah!\" Seketika itu juga Rasulullah shallallahu 'alaihi wasallam mengangkat tangannya, Khalid bin Walid pun berkata, \"Wahai Rasulullah, apakah daging biawak itu haram?\" Beliau menjawab: \"Tidak, namun di negeri kaumku tidak pernah aku jumpai daging tersebut, maka aku enggan (memakannya).\" Khalid berkata, \"Lantas aku mendekatkan daging tersebut dan memakannya, sementara Rasulullah melihatku dan tidak melarangnya.\" Telah menceritakan kepadaku [Abu Bakr bin An Nadlr] dan [Abdurrahman bin Humaid], Abd berkata; telah mengabarkan kepadaku, dan Abu Bakr berkata; telah menceritakan kepada kami [Ya'qub bin Ibrahim bin Sa'd] telah menceritakan kepada kami [Ayahku] dari [Shalih bin Kaisan] dari [Ibnu Syihab] dari [Abu Umamah bin Sahl] dari [Ibnu Abbas] dia mengabarkan kepadanya, bahwa [Khalid bin Walid] mengabarkan kepadanya, bahwa ia pernah bersama Rasulullah shallallahu 'alaihi wasallam masuk ke rumah Maimunah binti Al Harits -Maimunah adalah bibinya Khalid-, lalu Rasulullah shallallahu 'alaihi wasallam disuguhi daging biawak, hasil pemberian Ummu Hufaidl dari Najd, sementara Ummu Hufaidl adalah isteri seorang laki-laki bani Ja'far. Sudah menjadi kebiasaan Rasulullah shallallahu 'alaihi wasallam, beliau tidak mau menyantap hidangan hingga beliau mengetahui hidangan tersebut…kemudian perawi menyebutkan sebagaimana haditsnya Yunus. Dan ia menambahkan di akhir hadits. Dan telah menceritakan kepadanya [Ibnu Al Asham] dari [Maimunah], sedangkan ia (Ibnu Al Asham) termasuk dari anak asuhnya.\" Dan telah menceritakan kepada kami [Abd bin Humaid] telah mengabarkan kepada kami [Abdurrazaq] telah mengabarkan kepada kami [Ma'mar] dari [Az Zuhri] dari [Abu Umamah bin Sahl bin Hunaif] dari [Ibnu Abbas] dia berkata, \"Nabi shallallahu 'alaihi wasallam pernah disuguhi dua daging biawak panggang, ketika itu kami berada di rumah Maimunah…sebagaimana hadits mereka, namun ia tidak menyebutkan nama Yazid bin Al Asham dari Maimunah.\" Dan telah menceritakan kepada kami [Abdul Malik bin Syu'aib bin Al Laits] telah menceritakan kepada kami [Ayahku] dari [Kakekku] telah menceritakan kepadaku [Khalid bin Yazid] telah menceritakan kepadaku [Sa'id bin Abu Hilal] dari [Ibnu Al Munkadir] bahwa [Abu Umamah bin Sahl] telah mengabarkan kepadanya dari [Ibnu Abbas] dia berkata, \"Rasulullah shallallahu 'alaihi wasallam pernah disuguhi daging biawak, ketika itu beliau tengah berada di rumah Maimunah, sedangkan di samping beliau ada Khalid bin Walid …lalu perawi menyebutkan hadits yang semakna dengan hadits Zuhri.\""},"3360":{"ar":"و حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ وَأَبُو بَكْرِ بْنُ نَافِعٍ قَالَ ابْنُ نَافِعٍ أَخْبَرَنَا غُنْدَرٌ حَدَّثَنَا شُعْبَةُ عَنْ أَبِي بِشْرٍ عَنْ سَعِيدِ بْنِ جُبَيْرٍ قَالَ سَمِعْتُ ابْنَ عَبَّاسٍ يَقُولُاأَهْدَتْ خَالَتِي أَمُّ حُفَيْدٍ إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ سَمْنًا وَأَقِطًا وَأَضُبًّا فَأَكَلَ مِنْ السَّمْنِ وَالْأَقِطِ وَتَرَكَ الضَّبَّ تَقَذُّرًا وَأُكِلَ عَلَى مَائِدَةِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَلَوْ كَانَ حَرَامًا مَا أُكِلَ عَلَى مَائِدَةِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Dan telah menceritakan kepada kami [Muhammad bin Basysyar] dan [Abu Bakar bin Nafi'], [Ibnu Nafi'] berkata; telah mengabarkan kepada kami [Ghundar] telah menceritakan kepada kami [Syu'bah] dari [Abu Bisyr] dari [Sa'id bin Jubair] dia berkata; saya mendengar [Ibnu Abbas] berkata, \"Bibiku, Ummu Hufaid, pernah menghadiahkan minyak samin, susu kering dan daging biawak kepada Rasulullah shallallahu 'alaihi wasallam, lalu beliau memakan minyak samin dan susu kering, dan meninggalkan daging biawak karena merasa jijik. Namun daging tersebut pernah dihidangkan (dimakan) di atas meja makan Rasulullah shallallahu 'alaihi wasallam, seandainya hal itu haram, tentu ia tidak akan terhidang (dimakan) di meja makan Rasulullah shallallahu 'alaihi wasallam.\""},"3361":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا عَلِيُّ بْنُ مُسْهِرٍ عَنْ الشَّيْبَانِيِّ عَنْ يَزِيدَ بْنِ الْأَصَمِّ قَالَدَعَانَا عَرُوسٌ بِالْمَدِينَةِ فَقَرَّبَ إِلَيْنَا ثَلَاثَةَ عَشَرَ ضَبًّا فَآكِلٌ وَتَارِكٌ فَلَقِيتُ ابْنَ عَبَّاسٍ مِنْ الْغَدِ فَأَخْبَرْتُهُ فَأَكْثَرَ الْقَوْمُ حَوْلَهُ حَتَّى قَالَ بَعْضُهُمْ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا آكُلُهُ وَلَا أَنْهَى عَنْهُ وَلَا أُحَرِّمُهُ فَقَالَ ابْنُ عَبَّاسٍ بِئْسَ مَا قُلْتُمْ مَا بُعِثَ نَبِيُّ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِلَّا مُحِلًّا وَمُحَرِّمًا إِنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بَيْنَمَا هُوَ عِنْدَ مَيْمُونَةَ وَعِنْدَهُ الْفَضْلُ بْنُ عَبَّاسٍ وَخَالِدُ بْنُ الْوَلِيدِ وَامْرَأَةٌ أُخْرَى إِذْ قُرِّبَ إِلَيْهِمْ خُوَانٌ عَلَيْهِ لَحْمٌ فَلَمَّا أَرَادَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنْ يَأْكُلَ قَالَتْ لَهُ مَيْمُونَةُ إِنَّهُ لَحْمُ ضَبٍّ فَكَفَّ يَدَهُ وَقَالَ هَذَا لَحْمٌ لَمْ آكُلْهُ قَطُّ وَقَالَ لَهُمْ كُلُوا فَأَكَلَ مِنْهُ الْفَضْلُ وَخَالِدُ بْنُ الْوَلِيدِ وَالْمَرْأَةُ وَقَالَتْ مَيْمُونَةُ لَا آكُلُ مِنْ شَيْءٍ إِلَّا شَيْءٌ يَأْكُلُ مِنْهُ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] telah menceritakan kepada kami [Ali bin Musyhir] dari [Asy Syaibani] dari [Yazid bin Al Asham] dia berkata, \"Kami pernah diundang pesta perkawinan ketika di Madinah, lalu dihidangkan kepada kami tiga belas ekor daging biawak, maka di antara kami ada yang memakannya dan ada pula yang tidak memakannya. Keesokan harinya saya mendatangi [Ibnu Abbas] dan memberitahukan kepadanya, sedangkan di samping dia ada sekelompok kaum, hingga sebagian kaum tersebut berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Saya tidak memakannya, tidak melarang dan mengharamkan untuk memakannya.\" Ibnu Abbas pun berkata, \"Sungguh jelek apa yang kalian katakan, Nabi shallallahu 'alaihi wasallam tidak diutus melainkan untuk menghalalkan atau mengharamkan. Ketika Rasulullah shallallahu 'alaihi wasallam di rumah Maimunah, sedangkan di sisi beliau ada Fadl bin Abbas, Khalid bin Walid dan seorang wanita, mereka disuguhi daging dalam tempayan besar, sewaktu Nabi shallallahu 'alaihi wasallam hendak memakannya, maka Maimunah berkata kepada beliau, \"Itu adalah daging biawak.\" Maka beliau pun menarik tangannya seraya bersabda: \"Saya belum pernah sama sekali memakan daging ini.\" Beliau juga bersabda kepada mereka (yang ada di situ): \"Makanlah daging tersebut.\" Maka Al Fadll dan Khalid serta seorang wanita pun memakannya. Maimunah juga berkata, \"Saya tidak akan memakan sesuatu melainkan jika Rasulullah shallallahu 'alaihi wasallam memakannya.\""},"3362":{"ar":"و حَدَّثَنِي سَلَمَةُ بْنُ شَبِيبٍ حَدَّثَنَا الْحَسَنُ بْنُ أَعْيَنَ حَدَّثَنَا مَعْقِلٌ عَنْ أَبِي الزُّبَيْرِ قَالَ سَأَلْتُ جَابِرًا عَنْ الضَّبِّ فَقَالَ لَا تَطْعَمُوهُ وَقَذِرَهُ وَقَالَ قَالَ عُمَرُ بْنُ الْخَطَّابِإِنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَمْ يُحَرِّمْهُإِنَّ اللَّهَ عَزَّ وَجَلَّ يَنْفَعُ بِهِ غَيْرَ وَاحِدٍ فَإِنَّمَا طَعَامُ عَامَّةِ الرِّعَاءِ مِنْهُ وَلَوْ كَانَ عِنْدِي طَعِمْتُهُ","id":"Dan telah menceritakan kepadaku [Salamah bin Syabib] telah menceritakan kepada kami [Al Hasan bin A'yan] telah menceritakan kepada kami [Ma'qil] dari [Abu Az Zubair] dia berkata, \"Saya bertanya kepada [Jabir] mengenai daging biawak, dia menjawab, \"Jangan memakannya, karena ia termasuk makanan yang menjijikkan.\" Dan dia juga berkata, \"Namun [Umar bin Khatthab] pernah berkata, \"Sesungguhnya Nabi shallallahu 'alaihi wasallam tidak mengharamkannya, dan dengannya Allah Azza Wa Jalla tidak hanya memberi manfa'at untuk satu jenis saja, hanyasanya ia adalah makanannya para pengembala, sekiranya ia ada di sini, niscaya saya telah memakannya.\""},"3363":{"ar":"و حَدَّثَنِي مُحَمَّدُ بْنُ الْمُثَنَّى حَدَّثَنَا ابْنُ أَبِي عَدِيٍّ عَنْ دَاوُدَ عَنْ أَبِي نَضْرَةَ عَنْ أَبِي سَعِيدٍ قَالَقَالَ رَجُلٌ يَا رَسُولَ اللَّهِ إِنَّا بِأَرْضٍ مَضَبَّةٍ فَمَا تَأْمُرُنَا أَوْ فَمَا تُفْتِينَا قَالَ ذُكِرَ لِي أَنَّ أُمَّةً مِنْ بَنِي إِسْرَائِيلَ مُسِخَتْ فَلَمْ يَأْمُرْ وَلَمْ يَنْهَقَالَ أَبُو سَعِيدٍ فَلَمَّا كَانَ بَعْدَ ذَلِكَ قَالَ عُمَرُ إِنَّ اللَّهَ عَزَّ وَجَلَّ لَيَنْفَعُ بِهِ غَيْرَ وَاحِدٍ وَإِنَّهُ لَطَعَامُ عَامَّةِ هَذِهِ الرِّعَاءِ وَلَوْ كَانَ عِنْدِي لَطَعِمْتُهُ إِنَّمَا عَافَهُ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah menceritakan kepadaku [Muhammad bin Al Mutsanna] telah menceritakan kepada kami [Ibnu Abu 'Adi] dari [Daud] dari [Abu Nadlrah] dari [Abu Sa'id] dia berkata, \"Seorang laki-laki bertanya, \"Wahai Rasulullah, sesungguhnya saya hidup di negeri yang banyak biawaknya, maka apa kiranya yang anda perintahkan kepada kami?\" Atau, \"Berilah kami fatwa mengenainya!\" Beliau bersabda: 'Telah disebutkan kepadaku bahwa anak cucu Bani Israil telah dirubah bentuknya menjadi hewan.' Beliau tidak memerintahkan kami (memakannya) dan tidak pula melarangnya.\" [Abu Sa'id] berkata, \"Beberapa saat setelah itu, [Umar bin Khattab] berkata, \"Sungguh, dengannya Allah benar-benar memberi manfaat tidak hanya untuk satu golongan, dia adalah makanan kebanyakan para pengembala ini. Sekiranya daging tersebut ada di sini niscaya saya telah memakannya, Rasulullah shallallahu 'alaihi wasallam memberi keringanan untuk daging itu.\""},"3364":{"ar":"حَدَّثَنَا أَبُو كَامِلٍ الْجَحْدَرِيُّ حَدَّثَنَا أَبُو عَوَانَةَ عَنْ أَبِي يَعْفُورٍ عَنْ عَبْدِ اللَّهِ بْنِ أَبِي أَوْفَى قَالَغَزَوْنَا مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ سَبْعَ غَزَوَاتٍ نَأْكُلُ الْجَرَادَو حَدَّثَنَاه أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ وَإِسْحَقُ بْنُ إِبْرَاهِيمَ وَابْنُ أَبِي عُمَرَ جَمِيعًا عَنْ ابْنِ عُيَيْنَةَ عَنْ أَبِي يَعْفُورٍ بِهَذَا الْإِسْنَادِ قَالَ أَبُو بَكْرٍ فِي رِوَايَتِهِ سَبْعَ غَزَوَاتٍ و قَالَ إِسْحَقُ سِتَّ و قَالَ ابْنُ أَبِي عُمَرَ سِتَّ أَوْ سَبْعَ و حَدَّثَنَاه مُحَمَّدُ بْنُ الْمُثَنَّى حَدَّثَنَا ابْنُ أَبِي عَدِيٍّ ح و حَدَّثَنَا ابْنُ بَشَّارٍ عَنْ مُحَمَّدِ بْنِ جَعْفَرٍ كِلَاهُمَا عَنْ شُعْبَةَ عَنْ أَبِي يَعْفُورٍ بِهَذَا الْإِسْنَادِ وَقَالَ سَبْعَ غَزَوَاتٍ","id":"Telah menceritakan kepada kami [Abu Kamil Al Jahdari] telah menceritakan kepada kami [Abu 'Awanah] dari [Abu Ya'fur] dari ['Abdullah bin Abu Aufa] dia berkata, \"Kami berperang bersama Rasulullah shallallahu 'alaihi wasallam dalam tujuh peperangan, di mana kami pernah memakan belalang.\" Dan telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] dan [Ishaq bin Ibrahim] dan [Ibnu Abu 'Umar] semunya dari [Ibnu 'Uyaianah] dari [Abu Ya'fur] dengan isnad ini. Abu Bakar menyebutkan dalam riwayatnya, \"Tujuh peperangan.\" Dan Ishaq menyebutkan, \"Enam peperangan.\" Dan Ibnu Umar menyebutkan, \"Enam atau tujuh peperangan.\" Dan telah menceritakan kepada kami [Muhammad bin Al Mutsanna] telah menceritakan kepada kami [Ibnu Abu 'Adi]. (dalam jalur lain disebutkan) Telah menceritakan kepada kami [Ibnu Basysyar] dari [Muhammad bin Ja'far] keduanya dari [Syu'bah] dari [Abu Ya'fur] dengan isnad ini. Dia berkata, \"Tujuh kali.\""},"3365":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ الْمُثَنَّى حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ حَدَّثَنَا شُعْبَةُ عَنْ هِشَامِ بْنِ زَيْدٍ عَنْ أَنَسِ بْنِ مَالِكٍ قَالَمَرَرْنَا فَاسْتَنْفَجْنَا أَرْنَبًا بِمَرِّ الظَّهْرَانِ فَسَعَوْا عَلَيْهِ فَلَغَبُوا قَالَ فَسَعَيْتُ حَتَّى أَدْرَكْتُهَا فَأَتَيْتُ بِهَا أَبَا طَلْحَةَ فَذَبَحَهَا فَبَعَثَ بِوَرِكِهَا وَفَخِذَيْهَا إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَتَيْتُ بِهَا رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَبِلَهُو حَدَّثَنِيهِ زُهَيْرُ بْنُ حَرْبٍ حَدَّثَنَا يَحْيَى بْنُ سَعِيدٍ ح و حَدَّثَنِي يَحْيَى بْنُ حَبِيبٍ حَدَّثَنَا خَالِدٌ يَعْنِي ابْنَ الْحَارِثِ كِلَاهُمَا عَنْ شُعْبَةَ بِهَذَا الْإِسْنَادِ وَفِي حَدِيثِ يَحْيَى بِوَرِكِهَا أَوْ فَخِذَيْهَا","id":"Telah menceritakan kepada kami [Muhammad bin Al Mutsanna] telah menceritakan kepada kami [Muhammad bin Ja'far] telah menceritakan kepada kami [Syu'bah] dari [Hisyam bin Zaid] dari [Anas bin Malik] dia berkata, \"Pada suatu ketika kami lewat di Marru Zhahran (nama tempat), tiba-tiba kami dikagetkan oleh seekor kelinci, lalu kami kejar kelinci tersebut sampai mereka kelelahan.\" Anas melanjutkan, \"Saya juga turut mengejarnya sampai dapat, lantas saya membawanya kepada Abu Thalhah, kemudian dia menyembelihnya dan mengirimkan kedua pahanya kepada Rasulullah shallallahu 'alaihi wasallam. Aku lalu membawanya ke hadapan Rasulullah shallallahu 'alaihi wasallam dan beliau pun menerimanya.\" Dan telah menceritakan kepadaku [Zuhair bin Harb] telah menceritakan kepada kami [Yahya bin Sa'id]. (dalam jalur lain disebutkan) Telah menceritakan kepadaku [Yahya bin Habib] telah menceritakan kepada kami [Khalid] -yaitu Ibnu Al Harits- keduanya dari [Syu'bah] dengan isnad ini. Dan dalam hadits Yahya disebutkan, \"Dengan kedua pahanya.\""},"3366":{"ar":"حَدَّثَنَا عُبَيْدُ اللَّهِ بْنُ مُعَاذٍ الْعَنْبَرِيُّ حَدَّثَنَا أَبِي حَدَّثَنَا كَهْمَسٌ عَنْ ابْنِ بُرَيْدَةَ قَالَرَأَى عَبْدُ اللَّهِ بْنُ الْمُغَفَّلِ رَجُلًا مِنْ أَصْحَابِهِ يَخْذِفُ فَقَالَ لَهُ لَا تَخْذِفْ فَإِنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يَكْرَهُ أَوْ قَالَ يَنْهَى عَنْ الْخَذْفِ ف��إِنَّهُ لَا يُصْطَادُ بِهِ الصَّيْدُ وَلَا يُنْكَأُ بِهِ الْعَدُوُّ وَلَكِنَّهُ يَكْسِرُ السِّنَّ وَيَفْقَأُ الْعَيْنَ ثُمَّ رَآهُ بَعْدَ ذَلِكَ يَخْذِفُ فَقَالَ لَهُ أُخْبِرُكَ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يَكْرَهُ أَوْ يَنْهَى عَنْ الْخَذْفِ ثُمَّ أَرَاكَ تَخْذِفُ لَا أُكَلِّمُكَ كَلِمَةً كَذَا وَكَذَاحَدَّثَنِي أَبُو دَاوُدَ سُلَيْمَانُ بْنُ مَعْبَدٍ حَدَّثَنَا عُثْمَانُ بْنُ عُمَرَ أَخْبَرَنَا كَهْمَسٌ بِهَذَا الْإِسْنَادِ نَحْوَهُ","id":"Telah menceritakan kepada kami ['Ubaidullah bin Mu'adz Al 'Anbari] telah menceritakan kepada kami [ayahku] telah menceritakan kepada kami [Kahmas] dari [Ibnu Buraidah] dia berkata, \" [Abdullah bin Mughafal] melihat seorang laki-laki dari sahabatnya sedang melempar (dengan ketapel). Lalu Abdullah berkata kepadanya, \"Janganlah kamu melempar! sebab Rasulullah shallallahu 'alaihi wasallam membenci hal itu -atau dia berkata-, beliau melarang melempar, karena hal itu tidak akan mematikan buruan dan tidak pula mengalahkan musuh, tetapi hal itu hanya bisa mematahkan gigi dan membutakan mata.\" Setelah itu Abdullah melihat laki-laki itu melempar lagi, lantas dia berkata kepadanya, \"Saya pernah memberitahukan kepadamu bahwa Rasulullah shallallahu 'alaihi wasallam membenci hal itu -atau melarang dari melempar-, kemudian saya lihat kamu melakukannya lagi. Sungguh, saya tidak akan mengatakan hal ini lagi seperti ini dan ini.\" Dan telah menceritakan kepadaku [Abu Daud Sulaiman bin Ma'bad] telah menceritakan kepada kami [Utsman bin Umar] telah mengabarkan kepada kami [Kahmas] dengan sanad seperti ini.\""},"3367":{"ar":"و حَدَّثَنَا مُحَمَّدُ بْنُ الْمُثَنَّى حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ وَعَبْدُ الرَّحْمَنِ بْنُ مَهْدِيٍّ قَالَا حَدَّثَنَا شُعْبَةُ عَنْ قَتَادَةَ عَنْ عُقْبَةَ بْنِ صُهْبَانَ عَنْ عَبْدِ اللَّهِ بْنِ مُغَفَّلٍ قَالَنَهَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ الْخَذْفِ قَالَ ابْنُ جَعْفَرٍ فِي حَدِيثِهِ وَقَالَ إِنَّهُ لَا يَنْكَأُ الْعَدُوَّ وَلَا يَقْتُلُ الصَّيْدَ وَلَكِنَّهُ يَكْسِرُ السِّنَّ وَيَفْقَأُ الْعَيْنَ و قَالَ ابْنُ مَهْدِيٍّ إِنَّهَا لَا تَنْكَأُ الْعَدُوَّ وَلَمْ يَذْكُرْ تَفْقَأُ الْعَيْنَ","id":"Dan telah menceritakan kepada kami [Muhammad bin Al Mutsanna] telah menceritakan kepada kami [Muhammad bin Ja'far] dan [Abdurrahman bin Mahdi] keduanya berkata; telah menceritakan kepada kami [Syu'bah] dari [Qatadah] dari ['Uqbah bin Shahban] dari [Abdullah bin Mughaffal] dia berkata, \"Rasulullah shallallahu 'alaihi wasallam melarang melempar (buruan dengan batu atau kerikil).\" Ibnu Ja'far menyebutkan dalam haditsnya, \"Sesungguhnya itu tidak dapat mengalahkan musuh dan tidak pula membunuh hewan buruan, itu hanya dapat mematahkan gigi dan membutakan mata.\" Dan Ibnu Mahdi menyebutkan, \"Hal itu tidak dapat mengalahkan musuh.\" Dan tidak menyebutkan, \"Membutakan mata.\""},"3368":{"ar":"و حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا إِسْمَعِيلُ ابْنُ عُلَيَّةَ عَنْ أَيُّوبَ عَنْ سَعِيدِ بْنِ جُبَيْرٍ أَنَّ قَرِيبًا لِعَبْدِ اللَّهِ بْنِ مُغَفَّلٍ خَذَفَ قَالَ فَنَهَاهُ وَقَالَإِنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَهَى عَنْ الْخَذْفِ وَقَالَ إِنَّهَا لَا تَصِيدُ صَيْدًا وَلَا تَنْكَأُ عَدُوًّا وَلَكِنَّهَا تَكْسِرُ السِّنَّ وَتَفْقَأُ الْعَيْنَ قَالَ فَعَادَ فَقَالَ أُحَدِّثُكَ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَهَى عَنْهُ ثُمَّ تَخْذِفُ لَا أُكَلِّمُكَ أَبَدًاو حَدَّثَنَاه ابْنُ أَبِي عُمَرَ حَدَّثَنَا الثَّقَفِيُّ عَنْ أَيُّوبَ بِهَذَا الْإِسْنَادِ نَحْوَهُ","id":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] telah menceritakan kepada kami [Isma'il bin Ulayyah] dari [Ayyub] dari [Sa'id bin Jubair], bahwa sahabat karib [Abdullah bin Mughaffal] sedang melempar, lantas dia melarang sahabatnya tersebut seraya berkata, \"Sesungguhnya Rasulullah shallallahu 'alaihi wasallam melarang ini (melempar dengan batu), beliau bersabda: \"Sesungguhnya itu tidak dapat membunuh hewan buruan dan tidak pula dapat mengalahkan musuh, ia hanya dapat mematahkan gigi dan membutakan mata.\" Sa'id bin Jubair berkata, \"Ketika sahabatnya tersebut mengulangi perbuatannya, maka Abdullah bin Mughaffal pun berkata, \"Aku sampaikan bahwa Rasulullah shallallahu 'alaihi wasallam melarang dari perbuatan ini namun kamu masih mengulanginya lagi, sungguh aku tidak akan mengajakmu berbicara lagi!\" Dan telah menceritakan kepada kami [Ibnu Abu Umar] telah menceritakan kepada kami [At Tsaqafi] dari [Ayyub] dengan isnad seperti ini.\""},"3369":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا إِسْمَعِيلُ ابْنُ عُلَيَّةَ عَنْ خَالِدٍ الْحَذَّاءِ عَنْ أَبِي قِلَابَةَ عَنْ أَبِي الْأَشْعَثِ عَنْ شَدَّادِ بْنِ أَوْسٍ قَالَثِنْتَانِ حَفِظْتُهُمَا عَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِنَّ اللَّهَ كَتَبَ الْإِحْسَانَ عَلَى كُلِّ شَيْءٍ فَإِذَا قَتَلْتُمْ فَأَحْسِنُوا الْقِتْلَةَ وَإِذَا ذَبَحْتُمْ فَأَحْسِنُوا الذَّبْحَ وَلْيُحِدَّ أَحَدُكُمْ شَفْرَتَهُ فَلْيُرِحْ ذَبِيحَتَهُو حَدَّثَنَاه يَحْيَى بْنُ يَحْيَى حَدَّثَنَا هُشَيْمٌ ح و حَدَّثَنَا إِسْحَقُ بْنُ إِبْرَاهِيمَ أَخْبَرَنَا عَبْدُ الْوَهَّابِ الثَّقَفِيُّ ح و حَدَّثَنَا أَبُو بَكْرِ بْنُ نَافِعٍ حَدَّثَنَا غُنْدَرٌ حَدَّثَنَا شُعْبَةُ ح و حَدَّثَنَا عَبْدُ اللَّهِ بْنُ عَبْدِ الرَّحْمَنِ الدَّارِمِيُّ أَخْبَرَنَا مُحَمَّدُ بْنُ يُوسُفَ عَنْ سُفْيَانَ ح و حَدَّثَنَا إِسْحَقُ بْنُ إِبْرَاهِيمَ أَخْبَرَنَا جَرِيرٌ عَنْ مَنْصُورٍ كُلُّ هَؤُلَاءِ عَنْ خَالِدٍ الْحَذَّاءِ بِإِسْنَادِ حَدِيثِ ابْنِ عُلَيَّةَ وَمَعْنَى حَدِيثِهِ","id":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] telah menceritakan kepada kami [Isma'il bin 'Ulayyah] dari [Khalid Al Khaddza`] dari [Abu Qilabah] dari [Abu Al Asy'ats] dari [Syaddad bin Aus] dia berkata, \"Dua perkara yang selalu saya ingat dari Rasulullah shallallahu 'alaihi wasallam, beliau bersabda: \"Sesungguhnya Allah telah mewajibkan supaya selalu bersikap baik terhadap setiap sesuatu, jika kamu membunuh maka bunuhlah dengan cara yang baik, jika kamu menyembelih maka sembelihlah dengan cara yang baik, tajamkan pisaumu dan senangkanlah hewan sembelihanmu.\" Dan telah menceritakan kepada kami [Yahya bin Yahya] telah menceritakan kepada kami [Husyaim]. (dalam jalur lain disebutkan) Telah menceritakan kepada kami [Ishaq bin Ibrahim] telah mengabarkan kepada kami [Abdul Wahhab At Tsaqafi]. (dalam jalur lain disebutkan) Telah menceritakan kepada kami [Abu Bakar bin Nafi'] telah menceritakan kepada kami [Ghundar] telah menceritakan kepada kami [Syu'bah]. (dalam jalur lain disebutkan) Telah menceritakan kepada kami [Abdullah bin Abdurrahman Ad Darimi] telah mengabarkan kepada kami [Muhammad bin Yusuf] dari [Sufyan]. (dalam jalur lain disebutkan) Telah menceritakan kepada kami [Ishaq bin Ibrahim] telah mengabarkan kepada kami [Jarir] dari [Manshur] mereka semua dari [Khalid Al Khaddza`] dengan sanad dan makna yang sama dengan hadits Ibnu 'Ulayyah.\""},"3370":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ الْمُثَنَّى حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ حَدَّثَنَا شُعْبَةُ قَالَ سَمِعْتُ هِشَامَ بْنَ زَيْدِ بْنِ أَنَسِ بْنِ مَالِكٍ قَالَ دَخَلْتُ مَعَ جَدِّي أَنَسِ بْنِ مَالِكٍ دَارَ الْحَكَمِ بْنِ أَيُّوبَ فَإِذَا قَوْمٌ قَدْ نَصَبُوا دَجَاجَةً يَرْمُونَهَا قَالَفَقَالَ أَنَسٌ نَهَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنْ تُصْبَرَ الْبَهَائِمُو حَدَّثَنِيهِ زُهَيْرُ بْنُ حَرْبٍ حَدَّثَنَا يَحْيَى بْنُ سَعِيدٍ وَعَبْدُ الرَّحْمَنِ بْنُ مَهْدِيٍّ ح و حَدَّثَنِي يَحْيَى بْنُ حَبِيبٍ حَدَّثَنَا خَالِدُ بْنُ الْحَارِثِ ح و حَدَّثَنَا أَبُو كُرَيْبٍ حَدَّثَنَا أَبُو أُسَامَةَ كُلُّهُمْ عَنْ شُعْبَةَ بِهَذَا الْإِسْنَادِ","id":"Telah menceritakan kepada kami [Muhammad bin Al Mutsanna] telah menceritakan kepada kami [Muhammad bin Ja'far] telah menceritakan kepada kami [Syu'bah] dia berkata; saya mendengar [Hisyam bin Zaid bin Anas bin Malik] dia berkata, \"Saya bersama kakekku, [Anas bin Malik], datang ke rumah Al Hakam bin Ayyub, ternyata saya dapati kaum di sana menjadikan ayam sebagai sasaran memanah. Maka Anas berkata, \"Rasulullah shallallahu 'alaihi wasallam telah melarang menjadikan binatang sebagai sasaran memanah.\" Dan telah menceritakan kepadaku [Zuhair bin Harb] telah menceritakan kepada kami [Yahya bin Sa'id] dan [Abdurrahman bin Mahdi]. (dalam jalur lain disebutkan) Telah menceritakan kepadaku [Yahya bin Habib] telah menceritakan kepada kami [Khalid bin Al Harits]. (dalam jalur lain disebutkan) Telah menceritakan kepada kami [Abu Kuraib] telah menceritakan kepada kami [Abu Usamah] mereka semua dari [Syu'bah] dengan isnad ini.\""},"3371":{"ar":"و حَدَّثَنَا عُبَيْدُ اللَّهِ بْنُ مُعَاذٍ حَدَّثَنَا أَبِي حَدَّثَنَا شُعْبَةُ عَنْ عَدِيٍّ عَنْ سَعِيدِ بْنِ جُبَيْرٍ عَنْ ابْنِ عَبَّاسٍأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَا تَتَّخِذُوا شَيْئًا فِيهِ الرُّوحُ غَرَضًاو حَدَّثَنَاه مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ وَعَبْدُ الرَّحْمَنِ بْنُ مَهْدِيٍّ عَنْ شُعْبَةَ بِهَذَا الْإِسْنَادِ مِثْلَهُ","id":"Dan telah menceritakan kepada kami [Ubaidullah bin Mu'adz] telah menceritakan kepada kami [ayahku] telah menceritakan kepada kami [Syu'bah] dari ['Adi] dari [Sa'id bin Jubair] dari [Ibnu Abbas], bahwa Nabi shallallahu 'alaihi wasallam bersabda: \"Janganlah kalian mengambil sesuatu yang bernyawa sebagai sasaran (menembak).\" Dan telah menceritakan kepada kami [Muhammad bin Basysyar] telah menceritakan kepada kami [Muhammad bin Ja'far] dan [Abdurrahman bin Mahdi] dari [Syu'bah] dengan isnad seperti ini.\""},"3372":{"ar":"و حَدَّثَنَا شَيْبَانُ بْنُ فَرُّوخَ وَأَبُو كَامِلٍ وَاللَّفْظُ لِأَبِي كَامِلٍ قَالَا حَدَّثَنَا أَبُو عَوَانَةَ عَنْ أَبِي بِشْرٍ عَنْ سَعِيدِ بْنِ جُبَيْرٍ قَالَمَرَّ ابْنُ عُمَرَ بِنَفَرٍ قَدْ نَصَبُوا دَجَاجَةً يَتَرَامَوْنَهَا فَلَمَّا رَأَوْا ابْنَ عُمَرَ تَفَرَّقُوا عَنْهَا فَقَالَ ابْنُ عُمَرَ مَنْ فَعَلَ هَذَا إِنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَعَنَ مَنْ فَعَلَ هَذَا","id":"Dan telah menceritakan kepada kami [Syaiban bin Farruh] dan [Abu Kamil] sedangkan lafadznya dari Abu Kamil, keduanya berkata; telah menceritakan kepada kami [Abu 'Awanah] dari [Abu Bisyr] dari [Sa'id bin Jubair] dia berkata, \"Ibnu Umar pernah melewati sekelompok orang yang menjadikan seekor ayam sebagai sasaran memanah, saat melihat Ibnu Umar maka mereka lari berpencar, lantas [Ibnu Umar] berkata, \"Siapakah yang melakukan hal ini? Sesungguhnya Rasulullah shallallahu 'alaihi wasallam melaknat orang yang melakukan hal ini.\""},"3373":{"ar":"و حَدَّثَنِي زُهَيْرُ بْنُ حَرْبٍ حَدَّثَنَا هُشَيْمٌ أَخْبَرَنَا أَبُو بِشْرٍ عَنْ سَعِيدِ بْنِ جُبَيْرٍ قَالَ مَرَّ ابْنُ عُمَرَ بِفِتْيَانٍ مِنْ قُرَيْشٍ قَدْ نَصَبُوا طَيْرًا وَهُمْ يَرْمُونَهُ وَقَدْ جَعَلُوا لِصَاحِبِ الطَّيْرِ كُلَّ خَاطِئَةٍ مِنْ نَبْلِهِمْ فَلَمَّا رَأَوْا ابْنَ عُمَرَ تَفَرَّقُوافَقَالَ ابْنُ عُمَرَ مَنْ فَعَلَ هَذَا لَعَنْ اللَّهُ مَنْ فَعَلَ هَذَا إِنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَعَنَ مَنْ اتَّخَذَ شَيْئًا فِيهِ الرُّوحُ غَرَضًا","id":"Dan telah menceritakan kepadaku [Zuhair bin Harb] telah menceritakan kepada kami [Husyaim] telah mengabarkan kepada kami [Abu Bisyr] dari [Sa'id bi Jubair] dia berkata, \"Suatu ketika [Ibnu Umar] melewati beberapa pemuda orang Quraisy yang mengurung seekor burung untuk sasaran memanah. Mereka membayar kepada pemilik burung setiap panahan yang tidak mengena. Tatkala mereka melihat Ibnu Umar, mereka lari berpencar. Lantas Ibnu Umar berkata, \"Siapakah yang melakukan perbuatan ini? Allah telah melaknat orang yang melakukan hal ini. Sungguh, Rasulullah shallallahu 'alaihi wasallam mengutuk orang yang menjadikan makhluk bernyawa sebagai sasaran (menembak).\""},"3374":{"ar":"حَدَّثَنِي مُحَمَّدُ بْنُ حَاتِمٍ حَدَّثَنَا يَحْيَى بْنُ سَعِيدٍ عَنْ ابْنِ جُرَيْجٍ ح و حَدَّثَنَا عَبْدُ بْنُ حُمَيْدٍ أَخْبَرَنَا مُحَمَّدُ بْنُ بَكْرٍ أَخْبَرَنَا ابْنُ جُرَيْجٍ ح و حَدَّثَنِي هَارُونُ بْنُ عَبْدِ اللَّهِ حَدَّثَنَا حَجَّاجُ بْنُ مُحَمَّدٍ قَالَ قَالَ ابْنُ جُرَيْجٍ أَخْبَرَنِي أَبُو الزُّبَيْرِ أَنَّهُ سَمِعَ جَابِرَ بْنَ عَبْدِ اللَّهِ يَقُولُانَهَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَل��َمَ أَنْ يُقْتَلَ شَيْءٌ مِنْ الدَّوَابِّ صَبْرًا","id":"Dan telah menceritakan kepadaku [Muhammad bin Hatim] telah menceritakan kepada kami [Yahya bin Sa'id] dari [Ibnu Juraij]. (dalam jalur lain disebutkan) Telah menceritakan kepada kami [Abd bin Humaid] telah mengabarkan kepada kami [Muhammad bin Bakr] telah mengabarkan kepada kami [Ibnu Juraij]. (dalam jalur lain disebutkan) Telah menceritakan kepadaku [Harun bin Abdullah] telah menceritakan kepada kami [Hajjaj bin Muhammad] dia berkata; [Ibnu Juraij] berkata; telah mengabarkan kepadaku [Abu Az Zubair] bahwa dia mendengar [Jabir bin Abdullah] berkata, \"Rasulullah shallallahu 'alaihi wasallam melarang menjadikan binatang bernyawa sebagai sasaran (menembak).\""},"3375":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ يُونُسَ حَدَّثَنَا زُهَيْرٌ حَدَّثَنَا الْأَسْوَدُ بْنُ قَيْسٍ ح و حَدَّثَنَاه يَحْيَى بْنُ يَحْيَى أَخْبَرَنَا أَبُو خَيْثَمَةَ عَنْ الْأَسْوَدِ بْنِ قَيْسٍ حَدَّثَنِي جُنْدَبُ بْنُ سُفْيَانَ قَالَشَهِدْتُ الْأَضْحَى مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَلَمْ يَعْدُ أَنْ صَلَّى وَفَرَغَ مِنْ صَلَاتِهِ سَلَّمَ فَإِذَا هُوَ يَرَى لَحْمَ أَضَاحِيَّ قَدْ ذُبِحَتْ قَبْلَ أَنْ يَفْرُغَ مِنْ صَلَاتِهِ فَقَالَ مَنْ كَانَ ذَبَحَ أُضْحِيَّتَهُ قَبْلَ أَنْ يُصَلِّيَ أَوْ نُصَلِّيَ فَلْيَذْبَحْ مَكَانَهَا أُخْرَى وَمَنْ كَانَ لَمْ يَذْبَحْ فَلْيَذْبَحْ بِاسْمِ اللَّهِ","id":"Telah menceritakan kepada kami [Ahmad bin Yunus] telah menceritakan kepada kami [Zuhair] telah menceritakan kepada kami [Al Aswad bin Qais]. (dalam jalur lain disebutkan) Telah menceritakan kepada kami [Yahya bin Yahya] telah mengabarkan kepada kami [Abu Khaitsamah] dari [Al Aswad bin Qais] telah menceritakan kepadaku [Jundab bin Sufyan] dia berkata, \"Saya pernah ikut hadir shalat Idul Adlha bersama Rasulullah shallallahu 'alaihi wasallam, tidak lama setelah selesai shalat, beliau melihat daging kurban yang telah disembelih, maka beliau bersabda: \"Siapa yang menyembelih hewan kurban sebelum shalat, hendaknya ia mengulanginya sebagai gantinya. Dan siapa yang belum menyembelih hendaknya menyembelih dengan menyebut nama Allah.\""},"3376":{"ar":"و حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا أَبُو الْأَحْوَصِ سَلَّامُ بْنُ سُلَيْمٍ عَنْ الْأَسْوَدِ بْنِ قَيْسٍ عَنْ جُنْدَبِ بْنِ سُفْيَانَ قَالَشَهِدْتُ الْأَضْحَى مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَلَمَّا قَضَى صَلَاتَهُ بِالنَّاسِ نَظَرَ إِلَى غَنَمٍ قَدْ ذُبِحَتْ فَقَالَ مَنْ ذَبَحَ قَبْلَ الصَّلَاةِ فَلْيَذْبَحْ شَاةً مَكَانَهَا وَمَنْ لَمْ يَكُنْ ذَبَحَ فَلْيَذْبَحْ عَلَى اسْمِ اللَّهِو حَدَّثَنَاه قُتَيْبَةُ بْنُ سَعِيدٍ حَدَّثَنَا أَبُو عَوَانَةَ ح و حَدَّثَنَا إِسْحَقُ بْنُ إِبْرَاهِيمَ وَابْنُ أَبِي عُمَرَ عَنْ ابْنِ عُيَيْنَةَ كِلَاهُمَا عَنْ الْأَسْوَدِ بْنِ قَيْسٍ بِهَذَا الْإِسْنَادِ وَقَالَا عَلَى اسْمِ اللَّهِ كَحَدِيثِ أَبِي الْأَحْوَصِ","id":"Dan telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] telah menceritakan kepada kami [Abu Al Ahwash Sallam bin Sulaim] dari [Al Aswad bin Qais] dari [Jundab bin Sufyan] dia berkata, \"Saya pernah ikut shalat Iedul Adlha bersama Rasulullah shallallahu 'alaihi wasallam. Setelah beliau selesai shalat bersama orang-orang, beliau melihat ada seekor kambing yang telah disembelih, lantas beliau bersabda: \"Barangsiapa menyembelih sebelum shalat, hendaknya ia mengulangi sembelihannya lagi sebagai pengganti. Dan barangsiapa belum menyembelih hendaknya menyembelih dengan nama Allah.\" Dan telah menceritakan kepada kami [Qutaibah bin Sa'id] telah menceritakan kepada kami [Abu 'Awanah]. (dalam jalur lain disebutkan) Telah menceritakan kepada kami [Ishaq bin Ibrahim] dan [Ibnu Abu Umar] dari [Ibnu 'Uyainah] keduanya dari [Al Aswad bin Qais] dengan isnad ini, keduanya menyebutkan, 'Atas nama Allah, ' seperti hadits Abu Al Ahwash.\""},"3377":{"ar":"حَدَّثَنَا عُبَيْدُ اللَّهِ بْنُ مُعَاذٍ حَدَّثَنَا أَبِي حَدَّثَنَا شُعْبَةُ عَنْ الْأَسْوَدِ سَمِعَ جُنْدَبًا الْبَجَلِيَّ قَالَشَهِدْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ صَلَّى يَوْمَ أَضْحًى ثُمَّ خَطَبَ فَقَالَ مَنْ كَانَ ذَبَحَ قَبْلَ أَنْ يُصَلِّيَ فَلْيُعِدْ مَكَانَهَا وَمَنْ لَمْ يَكُنْ ذَبَحَ فَلْيَذْبَحْ بِاسْمِ اللَّهِحَدَّثَنَا مُحَمَّدُ بْنُ الْمُثَنَّى وَابْنُ بَشَّارٍ قَالَا حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ حَدَّثَنَا شُعْبَةُ بِهَذَا الْإِسْنَادِ مِثْلَهُ","id":"Telah menceritakan kepada kami [Ubaidullah bin Mu'adz] telah menceritakan kepada kami [ayahku] telah menceritakan kepada kami [Syu'bah] dari [Al Aswad] bahwa dia mendengar [Jundab Al Bajali] berkata, \"Saya pernah ikut shalat Iedul Adlha bersama Rasulullah shallallahu 'alaihi wasallam, kemudian beliau berkhutbah: \"Barangsiapa menyembelih sebelum shalat hendaknya ia mengulanginya, dan barangsiapa belum menyembelih hendaknya dengan menyebut nama Allah.\" Telah menceritakan kepada kami [Muhammad bin Al Mutsanna] dan [Ibnu Basyar] keduanya berkata; telah menceritakan kepada kami [Muhammad bin Ja'far] telah menceritakan kepada kami [Syu'bah] dengan isnad seperti ini.\""},"3378":{"ar":"و حَدَّثَنَا يَحْيَى بْنُ يَحْيَى أَخْبَرَنَا خَالِدُ بْنُ عَبْدِ اللَّهِ عَنْ مُطَرِّفٍ عَنْ عَامِرٍ عَنْ الْبَرَاءِ قَالَضَحَّى خَالِي أَبُو بُرْدَةَ قَبْلَ الصَّلَاةِ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ تِلْكَ شَاةُ لَحْمٍ فَقَالَ يَا رَسُولَ اللَّهِ إِنَّ عِنْدِي جَذَعَةً مِنْ الْمَعْزِ فَقَالَ ضَحِّ بِهَا وَلَا تَصْلُحُ لِغَيْرِكَ ثُمَّ قَالَ مَنْ ضَحَّى قَبْلَ الصَّلَاةِ فَإِنَّمَا ذَبَحَ لِنَفْسِهِ وَمَنْ ذَبَحَ بَعْدَ الصَّلَاةِ فَقَدْ تَمَّ نُسُكُهُ وَأَصَابَ سُنَّةَ الْمُسْلِمِينَ","id":"Dan telah menceritakan kepada kami [Yahya bin Yahya] telah mengabarkan kepada kami [Khalid bin Abdullah] dari [Mutharif] dari ['Amir] dari [Al Barra`] dia berkata, \"Pamanku, Abu Burdah, pernah menyembelih sebelum melaksanakan shalat Iedul Adlha, maka Rasulullah shallallahu 'alaihi wasallam bersabda: \"Itu adalah kambing yang disembelih untuk dagingnya.\" Pamanku berkata, \"Ya Rasulullah, aku punya memiliki seekor kambing muda.\" Beliau bersabda: \"Sembelihlah, dan ini hanya khusus kamu bukan untuk yang lain.\" Kemudian beliau melanjutkan sabdanya: \"Barangsiapa berkurban sebelum shalat (Iedul Adlha), dia hanya menyembelih untuk dirinya sendiri, dan barangsiapa menyembelih setelah shalat (Iedul Adlha), maka sempurnalah ibadahnya dan dia telah melaksanakan sunnah kaum Muslimin dengan tepat.\""},"3379":{"ar":"حَدَّثَنَا يَحْيَى بْنُ يَحْيَى أَخْبَرَنَا هُشَيْمٌ عَنْ دَاوُدَ عَنْ الشَّعْبِيِّ عَنْ الْبَرَاءِ بْنِ عَازِبٍأَنَّ خَالَهُ أَبَا بُرْدَةَ بْنَ نِيَارٍ ذَبَحَ قَبْلَ أَنْ يَذْبَحَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ يَا رَسُولَ اللَّهِ إِنَّ هَذَا يَوْمٌ اللَّحْمُ فِيهِ مَكْرُوهٌ وَإِنِّي عَجَّلْتُ نَسِيكَتِي لِأُطْعِمَ أَهْلِي وَجِيرَانِي وَأَهْلَ دَارِي فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَعِدْ نُسُكًا فَقَالَ يَا رَسُولَ اللَّهِ إِنَّ عِنْدِي عَنَاقَ لَبَنٍ هِيَ خَيْرٌ مِنْ شَاتَيْ لَحْمٍ فَقَالَ هِيَ خَيْرُ نَسِيكَتَيْكَ وَلَا تَجْزِي جَذَعَةٌ عَنْ أَحَدٍ بَعْدَكَحَدَّثَنَا مُحَمَّدُ بْنُ الْمُثَنَّى حَدَّثَنَا ابْنُ أَبِي عَدِيٍّ عَنْ دَاوُدَ عَنْ الشَّعْبِيِّ عَنْ الْبَرَاءِ بْنِ عَازِبٍ قَالَ خَطَبَنَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَوْمَ النَّحْرِ فَقَالَ لَا يَذْبَحَنَّ أَحَدٌ حَتَّى يُصَلِّيَ قَالَ فَقَالَ خَالِي يَا رَسُولَ اللَّهِ إِنَّ هَذَا يَوْمٌ اللَّحْمُ فِيهِ مَكْرُوهٌ ثُمَّ ذَكَرَ بِمَعْنَى حَدِيثِ هُشَيْمٍ","id":"Telah menceritakan kepada kami [Yahya bin Yahya] telah mengabarkan kepada kami [Husyaim] dari [Daud] dari [Asy Sya'bi] dari [Al Barra` bin 'Azib], bahwa pamannya, Abu Burdah bin Niyar, telah menyembelih hewan kurban sebelum Nabi shallallahu 'alaihi wasallam berkurban, maka dia berkata, \"Wahai Rasulullah, sesungguhnya hari ini adalah hari dibagikannya daging (kurban), dan hari makan-makan. Oleh karena itu, saya berkeinginan untuk berkurban lebih dahulu supaya saya dapat memberi makan keluarga dan para tetanggaku.\" Maka Rasulullah shallallahu 'alaihi wasallam bersabda: \"Ulangilah kurbanmu.\" Dia berkata, \"Wahai Rasulullah, sesungguhnya saya memiliki kambing yang belum cukup umur, dan dia lebih baik daripada dua ekor kambing.\" Beliau menjawab: \"Itu adalah sebaik-baik kurban yang kamu lakukan, dan jangan sampai ada lagi orang yang berkurban dengan Jad'ah setelah kamu.\" Dan telah menceritakan kepada kami [Muhammad bin Al Mutsanna] telah menceritakan kepada kami [Ibn Abu 'Adi] dari [Daud] dari [As Sya'bi] dari [Al Barra` bin 'Azib] dia berkata, \"Rasulullah shallallahu 'alaihi wasallam pernah berkhutbah pada hari raya Qurban, lalu beliau bersabda: \"Janganlah salah seorang dari kalian berkurban hingga selesai shalat.\" Barra` berkata, \"Lantas pamanku berkata, \"Wahai Rasulullah, sesungguhnya hari ini adalah hari dibagikannya daging kurban, dan hari makan-makan…, kemudian dia menyebutkan hadits yang serupa dengan hadits Husyaim.\""},"3380":{"ar":"و حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ نُمَيْرٍ ح و حَدَّثَنَا ابْنُ نُمَيْرٍ حَدَّثَنَا أَبِي حَدَّثَنَا زَكَرِيَّاءُ عَنْ فِرَاسٍ عَنْ عَامِرٍ عَنْ الْبَرَاءِ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ صَلَّى صَلَاتَنَا وَوَجَّهَ قِبْلَتَنَا وَنَسَكَ نُسُكَنَا فَلَا يَذْبَحْ حَتَّى يُصَلِّيَ فَقَالَ خَالِي يَا رَسُولَ اللَّهِ قَدْ نَسَكْتُ عَنْ ابْنٍ لِي فَقَالَ ذَاكَ شَيْءٌ عَجَّلْتَهُ لِأَهْلِكَ فَقَالَ إِنَّ عِنْدِي شَاةً خَيْرٌ مِنْ شَاتَيْنِ قَالَ ضَحِّ بِهَا فَإِنَّهَا خَيْرُ نَسِيكَةٍ","id":"Dan telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] telah menceritakan kepada kami [Abdullah bin Numair]. (dalam jalur lain disebutkan) Telah menceritakan kepada kami [Ibnu Numair] telah menceritakan kepada kami [ayahku] telah menceritakan kepada kami [Zakaria] dari [Firas] dari ['Amir] dari [Al Barra`] dia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa shalat sebagaimana shalat kami dengan menghadapkan kiblat kami dan beribadah sebagaimana ibadah kami, hendaknya ia tidak menyembelih hewan kurban hingga ia selesai shalat.\" Lantas pamanku berkata, \"Wahai Rasulullah, saya telah menyembelih dari binatang kurban milik puteraku.\" Beliau bersabda: \"Itu adalah sesuatu yang kamu segerakan untuk keluargamu.\" Pamanku berkata, \"Namun saya masih memliki seekor kambing yang lebih baik daripada dua ekor kambing.\" Beliau bersabda: \"Sembelihlah ia, karena ia termasuk dari sebaik-baik ibadah.\""},"3381":{"ar":"و حَدَّثَنَا مُحَمَّدُ بْنُ الْمُثَنَّى وَابْنُ بَشَّارٍ وَاللَّفْظُ لِابْنِ الْمُثَنَّى قَالَا حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ حَدَّثَنَا شُعْبَةُ عَنْ زُبَيْدٍ الْإِيَامِيِّ عَنْ الشَّعْبِيِّ عَنْ الْبَرَاءِ بْنِ عَازِبٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّ أَوَّلَ مَا نَبْدَأُ بِهِ فِي يَوْمِنَا هَذَا نُصَلِّي ثُمَّ نَرْجِعُ فَنَنْحَرُ فَمَنْ فَعَلَ ذَلِكَ فَقَدْ أَصَابَ سُنَّتَنَا وَمَنْ ذَبَحَ فَإِنَّمَا هُوَ لَحْمٌ قَدَّمَهُ لِأَهْلِهِ لَيْسَ مِنْ النُّسُكِ فِي شَيْءٍ وَكَانَ أَبُو بُرْدَةَ بْنُ نِيَارٍ قَدْ ذَبَحَ فَقَالَ عِنْدِي جَذَعَةٌ خَيْرٌ مِنْ مُسِنَّةٍ فَقَالَ اذْبَحْهَا وَلَنْ تَجْزِيَ عَنْ أَحَدٍ بَعْدَكَحَدَّثَنَا عُبَيْدُ اللَّهِ بْنُ مُعَاذٍ حَدَّثَنَا أَبِي حَدَّثَنَا شُعْبَةُ عَنْ زُبَيْدٍ سَمِعَ الشَّعْبِيَّ عَنْ الْبَرَاءِ بْنِ عَازِبٍ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِثْلَهُ و حَدَّثَنَا قُتَيْبَةُ بْنُ سَعِيدٍ وَهَنَّادُ بْنُ السَّرِيِّ قَالَا حَدَّثَنَا أَبُو الْأَحْوَصِ ح و حَدَّثَنَا عُثْمَانُ بْنُ أَبِي شَيْبَةَ وَإِسْحَقُ بْنُ إِبْرَاهِيمَ جَمِيعًا عَنْ جَرِيرٍ كِلَاهُمَا عَنْ مَنْصُورٍ عَنْ الشَّعْبِيِّ عَنْ الْبَرَاءِ بْنِ عَازِبٍ قَالَ خَطَبَنَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَوْمَ النَّحْرِ بَعْدَ الصَّلَاةِ ثُمَّ ذَكَرَ نَحْوَ حَدِيثِهِمْ","id":"Dan telah menceritakan kepada kami [Muhammad bin Al Mutsanna] dan [Ibnu Basyar] sedangkan lafadznya dari Ibnu Mutsanna, keduanya berkata; telah menceritakan kepada kami [Muhammad bin Ja'far] telah menceritakan kepada kami [Syu'bah] dari [Zubaid Al Iyyami] dari [As Sya'bi] dari [Al Barra` bin 'Azib] dia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Pekerjaan yang mula-mula kita lakukan hari ini ialah shalat. Sesudah shalat, kita pulang lalu menyembelih kurban. Siapa yang melakukan seperti itu, sesungguhnya dia melaksanakan sunnahku dengan tepat. Namun siapa menyembelih kurban sebelum shalat ied, itu hanya merupakan daging yang biasa diberikan kepada keluarganya, dan tidak merupakan kurban sama sekali.\" Ketika itu Abu Burdah bin Niyar telah menyembelih hewan kurban, lalu dia berkata, \"saya memiliki seekor kambing muda yang lebih baik dari kambing biasa.\" Lantas beliau bersabda: \"Sembelihlah ia, dan jangan sampai ada lagi orang yang menyembelih Jad'ah setelahmu.\" Dan telah menceritakan kepada kami ['Ubaidullah bin Mu'adz] telah menceritakan kepada kami [ayahku] telah menceritakan kepada kami [Syu'bah] dari [Zubaid] bahwa dia mendengar [Sya'bi] dari [Al Barra` bin 'Azib] dari Nabi shallallahu 'alaihi wasallam seperti hadits di atas.\" Dan telah menceritakan kepada kami [Qutaibah bin Sa'id] dan [Hannad bin As Sarri] keduanya berkata; telah menceritakan kepada kami [Abu Al Ahwash]. (dalam jalur lain disebutkan) Telah menceritakan kepada kami [Utsman bin Abu Syaibah] dan [Ishaq bin Ibrahim] semuanya dari [Jarir] keduanya dari [Manshur] dari [As Sya'bi] dari [Al Barra` bin 'Azib] dia berkata, \"Rasulullah shallallahu 'alaihi wasallam pernah berkhutbah pada hari raya kurban setelah melakukan shalat…kemudian dia menyebutkan sebagaimana hadits mereka.\""},"3382":{"ar":"و حَدَّثَنِي أَحْمَدُ بْنُ سَعِيدِ بْنِ صَخْرٍ الدَّارِمِيُّ حَدَّثَنَا أَبُو النُّعْمَانِ عَارِمُ بْنُ الْفَضْلِ حَدَّثَنَا عَبْدُ الْوَاحِدِ يَعْنِي ابْنَ زِيَادٍ حَدَّثَنَا عَاصِمٌ الْأَحْوَلُ عَنْ الشَّعْبِيِّ حَدَّثَنِي الْبَرَاءُ بْنُ عَازِبٍ قَالَخَطَبَنَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي يَوْمِ نَحْرٍ فَقَالَ لَا يُضَحِّيَنَّ أَحَدٌ حَتَّى يُصَلِّيَ قَالَ رَجُلٌ عِنْدِي عَنَاقُ لَبَنٍ هِيَ خَيْرٌ مِنْ شَاتَيْ لَحْمٍ قَالَ فَضَحِّ بِهَا وَلَا تَجْزِي جَذَعَةٌ عَنْ أَحَدٍ بَعْدَكَ","id":"Dan telah menceritakan kepadaku [Ahmad bin Sa'id bin Shakhr Ad Darimi] telah menceritakan kepada kami [Abu Nu'man 'Arim bin Al Fadl] telah menceritakan kepada kami [Abdul Wahid] -yaitu Ibnu Ziyad- telah menceritakan kepada kami ['Ashim Al Ahwal] dari [As Sya'bi] telah menceritakan kepadaku [Al Barra` bin 'Azib] dia berkata, \"Rasulullah shallallahu 'alaihi wasallam pernah berkhutbah pada hari Iedul Adlha, sabdanya: \"Janganlah salah seorang dari kalian menyembelih hewan kurban hingga selesai shalat (ied).\" Lantas seorang laki-laki berkata, \"Saya memiliki kambing dewasa yang lebih bagus dari pada dua ekor kambing biasa.\" Beliau bersabda: \"Berkurbanlah dengannya, dan setelahmu tidak boleh lagi seseorang berkurban dengan Jad'ah (kambing usia enam bulan sampai satu tahun).\""},"3383":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا مُحَمَّدٌ يَعْنِي ابْنَ جَعْفَرٍ حَدَّثَنَا شُعْبَةُ عَنْ سَلَمَةَ عَنْ أَبِي جُحَيْفَةَ عَنْ الْبَرَاءِ بْنِ عَازِبٍ قَالَذَبَحَ أَبُو بُرْدَةَ قَبْلَ الصَّلَاةِ فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَبْدِلْهَا فَقَالَ يَا رَسُولَ اللَّهِ لَيْسَ عِنْدِي إِلَّا جَذَعَةٌ قَالَ شُعْبَةُ وَأَظُنُّهُ قَالَ وَهِيَ خَيْرٌ مِنْ مُسِنَّةٍ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ اجْعَلْهَا مَكَانَهَا وَلَنْ تَجْزِيَ عَنْ أَحَدٍ بَعْدَكَو حَدَّثَنَاه ابْنُ الْمُثَنَّى حَدَّثَنِي وَهْبُ بْنُ جَرِيرٍ ح و حَدَّثَنَا إِسْحَقُ بْنُ إِبْرَاهِيمَ أَخْبَرَنَا أَبُو عَامِرٍ الْعَقَدِيُّ حَدَّثَنَا شُعْبَةُ بِهَذَا الْإِسْنَادِ وَلَمْ يَذْكُرْ الشَّكَّ فِي قَوْلِهِ هِيَ خَيْرٌ مِنْ مُسِنَّةٍ","id":"Telah menceritakan kepada kami [Muhammad bin Basyar] telah menceritakan kepada kami [Muhammad] -yaitu Ibnu Ja'far- telah menceritakan kepada kami [Syu'bah] dari [Salamah] dari [Abu Juhaifah] dari [Al Barra` bin 'Azib] dia berkata, \"Abu Burdah pernah menyembelih hewan kurban sebelum shalat (Ied), lantas Nabi shallallahu 'alaihi wasallam bersabda: \"Gantilah (berkurbanlah lagi).\" Dia berkata, \"Wahai Rasulullah, saya tidak memiliki lagi selain Jad'ah (kambing usia enam bulan sampai setahun)!\" Syu'bah berkata, \"Menurutku dia juga mengatakan: \"Dan dia lebih bagus daripada musinnah (kambing usia satu tahun lebih).\" Lantas Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sembelihlah ia sebagai ganti (dari kurbanmu), dan tidak boleh untuk orang setelahmu.\" Dan telah menceritakan kepada kami [Ibnu Al Mutsanna] telah menceritakan kepadaku [Wahb bin Jarir]. (dalam jalur lain disebutkan) Telah menceritakan kepada kami [Ishaq bin Ibrahim] telah mengabarkan kepada kami [Abu 'Amir Al 'Aqadi] telah menceritakan kepada kami [Syu'bah] dengan isnad ini, namun dia tidak menyebutkan akan adanya keraguan dalam perkataannya yaitu, \"Ia lebih baik daripada musinnah (kambing yang berusia satu tahun lebih).\""},"3384":{"ar":"و حَدَّثَنِي يَحْيَى بْنُ أَيُّوبَ وَعَمْرٌو النَّاقِدُ وَزُهَيْرُ بْنُ حَرْبٍ جَمِيعًا عَنْ ابْنِ عُلَيَّةَ وَاللَّفْظُ لِعَمْرٍو قَالَ حَدَّثَنَا إِسْمَعِيلُ بْنُ إِبْرَاهِيمَ عَنْ أَيُّوبَ عَنْ مُحَمَّدٍ عَنْ أَنَسٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَوْمَ النَّحْرِ مَنْ كَانَ ذَبَحَ قَبْلَ الصَّلَاةِ فَلْيُعِدْ فَقَامَ رَجُلٌ فَقَالَ يَا رَسُولَ اللَّهِ هَذَا يَوْمٌ يُشْتَهَى فِيهِ اللَّحْمُ وَذَكَرَ هَنَةً مِنْ جِيرَانِهِ كَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ صَدَّقَهُ قَالَ وَعِنْدِي جَذَعَةٌ هِيَ أَحَبُّ إِلَيَّ مِنْ شَاتَيْ لَحْمٍ أَفَأَذْبَحُهَا قَالَ فَرَخَّصَ لَهُ فَقَالَ لَا أَدْرِي أَبَلَغَتْ رُخْصَتُهُ مَنْ سِوَاهُ أَمْ لَا قَالَ وَانْكَفَأَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِلَى كَبْشَيْنِ فَذَبَحَهُمَا فَقَامَ النَّاسُ إِلَى غُنَيْمَةٍ فَتَوَزَّعُوهَا أَوْ قَالَ فَتَجَزَّعُوهَاحَدَّثَنَا مُحَمَّدُ بْنُ عُبَيْدٍ الْغُبَرِيُّ حَدَّثَنَا حَمَّادُ بْنُ زَيْدٍ حَدَّثَنَا أَيُّوبُ وَهِشَامٌ عَنْ مُحَمَّدٍ عَنْ أَنَسِ بْنِ مَالِكٍ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ صَلَّى ثُمَّ خَطَبَ فَأَمَرَ مَنْ كَانَ ذَبَحَ قَبْلَ الصَّلَاةِ أَنْ يُعِيدَ ذِبْحًا ثُمَّ ذَكَرَ بِمِثْلِ حَدِيثِ ابْنِ عُلَيَّةَ و حَدَّثَنِي زِيَادُ بْنُ يَحْيَى الْحَسَّانِيُّ حَدَّثَنَا حَاتِمٌ يَعْنِي ابْنَ وَرْدَانَ حَدَّثَنَا أَيُّوبُ عَنْ مُحَمَّدِ بْنِ سِيرِينَ عَنْ أَنَسِ بْنِ مَالِكٍ قَالَ خَطَبَنَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَوْمَ أَضْحًى قَالَ فَوَجَدَ رِيحَ لَحْمٍ فَنَهَاهُمْ أَنْ يَذْبَحُوا قَالَ مَنْ كَانَ ضَحَّى فَلْيُعِدْ ثُمَّ ذَكَرَ بِمِثْلِ حَدِيثِهِمَا","id":"Dan telah menceritakan kepadaku [Yahya bin Ayyub] dan ['Amru An Naqid] serta [Zuhair bin Harb] semuanya dari [Ibnu 'Ulayyah] sedangkan lafadznya dari Amru, dia berkata; telah menceritakan kepada kami [Isma'il bin Ibrahim] dari [Ayyub] dari [Muhammad] dari [Anas] dia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda pada hari Iedul Adlha: \"Barangsiapa menyembelih hewan kurban sebelum shalat Ied, hendaknya ia mengulanginya lagi.\" Tiba-tiba seorang laki-laki berdiri seraya berkata, \"Wahai Rasulullah, bukannya ini adalah hari-hari dibagikannya daging kurban!\" Kemudian menyebutkan kebutuhan tetangganya akan daging, dan seakan Rasulullah shallallahu 'alaihi wasallam pun membenarkannya.\" Laki-laki itu berkata, \"Saya memiliki Jad'ah yang lebih saya sukai dari pada dua ekor kambing biasa, maka apakah saya harus menyembelihnya?\" Anas berkata, \"Maka beliau memberi keringanan kepadanya (untuk berkurban dengan Jad'ah).\" Anas berkata, \"Saya tidak tahu, apakah keringanan tersebut khusus untuk dirinya atau untuk yang lain juga.\" Anas berkata lagi, \"Kemudian Rasulullah shallallahu 'alaihi wasallam kembali menuju dua ekor kambing dan menyembelihnya, maka orang-orang sama mengambil kambingnya masing-masing, setelah itu mereka membagi-bagikan dagingnya.\" Telah menceritakan kepada kami [Muhammad bin 'Ubaid Al 'Ubari] telah menceritakan kepada kami [Hammad bin Zaid] telah menceritakan kepada kami [Ayyub] dan [Hisyam] dari [Muhammad] dari [Anas bin Malik], bahwa Rasulullah shallallahu 'alaihi wasallam shalat kemudian berkhutbah, lalu beliau memerintahkan bagi siapa yang telah berkurban sebelum shalat ied, untuk mengulangi kurbannya…kemudian dia menyebutkan seperti hadits Ibnu 'Ulayyah.\" Dan telah menceritakan kepadaku [Ziyad bin Yahya Al Hassani] telah menceritakan kepada kami [Hatim] -yaitu Ibnu Wardan- telah menceritakan kepada kami [Ayyub] dari [Muhammad bin Sirin] dari [Anas bin Malik] dia berkata, \"Ketika Rasulullah shallallahu 'alaihi wasallam sedang berkhutbah pada hari raya Adlha, tiba-tiba beliau mencium bau daging (yang baru disembelih), maka beliau melarang mereka untuk menyembelih terlebih dahulu, sabdanya: \"Barang siapa terlanjur berkurban, hendaknya ia mengulangi kurbannya..., kemudian dia menyebutkan seperti hadits keduanya.\" "},"3385":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ يُونُسَ حَدَّثَنَا زُهَيْرٌ حَدَّثَنَا أَبُو الزُّبَيْرِ عَنْ جَابِرٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا تَذْبَحُوا إِلَّا مُسِنَّةً إِلَّا أَنْ يَعْسُرَ عَلَيْكُمْ فَتَذْبَحُوا جَذَعَةً مِنْ الضَّأْنِ","id":"Telah menceritakan kepada kami [Ahmad bin Yunus] telah menceritakan kepada kami [Zuhair] telah menceritakan kepada kami [Abu Az Zubair] dari [Jabir] dia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Janganlah kamu sembelih hewan untuk berkurban, melainkan hewan yang telah dewasa (Musinnah). Jika itu sulit kamu peroleh, sebelihlah jadz'ah.\" "},"3386":{"ar":"و حَدَّثَنِي مُحَمَّدُ بْنُ حَاتِمٍ حَدَّثَنَا مُحَمَّدُ بْنُ بَكْرٍ أَخْبَرَنَا ابْنُ جُرَيْجٍ أَخْبَرَنِي أَبُو الزُّبَيْرِ أَنَّهُ سَمِعَ جَابِرَ بْنَ عَبْدِ اللَّهِ يَقُولُاصَلَّى بِنَا النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَوْمَ النَّحْرِ بِالْمَدِينَةِ فَتَقَدَّمَ رِجَالٌ فَنَحَرُوا وَظَنُّوا أَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَدْ نَحَرَ فَأَمَرَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ كَانَ نَحَرَ قَبْلَهُ أَنْ يُعِيدَ بِنَحْرٍ آخَرَ وَلَا يَنْحَرُوا حَتَّى يَنْحَرَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Dan telah menceritakan kepadaku [Muhammad bin Hatim] telah menceritakan kepada kami [Muhammad bin Bakar] telah mengabarkan kepada kami [Ibnu Juraij] telah mengabarkan kepadaku [Abu Az Zubair] bahwa dia mendengar [Jabir bin Abdullah] berkata, \"Nabi shallallahu 'alaihi wasallam pernah shalat Iedul Adlha bersama kami di Madinah, lalu para laki-laki menyembelih (hewan kurban), sebab mereka menyangka bahwa Nabi shallallahu 'alaihi wasallam telah menyembelih (hewan kurban). Nabi shallallahu 'alaihi wasallam kemudian memerintahkan bagi mereka yang telah menyembelih sebelum shalat untuk mengulangi kurbannya, dan mereka tidak menyembelihnya hingga Nabi shallallahu 'alaihi wasallam menyembelihnya terlebih dahulu.\""},"3387":{"ar":"و حَدَّثَنَا قُتَيْبَةُ بْنُ سَعِيدٍ حَدَّثَنَا لَيْثٌ ح و حَدَّثَنَا مُحَمَّدُ بْنُ رُمْحٍ أَخْبَرَنَا اللَّيْثُ عَنْ يَزِيدَ بْنِ أَبِى حَبِيبٍ عَنْ أَبِي الْخَيْرِ عَنْ عُقْبَةَ بْنِ عَامِرٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَعْطَاهُ غَنَمًا يَقْسِمُهَا عَلَى أَصْحَابِهِ ضَحَايَا فَبَقِيَ عَتُودٌ فَذَكَرَهُ لِرَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ ضَحِّ بِهِ أَنْتَ قَالَ قُتَيْبَةُ عَلَى صَحَابَتِهِ","id":"Dan telah menceritakan kepada kami [Qutaibah bin Sa'id] telah menceritakan kepada kami [Laits]. (dalam jalur lain disebtkan) Telah menceritakan kepada kami [Muhammad bin Rumh] telah mengabarkan kepada kami [Al Laits] dari [Yazid bin Abu Habib] dari [Abu Al Khair] dari ['Uqbah bin 'Amir], bahwa Rasulullah shallallahu 'alaihi wasallam pernah memberikan kambing kepadanya supaya dia membagikannya kepada para sahabatnya. Setelah itu tidak ada yang tersisa melainkan seekor kambing yang masih muda, lantas dia memberitahukannya kepada Rasulullah shallallahu 'alaihi wasallam, beliau bersabda: \"Berkurbanlah dengannya.\" Qutaibah menyebutkan, \"Atas para sahabatnya.\""},"3388":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا يَزِيدُ بْنُ هَارُونَ عَنْ هِشَامٍ الدَّسْتَوَائِيِّ عَنْ يَحْيَى بْنِ أَبِي كَثِيرٍ عَنْ بَعْجَةَ الْجُهَنِيِّ عَنْ عُقْبَةَ بْنِ عَامِرٍ الْجُهَنِيِّ قَالَقَسَمَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِينَا ضَحَايَا فَأَصَابَنِي جَذَعٌ فَقُلْتُ يَا رَسُولَ اللَّهِ إِنَّهُ أَصَابَنِي جَذَعٌ فَقَالَ ضَحِّ بِهِو حَدَّثَنِي عَبْدُ اللَّهِ بْنُ عَبْدِ الرَّحْمَنِ الدَّارِمِيُّ حَدَّثَنَا يَحْيَى يَعْنِي ابْنَ حَسَّانَ أَخْبَرَنَا مُعَاوِيَةُ وَهُوَ ابْنُ سَلَّامٍ حَدَّثَنِي يَحْيَى بْنُ أَبِي كَثِيرٍ أَخْبَرَنِي بَعْجَةُ بْنُ عَبْدِ اللَّهِ أَنَّ عُقْبَةَ بْنَ عَامِرٍ الْجُهَنِيَّ أَخْبَرَهُ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَسَمَ ضَحَايَا بَيْنَ أَصْحَابِهِ بِمِثْلِ مَعْنَاهُ","id":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] telah menceritakan kepada kami [Yazid bin Harun] dari [Hisyam Ad Datawa`i] dari [Yahya bin Abu Katsir] dari [Ba'jah Al Juhani] dari ['Uqbah bin 'Amir Al Juhani] dia berkata, \"Rasulullah shallallahu 'alaihi wasallam pernah membagi-bagikan hewan kurban kepada kami. Saya mendapat seekor kambing muda. Lalu kukatakan kepada Rasulullah shallallahu 'alaihi wasallam, \"Wahai Rasulullah, saya mendapat kambing muda!\" Beliau bersabda: \"Berkurbanlah dengan itu!\" Dan telah menceritakan kepadaku [Abdullah bin Abdurrahman Ad Darimi] telah menceritakan kepada kami [Yahya] -yaitu Ibnu Hasan- telah mengabarkan kepada kami [Mu'awiyah] -yaitu Ibnu Sallam- telah menceritakan kepadaku [Yahya bin Abu Katsir] telah mengabarkan kepadaku [Ba'jah bin Abdullah] bahwa ['Uqbah bin 'Amir Al Juhani] mengabarkan kepadanya, bahwa Rasulullah shallallahu 'alaihi wasallam pernah membagi-bagikan hewan kurban untuk para sahabatnya, sebagaimana makna hadits di atas.\""},"3389":{"ar":"حَدَّثَنَا قُتَيْبَةُ بْنُ سَعِيدٍ حَدَّثَنَا أَبُو عَوَانَةَ عَنْ قَتَادَةَ عَنْ أَنَسٍ قَالَضَحَّى النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِكَبْشَيْنِ أَمْلَحَيْنِ أَقْرَنَيْنِ ذَبَحَهُمَا بِيَدِهِ وَسَمَّى وَكَبَّرَ وَوَضَعَ رِجْلَهُ عَلَى صِفَاحِهِمَا","id":"Telah menceritakan kepada kami [Qutaibah bin Sa'id] telah menceritakan kepada kami [Abu 'Awanah] dari [Qatadah] dari [Anas] dia berkata; Nabi shallallahu 'alaihi wasallam pernah berkurban dengan dua domba putih yang bertanduk, beliau menyembelih dengan tangannya sendiri sambil menyebut (nama Allah) dan bertakbir, dengan meletakkan kaki beliau dekat pangkal leher domba tersebut.\""},"3390":{"ar":"حَدَّثَنَا يَحْيَى بْنُ يَحْيَى أَخْبَرَنَا وَكِيعٌ عَنْ شُعْبَةَ عَنْ قَتَادَةَ عَنْ أَنَسٍ قَالَضَحَّى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِكَبْشَيْنِ أَمْلَحَيْنِ أَقْرَنَيْنِ قَالَ وَرَأَيْتُهُ يَذْبَحُهُمَا بِيَدِهِ وَرَأَيْتُهُ وَاضِعًا قَدَمَهُ عَلَى صِفَاحِهِمَا قَالَ وَسَمَّى وَكَبَّرَو حَدَّثَنَا يَحْيَى بْنُ حَبِيبٍ حَدَّثَنَا خَالِدٌ يَعْنِي ابْنَ الْحَارِثِ حَدَّثَنَا شُعْبَةُ أَخْبَرَنِي قَتَادَةُ قَالَ سَمِعْتُ أَنَسًا يَقُولُا ضَحَّى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِمِثْلِهِ قَالَ قُلْتُ آنْتَ سَمِعْتَهُ مِنْ أَنَسٍ قَالَ نَعَمْ حَدَّثَنَا مُحَمَّدُ بْنُ الْمُثَنَّى حَدَّثَنَا ابْنُ أَبِي عَدِيٍّ عَنْ سَعِيدٍ عَنْ قَتَادَةَ عَنْ أَنَسٍ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِمِثْلِهِ غَيْرَ أَنَّهُ قَالَ وَيَقُولُ بِاسْمِ اللَّهِ وَاللَّهُ أَكْبَرُ","id":"Telah menceritakan kepada kami [Yahya bin Yahya] telah mengabarkan kepada kami [Waki'] dari [Syu'bah] dari [Qatadah] dari [Anas] dia berkata, \"Rasulullah shallallahu 'alaihi wasallam pernah berkurban dua ekor domba putih yang bertanduk.\" Anas melanjutkan, \"Saya melihat beliau menyembelih keduanya dengan tangan beliau sendiri sambil membaca basmalah dan takbir, dan dengan menginjakkan kaki di pangkal leher domba itu.\" Dan telah menceritakan kepada kami [Yahya bin Habib] telah menceritakan kepada kami [Khalid] -yaitu Ibnu Al Harits- telah menceritakan kepada kami [Syu'bah] telah mengabarkan kepadaku [Qatadah] dia berkata; saya mendengar [Anas] berkata, \"Rasulullah shallallahu 'alaihi wasallam pernah berkurban...seperti hadits di atas.\" Syu'bah berkata, \"Lalu saya bertanya, \"Apakah kamu sendiri yang mendengar dari Anas?\" dia menjawab, \"Ya.\" Telah menceritakan kepada kami [Muhammad bin Al Mutsanna] telah menceritakan kepada kami [Ibnu Abu 'Adi] dari [Sa'id] dari [Qatadah] dari [Anas] dari Nabi shallallahu 'alaihi wasallam seperti hadits di atas, namun dia menyebutkan, \"Dengan mengucapkan bisimillah dan Allhu akbar.\""},"3391":{"ar":"حَدَّثَنَا هَارُونُ بْنُ مَعْرُوفٍ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ وَهْبٍ قَالَ قَالَ حَيْوَةُ أَخْبَرَنِي أَبُو صَخْرٍ عَنْ يَزِيدَ بْنِ قُسَيْطٍ عَنْ عُرْوَةَ بْنِ الزُّبَيْرِ عَنْ عَائِشَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَمَرَ بِكَبْشٍ أَقْرَنَ يَطَأُ فِي سَوَادٍ وَيَبْرُكُ فِي سَوَادٍ وَيَنْظُرُ فِي سَوَادٍ فَأُتِيَ بِهِ لِيُضَحِّيَ بِهِ فَقَالَ لَهَا يَا عَائِشَةُ هَلُمِّي الْمُدْيَةَ ثُمَّ قَالَ اشْحَذِيهَا بِحَجَرٍ فَفَعَلَتْ ثُمَّ أَخَذَهَا وَأَخَذَ الْكَبْشَ فَأَضْجَعَهُ ثُمَّ ذَبَحَهُ ثُمَّ قَالَ بِاسْمِ اللَّهِ اللَّهُمَّ تَقَبَّلْ مِنْ مُحَمَّدٍ وَآلِ مُحَمَّدٍ وَمِنْ أُمَّةِ مُحَمَّدٍ ثُمَّ ضَحَّى بِهِ","id":"Telah menceritakan kepada kami [Harun bin Ma'ruf] telah menceritakan kepada kami [Abdullah bin Wahb] dia berkata; [Haiwah] berkata; telah mengabarkan kepadaku [Abu Shahr] dari [Yazid in Qusaith] dari ['Urwah bin Zubair] dari ['Aisyah], bahwa Rasulullah shallallahu 'alaihi wasallam pernah menyuruh untuk diambilkan dua ekor domba bertanduk yang di kakinya berwarna hitam, perutnya terdapat belang hitam, dan di kedua matanya terdapat belang hitam. Kemudian domba tersebut di serahkan kepada beliau untuk dikurbankan, lalu beliau bersabda kepada 'Aisyah: \"Wahai 'Aisyah, bawalah pisau kemari.\" Kemudian beliau bersabda: \"Asahlah pisau ini dengan batu.\" Lantas 'Aisyah melakukan apa yang di perintahkan beliau, setelah di asah, beliau mengambilnya dan mengambil domba tersebut dan membaringkannya lalu beliau menyembelihnya.\" Kemudian beliau mengucapkan: \"Dengan nama Allah, ya Allah, terimalah ini dari Muhammad, keluarga Muhammad, dan ummat Muhammad.\" Kemudian beliau berkurban dengannya.\""},"3392":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ الْمُثَنَّى الْعَنَزِيُّ حَدَّثَنَا يَحْيَى بْنُ سَعِيدٍ عَنْ سُفْيَانَ حَدَّثَنِي أَبِي عَنْ عَبَايَةَ بْنِ رِفَاعَةَ بْنِ رَافِعِ بْنِ خَدِيجٍ عَنْ رَافِعِ بْنِ خَدِيجٍ قُلْتُيَا رَسُولَ اللَّهِ إِنَّا لَاقُو الْعَدُوِّ غَدًا وَلَيْسَتْ مَعَنَا مُدًى قَالَ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَعْجِلْ أَوْ أَرْنِي مَا أَنْهَرَ الدَّمَ وَذُكِرَ اسْمُ اللَّهِ فَكُلْ لَيْسَ السِّنَّ وَالظُّفُرَ وَسَأُحَدِّثُكَ أَمَّا السِّنُّ فَعَظْمٌ وَأَمَّا الظُّفُرُ فَمُدَى الْحَبَشَةِ قَالَ وَأَصَبْنَا نَهْبَ إِبِلٍ وَغَنَمٍ فَنَدَّ مِنْهَا بَعِيرٌ فَرَمَاهُ رَجُلٌ بِسَهْمٍ فَحَبَسَهُ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّ لِهَذِهِ الْإِبِلِ أَوَابِدَ كَأَوَابِدِ الْوَحْشِ فَإِذَا غَلَبَكُمْ مِنْهَا شَيْءٌ فَاصْنَعُوا بِهِ هَكَذَاو حَدَّثَنَا إِسْحَقُ بْنُ إِبْرَاهِيمَ أَخْبَرَنَا وَكِيعٌ حَدَّثَنَا سُفْيَانُ بْنُ سَعِيدِ بْنِ مَسْرُوقٍ عَنْ أَبِيهِ عَنْ عَبَايَةَ بْنِ رِفَاعَةَ بْنِ رَافِعِ بْنِ خَدِيجٍ عَنْ رَافِعِ بْنِ خَدِيجٍ قَالَ كُنَّا مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِذِي الْحُلَيْفَةِ مِنْ تِهَامَةَ فَأَصَبْنَا غَنَمًا وَإِبِلًا فَعَجِلَ الْقَوْمُ فَأَغْلَوْا بِهَا الْقُدُورَ فَأَمَرَ بِهَا فَكُفِئَتْ ثُمَّ عَدَلَ عَشْرًا مِنْ الْغَنَمِ بِجَزُورٍ وَذَكَرَ بَاقِيَ الْحَدِيثِ كَنَحْوِ حَدِيثِ يَحْيَى بْنِ سَعِيدٍ و حَدَّثَنَا ابْنُ أَبِي عُمَرَ حَدَّثَنَا سُفْيَانُ عَنْ إِسْمَعِيلَ بْنِ مُسْلِمٍ عَنْ سَعِيدِ بْنِ مَسْرُوقٍ عَنْ عَبَايَةَ عَنْ جَدِّهِ رَافِعٍ ثُمَّ حَدَّثَنِيهِ عُمَرُ بْنُ سَعِيدِ بْنِ مَسْرُوقٍ عَنْ أَبِيهِ عَنْ عَبَايَةَ بْنِ رِفَاعَةَ بْنِ رَافِعِ بْنِ خَدِيجٍ عَنْ جَدِّهِ قَالَ قُلْنَا يَا رَسُولَ اللَّهِ إِنَّا لَاقُو الْعَدُوِّ غَدًا وَلَيْسَ مَعَنَا مُدًى فَنُذَكِّي بِاللِّيطِ وَذَكَرَ الْحَدِيثَ بِقِصَّتِهِ وَقَالَ فَنَدَّ عَلَيْنَا بَعِيرٌ مِنْهَا فَرَمَيْنَاهُ بِالنَّبْلِ حَتَّى وَهَصْنَاهُ و حَدَّثَنِيهِ الْقَاسِمُ بْنُ زَكَرِيَّاءَ حَدَّثَنَا حُسَيْنُ بْنُ عَلِيٍّ عَنْ زَائِدَةَ عَنْ سَعِيدِ بْنِ مَسْرُوقٍ بِهَذَا الْإِسْنَادِ الْحَدِيثَ إِلَى آخِرِهِ بِتَمَامِهِ وَقَالَ فِيهِ وَلَيْسَتْ مَعَنَا مُدًى أَفَنَذْبَحُ بِالْقَصَبِ و حَدَّثَنَا مُحَمَّدُ بْنُ الْوَلِيدِ بْنِ عَبْدِ الْحَمِيدِ حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ حَدَّثَنَا شُعْبَةُ عَنْ سَعِيدِ بْنِ مَسْرُوقٍ عَنْ عَبَايَةَ بْنِ رِفَاعَةَ بْنِ رَافِعٍ عَنْ رَافِعِ بْنِ خَدِيجٍ أَنَّهُ قَالَ يَا رَسُولَ اللَّهِ إِنَّا لَاقُو الْعَدُوِّ غَدًا وَلَيْسَ مَعَنَا مُدًى وَسَاقَ الْحَدِيثَ وَلَمْ يَذْكُرْ فَعَجِلَ الْقَوْمُ فَأَغْلَوْا بِهَا الْقُدُورَ فَأَمَرَ بِهَا فَكُفِئَتْ وَذَكَرَ سَائِرَ الْقِصَّةِ","id":"Telah menceritakan kepada kami [Muhammad bin Al Mutsanna Al 'Anazi] telah menceritakan kepada kami [Yahya bin Sa'id] dari [Sufyan] telah menceritakan kepadaku [ayahku] dari ['Abayah bin Rifa'ah bin Rafi' bin Khadij] dari [Rafi' bin Khadij] ia berkata, \"Aku berkata kepada Rasulullah, 'Besok kita akan bertemu musuh, sementara kita tidak lagi mempunyai pisau tajam? ' Beliau menjawab: \"Sembelihlah dengan sesuatu yang dapat mengalirkan darah, sebutlah nama Allah lalu makanlah, kecuali dengan gigi dan kuku. Aku jelaskan kepada kalian; gigi itu sejenis tulang, sedangkan kuku adalah alat yang biasa digunakan oleh bangsa Habsyah (untuk menyembelih).\" Kami lalu mendapatkan rampasan unta dan kambing, saat ada salah satu unta tersebut yang kabur, maka seorang laki-laki melemparnya dengan anak panah, hingga dapat menangkapnya kembali. Maka Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sesungguhnya di antara unta-unta ini ada yang liar sebagaimana binatang buas, jika kalian merasa susah dibuatnya, maka lakukanlah seperti itu.\" Dan telah menceritakan kepada kami [Ishaq bin Ibrahim] telah mengabarkan kepada kami [Waki'] telah menceritakan kepada kami [Sufyan bin Sa'id bin Masruq] dari [ayahnya] dari ['Abayah bin Rifa'ah bin Rafi' bin Khadij] dari [Rafi' bin Khadij] dia berkata, \"Saya pernah bersama Rasulullah shallallahu 'alaihi wasallam ketika di Dzul Khulaifah, dari arah Tihamah, lalu kami mendapatkan rampasan kambing dan unta, maka orang-orang pun bersegera mendidihkan air dalam kuwali, namun beliau memerintahkan supaya kuwali tersebut ditumpahkan, kemudian beliau menjadikan sepuluh kambing setara dengan satu ekor unta...kemudian perawi menyebutkan sisa hadits tersebut sebagaimana hadits Yahya bin Sa'id.\" Dan telah menceritakan kepada kami [Ibnu Abu Umar] telah menceritakan kepada kami [Sufyan] dari [Isma'il bin Muslim] dari [Sa'id bin Masruq] dari ['Abayah] dari kakeknya [Rafi'] kemudian menceritakan kepadaku [Umar bin Sa'id bin Masruq] dari [Ayahnya] dari [Abayah bin Rifa'ah bin Rafi' bin Khadij] dari [Kakeknya] dia berkata, \"Kami berkata, \"Wahai Rasulullah, sesungguhnya esok hari kita akan bertemu musuh, sementara kami tidak memiliki pisau, maka kami menyembelihnya dengan dahan (yang tajam)...Kemudian ia menyebutkan hadits tersebut dengan kisahnya, ia menambahkan, \"Kemudian seekor unta kami kabur, kami pun langsung melesatkan anak panah hingga unta tersebut terjatuh.\" Dan telah menceritakan kepadaku [Al Qasim bin Zakaria] telah menceritakan kepada kami [Husain bin Ali] dari [Za`idah] dari [Sa'id bin Masruq] dengan sanad hadits ini hingga yang terakhir secara sempurna, ia menyebutkan dalam haditsnya, \"Sementara kami tidak memiliki pisau, apakah kami boleh menyembelihnya dengan kayu?\" Dan telah menceritakan kepada kami [Muhammad bin Al Walid bin Abdul hamid] telah menceritakan kepada kami [Muhammad bin Ja'far] telah menceritakan kepada kami [Syu'bah] dari [Sa'id bin Masruq] dari ['Abayah bin Rifa'ah bin Rafi'] dari [Rafi' bi Khadij] bahwa dia berkata, \"Wahai Rasulullah, sesungguhnya esok hari kita akan bertemu musuh, sementara kita tidak memiliki pisau (untuk menyembelih hewan sembelihan).... lalu ia menyebutkan hadits tersebut, namun ia tidak menyebutkan, \"Lalu para sahabat bersegera untuk mendidihkan air dalam kuwali, namun beliau memerintahkan supaya kuwali tersebut di tumpahkan...lalu ia menyebutkan semua kisah dalam hadits tersebut.\""},"3393":{"ar":"حَدَّثَنِي عَبْدُ الْجَبَّارِ بْنُ الْعَلَاءِ حَدَّثَنَا سُفْيَانُ حَدَّثَنَا الزُّهْرِيُّ عَنْ أَبِي عُبَيْدٍ قَالَشَهِدْتُ الْعِيدَ مَعَ عَلِيِّ بْنِ أَبِي طَالِبٍ فَبَدَأَ بِالصَّلَاةِ قَبْلَ الْخُطْبَةِ وَقَالَ إِنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَهَانَا أَنْ نَأْكُلَ مِنْ لُحُومِ نُسُكِنَا بَعْدَ ثَلَاثٍ","id":"Telah menceritakan kepadaku [Abdul Jabar bin Al 'Ala`] telah menceritakan kepada kami [Sufyan] telah menceritakan kepada kami [Az Zuhri] dari [Abu 'Ubaid] dia berkata, \"Saya pernah mengikuti shalat Iedul Adlha bersama [Ali bin Abu Thalib], dia memulai shalat terlebih dahulu sebelum khutbah seraya berkata, \"Sesungguhnya Rasulullah shallallahu 'alaihi wasallam melarang kita memakan daging kurban setelah tiga hari.\""},"3394":{"ar":"حَدَّثَنِي حَرْمَلَةُ بْنُ يَحْيَى أَخْبَرَنَا ابْنُ وَهْبٍ حَدَّثَنِي يُونُسُ عَنْ ابْنِ شِهَابٍ حَدَّثَنِي أَبُو عُبَيْدٍ مَوْلَى ابْنِ أَزْهَرَ أَنَّهُ شَهِدَ الْعِيدَ مَعَ عُمَرَ بْنِ الْخَطَّابِ قَالَ ثُمَّ صَلَّيْتُ مَعَ عَلِيِّ بْنِ أَبِي طَالِبٍ قَالَ فَصَلَّى لَنَا قَبْلَ الْخُطْبَةِ ثُمَّ خَطَبَ النَّاسَ فَقَالَإِنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَدْ نَهَاكُمْ أَنْ تَأْكُلُوا لُحُومَ نُسُكِكُمْ فَوْقَ ثَلَاثِ لَيَالٍ فَلَا تَأْكُلُواو حَدَّثَنِي زُهَيْرُ بْنُ حَرْبٍ حَدَّثَنَا يَعْقُوبُ بْنُ إِبْرَاهِيمَ حَدَّثَنَا ابْنُ أَخِي ابْنِ شِهَابٍ ح و حَدَّثَنَا حَسَنٌ الْحُلْوَانِيُّ حَدَّثَنَا يَعْقُوبُ بْنُ إِبْرَاهِيمَ حَدَّثَنَا أَبِي عَنْ صَالِحٍ ح و حَدَّثَنَا عَبْدُ بْنُ حُمَيْدٍ أَخْبَرَنَا عَبْدُ الرَّزَّاقِ أَخْبَرَنَا مَعْمَرٌ كُلُّهُمْ عَنْ الزُّهْرِيِّ بِهَذَا الْإِسْنَادِ مِثْلَهُ","id":"Telah menceritakan kepadaku [Harmalah bin Yahya] telah mengabarkan kepada kami [Ibnu Wahb] telah menceritakan kepadaku [Yunus] dari [Ibnu Syihab] telah menceritakan kepadaku [Abu 'Ubaid] bekas budak Ibnu Azhar, bahwa dia pernah menghadiri shalat 'Iedul Adlha bersama-sama Umar bin Khaththab.\" Abu Ubaid berkata, \"Aku juga pernah shalat bersama [Ali bin Abu Thalib], dia shalat sebelum khutbah. Setelah itu ia berkhutbah di hadapan orang-orang, \"Sesungguhnya Rasulullah shallallahu 'alaihi wasallam melarang kalian memakan daging kurban sesudah tiga hari, jika lebih dari tiga hari, maka janganlah kalian mamakannya.'\" Dan telah menceritakan kepadaku [Zuhair bin Harb] telah menceritakan kepada kami [Ya'qub bin Ibrahim] telah menceritakan kepada kami sepupuku [Ibnu Syihab]. (dalam jalur lain disebtkan) Telah menceritakan kepada kami [Hasan Al Khulwani] telah menceritakan kepada kami [Ya'qub bin Ibrahim] telah menceritakan kepada kami [ayahku] dari [Shalih]. (dalam jalur lain disebtkan) Telah menceritakan kepada kami [Abd bin Humaid] telah mengabarkan kepada kami [Abdurrazaq] telah mengabarkan kepada kami [Ma'mar] semuanya dari [Az Zuhri] dengan isnad seperti ini.\""},"3395":{"ar":"و حَدَّثَنَا قُتَيْبَةُ بْنُ سَعِيدٍ حَدَّثَنَا لَيْثٌ ح و حَدَّثَنِي مُحَمَّدُ بْنُ رُمْحٍ أَخْبَرَنَا اللَّيْثُ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهُ قَالَ لَا يَأْكُلْ أَحَدٌ مِنْ لَحْمِ أُضْحِيَّتِهِ فَوْقَ ثَلَاثَةِ أَيَّامٍو حَدَّثَنِي مُحَمَّدُ بْنُ حَاتِمٍ حَدَّثَنَا يَحْيَى بْنُ سَعِيدٍ عَنْ ابْنِ جُرَيْجٍ ح و حَدَّثَنِي مُحَمَّدُ بْنُ رَافِعٍ حَدَّثَنَا ابْنُ أَبِي فُدَيْكٍ أَخْبَرَنَا الضَّحَّاكُ يَعْنِي ابْنَ عُثْمَانَ كِلَاهُمَا عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِمِثْلِ حَدِيثِ اللَّيْثِ","id":"Dan telah menceritakan kepada kami [Qutaibah bin Sa'id] telah menceritakan kepada kami [Laits]. (dalam jalur lain disebtkan) Telah menceritakan kepadaku [Muhammad bin Rumh] telah mengabarkan kepada kami [Al Laits] dari [Nafi'] dari [Ibnu Umar] dari Nabi shallallahu 'alaihi wasallam, bahawa beliau bersabda: \"Janganlah salah seorang dari kalian memakan daging kurban setelah tiga hari.\" Dan telah menceritakan kepadaku [Muhammad bin Hatim] telah menceritakan kepada kami [Yahya bin Sa'id] dari [Ibnu Juraij]. (dalam jalur lain disebtkan) Telah menceritakan kepadaku [Muhammad bin Rafi'] telah menceritakan kepada kami [Ibnu Abu Fudaik] telah mengabarkan kepada kami [Adl Dlahak] -yaitu Ibnu Utsman- keduanya dari [Nafi'] dari [Ibnu Umar] dari Nabi shallallahu 'alaihi wasallam seperti hadits Laits.\""},"3396":{"ar":"حَدَّثَنَا إِسْحَقُ بْنُ إِبْرَاهِيمَ الْحَنْظَلِيُّ أَخْبَرَنَا رَوْحٌ حَدَّثَنَا مَالِكٌ عَنْ عَبْدِ اللَّهِ بْنِ أَبِي بَكْرٍ عَنْ عَبْدِ اللَّهِ بْنِ وَاقِدٍ قَالَنَهَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ أَكْلِ لُحُومِ الضَّحَايَا بَعْدَ ثَلَاثٍقَالَ عَبْدُ اللَّهِ بْنُ أ��بِي بَكْرٍ فَذَكَرْتُ ذَلِكَ لِعَمْرَةَ فَقَالَتْ صَدَقَ سَمِعْتُ عَائِشَةَ تَقُولُ دَفَّ أَهْلُ أَبْيَاتٍ مِنْ أَهْلِ الْبَادِيَةِ حَضْرَةَ الْأَضْحَى زَمَنَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ادَّخِرُوا ثَلَاثًا ثُمَّ تَصَدَّقُوا بِمَا بَقِيَ فَلَمَّا كَانَ بَعْدَ ذَلِكَ قَالُوا يَا رَسُولَ اللَّهِ إِنَّ النَّاسَ يَتَّخِذُونَ الْأَسْقِيَةَ مِنْ ضَحَايَاهُمْ وَيَجْمُلُونَ مِنْهَا الْوَدَكَ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَمَا ذَاكَ قَالُوا نَهَيْتَ أَنْ تُؤْكَلَ لُحُومُ الضَّحَايَا بَعْدَ ثَلَاثٍ فَقَالَ إِنَّمَا نَهَيْتُكُمْ مِنْ أَجْلِ الدَّافَّةِ الَّتِي دَفَّتْ فَكُلُوا وَادَّخِرُوا وَتَصَدَّقُوا","id":"Telah menceritakan kepada kami [Ishaq bin Ibrahim Al Hanzhali] telah mengabarkan kepada kami [Rauh] telah menceritakan kepada kami [Malik] dari [Abdullah bin Abu Bakar] dari [Abdullah bin Waqid] dia berkata, \"Rasulullah shallallahu 'alaihi wasallam melarang makan daging binatang kurban setelah tiga hari.\" [Abdullah bin Abu Bakar] berkata, \"kemudian saya memberitahukan hal itu kepada ['Amrah], lantas 'Amrah berkata, \"Dia benar, saya juga pernah mendengar ['Aisyah] berkata, \"Para penduduk kampung mempercepat langkahnya dan bersegera menghadiri iedul Adlha di zaman Rasulullah shallallahu 'alaihi wasallam, maka Rasulullah shallallahu 'alaihi wasallam bersabda: \"Simpanlah (daging kurban tersebut) hingga tiga hari, setelah itu sedekahkanlah yang masih tersisa.\" Setelah hal itu berlalu, orang-orang berkata, \"Wahai Rasulullah, sesungguhnya orang-orang memanfaatkan dari kurban, mereka mencairkan lemaknya dan darinya mereka membuat geriba.\" Beliau bersabda: \"Ada apa dengan hal itu?\" Mereka berkata, \"Engkau telah melarang memakan daging kurban setelah lewat tiga hari.\" Beliau bersabda: \"Sesungguhnya saya melarang sekelompok orang yang datang terburu-buru, oleh karena itu makan, simpan dan bersedekahlah.\""},"3397":{"ar":"حَدَّثَنَا يَحْيَى بْنُ يَحْيَى قَالَ قَرَأْتُ عَلَى مَالِكٍ عَنْ أَبِي الزُّبَيْرِ عَنْ جَابِرٍعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهُ نَهَى عَنْ أَكْلِ لُحُومِ الضَّحَايَا بَعْدَ ثَلَاثٍ ثُمَّ قَالَ بَعْدُ كُلُوا وَتَزَوَّدُوا وَادَّخِرُوا","id":"Telah menceritakan kepada kami [Yahya bin Yahya] dia berkata; saya bacakan di hadapan [Malik]; dari [Abu Az Zubair] dari [Jabir] dari Nabi shallallahu 'alaihi wasallam, bahwa beliau melarang makan daging kurban setelah tiga hari, kemudian beliau bersabda: \"Makan dan simpanlah sebagai perbekalan kalian.\""},"3398":{"ar":"حَدَّثَنَا إِسْحَقُ بْنُ إِبْرَاهِيمَ أَخْبَرَنَا زَكَرِيَّاءُ بْنُ عَدِيٍّ عَنْ عُبَيْدِ اللَّهِ بْنِ عَمْرٍو عَنْ زَيْدِ بْنِ أَبِي أُنَيْسَةَ عَنْ عَطَاءِ بْنِ أَبِي رَبَاحٍ عَنْ جَابِرِ بْنِ عَبْدِ اللَّهِ قَالَكُنَّا لَا نُمْسِكُ لُحُومَ الْأَضَاحِيِّ فَوْقَ ثَلَاثٍ فَأَمَرَنَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنْ نَتَزَوَّدَ مِنْهَا وَنَأْكُلَ مِنْهَا يَعْنِي فَوْقَ ثَلَاثٍو حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا سُفْيَانُ بْنُ عُيَيْنَةَ عَنْ عَمْرٍو عَنْ عَطَاءٍ عَنْ جَابِرٍ قَالَ كُنَّا نَتَزَوَّدُهَا إِلَى الْمَدِينَةِ عَلَى عَهْدِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah menceritakan kepada kami [Ishaq bin Ibrahim] telah mengabarkan kepada kami [Zakaria bin 'Adi] dari [Ubaidillah bin 'Amru] dari [Zaid bin Abu Unaisah] dari ['Atha bin Abu Rabah] dari [Jabir bin Abdullah] dia berkata, \"Kami tidak menyimpan daging kurban setelah tiga hari, lantas Rasulullah shallallahu 'alaihi wasallam memerintahkan kami untuk menyimpannya sebagai perbekalan, dan kami pun memakan daging tersebut setelah tiga hari.\" Dan telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] telah menceritakan kepada kami [Sufyan bin Uyainah] dari ['Amru] dari ['Atha] dari [Jabir] dia berkata, \"Kami menyimpannya untuk perbekalan ke Madinah pada masa Rasulullah shallallahu 'alaihi wasallam.\""},"3399":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا عَبْدُ الْأَعْلَى عَنْ الْجُرَيْرِيِّ عَنْ أَبِي نَضْرَةَ عَنْ أَبِي سَعِيدٍ الْخُدْرِيِّ ح و حَدَّثَنَا مُحَمَّدُ بْنُ الْمُثَنَّى حَدَّثَنَا عَبْدُ الْأَعْلَى حَدَّثَنَا سَعِيدٌ عَنْ قَتَادَةَ عَنْ أَبِي نَضْرَةَ عَنْ أَبِي سَعِيدٍ الْخُدْرِيِّ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَا أَهْلَ الْمَدِينَةِ لَا تَأْكُلُوا لُحُومَ الْأَضَاحِيِّ فَوْقَ ثَلَاثٍ و قَالَ ابْنُ الْمُثَنَّى ثَلَاثَةِ أَيَّامٍ فَشَكَوْا إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّ لَهُمْ عِيَالًا وَحَشَمًا وَخَدَمًا فَقَالَ كُلُوا وَأَطْعِمُوا وَاحْبِسُوا أَوْ ادَّخِرُوا قَالَ ابْنُ الْمُثَنَّى شَكَّ عَبْدُ الْأَعْلَى","id":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] telah menceritakan kepada kami [Abdul A'la] dari [Al Jurairi] darii [Abu Nadlrah] dari [Abu Sa'id Al Khudri]. (dalam jalur lain disebtkan) Telah menceritakan kepada kami [Muhammad bin Al Mutsanna] telah menceritakan kepada kami [Abdul A'la] telah menceritakan kepada kami [Sa'id] dari [Qatadah] dari [Abu Nadlrah] dari [Abu Sa'id Al Khudri] dia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Wahai penduduk Madinah, janganlah kalian memakan daging kurban setelah tiga.\" Ibnu Mutsanna menyebutkan, \"Setelah tiga hari.\" Lantas mereka mengadu kepada Rasulullah shallallahu 'alaihi wasallam bahwa mereka memiliki keluarga, para pembantu dan para pelayan.\" Beliau lalu bersabda: \"(Jika demikian) makan, berikan dan tahanlah, \" Atau, \"Simpanlah.\" Ibnu Mutsanna berkata, \"Abdul A'la merasa ragu.\""},"3400":{"ar":"حَدَّثَنَا إِسْحَقُ بْنُ مَنْصُورٍ أَخْبَرَنَا أَبُو عَاصِمٍ عَنْ يَزِيدَ بْنِ أَبِي عُبَيْدٍ عَنْ سَلَمَةَ بْنِ الْأَكْوَعِأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ ضَحَّى مِنْكُمْ فَلَا يُصْبِحَنَّ فِي بَيْتِهِ بَعْدَ ثَالِثَةٍ شَيْئًا فَلَمَّا كَانَ فِي الْعَامِ الْمُقْبِلِ قَالُوا يَا رَسُولَ اللَّهِ نَفْعَلُ كَمَا فَعَلْنَا عَامَ أَوَّلَ فَقَالَ لَا إِنَّ ذَاكَ عَامٌ كَانَ النَّاسُ فِيهِ بِجَهْدٍ فَأَرَدْتُ أَنْ يَفْشُوَ فِيهِمْ","id":"Telah menceritakan kepada kami [Ishaq bin Manshur] telah mengabarkan kepada kami [Abu 'Ashim] dari [Yazid bin Abu Ubaid] dari [Salamah bin Al Akwa'], bahwa Rasulullah shallallahu 'alaihi wasallam: \"Siapa dari kalian menyembelih kurban, maka hendaklah ia tidak menyisakan (menyimpan) di rumahnya setelah tiga hari.\" Pada tahun berikutnya mereka bertanya, \"Wahai Rasulullah, apakah kami mesti melakukan sebagaimana yang kami lakukan tahun lalu?\" Beliau menjawab: \"Tidak, sesungguhnya tahun lalu orang-orang berada dalam keadaan susah hingga saya menginginkan agar daging hewan kurban ini bisa merata dirasakan oleh mereka.\""},"3401":{"ar":"و حَدَّثَنِي إِسْحَقُ بْنُ مَنْصُورٍ أَخْبَرَنَا أَبُو مُسْهِرٍ حَدَّثَنَا يَحْيَى بْنُ حَمْزَةَ حَدَّثَنِي الزُّبَيْدِيُّ عَنْ عَبْدِ الرَّحْمَنِ بْنِ جُبَيْرِ بْنِ نُفَيْرٍ عَنْ أَبِيهِ عَنْ ثَوْبَانَ مَوْلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَقَالَ لِي رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي حَجَّةِ الْوَدَاعِ أَصْلِحْ هَذَا اللَّحْمَ قَالَ فَأَصْلَحْتُهُ فَلَمْ يَزَلْ يَأْكُلُ مِنْهُ حَتَّى بَلَغَ الْمَدِينَةَو حَدَّثَنِيهِ عَبْدُ اللَّهِ بْنُ عَبْدِ الرَّحْمَنِ الدَّارِمِيُّ أَخْبَرَنَا مُحَمَّدُ بْنُ الْمُبَارَكِ حَدَّثَنَا يَحْيَى بْنُ حَمْزَةَ بِهَذَا الْإِسْنَادِ وَلَمْ يَقُلْ فِي حَجَّةِ الْوَدَاعِ","id":"Dan telah menceritakan kepadaku [Ishaq bin Manshur] telah mengabarkan kepada kami [Abu Mushir] telah menceritakan kepada kami [Yahya bin Hamzah] telah menceritakan kepadaku [Az Zubaidi] dari [Abdurrahman bin Jubair bin Nufair] dari [ayahnya] dari [Tsauban] bekas budak Rasulullah shallallahu 'alaihi wasallam, dia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda kepadaku ketika haji Wada': \"Simpanlah daging ini untuk perbekalan.\" Tsauban berkata, \"Lalu saya pun menyimpannya sebagai perbekalan, dan beliau masih tetap memakan perbekalan tersebut hingga sampai tiba di Madinah.\" Dan telah menceritakan kepadaku [Abdullah bin Abdurrahman Ad Darimi] telah mengabarkan kepada kami [Muhammad bin Al Mubarak] telah menceritakan kepada kami [Yahya bin Hamzah] dengan isnad ini, hanya saja ia tidak menyebutkan, \"Ketika haji Wada'.\""},"3402":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ وَمُحَمَّدُ بْنُ الْمُثَنَّى قَالَا حَدَّثَنَا مُحَمَّدُ بْنُ فُضَيْلٍ قَالَ أَبُو بَكْرٍ عَنْ أَبِي سِنَانٍ و قَالَ ابْنُ الْمُثَنَّى عَنْ ضِرَارِ بْنِ مُرَّةَ عَنْ مُحَارِبٍ عَنْ ابْنِ بُرَيْدَةَ عَنْ أَبِيهِ ح و حَدَّثَنَا مُحَمَّدُ بْنُ عَبْدِ اللَّهِ بْنِ نُمَيْرٍ حَدَّثَنَا مُحَمَّدُ بْنُ فُضَيْلٍ حَدَّثَنَا ضِرَارُ بْنُ مُرَّةَ أَبُو سِنَانٍ عَنْ مُحَارِبِ بْنِ دِثَارٍ عَنْ عَبْدِ اللَّهِ بْنِ بُرَيْدَةَ عَنْ أَبِيهِ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَهَيْتُكُمْ عَنْ زِيَارَةِ الْقُبُورِ فَزُورُوهَا وَنَهَيْتُكُمْ عَنْ لُحُومِ الْأَضَاحِيِّ فَوْقَ ثَلَاثٍ فَأَمْسِكُوا مَا بَدَا لَكُمْ وَنَهَيْتُكُمْ عَنْ النَّبِيذِ إِلَّا فِي سِقَاءٍ فَاشْرَبُوا فِي الْأَسْقِيَةِ كُلِّهَا وَلَا تَشْرَبُوا مُسْكِرًاو حَدَّثَنِي حَجَّاجُ بْنُ الشَّاعِرِ حَدَّثَنَا الضَّحَّاكُ بْنُ مَخْلَدٍ عَنْ سُفْيَانَ عَنْ عَلْقَمَةَ بْنِ مَرْثَدٍ عَنْ ابْنِ بُرَيْدَةَ عَنْ أَبِيهِ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ كُنْتُ نَهَيْتُكُمْ فَذَكَرَ بِمَعْنَى حَدِيثِ أَبِي سِنَانٍ","id":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] dan [Muhammad bin Al Mutsanna] keduanya berkata; telah menceritakan kepada kami [Muhammad bin Fudlail], [Abu Bakar] berkata; dari [Abu Sinan], dan [Ibnu Al Mutsanna] berkata; dari [Dlirar bin Murrah] dari [Muharib] dari [Ibnu Buraidah] dari [ayahnya]. (dalam jalur lain disebutkan) Telah menceritakan kepada kami [Muhammad bin Abdullah bin Numair] telah menceritakan kepada kami [Muhammad bin Fudlail] telah menceritakan kepada kami [Dlirar bin Murrah Abu Sinan] dari [Muharib bin Ditsar] dari [Abdullah bin Buraidah] dari [ayahnya] dia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Aku pernah melarang kalian berziarah kubur, sekarang berziarahlah. Saya juga pernah melarang kalian makan daging kurban setelah tiga hari, sekarang simpanlah untuk keperluan kalian. Dan saya juga pernah melarang kalian meminum anggur kecuali jika dalam bejana minum, sekarang minumlah dalam semua bejana kalian, tetapi jangan sekali-kali kamu minum yang memabukkan.\" Dan telah menceritakan kepadaku [Hajjaj bin Sya'ir] telah menceritakan kepada kami [Adl Dlahak bin Makhlad] dari [Sufyan] dari ['Alqamah bin Martsad] dari [Ibnu Buraidah] dari [ayahnya] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Aku pernah melarang kalian…kemudian ia menyebutkan hadits Abu Sinan.\""},"3403":{"ar":"حَدَّثَنَا يَحْيَى بْنُ يَحْيَى التَّمِيمِيُّ وَأَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ وَعَمْرٌو النَّاقِدُ وَزُهَيْرُ بْنُ حَرْبٍ قَالَ يَحْيَى أَخْبَرَنَا و قَالَ الْآخَرُونَ حَدَّثَنَا سُفْيَانُ بْنُ عُيَيْنَةَ عَنْ الزُّهْرِيِّ عَنْ سَعِيدٍ عَنْ أَبِي هُرَيْرَةَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ح و حَدَّثَنِي مُحَمَّدُ بْنُ رَافِعٍ وَعَبْدُ بْنُ حُمَيْدٍ قَالَ عَبْدٌ أَخْبَرَنَا و قَالَ ابْنُ رَافِعٍ حَدَّثَنَا عَبْدُ الرَّزَّاقِ أَخْبَرَنَا مَعْمَرٌ عَنْ الزُّهْرِيِّ عَنْ ابْنِ الْمُسَيَّبِ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا فَرَعَ وَلَا عَتِيرَةَ زَادَ ابْنُ رَافِعٍ فِي رِوَايَتِهِ وَالْفَرَعُ أَوَّلُ النِّتَاجِ كَانَ يُنْتَجُ لَهُمْ فَيَذْبَحُونَهُ","id":"Telah menceritakan kepada kami [Yahya bin Yahya At Tamimi] dan [Abu Bakar bin Abu Syaibah] dan ['Amru An Naqid] dan [Zuhair bin Harb], Yahya berkata; telah mengabarkan kepada kami, dan yang lain mengatakan; telah menceritakan kepada kami [Sufyan bin 'Uyainah] dari [Az Zuhri] dari [Sa'id] dari [Abu Hurairah] dari Nabi shallallahu 'alaihi wasallam. (dalam jalur lain disebutkan) Telah menceritakan kepadaku [Muhammad bin Rafi'] dan [Abd bin Humaid], Abd berkata; telah mengabarkan kepada kami, dan Ibnu Rafi' berkata; telah menceritakan kepada kami [Abdurrazaq] telah mengabarkan kepada kami [Ma'mar] dari [Az Zuhri] dari [Ibnu Musayyab] dari [Abu Hurairah] dia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tidak ada fara' dan Atirah.\" Ibnu Rafi' menambahkan dalam riwayatnya, \"Fara' adalah anak unta yang pertama kali dilahirkan yang disembelih untuk sesembahan.\" "},"3404":{"ar":"حَدَّثَنَا ابْنُ أَبِي عُمَرَ الْمَكِّيُّ حَدَّثَنَا سُفْيَانُ عَنْ عَبْدِ الرَّحْمَنِ بْنِ حُمَيْدِ بْنِ عَبْدِ الرَّحْمَنِ بْنِ عَوْفٍ سَمِعَ سَعِيدَ بْنَ الْمُسَيَّبِ يُحَدِّثُ عَنْ أُمِّ سَلَمَةَأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِذَا دَخَلَتْ الْعَشْرُ وَأَرَادَ أَحَدُكُمْ أَنْ يُضَحِّيَ فَلَا يَمَسَّ مِنْ شَعَرِهِ وَبَشَرِهِ شَيْئًاقِيلَ لِسُفْيَانَ فَإِنَّ بَعْضَهُمْ لَا يَرْفَعُهُ قَالَ لَكِنِّي أَرْفَعُهُ","id":"Telah menceritakan kepada kami [Ibnu Abu Umar Al Makki] telah menceritakan kepada kami [Sufyan] dari [Abdurrahman bin Humaid bin Abdurrahman bin 'Auf] bahwa dia mendengar [Sa'id bin Musayyab] menceritakan dari [Ummu Salamah] bahwa Nabi shallallahu 'alaihi wasallam bersabda: \"Jika telah tiba sepuluh (dzul Hijjah) dan salah seorang dari kalian hendak berkurban, maka janganlah mencukur rambut atau memotong kuku sedikitpun.\" Dikatakan kepada [Sufyan], \"Sebagian orang tidak memarfu'kan (hadits ini)?\" Sufyan menjawab, \"Akan tetapi saya memarfu'kannya.\""},"3405":{"ar":"و حَدَّثَنَاه إِسْحَقُ بْنُ إِبْرَاهِيمَ أَخْبَرَنَا سُفْيَانُ حَدَّثَنِي عَبْدُ الرَّحْمَنِ بْنُ حُمَيْدِ بْنِ عَبْدِ الرَّحْمَنِ بْنِ عَوْفٍ عَنْ سَعِيدِ بْنِ الْمُسَيَّبِ عَنْ أُمِّ سَلَمَةَ تَرْفَعُهُقَالَ إِذَا دَخَلَ الْعَشْرُ وَعِنْدَهُ أُضْحِيَّةٌ يُرِيدُ أَنْ يُضَحِّيَ فَلَا يَأْخُذَنَّ شَعْرًا وَلَا يَقْلِمَنَّ ظُفُرًا","id":"Dan telah menceritakan kepada kami [Ishaq bin Ibrahim] telah mengabarkan kepada kami [Sufyan] telah menceritakan kepadaku [Abdurrahman bin Humaid bin Abdurrahman bin 'Auf] dari [Sa'id bin Musayyab] dari [Ummu Salamah] dan dimarfu'kan kepada Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Jika (Salah seorang) telah masuk sepuluh (Dzul Hijjah), sedangkan ia memiliki hewan kurban yang hendak dikurbankan, maka jangan sekali-kali ia mencukur rambut atau memotong kuku.\""},"3406":{"ar":"و حَدَّثَنِي حَجَّاجُ بْنُ الشَّاعِرِ حَدَّثَنِي يَحْيَى بْنُ كَثِيرٍ الْعَنْبَرِيُّ أَبُو غَسَّانَ حَدَّثَنَا شُعْبَةُ عَنْ مَالِكِ بْنِ أَنَسٍ عَنْ عُمَرَ بْنِ مُسْلِمٍ عَنْ سَعِيدِ بْنِ الْمُسَيَّبِ عَنْ أُمِّ سَلَمَةَأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِذَا رَأَيْتُمْ هِلَالَ ذِي الْحِجَّةِ وَأَرَادَ أَحَدُكُمْ أَنْ يُضَحِّيَ فَلْيُمْسِكْ عَنْ شَعْرِهِ وَأَظْفَارِهِو حَدَّثَنَا أَحْمَدُ بْنُ عَبْدِ اللَّهِ بْنِ الْحَكَمِ الْهَاشِمِيُّ حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ حَدَّثَنَا شُعْبَةُ عَنْ مَالِكِ بْنِ أَنَسٍ عَنْ عُمَرَ أَوْ عَمْرِو بْنِ مُسْلِمٍ بِهَذَا الْإِسْنَادِ نَحْوَهُ","id":"Dan telah menceritakan kepadaku [Hajjaj bin Sya'ir] telah menceritakan kepadaku [Yahya bin Katsir Al 'Anbari Abu Ghassan] telah menceritakan kepada kami [Syu'bah] dari [Malik bin Anas] dari [Umar bin Muslim] dari [Sa'id bin Musayyab] dari [Ummu Salamah] bahwa Nabi shallallahu 'alaihi wasallam bersabda: \"Jika kalian telah melihat hilal sepuluh Dzul Hijjah, dan salah seorang dari kalian hendak berkurban, hendaknya ia tidak mencukur rambut dan tidak memotong kuku terlebih dahulu.\" Dan telah menceritakan kepada kami [Ahmad bin Abdullah bin Al Hakam Al Hasyimi] telah menceritakan kepada kami [Muhammad bin Ja'far] telah menceritakan kepada kami [Syu'bah] dari [Malik bin Anas] dari [Umar] atau 'Amru bin Muslim dengan sanad ini, seperti hadits tersebut.\""},"3407":{"ar":"و حَدَّثَنِي عُبَيْدُ اللَّهِ بْنُ مُعَاذٍ الْعَنْبَرِيُّ حَدَّثَنَا أَبِي حَدَّثَنَا مُحَمَّدُ بْنُ عَمْرٍو اللَّيْثِيُّ عَنْ عُمَرَ بْنِ مُسْلِمِ بْنِ عَمَّارِ بْنِ أُكَيْمَةَ اللَّيْثِيِّ قَالَ سَمِعْتُ سَعِيدَ بْنَ الْمُسَيَّبِ يَقُولُ سَمِعْتُ أُمَّ سَلَمَةَ زَوْجَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ تَقُولُقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ كَانَ لَهُ ذِبْحٌ يَذْبَحُهُ فَإِذَا أُهِلَّ هِلَالُ ذِي الْحِجَّةِ فَلَا يَأْخُذَنَّ مِنْ شَعْرِهِ وَلَا مِنْ أَظْفَارِهِ شَيْئًا حَتَّى يُضَحِّيَحَدَّثَنِي الْحَسَنُ بْنُ عَلِيٍّ الْحُلْوَانِيُّ حَدَّثَنَا أَبُو أُسَامَةَ حَدَّثَنِي مُحَمَّدُ بْنُ عَمْرٍو حَدَّثَنَا عَمْرُو بْنُ مُسْلِمِ بْنِ عَمَّارٍ اللَّيْثِيُّ قَالَ كُنَّا فِي الْحَمَّامِ قُبَيْلَ الْأَضْحَى فَاطَّلَى فِيهِ نَاسٌ فَقَالَ بَعْضُ أَهْلِ الْحَمَّامِ إِنَّ سَعِيدَ بْنَ الْمُسَيَّبِ يَكْرَهُ هَذَا أَوْ يَنْهَى عَنْهُ فَلَقِيتُ سَعِيدَ بْنَ الْمُسَيَّبِ فَذَكَرْتُ ذَلِكَ لَهُ فَقَالَ يَا ابْنَ أَخِي هَذَا حَدِيثٌ قَدْ نُسِيَ وَتُرِكَ حَدَّثَتْنِي أُمُّ سَلَمَةَ زَوْجُ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَتْ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِمَعْنَى حَدِيثِ مُعَاذٍ عَنْ مُحَمَّدِ بْنِ عَمْرٍو و حَدَّثَنِي حَرْمَلَةُ بْنُ يَحْيَى وَأَحْمَدُ بْنُ عَبْدِ الرَّحْمَنِ بْنِ أَخِي ابْنِ وَهْبٍ قَالَا حَدَّثَنَا عَبْدُ اللَّهِ بْنُ وَهْبٍ أَخْبَرَنِي حَيْوَةُ أَخْبَرَنِي خَالِدُ بْنُ يَزِيدَ عَنْ سَعِيدِ بْنِ أَبِي هِلَالٍ عَنْ عُمَرَ بْنِ مُسْلِمٍ الْجُنْدَعِيِّ أَنَّ ابْنَ الْمُسَيَّبِ أَخْبَرَهُ أَنَّ أُمَّ سَلَمَةَ زَوْجَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَخْبَرَتْهُ وَذَكَرَ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِمَعْنَى حَدِيثِهِمْ","id":"Dan telah menceritakan kepadaku [Ubaidullah bin Mu'adz Al 'Anbari] telah menceritakan kepada kami [ayahku] telah menceritakan kepada kami [Muhammad bin 'Amru Al Laitsi] dari [Umar bin Muslim bin 'Ammar bin Ukaimah Al Laitsi] dia berkata; saya mendengar [Sa'id bin Musayyab] berkata; saya mendengar [Ummu Salamah] isteri Nabi shallallahu 'alaihi wasallam berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa memiliki hewan kurban, hendaknya ia berkurban jika hilal sepuluh Dzul Hujjah telah terlihat jelas, janganlah ia mencukur rambut dan memotong kuku terlebih dahulu walau sedikit hingga ia selesai berkurban.\" Telah menceritakan kepadaku [Al Hasan bin Ali Al Khulwani] telah menceritakan kepada kami [Abu Usamah] telah menceritakan kepadaku [Muhammad bin 'Amru] telah menceritakan kepada kami ['Amru bin Muslim bin 'Ammar Al Laitsi] dia berkata, \"Kami pernah berada di tempat pemandian menjelang iedul adlha, sedangkan sebagian orang ada yang mencukur ketiaknya dengan pisau cukur, maka sebagian orang di tempat pemandian berkata, \"Sesungguhnya Sa'id bin Musayyab membenci hal itu, atau ia melarang hal itu.\" Lantas aku menemui Sa'id bin Musayyab dan memberitahukan hal itu kepadanya, ia menjawab, \"Wahai keponakanku, hadits ini telah dilupakan, atau ditinggalkan.\" Telah menceritakan kepadaku [Ummu Salamah], isteri Nabi shallallahu 'alaihi wasallam, dia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda semakna dengan hadits Mu'adz dari Muhammad bin 'Amru.\" Dan telah menceritakan kepadaku [Harmalah bin Yahya] dan [Ahmad bin Abdurrahman Akhi Ibnu Syihab] keduanya berkata; telah menceritakan kepada kami [Abdullah bin Wahb] telah mengabarkan kepadaku [Haiwah] telah mengabarkan kepadaku [Khalid bin Yazid] dari [Sa'id bin Abu Hilal] dari [Umar bin Muslim Al Junda'i] bahwa [Ibnu Musayyab] telah mengabarkan kepadanya, bahwa [Ummu Salamah] isteri Nabi shallallahu 'alaihi wasallam, telah mengabarkan kepadanya, lalu ia menyebutkan Nabi shallallahu 'alaihi wasallam semakna dengan hadits mereka.\""},"3408":{"ar":"حَدَّثَنَا زُهَيْرُ بْنُ حَرْبٍ وَسُرَيْجُ بْنُ يُونُسَ كِلَاهُمَا عَنْ مَرْوَانَ قَالَ زُهَيْرٌ حَدَّثَنَا مَرْوَانُ بْنُ مُعَاوِيَةَ الْفَزَارِيُّ حَدَّثَنَا مَنْصُورُ بْنُ حَيَّانَ حَدَّثَنَا أَبُو الطُّفَيْلِ عَامِرُ بْنُ وَاثِلَةَ قَالَكُنْتُ عِنْدَ عَلِيِّ بْنِ أَبِي طَالِبٍ فَأَتَاهُ رَجُلٌ فَقَالَ مَا كَانَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُسِرُّ إِلَيْكَ قَالَ فَغَضِبَ وَقَالَ مَا كَانَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُسِرُّ إِلَيَّ شَيْئًا يَكْتُمُهُ النَّاسَ غَيْرَ أَنَّهُ قَدْ حَدَّثَنِي بِكَلِمَاتٍ أَرْبَعٍ قَالَ فَقَالَ مَا هُنَّ يَا أَمِيرَ الْمُؤْمِنِينَ قَالَ قَالَ لَعَنَ اللَّهُ مَنْ لَعَنَ وَالِدَهُ وَلَعَنَ اللَّهُ مَنْ ذَبَحَ لِغَيْرِ اللَّهِ وَلَعَنَ اللَّهُ مَنْ آوَى مُحْدِثًا وَلَعَنَ اللَّهُ مَنْ غَيَّرَ مَنَارَ الْأَرْضِ","id":"Telah menceritakan kepada kami [Zuhair bin Harb] dan [Suraij bin Yunus] keduanya dari [Marwan], [Zuhair] berkata; telah menceritakan kepada kami [Marwan bin Mu'awiyah Al Fazari] telah menceritakan kepada kami [Manshur bin Hayyan] telah menceritakan kepada kami [Abu At Thufail 'Amir bin Wastilah] dia berkata, \"Saya berada di samping [Ali bin Abu Thalib], tiba-tiba seorang laki-laki datang menemuinya seraya berkata, \"Apakah Nabi shallallahu 'alaihi wasallam pernah menyampaikan suatu rahasia kepadamu (yang tidak diberitahukan kepada manusia)?\" Abu Thufail berkata, \"Ali pun marah seraya berkata, \"Tidaklah Nabi shallallahu 'alaihi wasallam menyampaikan suatu rahasia kepadaku dan tidak menyampaikannya kepada manusia, kecuali bahwa beliau pernah menyampaikan empat hal kepadaku.\" Abu Thufail berkata, \"Laki-laki tersebut bertanya, \"Apakah empat perkara itu wahai Amirul Mukminin?\" Abu Thufail melanjutkan, \"Ali lalu menjawab, \"Allah melaknat orang yang melaknat orang tuanya, melaknat orang yang menyembelih untuk selain Allah, melaknat orang yang menyembunyikan penjahat dan melaknat orang yang memindah batas tanah.\""},"3409":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا أَبُو خَالِدٍ الْأَحْمَرُ سُلَيْمَانُ بْنُ حَيَّانَ عَنْ مَنْصُورِ بْنِ حَيَّانَ عَنْ أَبِي الطُّفَيْلِ قَالَقُلْنَا لِعَلِيِّ بْنِ أَبِي طَالِبٍ أَخْبِرْنَا بِشَيْءٍ أَسَرَّهُ إِلَيْكَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ مَا أَسَرَّ إِلَيَّ شَيْئًا كَتَمَهُ النَّاسَ وَلَكِنِّي سَمِعْتُهُ يَقُولُ لَعَنَ اللَّهُ مَنْ ذَبَحَ لِغَيْرِ اللَّهِ وَلَعَنَ اللَّهُ مَنْ آوَى مُحْدِثًا وَلَعَنَ اللَّهُ مَنْ لَعَنَ وَالِدَيْهِ وَلَعَنَ اللَّهُ مَنْ غَيَّرَ الْمَنَارَ","id":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] telah menceritakan kepada kami [Abu Khalid Al Ahmar Sulaiman bin Hayyan] dari [Manshur bin Hayyan] dari [Abu At Thufail] dia berkata; saya berkata kepada [Ali bin Abu Thalib], \"Beritahukanlah kepadaku sesuatu yang pernah dirahasiakan Rasulullah shallallahu 'alaihi wasallam kepadamu!\" Ali menjawab, \"Beliau tidak pernah merahasiakan kepadaku sesuatu pun dari manusia, akan tetapi saya mendengar beliau bersabda: \"Allah mengutuk orang yang menyembelih untuk selain Allah, dan mengutuk orang yang melindungi tindak kejahatan, mengutuk orang yang mencaci kedua orang tuanya, dan mengutuk orang yang memindahkan tanda batas tanah.\""},"3410":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ الْمُثَنَّى وَمُحَمَّدُ بْنُ بَشَّارٍ وَاللَّفْظُ لِابْنِ الْمُثَنَّى قَالَا حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ حَدَّثَنَا شُعْبَةُ قَالَ سَمِعْتُ الْقَاسِمَ بْنَ أَبِي بَزَّةَ يُحَدِّثُ عَنْ أَبِي الطُّفَيْلِ قَالَسُئِلَ عَلِيٌّ أَخَصَّكُمْ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِشَيْءٍ فَقَالَ مَا خَصَّنَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِشَيْءٍ لَمْ يَعُمَّ بِهِ النَّاسَ كَافَّةً إِلَّا مَا كَانَ فِي قِرَابِ سَيْفِي هَذَا قَالَ فَأَخْرَجَ صَحِيفَةً مَكْتُوبٌ فِيهَا لَعَنَ اللَّهُ مَنْ ذَبَحَ لِغَيْرِ اللَّهِ وَلَعَنَ اللَّهُ مَنْ سَرَقَ مَنَارَ الْأَرْضِ وَلَعَنَ اللَّهُ مَنْ لَعَنَ وَالِدَهُ وَلَعَنَ اللَّهُ مَنْ آوَى مُحْدِثًا","id":"Telah menceritakan kepada kami [Muhammad bin Al Mutsanna] dan [Muhammad bin Basysyar] dan ini adalah lafadz Ibnu Mutsanna, keduanya berkata; telah menceritakan kepada kami [Muhammad bin Ja'far] telah menceritakan kepada kami [Syu'bah] dia berkata; saya mendengar [Al Qasim bin Abu Bazzah] menceritakan dari [Abu Thufail] dia berkata, \" [Ali] pernah ditanya, \"Apakah Rasulullah shallallahu 'alaihi wasallam merahasiakan kepadamu dengan sesuatu?\" dia menjawab, \"Rasulullah shallallahu 'alaihi wasallam tidak pernah merahasiakan sesuatu pun yang tidak diumumkan kepada manusia, kecuali mengenai sesuatu yang ada dalam sarung pedangku ini.\" Abu Thufail berkata, \"Kemudian Ali mengeluarkan lembaran yang bertuliskan: \"Allah mengutuk orang yang menyembelih untuk selain Allah, mengutuk orang yang memindah batas tanah, mengutuk orang yang mencaci maki orang tuanya dan mengutuk orang yang melindungi pelaku kejahatan.\""},"3411":{"ar":"حَدَّثَنَا يَحْيَى بْنُ يَحْيَى التَّمِيمِيُّ أَخْبَرَنَا حَجَّاجُ بْنُ مُحَمَّدٍ عَنْ ابْنِ جُرَيْجٍ حَدَّثَنِي ابْنُ شِهَابٍ عَنْ عَلِيِّ بْنِ حُسَيْنِ بْنِ عَلِيٍّ عَنْ أَبِيهِ حُسَيْنِ بْنِ عَلِيٍّ عَنْ عَلِيِّ بْنِ أَبِي طَالِبٍ قَالَأَصَبْتُ شَارِفًا مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي مَغْنَمٍ يَوْمَ بَدْرٍ وَأَعْطَانِي رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ شَارِفًا أُخْرَى فَأَنَخْتُهُمَا يَوْمًا عِنْدَ بَابِ رَجُلٍ مِنْ الْأَنْصَارِ وَأَنَا أُرِيدُ أَنْ أَحْمِلَ عَلَيْهِمَا إِذْخِرًا لِأَبِيعَهُ وَمَعِي صَائِغٌ مِنْ بَنِي قَيْنُقَاعَ فَأَسْتَع��ينَ بِهِ عَلَى وَلِيمَةِ فَاطِمَةَ وَحَمْزَةُ بْنُ عَبْدِ الْمُطَّلِبِ يَشْرَبُ فِي ذَلِكَ الْبَيْتِ مَعَهُ قَيْنَةٌ تُغَنِّيهِ فَقَالَتْ أَلَا يَا حَمْزُ لِلشُّرُفِ النِّوَاءِفَثَارَ إِلَيْهِمَا حَمْزَةُ بِالسَّيْفِ فَجَبَّ أَسْنِمَتَهُمَا وَبَقَرَ خَوَاصِرَهُمَا ثُمَّ أَخَذَ مِنْ أَكْبَادِهِمَا قُلْتُ لِابْنِ شِهَابٍ وَمِنْ السَّنَامِ قَالَ قَدْ جَبَّ أَسْنِمَتَهُمَا فَذَهَبَ بِهَا قَالَ ابْنُ شِهَابٍ قَالَ عَلِيٌّ فَنَظَرْتُ إِلَى مَنْظَرٍ أَفْظَعَنِي فَأَتَيْتُ نَبِيَّ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَعِنْدَهُ زَيْدُ بْنُ حَارِثَةَ فَأَخْبَرْتُهُ الْخَبَرَ فَخَرَجَ وَمَعَهُ زَيْدٌ وَانْطَلَقْتُ مَعَهُ فَدَخَلَ عَلَى حَمْزَةَ فَتَغَيَّظَ عَلَيْهِ فَرَفَعَ حَمْزَةُ بَصَرَهُ فَقَالَ هَلْ أَنْتُمْ إِلَّا عَبِيدٌ لِآبَائِي فَرَجَعَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُقَهْقِرُ حَتَّى خَرَجَ عَنْهُمْو حَدَّثَنَا عَبْدُ بْنُ حُمَيْدٍ أَخْبَرَنِي عَبْدُ الرَّزَّاقِ أَخْبَرَنِي ابْنُ جُرَيْجٍ بِهَذَا الْإِسْنَادِ مِثْلَهُ","id":"Telah menceritakan kepada kami [Yahya bin Yahya At Tamimi] telah mengabarkan kepada kami [Hajjaj bin Muhammad] dari [Ibnu Juraij] telah menceritakan kepadaku [Ibnu Syihab] dari [Ali bin Husain bin Ali] dari ayahnya [Husain bin Ali] dari [Ali bin Abu Thalib] dia berkata, \"Dahulu saya pernah mendapatkan satu ekor unta dari hasil rampasan perang Badr bersama Rasulullah shallallahu 'alaihi wasallam, lalu Rasulullah shallallahu 'alaihi wasallam menambahku lagi dengan satu ekor unta. Suatu hari saya menambatkan kedua hewan tersebut di depan pintu rumah milik orang Anshar, aku ingin membawa idzkhir dan meletakkannya di atas kedua punggung hewan tersebut untuk saya jual, sedangkan aku bersama seorang laki-laki penjual emas dari Bani Qainuqa`. Dan hasil dari penjualan itu akan aku pergunakan untuk menyelenggarakan pesta pernikahan Fatimah. Ternyata dalam rumah tersebut terdapat Hamzah bin Abdul Mutthalib sedang meminum minuman keras, dia sedang dihibur oleh seorang penyanyi perempuan yang dalam salah satu nyanyiannya terselip kata-kata, \"Wahai Hamzah, ingatlah pada unta-unta yang montok.\" Maka Hamzah pun berdiri dengan membawa pedang terhunus. Lalu dia memotong punuk kedua unta tersebut, lalu membelah perutnya dan mengambil hati yang ada di dalamnya.\" Saya lalu bertanya kepada Ibnu Syihab, \"Dan dua punuknya?\" dia menjawab, \"Dan dia telah memotong kedua punuk unta tersebut.\" Ibnu Syihab berkata, \"Ali berkata, \"Saya melihat pemandangan yang mengejutkan bagiku, lantas saya langsung mendatangi Nabi shallallahu 'alaihi wasallam, dan di samping beliau terdapat Zaid bin Haritsah. Lalu saya memberitahukan kepada beliau apa yang terjadi. Setelah itu beliau keluar bersama Zaid bin Tsabit, dan saya pun ikut bersama beliau. Kemudian beliau menemui Hamzah dan memarahinya. Ternyata Hamzah memandangi beliau sambil berkata, \"Kalian ini tidak lain hanyalah para budak bapakku.\" Akhirnya Rasulullah shallallahu 'alaihi wasallam kembali pulang dan meninggalkan mereka.\" Dan telah menceritakan kepada kami ['Abd bin Humaid] telah mengabarkan kepadaku [Abdurrazaq] telah mengabarkan kepadaku [Ibnu Juraij] dengan isnad seperti ini.\""},"3412":{"ar":"و حَدَّثَنِي أَبُو بَكْرِ بْنُ إِسْحَقَ أَخْبَرَنَا سَعِيدُ بْنُ كَثِيرِ بْنِ عُفَيْرٍ أَبُو عُثْمَانَ الْمِصْرِيُّ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ وَهْبٍ حَدَّثَنِي يُونُسُ بْنُ يَزِيدَ عَنْ ابْنِ شِهَابٍ أَخْبَرَنِي عَلِيُّ بْنُ حُسَيْنِ بْنِ عَلِيٍّ أَنَّ حُسَيْنَ بْنَ عَلِيٍّ أَخْبَرَهُ أَنَّ عَلِيًّا قَالَكَانَتْ لِي شَارِفٌ مِنْ نَصِيبِي مِنْ الْمَغْنَمِ يَوْمَ بَدْرٍ وَكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَعْطَانِي شَارِفًا مِنْ الْخُمُسِ يَوْمَئِذٍ فَلَمَّا أَرَدْتُ أَنْ أَبْتَنِيَ بِفَاطِمَةَ بِنْتِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَاعَدْتُ رَجُلًا صَوَّاغًا مِنْ بَنِي قَيْنُقَاعَ يَرْتَحِلُ مَعِيَ فَنَأْتِي بِإِذْخِرٍ أَرَدْتُ أَنْ أَبِيعَهُ مِنْ الصَّوَّاغِينَ فَأَسْتَعِينَ بِهِ فِي وَلِيمَةِ عُرْسِي فَبَيْنَا أَنَا أَجْمَعُ لِشَارِفَيَّ مَتَاعًا مِنْ الْأَقْتَابِ وَالْغَرَائِرِ وَالْحِبَالِ وَشَارِفَايَ مُنَاخَانِ إِلَى جَنْبِ حُجْرَةِ رَجُلٍ مِنْ الْأَنْصَارِ وَجَمَعْتُ حِينَ جَمَعْتُ مَا جَمَعْتُ فَإِذَا شَارِفَايَ قَدْ اجْتُبَّتْ أَسْنِمَتُهُمَا وَبُقِرَتْ خَوَاصِرُهُمَا وَأُخِذَ مِنْ أَكْبَادِهِمَا فَلَمْ أَمْلِكْ عَيْنَيَّ حِينَ رَأَيْتُ ذَلِكَ الْمَنْظَرَ مِنْهُمَا قُلْتُ مَنْ فَعَلَ هَذَا قَالُوا فَعَلَهُ حَمْزَةُ بْنُ عَبْدِ الْمُطَّلِبِ وَهُوَ فِي هَذَا الْبَيْتِ فِي شَرْبٍ مِنْ الْأَنْصَارِ غَنَّتْهُ قَيْنَةٌ وَأَصْحَابَهُ فَقَالَتْ فِي غِنَائِهَا أَلَا يَا حَمْزُ لِلشُّرُفِ النِّوَاءِفَقَامَ حَمْزَةُ بِالسَّيْفِ فَاجْتَبَّ أَسْنِمَتَهُمَا وَبَقَرَ خَوَاصِرَهُمَا فَأَخَذَ مِنْ أَكْبَادِهِمَا فَقَالَ عَلِيٌّ فَانْطَلَقْتُ حَتَّى أَدْخُلَ عَلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَعِنْدَهُ زَيْدُ بْنُ حَارِثَةَ قَالَ فَعَرَفَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي وَجْهِيَ الَّذِي لَقِيتُ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَا لَكَ قُلْتُ يَا رَسُولَ اللَّهِ وَاللَّهِ مَا رَأَيْتُ كَالْيَوْمِ قَطُّ عَدَا حَمْزَةُ عَلَى نَاقَتَيَّ فَاجْتَبَّ أَسْنِمَتَهُمَا وَبَقَرَ خَوَاصِرَهُمَا وَهَا هُوَ ذَا فِي بَيْتٍ مَعَهُ شَرْبٌ قَالَ فَدَعَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِرِدَائِهِ فَارْتَدَاهُ ثُمَّ انْطَلَقَ يَمْشِي وَاتَّبَعْتُهُ أَنَا وَزَيْدُ بْنُ حَارِثَةَ حَتَّى جَاءَ الْبَابَ الَّذِي فِيهِ حَمْزَةُ فَاسْتَأْذَنَ فَأَذِنُوا لَهُ فَإِذَا هُمْ شَرْبٌ فَطَفِقَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَلُومُ حَمْزَةَ فِيمَا فَعَلَ فَإِذَا حَمْزَةُ مُحْمَرَّةٌ عَيْنَاهُ فَنَظَرَ حَمْزَةُ إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ثُمَّ صَعَّدَ النَّظَرَ إِلَى رُكْبَتَيْهِ ثُمَّ صَعَّدَ النَّظَرَ فَنَظَرَ إِلَى سُرَّتِهِ ثُمَّ صَعَّدَ النَّظَرَ فَنَظَرَ إِلَى وَجْهِهِ فَقَالَ حَمْزَةُ وَهَلْ أَنْتُمْ إِلَّا عَبِيدٌ لِأَبِي فَعَرَفَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهُ ثَمِلٌ فَنَكَصَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَلَى عَقِبَيْهِ الْقَهْقَرَى وَخَرَجَ وَخَرَجْنَا مَعَهُو حَدَّثَنِيهِ مُحَمَّدُ بْنُ عَبْدِ اللَّهِ بْنِ قُهْزَاذَ حَدَّثَنِي عَبْدُ اللَّهِ بْنُ عُثْمَانَ عَنْ عَبْدِ اللَّهِ بْنِ الْمُبَارَكِ عَنْ يُونُسَ عَنْ الزُّهْرِيِّ بِهَذَا الْإِسْنَادِ مِثْلَهُ","id":"Dan telah menceritakan kepadaku [Abu Bakar bin Ishaq] telah mengabarkan kepada kami [Sa'id bin Katsir bin 'Ufair Abu Utsman Al Mishri] telah menceritakan kepada kami [Abdullah bin Wahb] telah menceritakan kepadaku [Yunus bin Yazid] dari [Ibnu Syihab] telah mengabarkan kepadaku ['Ali bin Husain bin Ali] bahwa [Husain bin Ali] mengabarkan kepadanya, bahwa [Ali] berkata, \"Dahulu saya pernah memiliki seekor unta dari hasil pembagian harta rampasan perang Badr, pada hari itu pula Rasulullah shallallahu 'alaihi wasallam memberikan seekor unta dari bagian seperlima. Ketika hendak membina rumah tangga dengan Fatimah -puteri Rasulullah shallallahu 'alaihi wasallam- saya telah mengikat janji dengan seorang tukang emas dari Bani Qainuqa' untuk pergi bersamaku sambil membawa idzkir (semacam tumbuhan) yang akan saya jual, dan uang hasil penjualan itu dapat saya pergunakan untuk penyelenggaraan pernikahan saya. Pada saat mempersiapkan barang-barang bagi keperluan kedua unta tersebut, seperti pelana, karung dan tali. Saat itu kedua unta saya terikat di samping rumah seorang Anshar, dan ternyata saya mendapati kedua unta saya -setelah mempersiapkan barang-barang yang perlu dipersiapkan- sudah terpotong punuknya, terbelah perutnya dan telah terambil hatinya. Kedua mataku tidak kuasa melihat pemandangan itu, lalu saya bertanya, \"Siapakah yang melakukan semua ini?\" orang-orang menjawab, \"Hamzah bin Abdul Mutthalib, dan dia sekarang berada di rumah ini bersama-sama dengan orang-orang Anshar yang suka meminum minuman keras. Dia dan teman-temannya sedang dihibur oleh seorang penyanyi perempuan yang dalam salah satu nyanyiannya terselip kata-kata, 'Wahai Hamzah, ingatlah pada unta-unta yang montok.' Maka Hamzah pun berdiri dengan membawa pedang terhunus. Lalu dia memotong punuk kedua unta tersebut dan ia belah perut keduanya kemudian hati keduanya di ambil.\" Ali berkata, \"Kemudian saya langsung pergi menemui Rasulullah shallallahu 'alaihi wasallam yang pada saat itu beliau sedang duduk bersama Zaid bin Haritsah.\" Ali berkata, \"Melihat raut mukaku, ternyata Rasulullah shallallahu 'alaihi wasallam tahu akan peristiwa yang terjadi.\" Maka Rasulullah shallallahu 'alaihi wasallam bertanya: \"Apa yang terjadi denganmu?\" saya menjawab, \"Wahai Rasulullah, demi Allah belum pernah seumur hidupku melihat kejadian seperti hari ini. Hamzah telah menyerang kedua untaku, dia telah memotong punuknya dan membelah isi perutnya. Sekarang dia berada di rumah bersama teman-temannya yang suka meminum minuman keras.\" Ali berkata, \"Kemudian Rasulullah shallallahu 'alaihi wasallam mengambil jubahnya. Setelah mengenakannya beliau berangkat ke rumah yang disebutkannya itu dengan berjalan kaki, sementara saya dan Zaid mengikutinya dari belakang. Sesampainya di depan pintu rumah yang di dalamnya ada Hamzah, Rasulullah shallallahu 'alaihi wasallam meminta izin masuk. Para penghuni rumah pun memberikan izin masuk. Ternyata mereka adalah para peminum minuman keras. Lalu Rasulullah shallallahu 'alaihi wasallam mulai mencela Hamzah terhadap apa yang telah diperbuatnya. Pada saat itu, kedua mata Hamzah memerah dan dia juga mulai mengamati Rasulullah shallallahu 'alaihi wasallam dari kedua lutut naik ke pusar dan akhirnya ke wajah beliau. Kemudian Hamzah berkata, \"Kalian ini tidak lain hanyalah para budak bapakku.\" Akhirnya Rasulullah shallallahu 'alaihi wasallam mengetahui bahwa Hamzah sedang mabuk berat. Lalu beliau mundur ke belakang dan keluar. Melihat itu kami pun pergi keluar mengikuti beliau.\" Dan telah menceritakan kepadaku [Muhammad bin Abdullah Al Quhzadza] telah menceritakan kepadaku [Abdullah bin Utsman] dari [Abdullah bin Mubarak] dari [Yunus] dari [Az Zuhri] dengan sanad seperti ini.\""},"3413":{"ar":"حَدَّثَنِي أَبُو الرَّبِيعِ سُلَيْمَانُ بْنُ دَاوُدَ الْعَتَكِيُّ حَدَّثَنَا حَمَّادٌ يَعْنِي ابْنَ زَيْدٍ أَخْبَرَنَا ثَابِتٌ عَنْ أَنَسِ بْنِ مَالِكٍ قَالَكُنْتُ سَاقِيَ الْقَوْمِ يَوْمَ حُرِّمَتْ الْخَمْرُ فِي بَيْتِ أَبِي طَلْحَةَ وَمَا شَرَابُهُمْ إِلَّا الْفَضِيخُ الْبُسْرُ وَالتَّمْرُ فَإِذَا مُنَادٍ يُنَادِي فَقَالَ اخْرُجْ فَانْظُرْ فَخَرَجْتُ فَإِذَا مُنَادٍ يُنَادِي أَلَا إِنَّ الْخَمْرَ قَدْ حُرِّمَتْ قَالَ فَجَرَتْ فِي سِكَكِ الْمَدِينَةِ فَقَالَ لِي أَبُو طَلْحَةَ اخْرُجْ فَاهْرِقْهَا فَهَرَقْتُهَا فَقَالُوا أَوْ قَالَ بَعْضُهُمْ قُتِلَ فُلَانٌ قُتِلَ فُلَانٌ وَهِيَ فِي بُطُونِهِمْ قَالَ فَلَا أَدْرِي هُوَ مِنْ حَدِيثِ أَنَسٍ فَأَنْزَلَ اللَّهُ عَزَّ وَجَلَّ{ لَيْسَ عَلَى الَّذِينَ آمَنُوا وَعَمِلُوا الصَّالِحَاتِ جُنَاحٌ فِيمَا طَعِمُوا إِذَا مَا اتَّقَوْا وَآمَنُوا وَعَمِلُوا الصَّالِحَاتِ }","id":"Telah menceritakan kepadaku [Abu Ar Rabi' Sulaiman bin Daud Al 'Ataki] telah menceritakan kepada kami [Hammad] -yaitu Ibnu Zaid- telah mengabarkan kepada kami [Tsabit] dari [Anas bin Malik] dia berkata, \"Saya pernah menuangkan khamer kepada sekelompok kaum di rumah Abu Thalhah ketika khamer diharamkan, dan saat itu mereka tidak minum kecuali dari Fadlih (minuman keras yang terbuat dari perasan kurma), kurma muda dan kurma masak. Tiba-tiba ada seseorang yang berseru, lantas Abu Thalhah berkata, \"Keluarlah dan lihatlah apa yang terjadi.\" Ternyata seseorang berseru, katanya, \"Tidakkah khamer telah diharamkan.\" Anas berkata, \"Kemudian berita itu tersebar ke seluruh Kota Madinah, lantas Abu Thalhah berkata kepadaku, \"Keluar dan baunglah.\" Maka saya langsung menumpahkannya. Saat itu orang-orang berkata, atau sebagian dari mereka berkata, \"Seseorang telah meninggal, sedangkan khamer tersebut masih dalam perut mereka.\" -Tsabit berkata; \"Namun saya tidak mengetahui apakah itu termasuk dari hadits Anas- Maka Allah Azza Wa Jalla berfirman: '(Tidak ada dosa bagi orang-orang yang beriman dan mengerjakan amalan shalih karena memakan makanan yang telah mereka makan dahulu, apabila mereka bertakwa dan beriman serta beramal shalih …) ' (? Qs. Al Maidah: 93)."},"3414":{"ar":"و حَدَّثَنَا يَحْيَى بْنُ أَيُّوبَ حَدَّثَنَا ابْنُ عُلَيَّةَ أَخْبَرَنَا عَب��دُ الْعَزِيزِ بْنُ صُهَيْبٍ قَالَ سَأَلُوا أَنَسَ بْنَ مَالِكٍ عَنْ الْفَضِيخِ فَقَالَمَا كَانَتْ لَنَا خَمْرٌ غَيْرَ فَضِيخِكُمْ هَذَا الَّذِي تُسَمُّونَهُ الْفَضِيخَ إِنِّي لَقَائِمٌ أَسْقِيهَا أَبَا طَلْحَةَ وَأَبَا أَيُّوبَ وَرِجَالًا مِنْ أَصْحَابِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي بَيْتِنَا إِذْ جَاءَ رَجُلٌ فَقَالَ هَلْ بَلَغَكُمْ الْخَبَرُ قُلْنَا لَا قَالَ فَإِنَّ الْخَمْرَ قَدْ حُرِّمَتْ فَقَالَ يَا أَنَسُ أَرِقْ هَذِهِ الْقِلَالَ قَالَ فَمَا رَاجَعُوهَا وَلَا سَأَلُوا عَنْهَا بَعْدَ خَبَرِ الرَّجُلِ","id":"Dan telah menceritakan kepada kami [Yahya bin Ayyub] telah menceritakan kepada kami [Ibnu Ulayyah] telah mengabarkan kepada kami [Abdul Aziz bun Shuhaib] dia berkata, \"Orang-orang bertanya kepada [Anas bin Malik] mengenai minuman campuran kurma muda.\" Dia menjawab, \"Ketika itu kami tidak memiliki khamer selain minuman campuran kurma sebagaimana yang kalian namakan dengan Al Fadlikh. Ketika aku sedang menuangkan campuran kurma tersebut kepada Abu Thalhah, Abu Ayyub dan beberapa orang dari sahabat Rasulullah shallallahu 'alaihi wasallam di rumah kami, tiba-tiba seorang laki-laki datang sambil berkata, \"Apakah telah sampai kepada kalian suatu berita?\" kami menjawab, \"Belum.\" Dia berkata, \"Sesungguhnya Khamer telah diharamkan.\" Maka Abu Thalhah berkata, \"Wahai Anas, tumpahkanlah wadah ini.\" Anas berkata, \"Setelah laki-laki tersebut menyampaikan berita, maka mereka kembali dan tidak lagi bertanya-tanya lagi tentang hukumnya.\""},"3415":{"ar":"و حَدَّثَنَا يَحْيَى بْنُ أَيُّوبَ حَدَّثَنَا ابْنُ عُلَيَّةَ قَالَ وَأَخْبَرَنَا سُلَيْمَانُ التَّيْمِيُّ حَدَّثَنَا أَنَسُ بْنُ مَالِكٍ قَالَإِنِّي لَقَائِمٌ عَلَى الْحَيِّ عَلَى عُمُومَتِي أَسْقِيهِمْ مِنْ فَضِيخٍ لَهُمْ وَأَنَا أَصْغَرُهُمْ سِنًّا فَجَاءَ رَجُلٌ فَقَالَ إِنَّهَا قَدْ حُرِّمَتْ الْخَمْرُ فَقَالُوا اكْفِئْهَا يَا أَنَسُ فَكَفَأْتُهَا قَالَ قُلْتُ لِأَنَسٍ مَا هُوَ قَالَ بُسْرٌ وَرُطَبٌ قَالَ فَقَالَ أَبُو بَكْرِ بْنُ أَنَسٍ كَانَتْ خَمْرَهُمْ يَوْمَئِذٍقَالَ سُلَيْمَانُ وَحَدَّثَنِي رَجُلٌ عَنْ أَنَسِ بْنِ مَالِكٍ أَنَّهُ قَالَ ذَلِكَ أَيْضًا حَدَّثَنَا مُحَمَّدُ بْنُ عَبْدِ الْأَعْلَى حَدَّثَنَا الْمُعْتَمِرُ عَنْ أَبِيهِ قَالَ قَالَ أَنَسٌ كُنْتُ قَائِمًا عَلَى الْحَيِّ أَسْقِيهِمْ بِمِثْلِ حَدِيثِ ابْنِ عُلَيَّةَ غَيْرَ أَنَّهُ قَالَ فَقَالَ أَبُو بَكْرِ بْنُ أَنَسٍ كَانَ خَمْرَهُمْ يَوْمَئِذٍ وَأَنَسٌ شَاهِدٌ فَلَمْ يُنْكِرْ أَنَسٌ ذَاكَ و قَالَ ابْنُ عَبْدِ الْأَعْلَى حَدَّثَنَا الْمُعْتَمِرُ عَنْ أَبِيهِ قَالَ حَدَّثَنِي بَعْضُ مَنْ كَانَ مَعِي أَنَّهُ سَمِعَ أَنَسًا يَقُولُا كَانَ خَمْرَهُمْ يَوْمَئِذٍ","id":"Dan telah menceritakan kepada kami [Yahya bin Ayyub] telah menceritakan kepada kami [Ibnu Ulayyah] dia berkata; dan telah mengabarkan kepada kami [Sulaiman At Taimi] telah menceritakan kepada kami [Anas bin Malik] dia berkata, \"Saya pernah menjadi pelayan yang bertugas menuangkan minuman kepada paman-pamanku, ketika itu saya menuangkan Fadlikh (perasan dari kurma muda) kepada mereka, saat itu aku adalah orang yang termuda di antara mereka, tiba-tiba seorang laki-laki datang sambil berkata, \"Sesungguhnya khamer telah diharamkan.\" Lantas mereka berkata, \"Wahai Anas, buanglah!\" Lalu saya menumpahkannya. Sulaiman berkata, \"Saya bertanya kepada Anas, \"Minuman apakah itu?\" Anas menjawab, \"Busyr (kurma muda) dan ruthab (kurma masak).\" Perawi berkata, \"Lalu Abu Bakar bin Anas berkata, \"Saat itu khamer mereka adalah Al Fadlih (minuman dari campuran kurma).\" [Sulaiman] berkata, \" [seorang laki-laki] menceritakan kepadaku dari [Anas bin Malik], bahwa dia berkata seperti itu juga.\" Telah menceritakan kepadaku [Muhammad bin Abdul A'la] telah menceritakan kepadaku [Al Mu'tamir] dari [ayahnya] dia berkata; [Anas] berkata, \"Saya pernah menjadi pelayan di suatu kaum untuk menuangkan minuman kepada mereka...seperti hadits Ibnu Ulayyah, hanya saja ia menyebutkan, \"Abu Bakar bin Anas mengatakan, \"Khamer mereka saat itu adalah Al Fadlikh (terbuat dari campuran kurma).\" Anas adalah orang yang saat itu menyaksikannya, maka ia pun tidak mengingkarinya.\" [Ibnu Abdul A'la] berkata; telah menceritakan kepadaku [Al Mu'tamir] dari [ayahnya] dia berkata; telah menceritakan kepadaku [sebagian orang yang bersamaku] bahwa dia pernah mendengar [Anas] berkata, \"Saat itu khamer mereka adalah Al Fadlikh.\""},"3416":{"ar":"و حَدَّثَنَا يَحْيَى بْنُ أَيُّوبَ حَدَّثَنَا ابْنُ عُلَيَّةَ قَالَ وَأَخْبَرَنَا سَعِيدُ بْنُ أَبِي عَرُوبَةَ عَنْ قَتَادَةَ عَنْ أَنَسِ بْنِ مَالِكٍ قَالَكُنْتُ أَسْقِي أَبَا طَلْحَةَ وَأَبَا دُجَانَةَ وَمُعَاذَ بْنَ جَبَلٍ فِي رَهْطٍ مِنْ الْأَنْصَارِ فَدَخَلَ عَلَيْنَا دَاخِلٌ فَقَالَ حَدَثَ خَبَرٌ نَزَلَ تَحْرِيمُ الْخَمْرِ فَأَكْفَأْنَاهَا يَوْمَئِذٍ وَإِنَّهَا لَخَلِيطُ الْبُسْرِ وَالتَّمْرِقَالَ قَتَادَةُ وَقَالَ أَنَسُ بْنُ مَالِكٍ لَقَدْ حُرِّمَتْ الْخَمْرُ وَكَانَتْ عَامَّةُ خُمُورِهِمْ يَوْمَئِذٍ خَلِيطَ الْبُسْرِ وَالتَّمْرِ و حَدَّثَنَا أَبُو غَسَّانَ الْمِسْمَعِيُّ وَمُحَمَّدُ بْنُ الْمُثَنَّى وَابْنُ بَشَّارٍ قَالُوا أَخْبَرَنَا مُعَاذُ بْنُ هِشَامٍ حَدَّثَنِي أَبِي عَنْ قَتَادَةَ عَنْ أَنَسِ بْنِ مَالِكٍ قَالَ إِنِّي لَأَسْقِي أَبَا طَلْحَةَ وَأَبَا دُجَانَةَ وَسُهَيْلَ بْنَ بَيْضَاءَ مِنْ مَزَادَةٍ فِيهَا خَلِيطُ بُسْرٍ وَتَمْرٍ بِنَحْوِ حَدِيثِ سَعِيدٍ","id":"Telah menceritakan kepada kami [Yahya bin Ayyub] telah menceritakan kepada kami [Ibnu 'Ulayyah], dia berkata; dan telah mengabarkan kepada kami [Sa'id bin Abu 'Arubah] dari [Qatadah] dari [Anas bin Malik] dia berkata, \"Aku pernah menuangkan (minuman) untuk Abu Thalhah, Abu Dujanah dan Mu'adz bin Jabal disekumpulan orang-orang Anshar, tiba-tiba seseorang masuk menemui kami sambil berseru, \"Ada kabar baru! khamer telah diharamkan.\" Seketika itu kami langsung menumpahkannya, sedangkan khamer waktu itu terbuat dari campuran busr (kurma muda) dan tamr (kurma kering).\" [Qatadah] berkata, \" [Anas bin Malik] berkata, \"Sungguh, khamer telah diharamkan, sedangkan pada umumnya khamer waktu itu terbuat dari campuran busr dan tamr.\" Dan telah menceritakan kepada kami [Abu Ghassan Al Misma'i] dan [Muhammad bin Al Mutsanna] dan [Ibnu Basyar] mereka berkata; telah mengabarkan kepada kami [Mu'adz bin Hisyam] telah menceritakan kepadaku [Ayahku] dari [Qatadah] dari [Anas bin Malik] dia berkata, \"Sungguh, saya pernah menuangkan (minuman) campuran busr dan tamr kepada Abu Thalhah, Abu Dujanah dan Suhail bin Baidla` dari geriba besar....sebaimana haditsnya Sa'id.\""},"3417":{"ar":"و حَدَّثَنِي أَبُو الطَّاهِرِ أَحْمَدُ بْنُ عَمْرِو بْنِ سَرْحٍ أَخْبَرَنَا عَبْدُ اللَّهِ بْنُ وَهْبٍ أَخْبَرَنِي عَمْرُو بْنُ الْحَارِثِ أَنَّ قَتَادَةَ بْنَ دِعَامَةَ حَدَّثَهُ أَنَّهُ سَمِعَ أَنَسَ بْنَ مَالِكٍ يَقُولُاإِنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَهَى أَنْ يُخْلَطَ التَّمْرُ وَالزَّهْوُ ثُمَّ يُشْرَبَ وَإِنَّ ذَلِكَ كَانَ عَامَّةَ خُمُورِهِمْ يَوْمَ حُرِّمَتْ الْخَمْرُ","id":"Dan telah menceritakan kepadaku [Abu Thahir Ahmad bin 'Amru bin Sarh] telah mengabarkan kepada kami [Abdullah bin Wahb] telah mengabarkan kepadaku ['Amru bin Al Harits] bahwa [Qatadah bin Di'amah] telah menceritakan kepadanya, bahwa dia pernah mendengar [Anas bin Malik] berkata, \"Sesugguhnya Rasulullah shallallahu 'alaihi wasallam melarang minuman dengan mencapur antara kurma masak dengan kurma muda, sebab hal itu adalah awal kali khamer diharamkan.\""},"3418":{"ar":"و حَدَّثَنِي أَبُو الطَّاهِرِ أَخْبَرَنَا ابْنُ وَهْبٍ أَخْبَرَنِي مَالِكُ بْنُ أَنَسٍ عَنْ إِسْحَقَ بْنِ عَبْدِ اللَّهِ بْنِ أَبِي طَلْحَةَ عَنْ أَنَسِ بْنِ مَالِكٍ أَنَّهُ قَالَكُنْتُ أَسْقِي أَبَا عُبَيْدَةَ بْنَ الْجَرَّاحِ وَأَبَا طَلْحَةَ وَأُبَيَّ بْنَ كَعْبٍ شَرَابًا مِنْ فَضِيخٍ وَتَمْرٍ فَأَتَاهُمْ آتٍ فَقَالَ إِنَّ الْخَمْرَ قَدْ حُرِّمَتْ فَقَالَ أَبُو طَلْحَةَ يَا أَنَسُ قُمْ إِلَى هَذِهِ الْجَرَّةِ فَاكْسِرْهَا فَقُمْتُ إِلَى مِهْرَاسٍ لَنَا فَضَرَبْتُهَا بِأَسْفَلِهِ حَتَّى تَكَسَّرَتْ","id":"Dan telah menceritakan kepadaku [Abu At Thahir] telah mengabarkan kepada kami [Ibnu Wahb] telah mengabarkan kepadaku [Malik bin Anas] dari [Ishaq bin Abdullah bin Abu Thalhah] dari [Anas bin Malik] bahwa dia berkata, \"Saya pernah menuangkan minuman dari Fadlikh (minuman yang terbuat dari campuran kurma muda) dan Tamr (minuman yang terbuat dari kurma) kepada Abu Ubaidah bin Jarrah, Abu Thalhah dan Ubay bin Ka'ab, tiba-tiba seseorang datang kepada mereka sambil berkata, \"Sesungguhnya khamer telah diharamkan.\" Lantas Abu Thalhah berkata, \"Wahai Anas, berdirilah! Ambil dan pecahlah bejana (khamer) ini.\" Kemudian saya mengambil gentong milik kami dan saya pukul bawahnya hingga pecah.\""},"3419":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ الْمُثَنَّى حَدَّثَنَا أَبُو بَكْرٍ يَعْنِي الْحَنَفِيَّ حَدَّثَنَا عَبْدُ الْحَمِيدِ بْنُ جَعْفَرٍ حَدَّثَنِي أَبِي أَنَّهُ سَمِعَ أَنَسَ بْنَ مَالِكٍ يَقُولُالَقَدْ أَنْزَلَ اللَّهُ الْآيَةَ الَّتِي حَرَّمَ اللَّهُ فِيهَا الْخَمْرَ وَمَا بِالْمَدِينَةِ شَرَابٌ يُشْرَبُ إِلَّا مِنْ تَمْرٍ","id":"Telah menceritakan kepada kami [Muhammad bin Al Mutsanna] telah menceritakan kepada kami [Abu Bakar] -yaitu Al Hanafi- telah menceritakan kepada kami [Abdul Hamid bin Ja'far] telah menceritakan kepadaku [ayahku] bahwa dia pernah mendengar [Anas bin Malik] berkata, \"Sesungguhnya Allah telah menurunkan ayat tentang pengharaman khamer, ketika itu di Madinah tidak ada khamer kecuali yang terbuat dari tamr (kurma).\""},"3420":{"ar":"حَدَّثَنَا يَحْيَى بْنُ يَحْيَى أَخْبَرَنَا عَبْدُ الرَّحْمَنِ بْنُ مَهْدِيٍّ ح و حَدَّثَنَا زُهَيْرُ بْنُ حَرْبٍ حَدَّثَنَا عَبْدُ الرَّحْمَنِ عَنْ سُفْيَانَ عَنْ السُّدِّيِّ عَنْ يَحْيَى بْنِ عَبَّادٍ عَنْ أَنَسٍأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ سُئِلَ عَنْ الْخَمْرِ تُتَّخَذُ خَلًّا فَقَالَ لَا","id":"Telah menceritakan kepada kami [Yahya bin Yahya] telah mengabarkan kepada kami [Abdurrahman bin Mahdi]. (dalam jalur lain disebutkan) Telah menceritakan kepada kami [Zuhair bin Harb] telah menceritakan kepada kami [Abdurrahman] dari [Sufyan] dari [As Suddi] dari [Yahya bin 'Abbad] dari [Anas], bahwa Nabi shallallahu 'alaihi wasallam pernah ditanya mengenai khamer yang dibuat cuka, maka beliau bersabda: \"Jangan.\""},"3421":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ الْمُثَنَّى وَمُحَمَّدُ بْنُ بَشَّارٍ وَاللَّفْظُ لِابْنِ الْمُثَنَّى قَالَا حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ حَدَّثَنَا شُعْبَةُ عَنْ سِمَاكِ بْنِ حَرْبٍ عَنْ عَلْقَمَةَ بْنِ وَائِلٍ عَنْ أَبِيهِ وَائِلٍ الْحَضْرَمِيِّ أَنَّ طَارِقَ بْنَ سُوَيْدٍ الْجُعْفِيَّسَأَلَ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ الْخَمْرِ فَنَهَاهُ أَوْ كَرِهَ أَنْ يَصْنَعَهَا فَقَالَ إِنَّمَا أَصْنَعُهَا لِلدَّوَاءِ فَقَالَ إِنَّهُ لَيْسَ بِدَوَاءٍ وَلَكِنَّهُ دَاءٌ","id":"Telah menceritakan kepada kami [Muhammad bin Al Mutsanna] dan [Muhammad bin Basysyar] dan ini adalah lafadz Ibnu Al Mutsanna, keduanya berkata; telah menceritakan kepada kami [Muhammad bin Ja'far] telah menceritakan kepada kami [Syu'bah] dari [Simak bin Harb] dari ['Alqamah bin Wa`il] dari ayahnya [Wa`il Al Hadlrami] bahwa Thariq bin Suwaid Al Ju'fi pernah bertanya kepada Nabi shallallahu 'alaihi wasallam mengenai khamer, maka beliau pun melarangnya atau benci membuatnya.\" Lalu dia berkata, \"Saya membuatnya hanya untuk obat.\" Maka beliau bersabda: \"Khamer itu bukanlah obat, akan tetapi ia adalah penyakit.\""},"3422":{"ar":"حَدَّثَنِي زُهَيْرُ بْنُ حَرْبٍ حَدَّثَنَا إِسْمَعِيلُ بْنُ إِبْرَاهِيمَ أَخْبَرَنَا الْحَجَّاجُ بْنُ أَبِي عُثْمَانَ حَدَّثَنِي يَحْيَى بْنُ أَبِي كَثِيرٍ أَنَّ أَبَا كَثِيرٍ حَدَّثَهُ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْخَمْرُ مِنْ هَاتَيْنِ الشَّجَرَتَيْنِ النَّخْلَةِ وَالْعِنَبَةِ","id":"Telah menceritakan kepadaku [Zuhair bin Harb] telah menceritakan kepada kami [Isma'il bin Ibrahim] telah mengabarkan kepada kami [Al Hajjaj bin Abu Utsman] telah menceritakan kepadaku [Yahya bin Abu Katsir] bahwa [Abu Katsir] telah menceritakan kepadanya dari [Abu Hurairah] dia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Khamer itu bisa terbuat dari dua macam pohon ini; kurma dan anggur.\""},"3423":{"ar":"و حَدَّثَنَا مُحَمَّدُ بْنُ عَبْدِ اللَّهِ بْنِ نُمَيْرٍ حَدَّثَنَا أَبِي حَدَّثَنَا الْأَوْزَاعِيُّ حَدَّثَنَا أَبُو كَثِيرٍ قَالَ سَمِعْتُ أَبَا هُرَيْرَةَ يَقُولُاسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ الْخَمْرُ مِنْ هَاتَيْنِ الشَّجَرَتَيْنِ النَّخْلَةِ وَالْعِنَبَةِ","id":"Dan telah menceritakan kepada kami [Muhammad bin Abdullah bin Numair] telah menceritakan kepada kami [ayahku] telah menceritakan kepada kami [Al Auza'i] telah menceritakan kepada kami [Abu Katsir] dia berkata; saya mendengar [Abu Hurairah] berkata, \"Saya mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Khamer itu bisa terbuat dari dua macam pohon ini; kurma dan anggur.\""},"3424":{"ar":"و حَدَّثَنَا زُهَيْرُ بْنُ حَرْبٍ وَأَبُو كُرَيْبٍ قَالَا حَدَّثَنَا وَكِيعٌ عَنْ الْأَوْزَاعِيِّ وَعِكْرِمَةَ بْنِ عَمَّارٍ وَعُقْبَةَ بْنِ التَّوْأَمِ عَنْ أَبِي كَثِيرٍ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْخَمْرُ مِنْ هَاتَيْنِ الشَّجَرَتَيْنِ الْكَرْمَةِ وَالنَّخْلَةِوَفِي رِوَايَةِ أَبِي كُرَيْبٍ الْكَرْمِ وَالنَّخْلِ","id":"Dan telah menceritakan kepada kami [Zuhair bin Harb] dan [Abu Kuraib] keduanya berkata; telah menceritakan kepada kami [Waki'] dari [Al Auza'i] dan [Ikrimah bin 'Ammar] dan ['Uqbah bi At Tau`am] dari [Abu Katsir] dari [Abu Hurairah] dia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: Khamer itu bisa terbuat dari dua jenis pohon ini; anggur dan kurma.\" Dan dalam riwayatnya Abu Kuraib juga menyebutkan, \"Pohon anggur dan pohon kurma.\""},"3425":{"ar":"حَدَّثَنَا شَيْبَانُ بْنُ فَرُّوخَ حَدَّثَنَا جَرِيرُ بْنُ حَازِمٍ سَمِعْتُ عَطَاءَ بْنَ أَبِي رَبَاحٍ حَدَّثَنَا جَابِرُ بْنُ عَبْدِ اللَّهِ الْأَنْصَارِيُّأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَهَى أَنْ يُخْلَطَ الزَّبِيبُ وَالتَّمْرُ وَالْبُسْرُ وَالتَّمْرُ","id":"Telah menceritakan kepada kami [Syaiban bin Farruh] telah menceritakan kepada kami [Jarir bin Hazim] saya mendengar ['Atha bin Abu Rabah] telah menceritakan kepada kami [Jabir bin Abdullah Al Anshari], bahwa Nabi shallallahu 'alaihi wasallam melarang mencampur antara anggur dengan kurma masak, kurma muda dengan kurma masak (untuk dibuat perasan).\""},"3426":{"ar":"حَدَّثَنَا قُتَيْبَةُ بْنُ سَعِيدٍ حَدَّثَنَا لَيْثٌ عَنْ عَطَاءِ بْنِ أَبِي رَبَاحٍ عَنْ جَابِرِ بْنِ عَبْدِ اللَّهِ الْأَنْصَارِيِّعَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهُ نَهَى أَنْ يُنْبَذَ التَّمْرُ وَالزَّبِيبُ جَمِيعًا وَنَهَى أَنْ يُنْبَذَ الرُّطَبُ وَالْبُسْرُ جَمِيعًا","id":"Telah menceritakan kepada kami [Qutaibah bin Sa'id] telah menceritakan kepada kami [Laits] dari ['Atha bin Abu Rabah] dari [Jabir bin Abdullah Al Anshari] dari Rasulullah shallallahu 'alaihi wasallam, bahwa beliau melarang membuat perasan kurma dengan anggur menjadi satu, dan melarang membuat perasan kurma segar (matang) dengan kurma muda menjadi satu.\""},"3427":{"ar":"و حَدَّثَنِي مُحَمَّدُ بْنُ حَاتِمٍ حَدَّثَنَا يَحْيَى بْنُ سَعِيدٍ عَنْ ابْنِ جُرَيْجٍ ح و حَدَّثَنَا إِسْحَقُ بْنُ إِبْرَاهِيمَ وَمُحَمَّدُ بْنُ رَافِعٍ وَاللَّفْظُ لِابْنِ رَافِعٍ قَالَا حَدَّثَنَا عَبْدُ الرَّزَّاقِ أَخْبَرَنَا ابْنُ جُرَيْجٍ قَالَ قَالَ لِي عَطَاءٌ سَمِعْتُ جَابِرَ بْنَ عَبْدِ اللَّهِ يَقُولُاقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا تَجْمَعُوا بَيْنَ الرُّطَبِ وَالْبُسْرِ وَبَيْنَ الزَّبِيبِ وَالتَّمْرِ نَبِيذًا","id":"Dan telah menceritakan kepadaku [Muhammad bin Hatim] telah menceritakan kepada kami [Yahya bin Sa'id] dari [Ibnu Juraij]. (dalam jalur lain disebutkan) Telah menceritakan kepada kami [Ishaq bin Ibrahim] dan [Muhammad bin Rafi'] dan ini adalah lafadz Ibnu Rafi', keduanya berkata; telah menceritakan kepada kami [Abdurrazaq] telah mengabarkan kepada kami [Ibnu Juraij] dia berkata; ['Atha] pernah berkata; saya pernah mendengar [Jabir bin Abdullah] berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Janganlah kalian mencampur antara perasan ruthab (kurma segar) dengan busr (kurma muda) dan antara perasan anggur dengan tamr (kurma masak).\""},"3428":{"ar":"حَدَّثَنَا يَحْيَى بْنُ يَحْيَى أَخْبَرَنَا يَزِيدُ بْنُ زُرَيْعٍ عَنْ التَّيْمِيِّ عَنْ أَبِي نَضْرَةَ عَنْ أَبِي سَعِيدٍأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَهَى عَنْ التَّمْرِ وَالزَّبِيبِ أَنْ يُخْلَطَ بَيْنَهُمَا وَعَنْ التَّمْرِ وَالْبُسْرِ أَنْ يُخْلَطَ بَيْنَهُمَا","id":"Telah menceritakan kepada kami [Yahya bin Yahya] telah mengabarkan kepada kami [Yazid bin Zurai'] dari [At Taimi] dari [Abu An Nadlrah] dari [Abu Sa'id], bahwa Nabi shallallahu 'alaihi wasallam melarang mencampurkan antara kurma dengan anggur dan antara tamr (kurma masak) dan busr (kurma muda) untuk dibuat perasan.\""},"3429":{"ar":"حَدَّثَنَا يَحْيَى بْنُ أَيُّوبَ حَدَّثَنَا ابْنُ عُلَيَّةَ حَدَّثَنَا سَعِيدُ بْنُ يَزِيدَ أَبُو مَسْلَمَةَ عَنْ أَبِي نَضْرَةَ عَنْ أَبِي سَعِيدٍ قَالَنَهَانَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنْ نَخْلِطَ بَيْنَ الزَّبِيبِ وَالتَّمْرِ وَأَنْ نَخْلِطَ الْبُسْرَ وَالتَّمْرَو حَدَّثَنَا نَصْرُ بْنُ عَلِيٍّ الْجَهْضَمِيُّ حَدَّثَنَا بِشْرٌ يَعْنِي ابْنَ مُفَضَّلٍ عَنْ أَبِي مَسْلَمَةَ بِهَذَا الْإِسْنَادِ مِثْلَهُ","id":"Telah menceritakan kepada kami [Yahya bin Ayyub] telah menceritakan kepada kami [Ibnu Ulayyah] telah menceritakan kepada kami [Sa'id bin Zaid Abu Maslamah] dari [Abu Nadlrah] dari [Abu Sa'id] dia berkata, \"Rasulullah shallallahu 'alaihi wasallam melarang kami membuat perasan dengan mencampurkan antara anggur dan kurma, antara kurma muda dan kurma masak.\" Telah menceritakan kepada kami [Nashr bin Ali Al Jahdlami] telah menceritakan kepada kami [Bisyr] -yaitu Ibnu Mufadlal- dari [Abu Maslamah] dengan sanad seperti ini.\""},"3430":{"ar":"حَدَّثَنَا يَحْيَى بْنُ أَيُّوبَ حَدَّثَنَا ابْنُ عُلَيَّةَ أَخْبَرَنَا هِشَامٌ الدَّسْتَوَائِيُّ عَنْ يَحْيَى بْنِ أَبِي كَثِيرٍ عَنْ عَبْدِ اللَّهِ بْنِ أَبِي قَتَادَةَ عَنْ أَبِيهِقَالَ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا تَنْتَبِذُوا الزَّهْوَ وَالرُّطَبَ جَمِيعًا وَلَا تَنْتَبِذُوا الزَّبِيبَ وَالتَّمْرَ جَمِيعًا وَانْتَبِذُوا كُلَّ وَاحِدٍ مِنْهُمَا عَلَى حِدَتِهِو حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا مُحَمَّدُ بْنُ بِشْرٍ الْعَبْدِيُّ عَنْ حَجَّاجِ بْنِ أَبِي عُثْمَانَ عَنْ يَحْيَى بْنِ أَبِي كَثِيرٍ بِهَذَا الْإِسْنَادِ مِثْلَهُ","id":"Telah menceritakan kepada kami [Yahya bin Ayyub] telah menceritakan kepada kami [Ibnu Ulayyah] telah mengabarkan kepada kami [Hisyam Ad Dastawa`i] dari [Yahya bin Abu Katsir] dari [Abdullah bin Abu Qatadah] dari [ayahnya] dia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Janganlah kalian membuat perasan nabidz dengan mencampur antara kurma muda dengan kurma segar (sudah masak), atau antara anggur dengan kurma masak, tetapi hendaklah kalian buat dengan sendiri-sendiri (tidak dengan mencampurnya).\" Dan telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] telah menceritakan kepada kami [Muhammad bin Bisyr Al 'Abdi] dari [Hajjaj bin Abu 'Utsman] dari [Yahya bin Abu Katsir] dengan sanad seperti ini.\""},"3431":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ الْمُثَنَّى حَدَّثَنَا عُثْمَانُ بْنُ عُمَرَ أَخْبَرَنَا عَلِيٌّ وَهُوَ ابْنُ الْمُبَارَكِ عَنْ يَحْيَى عَنْ أَبِي سَلَمَةَ عَنْ أِبِي قَتَادَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَا تَنْتَبِذُوا الزَّهْوَ وَالرُّطَبَ جَمِيعًا وَلَا تَنْتَبِذُوا الرُّطَبَ وَالزَّبِيبَ جَمِيعًا وَلَكِنْ انْتَبِذُوا كُلَّ وَاحِدٍ عَلَى حِدَتِهِوَزَعَمَ يَحْيَى أَنَّهُ لَقِيَ عَبْدَ اللَّهِ بْنَ أَبِي قَتَادَةَ فَحَدَّثَهُ عَنْ أَبِيهِ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِمِثْلِ هَذَا و حَدَّثَنِيهِ أَبُو بَكْرِ بْنُ إِسْحَقَ حَدَّثَنَا رَوْحُ بْنُ عُبَادَةَ حَدَّثَنَا حُسَيْنٌ الْمُعَلِّمُ حَدَّثَنَا يَحْيَى بْنُ أَبِي كَثِيرٍ بِهَذَيْنِ الْإِسْنَادَيْنِ غَيْرَ أَنَّهُ قَالَ الرُّطَبَ وَالزَّهْوَ وَالتَّمْرَ وَالزَّبِيبَ","id":"Telah menceritakan kepada kami [Muhammad bin Al Mutsanna] telah menceritakan kepada kami [Utsman bin Umar] telah mengabarkan kepada kami [Ali yaitu Ibnu Mubarak] dari [Yahya] dari [Abu Salamah] dari [Abu Qatadah], bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Janganlah kalian membuat perasan kurma muda dengan kurma segar (sudah masak) menjadi satu, atau kurma segar dengan anggur, akan tetapi sendirikanlah setiap perasannya sesuai dengan takarannya masing-masing.\" [Yahya] menyakini bahwa ia pernah bertemu dengan [Abdullah bin Abu Qatadah] kemudian dia menceritakan kepadanya dari [ayahnya] dari Nabi shallallahu 'alaihi wasallam seperti hadits ini.\" Dan telah menceritakan kepadaku [Abu Bakar bin Ishaq] telah menceritakan kepada kami [Rauh bin Ubadah] telah menceritakan kepada kami [Husain Al Mu'allim] telah menceritakan kepada kami [Yahya bin Abu Katsir] dengan kedua isnad ini, namun dia menyebutkan, \"Antara kurma segar dengan kurma muda, atau kurma masak dengan anggur.\""},"3432":{"ar":"و حَدَّثَنِي أَبُو بَكْرِ بْنُ إِسْحَقَ حَدَّثَنَا عَفَّانُ بْنُ مُسْلِمٍ حَدَّثَنَا أَبَانُ الْعَطَّارُ حَدَّثَنَا يَحْيَى بْنُ أَبِي كَثِيرٍ حَدَّثَنِي عَبْدُ اللَّهِ بْنُ أَبِي قَتَادَةَ عَنْ أَبِيهِأَنَّ نَبِيَّ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَهَى عَنْ خَلِيطِ التَّمْرِ وَالْبُسْرِ وَعَنْ خَلِيطِ الزَّبِيبِ وَالتَّمْرِ وَعَنْ خَلِيطِ الزَّهْوِ وَالرُّطَبِ وَقَالَ انْتَبِذُوا كُلَّ وَاحِدٍ عَلَى حِدَتِهِو حَدَّثَنِي أَبُو سَلَمَةَ بْنُ عَبْدِ الرَّحْمَنِ عَنْ أَبِي قَتَادَةَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِمِثْلِ هَذَا الْحَدِيثِ","id":"Dan telah menceritakan kepadaku [Abu Bakar bin Ishaq] telah menceritakan kepada kami ['Affan bin Muslim] telah menceritakan kepada kami [Aban Al 'Athar] telah menceritakan kepada kami [Yahya bin Abu Katisr] telah menceritakan kepadaku [Abdullah bin Abu Qatadah] dari [ayahnya], bahwa Nabi Allah shallallahu 'alaihi wasallam melarang mencampurkan antara kurma masak dengan kurma muda, anggur dengan kurma masak, kurma muda dengan kurma segar (masak). Dan beliau mengatakan: \"Buatlah perasan setiap darinya secara sendiri-sendiri.\" Dan telah menceritakan kepadaku [Abu Salamah bin Abdurrahman] dari [Abu Qatadah] dari Nabi shallallahu 'alaihi wasallam seperti hadits ini.\""},"3433":{"ar":"و حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا عَلِيُّ بْنُ مُسْهِرٍ عَنْ الشَّيْبَانِيِّ عَنْ حَبِيبٍ عَنْ سَعِيدِ بْنِ جُبَيْرٍ عَنْ ابْنِ عَبَّاسٍ قَالَنَهَى النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنْ يُخْلَطَ التَّمْرُ وَالزَّبِيبُ جَمِيعًا وَأَنْ يُخْلَطَ الْبُسْرُ وَالتَّمْرُ جَمِيعًا وَكَتَبَ إِلَى أَهْلِ جُرَشَ يَنْهَاهُمْ عَنْ خَلِيطِ التَّمْرِ وَالزَّبِيبِو حَدَّثَنِيهِ وَهْبُ بْنُ بَقِيَّةَ أَخْبَرَنَا خَالِدٌ يَعْنِي الطَّحَّانَ عَنْ الشَّيْبَانِيِّ بِهَذَا الْإِسْنَادِ فِي التَّمْرِ وَالزَّبِيبِ وَلَمْ يَذْكُرْ الْبُسْرَ وَالتَّمْرَ","id":"Dan telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] telah menceritakan kepada kami [Ali bin Mushir] dari [As Syaibani] dari [Habib] dari [Sa'id bin Jubair] dari [Ibnu Abbas] dia berkata, \"Rasulullah shallallahu 'alaihi wasallam melarang (membuat perasan) dengan mencampur antara kurma masak dengan anggur, atau kurma muda dengan kurma masak. Kemudian beliau menulis surat kepada penduduk Jurasy melarang mereka mencampur kurma masak dengan anggur menjadi satu.\" Dan telah menceritakan kepadaku [Wahb bin Baqiyah] telah mengabarkan kepada kami [Khalid] -yaitu At Thahan- dari [As Syaibani] dengan sanad ini tentang (mencampur) kurma masak dengan anggur, dan ia tidak menyebutkan 'kurma muda dengan kurma masak'.\""},"3434":{"ar":"حَدَّثَنِي مُحَمَّدُ بْنُ رَافِعٍ حَدَّثَنَا عَبْدُ الرَّزَّاقِ أَخْبَرَنَا ابْنُ جُرَيْجٍ أَخْبَرَنِي مُوسَى بْنُ عُقْبَةَ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَأَنَّهُ كَانَ يَقُولُ قَدْ نُهِيَ أَنْ يُنْبَذَ الْبُسْرُ وَالرُّطَبُ جَمِيعًا وَالتَّمْرُ وَالزَّبِيبُ جَمِيعًا","id":"Dan telah menceritakan kepadaku [Muhammad bin Rafi'] telah menceritakan kepada kami [Abdurrazaq] telah mengabarkan kepada kami [Ibnu Juraij] telah mengabarkan kepadaku [Musa bin Uqbah] dari [Nafi'] dari [Ibnu Umar] bahwa dia berkata, \"Telah dilarang membuat perasan nabidz dengan mencampur antara kurma muda dengan kurma segar, dan kurma masak dengan anggur.\""},"3435":{"ar":"حَدَّثَنَا قُتَيْبَةُ بْنُ سَعِيدٍ حَدَّثَنَا لَيْثٌ عَنْ ابْنِ شِهَابٍ عَنْ أَنَسِ بْنِ مَالِكٍ أَنَّهُ أَخْبَرَهُأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَهَى عَنْ الدُّبَّاءِ وَالْمُزَفَّتِ أَنْ يُنْبَذَ فِيهِ","id":"Telah menceritakan kepada kami [Qutaibah bin Sa'id] telah menceritakan kepada kami [Laits] dari [Ibnu Syihab] dari [Anas bin Malik] bahwa dia telah mengabarkan kepadanya, bahwa Rasulullah shallallahu 'alaihi wasallam telah melarang membuat perasan dalam Ad Dubba dan Al Muzaffat.\" "},"3436":{"ar":"و حَدَّثَنِي عَمْرٌو النَّاقِدُ حَدَّثَنَا سُفْيَانُ بْنُ عُيَيْنَةَ عَنْ الزُّهْرِيِّ عَنْ أَنَسِ بْنِ مَالِكٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَهَى عَنْ الدُّبَّاءِ وَالْمُزَفَّتِ أَنْ يُنْتَبَذَ فِيهِ","id":"Dan telah menceritakan kepadaku ['Amru An Naqid] telah menceritakan kepada kami [Sufyan bin 'Uyainah] dari [Az Zuhri] dari [Anas bin Malik], bahwa Rasulullah shallallahu 'alaihi wasallam melarang membuat perasan dalam bejana dalam bejana dari Ad Duba dan Al Muzaffat.\" "},"3437":{"ar":"قَالَ وَأَخْبَرَهُ أَبُو سَلَمَةَ أَنَّهُ سَمِعَ أَبَا هُرَيْرَةَ يَقُولُاقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا تَنْتَبِذُوا فِي الدُّبَّاءِ وَلَا فِي الْمُزَفَّتِ ثُمَّ يَقُولُ أَبُو هُرَيْرَةَ وَاجْتَنِبُوا الْحَنَاتِمَ","id":"Perawi berkata; (Dan telah menceritakan kepadaku ['Amru An Naqid] telah menceritakan kepada kami [Sufyan bin 'Uyainah] dari [Az Zuhri]) dan telah mengabarkan kepadanya [Abu Salamah] bahwa dia pernah mendengar [Abu Hurairah] berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Janganlah kalian membuat perasan dalam Ad Dubba dan Al Muzaffat.\" Kemudian Abu Hurairah berkata, \"Dan jauhilah oleh kalian Al Hantam.\""},"3438":{"ar":"حَدَّثَنَا نَصْرُ بْنُ عَلِيٍّ الْجَهْضَمِيُّ أَخْبَرَنَا نُوحُ بْنُ قَيْسٍ حَدَّثَنَا ابْنُ عَوْنٍ عَنْ مُحَمَّدٍ عَنْ أَبِي هُرَيْرَةَأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لِوَفْدِ عَبْدِ الْقَيْسِ أَنْهَاكُمْ عَنْ الدُّبَّاءِ وَالْحَنْتَمِ وَالنَّقِيرِ وَالْمُقَيَّرِ وَالْحَنْتَمُ وَالْمَزَادَةُ الْمَجْبُوبَةُ وَلَكِنْ اشْرَبْ فِي سِقَائِكَ وَأَوْكِهِ","id":"Telah menceritakan kepada kami [Nahsr bin Ali Al Jahdlami] telah mengabarkan kepada kami [Nuh bin Qais] telah menceritakan kepada kami [Ibnu 'Aun] dari [Muhammad] dari [Abu Hurairah], bahwa Nabi shallallahu 'alaihi wasallam bersabda kepada delegasi Abdul Qais: \"Saya telah melarang kalian dari Ad Dubba, Al Hantam, An Naqir, Al Muqayyar, Al Hantam dan guci tempat penyimpanan air yang memabukkan, akan tetapi minumlah dari wadah air minum.\""},"3439":{"ar":"حَدَّثَنَا سَعِيدُ بْنُ عَمْرٍو الْأَشْعَثِيُّ أَخْبَرَنَا عَبْثَرٌ ح و حَدَّثَنِي زُهَيْرُ بْنُ حَرْبٍ حَدَّثَنَا جَرِيرٌ ح و حَدَّثَنِي بِشْرُ بْنُ خَالِدٍ أَخْبَرَنَا مُحَمَّدٌ يَعْنِي ابْنَ جَعْفَرٍ عَنْ شُعْبَةَ كُلُّهُمْ عَنْ الْأَعْمَشِ عَنْ إِبْرَاهِيمَ التَّيْمِيِّ عَنْ الْحَارِثِ بْنِ سُوَيْدٍ عَنْ عَلِيٍّ قَالَنَهَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنْ يُنْتَبَذَ فِي الدُّبَّاءِ وَالْمُزَفَّتِهَذَا حَدِيثُ جَرِيرٍ وَفِي حَدِيثِ عَبْثَرٍ وَشُعْبَةَ أَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَهَى عَنْ الدُّبَّاءِ وَالْمُزَفَّتِ","id":"Telah menceritakan kepada kami [Sa'id bin 'Amru Al Asy'atsi] telah mengabarkan kepada kami ['Abtsar]. (dalam jalur lain disebutkan) Telah menceritakan kepadaku [Zuhair bin Harb] telah menceritakan kepada kami [Jarir]. (dalam jalur lain disebutkan) Telah menceritakan kepadaku [Bisyr bin Khalid] telah mengabarkan kepada kami [Muhammad] -yaitu Ibnu Ja'far- dari [Syu'bah] semuanya dari [Al A'masy] dari [Ibrahim At Taimi] dari [Al Harits bin Suwaid] dari [Ali] dia berkata, \"Rasulullah shallallahu 'alaihi wasallam melarang membuat perasan dalam Ad Dubba dan Al Muzaffat.\" Ini adalah hadits riwayat Jarir, dan dalam hadits 'Abtsar dan Syu'bah disebutkan, bahwa Nabi shallallahu 'alaihi wasallam melarang dari Ad Dubba dan Al Muzaffat.\" "},"3440":{"ar":"و حَدَّثَنَا سَعِيدُ بْنُ عَمْرٍو الْأَشْعَثِيُّ أَخْبَرَنَا عَبْثَرٌ عَنْ الْأَعْمَشِ عَنْ إِبْرَاهِيمَ عَنْ الْأَسْوَدِ عَنْ عَائِشَةَأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَهَى عَنْ الدُّبَّاءِ وَالْمُزَفَّتِو حَدَّثَنِي مُحَمَّدُ بْنُ حَاتِمٍ حَدَّثَنَا يَحْيَى وَهُوَ الْقَطَّانُ حَدَّثَنَا سُفْيَانُ وَشُعْبَةُ قَالَا حَدَّثَنَا مَنْصُورٌ وَسُلَيْمَانُ وَحَمَّادٌ عَنْ إِبْرَاهِيمَ عَنْ الْأَسْوَدِ عَنْ عَائِشَةَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِمِثْلِهِ","id":"Dan telah menceritakan kepada kami [Sa'id bin 'Amru Al Asy'atsi] telah mengabarkan kepada kami ['Abtsar] dari [Al A'masy] dari [Ibrahim] dari [Al Aswad] dari ['Aisyah], bahwa Nabi shallallahu 'alaihi wasallam melarang Ad Dubba dan Al Muzaffat.\" Dan telah menceritakan kepadaku [Muhammad bin Hatim] telah menceritakan kepada kami [Yahya yaitu Al Qathan] telah menceritakan kepada kami [Sufyan] dan [Syu'bah] keduanya berkata; telah menceritakan kepada kami [Manshur] dan [Sulaiman] dan [Hammad] dari [Ibrahim] dari [Al Aswad] dari ['Aisyah] dari Nabi shallallahu 'alaihi wasallam seperti hadits di atas.\" "},"3441":{"ar":"حَدَّثَنَا شَيْبَانُ بْنُ فَرُّوخَ حَدَّثَنَا الْقَاسِمُ يَعْنِي ابْنَ الْفَضْلِ حَدَّثَنَا ثُمَامَةُ بْنُ حَزْنٍ الْقُشَيْرِيُّ قَالَلَقِيتُ عَائِشَةَ فَسَأَلْتُهَا عَنْ النَّبِيذِ فَحَدَّثَتْنِي أَنَّ وَفْدَ عَبْدِ الْقَيْسِ قَدِمُوا عَلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَسَأَلُوا النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ النَّبِيذِ فَنَهَاهُمْ أَنْ يَنْتَبِذُوا فِي الدُّبَّاءِ وَالنَّقِيرِ وَالْمُزَفَّتِ وَالْحَنْتَمِ","id":"Telah menceritakan kepada kami [Syaiban bin Farruh] telah menceritakan kepada kami [Al Qasim] -yaitu Ibnu Al Fadll- telah menceritakan kepada kami [Tsumamah bin Hazn Al Qusyairi] dia berkata, \"Saya pernah bertemu ['Aisyah], lalu saya bertanya kepadanya mengenai perasan nabidz. Lantas dia menceritakan kepadaku bahwa suatu ketika utusan Abdul Qais datang kepada Nabi shallallahu 'alaihi wasallam sambil bertanya kepada Nabi shallallahu 'alaihi wasallam mengenai perasan nabidz, maka beliau melarang mereka membuat perasan dalam Ad Dubba, An Naqir, Al Muzaffat dan Al Hantam.\" "},"3442":{"ar":"و حَدَّثَنَا يَعْقُوبُ بْنُ إِبْرَاهِيمَ حَدَّثَنَا ابْنُ عُلَيَّةَ حَدَّثَنَا إِسْحَقُ بْنُ سُوَيْدٍ عَنْ مُعَاذَةَ عَنْ عَائِشَةَ قَالَتْنَهَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ الدُّبَّاءِ وَالْحَنْتَمِ وَالنَّقِيرِ وَالْمُزَفَّتِو حَدَّثَنَاه إِسْحَقُ بْنُ إِبْرَاهِيمَ أَخْبَرَنَا عَبْدُ الْوَهَّابِ الثَّقَفِيُّ حَدَّثَنَا إِسْحَقُ بْنُ سُوَيْدٍ بِهَذَا الْإِسْنَادِ إِلَّا أَنَّهُ جَعَلَ مَكَانَ الْمُزَفَّتِ الْمُقَيَّرَ","id":"Dan telah menceritakan kepada kami [Ya'qub bin Ibrahim] telah menceritakan kepada kami [Ibnu Ulayyah] telah menceritakan kepada kami [Ishaq bin Suwaid] dari [Mu'adzah] dari ['Aisyah] dia berkata, \"Rasulullah shallallahu 'alaihi wasallam melarang Ad Duba, Al Hantam, An Naqir dan Al Muzaffat.\" Telah menceritakan kepada kami [Ishaq bin Ibrahim] telah mengabarkan kepada kami [Abdul Wahhab At Tsaqafi] telah menceritakan kepada kami [Ishaq bin Suwaid] dengan isnad ini, hanya saja lafadz Al Muzaffat menjadi Al Muqayyar.\" "},"3443":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا عَلِيُّ بْنُ مُسْهِرٍ عَنْ الشَّيْبَانِيِّ عَنْ حَبِيبٍ عَنْ سَعِيدِ بْنِ جُبَيْرٍ عَنْ ابْنِ عَبَّاسٍ قَالَنَهَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ الدُّبَّاءِ وَالْحَنْتَمِ وَالْمُزَفَّتِ وَالنَّقِيرِ","id":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] telah menceritakan kepada kami [Ali bin Mushir] dari [As Syaibani] dari [Habib] dari [Sa'id bin Jubair] dari [Ibnu Abbas] dia berkata, \"Rasulullah shallallahu 'alaihi wasallam melarang Ad Dubba, Al Hantam, Al Muzaffat dan An Naqir.\" "},"3444":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا مُحَمَّدُ بْنُ فُضَيْلٍ عَنْ حَبِيبِ بْنِ أَبِي عَمْرَةَ عَنْ سَعِيدِ بْنِ جُبَيْرٍ عَنْ ابْنِ عَبَّاسٍ قَالَنَهَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ الدُّبَّاءِ وَالْحَنْتَمِ وَالْمُزَفَّتِ وَالنَّقِيرِ وَأَنْ يُخْلَطَ الْبَلَحُ بِالزَّهْوِ","id":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] telah menceritakan kepada kami [Muhammad bin Fudlail] dari [Habib bin Abu 'Amrah] dari [Sa'id bin Jubair] dari [Ibnu Abbas] dia berkata, \"Rasulullah shallallahu 'alaihi wasallam melarang dari Ad Dubba, Al Hantam, Al Muzaffat dan An Naqir. Beliau juga melarang membuat perasan dengan mencampur antara kurma muda dengan kurma masak.\" "},"3445":{"ar":"حَدَّثَنَا يَحْيَى بْنُ يَحْيَى قَالَ قَرَأْتُ عَلَى مَالِكٍ عَنْ ابْنِ شِهَابٍ عَنْ أَبِي سَلَمَةَ بْنِ عَبْدِ الرَّحْمَنِ عَنْ عَائِشَةَ قَالَتْسُئِلَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ الْبِتْعِ فَقَالَ كُلُّ شَرَابٍ أَسْكَرَ فَهُوَ حَرَامٌ","id":"Telah menceritakan kepada kami [Yahya bin Yahya] dia berkata; saya bacakan di hadapan [Malik]; dari [Ibnu Syihab] dari [Abu Salamah bin Abdurrahman] dari ['Aisyah] dia berkata, \"Rasulullah shallallahu 'alaihi wasallam ditanya mengenai bit'u (yaitu minuman yang terbuat dari madu) maka beliau bersabda: \"Setiap minuman yang memabukkan adalah haram.\""},"3446":{"ar":"و حَدَّثَنِي حَرْمَلَةُ بْنُ يَحْيَى التُّجِيبِيُّ أَخْبَرَنَا ابْنُ وَهْبٍ أَخْبَرَنِي يُونُسُ عَنْ ابْنِ شِهَابٍ عَنْ أَبِي سَلَمَةَ بْنِ عَبْدِ الرَّحْمَنِ أَنَّهُ سَمِعَ عَائِشَةَ تَقُولُسُئِلَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ الْبِتْعِ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كُلُّ شَرَابٍ أَسْكَرَ فَهُوَ حَرَامٌحَدَّثَنَا يَحْيَى بْنُ يَحْيَى وَسَعِيدُ بْنُ مَنْصُورٍ وَأَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ وَعَمْرٌو النَّاقِدُ وَزُهَيْرُ بْنُ حَرْبٍ كُلُّهُمْ عَنْ ابْنِ عُيَيْنَةَ ح و حَدَّثَنَا حَسَنٌ الْحُلْوَانِيُّ وَعَبْدُ بْنُ حُمَيْدٍ عَنْ يَعْقُوبَ بْنِ إِبْرَاهِيمَ بْنِ سَعْدٍ حَدَّثَنَا أَبِي عَنْ صَالِحٍ ح و حَدَّثَنَا إِسْحَقُ بْنُ إِبْرَاهِيمَ وَعَبْدُ بْنُ حُمَيْدٍ قَالَا أَخْبَرَنَا عَبْدُ الرَّزَّاقِ أَخْبَرَنَا مَعْمَرٌ كُلُّهُمْ عَنْ الزُّهْرِيِّ بِهَذَا الْإِسْنَادِ وَلَيْسَ فِي حَدِيثِ سُفْيَانَ وَصَالِحٍ سُئِلَ عَنْ الْبِتْعِ وَهُوَ فِي حَدِيثِ مَعْمَرٍ وَفِي حَدِيثِ صَالِحٍ أَنَّهَا سَمِعَتْ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ كُلُّ شَرَابٍ مُسْكِرٍ حَرَامٌ","id":"Dan telah menceritakan kepada kami [Harmalah bin Yahya At Tujibi] telah mengabarkan kepada kami [Ibnu Wahb] telah mengabarkan kepadaku [Yunus] dari [Ibnu Syihab] dari [Abu Salamah bin Abdurrahman] bahwa dia mendengar ['Aisyah] berkata, \"Rasulullah shallallahu 'alaihi wasallam ditanya mengenai bit'u, maka Rasulullah shallallahu 'alaihi wasallam menjawab: \"Setiap minuman yang memabukkan adalah haram.\" Telah menceritakan kepada kami [Yahya bin Yahya] dan [Sa'id bin Manshur] dan [Abu Bakar bin Abi Syaibah] dan [Amru An Naqid] dan [Zuhair bin Harb] semuanya dari [Ibnu 'Uyainah]. (dalam jalur lain disebutkan) Telah menceritakan kepada kami [Hasan Al Khulwani] dan ['Abd bin Humaid] dari [Ya'qub bin Ibrahim bin Sa'd] telah menceritakan kepada kami [Ayahku] dari [Shalih]. (dalam jalur lain disebutkan) Telah menceritakan kepada kami [Ishaq bin Ibrahim] dan [Abdu bin Humaid] keduanya berkata; telah mengabarkan kepada kami [Abdurrazaq] telah mengabarkan kepada kami [Ma'mar] semuanya dari [Az Zuhri] dengan sanad ini, namun dalam hadits Sufyan dan Shalih tidak disebutkan, 'Beliau ditanya mengenai bit'u', akan tetapi hal itu terdapat dalam hadits Ma'mar. Dan dalam hadits Shalih bahwa 'Aisyah mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Setiap minuman yang memabukkan adalah haram.\""},"3447":{"ar":"و حَدَّثَنَا قُتَيْبَةُ بْنُ سَعِيدٍ وَإِسْحَقُ بْنُ إِبْرَاهِيمَ وَاللَّفْظُ لِقُتَيْبَةَ قَالَا حَدَّثَنَا وَكِيعٌ عَنْ شُعْبَةَ عَنْ سَعِيدِ بْنِ أَبِي بُرْدَةَ عَنْ أَبِيهِ عَنْ أَبِي مُوسَى قَالَبَعَثَنِي النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَا وَمُعَاذَ بْنَ جَبَلٍ إِلَى الْيَمَنِ فَقُلْتُ يَا رَسُولَ اللَّهِ إِنَّ شَرَابًا يُصْنَعُ بِأَرْضِنَا يُقَالُ لَهُ الْمِزْرُ مِنْ الشَّعِيرِ وَشَرَابٌ يُقَالُ لَهُ الْبِتْعُ مِنْ الْعَسَلِ فَقَالَ كُلُّ مُسْكِرٍ حَرَامٌ","id":"Dan telah menceritakan kepada kami [Qutaibah bin Sa'id] dan [Ishaq bin Ibrahim] dan ini adalah lafadz Qutaibah, keduanya berkata; telah menceritakan kepada kami [Waki'] dari [Syu'bah] dari [Sa'id bin Abi Burdah] dari [Ayahnya] dari [Abu Musa] dia berkata, \"Nabi shallallahu 'alaihi wasallam mengutusku bersama Mu'adz bin Jabal ke Negeri Yaman, lalu saya berkata, \"Wahai Rasulullah, bagaimana dengan minuman yang dibuat di negeri kami yang biasa disebut dengan miizr dari (perasan) gandum dan minuman yang biasa disebut dengan bit'u (yang terbuat) dari madu?\" Beliau menjawab: \"Setiap minuman yang memabukkan adalah haram.\""},"3448":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ عَبَّادٍ حَدَّثَنَا سُفْيَانُ عَنْ عَمْرٍو سَمِعَهُ مِنْ سَعِيدِ بْنِ أَبِي بُرْدَةَ عَنْ أَبِيهِ عَنْ جَدِّهِأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بَعَثَهُ وَمُعَاذًا إِلَى الْيَمَنِ فَقَالَ لَهُمَا بَشِّرَا وَيَسِّرَا وَعَلِّمَا وَلَا تُنَفِّرَا وَأُرَاهُ قَالَ وَتَطَاوَعَا قَالَ فَلَمَّا وَلَّى رَجَعَ أَبُو مُوسَى فَقَالَ يَا رَسُولَ اللَّهِ إِنَّ لَهُمْ شَرَابًا مِنْ الْعَسَلِ يُطْبَخُ حَتَّى يَعْقِدَ وَالْمِزْرُ يُصْنَعُ مِنْ الشَّعِيرِ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كُلُّ مَا أَسْكَرَ عَنْ الصَّلَاةِ فَهُوَ حَرَامٌ","id":"Telah menceritakan kepada kami [Muhammad bin 'Abbad] telah menceritakan kepada kami [Sufyan] dari ['Amru] ia mendengar dari [Sa'id bin Abu Burdah] dari [ayahnya] dari [kakeknya], bahwa Nabi shallallahu 'alaihi wasallam mengutusnya bersama Mu'adz ke negeri Yaman, lalu beliau bersabda kepada keduanya: \"Berilah kabar gembira dan mudahkanlah setiap urusannya, ajarilah dan jangan kamu membuatnya lari.\" Dan sepertinya beliau juga bersabda: \"Dan janganlah kalian berdua saling berselisih.\" Ketika Abu Musa kembali, maka dia berkata, \"Wahai Rasulullah, sesungguhnya mereka (penduduk Yaman) terbiasa membuat minuman dari madu yang direbus hingga mengental dan minuman keras yang terbuat dari tepung?\" Maka Rasulullah shallallahu 'alaihi wasallam bersabda: \"Setiap sesuatu yang memabukkan (menghalangi dari) shalat, maka hukumnya haram.\""},"3449":{"ar":"و حَدَّثَنَا إِسْحَقُ بْنُ إِبْرَاهِيمَ وَمُحَمَّدُ بْنُ أَحْمَدَ بْنِ أَبِي خَلَفٍ وَاللَّفْظُ لِابْنِ أَبِي خَلَفٍ قَالَا حَدَّثَنَا زَكَرِيَّاءُ بْنُ عَدِيٍّ حَدَّثَنَا عُبَيْدُ اللَّهِ وَهُوَ ابْنُ عَمْرٍو عَنْ زَيْدِ بْنِ أَبِي أُنَيْسَةَ عَنْ سَعِيدِ بْنِ أَبِي بُرْدَةَ حَدَّثَنَا أَبُو بُرْدَةَ عَنْ أَبِيهِ قَالَبَعَثَنِي رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَمُعَاذًا إِلَى الْيَمَنِ فَقَالَ ادْعُوَا النَّاسَ وَبَشِّرَا وَلَا تُنَفِّرَا وَيَسِّرَا وَلَا تُعَسِّرَا قَالَ فَقُلْتُ يَا رَسُولَ اللَّهِ أَفْتِنَا فِي شَرَابَيْنِ كُنَّا نَصْنَعُهُمَا بِالْيَمَنِ الْبِتْعُ وَهُوَ مِنْ الْعَسَلِ يُنْبَذُ حَتَّى يَشْتَدَّ وَالْمِزْرُ وَهُوَ مِنْ الذُّرَةِ وَالشَّعِيرِ يُنْبَذُ حَتَّى يَشْتَدَّ قَالَ وَكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَدْ أُعْطِيَ جَوَامِعَ الْكَلِمِ بِخَوَاتِمِهِ فَقَالَ أَنْهَى عَنْ كُلِّ مُسْكِرٍ أَسْكَرَ عَنْ الصَّلَاةِ","id":"Telah menceritakan kepada kami [Ishaq bin Ibrahim] dan [Muhammad bin Ahmad bin Abu Khalaf] sedangkan lafadznya dari Ibnu Abu Khalaf, keduanya berkata; telah menceritakan kepada kami [Zakaria bin Adi] telah menceritakan kepada kami [Ubaidullah] dia adalah Ibnu Amru, dari [Zaid bin Abu Unaisah] dari [Sa'id bin Abu Burdah] telah menceritakan kepada kami [Abu Burdah] dari [ayahnya] dia berkata, \"Rasulullah shallallahu 'alaihi wasallam mengutusku bersama Mu'adz ke negeri Yaman, beliau bersabda: \"Serulah manusia dan berilah kabar gembira, jangan kamu buat mereka lari, mudahkan semua urusan dan jangan kamu persulit.\" Ayahku berkata, \"Lalu saya berkata, \"Wahai Rasulullah, berilah fatwa kepada kami mengenai minuman yang biasa kami buat di negeri Yaman, yaitu Al Bit'u, yang terbuat dari madu dengan merendamnya hingga mengental, dan minuman keras yaitu dari perasan gandum dan tepung.\" Ayahku berkata, \"Saat itu Rasulullah shallallahu 'alaihi wasallam baru selesai mendapatkan ayat Al Qur'an, maka beliau bersabda: \"Saya melarang dari setiap sesuatu yang memabukkan dan dapat menghalangi dari shalat.\""},"3450":{"ar":"حَدَّثَنَا قُتَيْبَةُ بْنُ سَعِيدٍ حَدَّثَنَا عَبْدُ الْعَزِيزِ يَعْنِي الدَّرَاوَرْدِيَّ عَنْ عُمَارَةَ بْنِ غَزِيَّةَ عَنْ أَبِي الزُّبَيْرِ عَنْ جَابِرٍأَنَّ رَجُلًا قَدِمَ مِنْ جَيْشَانَ وَجَيْشَانُ مِنْ الْيَمَنِ فَسَأَلَ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ شَرَابٍ يَشْرَبُونَهُ بِأَرْضِهِمْ مِنْ الذُّرَةِ يُقَالُ لَهُ الْمِزْرُ فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَوَ مُسْكِرٌ هُوَ قَالَ نَعَمْ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كُلُّ مُسْكِرٍ حَرَامٌ إِنَّ عَلَى اللَّهِ عَزَّ وَجَلَّ عَهْدًا لِمَنْ يَشْرَبُ الْمُسْكِرَ أَنْ يَسْقِيَهُ مِنْ طِينَةِ الْخَبَالِ قَالُوا يَا رَسُولَ اللَّهِ وَمَا طِينَةُ الْخَبَالِ قَالَ عَرَقُ أَهْلِ النَّارِ أَوْ عُصَارَةُ أَهْلِ النَّارِ","id":"Telah menceritakan kepada kami [Qutaibah bin Sa'id] telah menceritakan kepada kami [Abdul Aziz] -yaitu Ad Darawardi- dari ['Ummarah bin Ghaziyah] dari [Abu Az Zubair] dari [Jabir], bahwa seorang laki-laki tiba dari daerah Jaisyan, dan Jaisyan adalah daerah Yaman, lantas dia bertanya kepada Nabi shallallahu 'alaihi wasallam mengenai minuman yang biasa mereka minum di negeri mereka, yang terbuat dari perasan tepung yang biasa disebut Mizr. Maka Nabi shallallahu 'alaihi wasallam bersabda: \"Apakah ia memabukkan?\" dia menjawab, \"Ya.\" Rasulullah shallallahu 'alaihi wasallam lantas bersabda: \"Setiap yang memabukkan adalah haram, sesungguhnya Allah menjanjikan kepada siapa saja yang minum minuman memabukkan, maka akan memberinya minuman kepadanya Thinatul Khabal.\" Mereka bertanya, \"Wahai Rasulullah apa itu Thinatul Khabal?\" Beliau menjawab: \"Keringat penghuni neraka. atau perasan -keringat- penghuni neraka.\""},"3451":{"ar":"حَدَّثَنَا أَبُو الرَّبِيعِ الْعَتَكِيُّ وَأَبُو كَامِلٍ قَالَا حَدَّثَنَا حَمَّادُ بْنُ زَيْدٍ حَدَّثَنَا أَيُّوبُ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كُلُّ مُسْكِرٍ خَمْرٌ وَكُلُّ مُسْكِرٍ حَرَامٌ وَمَنْ شَرِبَ الْخَمْرَ فِي الدُّنْيَا فَمَاتَ وَهُوَ يُدْمِنُهَا لَمْ يَتُبْ لَمْ يَشْرَبْهَا فِي الْآخِرَةِ","id":"Telah menceritakan kepada kami [Abu Ar Rabi' Al 'Ataki] dan [Abu Kamil] keduanya berkata; telah menceritakan kepada kami [Hammad bin Zaid] telah menceritakan kepada kami [Ayyub] dari [Nafi'] dari [Ibnu Umar] dia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Setiap yang memabukkan adalah khamer, dan setiap yang memabukkan adalah haram. Barangsiapa meminum khamer di dunia -kemudian ia mati- sedangkan ia biasa meminumnya, niscaya tidak akan diterima taubatnya dan tidak akan meminumnya di akhirat.\""},"3452":{"ar":"و حَدَّثَنَا إِسْحَقُ بْنُ إِبْرَاهِيمَ وَأَبُو بَكْرِ بْنُ إِسْحَقَ كِلَاهُمَا عَنْ رَوْحِ بْنِ عُبَادَةَ حَدَّثَنَا ابْنُ جُرَيْجٍ أَخْبَرَنِي مُوسَى بْنُ عُقْبَةَ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ كُلُّ مُسْكِرٍ خَمْرٌ وَكُلُّ مُسْكِرٍ حَرَامٌو حَدَّثَنَا صَالِحُ بْنُ مِسْمَارٍ السُّلَمِيُّ حَدَّثَنَا مَعْنٌ حَدَّثَنَا عَبْدُ الْعَزِيزِ بْنُ الْمُطَّلِبِ عَنْ مُوسَى بْنِ عُقْبَةَ بِهَذَا الْإِسْنَادِ مِثْلَهُ","id":"Dan telah menceritakan kepada kami [Ishaq bin Ibrahim] dan [Abu Bakar bin Ishaq] keduanya dari [Rauh bin Ubadah] telah menceritakan kepada kami [Ibnu Juraij] telah mengabarkan kepadaku [Musa bin 'Uqbah] dari [Nafi'] dari [Ibnu Umar], bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Setiap yang memabukkan adalah khamer, dan setiap yang memabukkan adalah haram.\" Dan telah menceritakan kepada kami [Shalih bin Mismar As Sulami] telah menceritakan kepada kami [Ma'an] telah menceritakan kepada kami [Abdul Aziz bin Mutthalib] dari [Musa bin 'Uqbah] dengan isnad yang seperti ini.\""},"3453":{"ar":"و حَدَّثَنَا مُحَمَّدُ بْنُ الْمُثَنَّى وَمُحَمَّدُ بْنُ حَاتِمٍ قَالَا حَدَّثَنَا يَحْيَى وَهُوَ الْقَطَّانُ عَنْ عُبَيْدِ اللَّهِ أَخْبَرَنَا نَافِعٌ عَنْ ابْنِ عُمَرَ قَالَ وَلَا أَعْلَمُهُ إِلَّاعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ كُلُّ مُسْكِرٍ خَمْرٌ وَكُلُّ خَمْرٍ حَرَامٌ","id":"Telah menceritakan kepada kami [Muhammad bin Mutsanna] dan [Muhammad bin Hatim] keduanya berkata; telah menceritakan kepada kami [Yahya] -yaitu Al Qatthan- dari [Ubaidullah] telah mengabarkan kepada kami [Nafi'] dari [Ibnu Umar] dia berkata -dan saya tidak mengetahuinya kecuali dari Nabi shallallahu 'alaihi wasallam-, beliau bersabda: \"Setiap yang memabukkan adalah khamer dan setiap khamer adalah haram.\""},"3454":{"ar":"حَدَّثَنَا يَحْيَى بْنُ يَحْيَى قَالَ قَرَأْتُ عَلَى مَالِكٍ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ شَرِبَ الْخَمْرَ فِي الدُّنْيَا حُرِمَهَا فِي الْآخِرَةِ","id":"Telah menceritakan kepada kami [Yahya bin Yahya] dia berkata; saya bacakan di hadapan [Malik]; dari [Nafi'] dari [Ibnu Umar] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa meminum khamer di dunia, maka diharamkan baginya di akhirat.\""},"3455":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ مَسْلَمَةَ بْنِ قَعْنَبٍ حَدَّثَنَا مَالِكٌ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَ قَالَمَنْ شَرِبَ الْخَمْرَ فِي الدُّنْيَا فَلَمْ يَتُبْ مِنْهَا حُرِمَهَا فِي الْآخِرَةِ فَلَمْ يُسْقَهَاقِيلَ لِمَالِكٍ رَفَعَهُ قَالَ نَعَمْ","id":"Telah menceritakan kepada kami [Abdullah bin Maslamah bin Qa'nab] telah menceritakan kepada kami [Malik] dari [Nafi'] dari [Ibnu Umar] dia berkata, \"Barangsiapa meminum khamer di dunia dan tidak bertaubat, maka diharamkan baginya di akhirat kelak dan tidak akan diberi minum dengannya.\" Dikatakan kepada Malik, \"Apakah (riwayat ini) dimarfu'kan (bersambung sampai kepada Nabi shallallahu 'alaihi wasallam)?\" dia menjawab, \"Ya.\""},"3456":{"ar":"و حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ نُمَيْرٍ ح و حَدَّثَنَا ابْنُ نُمَيْرٍ حَدَّثَنَا أَبِي حَدَّثَنَا عُبَيْدُ اللَّهِ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ شَرِبَ الْخَمْرَ فِي الدُّنْيَا لَمْ يَشْرَبْهَا فِي الْآخِرَةِ إِلَّا أَنْ يَتُوبَو حَدَّثَنَا ابْنُ أَبِي عُمَرَ حَدَّثَنَا هِشَامٌ يَعْنِي ابْنَ سُلَيْمَانَ الْمَخْزُومِيَّ عَنْ ابْنِ جُرَيْجٍ أَخْبَرَنِي مُوسَى بْنُ عُقْبَةَ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِمِثْلِ حَدِيثِ عُبَيْدِ اللَّهِ","id":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] telah menceritakan kepada kami [Abdullah bin Numair]. (dalam jalur lain disebutkan) Telah menceritakan kepada kami [Ibnu Numair] telah menceritakan kepada kami [ayahku] telah menceritakan kepada kami [Ubaidullah] dari [Nafi'] dari [Ibnu Umar], bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa meminum khamer di dunia, maka ia tidak akan meminumnya di akhirat kecuali jika ia bertaubat.\" Dan telah menceritakan kepada kami [Ibnu Abi Umar] telah menceritakan kepada kami [Hisyam] -yaitu Ibnu Sulaiman Al Mahzumi- dari [Ibnu Juraij] telah mengabarkan kepadaku [Musa bin Uqbah] dari [Nafi'] dari [Ibnu Umar] dari Nabi shallallahu 'alaihi wasallam seperti hadits Ubaidullah.\""},"3457":{"ar":"حَدَّثَنَا عُبَيْدُ اللَّهِ بْنُ مُعَاذٍ الْعَنْبَرِيُّ حَدَّثَنَا أَبِي حَدَّثَنَا شُعْبَةُ عَنْ يَحْيَى بْنِ عُبَيْدٍ أَبِي عُمَرَ الْبَهْرَانِيِّ قَالَ سَمِعْتُ ابْنَ عَبَّاسٍ يَقُولُاكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُنْتَبَذُ لَهُ أَوَّلَ اللَّيْلِ فَيَشْرَبُهُ إِذَا أَصْبَحَ يَوْمَهُ ذَلِكَ وَاللَّيْلَةَ الَّتِي تَجِيءُ وَالْغَدَ وَاللَّيْلَةَ الْأُخْرَى وَالْغَدَ إِلَى الْعَصْرِ فَإِنْ بَقِيَ شَيْءٌ سَقَاهُ الْخَادِمَ أَوْ أَمَرَ بِهِ فَصُبَّ","id":"Telah menceritakan kepada kami [Ubaidullah bin Mu'adz Al Anbari] telah menceritakan kepada kami [ayahku] telah menceritakan kepada kami [Syu'bah] dari [Yahya bin Ubaid Abu Umar Al Bahrani] dia berkata; saya mendengar [Ibnu Abbas] berkata, \"Rasulullah shallallahu 'alaihi wasallam dibuatkan perasan nabidz di awal malam, kemudian beliau meminumnya di pagi harinya, kemudian malam harinya, kemudian lusa dan malam harinya serta keesokan harinya lagi sampai menjelang ashar. Jika perasannya tersebut masih, beliau memerintahkan pelayannya untuk menumpahkannya, atau menyuruhnya untuk ditumpahkan.\""},"3458":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ حَدَّثَنَا شُعْبَةُ عَنْ يَحْيَى الْبَهْرَانِيِّ قَالَذَكَرُوا النَّبِيذَ عِنْدَ ابْنِ عَبَّاسٍ فَقَالَ كَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُنْتَبَذُ لَهُ فِي سِقَاءٍ قَالَ شُعْبَةُ مِنْ لَيْلَةِ الِاثْنَيْنِ فَيَشْرَبُهُ يَوْمَ الِاثْنَيْنِ وَالثُّلَاثَاءِ إِلَى الْعَصْرِ فَإِنْ فَضَلَ مِنْهُ شَيْءٌ سَقَاهُ الْخَادِمَ أَوْ صَبَّهُ","id":"Telah mengabarkan kepada kami [Muhammad bin Basysyar] telah menceritakan kepada kami [Muhammad bin Ja'far] telah menceritakan kepada kami [Syu'bah] dari [Yahya Al Bahrani] dia berkata, \"Mereka menyebut-nyebut nabidz (perasan buah) di sisi [Ibnu Abbas], lantas dia berkata, \"Rasulullah shallallahu 'alaihi wasallam biasa dibuatkan perasan dalam wadah air minum -Syu'bah berkata; dari malam senin-, kemudian beliau meminumnya pada hari senin dan selasa sampai ashar, jika masih terdapat perasan yang tersisa, maka beliau menyuruh pelayannya untuk menumpahkan.\""},"3459":{"ar":"و حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ وَأَبُو كُرَيْبٍ وَإِسْحَقُ بْنُ إِبْرَاهِيمَ وَاللَّفْظُ لِأَبِي بَكْرٍ وَأَبِي كُرَيْبٍ قَالَ إِسْحَقُ أَخْبَرَنَا و قَالَ الْآخَرَانِ حَدَّثَنَا أَبُو مُعَاوِيَةَ عَنْ الْأَعْمَشِ عَنْ أَبِي عُمَرَ عَنْ ابْنِ عَبَّاسٍ قَالَكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُنْقَعُ لَهُ الزَّبِيبُ فَيَشْرَبُهُ الْيَوْمَ وَالْغَدَ وَبَعْدَ الْغَدِ إِلَى مَسَاءِ الثَّالِثَةِ ثُمَّ يَأْمُرُ بِهِ فَيُسْقَى أَوْ يُهَرَاقُ","id":"Dan telah menceritakan kepada kami [Abu Bakar bin Abi Syaibah] dan [Abu Kuraib] dan [Ishaq bin Ibrahim] sedangkan lafadz dari Abu Bakar dan Abu Kuraib. Ishaq berkata; telah mengabarkan kepada kami, sedangkan yang kedua berkata; telah menceritakan kepada kami [Abu Mu'awiyah] dari [Al A'masy] dari [Abu Umar] dari [Ibnu Abbas] dia berkata, \"Rasulullah shallallahu 'alaihi wasallam biasa dibuatkan perasan zabib (buah kismis), kemudian beliau meminumnya pada hari itu, esok hari dan lusa sampai sore di hari ketiga. Kemudian beliau menyuruh untuk membuangnya atau menumpahkannya.\""},"3460":{"ar":"و حَدَّثَنَا إِسْحَقُ بْنُ إِبْرَاهِيمَ أَخْبَرَنَا جَرِيرٌ عَنْ الْأَعْمَشِ عَنْ يَحْيَى بْنِ أَبِي عُمَرَ عَنْ ابْنِ عَبَّاسٍ قَالَكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُنْبَذُ لَهُ الزَّبِيبُ فِي السِّقَاءِ فَيَشْرَبُهُ يَوْمَهُ وَالْغَدَ وَبَعْدَ الْغَدِ فَإِذَا كَانَ مَسَاءُ الثَّالِثَةِ شَرِبَهُ وَسَقَاهُ فَإِنْ فَضَلَ شَيْءٌ أَهَرَاقَهُ","id":"Telah menceritakan kepada kami [Ishaq bin Ibrahim] telah mengabarkan kepada kami [Jarir] dari [Al A'masy] dari [Yahya bin Abi Umar] dari [Ibnu Abbas] dia berkata, \"Rasulullah shallallahu 'alaihi wasallam biasa dibuatkan perasan zabib dalam wadah air minum, kemudian beliau meminumnya pada hari itu, esok harinya dan lusa, pada waktu sore di hari ketiga beliau masih menuangkan dan meminumnya, tapi jika masih juga tersisa maka beliau menumpahkannya.\""},"3461":{"ar":"و حَدَّثَنِي مُحَمَّدُ بْنُ أَحْمَدَ بْنِ أَبِي خَلَفٍ حَدَّثَنَا زَكَرِيَّاءُ بْنُ عَدِيٍّ حَدَّثَنَا عُبَيْدُ اللَّهِ عَنْ زَيْدٍ عَنْ يَحْيَى أَبِي عُمَرَ النَّخَعِيِّ قَالَ سَأَلَ قَوْمٌ ابْنَ عَبَّاسٍ عَنْ بَيْعِ الْخَمْرِ وَشِرَائِهَا وَالتِّجَارَةِ فِيهَا فَقَالَ أَمُسْلِمُونَ أَنْتُمْ قَالُوا نَعَمْ قَالَ فَإِنَّهُ لَا يَصْلُحُ بَيْعُهَا وَلَا شِرَاؤُهَا وَلَا التِّجَارَةُ فِيهَا قَالَ فَسَأَلُوهُ عَنْ النَّبِيذِ فَقَالَخَرَجَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي سَفَرٍ ثُمَّ رَجَعَ وَقَدْ نَبَذَ نَاسٌ مِنْ أَصْحَابِهِ فِي حَنَاتِمَ وَنَقِيرٍ وَدُبَّاءٍ فَأَمَرَ بِهِ فَأُهْرِيقَ ثُمَّ أَمَرَ بِسِقَاءٍ فَجُعِلَ فِيهِ زَبِيبٌ وَمَاءٌ فَجُعِلَ مِنْ اللَّيْلِ فَأَصْبَحَ فَشَرِبَ مِنْهُ يَوْمَهُ ذَلِكَ وَلَيْلَتَهُ الْمُسْتَقْبَلَةَ وَمِنْ الْغَدِ حَتَّى أَمْسَى فَشَرِبَ وَسَقَى فَلَمَّا أَصْبَحَ أَمَرَ بِمَا بَقِيَ مِنْهُ فَأُهْرِيقَ","id":"Dan telah menceritakan kepadaku [Muhammad bin Ahmad bin Abi Khalaf] telah menceritakan kepada kami [Zakaria bin Adi] telah menceritakan kepada kami ['Ubaidullah] dari [Zaid] dari [Yahya Abu Umar An Nakha'i] dia berkata, \"Suatu kaum bertanya kepada [Ibnu Abbas] tentang memperdagangkan khamer; membeli dan menjualnya lagi. Maka dia balik bertanya, \"Apakah kalian orang-orang muslim?\" Mereka menjawab, \"Ya, benar.\" Dia berkata, \"Sesungguhnya tidak boleh memperdagangkan khamer; membelinya dan menjualnya.\" Yahya berkata, \"Kemudian mereka bertanya mengenai Nabidz (minuman yang terbuat dari perasan buah), maka Ibnu Abbas berkata, \"Rasulullah shallallahu 'alaihi wasallam pernah keluar kota kemudian beliau kembali pulang, ternyata sebagian dari para sahabat beliau sedang membuat perasan di dalam Al Khantam, An Naqir dan Ad Dubba`, maka beliau menyuruh untuk menumpahkannya. Setelah itu, beliau membuat perasan dari buah anggur dan air, lalu membiarkannya hingga malam. Keesokan harinya beliau meminum perasan tersebut, lalu malam harinya, lalu keesokan harinya lagi dan lusa hingga waktu sampai sore. Dan apabila di pagi harinya perasan tersebut masih tersisa, maka beliau memerintahkan untuk menumpahkannya.\""},"3462":{"ar":"حَدَّثَنَا شَيْبَانُ بْنُ فَرُّوخَ حَدَّثَنَا الْقَاسِمُ يَعْنِي ابْنَ الْفَضْلِ الْحُدَّانِيَّ حَدَّثَنَا ثُمَامَةُ يَعْنِي ابْنَ حَزْنٍ الْقُشَيْرِيَّ قَالَلَقِيتُ عَائِشَةَ فَسَأَلْتُهَا عَنْ النَّبِيذِ فَدَعَتْ عَائِشَةُ جَارِيَةً حَبَشِيَّةً فَقَالَتْ سَلْ هَذِهِ فَإِنَّهَا كَانَتْ تَنْبِذُ لِرَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَتْ الْحَبَشِيَّةُ كُنْتُ أَنْبِذُ لَهُ فِي سِقَاءٍ مِنْ اللَّيْلِ وَأُوكِيهِ وَأُعَلِّقُهُ فَإِذَا أَصْبَحَ شَرِبَ مِنْهُ","id":"Telah menceritakan kepada kami [Syaiban bin Farruh] telah menceritakan kepada kami [Al Qasim] -yaitu Ibnu Fadl Al Huddani- telah menceritakan kepada kami [Tsumamah] -yaitu Ibnu Hazn Al Qusyairi- dia berkata; saya menemui ['Aisyah] dan menanyakan kepadanya mengenai nabidz, lantas 'Aisyah memanggil pelayannya dari negeri Habsyi. 'Aisyah lantas berkata, \"Tanyakanlah kepadanya, karena dialah yang biasa membuatkan perasan untuk Rasulullah shallallahu 'alaihi wasallam, lantas [pelayan dari negeri Habsyi] itu menjawab, \"Saya biasa membuatkan perasan untuk beliau dalam wadah air minum, kemudian saya mengikatnya dan menggantungkannya, lalu beliau meminumnya ketika datang waktu pagi.\""},"3463":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ الْمُثَنَّى الْعَنَزِيُّ حَدَّثَنَا عَبْدُ الْوَهَّابِ الثَّقَفِيُّ عَنْ يُونُسَ عَنْ الْحَسَنِ عَنْ أُمِّهِ عَنْ عَائِشَةَ قَالَتْكُنَّا نَنْبِذُ لِرَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي سِقَاءٍ يُوكَى أَعْلَاهُ وَلَهُ عَزْلَاءُ نَنْبِذُهُ غُدْوَةً فَيَشْرَبُهُ عِشَاءً وَنَنْبِذُهُ عِشَاءً فَيَشْرَبُهُ غُدْوَةً","id":"Telah menceritakan kepada kami [Muhammad bin Mutsanna Al Anazi] telah menceritakan kepada kami [Abdul Wahhab Ats Tsaqafi] dari [Yunus] dari [Al Hasan] dari [Ibunya] dari ['Aisyah] dia berkata, \"Kami biasa membuat perasan untuk Rasulullah shallallahu 'alaihi wasallam di dalam air minum yang bertali di atasnya, kami membuat rendaman di pagi hari dan meminumnya di sore hari, atau membuat rendaman di sore hari lalu meminumnya di pagi hari.\""},"3464":{"ar":"حَدَّثَنَا قُتَيْبَةُ بْنُ سَعِيدٍ حَدَّثَنَا عَبْدُ الْعَزِيزِ يَعْنِي ابْنَ أَبِي حَازِمٍ عَنْ أَبِي حَازِمٍ عَنْ سَهْلِ بْنِ سَعْدٍ قَالَدَعَا أَبُو أُسَيْدٍ السَّاعِدِيُّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي عُرْسِهِ فَكَانَتْ امْرَأَتُهُ يَوْم��ئِذٍ خَادِمَهُمْ وَهِيَ الْعَرُوسُ قَالَ سَهْلٌ تَدْرُونَ مَا سَقَتْ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنْقَعَتْ لَهُ تَمَرَاتٍ مِنْ اللَّيْلِ فِي تَوْرٍ فَلَمَّا أَكَلَ سَقَتْهُ إِيَّاهُو حَدَّثَنَا قُتَيْبَةُ بْنُ سَعِيدٍ حَدَّثَنَا يَعْقُوبُ يَعْنِي ابْنَ عَبْدِ الرَّحْمَنِ عَنْ أَبِي حَازِمٍ قَالَ سَمِعْتُ سَهْلًا يَقُولُا أَتَى أَبُو أُسَيْدٍ السَّاعِدِيُّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَدَعَا رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِمِثْلِهِ وَلَمْ يَقُلْ فَلَمَّا أَكَلَ سَقَتْهُ إِيَّاهُ و حَدَّثَنِي مُحَمَّدُ بْنُ سَهْلٍ التَّمِيمِيُّ حَدَّثَنَا ابْنُ أَبِي مَرْيَمَ أَخْبَرَنَا مُحَمَّدٌ يَعْنِي أَبَا غَسَّانَ حَدَّثَنِي أَبُو حَازِمٍ عَنْ سَهْلِ بْنِ سَعْدٍ بِهَذَا الْحَدِيثِ وَقَالَ فِي تَوْرٍ مِنْ حِجَارَةٍ فَلَمَّا فَرَغَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِنْ الطَّعَامِ أَمَاثَتْهُ فَسَقَتْهُ تَخُصُّهُ بِذَلِكَ","id":"Telah menceritakan kepada kami [Qutaibah bin Sa'id] telah menceritakan kepada kami [Abdul Aziz] -yaitu Ibnu Abu Hazim- dari [Abu Hazim] dari [Sahal bin Sa'd] dia berkata, \"Abu Usaid As Sa'idi mengundang Rasulullah shallallahu 'alaihi wasallam di hari pernikahannya, Saat itu, isterinya membantu mereka, padahal ia adalah pengantin wanita.\" Sahl bertkata, \"Tahukah kalian minuman apa yang ia suguhkan olehnya (isterinya) kepada Rasulullah shallallahu 'alaihi wasallam?\" ia merendam kurma di dalam kuwali pada waktu malam, ketika beliau makan, ia memberikan minuman tersebut kepada beliau.\" Dan telah menceritakan kepada kami [Qutaibah bin Sa'id] telah menceritakan kepada kami [Ya'qub] -yaitu Ibnu Abdurrahman- dari [Abu Hazim] dia berkata; saya mendengar [Sahl] berkata, \"Abu Usaid As Sa'idi datang kepada Rasulullah shallallahu 'alaihi wasallam, lalu ia mengundang Rasulullah shallallahu 'alaihi wasallam…seperti hadits di atas, namun ia tidak menyebutkan, \"Ketika beliau makan, maka wanita itu menuangkannya kepada beliau.\" Dan telah menceritakan kepadaku [Muhammad bin Sahl At Tamimi] telah menceritakan kepada kami [Ibnu Abu Maryam] telah mengabarkan kepada kami [Muhammad] -yaitu Abu Ghassan- telah menceritakan kepadaku [Abu Hazim] dari [Sahl bin Sa'd] dengan hadits ini, ia menambahkan, \"…menuangkannya di kuwali yang terbuat dari tanah, seusai Rasulullah shallallahu 'alaihi wasallam makan, maka ia menuangkan minuman tersebut untuk beliau.\""},"3465":{"ar":"حَدَّثَنِي مُحَمَّدُ بْنُ سَهْلٍ التَّمِيمِيُّ وَأَبُو بَكْرِ بْنُ إِسْحَقَ قَالَ أَبُو بَكْرٍ أَخْبَرَنَا و قَالَ ابْنُ سَهْلٍ حَدَّثَنَا ابْنُ أَبِي مَرْيَمَ أَخْبَرَنَا مُحَمَّدٌ وَهُوَ ابْنُ مُطَرِّفٍ أَبُو غَسَّانَ أَخْبَرَنِي أَبُو حَازِمٍ عَنْ سَهْلِ بْنِ سَعْدٍ قَالَذُكِرَ لِرَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ امْرَأَةٌ مِنْ الْعَرَبِ فَأَمَرَ أَبَا أُسَيْدٍ أَنْ يُرْسِلَ إِلَيْهَا فَأَرْسَلَ إِلَيْهَا فَقَدِمَتْ فَنَزَلَتْ فِي أُجُمِ بَنِي سَاعِدَةَ فَخَرَجَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حَتَّى جَاءَهَا فَدَخَلَ عَلَيْهَا فَإِذَا امْرَأَةٌ مُنَكِّسَةٌ رَأْسَهَا فَلَمَّا كَلَّمَهَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَتْ أَعُوذُ بِاللَّهِ مِنْكَ قَالَ قَدْ أَعَذْتُكِ مِنِّي فَقَالُوا لَهَا أَتَدْرِينَ مَنْ هَذَا فَقَالَتْ لَا فَقَالُوا هَذَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ جَاءَكِ لِيَخْطُبَكِ قَالَتْ أَنَا كُنْتُ أَشْقَى مِنْ ذَلِكَ قَالَ سَهْلٌ فَأَقْبَلَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَوْمَئِذٍ حَتَّى جَلَسَ فِي سَقِيفَةِ بَنِي سَاعِدَةَ هُوَ وَأَصْحَابُهُ ثُمَّ قَالَ اسْقِنَا لِسَهْلٍ قَالَ فَأَخْرَجْتُ لَهُمْ ��َذَا الْقَدَحَ فَأَسْقَيْتُهُمْ فِيهِقَالَ أَبُو حَازِمٍ فَأَخْرَجَ لَنَا سَهْلٌ ذَلِكَ الْقَدَحَ فَشَرِبْنَا فِيهِ قَالَ ثُمَّ اسْتَوْهَبَهُ بَعْدَ ذَلِكَ عُمَرُ بْنُ عَبْدِ الْعَزِيزِ فَوَهَبَهُ لَهُ وَفِي رِوَايَةِ أَبِي بَكْرِ بْنِ إِسْحَقَ قَالَ اسْقِنَا يَا سَهْلُ","id":"Telah menceritakan kepadaku [Muhammad bin Sahl At Tamimi] dan [Abu Bakar bin Ishaq], Abu Bakar berkata; telah mengabarkan kepada kami, sedangkan Ibnu Sahl berkata; telah menceritakan kepada kami [Ibnu Abu Maryam] telah mengabarkan kepada kami [Muhammad] -yaitu Ibnu Mutharif Abu Ghassan- telah mengabarkan kepadaku [Abu Hazim] dari [Sahl bin Sa'd] dia berkata, \"Ketika dituturkan kepada Rasulullah shallallahu 'alaihi wasallam tentang cerita wanita Arab kampung, maka beliau pun memerintahkan Abu Usaid untuk memanggilnya. Tidak lama kemudian wanita itu datang dan tinggal di rumah Bani Sa'idah. Kemudian Rasulullah shallallahu 'alaihi wasallam keluar dan pergi menemui wanita tersebut, ternyata wanita itu selalu menundukkan kepalanya. Pada saat Rasulullah shallallahu 'alaihi wasallam mengajaknya bicara, wanita itu justru berkata, \"Saya berlindung kepada Allah darimu.\" Beliau menjawab: \"Baiklah, saya juga melindungimu dariku.\" Setelah itu para sahabat berkata kepadanya, \"Tahukah kamu siapakah orang yang mengajakmu bicara tadi?\" wanita itu menjawab, \"Tidak.\" Para sahabat berkata, \"Orang itu adalah Rasulullah shallallahu 'alaihi wasallam, beliau datang untuk melamarmu.\" Wanita itu berkata, \"Kalau begitu, saya termasuk orang yang tidak beruntung.\" Sahl berkata, \"Pada saat itu Rasulullah shallallahu 'alaihi wasallam datang dan duduk di bangsal Bani Sa'idah bersama dengan para sahabat. Kemudian beliau bersabda kepada Sahl: \"Berilah kami minuman.\" Sahl berkata, \"Lalu saya mengeluarkan mangkuk ini untuk mereka dan memberikan minuman kepada mereka dengan menggunakan mangkuk tersebut.\" Abu Hazim berkata, \"Kemudian Sahl mengeluarkan mangkuk tersebut untuk kami dan kami langsung meminumnya.\" Abu Hazim berkata, \"Selang beberapa tahun kemudian, Umar bin Abdul Aziz meminta mangkuk itu. Lalu mangkuk itu pun akhirnya diberikan kepadanya.\" Dan dalam riwayat Abu Bakar bin Ishaq disebutkan, \"Beliau bersabda: \"Hidangkanlah minuman buat kami wahai Sahl!.\""},"3466":{"ar":"و حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ وَزُهَيْرُ بْنُ حَرْبٍ قَالَا حَدَّثَنَا عَفَّانُ حَدَّثَنَا حَمَّادُ بْنُ سَلَمَةَ عَنْ ثَابِتٍ عَنْ أَنَسٍ قَالَلَقَدْ سَقَيْتُ رَسُولَ اللَّهِ بِقَدَحِي هَذَا الشَّرَابَ كُلَّهُ الْعَسَلَ وَالنَّبِيذَ وَالْمَاءَ وَاللَّبَنَ","id":"Dan telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] dan [Zuhair bin Harb] keduanya berkata; telah menceritakan kepada kami ['Affan] telah menceritakan kepada kami [Hammad bin Salamah] dari [Tsabit] dari [Anas] dia berkata, \"Sungguh saya pernah menuangkan minuman apa saja ke dalam gelasku (mangkuk) untuk Rasulullah shallallahu 'alaihi wasallam; madu, perasan nabidz (semacam arak), air dan susu.\""},"3467":{"ar":"حَدَّثَنَا عُبَيْدُ اللَّهِ بْنُ مُعَاذٍ الْعَنْبَرِيُّ حَدَّثَنَا أَبِي حَدَّثَنَا شُعْبَةُ عَنْ أَبِي إِسْحَقَ عَنْ الْبَرَاءِ قَالَ قَالَ أَبُو بَكْرٍ الصِّدِّيقُلَمَّا خَرَجْنَا مَعَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِنْ مَكَّةَ إِلَى الْمَدِينَةِ مَرَرْنَا بِرَاعٍ وَقَدْ عَطِشَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ فَحَلَبْتُ لَهُ كُثْبَةً مِنْ لَبَنٍ فَأَتَيْتُهُ بِهَا فَشَرِبَ حَتَّى رَضِيتُ","id":"Telah menceritakan kepada kami ['Ubaidullah bin Mu'adz Al 'Anbari] telah menceritakan kepada kami [ayahku] telah menceritakan kepada kami [Syu'bah] dari [Abu Ishaq] dari [Al Barra`] dia berkata, \" [Abu Bakar As Shidiq] berkata, \"Ketika kami keluar bersama-sama dengan Nabi shallallahu 'alaihi wasallam dari Makkah menuju Madinah, kami melewati seorang penggembala, ketika itu Rasulullah shallallahu 'alaihi wasallam sangat kehausan.\" Abu Bakar berkata, \"Lalu saya memeraskan untuk beliau sedikit dari air susu (kambing milik pengembala), kemudian saya membawanya ke hadapan beliau lalu beliau meminumnya sampai saya merasa puas.\""},"3468":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ الْمُثَنَّى وَابْنُ بَشَّارٍ وَاللَّفْظُ لِابْنِ الْمُثَنَّى قَالَا حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ حَدَّثَنَا شُعْبَةُ قَالَ سَمِعْتُ أَبَا إِسْحَقَ الْهَمْدَانِيَّ يَقُولُ سَمِعْتُ الْبَرَاءَ يَقُولَلَمَّا أَقْبَلَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِنْ مَكَّةَ إِلَى الْمَدِينَةِ فَأَتْبَعَهُ سُراقَةُ بْنُ مَالِكِ بْنِ جُعْشُمٍ قَالَ فَدَعَا عَلَيْهِ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَسَاخَتْ فَرَسُهُ فَقَالَ ادْعُ اللَّهَ لِي وَلَا أَضُرُّكَ قَالَ فَدَعَا اللَّهَ قَالَ فَعَطِشَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَمَرُّوا بِرَاعِي غَنَمٍ قَالَ أَبُو بَكْرٍ الصِّدِّيقُ فَأَخَذْتُ قَدَحًا فَحَلَبْتُ فِيهِ لِرَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كُثْبَةً مِنْ لَبَنٍ فَأَتَيْتُهُ بِهِ فَشَرِبَ حَتَّى رَضِيتُ","id":"Telah menceritakan kepada kami [Muhammad bin Al Mutsanna] dan [Ibnu Basysyar] sedangkan lafadznya dari Ibnu Mutsanna, keduanya berkata; telah menceritakan kepada kami [Muhammad bin Ja'far] telah menceritakan kepada kami [Syu'bah] dia berkata; saya mendengar [Abu Ishaq Al Hamdani] dia berkata; saya mendengar [Al Barra`] berkata, \"Ketika Rasulullah shallallahu 'alaihi wasallam berangkat dari kota Makkah menuju Madinah, Suraqah bin Malik bin Ju'syum mengejarnya dari belakang.\" Al Barra` mengatakan, \"Lalu Rasulullah shallallahu 'alaihi wasallam mendoakannya hingga kaki kudanya terperosok ke dalam tanah, Suraqah lalu berkata, \"Mohonkanlah kepada Allah agar saya dapat terlepas dari kecelakaan ini dan saya tidak akan mengganggu anda lagi.\" Al Barra` berkata, \"Lantas beliau berdo'a kepada Allah.\" Al Barra` melanjutkan ceritanya, \"Tidak lama kemudian Rasulullah shallallahu 'alaihi wasallam merasa kehausan dan kebetulan beliau melewati seorang penggembala kambing. Maka [Abu Bakar] berkata, \"Kemudian saya mengambil mangkuk dan memerah sedikit susu untuk Rasulullah shallallahu 'alaihi wasallam, lalu saya membawanya kepada beliau dan beliau pun meminumnya hingga saya merasa puas.\""},"3469":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ عَبَّادٍ وَزُهَيْرُ بْنُ حَرْبٍ وَاللَّفْظُ لِابْنِ عَبَّادٍ قَالَا حَدَّثَنَا أَبُو صَفْوَانَ أَخْبَرَنَا يُونُسُ عَنْ الزُّهْرِيِّ قَالَ قَالَ ابْنُ الْمُسَيَّبِ قَالَ أَبُو هُرَيْرَةَإِنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أُتِيَ لَيْلَةَ أُسْرِيَ بِهِ بِإِيلِيَاءَ بِقَدَحَيْنِ مِنْ خَمْرٍ وَلَبَنٍ فَنَظَرَ إِلَيْهِمَا فَأَخَذَ اللَّبَنَ فَقَالَ لَهُ جِبْرِيلُ عَلَيْهِ السَّلَام الْحَمْدُ لِلَّهِ الَّذِي هَدَاكَ لِلْفِطْرَةِ لَوْ أَخَذْتَ الْخَمْرَ غَوَتْ أُمَّتُكَو حَدَّثَنِي سَلَمَةُ بْنُ شَبِيبٍ حَدَّثَنَا الْحَسَنُ بْنُ أَعْيَنَ حَدَّثَنَا مَعْقِلٌ عَنْ الزُّهْرِيِّ عَنْ سَعِيدِ بْنِ الْمُسَيَّبِ أَنَّهُ سَمِعَ أَبَا هُرَيْرَةَ يَقُولُا أُتِيَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِمِثْلِهِ وَلَمْ يَذْكُرْ بِإِيلِيَاءَ","id":"Telah menceritakan kepada kami [Muhammad bin 'Abbas] dan [Zuhair bin Harb] dan lafazh ini milik Ibnu 'Abbas mereka berkata; Telah menceritakan kepada kami [Abu Shafwan]; Telah mengabarkan kepada kami [Yunus] dari [Zuhri] ia berkata; [Ibnu Musayyab] berkata; [Abu Hurairah] berkata; bahwa Nabi shallallahu 'alaihi wasallam pernah diberikan dua cangkir yang berisi khamer dan susu di Iliya pada malam Isra. Beliau kemudian mengambil susu. Setelah itu Jibril berkata; 'Segala puji bagi Allah yang telah menunjukimu kepada kesucian. Seandainya engkau mengambil khamer, niscaya umatmu akan sesat.' Dan telah menceritakan kepadaku [Salamah bin Syabib] telah menceritakan kepada kami [Al Hasan bin A'Yan] telah menceritakan kepada kami [Ma'qil] dari [Az Zuhri] dari [Sa'id bin Al Musayyab] bahwa dia mendengar [Abu Hurairah] berkata; -dengan Hadits yang serupa, namun tidak menyebutkan di Iliya.-"},"3470":{"ar":"حَدَّثَنَا زُهَيْرُ بْنُ حَرْبٍ وَمُحَمَّدُ بْنُ الْمُثَنَّى وَعَبْدُ بْنُ حُمَيْدٍ كُلُّهُمْ عَنْ أَبِي عَاصِمٍ قَالَ ابْنُ الْمُثَنَّى حَدَّثَنَا الضَّحَّاكُ أَخْبَرَنَا ابْنُ جُرَيْجٍ أَخْبَرَنِي أَبُو الزُّبَيْرِ أَنَّهُ سَمِعَ جَابِرَ بْنَ عَبْدِ اللَّهِ يَقُولُ أَخْبَرَنِي أَبُو حُمَيْدٍ السَّاعِدِيُّ قَالَأَتَيْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِقَدَحِ لَبَنٍ مِنْ النَّقِيعِ لَيْسَ مُخَمَّرًا فَقَالَ أَلَّا خَمَّرْتَهُ وَلَوْ تَعْرُضُ عَلَيْهِ عُودًا قَالَ أَبُو حُمَيْدٍ إِنَّمَا أُمِرَ بِالْأَسْقِيَةِ أَنْ تُوكَأَ لَيْلًا وَبِالْأَبْوَابِ أَنْ تُغْلَقَ لَيْلًاو حَدَّثَنِي إِبْرَاهِيمُ بْنُ دِينَارٍ حَدَّثَنَا رَوْحُ بْنُ عُبَادَةَ حَدَّثَنَا ابْنُ جُرَيْجٍ وَزَكَرِيَّاءُ بْنُ إِسْحَقَ قَالَا أَخْبَرَنَا أَبُو الزُّبَيْرِ أَنَّهُ سَمِعَ جَابِرَ بْنَ عَبْدِ اللَّهِ يَقُولُ أَخْبَرَنِي أَبُو حُمَيْدٍ السَّاعِدِيُّ أَنَّهُ أَتَى النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِقَدَحِ لَبَنٍ بِمِثْلِهِ قَالَ وَلَمْ يَذْكُرْ زَكَرِيَّاءُ قَوْلَ أَبِي حُمَيْدٍ بِاللَّيْلِ","id":"Telah menceritakan kepada kami [Zuhair bin Harb] dan [Muhammad bin Al Mutsanna] dan ['Abdu bin Humaid], semuanya Dari [Abu 'Ashim], [Ibnu Al Mutsanna] berkata; Telah menceritakan kepada kami [Adh Dhahak] telah mengabarkan kepada kami [Ibnu Juraij]; Telah mengabarkan kepadaku [Abu Zubair]; Bahwa dia mendengar [Jabir bin 'Abdullah] berkata; Telah mengabarkan kepada kami [Abu Humaid As Sa'idi] ia berkata; Aku pernah mengunjungi Nabi shallallahu 'alaihi wasallam dengan membawa cangkir susu yang berisi minuman dari anggur dalam keadaan tidak tertutup, lalu beliau bersabda: \"Tidakkah engkau menutupinya walaupun hanya dengan melintangkan sepotong kayu?.\" Abu Hamid berkata; 'Minuman-minuman diperintahkan untuk diikat di waktu malam (ditutup) dan pintu-pintu ditutup. Dan telah menceritakan kepadaku [Ibrahim bin Dinar], telah menceritakan kepada kami [Rauh bin Ubadah], telah menceritakan kepada kami [Ibnu Juraij] dan [Zakaria bin Ishaq] mereka berkata; Telah mengabarkan kepada kami [Abu Zubair] bahwa dia mendengar [Jabir bin Abdullah] berkata; 'Telah mengabarkan kepadaku [Abu Humaid As Saidi], bahwa dia mendatangi Nabi shallallahu 'alaihi wasallam dengan cangkir susu -dengan Hadits yang serupa- dia berkata; Zakaria tidak menyebutkan perkataan Abu Humaid mengenai di malam hari."},"3471":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ وَأَبُو كُرَيْبٍ وَاللَّفْظُ لِأَبِي كُرَيْبٍ قَالَا حَدَّثَنَا أَبُو مُعَاوِيَةَ عَنْ الْأَعْمَشِ عَنْ أَبِي صَالِحٍ عَنْ جَابِرِ بْنِ عَبْدِ اللَّهِ قَالَكُنَّا مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَاسْتَسْقَى فَقَالَ رَجُلٌ يَا رَسُولَ اللَّهِ أَلَا نَسْقِيكَ نَبِيذًا فَقَالَ بَلَى قَالَ فَخَرَجَ الرَّجُلُ يَسْعَى فَجَاءَ بِقَدَحٍ فِيهِ نَبِيذٌ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَلَّا خَمَّرْتَهُ وَلَوْ تَعْرُضُ عَلَيْهِ عُودًا قَالَ فَشَرِبَ","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] dan [Abu Kuraib] dan lafazh ini milik Abu Kuraib, keduanya berkata; Telah menceritakan kepada kami [Abu Mu'awiyah] dari [Al A'masy] dari [Abu Shalih] dari [Jabir bin Abdullah] dia berkata; ketika kami bersama Nabi shallallahu 'alaihi wasallam tiba-tiba beliau meminta air. Lalu ada seorang laki-laki berkata; 'Maukah aku beri nabidz (minuman yang biasa terbuat dari kurma atau anggur)? Beliau menjawab: \"Ya.\" (Jabir bin Abdullah) berkata; maka laki-laki itu mencari keluar, lalu dia datang dengan membawa bejana yang berisi nabidz. Nabi shallallahu 'alaihi wasallam bersabda: \"Tidakkah engkau menutupinya? Walaupun hanya dengan membentangkan sepotong kayu.\" (Jabir bin Abdullah) berkata; kemudian (Rasulullah shallallahu 'alaihi wasallam) minum."},"3472":{"ar":"و حَدَّثَنَا عُثْمَانُ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا جَرِيرٌ عَنْ الْأَعْمَشِ عَنْ أَبِي سُفْيَانَ وَأَبِي صَالِحٍ عَنْ جَابِرٍ قَالَجَاءَ رَجُلٌ يُقَالُ لَهُ أَبُو حُمَيْدٍ بِقَدَحٍ مِنْ لَبَنٍ مِنْ النَّقِيعِ فَقَالَ لَهُ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَلَا خَمَّرْتَهُ وَلَوْ تَعْرُضُ عَلَيْهِ عُودًا","id":"Telah menceritakan kepada kami ['Utsman bin Abu Syaibah]; Telah menceritakan kepada kami [Jarir] dari [Al A'masy] dari [Abu Sufyan] dan [Abu Shalih] dari [Jabir] ia berkata; seorang laki-laki yang biasa disebut Abu Humaid datang dengan membawa cangkir yang berisi susu yang sudah didinginkan, lalu Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tidakkah engkau menutupinya? Walaupun hanya dengan sepotong kayu?.\""},"3473":{"ar":"حَدَّثَنَا قُتَيْبَةُ بْنُ سَعِيدٍ حَدَّثَنَا لَيْثٌ ح و حَدَّثَنَا مُحَمَّدُ بْنُ ر��مْحٍ أَخْبَرَنَا اللَّيْثُ عَنْ أَبِي الزُّبَيْرِ عَنْ جَابِرٍعَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهُ قَالَ غَطُّوا الْإِنَاءَ وَأَوْكُوا السِّقَاءَ وَأَغْلِقُوا الْبَابَ وَأَطْفِئُوا السِّرَاجَ فَإِنَّ الشَّيْطَانَ لَا يَحُلُّ سِقَاءً وَلَا يَفْتَحُ بَابًا وَلَا يَكْشِفُ إِنَاءً فَإِنْ لَمْ يَجِدْ أَحَدُكُمْ إِلَّا أَنْ يَعْرُضَ عَلَى إِنَائِهِ عُودًا وَيَذْكُرَ اسْمَ اللَّهِ فَلْيَفْعَلْ فَإِنَّ الْفُوَيْسِقَةَ تُضْرِمُ عَلَى أَهْلِ الْبَيْتِ بَيْتَهُمْوَلَمْ يَذْكُرْ قُتَيْبَةُ فِي حَدِيثِهِ وَأَغْلِقُوا الْبَابَ و حَدَّثَنَا يَحْيَى بْنُ يَحْيَى قَالَ قَرَأْتُ عَلَى مَالِكٍ عَنْ أَبِي الزُّبَيْرِ عَنْ جَابِرٍ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِهَذَا الْحَدِيثِ غَيْرَ أَنَّهُ قَالَ وَأَكْفِئُوا الْإِنَاءَ أَوْ خَمِّرُوا الْإِنَاءَ وَلَمْ يَذْكُرْ تَعْرِيضَ الْعُودِ عَلَى الْإِنَاءِ و حَدَّثَنَا أَحْمَدُ بْنُ يُونُسَ حَدَّثَنَا زُهَيْرٌ حَدَّثَنَا أَبُو الزُّبَيْرِ عَنْ جَابِرٍ قَالَ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَغْلِقُوا الْبَابَ فَذَكَرَ بِمِثْلِ حَدِيثِ اللَّيْثِ غَيْرَ أَنَّهُ قَالَ وَخَمِّرُوا الْآنِيَةَ وَقَالَ تُضْرِمُ عَلَى أَهْلِ الْبَيْتِ ثِيَابَهُمْ و حَدَّثَنِي مُحَمَّدُ بْنُ الْمُثَنَّى حَدَّثَنَا عَبْدُ الرَّحْمَنِ حَدَّثَنَا سُفْيَانُ عَنْ أَبِي الزُّبَيْرِ عَنْ جَابِرٍ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِمِثْلِ حَدِيثِهِمْ وَقَالَ وَالْفُوَيْسِقَةُ تُضْرِمُ الْبَيْتَ عَلَى أَهْلِهِ","id":"Telah menceritakan kepada kami [Qutaibah bin Sa'id]; Telah menceritakan kepada kami [Laits]; Demikian juga telah diriwayatkan dari jalur yang lain; Dan telah menceritakan kepada kami [Muhammad bin Rumh]; Telah mengabarkan kepada kami [Al Laits] dari [Abu Zubair] dari [Jabir] dari Rasulullah shallallahu 'alaihi wasallam, beliau bersabda: \"Tutuplah oleh kalian bejana-bejana, rapatkanlah tempat-tempat minuman, tutuplah pintu-pintu, dan matikanlah lampu, karena setan tidak dapat membuka ikatan tempat minum, pintu, dan bejana. Jika kalian tidak mendapatkan penutupnya kecuali dengan membentangkan sepotong kayu di atas bejananya dan menyebut nama Allah, maka lakukanlah. Karena tikus dapat merusak pemilik rumah dengan membakar rumahnya.\" Tapi Qutaibah dalam Haditsnya tidak menyebutkan; \"dan tutuplah pintu-pintu\". Dan telah menceritakan kepada kami [Yahya bin Yahya] dia berkata; Aku membaca kitab [Malik] mengenai Hadits ini dari [Abu Zubair] dari [Jabir] dari Nabi shallallahu 'alaihi wasallam, namun dia menyebutkan; \"Dan tutupalah rapat-rapat atau tutuplah bejana-bejana.\" Dia tidak menyebutkan merentangkan kayu di atas bejana. Dan telah mengabarkan kepada kami [Ahmad bin Yunus], telah menceritakan kepada kami [Zuhair], telah menceritakan kepada kami [Abu Zubair] dari [Jabir] dia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tutuplah pintu-pintu, \" dan kemudian dia menyebutkan yang serupa dengan Hadist Laits, namun dia menyebutkan; \"Tutuplah bejana, \" dan berkata; \"Sesungguhnya tikus dapat merusak pemilik rumah dengan membakar pakaiannya.\" Dan telah menceritakan kepadaku [Muhammad bin Al Mutsanna], telah menceritakan kepada kami [Abdurrahman], telah menceritakan kepada kami [Sufyan] dari [Abu Zubair] dari [Jabir] dari Nabi shallallahu 'alaihi wasallam dengan Hadits yang serupa, dan dia berkata; 'Tikus dapat merusak pemilik rumah dengan membakar rumahnya.'"},"3474":{"ar":"و حَدَّثَنِي إِسْحَقُ بْنُ مَنْصُورٍ أَخْبَرَنَا رَوْحُ بْنُ عُبَادَةَ حَدَّثَنَا ابْنُ جُرَيْجٍ أَخْبَرَنِي عَطَاءٌ أَنَّهُ سَمِعَ جَابِرَ بْنَ عَبْدِ اللَّهِ يَقُولُاقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا كَانَ جُنْحُ اللَّيْلِ أَوْ أَمْسَيْتُمْ فَكُفُّوا صِبْيَانَكُمْ فَإِنَّ الشَّيْطَانَ يَنْتَشِرُ حِينَئِذٍ فَإِذَا ذَهَبَ سَاعَةٌ مِنْ اللَّيْلِ فَخَلُّوهُمْ وَأَغْلِقُوا الْأَبْوَابَ وَاذْكُرُوا اسْمَ اللَّهِ فَإِنَّ الشَّيْطَانَ لَا يَفْتَحُ بَابًا مُغْلَقًا وَأَوْكُوا قِرَبَكُمْ وَاذْكُرُوا اسْمَ اللَّهِ وَخَمِّرُوا آنِيَتَكُمْ وَاذْكُرُوا اسْمَ اللَّهِ وَلَوْ أَنْ تَعْرُضُوا عَلَيْهَا شَيْئًا وَأَطْفِئُوا مَصَابِيحَكُمْو حَدَّثَنِي إِسْحَقُ بْنُ مَنْصُورٍ أَخْبَرَنَا رَوْحُ بْنُ عُبَادَةَ حَدَّثَنَا ابْنُ جُرَيْجٍ أَخْبَرَنِي عَمْرُو بْنُ دِينَارٍ أَنَّهُ سَمِعَ جَابِرَ بْنَ عَبْدِ اللَّهِ يَقُولُا نَحْوًا مِمَّا أَخْبَرَ عَطَاءٌ إِلَّا أَنَّهُ لَا يَقُولُ اذْكُرُوا اسْمَ اللَّهِ عَزَّ وَجَلَّ و حَدَّثَنَا أَحْمَدُ بْنُ عُثْمَانَ النَّوْفَلِيُّ حَدَّثَنَا أَبُو عَاصِمٍ أَخْبَرَنَا ابْنُ جُرَيْجٍ بِهَذَا الْحَدِيثِ عَنْ عَطَاءٍ وَعَمْرِو بْنِ دِينَارٍ كَرِوَايَةِ رَوْحٍ","id":"Telah menceritakan kepadaku [Ishaq bin Manshur]; Telah mengabarkan kepada kami [Rauh bin 'Ubadah]; Telah menceritakan kepada kami [Ibnu Juraij]; Telah mengabarkan kepadaku ['Atha]; bahwa dia mendengar [Jabir bin 'Abdullah] berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Bila hari telah senja laranglah anak-anak keluar rumah, karena ketika itu setan berkeliaran. Dan bila waktu malam tiba biarkanlah mereka. Kuncilah pintu dan sebut nama Allah, karena setan tidak dapat membuka pintu yang terkunci (dengan menyebut nama Allah). Tutup semua bejanamu dengan menyebut nama Allah, sekalipun dengan membentangkan sesuatu di atasnya, dan padamkan lampu (ketika hendak tidur).\" Telah menceritakan kepadaku [Ishaq bin Manshur]; Telah mengabarkan kepada kami [Rauh bin 'Ubadah]; Telah menceritakan kepada kami [Ibnu Juraij]; Telah mengabarkan kepadaku ['Amru bin Dinar]; dia mendengar [Jabir bin Abdullah] berkata sebagimana yang telah dikabarkan oleh 'Atha, hanya saja dia tidak menyebutkan kalimat 'Sebutlah nama Allah Azza Wa Jalla'. Dan telah menceritakan kepada kami [Ahmad bin 'Utsman An Naufali]; Telah menceritakan kepada kami [Abu 'Ashim]; Telah mengabarkan kepada kami [Ibnu Juraij] dengan Hadits ini. Dari ['Atha] dan ['Amru bin Dinar] sebagaimana riwayat Rauh."},"3475":{"ar":"و حَدَّثَنَا أَحْمَدُ بْنُ يُونُسَ حَدَّثَنَا زُهَيْرٌ حَدَّثَنَا أَبُو الزُّبَيْرِ عَنْ جَابِرٍ ح و حَدَّثَنَا يَحْيَى بْنُ يَحْيَى أَخْبَرَنَا أَبُو خَيْثَمَةَ عَنْ أَبِي الزُّبَيْرِ عَنْ جَابِرٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا تُرْسِلُوا فَوَاشِيَكُمْ وَصِبْيَانَكُمْ إِذَا غَابَتْ الشَّمْسُ حَتَّى تَذْهَبَ فَحْمَةُ الْعِشَاءِ فَإِنَّ الشَّيَاطِينَ تَنْبَعِثُ إِذَا غَابَتْ الشَّمْسُ حَتَّى تَذْهَبَ فَحْمَةُ الْعِشَاءِو حَدَّثَنِي مُحَمَّدُ بْنُ الْمُثَنَّى حَدَّثَنَا عَبْدُ الرَّحْمَنِ حَدَّثَنَا سُفْيَانُ عَنْ أَبِي الزُّبَيْرِ عَنْ جَابِرٍ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِنَحْوِ حَدِيثِ زُهَيْرٍ","id":"Telah menceritakan kepada kami [Ahmad bin Yunus]; Telah menceritakan kepada kami [Zuhair]; Telah menceritakan kepada kami [Abu Az Zubair] dari [Jabir]; Demikian juga telah diriwayatkan dari jalur yang lain; Dan telah menceritakan kepada kami [Yahya bin Yahya]; Telah mengabarkan kepada kami [Abu Khaitsamah] dari [Abu Az Zubair] dari [Jabir] ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Jangan biarkan ternak dan anak-anakmu lepas berkeliaran ketika matahari terbenam sampai hilangnya cahaya senja. Karena setan keluar ketika matahari terbenam sampai hilang cahaya senja.\" Dan telah menceritakan kepadaku [Muhammad bin Al Mutsanna]; Telah menceritakan kepada kami ['Abdurrahman]; Telah menceritakan kepada kami [Sufyan] dari [Abu Az Zubair] dari [Jabir] dari Nabi shallallahu 'alaihi wasallam dengan Hadits yang serupa."},"3476":{"ar":"و حَدَّثَنَا عَمْرٌو النَّاقِدُ حَدَّثَنَا هَاشِمُ بْنُ الْقَاسِمِ حَدَّثَنَا اللَّيْثُ بْنُ سَعْدٍ حَدَّثَنِي يَزِيدُ بْنُ عَبْدِ اللَّهِ بْنِ أُسَامَةَ بْنِ الْهَادِ اللَّيْثِيُّ عَنْ يَحْيَى بْنِ سَعِيدٍ عَنْ جَعْفَرِ بْنِ عَبْدِ اللَّهِ بْنِ الْحَكَمِ عَنْ الْقَعْقَاعِ بْنِ حَكِيمٍ عَنْ جَابِرِ بْنِ عَبْدِ اللَّهِ قَالَسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ غَطُّوا الْإِنَاءَ وَأَوْكُوا السِّقَاءَ فَإِنَّ فِي السَّنَةِ لَيْلَةً يَنْزِلُ فِيهَا وَبَاءٌ لَا يَمُرُّ بِإِنَاءٍ لَيْسَ عَلَيْهِ غِطَاءٌ أَوْ سِقَاءٍ لَيْسَ عَلَيْهِ وِكَاءٌ إِلَّا نَزَلَ فِيهِ مِنْ ذَلِكَ الْوَبَاءِو حَدَّثَنَا نَصْرُ بْنُ عَلِيٍّ الْجَهْضَمِيُّ حَدَّثَنِي أَبِي حَدَّثَنَا لَيْثُ بْنُ سَعْدٍ بِهَذَا الْإِسْنَادِ بِمِثْلِهِ غَيْرَ أَنَّهُ قَالَ فَإِنَّ فِي السَّنَةِ يَوْمًا يَنْزِلُ فِيهِ وَبَاءٌ وَزَادَ فِي آخِرِ الْحَدِيثِ قَالَ اللَّيْثُ فَالْأَعَاجِمُ عِنْدَنَا يَتَّقُونَ ذَلِكَ فِي كَانُونَ الْأَوَّلِ","id":"Telah menceritakan kepada kami ['Amru An Naqid]; Telah menceritakan kepada kami [Hasyim bin Al Qasim]; Telah menceritakan kepada kami [Al Laits bin Sa'd]; Telah menceritakan kepadaku [Yazid bin 'Abdullah bin Usamah bin Al Hadi Al Laitsi] dari [Yahya bin Sa'id] dari [Ja'far bin 'Abdullah bin Al Hakam] dari [Al Qa'qa' bin Hakim] dari [Jabir bin 'Abdullah] ia berkata; Aku mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tutuplah bejana-bejana, dan ikatlah tempat-tempat minuman, karena di suatu malam pada setiap tahunnya akan ada wabah penyakit (berbahaya) yang akan jatuh ke dalam bejana dan ketempat-tempat air yang tidak tertutup.\" Dan telah menceritakan kepada kami [Nashr bin 'Ali Al Jahdlami]; Telah menceritakan kepadaku [Bapakku]; Telah menceritakan kepada kami [Laits bin Sa'd] dengan Hadits dan sanad yang serupa, hanya saja dia berkata dengan kalimat 'Karena di suatu hari pada setiap tahunnya akan ada wabah penyakit'. Dia juga menambahkan pada akhir Haditsnya; Al laits berkata; 'Orang-orang 'Ajam (selain orang arab) diantara kami merasa takut pada hal itu sejak bulan pertama.'"},"3477":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ وَعَمْرٌو النَّاقِدُ وَزُهَيْرُ بْنُ حَرْبٍ قَالُوا حَدَّثَنَا سُفْيَانُ بْنُ عُيَيْنَةَ عَنْ الزُّهْرِيِّ عَنْ سَالِمٍ عَنْ أَبِيهِعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَا تَتْرُكُوا النَّارَ فِي بُيُوتِكُمْ حِينَ تَنَامُونَ","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] dan ['Amru An Naqid] dan [Zuhair bin Harb] mereka berkata; Telah menceritakan kepada kami [Sufyan bin 'Uyainah] dari [Az Zuhair] dari [Salim] dari [Bapaknya] dari Nabi shallallahu 'alaihi wasallam beliau bersabda: \"Ketika kalian tidur di rumah, janganlah kalian meninggalkan api dalam keadaan menyala.\""},"3478":{"ar":"حَدَّثَنَا سَعِيدُ بْنُ عَمْرٍو الْأَشْعَثِيُّ وَأَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ وَمُحَمَّدُ بْنُ عَبْدِ اللَّهِ بْنِ نُمَيْرٍ وَأَبُو عَامِرٍ الْأَشْعَرِيُّ وَأَبُو كُرَيْبٍ وَاللَّفْظُ لِأَبِي عَامِرٍ قَالُوا حَدَّثَنَا أَبُو أُسَامَةَ عَنْ بُرَيْدٍ عَنْ أَبِي بُرْدَةَ عَنْ أَبِي مُوسَى قَالَاحْتَرَقَ بَيْتٌ عَلَى أَهْلِهِ بِالْمَدِينَةِ مِنْ اللَّيْلِ فَلَمَّا حُدِّثَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِشَأْنِهِمْ قَالَ إِنَّ هَذِهِ النَّارَ إِنَّمَا هِيَ عَدُوٌّ لَكُمْ فَإِذَا نِمْتُمْ فَأَطْفِئُوهَا عَنْكُمْ","id":"Telah menceritakan kepada kami [Sa'id bin 'Amru Al Asy'atsi] dan [Abu Bakr bin Syaibah] dan [Muhammad bin 'Abdullah bin Numair] dan [Abu 'Amir Al Asy'ari] dan [Abu Kuraib] dan lafazh ini milik Abu 'Amir, berkata; Telah menceritakan kepada kami [Abu Usamah] dari [Buraid] dari [Abu Burdah] dari [Abu Musa] ia berkata; Pada suatu malam sebuah rumah penduduk Madinah terbakar. Ketika hal itu di ceritakan kepada Rasulullah shallallahu 'alaihi wasallam, beliau bersabda: \"Sesungguhnya api ini adalah musuh kalian, karena itu apabila kalian hendak tidur, maka padamkanlah lebih dahulu.\""},"3479":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ وَأَبُو كُرَيْبٍ قَالَا حَدَّثَنَا أَبُو مُعَاوِيَةَ عَنْ الْأَعْمَشِ عَنْ خَيْثَمَةَ عَنْ أَبِي حُذَيْفَةَ عَنْ حُذَيْفَةَ قَالَكُنَّا إِذَا حَضَرْنَا مَعَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ طَعَامًا لَمْ نَضَعْ أَيْدِيَنَا حَتَّى يَبْدَأَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَيَضَعَ يَدَهُ وَإِنَّا حَضَرْنَا مَعَهُ مَرَّةً طَعَامًا فَجَاءَتْ جَارِيَةٌ كَأَنَّهَا تُدْفَعُ فَذَهَبَتْ لِتَضَعَ يَدَهَا فِي الطَّعَامِ فَأَخَذَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِيَدِهَا ثُمَّ جَاءَ أَعْرَابِيٌّ كَأَنَّمَا يُدْفَعُ فَأَخَذَ بِيَدِهِ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّ الشَّيْطَانَ يَسْتَحِلُّ الطَّعَامَ أَنْ لَا يُذْكَرَ اسْمُ اللَّهِ عَلَيْهِ وَإِنَّهُ جَاءَ بِهَذِهِ الْجَارِيَةِ لِيَسْتَحِلَّ بِهَا فَأَخَذْتُ بِيَدِهَا فَجَاءَ بِهَذَا الْأَعْرَابِيِّ لِيَسْتَحِلَّ بِهِ فَأَخَذْتُ بِيَدِهِ وَالَّذِي نَفْسِي بِيَدِهِ إِنَّ يَدَهُ فِي يَدِي مَعَ يَدِهَاو حَدَّثَنَاه إِسْحَقُ بْنُ إِبْرَاهِيمَ الْحَنْظَلِيُّ أَخْبَرَنَا عِيسَى بْنُ يُونُسَ أَخْبَرَنَا الْأَعْمَشُ عَنْ خَيْثَمَةَ بْنِ عَبْدِ الرَّحْمَنِ عَنْ أَبِي حُذَيْفَةَ الْأَرْحَبِيِّ عَنْ حُذَيْفَةَ بْنِ الْيَمَانِ قَالَ كُنَّا إِذَا دُعِينَا مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِلَى طَعَامٍ فَذَكَرَ بِمَعْنَى حَدِيثِ أَبِي مُعَاوِيَةَ وَقَالَ كَأَنَّمَا يُطْرَدُ وَفِي الْجَارِيَةِ كَأَنَّمَا تُطْرَدُ وَقَدَّمَ مَجِيءَ الْأَعْرَابِيِّ فِي حَدِيثِهِ قَبْلَ مَجِيءِ الْجَارِيَةِ وَزَادَ فِي آخِرِ الْحَدِيثِ ثُمَّ ذَكَرَ اسْمَ اللَّهِ وَأَكَلَ و حَدَّثَنِيهِ أَبُو بَكْرِ بْنُ نَافِعٍ حَدَّثَنَا عَبْدُ الرَّحْمَنِ حَدَّثَنَا سُفْيَانُ عَنْ الْأَعْمَشِ بِهَذَا الْإِسْنَادِ وَقَدَّمَ مَجِيءَ الْجَارِيَةِ قَبْلَ مَجِيءِ الْأَعْرَابِيِّ","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] dan [Abu Kuraib] keduanya berkata; Telah menceritakan kepada kami [Abu Mu'awiyah] dari [Al A'masy] dari [Khaitsamah] dari [Abu Hudzaifah] dari [Hudzaifah] dia berkata; Bila kami menghadiri jamuan makan bersama Rasulullah Shallallahu 'alaihi Wa Salam, kami tidak meletakkan tangan kami hingga beliau memulai meletakkan tangan beliau. ketika kami menghadiri jamuan makan bersama beliau, tiba-tiba datang seorang budak perempuan yang ingin meletakkan tangannya pada makanan itu, Rasulullah Shallallahu 'alaihi Wa Salam meraih tangannya (menyingkirkannya), kemudian seorang badui datang yang ingin meletakkan tangannya diatas makanan itu, Rasulullah Shallallahu 'Alaihi Wa Salam pun meraih tangannya. Beliau lalu bersabda: \"Sesungguhnya Setan akan mendapatkan makanan yang tidak disebut nama Allah dan ia datang bersama anak perempuan ini untuk mendapatkannya, lalu aku meraih tangannya, ia juga datang bersama orang badui ini untuk mendapatkannya lalu aku meraih tangannya. Demi Dzat Yang jiwaku berada ditanganNya, Sesungguhnya tangan setan itu berada di tanganku seperti ia ada di dalam tangan keduanya (orang badui dan budak perempuan).\" Dan telah menceritakan pula kepada kami [Ishaq bin Ibrahim Al Hanzhali], telah mengabarkan kepada kami [Isa bin Yunus], telah mengabarkan kepada kami [Al 'Amasy] dari [Khaitsamah bin Abdurrahman] dari [Abu Hudzaifah Al Arhabi] dari [Khudzaifah bin Al Yaman] dia berkata; Bila kami diundang untuk menghadiri jamuan makan bersama Rasulullah Shallallahu 'alaihi Wa Salam, - lalu dia menyebutkan Hadits yang semakna dengan Hadits Abu Mu'awiyah, dan dia berkata; dengan lafazh; 'Ka annama Yuthradu', sedangkan pada budak perempuan dengan lafazh 'Ka annama tuthradu'. Dalam Haditsnya dia mendahulukan kedatangan orang badui daripada budak perempuan. Dan di akhir Haditsnya dia menambahkan; 'Beliau menyebut nama Allah lalu makan.' Dan telah menceritakan kepadaku pula [Abu Bakr bin Nafi'], telah menceritakan kepada kami [Abdurrahman], telah menceritakan kepada kami [Sufyan] dari [Al A'Masy] dengan sanad ini. Dan dia mendahulukan datangnya budak perempuan dari pada orang badui."},"3480":{"ar":"و حَدَّثَنَا مُحَمَّدُ بْنُ الْمُثَنَّى الْعَنَزِيُّ حَدَّثَنَا الضَّحَّاكُ يَعْنِي أَبَا عَاصِمٍ عَنْ ابْنِ جُرَيْجٍ أَخْبَرَنِي أَبُو الزُّبَيْرِ عَنْ جَابِرِ بْنِ عَبْدِ اللَّهِ أَنَّهُسَمِعَ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ إِذَا دَخَلَ الرَّجُلُ بَيْتَهُ فَذَكَرَ اللَّهَ عِنْدَ دُخُولِهِ وَعِنْدَ طَعَامِهِ قَالَ الشَّيْطَانُ لَا مَبِيتَ لَكُمْ وَلَا عَشَاءَ وَإِذَا دَخَلَ فَلَمْ يَذْكُرْ اللَّهَ عِنْدَ دُخُولِهِ قَالَ الشَّيْطَانُ أَدْرَكْتُمْ الْمَبِيتَ وَإِذَا لَمْ يَذْكُرْ اللَّهَ عِنْدَ طَعَامِهِ قَالَ أَدْرَكْتُمْ الْمَبِيتَ وَالْعَشَاءَو حَدَّثَنِيهِ إِسْحَقُ بْنُ مَنْصُورٍ أَخْبَرَنَا رَوْحُ بْنُ عُبَادَةَ حَدَّثَنَا ابْنُ جُرَيْجٍ أَخْبَرَنِي أَبُو الزُّبَيْرِ أَنَّهُ سَمِعَ جَابِرَ بْنَ عَبْدِ اللَّهِ يَقُولُ إِنَّهُ سَمِعَ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ بِمِثْلِ حَدِيثِ أَبِي عَاصِمٍ إِلَّا أَنَّهُ قَالَ وَإِنْ لَمْ يَذْكُرْ اسْمَ اللَّهِ عِنْدَ طَعَامِهِ وَإِنْ لَمْ يَذْكُرْ اسْمَ اللَّهِ عِنْدَ دُخُولِهِ","id":"Telah menceritakan kepada kami [Muhammad bin Al Mutsanna Al 'Anazi]; Telah menceritakan kepada kami [Adl Dlahak] yaitu Abu Ashim, dari [Ibnu Juraij]; Telah mengabarkan kepadaku [Abu Zubair] dari [Jabir bin 'Abdullah]; Sesungguhnya dia mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Jika seseorang menyebut nama Allah ketika hendak masuk rumahnya dan ketika hendak makan, maka setan berkata; 'Kalian (bangsa setan) tidak bisa menginap dan tidak bisa makan! ' Jika seseorang tidak menyebut nama Allah ketika hendak masuk rumahnya, maka setan berkata; 'Kalian bisa masuk dan bisa menginap.' Jika seseorang tidak menyebut nama Allah sewaktu hendak makan, maka setan berkata; 'Kalian bisa menginap dan makan malam.'"},"3481":{"ar":"حَدَّثَنَا قُتَيْبَةُ بْنُ سَعِيدٍ حَدَّثَنَا لَيْثٌ ح و حَدَّثَنَا مُحَمَّدُ بْنُ رُمْحٍ أَخْبَرَنَا اللَّيْثُ عَنْ أَبِي الزُّبَيْرِ عَنْ جَابِرٍعَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَا تَأْكُلُوا بِالشِّمَالِ فَإِنَّ الشَّيْطَانَ يَأْكُلُ بِالشِّمَالِ","id":"Telah menceritakan kepada kami [Qutaibah bin Sa'id]; Telah menceritakan kepada kami [Laits]; Demikian juga telah diriwayatkan dari jalur yang lain; dan telah menceritakan kepada kami [Muhammad bin Rumh]; Telah mengabarkan kepada kami [Al Laits] dari [Abu Zubair] dari [Jabir] dari Rasulullah shallallahu 'alaihi wasallam, beliau bersabda: \"Janganlah kalian makan dengan tangan kiri, karena setan makan dengan tangan kiri.\""},"3482":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ وَمُحَمَّدُ بْنُ عَبْدِ اللَّهِ بْنِ نُمَيْرٍ وَزُهَيْرُ بْنُ حَرْبٍ وَابْنُ أَبِي عُمَرَ وَاللَّفْظُ لِابْنِ نُمَيْرٍ قَالُوا حَدَّثَنَا سُفْيَانُ عَنْ الزُّهْرِيِّ عَنْ أَبِي بَكْرِ بْنِ عُبَيْدِ اللَّهِ بْنِ عَبْدِ اللَّهِ بْنِ عُمَرَ عَنْ جَدِّهِ ابْنِ عُمَرَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِذَا أَكَلَ أَحَدُكُمْ فَلْيَأْكُلْ بِيَمِينِهِ وَإِذَا شَرِبَ فَلْيَشْرَبْ بِيَمِينِهِ فَإِنَّ الشَّيْطَانَ يَأْكُلُ بِشِمَالِهِ وَيَشْرَبُ بِشِمَالِهِو حَدَّثَنَا قُتَيْبَةُ بْنُ سَعِيدٍ عَنْ مَالِكِ بْنِ أَنَسٍ فِيمَا قُرِئَ عَلَيْهِ ح و حَدَّثَنَا ابْنُ نُمَيْرٍ حَدَّثَنَا أَبِي ح و حَدَّثَنَا ابْنُ الْمُثَنَّى حَدَّثَنَا يَحْيَى وَهُوَ الْقَطَّانُ كِلَاهُمَا عَنْ عُبَيْدِ اللَّهِ جَمِيعًا عَنْ الزُّهْرِيِّ بِإِسْنَادِ سُفْيَانَ","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] dan [Muhammad bin 'Abdullah bin Numair] dan [Zuhair bin Harb] dan [Ibnu Abu 'Umar]; Dan lafazh ini milik Ibnu Numair, ia berkata; Telah menceritakan kepada kami [Sufyan] dari [Az Zuhri] dari [Abu Bakr bin 'Ubaidullah bin 'Abdullah bin 'Umar] dari kakeknya [Ibnu 'Umar]; bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Jika seseorang diantara kalian makan, maka hendaknya dia makan dengan tangan kanannya. Jika minum maka hendaknya juga minum dengan tangan kanannya, karena setan makan dengan tangan kirinya dan minum dengan tangan kirinya pula.\" Dan telah menceritakan kepada kami [Qutaibah bin Sa'id] dari [Malik bin Anas] yang dia bacakan kepadanya. Demikian juga diriwayatkan dari jalur lainnya, dan telah menceritakan kepada kami [Ibnu Numair], telah menceritakan kepada kami [bapakku]. Demikian juga diriwayatkan dari jalur lainnya, dan telah menceritakan kepada kami [Ibnu Al Mutsanna], telah menceritakan kepada kami [Yahya] yaitu Al Qaththan, keduanya dari [Ubaidullah], dari [Az Zuhri], dengan sanad Sufyan."},"3483":{"ar":"و حَدَّثَنِي أَبُو الطَّاهِرِ وَحَرْمَلَةُ قَالَ أَبُو الطَّاهِرِ أَخْبَرَنَا و قَالَ حَرْمَلَةُ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ وَهْبٍ حَدَّثَنِي عُمَرُ بْنُ مُحَمَّدٍ حَدَّثَنِي الْقَاسِمُ بْنُ عُبَيْدِ اللَّهِ بْنِ عَبْدِ اللَّهِ بْنِ عُمَرَ حَدَّثَهُ عَنْ سَالِمٍ عَنْ أَبِيهِأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَا يَأْكُلَنَّ أَحَدٌ مِنْكُمْ بِشِمَالِهِ وَلَا يَشْرَبَنَّ بِهَا فَإِنَّ الشَّيْطَانَ يَأْكُلُ بِشِمَالِهِ وَيَشْرَبُ بِهَاقَالَ وَكَانَ نَافِعٌ يَزِيدُ فِيهَا وَلَا يَأْخُذُ بِهَا وَلَا يُعْطِي بِهَا وَفِي رِوَايَةِ أَبِي الطَّاهِرِ لَا يَأْكُلَنَّ أَحَدُكُمْ","id":"Telah menceritakan kepadaku [Abu Ath Thahir] dan [Harmalah], Abu Ath Thahir berkata; telah mengabarkan kepada kami; sedangkan Harmalah berkata; Telah menceritakan kepada kami ['Abdullah bin Wahb]; Telah menceritakan kepadaku ['Umar bin Muhammad]; Telah menceritakan kepadaku [Al Qasim bin 'Ubaidullah bin 'Abdillah bin 'Umar]; Telah menceritakan kepadanya [Salim] dari [Bapaknya], bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Janganlah sekali-kali seseorang diantara kalian makan dan minum dengan tangan kiri, karena setan makan dengan tangan kiri dan minum dengan tangan kiri pula. Perawi berkata; di dalam Hadits tersebut [Nafi'] menambahkan; 'Dan jangan pula mengambil dan memberi dengan tangan kiri.' Di dalam riwayat Abu At Thahir disebutkan, 'Janganlah sekali-kali seseorang di antara kalian….'"},"3484":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا زَيْدُ بْنُ الْحُبَابِ عَنْ عِكْرِمَةَ بْنِ عَمَّارٍ حَدَّثَنِي إِيَاسُ بْنُ سَلَمَةَ بْنِ الْأَكْوَعِ أَنَّ أَبَاهُ حَدَّثَهُأَنَّ رَجُلًا أَكَلَ عِنْدَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِشِمَالِهِ فَقَالَ كُلْ بِيَمِينِكَ قَالَ لَا أَسْتَطِيعُ قَالَ لَا اسْتَطَعْتَ مَا مَنَعَهُ إِلَّا الْكِبْرُ قَالَ فَمَا رَفَعَهَا إِلَى فِيهِ","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah]; Telah menceritakan kepada kami [Zaid bin Al Hubab] dari ['Ikrimah bin 'Ammar]; Telah menceritakan kepadaku [Iyas bin Salamah bin Al Akwa']; [Bapaknya] telah menceritakan kepadanya, bahwa seorang laki-laki makan di samping Rasulullah shallallahu 'alaihi wasallam dengan tangan kirinya, Lalu Rasulullah bersabda: \"Makanlah dengan tangan kananmu! Dia menjawab; 'Aku tidak bisa.' Beliau bersabda: \"Apakah kamu tidak bisa?\" -dia menolaknya karena sombong-. Setelah itu tangannya tidak bisa sampai ke mulutnya."},"3485":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ وَابْنُ أَبِي عُمَرَ جَمِيعًا عَنْ سُفْيَانَ قَالَ أَبُو بَكْرٍ حَدَّثَنَا سُفْيَانُ بْنُ عُيَيْنَةَ عَنْ الْوَلِيدِ بْنِ كَثِيرٍ عَنْ وَهْبِ بْنِ كَيْسَانَ سَمِعَهُ مِنْ عُمَرَ بْنِ أَبِي سَلَمَةَ قَالَكُنْتُ فِي حَجْرِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَكَانَتْ يَدِي تَطِيشُ فِي الصَّحْفَةِ فَقَالَ لِي يَا غُلَامُ سَمِّ اللَّهَ وَكُلْ بِيَمِينِكَ وَكُلْ مِمَّا يَلِيكَ","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] dan [Ibnu Abu 'Umar] -semuanya- dari [Sufyan]; Abu Bakr berkata; Telah menceritakan kepada kami [Sufyan bin 'Uyainah] dari [Al Walid bin Katsir] dari [Wahb bin Kaisan] yang dia dengar dari ['Umar bin Abu Salamah] ia berkata; Dulu aku berada di pangkuan Rasulullah shallallahu 'alaihi wasallam, lantas tanganku memegang piring, maka beliau bersabda kepadaku: \"Wahai anak, sebutlah nama Allah, dan makanlah dengan tangan kananmu, serta makanlah yang ada di hadapanmu.\""},"3486":{"ar":"و حَدَّثَنَا الْحَسَنُ بْنُ عَلِيٍّ الْحُلْوَانِيُّ وَأَبُو بَكْرِ بْنُ إِسْحَقَ قَالَا حَدَّثَنَا ابْنُ أَبِي مَرْيَمَ أَخْبَرَنَا مُحَمَّدُ بْنُ جَعْفَرٍ أَخْبَرَنِي مُحَمَّدُ بْنُ عَمْرِو بْنِ حَلْحَلَةَ عَنْ وَهْبِ بْنِ كَيْسَانَ عَنْ عُمَرَ بْنِ أَبِي سَلَمَةَ أَنَّهُ قَالَأَكَلْتُ يَوْمًا مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَجَعَلْتُ آخُذُ مِنْ لَحْمٍ حَوْلَ الصَّحْفَةِ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كُلْ مِمَّا يَلِيكَ","id":"Telah menceritakan kepada kami [Al Hasan bin 'Ali Al Hulwani] dan [Abu Bakr bin Ishaq] mereka berkata; Telah menceritakan kepada kami [Ibnu Abu Maryam]; Telah mengabarkan kepada kami [Muhammad bin Ja'far]; Telah mengabarkan kepadaku [Muhammad bin 'Amru bin Halhalah] dari [Wahb bin Kaisan] dari ['Umar bin Abu Salamah], bahwa dia berkata; \"Pada suatu hari aku makan bersama Rasulullah shallallahu 'alaihi wasallam, lalu aku mengambil daging di sekitar piring-piring hidangan, maka Rasulullah shallallahu 'alaihi wasallam bersabda: 'Makanlah yang ada di hadapanmu.'"},"3487":{"ar":"و حَدَّثَنَا عَمْرٌو النَّاقِدُ حَدَّثَنَا سُفْيَانُ بْنُ عُيَيْنَةَ عَنْ الزُّهْرِيِّ عَنْ عُبَيْدِ اللَّهِ عَنْ أَبِي سَعِيدٍ قَالَنَهَى النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ اخْتِنَاثِ الْأَسْقِيَةِ","id":"Telah menceritakan kepada kami ['Amru An Naqid]; Telah menceritakan kepada kami [Sufyan bin 'Uyainah] dari [Az Zuhri] dari ['Ubaidillah] dari [Abu Sa'id] ia berkata; Rasulullah shallallahu 'alaihi wasallam melarang membengkokkan mulut tempat air."},"3488":{"ar":"و حَدَّثَنِي حَرْمَلَةُ بْنُ يَحْيَى أَخْبَرَنَا ابْنُ وَهْبٍ أَخْبَرَنِي يُونُسُ عَنْ ابْنِ شِهَابٍ عَنْ عُبَيْدِ اللَّهِ بْنِ عَبْدِ اللَّهِ بْنِ عُتْبَةَ عَنْ أَبِي سَعِيدٍ الْخُدْرِيِّ أَنَّهُ قَالَنَهَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ اخْتِنَاثِ الْأَسْقِيَةِ أَنْ يُشْرَبَ مِنْ أَفْوَاهِهَاو حَدَّثَنَاه عَبْدُ بْنُ حُمَيْدٍ أَخْبَرَنَا عَبْدُ الرَّزَّاقِ أَخْبَرَنَا مَعْمَرٌ عَنْ الزُّهْرِيِّ بِهَذَا الْإِسْنَادِ مِثْلَهُ غَيْرَ أَنَّهُ قَالَ وَاخْتِنَاثُهَا أَنْ يُقْلَبَ رَأْسُهَا ثُمَّ يُشْرَبَ مِنْهُ","id":"Telah menceritakan kepadaku [Harmalah bin Yahya]; Telah mengabarkan kepada kami [Ibnu Wahb]; Telah mengabarkan kepadaku [Yunus] dari [Ibnu Syihab] dari ['Ubaidillah bin 'Ubaidillah bin 'Utbah] dari [Abu Sa'id Al Khudri] dia berkata; Rasulullah shallallahu 'alaihi wasallam melarang membengkokkan mulut tempat air agar dapat diminum.\" Dan telah menceritakan pula kepada kami [Abdu bin Humaid], telah mengabarkan kepada kami [Abdurrazaq], telah mengabarkan kepada kami [Ma'mar] dari [Az Zuhri] dengan sanad ini yang serupa dengannya. Namun dia menambahkan; 'Ikhtinatsuha adalah membalikkan mulut tempat air kemudian meminum darinya'."},"3489":{"ar":"حَدَّثَنَا هَدَّابُ بْنُ خَالِدٍ حَدَّثَنَا هَمَّامٌ حَدَّثَنَا قَتَادَةُ عَنْ أَنَسٍأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ زَجَرَ عَنْ الشُّرْبِ قَائِمًا","id":"Telah menceritakan kepada kami [Haddab bin Khalid]; Telah menceritakan kepada kami [Hammam]; Telah menceritakan kepada kami [Qatadah] dari [Anas] bahwa Nabi Shallallahu A'laihi Wa Sallam melarang minum sambil berdiri."},"3490":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ الْمُثَنَّى حَدَّثَنَا عَبْدُ الْأَعْلَى حَدَّثَنَا سَعِيدٌ عَنْ قَتَادَةَ عَنْ أَنَسٍعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهُ نَهَى أَنْ يَشْرَبَ الرَّجُلُ قَائِمًا قَالَ قَتَادَةُ فَقُلْنَا فَالْأَكْلُ فَقَالَ ذَاكَ أَشَرُّ أَوْ أَخْبَثُو حَدَّثَنَاه قُتَيْبَةُ بْنُ سَعِيدٍ وَأَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ قَالَا حَدَّثَنَا وَكِيعٌ عَنْ هِشَامٍ عَنْ قَتَادَةَ عَنْ أَنَسٍ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِمِثْلِهِ وَلَمْ يَذْكُرْ قَوْلَ قَتَادَةَ","id":"Telah menceritakan kepada kami [Muhammad bin Al Mutsanna]; Telah menceritakan kepada kami [Abdul A'la]; Telah menceritakan kepada kami [Sa'id] dari [Qatadah] dari [Anas] dari Nabi shallallahu 'alaihi wasallam, bahwa beliau melarang seseorang minum sambil berdiri. Qatadah berkata; 'Maka kami tanyakan, bagaimana dengan makan? ' Anas menjawab: 'Apalagi makan, itu lebih buruk, atau lebih jelek.' Dan telah mengabarkannya pula [Qutaibah bin Sa'id] dan [Abu Bakr bin Abu Syaibah] keduanya berkata; Telah menceritakan kepada kami [Waki'] dari [Hisyam] dari [Qatadah] dari [Anas] dari Nabi shallallahu 'alaihi wasallam, dengan Hadits yang serupa, namun dia tidak menyebutkan ucapan Qatadah."},"3491":{"ar":"حَدَّثَنَا هَدَّابُ بْنُ خَالِدٍ حَدَّثَنَا هَمَّامٌ حَدَّثَنَا قَتَادَةُ عَنْ أَبِي عِيسَى الْأُسْوَارِيِّ عَنْ أَبِي سَعِيدٍ الْخُدْرِيِّأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ زَجَرَ عَنْ الشُّرْبِ قَائِمًا","id":"Telah menceritakan kepada kami [Haddab bin Khalid]; Telah menceritakan kepada kami [Hammam]; Telah menceritakan kepada kami [Qatadah] dari [Abu 'Isa Al Uswari] dari [Abu Sa'id Al Khudri] bahwa Nabi shallallahu 'alaihi wasallam melarang minum sambil berdiri."},"3492":{"ar":"و حَدَّثَنَا زُهَيْرُ بْنُ حَرْبٍ وَمُحَمَّدُ بْنُ الْمُثَنَّى وَابْنُ بَشَّارٍ وَاللَّفْظُ لِزُهَيْرٍ وَابْنِ الْمُثَنَّى قَالُوا حَدَّثَنَا يَحْيَى بْنُ سَعِيدٍ حَدَّثَنَا شُعْبَةُ حَدَّثَنَا قَتَادَةُ عَنْ أَبِي عِيسَى الْأُسْوَارِيِّ عَنْ أَبِي سَعِيدٍ الْخُدْرِيِّأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَهَى عَنْ الشُّرْبِ قَائِمًا","id":"Telah menceritakan kepada kami [Zuhair bin Harb] dan [Muhammad bin Al Mutsanna] dan [Ibnu Basyar]; Dan lafazh ini milik [Zuhair] dan [Ibnu Al Mutsanna], mereka berkata; Telah menceritakan kepada kami [Yahya bin Sa'id]; Telah menceritakan kepada kami [Syu'bah]; Telah menceritakan kepada kami [Qatadah] dari [Abu 'Isa Al Uswari] dari [Abu Sa'id Al Khudri]; Bahwa Rasulullah shallallahu 'alaihi wasallam minum sambil berdiri."},"3493":{"ar":"حَدَّثَنِي عَبْدُ الْجَبَّارِ بْنُ الْعَلَاءِ حَدَّثَنَا مَرْوَانُ يَعْنِي الْفَزَارِيَّ حَدَّثَنَا عُمَرُ بْنُ حَمْزَةَ أَخْبَرَنِي أَبُو غَطَفَانَ الْمُرِّيُّ أَنَّهُ سَمِعَ أَبَا هُرَيْرَةَ يَقُولُاقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا يَشْرَبَنَّ أَحَدٌ مِنْكُمْ قَائِمًا فَمَنْ نَسِيَ فَلْيَسْتَقِئْ","id":"Telah menceritakan kepadaku ['Abdul Jabbar bin Al 'Alaa`]; Telah menceritakan kepada kami [Marwan] yaitu Al Fazari; Telah menceritakan kepada kami ['Umar bin Hamzah]; Telah mengabarkan kepadaku [Abu Ghathafan Al Murri] bahwa dia mendengar [Abu Hurairah] berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Janganlah sekali-kali salah seorang diantara kalian minum sambil berdiri, apabila dia lupa maka muntahkanlah.\""},"3494":{"ar":"و حَدَّثَنَا أَبُو كَامِلٍ الْجَحْدَرِيُّ حَدَّثَنَا أَبُو عَوَانَةَ عَنْ عَاصِمٍ عَنْ الشَّعْبِيِّ عَنْ ابْنِ عَبَّاسٍ قَالَسَقَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِنْ زَمْزَمَ فَشَرِبَ وَهُوَ قَائِمٌ","id":"Telah menceritakan kepada kami [Abu Kamil Al Jahdari]; Telah menceritakan kepada kami [Abu 'Awanah] dari [Ashim] dari [Asy Sya'bi] dari [Ibnu 'Abbas] ia berkata; \"Aku memberi minum dari Air Zam-zam kepada Rasulullah, lalu beliau minum sambil berdiri.\""},"3495":{"ar":"و حَدَّثَنَا مُحَمَّدُ بْنُ عَبْدِ اللَّهِ بْنِ نُمَيْرٍ حَدَّثَنَا سُفْيَانُ عَنْ عَاصِمٍ عَنْ الشَّعْبِيِّ عَنْ ابْنِ عَبَّاسٍأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ شَرِبَ مِنْ زَمْزَمَ مِنْ دَلْوٍ مِنْهَا وَهُوَ قَائِمٌ","id":"Telah menceritakan kepada kami [Muhammad bin 'Abdullah bin Numair]; Telah menceritakan kepada kami [Sufyan] dari ['Ashim] dari [Asy Sya'bi] dari [Ibnu 'Abbas] bahwa Nabi shallallahu 'alaihi wasallam minum air Zam-Zam dari gayungnya sambil berdiri."},"3496":{"ar":"و حَدَّثَنَا سُرَيْجُ بْنُ يُونُسَ حَدَّثَنَا هُشَيْمٌ أَخْبَرَنَا عَاصِمٌ الْأَحْوَلُ ح و حَدَّثَنِي يَعْقُوبُ الدَّوْرَقِيُّ وَإِسْمَعِيلُ بْنُ سَالِمٍ قَالَ إِسْمَعِيلُ أَخْبَرَنَا و قَالَ يَعْقُوبُ حَدَّثَنَا هُشَيْمٌ حَدَّثَنَا عَاصِمٌ الْأَحْوَلُ وَمُغِيرَةُ عَنْ الشَّعْبِيِّ عَنْ ابْنِ عَبَّاسٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ شَرِبَ مِنْ زَمْزَمَ وَهُوَ قَائِمٌ","id":"Telah menceritakan kepada kami [Suraij bin Yunus]; Telah menceritakan kepada kami [Husyaim]; Telah mengabarkan kepada kami ['Ashim Al Ahwal]; Demikian juga telah diriwayatkan dari jalur yang lain; Dan telah menceritakan kepadaku [Ya'qub Ad Dauraqi] dan [Isma'il bin Salim], Isma'il berkata; Telah mengabarkan kepada kami, sedangkan Ya'qub berkata; Telah menceritakan kepada kami [Husyaim]; Telah menceritakan kepada kami ['Ashim Al Ahwal] dan [Mughirah] dari [Asy Sya'biy] dari [Ibnu 'Abbas]; Bahwa Rasulullah shallallahu 'alaihi wasallam minum dari air zam-zam sambil berdiri."},"3497":{"ar":"و حَدَّثَنِي عُبَيْدُ اللَّهِ بْنُ مُعَاذٍ حَدَّثَنَا أَبِي حَدَّثَنَا شُعْبَةُ عَنْ عَاصِمٍ سَمِعَ الشَّعْبِيَّ سَمِعَ ابْنَ عَبَّاسٍ قَالَسَقَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِنْ زَمْزَمَ فَشَرِبَ قَائِمًا وَاسْتَسْقَى وَهُوَ عِنْدَ الْبَيْتِو حَدَّثَنَاه مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ ح و حَدَّثَنِي مُحَمَّدُ بْنُ الْمُثَنَّى حَدَّثَنَا وَهْبُ بْنُ جَرِيرٍ كِلَاهُمَا عَنْ شُعْبَةَ بِهَذَا الْإِسْنَادِ وَفِي حَدِيثِهِمَا فَأَتَيْتُهُ بِدَلْوٍ","id":"Telah menceritakan kepadaku ['Ubaidullah bin Mu'adz]; Telah menceritakan kepada kami [Bapakku]; Telah menceritakan kepada kami [Syu'bah] dari ['Ashim]; dia mendengar dari [Asy Sya'bi]; dia mendengar [Ibnu 'Abbas] berkata; Aku memberi minum Rasulullah shallallahu 'alaihi wasallam dari air zam-zam, lalu beliau minum sambil berdiri. Waktu itu beliau meminta air ketika beliau berada di samping baitullah (Ka'bah). Telah menceritakannya kepada kami [Muhammad bin Basyar]; Telah menceritakan kepada kami [Muhammad bin Ja'far]; Demikian juga telah diriwayatkan dari jalur yang lain; Dan telah menceritakan kepadaku [Muhammad bin Al Mutsanna]; Telah menceritakan kepada kami [Wahb bin Jarir] keduanya dari [Syu'bah] dengan sanad ini. Namun dalam Hadits keduanya disebutkan kalimat; 'lalu aku membawakan gayung untuk beliau.'"},"3498":{"ar":"حَدَّثَنَا ابْنُ أَبِي عُمَرَ حَدَّثَنَا الثَّقَفِيُّ عَنْ أَيُّوبَ عَنْ يَحْيَى بْنِ أَبِي كَثِيرٍ عَنْ عَبْدِ اللَّهِ بْنِ أَبِي قَتَادَةَ عَنْ أَبِيهِأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَهَى أَنْ يُتَنَفَّسَ فِي الْإِنَاءِ","id":"Telah menceritakan kepada kami [Ibnu Abu 'Umar]; Telah menceritakan kepada kami [Ats Tsaqafi] dari [Ayyub] dari [Yahya bin Abu Katsir] dari ['Abdillah bin Abu Qatadah] dari [Bapaknya]; Bahwa Nabi shallallahu 'alaihi wasallam melarang menghembuskan nafas di dalam bejana (ketika minum)."},"3499":{"ar":"و حَدَّثَنَا قُتَيْبَةُ بْنُ سَعِيدٍ وَأَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ قَالَا حَدَّثَنَا وَكِيعٌ عَنْ عَزْرَةَ بْنِ ثَابِتٍ الْأَنْصَارِيِّ عَنْ ثُمَامَةَ بْنِ عَبْدِ اللَّهِ بْنِ أَنَسٍ عَنْ أَنَسٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يَتَنَفَّسُ فِي الْإِنَاءِ ثَلَاثًا","id":"Telah menceritakan kepada kami [Qutaibah bin Sa'id] dan [Abu Bakr bin Abu Syaibah] mereka berkata; Telah menceritakan kepada kami [Waki'] dari ['Azrah bin Tsabit Al Anshari] dari [Tsumamah bin 'Abdillah bin Anas] dari [Anas]; Bahwa Rasulullah shallallahu 'alaihi wasallam bernafas (ketika minum) di bejana sebanyak tiga kali."},"3500":{"ar":"حَدَّثَنَا يَحْيَى بْنُ يَحْيَى أَخْبَرَنَا عَبْدُ الْوَارِثِ بْنُ سَعِيدٍ ح و حَدَّثَنَا شَيْبَانُ بْنُ فَرُّوخَ حَدَّثَنَا عَبْدُ الْوَارِثِ عَنْ أَبِي عِصَامٍ عَنْ أَنَسٍ قَالَكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَتَنَفَّسُ فِي الشَّرَابِ ثَلَاثًا وَيَقُولُ إِنَّهُ أَرْوَى وَأَبْرَأُ وَأَمْرَأُقَالَ أَنَسٌ فَأَنَا أَتَنَفَّسُ فِي الشَّرَابِ ثَلَاثًا و حَدَّثَنَاه قُتَيْبَةُ بْنُ سَعِيدٍ وَأَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ قَالَا حَدَّثَنَا وَكِيعٌ عَنْ هِشَامٍ الدَّسْتَوَائِيِّ عَنْ أَبِي عِصَامٍ عَنْ أَنَسٍ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِمِثْلِهِ وَقَالَ فِي الْإِنَاءِ","id":"Telah menceritakan kepada kami [Yahya bin Yahya]; Telah mengabarkan kepada kami ['Abdul Warits bin Sa'id]; Demikian juga telah diriwayatkan dari jalur yang lain; Dan telah menceritakan kepada kami [Syaiban bin Farrukh]; Telah menceritakan kepada kami ['Abdul Warits] dari [Abu 'Isham] dari [Anas] ia berkata; Rasulullah shallallahu 'alaihi wasallam pernah bernafas tiga kali ketika minum. Beliau berkata: 'Itu lebih melegakan, lebih bersih, dan lebih bermanfaat.\" Kata Anas; 'Karena itu aku bernafas tiga kali setiap minum.' Dan telah menceritakannya kepada kami [Qutaibah bin Sa'id] dan [Abu Bakr bin Abu Syaibah] mereka berkata; Telah menceritakan kepada kami [Waki'] dari [Hisyam Ad Dawastai] dari [Abu 'Isham] dari [Anas] dari Nabi shallallahu 'alaihi wasallam dengan Hadits yang serupa, dengan kalimat 'fil Inaa' (di dalam bejana)."}};
